var XG_2026_QUESTIONS = [
  {"question": "1. 根据民法典总则编及相关规定，因下列哪些行为所产生的当事人之间的关系属于民法调整的范围？(单选)", "options": ["A. 国家知识产权局与商标注册证打印纸供应商之间的关系", "B. 国家知识产权局与非正常专利申请行为人之间的关系", "C. 国家知识产权局与外聘专利审查辅助人员之间的关系", "D. 国家知识产权局与专利代理事务所之间的关系"], "answer": "A", "explanation": "A选项行政机关参与民事活动属于平等主体之间的财产关系，属于民法调整的范围。B、D选项均属于行政机关与行政相对人之间的行政法律关系，不属于民法调整的范围。C选项为劳动合同关系，不属于民法调整范围。(新编)", "type": "single", "topic": "专题一 民法典总则编", "page": 2, "subject": "相关法", "id": "xg_0"},
  {"question": "2. 根据法律规定，下列哪一种社会关系应由民法调整？(单选)", "options": ["A. 甲请求税务机关退还其多缴的个人所得税", "B. 乙手机丢失后发布寻物启事称：“拾得者送还手机，本人当面酬谢”", "C. 丙发微信朋友圈承诺：“如我在上海找到工作，就陪女友去欧洲旅游”", "D. 丁作为青年志愿者，定期去福利院做帮工"], "answer": "B", "explanation": "A选项属于行政机关与相对人之间的行政关系，不由民法调整。B选项属于单方允诺，应由民法调整。C、D选项属于好意施惠，不是意思表示，不由民法调整。(法考2016)", "type": "single", "topic": "专题一 民法典总则编", "page": 2, "subject": "相关法", "id": "xg_1"},
  {"question": "3. 下列哪一情形下，乙的请求依法应得到支持？(单选)", "options": ["A. 甲应允乙同看演出，但迟到半小时。乙要求甲赔偿损失", "B. 甲听说某公司股票可能大涨，便告诉乙，乙信以为真大量购进，事后该支股票大跌。乙要求甲赔偿损失", "C. 甲与其妻乙约定，如因甲出轨导致离婚，甲应补偿乙50万元，后二人果然因此离婚。乙要求甲依约赔偿", "D. 甲对乙承诺，如乙比赛夺冠，乙出国旅游时甲将陪同，后乙果然夺冠，甲失约。乙要求甲承担赔偿责任"], "answer": "C", "explanation": "A、D选项，甲的行为均属于好意施惠行为，不产生财产关系，乙的请求不能依法得到支持。B选项，甲向乙传递小道消息，乙作为完全民事行为能力人对自己的投资行为应进行独立的判断，造成损失应自行承担。C选项，甲与乙的约定属于“离婚过错损害赔偿”的约定，乙要求甲依约赔偿的请求依法应得到支持。(法考2010)", "type": "single", "topic": "专题一 民法典总则编", "page": 2, "subject": "相关法", "id": "xg_2"},
  {"question": "4. 甲诉某专利的专利权利人乙专利权权属纠纷一案正在审理中,证据交换阶段乙觉得自己胜诉无望,随即向国家知识产权局提出放弃该专利的申请,乙的行为违背民法典的下列哪一基本原则? (单选)", "options": ["A. 平等原则", "B. 自愿原则", "C. 公平原则", "D. 诚信原则"], "answer": "D", "explanation": "在民事诉讼中，当事人不能因为诉讼结果对自己不利就随意放弃权利，这种行为违背了诚信原则，因为诚信原则要求当事人在民事活动中应当遵循诚实信用的原则。", "type": "single", "topic": "专题一 民法典总则编", "page": 3, "subject": "相关法", "id": "xg_3"},
  {"question": "5. 胡某在自家菜园里发现一只甲虫,非常好奇遂拍照发到网上,付某出价30万元购买。后来发现该甲虫是濒危动物,国家二级保护动物。此种情形违反以下民法的哪一个原则?(多选)", "options": ["A. 公序良俗原则", "B. 自愿原则", "C. 绿色原则", "D. 诚信原则"], "answer": "AC", "explanation": "胡某与付某二人买卖国家二级保护动物的行为违反了《野生动物保护法》,故其违反了合法与公序良俗原则。且售卖野生动物不利于保护生态环境,故其违反了绿色原则。(法考2024)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 3, "subject": "相关法", "id": "xg_4"},
  {"question": "6. 某公司挖天然气管道途经郝某家耕地,不影响耕地使用。郝某报出高价索赔,否则不让挖掘。经过协商,某公司以行业规定最高标准给予补偿。后郝某觉得补偿太少,要求补上之前索要高价的差额。郝某的行为违反了哪种原则?(单选)", "options": ["A. 违反公序良俗原则", "B. 违反诚信原则", "C. 违反平等原则", "D. 违反公平原则"], "answer": "B", "explanation": "某公司挖天然气管道途经郝某家耕地,郝某请求补偿理所当然,但是,趁机索要高价,属于权利滥用行为。因此,郝某的行为违反了诚信原则,B选项正确。(法考2023)", "type": "single", "topic": "专题一 民法典总则编", "page": 3, "subject": "相关法", "id": "xg_5"},
  {"question": "7. 关于民事法律关系,下列哪一选项是正确的?(单选)", "options": ["A. 民事法律关系只能由当事人自主设立", "B. 民事法律关系的主体即自然人和法人", "C. 民事法律关系的客体包括不作为", "D. 民事法律关系的内容均由法律规定"], "answer": "C", "explanation": "A、D选项,有些民事法律关系由当事人自主设立,如合同关系;有些民事法律关系由法律直接规定,如物权的种类和内容,因此A、D选项错误。B选项,民事法律关系的主体包括自然人、法人和非法人组织,因此B选项错误。C选项,民事法律关系的客体,包括作为和不作为;作为的客体,例如买卖合同之债,买方基于债权可以请求卖方交付标的物,卖方基于债权可以请求买方支付价款,在买卖合同中法律关系的客体是请求对方做出某种行为;再如专利权人获得专利授权,获得了对该技术的排他权,该法律关系的客体是其他人未经许可不得使用其专利技术,即不作为,因此C选项正确。(法考2008,思维扩展)", "type": "single", "topic": "专题一 民法典总则编", "page": 3, "subject": "相关法", "id": "xg_6"},
  {"question": "1. 根据民法典总则编及相关规定,下列哪些属于限制民事行为能力人?(多选)", "options": ["A. 6岁上初中的神童甲", "B. 18岁依靠父母资助上大学的乙", "C. 9岁在读小学生丙", "D. 16岁已经掌握一定维修技术的技校生丁"], "answer": "CD", "explanation": "A选项,6岁的甲为无民事行为能力人。B选项,18岁的乙为完全民事行为能力人,A、B选项错误。C、D选项,9岁的丙为限制民事行为能力人,16岁的丁虽掌握一定维修技术,但不是以自己的劳动收入为主要生活来源,仍为限制民事行为能力人,因此C、D选项正确。(2018)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 4, "subject": "相关法", "id": "xg_7"},
  {"question": "2. 根据民法典总则编的规定,关于民事行为能力下列哪些表述是错误的?(多选)", "options": ["A. 十六周岁以上的自然人是成年人,具有完全民事行为能力,可以独立进行民事活动,是完全民事行为能力人", "B. 十四周岁以上不满十六周岁的自然人,以自己的劳动收入为主要生活来源的,视为完全民事行为能力人", "C. 十周岁以上的未成年人是限制民事行为能力人,进行民事活动应当征得他的法定代理人的同意", "D. 无民事行为能力人、限制民事行为能力人的监护人是他的法定代理人"], "answer": "ABC", "explanation": "A选项,《民法典》第17条规定:\"十八周岁以上的自然人为成年人。不满十八周岁的自然人为未成年人\",因此A选项错误。B选项,《民法典》第18条第2款规定:\"十六周岁以上的未成年人,以自己的劳动收入为主要生活来源的,视为完全民事行为能力人\",因此B选项错误。C选项,《民法典》第19条规定:\"八周岁以上的未成年人为限制民事行为能力人......可以独立实施纯获利益的民事法律行为或者与其年龄、智力、精神健康状况相适应的民事法律行为\",C选项错误。D选项,《民法典》第23条规定:\"无民事行为能力人、限制民事行为能力人的监护人是其法定代理人\",因此D选项正确。[注意]学员注意第2题和第1题之间的区别,第2题为法条题,严格按法条说法选答案,第1题为案例题,按照实际情况选答案。(2019)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 4, "subject": "相关法", "id": "xg_8"},
  {"question": "3. 下列选项中哪些属于无民事行为能力人?(多选)", "options": ["A. 跟随母亲来中国旅游的外国籍7岁儿童", "B. 30岁的精神病人,经鉴定其智商只有5岁", "C. 16岁的脑瘫患者,不能辨认自己的行为", "D. 7岁小学生,已经可以通过网络直播收入为主要生活来源"], "answer": "ABCD", "explanation": "《民法典》第12条中规定\"中华人民共和国领域内的民事活动,适用中华人民共和国法律。法律另有规定的,依照其规定。\"其他法律中未明确规定外国籍未成年人在中国进行民事法律活动时行为能力判断的适用标准,因此,应适用《民法典》中的规定,A选项正确。B选项,按照鉴定其智商属于不能辨认自己的行为,属于无民事行为能力人。C选项,不能辨认自己行为的人", "type": "multiple", "topic": "专题一 民法典总则编", "page": 4, "subject": "相关法", "id": "xg_9"},
  {"question": "1. 陆某因诈骗罪被判入狱，和妻子协议离婚，双方约定，12岁的儿子由陆某抚养，但实际是由陆某父母抚养。下列哪一说法是正确的？(单选)", "options": ["A. 陆某是唯一监护人", "B. 陆某的妻子是唯一监护人", "C. 夫妻二人均为监护人", "D. 陆某的父母为监护人"], "answer": "C", "explanation": "《民法典》第27条第1款规定：“父母是未成年子女的监护人。”父母分居或者离婚的，不影响监护能力。不论谁是陆某12岁的儿子的实际抚养人，父母都为其监护人。因此C选项正确。(法考2020)", "type": "single", "topic": "专题一 民法典总则编", "page": 5, "subject": "相关法", "id": "xg_10"},
  {"question": "5. 甲男、乙女为夫妻，生子丙，甲男去世。丙6岁的时候，甲父赠送给丙一幅价值百万元的名画。丙8岁的时候，甲父再赠送给丙一块价值10万元的名表。以下说法哪些正确？(多选)", "options": ["A. 因为是纯获利益的行为，故名画赠与合同有效", "B. 因为在受赠名画时，丙为无民事行为能力人，故名画赠与合同无效", "C. 因为是纯获利益的行为，故名表赠与合同有效", "D. 因为在受赠名表时，丙为限制民事行为能力人，故名表赠与合同无效"], "answer": "BC", "explanation": "A、B选项，由于赠与名画时丙仅6岁，属于无民事行为能力人，其独立实施的民事法律行为一律无效，因此A选项错误，B选项正确。C、D选项，由于赠与名表时丙已8岁，属于限制民事行为能力人，且接受名表属于纯获利益的行为，赠与合同有效，因此C选项正确，D选项错误。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 5, "subject": "相关法", "id": "xg_11"},
  {"question": "6. 王某户籍所在地是上海，大学毕业后在北京工作了两年。因身体原因前往广州就医，并在广州某医院住院一年半。痊愈后在深圳居住工作，至今已逾半年。根据民法典总则编及相关规定，王某在下列哪个城市的居住地视为其现在的住所？(单选)", "options": ["A. 上海", "B. 北京", "C. 广州", "D. 深圳 第二节 监护"], "answer": "A", "explanation": "《民法典》第25条规定：“自然人以户籍登记或者其他有效身份登记记载的居所为住所；经常居所与住所不一致的，经常居所视为住所”。本题中，王某现居住地为深圳，还不到一年，因此应当以户籍所在地为住所，因此A选项正确。(2009改编)", "type": "single", "topic": "专题一 民法典总则编", "page": 5, "subject": "相关法", "id": "xg_12"},
  {"question": "2. 李某是无民事行为能力的精神病人，其近亲属对担任李某的监护人有争议，并且对李某住所地居民委员会的指定不服，向人民法院提起诉讼。根据民法典总则编及相关规定，人民法院一般应按照下列哪项中的顺序指定监护人?(单选)", "options": ["A. (1)配偶;(2)父母、子女;(3)其他近亲属", "B. (1)配偶、成年子女;(2)父母;(3)其他近亲属", "C. (1)父母;(2)配偶、子女;(3)其他近亲属", "D. (1)父母、子女;(2)配偶;(3)其他近亲属"], "answer": "A", "explanation": "《民法典》第28条规定：“无民事行为能力人或者限制民事行为能力人由下列有监护能力的人按照顺序担任监护人：（一）配偶；（二）父母、子女；（三）其他近亲属；（四）其他愿意担任监护人的个人或者组织，因此A选项正确。", "type": "single", "topic": "专题一 民法典总则编", "page": 6, "subject": "相关法", "id": "xg_13"},
  {"question": "3. 陈某夫妇因意外事故双亡，二人的儿子陈畅刚刚年满3周岁。根据民法典总则编及相关规定，下列关于陈畅的监护人的哪些说法是正确的?(多选)", "options": ["A. 可以由陈畅的祖父母、外祖父母中的一人或数人担任监护人", "B. 对担任监护人有争议的，可以由陈畅住所地的居民委员会在近亲属中指定", "C. 陈畅的祖父被指定担任监护人后，可以自行变更监护人", "D. 若关系密切的其他亲属、朋友愿意承担监护责任，经陈畅住所地的居民委员会同意，也可以作为陈畅的监护人"], "answer": "ABD", "explanation": "A、D选项，《民法典》第27条第2款规定：“未成年人的父母已经死亡或者没有监护能力的，由下列有监护能力的人按顺序担任监护人：(一)祖父母、外祖父母……(三)其他愿意担任监护人的个人或者组织，但是须经未成年人住所地的居民委员会、村民委员会或者民政部门同意”，因此A、D选项正确。B选项，《民法典》第31条第1款规定：“对监护人的确定有争议的，由被监护人住所地的居民委员会、村民委员会或者民政部门指定监护人……”，因此B选项正确。C选项，《民法典》第31条第4款规定：“监护人被指定后，不得擅自变更”，因此C选项错误。(2017改编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 6, "subject": "相关法", "id": "xg_14"},
  {"question": "4. 余某与其妻婚后很久才育有一女小翠。不久后余某与妻子离婚，小翠由余某抚养。现余某身患重病，为自己和幼女小翠的未来担忧，欲作相应安排。下列哪些选项是正确的?(多选)", "options": ["A. 余某可通过遗嘱指定其弟弟在其身故后担任小翠的监护人", "B. 余某可与前妻协议确定，余某不再承担监护职责", "C. 余某可与其堂兄事先协商以书面形式确定堂兄为自己的监护人", "D. 如余某病故，应由余某父母担任小翠的监护人"], "answer": "AC", "explanation": "A选项，《民法典》第29条规定：“被监护人的父母担任监护人的，可以通过遗嘱指定监护人”，A选项意欲表达余某“可以”通过遗嘱为小翠指定监护人，该遗嘱是否能够生效还需要看余某前妻的态度，因此A选项正确。B选项，根据《总则编司法解释》第8条，订立协议约定免除具有监护能力的父母的监护职责的，人民法院不予支持，因此B选项错误。C选项，《民法典》第33条规定：“具有完全民事行为能力的成年人，可以与其近亲属、其他愿意担任监护人的个人或者组织事先协商，以书面形式确定自己的监护人，在自己丧失或者部分丧失民事行为能力时，由该监护人履行监护职责”，因此C选项正确。D选项，父母是子女的当然监护人，余某去世后，余某前妻是监护人，因此D选项错误。(法考2017改编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 6, "subject": "相关法", "id": "xg_15"},
  {"question": "5. 丧偶的汪某(70岁)有成年子女但独立生活，与同样丧偶的肖某(50岁)十分投缘，汪某与肖某订立书面监护协议约定：", "options": ["A. 因汪某有成年子女，监护协议无效", "B. 监护协议中关于遗产处理的部分无效", "C. 汪某丧失或部分丧失行为能力时，肖某按约定成为汪某的监护人", "D. 监护协议的全部都约定于汪某死亡时生效"], "answer": "C", "explanation": "A选项，根据《民法典》第33条意定监护的有关规定，在效力上，成年协议监护优先于法定监护，因此A选项错误。汪某与肖某书面约定有偿设立成年协议监护，该约定符合法律规定，因此B选项错误。关于该监护协议生效的时间，肖某取得汪某一半", "type": "single", "topic": "专题一 民法典总则编", "page": 6, "subject": "相关法", "id": "xg_16"},
  {"question": "9. 甲乙婚后生子丙,乙死亡。在丙12岁时,甲因吸毒处分被监护人财产而被撤销监护人资格。以下说法正确的是?（多选）", "options": ["A. 甲的监护资格撤销后,无需再承担对丙的抚养费义务", "B. 甲的监护资格撤销后,可通过遗嘱指定其母在其死后成为丙的监护人", "C. 甲戒毒成功后可以申请重新担任丙的监护人", "D. 甲能否重新担任丙的监护人需尊重丙的意愿"], "answer": "CD", "explanation": "A选项,监护人被撤销监护人资格后,应当继续履行负担抚养费、赡养费、扶养费的义务,因此A选项错误。B选项,甲的监护人资格被撤销后,丧失了遗嘱监护的权利,因此B选项错误。C、D选项,《民法典》第38条规定：“被监护人的父母或者子女被人民法院撤销监护人资格后,除对被监护人实施故意犯罪的外,确有悔改表现的,经其申请,人民法院可以在尊重被监护人真实意愿的前提下,视情况恢复其监护人资格,人民法院指定的监护人与被监护人的监护关系同时终止”,因此C、D选项正确。（新编）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 8, "subject": "相关法", "id": "xg_17"},
  {"question": "10. 张某和李某婚后育有一女,因有智力障碍,遭到父母嫌弃。后张某和李某离婚,女儿由张某抚养。某日张某酒后殴打其女,并将其嘴唇剪破,酒醒后将其女送至医院。以下说法正确的有:（多选）", "options": ["A. 医院可以向人民法院申请撤销监护权", "B. 医院可以向民政部门申请撤销监护权", "C. 张某的监护权被撤销后,法院应当按照有利于被监护人的原则指定监护人", "D. 张某的监护权被撤销后,不可恢复"], "answer": "AD", "explanation": "医院有权申请撤销监护,监护人的资格只能由法院撤销,因此A选项正确,B选项错误。C选项,父母为未成年子女的当然监护人,张某的监护人资格被撤销后,李某监护权依然存在,不涉及指定监护的问题,C选项错误。D选项,监护人因对被监护人故意犯罪,监护权撤销后不能恢复,D选项正确。（新编）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 8, "subject": "相关法", "id": "xg_18"},
  {"question": "11. 有权向法院提出申请,要求撤销监护人资格的主体有?（多选）", "options": ["A. 学校", "B. 医疗机构", "C. 未成年人保护组织", "D. 残疾人联合会"], "answer": "ABCD", "explanation": "根据《民法典》第36条的规定,有权向人民法院申请撤销监护人资格的撤销人包括：① 其他依法具有监护资格的人；② 居民委员会、村民委员会、学校、医疗机构、妇女联合会、残疾人联合会、未成年人保护组织、依法设立的老年人组织、民政部门等。因此A、B、C、D选项均正确。（新编）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 8, "subject": "相关法", "id": "xg_19"},
  {"question": "1. 根据民法典总则编及相关规定，关于宣告失踪的下列哪些说法是正确的?(多选)", "options": ["A. 自然人下落不明满二年的，利害关系人可以向人民法院申请宣告其为失踪人", "B. 宣告失踪是宣告死亡的必经程序", "C. 失踪人的财产由其配偶、成年子女、父母或者其他愿意担任财产代管人的人代管", "D. 宣告失踪后，失踪人所欠税款、债务和应付的其他费用应暂停支付"], "answer": "AC", "explanation": "A选项，《民法典》第40条规定：“自然人下落不明满二年的，利害关系人可以向人民法院申请宣告该自然人为失踪人”，因此 A 选项正确。B选项，宣告失踪不是宣告死亡的必经程序,B选项错误。C选项，《民法典》第42条第1款规定：“失踪人的财产由其配偶、成年子女、父母或者其他愿意担任财产代管人的人代管”，因此 C 选项正确。D选项，《民法典》第43条第2款规定：“失踪人所欠税款、债务和应付的其他费用，由财产代管人从失踪人的财产中支付”，因此 D选项错误。(2013改编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 9, "subject": "相关法", "id": "xg_20"},
  {"question": "2. 根据民法典总则编及相关规定，下列关于宣告失踪和宣告死亡的哪种说法是正确的?(多选)", "options": ["A. 自然人下落不明满四年的，利害关系人可以向人民法院申请宣告他死亡", "B. 因意外事件，下落不明满两年，利害关系人可以向人民法院申请宣告他死亡", "C. 因战争下落不明的，从下落不明之日起满2年可以申请宣告失踪", "D. 因意外事件下落不明，经有关机关证明该自然人不可能生存的，申请宣告死亡不受2年时间的限制"], "answer": "ABD", "explanation": "《民法典》第46条规定：“自然人有下列情形之一的，利害关系人可以向人民法院申请宣告该自然人死亡:(一)下落不明满四年;(二)因意外事件，下落不明满二年。因意外事件下落不明，经有关机关证明该自然人不可能生存的，申请宣告死亡不受二年时间的限制”，因此 A、B、D选项正确。《民法典》第41条规定：“自然人下落不明的时间自其失去音讯之日起计算。战争期间下落不明的，下落不明的时间自战争结束之日或者有关机关确定的下落不明之日起计算”，因此 C 选项错误。(2015改编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 9, "subject": "相关法", "id": "xg_21"},
  {"question": "3. 下列关于财产代管人，说法正确的有哪些？(多选)", "options": ["A. 对担任财产代管人有争议的，由法院指定", "B. 失踪人所欠税款、债务和应付的其他费用，由财"], "answer": "ACD", "explanation": "A选项，《民法典》第42条第2款的规定：“代管有争议，没有前款规定的人，或者前款规定的人无代管能力的，由人民法院指定的人代管”，因此 A 选项正确。B、C选项，《民法典》第43条的规定：“……失踪人所欠税款、债务和应付的其他费用，由财产代管人从失踪人的财产中支付。财产代管人因故意或者重大过失造成失踪人财产损失的，应当承担赔", "type": "multiple", "topic": "专题一 民法典总则编", "page": 9, "subject": "相关法", "id": "xg_22"},
  {"question": "12. 根据民法典总则编及相关规定，导致监护关系终止有以下哪些原因?(多选)", "options": ["A. 被监护人或者监护人死亡", "B. 监护人丧失监护能力", "C. 经民政部门认定监护关系终止", "D. 监护人与未成年的被监护人协商一致解除监护关系 第三节 宣告失踪和宣告死亡"], "answer": "ABC", "explanation": "《民法典》第39条第1款规定：‘有下列情形之一的，监护关系终止：（一）被监护人取得或者恢复完全民事行为能力；（二）监护人丧失监护能力；（三）被监护人或者监护人死亡；（四）人民法院认定监护关系终止的其他情形’。因此A、B选项正确；监护关系终止应由法院认定，民政部门无权认定监护关系终止，因此C选项错误。D选项，监护人与被监护人无权自行协商解除监护关系，因此D选项错误。（2018）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 9, "subject": "相关法", "id": "xg_23"},
  {"question": "4. 李某因所乘飞机失事自2021年6月1日至今下落不明。根据民法典总则编及相关规定，下列哪些说法是正确的?(多选)", "options": ["A. 李某的配偶申请宣告其死亡，可以自2021年6月1日起满2年向人民法院申请", "B. 如果人民法院宣告李某死亡，则判决宣告之日为李某死亡的日期", "C. 若李某被宣告死亡但并未死亡，其在被宣告死亡期间实施的民事法律行为有效", "D. 若李某重新出现，经其本人申请，人民法院应当撤销死亡宣告"], "answer": "ACD", "explanation": "A选项，飞机失事属于意外事件，因此李某的配偶在事故发生之日起满2年即可申请宣告其死亡，A选项正确。B选项，《民法典》第48条规定：“……因意外事件下落不明宣告死亡的，意外事件发生之日视为其死亡的日期”，因此李某死亡日期为2021年6月1日，B选项错误。C选项，《民法典》第49条规定：“自然人被宣告死亡但是并未死亡的，不影响该自然人在被宣告死亡期间实施的民事法律行为的效力”，C选项为一般笼统性说法，正确。D选项，《民法典》第50规定：“被宣告死亡的人重新出现，经本人或者利害关系人申请，人民法院应当撤销死亡宣告”，因此D选项正确。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 10, "subject": "相关法", "id": "xg_24"},
  {"question": "5. 2020年6月1日，家住北京市通州区的刘某乘坐某航班从马来西亚飞回北京。飞机中途失事，至今下落不明。刘某的父母担心刘某妻子带房改嫁，于2022年8月15日向通州区人民法院申请宣告刘某死亡。下列哪些说法是错误的?(多选)", "options": ["A. 如果刘某的妻子不宣告刘某死亡，刘某的父母不能申请宣告刘某死亡", "B. 刘某的父母申请宣告刘某死亡距刘某下落不明尚不满4年，不符合宣告死亡的要求", "C. 如通州区法院宣告刘某死亡，则判决作出之日视为刘某死亡的日期", "D. 如通州区法院宣告刘某死亡但是刘某并未死亡的，在被宣告死亡期间刘某所实施的民事法律行为均有效"], "answer": "ABCD", "explanation": "A选项，宣告死亡的申请人(利害关系人)不存在顺序先后的限制，因此A选项错误。B选项，刘某因意外事件下落不明，满2年即可宣告死亡，因此B选项错误。C选项，刘某因意外事件下落不明，意外事件发生之日视为其死亡的日期，刘某死亡的日期应是2020年6月1日，因此C选项错误。D选项，自然人被宣告死亡但是并未死亡的，不影响该自然人在被宣告死亡期间实施的民事法律行为的效力，但是其在被宣告死亡期间所实施的民事法律行为的效力应具体情况具体分析(可能有效、无效、效力待定，可撤销)，并非一定有效，因此D选项错误。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 10, "subject": "相关法", "id": "xg_25"},
  {"question": "7. 袁某和祖某系夫妻，后二人吵架，袁某离家出走。2年后，依祖某申请，法院宣告袁某失踪。四年后，因袁某一直未偿还借款债务，债权人胡某申请法院宣告袁某死亡。关于本案，下列说法正确的有？(多选)", "options": ["A. 袁某被宣告失踪后，丧失民事行为能力", "B. 胡某的宣告申请，法院不应予以支持", "C. 袁某父母不同意，可以申请撤回失踪宣告", "D. 祖某提出离婚诉讼的，法院应当准许"], "answer": "BD", "explanation": "A选项，袁某被宣告失踪后，其民事行为能力不受影响，因此A选项错误。B选项，《总则编司法解释》第16条规定，被申请人的债权人、债务人、合伙人等民事主体不能认定为宣告死亡的利害关系人，债权人胡某无权向法院申请宣告袁某死亡，因此B选项正确。C选项，自然人下落不明满2年的，利害关系人可以向人民法院申请宣告该自然人为失踪人。其中，配偶和父母均为利害关系人且申请宣告失踪无顺序先后的限制。袁某的配偶祖某有权申请袁某失踪，袁某父母不同意的，不可以申请撤回失踪宣告，因此C选项错误。D选项，《民法典》第1079条规定，一方被宣告失踪，另一方提起离婚诉讼的，应当准予离婚，因此祖某提出离婚诉讼，法院应当准许，D选项正确。\n(法考2022，思维扩展)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 11, "subject": "相关法", "id": "xg_26"},
  {"question": "8. 甲于2023年1月1日在攀爬雪山返程途中不幸遭遇雪崩而下落不明，根据民法典总则编以及相关规定，下列说法正确的有哪些？(多选)", "options": ["A. 甲的妻子可以自2023年1月1日之日起满两年向法院申请宣告甲死亡", "B. 如果甲的父母申请宣告死亡，甲的妻子申请宣告失踪的，法院应当宣告死亡", "C. 如果人民法院宣告甲死亡，则甲的死亡日期为法院判决宣告之日", "D. 如果甲重新出现，只能由甲向人民法院撤销死亡宣告"], "answer": "AB", "explanation": "雪崩属于意外事件，因此甲的妻子可以在雪崩之日起起满2年宣告甲死亡，A选项正确。《民法典》第47条规定：“对同一自然人，有的利害关系人申请宣告死亡，有的利害关系人申请宣告失踪，符合本法规定的宣告死亡条件的，人民法院应当宣告死亡”，B选项正确。甲因意外事件下落不明被宣告死亡的，意外事件发生之日视为其死亡的日期，C选项错误。甲被宣告死亡后重新出现，可以由其本人或者利害关系人申请撤销死亡宣告，D选项错误。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 11, "subject": "相关法", "id": "xg_27"},
  {"question": "2. 村民钱某与村办食品厂共同设立了具有独立法人资格的“美新农副产品有限责任公司”（以下简称“美新公司”），钱某担任公司的法定代表人。根据民法典总则编及相关规定，下列说法哪些是正确的？（多选）", "options": ["A. 美新公司从其依法成立时具有民事权利能力和民事行为能力", "B. 美新公司对钱某的经营活动承担民事责任", "C. 美新公司在经营活动中产生的债务由钱某、食品厂按各自的出资比例承担", "D. 钱某和食品厂对美新公司在经营活动中产生的债务承担连带责任"], "answer": "AB", "explanation": "A选项，法人的民事权利能力和民事行为能力，从法人成立时产生，到法人终止时消灭，因此美新公司从其依法成立时具有民事权利能力和民事行为能力，A选项正确。B、C、D选项，《民法典》第60条规定：“法人以其全部财产独立承担民事责任”；《民法典》第61条规定：“……代表法人从事民事活动的负责人，为法人的法定代表人。法定代表人以法人名义从事的民事活动，其法律后果由法人承受……”，钱某为美新公司的法定代表人，其经营活动以及美新公司在经营活动中产生的债务均由美新公司独立承担，因此B选项正确，C、D选项错误。(2011)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 12, "subject": "相关法", "id": "xg_28"},
  {"question": "3. 甲乙丙丁戊五个人均为执业两年以上的专利代理师，协商一致打算成立知识产权代理有限责任公司，关于公司设立过程中法律后果的承担，以下说法正确的有哪些？（多选）", "options": ["A. 甲以自己名义租赁办公场所，但是知识产权代理有限公司并未设立成功，对于房租费用，由五位设立人承担连带责任", "B. 甲以自己名义租赁办公场所，知识产权代理有限公司设立后，房东可以选择该公司或者甲承担尚未支付的费用", "C. 乙为将来公司办公购买大型复印机一台，公司设立成功后，该复印机损坏无法使用，公司可以要求厂家进行维修", "D. 该专利代理公司成立两年后设立分公司，该分公司可以以其自己的名义签订专利代理协议"], "answer": "ABCD", "explanation": "《民法典》第75条的规定：“设立人为设立法人从事的民事活动，其法律后果由法人承受；法人未成立的，其法律后果由设立人承受，设立人为二人以上的，享有连带债权，承担连带债务。设立人为设立法人以自己的名义从事民事活动产生的民事责任，第三人有权选择请求法人或者设立人承担”，因此A、B、C选项正确。《民法典》第74条的规定：“法人可以依法设立分支机构……分支机构以自己的名义从事民事活动，产生的民事责任由法人承担……”，D选项正确。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 12, "subject": "相关法", "id": "xg_29"},
  {"question": "4. 甲公司分立为乙丙两公司,约定由乙公司承担甲公司全部债务的清偿责任,丙公司继受甲公司全部债权。关于该协议的效力,下列哪一选项是正确的?(单选)", "options": ["A. 该协议仅对乙丙两公司具有约束力,对甲公司的债权人并非当然有效", "B. 该协议无效,应当由乙丙两公司对甲公司的债务承担连带清偿责任", "C. 该协议有效,甲公司的债权人只能请求乙公司对甲公司的债务承担清偿责任", "D. 该协议效力待定,应当由甲公司的债权人选择分立后的公司清偿债务"], "answer": "A", "explanation": "《民法典》第67条第2款规定：“法人分立的,分立后的法人享有连带债权,承担连带债务,但是债权人和债务人另有约定的除外”。本题中,甲公司分立为乙丙两公司后的约定对内有效,对外并不当然有效,除非债权人和债务人另有约定,因此A选项正确,B、C、D选项错误。(法考2019)", "type": "single", "topic": "专题一 民法典总则编", "page": 13, "subject": "相关法", "id": "xg_30"},
  {"question": "5. 下列情形中,属于法人解散的原因的有哪些?(多选)", "options": ["A. 被吊销营业执照", "B. 被吊销登记证书", "C. 章程规定的存续期间届满", "D. 变更名称"], "answer": "ABC", "explanation": "《民法典》第69条规定：“有下列情形之一的,法人解散：(一)法人章程规定的存续期间届满或者法人章程规定的其他解散事由出现；(二)法人的权力机构决议解散；(三)因法人合并或者分立需要解散；(四)法人依法被吊销营业执照、登记证书,被责令关闭或者被撤销；(五)法律规定的其他情形。”变更名称不属于上述情形,因此A、B、C选项正确,D选项错误。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 13, "subject": "相关法", "id": "xg_31"},
  {"question": "6. 关于法人,下列哪一表述是正确的?(多选)", "options": ["A. 社会团体法人均为非营利法人", "B. 基金会法人属于捐助法人", "C. 社会团体法人可以属于营利法人", "D. 民办非企业单位法人属于营利法人"], "answer": "AB", "explanation": "《民法典》第87条规定“非营利法人包括事业单位、社会团体、基金会、社会服务机构等”,因此,A选项正确、C选项错误,D选项中的民办非企业单位属于社会服务机构,因此属于非营利法人,D选项错误。《民法典》第92条规定,“具备法人条件,为公益目的以捐助财产设立的基金会、社会服务机构等,经依法登记成立,取得捐助法人资格”,因此B选项正确。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 13, "subject": "相关法", "id": "xg_32"},
  {"question": "7. 根据民法典及相关规定,下列关于事业单位法人的说法哪些是错误的?(多选)", "options": ["A. 具备法人条件的事业单位从成立之日起取得法人资格", "B. 事业单位法人名誉权遭受侵害的,有权诉请精神损害赔偿", "C. 所有事业单位法人的全部经费均来自国家财政拨款", "D. 国家举办的事业单位对其直接占有的动产享有所有权"], "answer": "ABCD", "explanation": "A选项,《民法典》第88条规定：“具备法人条件,为适应经济社会发展需要,提供公益服务设立的事业单位,经依法登记成立,取得事业单位法人资格；依法不需要办理法人登记的,从成立之日起,具有事业单位法人资格”,因此A选项错误。B选项,只有自然人享有主张精神损害赔偿的权利,法人不具有主张精神损害赔偿的权利,因此B选项错误。C选项,事业单位分为全额拨款、自负盈亏的事业编制,并非所有事业单位的经费均来自国家财政拨款,因此C选项错误。D选项,《民法典》第256条规定：“国家举办的事业单位对其直接支配", "type": "multiple", "topic": "专题一 民法典总则编", "page": 13, "subject": "相关法", "id": "xg_33"},
  {"question": "9. 根据民法典及相关规定，下列哪些组织属于非营利法人?(多选)", "options": ["A. 社会服务机构", "B. 事业单位", "C. 基金会", "D. 行政机关"], "answer": "ABC", "explanation": "非营利法人包括事业单位、社会团体、基金会、社会服务机构等，因此A、B、C选项正确。D选项，行政机关属于特别法人，D选项错误。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 14, "subject": "相关法", "id": "xg_34"},
  {"question": "10. 根据民法典总则编及相关规定，关于非法人组织，下列说法哪些是正确的?(多选)", "options": ["A. 非法人组织不具有法人资格，不能以自己的名义从事民事活动", "B. 非法人组织的财产不足以清偿债务的，其出资人或者设立人承担无限责任", "C. 非法人组织解散的，应当依法进行清算", "D. 非法人组织只能确定一人代表该组织从事民事活动"], "answer": "BC", "explanation": "A选项，《民法典》第102条第1款规定：“非法人组织是不具有法人资格，但是能够依法以自己的名义从事民事活动的组织”，因此A选项错误。B选项，《民法典》第104条规定：“非法人组织的财产不足以清偿债务的，其出资人或者设立人承担无限责任……”，因此B选项正确。C选项，《民法典》第107条规定：“非法人组织解散的，应当依法进行清算”，因此C选项正确。D选项，《民法典》第105条规定：“非法人组织可以确定一人或者数人代表该组织从事民事活动”，因此D选项错误。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 14, "subject": "相关法", "id": "xg_35"},
  {"question": "11. 甲企业是由自然人安琚与乙企业(个人独资)各出资500万设立的普通合伙企业，甲企业欠丙企业货款50万元，由于经营不善，甲企业全部资产仅剩20万元。现所欠货款到期，相关各方因货款清偿发生纠纷。对此，下列哪一表述是正确的?(单选)", "options": ["A. 丙企业只能要求安琚与乙企业各自承担15万元的清偿责任", "B. 丙企业只能要求甲企业承担清偿责任", "C. 欠款应先以甲企业的财产偿还，不足部分由安琚与乙企业承担无限连带责任", "D. 就乙企业对丙企业的应偿债务，乙企业投资人不承担责任"], "answer": "C", "explanation": "A、B、C选项，甲为合伙企业，合伙企业属于非法人组织，其债务应先以其全部财产进行清偿，合伙企业财产不能清偿到期债务的，合伙人承担无限连带责任，连带责任由法律规定或者当事人约定，不只是合伙人平均承担责任，或只要求合伙企业承担清偿责任，因此A、B选项错误，C选项正确。D选项，乙企业为个人独资企业，属于非法人组织，其债务应先以其全部财产进行清偿，个人独资企业财产不能清偿到期债务的，企业主承担无限责任，因此D选项错误。\n（法考2016）", "type": "single", "topic": "专题一 民法典总则编", "page": 14, "subject": "相关法", "id": "xg_36"},
  {"question": "2. 根据民法典总则编及相关规定,下列哪种民事主体享有姓名权?(单选)", "options": ["A. 法人", "B. 自然人", "C. 个体工商户", "D. 个人合伙企业"], "answer": "B", "explanation": "只有自然人享有姓名权,法人、个体工商户和个人合伙企业享有名称权,因此A、C、D选项错误,B选项正确。(2017)", "type": "single", "topic": "专题一 民法典总则编", "page": 15, "subject": "相关法", "id": "xg_37"},
  {"question": "3. 根据民法典及相关规定,下列说法哪些是正确的?(多选)", "options": ["A. 自然人享有姓名权,有权依法决定、使用、变更自己的姓名,禁止他人干涉、盗用、假冒", "B. 法人享有名称权,但是不得转让自己的名称", "C. 自然人享有肖像权,未经肖像权人同意,不得以任何目的使用公民的肖像", "D. 法人享有名誉权,禁止用侮辱、诽谤等方式损害法人的名誉"], "answer": "AD", "explanation": "A选项,《民法典》第1012条规定:“自然人享有姓名权,有权依法决定、使用、变更或者许可他人使用自己的姓名,但是不得违背公序良俗”;《民法典》第1014条规定:“任何组织或者个人不得以干涉、盗用、假冒等方式侵害他人的姓名权或者名称权”;因此A选项正确。B选项,《民法典》第1013条规定:“法人、非法人组织享有名称权,有权依法决定、使用、变更、转让或者许可他人使用自己的名称”,因此B选项错误。C选项,《民法典》第1018条第1款规定:“自然人享有肖像权,有权依法制作、使用、公开或者许可他人使用自己的肖像”;根据《民法典》第1020条的规定,合理实施可以不经过肖像权人同意,因此C选项错误。D选项,《民法典》第1024条第1款规定:“民事主体享有名誉权。任何组织或者个人不得以侮辱、诽谤等方式侵害他人的名誉权”,法人作为民事主体享有名誉权,因此D选项正确。(2011)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 15, "subject": "相关法", "id": "xg_38"},
  {"question": "4. 根据民法典总则编及相关规定,下列哪项属于不当得利?(单选)", "options": ["A. 债务人偿还未到期的债务", "B. 债务人清偿已超过诉讼时效的债务", "C. 养子女向生父母给付赡养费", "D. 顾客多付售货员的货款"], "answer": "D", "explanation": "A、B选项,债务人偿还债务是基于债权,C选项养子女给付赡养费是基于其负有的赡养义务,以上均是依据法律规定应当得到的利益,不属于不当得利;D选项售货员多收货款属于不当得利,因此D选项正确。", "type": "single", "topic": "专题一 民法典总则编", "page": 15, "subject": "相关法", "id": "xg_39"},
  {"question": "5. 根据民法典总则编及相关规定，下列哪些情形下当事人获得的利益构成不当得利?(单选)", "options": ["A. 居民何某位于地铁沿线的商品房因地铁通车大幅度升值", "B. 乙公司接收了物流公司误送的甲公司的货物", "C. 蒋某走失的宠物狗得到石某的喂养、照顾", "D. 李某屋内的积水由邻居帮助排出"], "answer": "B", "explanation": "A选项，何某的收益属于自然增值，不构成不当得利。B选项，乙公司接收误送的货物没有合法根据，属于不当得利。C选项属于无因管理，不构成不当得利。D选项属于邻里互助，不构成不当得利。(2011)", "type": "single", "topic": "专题一 民法典总则编", "page": 16, "subject": "相关法", "id": "xg_40"},
  {"question": "6. 根据民法典总则编对知识产权的相关规定，以下属于知识产权客体的是?(多选)", "options": ["A. 发明", "B. 网络虚拟财产", "C. 商业秘密", "D. 个人信息"], "answer": "AC", "explanation": "A、C选项，《民法典》第123条第2款规定：“知识产权是权利人依法就下列客体享有的专有的权利：……;(二)发明、实用新型、外观设计；……;(五)商业秘密；……”，因此A、C选项正确。B选项网络虚拟财产属于财产权，D选项个人信息属于人身权，均不属于知识产权客体，因此B、D选项错误。(2018)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 16, "subject": "相关法", "id": "xg_41"},
  {"question": "7. 甲公司向法院起诉乙公司产品侵犯其专利权，法院未作出判决前，甲公司在社交媒体上对乙公司产品侵犯其专利权的情况进行了宣传，根据民法典总则编规定，甲公司的行为侵犯了乙公司的哪项权利?(单选)", "options": ["A. 名誉权", "B. 荣誉权", "C. 隐私权", "D. 名称权 第五章 民事法律行为"], "answer": "A", "explanation": "甲公司在法院未判决前，就在社交媒体上宣传乙公司产品侵犯其专利权，可能会使公众对乙公司的商业信誉、产品声誉产生负面评价，侵犯了乙公司的名誉权。(新编)", "type": "single", "topic": "专题一 民法典总则编", "page": 16, "subject": "相关法", "id": "xg_42"},
  {"question": "6. 甲和乙签订了两份房屋买卖合同，第一份约定房屋价款500万元，注明房屋过户备案事项不按此合同履行。第二份合同约定房屋价款200万元，房屋过户备案事项按此合同履行。关于两份合同，下列哪一选项正确？(单选)", "options": ["A. 第一份合同部分无效，第二份合同无效", "B. 第一份合同有效，第二份合同部分无效", "C. 两份合同均无效", "D. 两份合同均有效"], "answer": "B", "explanation": "《民法典》第146条规定：“行为人与相对人以虚假的意思表示实施的民事法律行为无效。以虚假的意思表示隐藏的民事法律行为的效力，依照有关法律规定处理。”虚假的意思表示以及隐藏的民事法律行为常表现为“阴阳合同”。本题中，甲乙二人为房屋过户备案事项签订的第二份合同为“阳合同”。该合同中关于“房屋价款200万元”的约定系虚假的意思表示，该合同中有关价款的部分无效。以虚假的意思表示隐藏的民事法律行为的效力，即“阴合同”，本题中第一份房屋买卖合同为甲乙二人真实的意思表示，该份合同有效。因此，B选项正确。(法考2020，思维扩展)", "type": "single", "topic": "专题一 民法典总则编", "page": 18, "subject": "相关法", "id": "xg_43"},
  {"question": "7. 下列属于可撤销合同情形的是？(单选)", "options": ["A. 违反法律法规强制规定的", "B. 以恶意串通损害他人利益的", "C. 因重大误解签订的", "D. 以虚假的意思表示签订的"], "answer": "C", "explanation": "A选项，违反法律、行政法规的强制性规定的民事法律行为无效。B选项，恶意串通损害他人利益的民事法律行为无效。C选项，基于重大误解实施的民事法律行为可撤销。D选项，以虚假的意思表示实施的民事法律行为无效。(新编)", "type": "single", "topic": "专题一 民法典总则编", "page": 18, "subject": "相关法", "id": "xg_44"},
  {"question": "8. 根据民法典及相关规定，下列哪些属于当事人可以请求人民法院撤销的合同？(多选)", "options": ["A. 甲公司与乙公司恶意串通签订的损害丙公司利益的买卖合同", "B. 贾某以欺诈的手段使齐某在违背真实意思的情况下与之订立的买卖合同", "C. 韩某把一个古董花瓶错当成现代仿制花瓶与赵某签订的买卖合同", "D. 非法垄断技术的技术合同"], "answer": "BC", "explanation": "A选项恶意串通损害他人利益的民事法律行为无效。B选项，以欺诈手段", "type": "multiple", "topic": "专题一 民法典总则编", "page": 18, "subject": "相关法", "id": "xg_45"},
  {"question": "10. 王某明知自己某项专利技术落入他人专利保护范围，仍与不知情的甲公司签订专利权转让合同，并隐瞒了专利侵权的问题。根据民法典及相关规定，下列关于该合同效力的说法哪个是正确的？(单选)", "options": ["A. 有效", "B. 无效", "C. 效力待定", "D. 可撤销"], "answer": "D", "explanation": "本题中，王某隐瞒专利侵权的事实，构成欺诈，基于欺诈所签订的合同属于可撤销的合同，因此A、B、C选项错误，D选项正确。(2019)", "type": "single", "topic": "专题一 民法典总则编", "page": 19, "subject": "相关法", "id": "xg_46"},
  {"question": "11. 金某家中有一块祖传玉佩。当地著名企业家孟某甚是喜爱，多次上门求购，均被金某拒绝。2022年2月1日，孟某的生意伙伴曹某为讨孟某欢心，对金某讲：“三日内不将玉佩卖给孟某，小心金某在某高中上学的女儿”。金某心生恐惧，次日主动以5万元出售给孟某。2025年3月2日，女儿留学德国，金某再无后顾之忧，于3月10日向法院起诉要求撤销玉佩买卖合同。关于本案，下列哪一说法是正确的？(多选)", "options": ["A. 无论孟某是否知道曹某胁迫金某一事，金某均有权请求撤销与孟某的玉佩买卖合同", "B. 只有当孟某知道曹某胁迫金某一事，金某才有权请求撤销与孟某的玉佩买卖合同", "C. 金某基于受胁迫撤销玉佩买卖合同的权利因超过1年除斥期间而不予支持", "D. 金某最迟应当自2022年2月2日起五年内行使撤销权"], "answer": "AD", "explanation": "根据《民法典》第150条的规定：“一方或者第三人以胁迫手段，使对方在违背真实意思的情况下实施的民事法律行为，受胁迫方有权请求人民法院或者仲裁机构予以撤销。”本题属于第三人胁迫，第三人实施胁迫行为不论相对人是否知情，受胁迫方都可以行使撤销权。曹某以金某上高中的女儿相威胁，金某出于恐惧心理，将祖传玉佩出售给了孟某。曹某实施的胁迫行为不论孟某是否知情，金某均有权要求撤销其与孟某间的买卖合同，因此A选项正确，B选项错误。根据《民法典》第152条的规定，当事人受胁迫，自胁迫行为终止之日起一年内没有行使撤销权的，撤销权消灭。当事人自民事法律行为发生之日起五年内没有行使撤销权的，撤销权消灭。本题中，金某的女儿2025年3月2日出国留学，胁迫行为终止，因此，金某起诉时并未超过除斥期间，C选项错误。金某受胁迫将玉佩出售给孟某的时间为2022年2月2日，因此金某应当自该行为发生之日起5年内行使撤销权，D选项正确。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 19, "subject": "相关法", "id": "xg_47"},
  {"question": "12. 齐某扮成建筑工人模样，在工地旁摆放一尊廉价购得的旧蟾蜍石雕，冒充新挖出文物等待买主。甲曾以5000元从齐", "options": ["A. 乙可向甲主张撤销其购买行为", "B. 乙可向齐某主张撤销其购买行为", "C. 甲不得向齐某主张撤销其购买行为", "D. 乙的撤销权自购买行为发生之日起1年内不行使则消灭"], "answer": "B", "explanation": "A、B、C选项，甲实施欺诈行为，使乙在违背真实意思的情况下以5000元购买了齐某的石雕，齐某在场却未作反对表示，应认定为其知道甲实施欺诈行为，受欺诈方乙可以请求法院或仲裁机构撤销与齐某的购买行为，因此A、C选项错误，B选项正确。D选项，《民法典》第152条规定：“……当事人自民事法律行为发生之日起5年内没有行使撤销权的，撤销权消灭”，D选项错误。（法考2017）", "type": "single", "topic": "专题一 民法典总则编", "page": 19, "subject": "相关法", "id": "xg_48"},
  {"question": "13. 乙公司以国产牛肉为样品，伪称某国进口牛肉，与甲公司签订了买卖合同，后甲公司得知这一事实。此时恰逢某国流行疯牛病，某国进口牛肉滞销，国产牛肉价格上涨。下列哪些说法是正确的？(多选)", "options": ["A. 甲公司有权自知道样品为国产牛肉之日起一年内主张撤销该合同", "B. 乙公司有权自合同订立之日起一年内主张撤销该合同", "C. 甲公司有权决定履行该合同，乙公司无权拒绝履行", "D. 在甲公司决定撤销该合同前，乙公司有权按约定向甲公司要求支付货款"], "answer": "ACD", "explanation": "A、B选项，乙公司以国产牛肉伪称某国进口牛肉的行为构成欺诈，受欺诈方即甲公司有权向法院主张撤销合同，欺诈方乙公司则无此权利，受欺诈方应当自知道或应当知道撤销事由之日起1年内行使撤销权，因此A选项正确，B选项错误。C、D选项，可撤销的民事法律行为（合同）在没有被撤销前是有效的，因此，甲公司有权决定履行该合同，乙公司无权拒绝，乙公司履行合同后也有权按约定向甲公司要求支付货款，因此C、D选项正确。(法考2009)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 20, "subject": "相关法", "id": "xg_49"},
  {"question": "14. 王某与张某签订了一个二手汽车买卖合同，但王某隐瞒了该汽车存在重大质量瑕疵的情况。根据民法典及相关规定，下列说法哪些是正确的？(多选)", "options": ["A. 张某有权请求人民法院确认该买卖合同无效", "B. 张某有权请求人民法院撤销该买卖合同", "C. 张某有权请求仲裁机构确认该买卖合同无效", "D. 张某有权请求仲裁机构撤销该买卖合同"], "answer": "BD", "explanation": "本题中，王某隐瞒了该汽车存在重大质量瑕疵，属于欺诈行为，根据《民法典》第148条的规定，张某有权请求人民法院或仲裁机构撤销该买卖合同，因此A、C选项错误，B、D选项正确。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 20, "subject": "相关法", "id": "xg_50"},
  {"question": "16. 某日，李某醉酒搭乘出租车回家，车程20公里。李某下车前用手机支付车费，误将80元输错成8080元。司机收到后，未提醒李某。对此，下列哪些选项是正确的？（多选）", "options": ["A. 该运输合同因显失公平而可撤销", "B. 对于多付的8000元视为李某对司机的赠与", "C. 醉酒不影响该运输合同的效力", "D. 李某有权请求出租车司机返还8000元不当得利"], "answer": "CD", "explanation": "A、C选项，显失公平，是指一方利用对方处于危困状态、缺乏判断能力等情形，致使民事法律行为成立时显失公平。李某醉酒打车，与出租车公司订立了运输合同。出租车公司的司机并未利用李某因醉酒而缺乏判断力与其实施显失公平的民事法律行为。因此，不影响该运输合同的效力，A选项错误，C选项正确。B、D选项，不当得利是指，因他人没有法律根据，取得不当利益，受损失的人有权请求其返还。李某将8000元给予司机欠缺法律上的依据，且李某并无赠予的意思表示，李某与司机之间构成了不当得利之债，受损害方李某有权要求司机返还，因此B选项错误，D选项正确。（法考2020）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 21, "subject": "相关法", "id": "xg_51"},
  {"question": "17. 某日，古玩爱好者王某在本地经常光顾的古玩街花费数万元购买了一对青铜烛台，疑为明代真品。后经鉴定，该烛台为现代仿品，仅值数百元，对此，下列哪一说法是正确的？（单选）", "options": ["A. 王某可主张存在重大误解，请求撤销合同", "B. 王某意思表示真实有效，无权请求撤销合同", "C. 王某可主张存在显失公平，请求撤销合同", "D. 王某可主张其被出卖人欺诈，请求撤销合同 - 20 -"], "answer": "B", "explanation": "重大误解，是指行为人对行为的性质、对方当事人或标的物的品种、质量、规格、价格、数量等产生错误认识，按照通常理解如果不发生该错误认识行为人就不会作出相应意思表示。本题中，双方当事人交易的标的物是“古玩”，属于特殊商品，由买受人通过实物查看，自行判断商品价值，并与出卖人达成交易合意，即便买受人确实对商品价值存在误判，也不构成法律上所认可的重大误解。因此，A项错误；B项正确。C选项，虽然王某花费数万元购买了仅值数百元的青铜烛台，客观上价格相差悬殊。但是，主观上，出卖人并未“利用”王某处于危困状态、缺乏判断能力。因此，不符合显失", "type": "single", "topic": "专题一 民法典总则编", "page": 21, "subject": "相关法", "id": "xg_52"},
  {"question": "18. 根据民法典总则编及相关规定，下列哪些说法是正确的？(多选)", "options": ["A. 在订立合同时显失公平的，受损害方有权请求人民法院或者仲裁机构撤销", "B. 合同被依法撤销的，该合同自人民法院判决撤销之日起丧失法律约束力", "C. 合同部分无效，不影响其他部分效力的，其他部分仍然有效", "D. 合同被撤销后，因该合同取得的财产应当予以返还；不能返还或者没有必要返还的，应当折价补偿"], "answer": "ACD", "explanation": "A选项，根据《民法典》第151条的规定，显失公平的民事法律行为，受损害方有权请求人民法院或者仲裁机构予以撤销，因此A选项正确。B选项，《民法典》第155条规定：“无效的或者被撤销的民事法律行为自始没有法律约束力”，因此B选项错误。C选项，《民法典》第156条规定：“民事法律行为部分无效，不影响其他部分效力的，其他部分仍然有效”，因此C选项正确。D选项，《民法典》第157条规定：“民事法律行为无效、被撤销或者确定不发生效力后，行为人因该行为取得的财产，应当予以返还；不能返还或者没有必要返还的，应当折价补偿……”，因此D选项正确。(2017)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 22, "subject": "相关法", "id": "xg_53"},
  {"question": "19. 根据民法典总则编及相关规定，关于无效、被撤销的民事行为，下列说法正确的是？(多选)", "options": ["A. 无效的民事行为从行为开始起就没有法律约束力", "B. 无效的民事行为从人民法院确认无效之日起没有法律约束力", "C. 被撤销的民事行为从人民法院撤销该民事行为之日起没有法律约束力", "D. 被撤销的民事行为从行为开始起就没有法律约束力"], "answer": "AD", "explanation": "根据《民法典》第155条的规定，无效的或者被撤销的民事法律行为自始没有法律约束力，因此A、D选项正确，B、C选项错误。(2019)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 22, "subject": "相关法", "id": "xg_54"},
  {"question": "20. 根据民法典总则编及相关规定，下列关于可撤销合同的哪些说法是正确的？(多选)", "options": ["A. 因重大误解订立的合同，行为人有权请求人民法院或者仲裁机构撤销", "B. 合同被依法撤销的，该合同自人民法院判决撤销之日起丧失法律约束力", "C. 因重大误解订立的合同，具有撤销权的当事人自知道或者应当知道撤销事由之日起90日内没有行使撤销权的，撤销权消灭", "D. 当事人自民事法律行为发生之日起一年内没有行使撤销权的，撤销权消灭"], "answer": "AC", "explanation": "A选项，基于重大误解订立的合同，行为人有权请求人民法院或者仲裁机构予以撤销，因此A选项正确。B选项，无效的或者被撤销的民事法律行为自始没有法律约束力，因此B选项错误。C选项，《民法典》第152条规定，重大误解的当事人自知道或者应当知道撤销事由之日起90日内没有行使撤销权的，撤销权消灭，因此C选项正确。D选项，当事人自民事法律行为发生之日起5年内没有行使撤销权的，撤销权消灭，因此D选项错误。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 22, "subject": "相关法", "id": "xg_55"},
  {"question": "25. 张某在某专利代理事务所实习,表现优异。该事务所与张某达成约定,如果张某一年内通过专利代理师资格考试,将资助其出国进修三个月。根据民法典总则编及相关规定,在张某通过专利代理师资格考试之前,下列说法正确的是?(多选)", "options": ["A. 该约定既未成立,也未生效", "B. 该约定已经成立,但未生效", "C. 该约定是附期限的民事法律行为", "D. 该约定是附条件的民事法律行为"], "answer": "BD", "explanation": "本题中,事务所与张某达成约定时该约定已经成立,但未生效,所附生效条件为张某一年内通过专利代理师资格考试,若该条件成就,则该约定生效,资助张某出国进修三个月,因此A、C选项错误,B、D选项正确。此题考生疑问较多,此处做进一步说明区分:附条件是不确定的偶然性事实,附期限是确定的必然性事实。本题中“一年内通过专代考试”,属于不确定的条件,如果题目改为“2026年12月资助出国进修3个月”则因期限是明确的时间点,是一定会到来的,则为附期限的民事法律行为。故此题应为附条件,而不是附期限。(2019)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 24, "subject": "相关法", "id": "xg_56"},
  {"question": "26. 2020年11月1日,李某和赵某签订房屋租赁合同,约定2021年3月1日该合同生效。根据民法典总则编及相关规定,下列关于该合同的哪种说法是正确的?(单选)", "options": ["A. 该合同为附生效期限的合同", "B. 该合同为附终止期限的合同", "C. 该合同为附生效条件的合同", "D. 该合同为附解除条件的合同"], "answer": "A", "explanation": "本题中,李某和赵某的合同约定于2021年3月1日生效,属于附生效期限的合同,因此A选项正确,B、C、D选项错误。(2016改编)", "type": "single", "topic": "专题一 民法典总则编", "page": 24, "subject": "相关法", "id": "xg_57"},
  {"question": "27. 刘某与史某约定,如将来刘某不在甲公司上班,刘某即将其在甲公司附近一套自有公寓卖给史某。史某为尽快购得该房屋,贿赂甲公司经理,让其辞退了刘某。刘某和史某关于刘某不在甲公司上班的约定,下列哪一说法是正确的?(多选)", "options": ["A. 该约定属于附生效条件的约定", "B. 该约定属于附生效期限的约定", "C. 应视为条件不成就", "D. 应视为约定无效"], "answer": "AC", "explanation": "刘某与史某约定不在甲公司上班,将公寓卖给史某,属于附条件生效的约定,因此A选项正确,B选项错误。《民法典》第159条规定:“附条件的民事法律行为,当事人为自己的利益不正当地阻止条件成就的,视为条件已经成就;不正当地促成条件成就的,视为条件不成就”,史某贿赂公司经理让刘某被辞退,属于不正当促进条件成就,因此C选项正确,D选项错误。(法考2020)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 24, "subject": "相关法", "id": "xg_58"},
  {"question": "1. 甲和乙为丙的连带债务人。后甲和乙约定，甲负责偿还60%的债务，乙负责偿还40%的债务。对此，根据民法典总则编的规定，下列哪些说法是正确的？（多选）", "options": ["A. 丙可以要求甲偿还全部债务", "B. 丙可以要求乙偿还全部债务", "C. 甲偿还了全部债务后，有权要求乙偿付其应当承担的40%的债务", "D. 甲有权拒绝偿还超过60%的债务"], "answer": "ABC", "explanation": "本题中，甲、乙为连带债务人，丙为债权人，丙有权要求甲或乙清偿全部债务，甲和乙都负有清偿全部债务的义务，甲偿还了全部债务后，有权要求乙偿付乙应当承担的40%的债务，甲和乙之间对债务偿还的约定不得对抗债权人丙，因此A、B、C选项正确，D选项错误。（2007）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 30, "subject": "相关法", "id": "xg_59"},
  {"question": "2. 根据民法典总则编及相关规定，下列哪些属于承担民事责任的方式？（多选）", "options": ["A. 继续履行", "B. 恢复原状"], "answer": "ABCD", "explanation": "《民法典》第179条第1款规定：“承担民事责任的方式主要有：（一）停止侵害……（五）恢复原状……（七）继续履行……（十）……恢复名誉……”，因此A、B、C、D选项均正确。（新编）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 30, "subject": "相关法", "id": "xg_60"},
  {"question": "1. 根据民法典总则编及相关规定，下列关于诉讼时效期间的哪种说法是错误的？(单选)", "options": ["A. 向人民法院请求保护民事权利的诉讼时效期间为3年，法律另有规定的除外", "B. 诉讼时效期间自权利人知道或者应当知道权利受到损害以及义务人之日起计算"], "answer": "D", "explanation": "《民法典》第188条规定：“向人民法院请求保护民事权利的诉讼时效期间为三年。法律另有规定的，依照其规定。诉讼时效期间自权利人知道或者应当知道权利受到损害以及义务人之日起计算。法律另有规定的，依照其规定。但是，自权利受到", "type": "single", "topic": "专题一 民法典总则编", "page": 31, "subject": "相关法", "id": "xg_61"},
  {"question": "3. 根据民法典总则编及相关规定，下列哪些属于侵犯知识产权的民事责任承担方式？(多选)", "options": ["A. 赔偿损失", "B. 没收违法所得", "C. 停止侵害", "D. 消除影响"], "answer": "ABCD", "explanation": "侵犯物权应负的法律责任包括：返还原物；排除妨碍；消除危险；请求修理、重作、更换；恢复原状；损害赔偿，因此A、B、C、D选项均正确。（2019）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 31, "subject": "相关法", "id": "xg_62"},
  {"question": "4. 根据民法典总则编及相关规定，下列哪些属于法定减轻或免除民事责任的情形？(多选)", "options": ["A. 不可抗力", "B. 紧急避险", "C. 正当防卫", "D. 紧急救助"], "answer": "ABCD", "explanation": "A选项，《民法典》第180条第1款规定：“因不可抗力不能履行民事义务的，不承担民事责任”，因此A选项正确。B选项，《民法典》第182条第1款规定：“因紧急避险造成损害的，由引起险情发生的人承担民事责任”，因此B选项正确。C选项，《民法典》第181条规定：“因正当防卫造成损害的，不承担民事责任”，因此C选项正确。D选项，《民法典》第184条规定：“因自愿实施紧急救助行为造成受助人损害的，救助人不承担民事责任”，因此D选项正确。(2018)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 31, "subject": "相关法", "id": "xg_63"},
  {"question": "5. 何某被恶狗咬，马某用吕某的雨伞打狗，伞坏人伤。经查，恶狗为赵某所豢养。关于本案，下列哪些说法是正确的？(多选)", "options": ["A. 马某的医疗费应由何某赔偿", "B. 马某的医疗费应由赵某赔偿", "C. 吕某的雨伞损害应由马某赔偿", "D. 吕某的雨伞损害应由赵某赔偿 第八章 诉讼时效"], "answer": "BD", "explanation": "A、B选项，《民法典》第183条规定：“因保护他人民事权益使自己受到损害的，由侵权人承担民事责任，受益人可以给予适当补偿。没有侵权人、侵权人逃逸或者无力承担民事责任，受害人请求补偿的，受益人应当给予适当补偿”，马某的行为属于见义勇为，马某的损失应由侵权人赵某赔偿，何某作为受益人，其责任为适当补偿责任，而非赔偿责任，因此A选项错误，B选项正确。C、D选项，因紧急避险造成损害的，由引起险情发生的人承担民事责任，马某用吕某的雨伞打狗，构成紧急避险，吕某的损失也应由引起险情发生的人赵某赔偿，因此C选项错误，D选项正确。(法考2018)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 31, "subject": "相关法", "id": "xg_64"},
  {"question": "6. 甲从其朋友乙处购买一件古董花瓶，约定乙于甲付款后5日内交付花瓶。甲于2018年2月8日付款后，乙一直未交付该花瓶。甲于2021年10月向人民法院起诉，要求乙交付该花瓶。乙得知后，主动将该花瓶交给甲，甲撤诉。后乙反悔，以甲的起诉超过诉讼时效期间为由向人民法院起诉，要求甲返还该花瓶。对此，下列哪些说法是正确的？(多选)", "options": ["A. 甲的起诉超过诉讼时效期间", "B. 甲获得该花瓶属于不当得利", "C. 人民法院对乙的诉讼请求应当不予支持", "D. 人民法院对乙的诉讼请求应当予以支持"], "answer": "AC", "explanation": "甲于2018年2月8日得知其权利受到损害，于2021年10月起诉已超过诉讼时效三年期限，因此A选项正确。B、C、D选项，《民法典》第192条第2款规定：“诉讼时效期间届满后，义务人同意履行的，不得以诉讼时效期间届满为由抗辩；义务人已经自愿履行的，不得请求返还”，甲获得该花瓶不属于不当得利，人民法院对乙的诉讼请求应当不予支持，因此B、D选项错误，C选项正确。(2008)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 33, "subject": "相关法", "id": "xg_65"},
  {"question": "7. 根据民法典总则编及相关规定，下列关于诉讼时效的哪项说法是正确的？(单选)", "options": ["A. 诉讼时效因提起诉讼而中断，从中断的原因消除之日起，诉讼时效期间继续计算", "B. 诉讼时效中止的，从中止时效的原因消除之日起，诉讼时效期间重新计算", "C. 超过诉讼时效期间，当事人自愿履行的，不受诉讼时效限制", "D. 超过诉讼时效期间，义务人履行义务后又以超过诉讼时效为由反悔的，应当予以支持"], "answer": "C", "explanation": "A选项，诉讼时效中断，从中断、有关程序终结时起，诉讼时效期间重新计算，A选项错误。B选项，自中止时效的原因消除之日起满六个月，诉讼时效期间届满，因此B选项错误。C、D选项，诉讼时效期间届满后，义务人同意履行的，不得以诉讼时效期间届满为由抗辩；义务人已经自愿履行的，不得请求返还，因此C选项正确，D选项错误。(新编)", "type": "single", "topic": "专题一 民法典总则编", "page": 33, "subject": "相关法", "id": "xg_66"},
  {"question": "8. 甲乙是夫妻，育有一子丙(4岁)。后甲、乙因感情不和协议离婚，双方约定儿子丙归甲抚养。后甲沉迷赌博，时常殴打丙，并将甲母赠与丙的两块玉佩卖掉做赌资。对此，下列哪些说法正确？(多选)", "options": ["A. 乙可以申请法院撤销甲的监护权", "B. 丙可以请求甲承担赔偿损失", "C. 丙对甲殴打致损的赔偿请求权不受诉讼时效的限制", "D. 丙对甲卖掉玉佩的赔偿请求权诉讼时效期间为自丙知"], "answer": "AB", "explanation": "A选项，甲乙虽离婚，但乙并未丧失监护权，甲在监护期间实施了侵害被监护人的行为，乙可以请求法院撤销甲的监护权，因此A选项正确。B选项，甲殴打丙且卖掉了丙的玉佩，侵害了丙的合法权益，丙可以请求甲承担赔偿责任，因此B选项正确。C选项，丙对殴打及卖掉玉佩的赔偿请求权的诉讼时效为3年，从法定代理终止起算，因此C、D选项错误。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 33, "subject": "相关法", "id": "xg_67"},
  {"question": "1. 根据民法典总则编及相关规定,非法人组织享有下列哪些民事权利?(多选)", "options": ["A. 隐私权", "B. 健康权", "C. 名誉权", "D. 名称权"], "answer": "CD", "explanation": "《民法典》第110条规定:“自然人享有生命权、身体权、健康权、姓名权、肖像权、名誉权、荣誉权、隐私权、婚姻自主权等权利。法人、非法人组织享有名称权、名誉权和荣誉权”,因此A、B选项错误,C、D选项正确。(2019)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 15, "subject": "相关法", "id": "xg_68"},
  {"question": "王某将房子租给甲公司，甲公司在装修时砸开了房子的承重墙，导致整栋楼墙体开裂，其行为违背了下列哪一原则？（单选）", "options": ["A. 公平原则", "B. 平等原则", "C. 公序良俗原则", "D. 诚信原则"], "answer": "C", "explanation": "本题在C、D两项之间争议较大。公序良俗包括不得违反公共秩序和不得违反善良风俗。对社会公共利益而言，甲公司的行为违反了公序良俗原则，C选项正确。但是有学员认为，对王某而言，甲公司砸墙行为违背了诚信原则，也有一定道理。本题为单选题，从题目敘述文字看，还是应当考量对社会公共利益而言甲公司的行为违背了哪个原则，本题选C的更符合出题人的想法。", "type": "single", "topic": "专题一 民法典总则编", "page": 8, "subject": "相关法", "id": "xg_69"},
  {"question": "一般情况下，自然人的出生时间和死亡时间，以______记载的时间为准。（单选）", "options": ["A. 出生证明、死亡证明", "B. 户籍登记证明、死亡证明"], "answer": "A", "explanation": "《民法典》第15条规定：‘自然人的出生时间和死亡时间，以出生证明、死亡证明记载的时间为准；没有出生证明、死亡证明的，以户籍登记或者其他有效身份登记记载的时间为准。有其他证据足以推翻以上记载时间的，以该证据证明的时间为准’。", "type": "single", "topic": "专题一 民法典总则编", "page": 8, "subject": "相关法", "id": "xg_70"},
  {"question": "甲、乙为夫妻关系。后甲与丙发生婚外情，双方签订协议，约定甲支付丙100万元，丙不得要求甲离婚，以后某一方丧失行为能力时另一方为监护人。关于该协议，下列说法正确的是？(多选)", "options": ["A. 该协议构成无处分权", "B. 该协议监护部分有效", "C. 该协议违反公序良俗原则", "D. 甲和丙就监护人的约定为意定监护，受法律保护"], "answer": "AC", "explanation": "A选项，甲协议支付给丙的钱属于夫妻共有财产，构成无处分权，因此A选项正确。B、C、D选项，甲与丙的协议违背公序良俗，属于无效的协议，因此B、D选项错误，C选项正确。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 14, "subject": "相关法", "id": "xg_71"},
  {"question": "关于刁某的行为，下列哪一说法是正确的？(单选)", "options": ["A. 应向刘某家人给付5万元", "B. 应向刘某家人给付3万元", "C. 应向刘某家人给付4万元", "D. 应向刘某家人给付3.5万元"], "answer": "D", "explanation": "刁某的行为属于无因管理，根据《民法典》第121条规定，有权请求受益人偿还由此支出的必要费用。刁某花费1万元办理后事，摘卖西瓜工费及其他必要费用共5000元，共计1.5万元。刁某认为自己应得劳务费5000元，因此应向刘某家人给付的金额是收益5万元减去必要费用1.5万元和劳务费5000元，即3.5万元。", "type": "single", "topic": "专题一 民法典总则编", "page": 23, "subject": "相关法", "id": "xg_72"},
  {"question": "甲对乙承诺，如乙比赛夺冠，乙出国旅游时甲将陪同，后乙果然夺冠，甲失约。乙要求甲承担赔偿责任", "options": ["A. 自愿", "B. 公平", "C. 等价有偿", "D. 诚信"], "answer": "D", "explanation": "根据民法典总则编及相关规定，民事活动应当遵循自愿、公平、等价有偿、诚信等原则。本题中甲对乙的承诺属于民事法律行为，甲失约违背了诚信原则，因此乙有权要求甲承担赔偿责任。", "type": "single", "topic": "专题一 民法典总则编", "page": 7, "subject": "相关法", "id": "xg_73"},
  {"question": "根据民法典总则编及相关规定，民事活动应当遵循哪些原则？（多选）", "options": ["A. 自愿", "B. 公平", "C. 等价有偿", "D. 诚信"], "answer": "ABD", "explanation": "民事活动应当遵循自愿、公平、诚信等原则。等价有偿原则主要适用于合同关系，不是所有民事活动都必须遵循的原则。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 7, "subject": "相关法", "id": "xg_74"},
  {"question": "蒋男与韩女在离婚协议中约定：为了专心抚养育婴女蒋小萍，韩女将来若与他人结婚，不得再生育孩子。该约定因违反下列哪一原则而无效？（单选）", "options": ["A. 自愿原则", "B. 公序良俗原则", "C. 公平原则", "D. 平等原则"], "answer": "B", "explanation": "离婚协议中的约定不能违反公序良俗原则。公序良俗原则是指民事法律行为不得违反社会公共利益和良好风俗。限制再生育的约定违反了社会公共利益和良好风俗，因此无效。", "type": "single", "topic": "专题一 民法典总则编", "page": 7, "subject": "相关法", "id": "xg_75"},
  {"question": "甲接受赠与的行为无效，因为其是限制民事行为能力人", "options": ["A. 甲接受赠与的行为无效，因为其是限制民事行为能力人", "B. 甲接受赠与的行为有效", "C. 丙的转赠行为有效，因为已经得到乙的同意", "D. 丙无权处理甲受赠的助学款"], "answer": "BD", "explanation": "本题中，12周岁小学生甲属于限制民事行为能力人，其接受乙的捐赠属于纯获利益的行为，因此甲接受赠与的行为有效，A选项错误，B选项正确。由于小学生甲是限制民事行为能力人，其实施转赠的行为应由其法定代理人代理或者经其法定代理人同意、追认，因此即使乙表示赞同，丙也无权处理甲受赠的助学款，C选项错误，D选项正确。(2013改编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 10, "subject": "相关法", "id": "xg_76"},
  {"question": "肖特有音乐天赋，16岁便不再上学，以演出收入为主要生活来源。肖特成长过程中，多有长辈馈赠：7岁时受赠口琴1个，9岁时受赠钢琴1架，16岁赠送其他演奏者名贵小提琴1把。对肖特行为能力及其受赠、赠与行为效力的判断，根据《民法典》总则编及相关规定，下列哪一选项是正确的？（单选）", "options": ["A. 肖特尚不具备完全的民事行为能力", "B. 受赠口琴的行为无效，应由其法定代理人代理实施", "C. 受赠钢琴的行为无效，因与其当时的年龄智力不相当", "D. 赠送小提琴的行为无效，因与其当时的年龄智力不相当"], "answer": "B", "explanation": "A、D选项，肖特16周岁以演出收入为主要生活来源，应视为完全民事行为能力人，赠与行为有效，因此A、D选项错误。B选项，肖特7周岁受赠口琴时属于无民事行为能力人，其独立实施的民事法律行为一律无效，应由其法定代理人代理实施，因此B选项正确。C选项，肖特9岁受赠钢琴时属于限制民事行为能力人，受赠钢琴的行为系纯获利益，该民事法律行为有效，因此C选项错误。(法考2017改编)", "type": "single", "topic": "专题一 民法典总则编", "page": 10, "subject": "相关法", "id": "xg_77"},
  {"question": "关于监护，下列哪一表述是正确的？（单选）", "options": ["A. 甲委托医院照料其患精神病的配偶乙，医院是受委托监护人", "B. 甲的幼子乙在寄宿制幼儿园期间，甲的监护职责全部转移给幼儿园", "C. 甲丧夫后携幼子乙改嫁，乙的爷爷有权要求法院确定自己为乙的法定监护人", "D. 市民甲、乙之子丙5周岁，甲乙离婚后对谁担任丙的监护人发生争议，两住地的居民委员会有权指定"], "answer": "A", "explanation": "《民法典》第31条规定：“对监护人的确定有争议的，由监护人协商解决；协商不成的，由人民法院指定监护人。”因此C选项正确。", "type": "single", "topic": "专题一 民法典总则编", "page": 11, "subject": "相关法", "id": "xg_78"},
  {"question": "15日向通州区人民法院申请宣告刘某死亡。下列哪些说法是错误的？（多选）", "options": ["A. 如果刘某的妻子不宣告刘某死亡，刘某的父母不能申请宣告刘某死亡", "B. 刘某的父母申请宣告刘某死亡时刘某下落不明满4年，不符合宣告死亡的要求", "C. 如通州区法院宣告刘某死亡，则判决作出之日视为刘某死亡的日期", "D. 如通州区法院宣告刘某死亡但是刘某并未死亡，在被宣告死亡期间刘某所实施的民事法律行为均有效"], "answer": "ABD", "explanation": "根据民法典的规定，宣告死亡的申请可以由配偶、父母、子女等利害关系人提出，因此A项错误。刘某下落不明满4年，符合宣告死亡的要求，所以B项错误。宣告死亡的判决作出之日并不自动视为死亡日期，死亡日期应为法院宣告之日，因此C项正确。D项错误，因为被宣告死亡的人在被宣告死亡期间所实施的民事法律行为是无效的。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 16, "subject": "相关法", "id": "xg_79"},
  {"question": "企业法人甲公司的法定代表人赵某以甲公司名义从事经营活动，给他人造成了经济损失。根据民法典总则编及相关规定，应由谁就该经济损失承担民事责任？", "options": ["A. 赵某", "B. 甲公司", "C. 赵某和甲公司", "D. 赵某和甲公司均无须承担"], "answer": "B", "explanation": "根据民法典规定，企业法人应当对其法定代表人的行为承担责任。因此，甲公司作为法人，应当对其法定代表人赵某的行为造成的经济损失承担民事责任。", "type": "single", "topic": "专题一 民法典总则编", "page": 19, "subject": "相关法", "id": "xg_80"},
  {"question": "德胜公司注册地在北京，在中国深圳设有分支机构，德胜公司是一家由台湾地区凯旋集团公司全资设立的法人企业。由于决策失误，德胜公司的深圳分支机构欠下700万元债务。对此，下列哪一选项是正确的？", "options": ["A. 该债务应限于深圳分支机构的全部财产", "B. 该债务应以深圳分支机构和北京总部的全部财产清偿债务", "C. 无论德胜公司的全部财产能否清偿，凯旋公司都应承担连带责任", "D. 当德胜公司的全部财产不足清偿时，由凯旋公司承担补充责任"], "answer": "B", "explanation": "根据相关法律规定，分支机构的债务由设立该分支机构的企业法人承担。因此，德胜公司的债务应由其全部财产清偿，包括深圳分支机构和北京总部的财产。", "type": "single", "topic": "专题一 民法典总则编", "page": 19, "subject": "相关法", "id": "xg_81"},
  {"question": "2018年春节前夕，孟某的妻子刘某收拾房间时发现一件孟某穿了5年的旧大衣。刘某欲购买一件新衣服给孟某，遂将孟某的旧大衣扔到楼下的垃圾箱里。第二天，孟某问妻子刘某自己的大衣为何不见了。刘某说已经扔掉啦。孟某说：‘大衣里价值27500元的欧米茄手表拿出来了么？’，刘某说没有。经查，该大衣连同手表被同小区捡拾垃圾的徐老太捡走。关于本案，下列哪一说法是正确的？（单选）", "options": ["A. 刘某将孟某大衣扔掉的行为属于事实行为", "B. 大衣属于遗失物，徐老太应当返还", "C. 手表属于无主物，徐老太可以先占", "D. 徐老太应当返还手表，但大衣可以先占"], "answer": "D", "explanation": "A选项，事实行为是指行为人不具有设立、变更或消灭民事法律关系的意图，但依照行为的规定能引起民事法律后果的行为；刘某将孟某大衣扔掉的行为是动产所有权的抛弃，属于单方民事法律行为（依一方当事人的意思表示而成立的民事法律行为）而非事实行为，因此A选项错误。B、C、D选项，《民法典》第314条规定：‘拾得遗失物，应当返还权利人。拾得人应当及时通知权利人领取，或者送交公安等有关部门’，孟某的大衣被刘某抛弃后属于无主动产，徐老太可以基于先占而取得大衣的所有权，而刘某将孟某大衣扔掉时不存在抛弃欧米茄手表的意思表示，手表属于遗失物，徐老太拾得遗失物，依法应当返还，因此B、C选项错误，D选项正确。（法考2018）", "type": "single", "topic": "专题一 民法典总则编", "page": 24, "subject": "相关法", "id": "xg_82"},
  {"question": "单从合同的法律性质分析，赠与合同属于（ ）。（多选）", "options": ["A. 单务合同", "B. 要式合同", "C. 有偿合同", "D. 诺成性合同"], "answer": "AD", "explanation": "A选项，赠与合同仅一方负担义务，另一方仅享有权利，属于单务合同，因此A选项正确。B选项，赠与属于不拘形式的民事法律行为，当事人可以自由决定行为的形式，只要该行为意思表示合法，行为即可生效，因此赠与合同属于不要式合同，B选项错误。C选项，赠与合同无需受赠方支付报酬，属于无偿合同，因此C选项错误。D选项，赠与合同是基于双方意思表示一致成立，不以实际转移所有权为条件，属于诺成性合同，因此D选项正确。（新编）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 24, "subject": "相关法", "id": "xg_83"},
  {"question": "根据民法典总则编及相关规定，下列哪些情形构成意思表示？（多选）", "options": ["A. 孙某临终前在日记中写道：若离人世，愿将个人藏书赠与好友汪某", "B. 何某向一台自动售货机投币购买饮料", "C. 张某对李某说：我儿子如果考上重点大学，我一定请你喝酒", "D. 潘某在寻物启事中称，愿向送还失物者付酬金500元"], "answer": "ABD", "explanation": "A选项，孙某通过日记将其个人藏书赠与好友汪某的行为属于遗赠行为，构成意思表示。B选项，自动售货机的价格设置属于要约，购买人的投币行为属于承诺，因此何某向一台自动售货机投币购买饮料的行为构成意思表示。C选项，请客吃饭属于好意施惠，是日常生活中的人际交往情谊行为，张某的行为不构成意思表示。D选项，悬赏广告属于单方允诺的意思表示，潘某的行为构成意思表示。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 25, "subject": "相关法", "id": "xg_84"},
  {"question": "小倩（9岁）的父亲因坐牢与小倩母亲离婚，小倩母亲再婚生子后虐待小倩，小倩的祖父母想要成为其监护人。以下说法正确的有？（单选）", "options": ["A. 祖父母想要成为其监护人，需要向法院申请", "B. 因小倩母亲的虐待行为，祖父母自动成为监护人", "C. 祖父母想要成为其监护人，需要经小倩的父亲同意", "D. 祖父母想要成为其监护人，需要经民政部门同意"], "answer": "A", "explanation": "根据《民法典》第36条第1款的规定，监护人不履行监护职责时，有关个人或组织可以向法院申请撤销监护人资格，并指定监护人。本题中，在被监护人父母不能担任监护人的情况下，小倩祖父母需要向法院申请撤销其父母的监护权，再由法院指定其为监护人，而不能自动成为监护人，且无需其父母同意，也无需民政部门、居委会或村委会的同意，因此A选项正确，B、C、D选项错误。（法考2019）", "type": "single", "topic": "专题一 民法典总则编", "page": 12, "subject": "相关法", "id": "xg_85"},
  {"question": "甲公司为有限责任公司，总部设在青岛，在北京设有分公司，上海设有办事处，根据民法典总则编及相关规定，下列关于该公司住所的表述哪个是正确的？（单选）", "options": ["A. 甲公司的住所为青岛", "B. 甲公司的住所为北京", "C. 甲公司的住所为上海", "D. 青岛、北京和上海均是甲公司的住所"], "answer": "A", "explanation": "《民法典》第63条规定：‘法人以其主要办事机构所在地为住所’，青岛总部是甲公司的主要办事机构，因此甲公司的住所为青岛，A选项正确，B、C、D选项错误。（2019改编）", "type": "single", "topic": "专题一 民法典总则编", "page": 18, "subject": "相关法", "id": "xg_86"},
  {"question": "根据《民法典》第一编总则编第三章的规定，对法人分类包括：", "options": ["A. 社团法人、营利法人、机关法人", "B. 营利法人、非营利法人、特别法人", "C. 机关法人、企业法人、特别法人", "D. 企业法人、非营利法人、财团法人"], "answer": "B", "explanation": "根据《民法典》的规定，法人分为营利法人、非营利法人和特别法人。", "type": "single", "topic": "专题一 民法典总则编", "page": 20, "subject": "相关法", "id": "xg_87"},
  {"question": "黄大、黄二和黄三共同出资，拟设立名为“黄金黄研究会”的社会团体法人。设立过程中，黄大等3人以黄金黄研究会名义与某科技园签署了为期3年的商铺租赁协议，月租金5万元，押3付1。此外，黄三设立黄金黄研究会，以个人名义向某科技园的租赁权可向黄大等3人主张，黄大等3人承担连带债务。关于某科技园和某印刷厂的债权，下列哪些选项是正确的？(多选)", "options": ["A. 如黄金黄研究会未成立，则某科技园的租赁权消灭", "B. 即便黄金黄研究会未成立，某科技园就租赁权，仍可向黄大等3人主张", "C. 如黄金黄研究会未成立，则某科技园的租赁权消灭，黄大等3人承担连带债务", "D. 黄金黄研究会成立后，某印刷厂就租赁权，既可向黄金黄研究会主张，也可向黄大等3主张"], "answer": "BC", "explanation": "如果黄金黄研究会未成立，根据《民法典》的相关规定，黄大等3人作为发起人，需要承担连带责任。黄金黄研究会成立后，债权人可以向黄金黄研究会主张债权，也可以向发起人主张。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 20, "subject": "相关法", "id": "xg_88"},
  {"question": "贫困山区12周岁小学生甲接受乙捐助的5000元助学款，甲的老师将其中的2000元转赠给另一个小学生，并将此事告知了乙，乙表示赞同。据此，下列哪些说法是正确的？（多选）", "options": ["A. 自然人从出生时起到死亡时止，具有民事权利能力，依法享有民事权利，承担民事义务", "B. 自然人的民事权利能力一律平等", "C. 限制民事行为能力人可以进行与其年龄、智力相适应的民事活动", "D. 无民事行为能力人的民事活动由其法定代理人代理"], "answer": "ABCD", "explanation": "所有选项均正确。选项A正确，自然人从出生时起到死亡时止，具有民事权利能力，依法享有民事权利，承担民事义务。选项B正确，自然人的民事权利能力一律平等。选项C正确，限制民事行为能力人可以进行与其年龄、智力相适应的民事活动。选项D正确，无民事行为能力人的民事活动由其法定代理人代理。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 9, "subject": "相关法", "id": "xg_89"},
  {"question": "张某的监护权被撤销后，法院应当按照有利于被监护人的原则指定监护人", "options": ["A. 张某的监护权被撤销后，法院应当按照有利于被监护人的原则指定监护人", "B. 张某的监护权被撤销后，不可恢复"], "answer": "A", "explanation": "人的资格只能有法院撤销，因此A选项正确，B选项错误。C选项，张某的监护人资格被撤销后，李某监护权为当然监护，不涉及指定监护的问题，C选项错误。D选项，监护人因对被监护人故意犯罪，监护权被撤销后不能恢复，D选项正确。（新编）", "type": "single", "topic": "专题一 民法典总则编", "page": 13, "subject": "相关法", "id": "xg_90"},
  {"question": "监护人因发生突发事件等紧急情况暂时无法履行监护职责，被监护人的生活处于无人照料状态的，应当为被监护人安排必要的临时生活照料措施的组织有？（多选）", "options": ["A. 被监护人住所地的居委会", "B. 被监护人住所地的村委会", "C. 被监护人住所地的民政部门", "D. 被监护人住所地的学校"], "answer": "ABC", "explanation": "因发生突发事件等紧急情况，监护人暂时无法履行监护职责，被监护人的生活处于无人照料状态的，被监护人住所地的居民委员会、村民委员会或者民政部门应当为被监护人安排必要的临时生活照料措施”，因此A、B、C选项正确，D选项错误。（新编）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 13, "subject": "相关法", "id": "xg_91"},
  {"question": "根据民法典总则编关于显失公平民事法律行为的相应规定，一方利用对方处于以下哪种情形时，致使民事法律行为成立时显失公平，受损害方有权请求予以撤销？（多选）", "options": ["A. 无民事行为能力", "B. 处于危困状态", "C. 缺乏判断能力", "D. 虚假意思表示"], "answer": "BC", "explanation": "《民法典》第151条规定：‘一方利用对方处于危困状态、缺乏判断能力等情形，致使民事法律行为成立时显失公平的，受损害方有权请求人民法院或者仲裁机构予以撤销’，因此A、D选项错误，B、C选项正确。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 27, "subject": "相关法", "id": "xg_92"},
  {"question": "李某和王某离婚后，其子李小某由王某抚养，李小某于其10岁的一年间，陆续向其游戏账户充值共2万元。游戏公司发现充值人系未成年人后，向王某发出催告要求王某在30日内确认。根据民法典及相关规定，下列说法哪些是正确的？（多选）", "options": ["A. 对游戏公司的追认催告，王某未作表示的，视为拒绝追认", "B. 李小某的充值行为经王某同意或者追认后有效", "C. 王某明确表示对李小某的充值行为不予追认的，该民事法律行为无效", "D. 李某和王某是李小某的法定代理人"], "answer": "ABCD", "explanation": "10岁的李小某属于限制民事行为能力人，其向游戏账户充值2万元的民事法律行为超出了与其年龄和智力相适应的范围，该行为须经其法定代理人王某同意或者追认后有效，否则该行为无效。若王某未作表示，则视为拒绝追认，因此A、B、C选项正确。D选项，虽然李小某由母亲抚养，但是其父仍然是未成年子女的监护人，因此李小某的父母李某和王某均是法定代理人，D选项正确。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 31, "subject": "相关法", "id": "xg_93"},
  {"question": "根据民法典总则编及相关规定，下列哪些民事行为属于无效民事法律行为(多选)", "options": ["A. 周某因欠债而向孟某出具欠条", "B. 某国有公司经理曹某与宋某恶意串通，将公司财产以明显低价卖给张某", "C. 12岁的小学生给游戏账户充值一万元", "D. 王某利用李某没有经验，以1万元的价格从李某手中购进一套价值50万元的旧版人民币"], "answer": "AB", "explanation": "A选项，周某欠债属于违反法律规定的民事法律行为，该民事法律行为无效。B选项，恶意串通损害他人合法权益的民事法律行为无效。C选项，12岁的学生给游戏账户充值一万元属于显失公平的民事法律行为。D选项，李某将其合法持有的猎枪出售给未取得枪支许可证的朋友属于可撤销的民事法律行为，而不是无效的民事法律行为。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 26, "subject": "相关法", "id": "xg_94"},
  {"question": "根据民法典的规定，下列哪些行为属于无效民事法律行为(多选)", "options": ["A. 7岁儿童刘某给游戏主播打赏的民事法律行为", "B. 张某在受欺诈状态下所实施的民事法律行为", "C. 甲装饰公司卖给乙公司100盏吸顶灯，乙公司发现甲公司营业执照上的核准经营范围仅为装饰业务，遂请请求法院确认该买卖合同无效", "D. 李某将其合法持有的猎枪出售给未取得枪支许可证的朋友"], "answer": "AD", "explanation": "A选项，违反法律法规强制规定的属于可撤销的民事法律行为，而不是无效的民事法律行为。B选项，损害他人利益的属于可撤销的民事法律行为，而不是无效的民事法律行为。C选项，显失公平的属于可撤销的民事法律行为，而不是无效的民事法律行为。D选项，一方当事人利用对方处于危困状态，致使显失公平的属于可撤销的民事法律行为，而不是无效的民事法律行为。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 26, "subject": "相关法", "id": "xg_95"},
  {"question": "根据民法典总则编及相关规定，下列哪些情形属于代理行为？（多选）", "options": ["A. 甲律师接受法院指定担任被告人乙的辩护代理人", "B. 某明星甲让明星乙代替其参加春节晚会表演节目", "C. 甲公司法定代表人乙委托员工丙与丁公司签订合同", "D. 某高校教授甲让教授乙代替他去主持一场学术交流会"], "answer": "AC", "explanation": "B、D选项，代理是代理人以被代理人的名义在代理权限内与第三人实施法律行为，B、D选项的行为由于具有人身属性，均不属于不能代理的行为。A选项为委托代理，C选项属于职务代理行为。（新编）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 34, "subject": "相关法", "id": "xg_96"},
  {"question": "根据民法典总则编及相关规定，下列有关代理的哪些说法是正确的？（多选）", "options": ["A. 代理人在代理权限内，以被代理人名义实施的民事法律行为，对被代理人发生效力", "B. 代理人知道或者应当知道代理事项违法仍然实施代理行为，或者被代理人知道或者应当知道代理人的代理行为违法未作反对表示的，被代理人和代理人应当承担连带责任", "C. 相对人知道或者应当知道行为人无权代理的，相对人和行为人按照各自的过错承担责任", "D. 代理人和相对人恶意串通，损害被代理人合法权益的，代理人和相对人应当承担连带责任"], "answer": "ABCD", "explanation": "A选项，《民法典》第162条规定：‘代理人在代理权限内，以被代理人名义实施的民事法律行为，对被代理人发生效力’，因此A选项正确。B选项，《民法典》第167条规定：‘代理人知道或者应当知道代理事项违法仍然实施代理行为，或者被代理人知道或者应当知道代理人的代理行为违法未作反对表示的，被代理人和代理人应当承担连带责任’，因此B选项正确。C选项，《民法典》第171条第4款规定：‘相对人知道或者应当知道行为人无权代理的，相对人和行为人按照各自的过错承担责任’，因此C选项正确。D选项，《民法典》第164条第2款规定：‘代理人和相对人恶意串通，损害被代理人合法权益的，代理人和相对人应当承担连带责任’，因此D选项正确。（2013）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 34, "subject": "相关法", "id": "xg_97"},
  {"question": "甲委托乙出卖红木，乙同时联系了丙和丁。丙出价500万元，丁出价400万元，但约定给乙50万元回扣。乙告诉甲现在行情不好，应及时卖出红木，甲同意，乙与丁签订了价格为350万元的合同，甲后来知情。下列说法正确的有：（多选）", "options": ["A. 红木买卖合同有效", "B. 红木买卖合同无效", "C. 乙构成无权代理", "D. 乙和丁对甲的损失承担连带责任"], "answer": "BD", "explanation": "A、B选项，乙为收取回扣，将红木出卖给出价较低的丁，其行为构成恶意串通，损害了甲的合法权益，属于无效的民事法律行为，因此A选项错误，B选项正确。C选项，乙以350万元的价格将红木出售给丁，并未逾越代理权限，不构成无权代理。D选项，代理人和相对人恶意串通，应当承担连带责任，D选项正确。（法考2021）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 34, "subject": "相关法", "id": "xg_98"},
  {"question": "根据民法典总则编及相关规定，下列关于代理的哪些说法是正确的？（多选）", "options": ["A. 代理包括委托代理和法定代理", "B. 代理人应当在代理权限内，以被代理人的名义实施民事法律行为，不得发生代理人的效力", "C. 依照法律规定应当由本人实施的民事法律行为，不得由代理人实施", "D. 委托代理人需要转委托他人代理的，在何种情况下应当取得被代理人的同意"], "answer": "ABC", "explanation": "代理分为委托代理和法定代理，代理人必须在代理权限内以被代理人的名义实施民事法律行为，且不得发生代理人的效力。法律规定某些行为必须由本人实施，不能由代理人代理。转委托他人代理时，需要取得被代理人的同意。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 35, "subject": "相关法", "id": "xg_99"},
  {"question": "甲公司特邀邀请知名画家张某为公司庆典创作一幅书画作品，并明确约定由张某亲自完成。张某在构思过程中因事繁忙无法在规定期限内完成作品，遂请其学生王某代为完成画作，但并未告知甲公司，甲公司收到画作后支付给张某的画款。根据民法典总则编及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 张某因故无法在规定期限内完成作品，可以转委托他人完成", "B. 张某系甲公司利益着想，可以转委托他人完成作品", "C. 根据甲公司与张某的约定，该画作应当由张某亲自完成，不能转委托他人", "D. 张某应当对其学生王某的行为承担责任"], "answer": "CD", "explanation": "根据甲公司与张某的约定，张某应当亲自完成作品，因此不能转委托他人。张某未告知甲公司而转委托他人完成作品，违反了与甲公司的约定，因此张某应当对其学生王某的行为承担责任。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 35, "subject": "相关法", "id": "xg_100"},
  {"question": "某公司的印章由其工作人员刘某保管。刘某未经该公司授权以该公司的名义与张某签订买卖合同，并加盖该公司印章，将该公司的产品卖给张某。对此，下列哪些说法是正确的？（单选）", "options": ["A. 该公司与张某之间的买卖合同无效", "B. 该公司与张某之间的买卖合同效力待定", "C. 该公司与张某之间的买卖合同有效", "D. 该公司与张某之间的买卖合同无效，但该公司与张某之间的买卖合同有效"], "answer": "A", "explanation": "刘某未经公司授权，使用公司印章签订的合同，属于无权代理。根据民法典的规定，该合同无效。", "type": "single", "topic": "专题一 民法典总则编", "page": 35, "subject": "相关法", "id": "xg_101"},
  {"question": "是正确的？（多选） A. 该约定属于附生效条件的约定 B. 该约定属于附生效期限的约定 C. 应视为条件不成就 D. 应视为约定无效", "options": ["A. 该约定属于附生效条件的约定", "B. 该约定属于附生效期限的约定", "C. 应视为条件不成就", "D. 应视为约定无效"], "answer": "AC", "explanation": "窝卖给史某，属于附条件生效的约定，因此A选项正确，B选项错误。《民法典》第159条规定：\"附条件的民事法律行为，当事人为了自己的利益不正当地阻止条件成就的，视为条件已经成就；不正当地促成条件成就的，视为条件不成就\"。史某贿赂公司经理让刘某被辞退，属于不正当促进条件成就，因此C选项正确，D选项错误。（法考2020）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 33, "subject": "相关法", "id": "xg_102"},
  {"question": "4. 甲今年16岁，成绩优异。与其阿姨乙约定，若甲高考成绩优异，将赠与甲一部价值一万元的笔记本电脑。下列哪些选项是正确的？（单选） A. 甲为限制民事行为能力人，故该赠与合同无效 B. 甲与其阿姨乙约定时，该赠与合同成立未生效 C. 甲的母亲丁得知此事后，认为笔记本电脑过于贵重，表示坚决反对，该赠与合同因其母亲丁的反对而无效 D. 甲受赠电脑的行为需要其父母追认才能生效", "options": ["A. 甲为限制民事行为能力人，故该赠与合同无效", "B. 甲与其阿姨乙约定时，该赠与合同成立未生效", "C. 甲的母亲丁得知此事后，认为笔记本电脑过于贵重，表示坚决反对，该赠与合同因其母亲丁的反对而无效", "D. 甲受赠电脑的行为需要其父母追认才能生效"], "answer": "B", "explanation": "A选项，《民法典》第145条规定\"限制民事行为能力人实施的纯获利益的民事法律行为或者与其年龄、智力、精神健康状况相适应的民事法律行为有效；实施的其他民事法律行为经法定代理人同意或者追认后有效\"。甲获赠电脑为纯获利的民事法律行为，因此不论其法定代理人（父母）追认或是否认，该行为均有效，因此，A、C、D选项错误。B选项，甲高考前，能否取得优异的成绩是不确定的事实，该赠与合同明确约定了取得优异成绩这一条件，系附生效条件的赠与合同，即在甲高考取得优异成绩前，赠与合同成立但未生效。而甲高考取得优异成绩后，条件成就，附生效条件的赠与合同成立并生效，因此，B选项正确。（新编）", "type": "single", "topic": "专题一 民法典总则编", "page": 33, "subject": "相关法", "id": "xg_103"},
  {"question": "某公司因合同纠纷的诉讼时效问题咨询律师。关于律师的答复，下列哪些选项是正确的？（多选）", "options": ["A. 当事人不得违反法律规定，约定延长或者缩短诉讼时效期间、预先放弃诉讼时效利益", "B. 当事人约定同一债务分期履行的，诉讼时效期间从最后一期履行期限届满之日起计算", "C. 超过诉讼时效期间，一方当事人履行，另一方当事人接受的，该另一方当事人构成不当得利", "D. 诉讼时效届满，当事人一方向对方当事人作出同意履行义务意思表示的，不得再以时效届满为由进行抗辩"], "answer": "ABD", "explanation": "A选项，《民法典》第197条第1款规定：‘诉讼时效的期间、计算方法以及中止、中断的事由由法律规定，当事人约定无效’，因此当事人不得以约定排斥或变更这一制度的适用，A选项正确。B选项，《民法典》第189条规定：‘当事人约定同一债务分期履行的，诉讼时效期间自最后一期履行期限届满之日起计算’，因此B选项正确。C、D选项，接受履行的一方不构成不当得利，诉讼时效期间届满，当事人一方向对方当事人作出同意履行义务的意思表示或者自愿履行义务后，不得反悔，C选项错误，D选项正确。（法考2010）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 43, "subject": "相关法", "id": "xg_104"},
  {"question": "同约定房屋价款200万元，房屋过户备案事项按此合同履行。关于两份合同，下列哪一项正确？（单选）", "options": ["A. 第一份合同部分无效，第二份合同无效", "B. 第一份合同有效，第二份合同部分无效", "C. 两份合同均无效", "D. 两份合同均有效"], "answer": "B", "explanation": "甲乙二人真实的意愿表示系第一份房屋买卖合同，即价款500万元。该份合同有效。因此，B选项正确，A、C、D选项错误。（法考2020）", "type": "single", "topic": "专题一 民法典总则编", "page": 28, "subject": "相关法", "id": "xg_105"},
  {"question": "下列哪些情形下，甲对乙的行为构成胁迫？（多选）", "options": ["A. 甲说：如不出借1万元，则举报乙犯罪。乙照办，后查实乙构成犯罪", "B. 甲说：如不将藏獒卖给甲，则举报乙犯罪。乙照办，后查实乙不构成犯罪", "C. 甲说：如不购买甲即将报废的汽车，将公开乙的个人隐私。乙照办", "D. 甲说：如不赔偿乙撞伤甲的医疗费，则举报乙醉酒驾车。乙照办，甲取得医疗费和慰问金"], "answer": "ABC", "explanation": "所谓胁迫，是指为达到非法目的，采用某种方法造成他人精神上的巨大压力或直接对他人肉体施加暴力的行为，其核心在于“目的非法”或“手段非法”。A、B选项，甲举报犯罪虽手段合法但目的非法，即强迫借款和强买强卖，构成胁迫。C选项，甲强买强卖的目的和公开隐私的手段均非法，构成胁迫。D选项，乙赔偿撞伤甲的医疗费是法律规定必须承担的责任，甲并没有非法目的，甲举报乙醉酒驾车的手段也合法，不构成胁迫。（法考2013改编）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 28, "subject": "相关法", "id": "xg_106"},
  {"question": "根据民法典总则编关于无权代理民事法律行为的相关规定，下列哪些关于无权代理法律后果的表述是错误的？（多选）", "options": ["A. 相对人可以催告被代理人自收到通知之日起两个月内予以追认", "B. 行为人实施的行为未被追认的，善意相对人只能就其受到的损害请求行为人赔偿", "C. 相对人知道或者应当知道行为人无权代理的，相对人和行为人按照各自的过错承担责任", "D. 被代理人未作出表示的，视为同意追认"], "answer": "ABD", "explanation": "A选项，相对人可以催告被代理人自收到通知之日起30日内予以追认，因此A选项错误。B选项，善意相对人有撤销的权利，因此B选项错误。C选项，相对人知道或者应当知道行为人无权代理的，相对人和行为人按照各自的过错承担责任，因此C选项正确。D选项，被代理人未作出表示的，视为拒绝追认，因此D选项错误。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 36, "subject": "相关法", "id": "xg_107"},
  {"question": "甲公司委托乙代理机构与丙公司谈判购买一项专利权，乙代理机构委派代理师王某与丙公司谈判。谈判过程中王某认为丙公司的另一项专利更好，便自作主张以甲公司的名义与丙公司签订了该项专利的转让合同。丙公司未审核乙代理机构的代理权限，便与之订立了专利权转让合同。根据民法典总则编及相关规定，下列说法正确的是？（多选）", "options": ["A. 甲公司对该项合同有追认权", "B. 丙公司对该项合同有催告权", "C. 丙公司对该项合同有撤销权", "D. 甲公司对该项合同有撤销权"], "answer": "ABC", "explanation": "本题中，丙公司未审核乙代理公司的代理权限，存在疏忽，不构成表见代理，属于无权代理，因此甲公司有追认权，善意的丙公司有催告权和撤销权，A、B、C选项正确，D选项错误。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 36, "subject": "相关法", "id": "xg_108"},
  {"question": "根据民法典总则编及相关规定，对于代理人在代理权终止后的代理行为，下列哪些说法是正确的？（多选）", "options": ["A. 未经被代理人追认的，对被代理人不发生效力", "B. 相对人有理由相信行为人有代理权的，代理行为有效", "C. 相对人知道或者应当知道行为人无权代理的，相对人和行为人按照各自的过错承担责任", "D. 相对人知道或者应当知道行为人无权代理的，相对人和行为人各承担百分之五十的责任"], "answer": "ABC", "explanation": "A选项，《民法典》第171条第1款规定：‘行为人没有代理权、超越代理权或者代理权终止后，仍然实施代理行为，未经被代理人追认的，对被代理人不发生效力’，因此A选项正确。B选项为表见代理，正确。C、D选项，《民法典》第171条第4款规定：‘相对人知道或者应当知道行为人无权代理的，相对人和行为人按照各自的过错承担责任’，因此C选项正确，D选项错误。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 36, "subject": "相关法", "id": "xg_109"},
  {"question": "甲在早市购物时被乙的狗咬伤。甲躲闪时踩烂丙的水果若干，同时用丙的水果刀将狗刺伤。甲为治伤花去医疗费1000元，乙给狗治伤花去治疗费500元。对此，下列哪些说法是正确的？（多选）", "options": ["A. 甲受到的损失应当由乙赔偿", "B. 丙受到的损失应当由甲赔偿", "C. 丙受到的损失应当由乙赔偿", "D. 如果甲不赔偿乙的损失，则乙可以不赔偿甲的损失"], "answer": "AC", "explanation": "《民法典》第181条第1款规定：‘因正当防卫造成损害的，不承担民事责任’；《民法典》第182条第1款规定：‘因紧急避险造成损害的，由引起险情发生的人承担民事责任’。本题中，甲躲闪狗时踩烂丙的水果的行为属于紧急避险，甲和丙的损失均应由引起险情发生的乙承担赔偿责任，甲刺伤狗的行为属于正当防卫，且没有超过必要的限度，不承担赔偿责任，因此A、C选项正确，B、D选项错误。（2008）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 40, "subject": "相关法", "id": "xg_110"},
  {"question": "某公司的董事长甲在宴会上醉酒，看有人递来一个东西，以为是酒水单而签字，实际上该文本是一份红酒买卖合同。关于该行为的效力，下列哪一选项是正确的？", "options": ["A. 因无权代理效力待定", "B. 因重大误可撤销", "C. 因显失公平可撤销", "D. 因意思表示不真实而无效"], "answer": "B", "explanation": "根据民法典的相关规定，如果一方在重大误解的情况下作出意思表示，该行为可以被撤销。董事长甲在醉酒状态下签字，显然存在重大误解，因此该行为效力可撤销。", "type": "single", "topic": "专题一 民法典总则编", "page": 32, "subject": "相关法", "id": "xg_111"},
  {"question": "根据民法典总则编及相关规定，下列哪些属于诉讼时效中断的事由？（多选）", "options": ["A. 权利人向法院提起诉讼", "B. 因不可抗力导致权利人不能行使请求权", "C. 权利人向义务人提出履行请求", "D. 义务人同意履行债务"], "answer": "ACD", "explanation": "根据《民法典》第195条规定：‘有下列情形之一的，诉讼时效中断，从中断、有关程序终结时起，诉讼时效期间重新计算：（一）权利人向义务人提出履行请求；（二）义务人同意履行义务；（三）权利人提起诉讼或者申请仲裁；（四）与提起诉讼或者申请仲裁具有同等效力的其他情形’。因此A、C、D选项正确。B选项属于诉讼时效中止的情形。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 42, "subject": "相关法", "id": "xg_112"},
  {"question": "某专利代理机构受孙某的委托代为办理专利申请事务。代理事项尚未完成时，孙某意外身亡。在下列哪些情况下，该代理机构在孙某死亡后实施的代理行为有效？（多选）", "options": ["A. 该代理机构在孙某死亡前已经进行、而在孙某死亡后为了孙某的继承人的利益继续完成的", "B. 该代理机构不知道且不应知道孙某死亡的", "C. 孙某和该代理机构约定到代理事项完成时代理权终止的", "D. 孙某的继承人均予以承认的"], "answer": "ABCD", "explanation": "被代理人死亡后，有下列情形之一的，委托代理人实施的代理行为有效：（一）代理人不知道且不应当知道被代理人死亡；（二）被代理人的继承人予以承认；（三）授权中明确代理权在代理事务完成时终止；（四）被代理人死亡前已经实施，为了被代理人的继承人的利益继续代理”。因此A、B、C、D选项均正确。（2008改编）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 39, "subject": "相关法", "id": "xg_113"},
  {"question": "根据民法典总则编及相关规定，下列哪些情形下法定代理终止？（多选）", "options": ["A. 被代理人取得完全民事行为能力", "B. 被代理人死亡", "C. 代理人死亡", "D. 代理人丧失民事行为能力"], "answer": "ABCD", "explanation": "《民法典》第175条规定：‘有下列情形之一的，法定代理终止：（一）被代理人取得或者恢复完全民事行为能力；（二）代理人丧失民事行为能力；（三）代理人或者被代理人死亡；（四）法律规定的其他情形’。因此A、B、C、D选项均正确。（2013）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 39, "subject": "相关法", "id": "xg_114"},
  {"question": "甲去购买彩票，其友乙给甲10元钱让其顺便代购彩票，同时告知购买号码，并一再嘱咐甲不要改变。甲预测乙提供的号码不能中奖，便擅自更换号码为乙购买了彩票并替乙保管。开奖时，甲为乙购买的彩票中了奖，二人为奖项归属发生纠纷。下列哪一分析是正确的？（单选）", "options": ["A. 甲应获得奖项，因按乙的号码无法中奖", "B. 甲、乙应平分该奖项，因乙出了钱，而甲更换了号码", "C. 甲的贡献大，应获得该奖项之大部，同时按比例承担彩票购买款", "D. 乙应获得该奖项，因乙是委托人"], "answer": "D", "explanation": "A、B、C选项错误，D选项正确。（法考2015）", "type": "single", "topic": "专题一 民法典总则编", "page": 37, "subject": "相关法", "id": "xg_115"},
  {"question": "下列哪一情形构成无权代理？（单选）", "options": ["A. 甲冒用乙的姓名从某杂志社领取乙的论文稿酬据为己有", "B. 某公司法定代表人超越权限以本公司名义为他人提供担保", "C. 刘某受同学周某之托冒充丁某参加求职面试", "D. 关某代收某推销员谎称关某的邻居李某订购的保健品并代为付款"], "answer": "D", "explanation": "A选项，甲冒用乙之名不构成代理。B选项，法定代表人以公司名义实施民事行为，为代表行为，不构成代理。C选项，冒用他人名义不构成代理，此外面试是具有人身专属性的行为，不能通过代理实施。D选项，李某为被代理人，推销员为相对人，关某为行为人，但关某并不具有代理权，构成无权代理。（法考2009改编）", "type": "single", "topic": "专题一 民法典总则编", "page": 37, "subject": "相关法", "id": "xg_116"},
  {"question": "肖某系甲烟草公司经理，因违纪被开除，后伪造公章，于2024年5月25日以甲公司名义与不知情的乙公司约定，向乙公司出售香烟50箱，价款50万元。2024年6月1日，乙公司得知肖某被开除，询问甲公司是否认可该合同，2024年6月10日，甲公司通知乙公司不承认肖某所订立的香烟合同。下列说法正确的是？（多选）", "options": ["A. 2024年6月10日后，乙公司有权请求肖某赔偿损失", "B. 2024年6月10日后，乙公司有权请求甲公司履行合同", "C. 2024年6月10日后，乙公司有权请求肖某履行合同", "D. 2024年6月10日前，乙公司有权通知甲公司撤销"], "answer": "ACD", "explanation": "2024年6月1日，相对人乙公司得知行为人肖某被开除，即没有代理权。因此，肖某为无权代理。无权代理，烟草买卖合同效力待定，在被代理人甲烟草公司追认或否认前，善意相对人乙公司享有撤销权，D选项正确。2024年6月10日，甲烟草公司拒绝追认肖某的无权代理行为，烟草买卖合同对甲公司不发生效力。甲公司无须履行合同，B选项错误。善意相对人乙公司有权要求行为人肖某履行合同或是赔偿损失。因此，A、C选项正确。（法考2020）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 37, "subject": "相关法", "id": "xg_117"},
  {"question": "行为人超越代理权实施代理行为，相对人有理由相信行为人有代理权的，代理行为有效", "options": ["A. 行为人超越代理权实施代理行为，相对人有理由相信行为人有代理权的，代理行为有效", "B. 代理人和相对人恶意串通，损害被代理人合法权益的，代理人和相对人按照过错大小承担相应的责任", "C. 代理人知道代理事项违法仍然实施代理行为的，被代理人和代理人承担连带责任", "D. 行为人代理权终止后，仍然实施代理行为的，对被代理人不发生效力"], "answer": "A", "explanation": "根据表见代理原则，如果相对人有理由相信行为人有代理权，即使行为人超越了代理权，代理行为也是有效的。", "type": "single", "topic": "专题一 民法典总则编", "page": 38, "subject": "相关法", "id": "xg_118"},
  {"question": "代理人和相对人恶意串通，损害被代理人合法权益的，代理人和相对人按照过错大小承担相应的责任", "options": ["A. 行为人超越代理权实施代理行为，相对人有理由相信行为人有代理权的，代理行为有效", "B. 代理人和相对人恶意串通，损害被代理人合法权益的，代理人和相对人按照过错大小承担相应的责任", "C. 代理人知道代理事项违法仍然实施代理行为的，被代理人和代理人承担连带责任", "D. 行为人代理权终止后，仍然实施代理行为的，对被代理人不发生效力"], "answer": "B", "explanation": "当代理人和相对人恶意串通损害被代理人权益时，他们需要根据各自的过错承担相应的责任。", "type": "single", "topic": "专题一 民法典总则编", "page": 38, "subject": "相关法", "id": "xg_119"},
  {"question": "代理人知道代理事项违法仍然实施代理行为的，被代理人和代理人承担连带责任", "options": ["A. 行为人超越代理权实施代理行为，相对人有理由相信行为人有代理权的，代理行为有效", "B. 代理人和相对人恶意串通，损害被代理人合法权益的，代理人和相对人按照过错大小承担相应的责任", "C. 代理人知道代理事项违法仍然实施代理行为的，被代理人和代理人承担连带责任", "D. 行为人代理权终止后，仍然实施代理行为的，对被代理人不发生效力"], "answer": "C", "explanation": "如果代理人明知代理事项违法仍然实施代理行为，那么代理人和被代理人将承担连带责任。", "type": "single", "topic": "专题一 民法典总则编", "page": 38, "subject": "相关法", "id": "xg_120"},
  {"question": "行为人代理权终止后，仍然实施代理行为的，对被代理人不发生效力", "options": ["A. 行为人超越代理权实施代理行为，相对人有理由相信行为人有代理权的，代理行为有效", "B. 代理人和相对人恶意串通，损害被代理人合法权益的，代理人和相对人按照过错大小承担相应的责任", "C. 代理人知道代理事项违法仍然实施代理行为的，被代理人和代理人承担连带责任", "D. 行为人代理权终止后，仍然实施代理行为的，对被代理人不发生效力"], "answer": "D", "explanation": "当行为人的代理权已经终止，其之后的代理行为对被代理人不产生法律效力。", "type": "single", "topic": "专题一 民法典总则编", "page": 38, "subject": "相关法", "id": "xg_121"},
  {"question": "根据民法典总则编及相关规定，下列哪些情形下委托代理终止？（多选）", "options": ["A. 代理期间届满或者代理事务完成", "B. 被代理人死亡", "C. 代理人死亡或者作为代理人的法人终止", "D. 代理人丧失民事行为能力"], "answer": "ABCD", "explanation": "根据《民法典》第173条，委托代理终止的情形包括代理期间届满或代理事务完成、被代理人死亡、代理人死亡或作为代理人的法人、非法人组织终止，以及代理人丧失民事行为能力。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 38, "subject": "相关法", "id": "xg_122"},
  {"question": "十五岁的中学生李某作出了一项发明创造，并就此获得了一项发明专利。某公司认为该项技术市场前景较好，遂与李某签订了专利权转让合同，以50万元的价格受让该项专利。根据民法典总则编及相关规定，该转让合同的效力应当如何认定？（单选）", "options": ["A. 合同自签订之日起有效", "B. 由于李某不具有完全民事行为能力，因此该合同自无效", "C. 经李某的法定代理人追认后，该合同方为有效", "D. 在李某的法定代理人追认之后，该公司有权以李某不具有完全民事行为能力为由拒绝承认"], "answer": "C", "explanation": "根据民法典规定，未成年人订立的合同需要经过法定代理人的追认才能生效。因此，该专利权转让合同在李某的法定代理人追认后方为有效。", "type": "single", "topic": "专题一 民法典总则编", "page": 30, "subject": "相关法", "id": "xg_123"},
  {"question": "甲公司欠乙公司200万元货款，甲公司与丙公司约定丙公司加入甲公司对乙公司的债务，但只承诺还100万元，并将情况通知了乙公司，乙公司表示同意，后丙公司偿还了50万元。根据《民法典》，下列哪些选项是正确的？（多选）", "options": ["A. 该债务承担协议自通知乙公司对乙公司有效果", "B. 乙公司有权请求丙公司支付50万元", "C. 乙公司有权请求丙公司支付150万元", "D. 该债务承担协议自乙公司同意对乙公司有效果"], "answer": "AB", "explanation": "根据《民法典》的规定，债务承担协议在通知债权人后对债权人有效。因此，A选项正确。由于乙公司同意了债务承担协议，丙公司作为新的债务人承担了部分债务，即偿还100万元。乙公司有权请求丙公司支付已偿还的50万元，但不能请求丙公司支付未偿还的150万元，因为丙公司只承诺偿还100万元，且乙公司已同意此协议。因此，B选项正确，C选项错误。D选项错误，因为债务承担协议在通知债权人后即对债权人有效，不需要债权人的额外同意。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 66, "subject": "相关法", "id": "xg_124"},
  {"question": "根据民法典总则编及相关规定，下列哪些民事案件不适用诉讼时效的规定？（单选）", "options": ["A. 赔偿损失", "B. 返还财产", "C. 停止侵害", "D. 继续履行"], "answer": "C", "explanation": "C.《民法典》第196条规定：‘下列请求权不适用诉讼时效的规定：（一）请求停止侵害、排除妨碍、消除危险；（二）不动产物权和登记的动产物权的权利人请求返还原物；（三）请求支付抚养费、赡养费或者扶养费；（四）依法不适用诉讼时效的其他请求权’，因此A、B、D选项均适用诉讼时效的规定，C选项不适用诉讼时效的规定。（新编）", "type": "single", "topic": "专题一 民法典总则编", "page": 41, "subject": "相关法", "id": "xg_125"},
  {"question": "甲将一辆油罐车擅自停在邻居乙的院子里，还把乙没上锁的自行车骑走了。3年后，乙可采取的措施中，下列哪些选项属于甲可以时效经过为由主张的抗辩？（多选）", "options": ["A. 赔偿损失请求权", "B. 返还财产请求权", "C. 停止侵害请求权", "D. 继续履行请求权"], "answer": "AB", "explanation": "A选项，赔偿损失请求权，为一般的债权请求权，适用诉讼时效，因此A选项正确。B、C、D选项，《民法典》第196条规定：‘下列请求权不适用诉讼时效的规定：（一）请求停止侵害、排除妨碍、消除危险；（二）不动产物权和登记的动产物权的权利人请求返还原物；（三）请求支付抚养费、赡养费或者扶养费；（四）依法不适用诉讼时效的其他请求权’，因此B选项（返还原物）不适用诉讼时效，C选项（停止侵害）也不适用诉讼时效，D选项（继续履行）一般属于合同请求权，适用诉讼时效。故只有A、B选项可能以时效经过为由主张抗辩。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 41, "subject": "相关法", "id": "xg_126"},
  {"question": "实际是给电商平台供货。由于乙公司准备不足，无法按时交货，造成电商平台损失。这时甲公司告知电商平台其系与乙公司订立的购销合同。关于纠纷处理，说法正确的有：（多选）", "options": ["A. 电商平台可以要求甲承担违约责任", "B. 电商平台可以要求乙承担违约责任", "C. 如果乙知道实际上是给电商平台供货，就不会签订合同，则电商平台不能追究乙的违约责任", "D. 电商平台要求数甲、乙承担连带责任"], "answer": "AB", "explanation": "根据《民法典》第926条第1款规定：‘受托人以自己的名义与第三人订立合同时，第三人不知道受托人与委托人之间的代理关系的，受托人因第三人的原因对委托人不履行义务，受托人应当向委托人披露第三人，委托人因此可以使受托人对第三人的权利。但是，第三人与受托人订立合同时如果知道该委托人就不会订立合同的除外’。本题中，电商平台为委托人，甲公司为受托人，乙公司为第三人，因此A、B、C选项正确，D选项错误。（新编）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 85, "subject": "相关法", "id": "xg_127"},
  {"question": "甲委托乙代销电视机，乙分别与丙、丁签订了买卖合同，但没有说明是代甲销售。后乙将与丙、丁签订合同的事实告知甲。甲分别以自己的名义向丙和丁送交了约定数量的电视机。丙接收了电视机，丁拒收电视机并要求乙履行合同。后丁反悔，直接向甲履行了付款义务。下列哪些选项是正确的？（多选）", "options": ["A. 如丙迟延履行付款义务，甲可以要求乙承担连带责任", "B. 乙可以自己是受托人为由拒绝对丁履行交货义务", "C. 丁拒收电视机并要求乙履行合同意味着选择乙作为相对人", "D. 丁拒收电视机后又向甲付款的行为不发生合同履行的效力"], "answer": "CD", "explanation": "A选项，第三人丙、丁分别与乙订立合同时并不知道甲与乙之间的代理关系，因此若丙迟延履行付款义务，乙应当向甲披露丙，甲可以行使乙对丙的权利，要求丙承担违约责任，乙并不需要承担连带责任，因此A选项错误。B、C、D选项，丁可以选择甲或者乙履行义务，如果丁拒收电视机并要求乙履行合同，说明丁选择受托人乙作为电视机买卖合同的相对人，乙不能以自己是受托人为由拒绝履行对丁的交货义务。一旦第三人选定了履行义务的相对人之后，不可以变更，所以丁既然拒收甲交付的电视机并要求乙履行合同，那么他就已经选定了乙作为相对人，不得再更改，其后反悔，在拒收电视机后又向甲付款的行为不发生合同履行的效力，因此B选项错误，C、D选项正确。（法考2008）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 85, "subject": "相关法", "id": "xg_128"},
  {"question": "张某和李某合作开发完成一项发明创造，但未约定权利归属。该项发明创造完成后，张某想要申请专利，而李某则想通过商业秘密保护，不同意申请专利。根据民法典合同编及相关规定，下列哪种说法是正确的？（单选）", "options": ["A. 张某不得申请专利", "B. 张某可以申请专利，获得授权后专利权归张某和李某共有", "C. 张某可以申请专利，获得授权后专利权归张某所有，李某可以免费实施该专利", "D. 张某可以申请专利，获得授权后专利权归张某所有，但获得的收益应在两人之间分配"], "answer": "B", "explanation": "根据《民法典》第863条第3款规定：‘技术转让合同和技术许可合同应当采用书面形式’，且合作开发完成的发明创造，申请专利的权利属于合作开发的当事人共有；当事人一方转让其共有的专利申请权的，其他各方享有以同等条件优先受让的权利。但是，当事人另有约定的除外。合作开发的当事人一方声明放弃其共有的专利申请权的，除当事人另有约定外，可以由另一方单独申请或者由其他各方共同申请。申请人取得专利权的，放弃专利申请权的一方可以免费实施该专利。合作开发的当事人一方不同意申请专利的，另一方或者其他各方不得申请专利’，因此A选项错误，B、D选项正确。C选项，因《民法典》第863条第3款规定：‘技术转让合同和技术许可合同应当采用书面形式’，因此C选项正确。（2018）", "type": "single", "topic": "专题一 民法典总则编", "page": 79, "subject": "相关法", "id": "xg_129"},
  {"question": "在某专利侵权纠纷民事诉讼中，专利权人申请人民法院通知具有专门知识的人张某出庭，代表当事人对专利侵权技术比对涉及的专业问题在法庭上提出意见。根据民事诉讼法及相关规定，下列关于该意见的哪种说法是正确的？(单选)", "options": ["A. 该意见视为证人证言", "B. 该意见视为当事人的陈述", "C. 该意见视为鉴定意见", "D. 该意见视为勘验笔录"], "answer": "C", "explanation": "具有专门知识的人出庭提出的意见视为鉴定意见。", "type": "single", "topic": "专题一 民法典总则编", "page": 101, "subject": "相关法", "id": "xg_130"},
  {"question": "10岁的张某与6岁的李某在操场踢球的的过程中，张某不慎将李某的眼睛撞伤，双方父母因损害赔偿问题发生争执，决定向人民法院提起诉讼。下列关于本案当事人的说法，哪个是正确的？（单选）", "options": ["A. 李某为原告，张某及其父母共同被告", "B. 李某的父母为原告，张某的父母为被告", "C. 李某为原告，张某的父母为被告", "D. 李某的父母为原告，张某为被告"], "answer": "C", "explanation": "根据《中华人民共和国民事诉讼法》关于当事人资格的规定，未成年人的监护人可以作为法定代理人代为诉讼。因此，李某作为原告，张某的父母作为被告。", "type": "single", "topic": "专题一 民法典总则编", "page": 95, "subject": "相关法", "id": "xg_131"},
  {"question": "根据民事诉讼法及相关规定，法律规定的机关和有关组织对下列哪些行为可以向人民法院提起公益诉讼？（多选）", "options": ["A. 污染环境的行为", "B. 侵害众多消费者合法权益的行为", "C. 侵犯专利权、未损害社会公共利益的行为", "D. 侵犯商标权、未损害社会公共利益的行为"], "answer": "AB", "explanation": "根据《中华人民共和国民事诉讼法》第55条，法律规定的机关和有关组织可以对污染环境、侵害众多消费者合法权益的行为提起公益诉讼。", "type": "multiple", "topic": "专题一 民法典总则编", "page": 95, "subject": "相关法", "id": "xg_132"},
  {"question": "某消费者权益保护协会认为，某手机生产商在生产手机出厂前，未依法履行消费者保护义务，向人民法院提起公益诉讼，法院依法支持了该协会的诉讼请求。下列关于该协会的说法，正确的是？（单选）", "options": ["A. 该协会的诉讼请求是正确的，法院依法支持了该协会的诉讼请求", "B. 该协会的诉讼请求是错误的，法院依法驳回了该协会的诉讼请求", "C. 该协会的诉讼请求是正确的，法院依法驳回了该协会的诉讼请求", "D. 该协会的诉讼请求是错误的，法院依法支持了该协会的诉讼请求"], "answer": "A", "explanation": "根据《中华人民共和国民事诉讼法》第55条，消费者权益保护协会作为法律规定的机关和有关组织，有权提起公益诉讼，如果法院支持了该协会的诉讼请求，说明其诉讼请求是正确的。", "type": "single", "topic": "专题一 民法典总则编", "page": 95, "subject": "相关法", "id": "xg_133"},
  {"question": "根据最高人民法院关于互联网法院审理案件若干问题的规定，下列说法哪个是正确的？（单选）", "options": ["A. 互联网法院向受送达人主动提供或者确认的电子地址进行送达的，送达信息到达受送达人指定系统时，即为送达", "B. 当事人对广州互联网法院就互联网域名纠纷作出的判决提起上诉的案件，由广州市中级人民法院审理", "C. 互联网法院的庭审应当直接围绕诉讼请求或者案件要素进行", "D. 对需要进行公告送达的民事案件，互联网法院应当适用普通程序审理"], "answer": "A", "explanation": "A选项，《最高人民法院关于互联网法院审理案件若干问题的规定》第17条第1款规定：‘互联网法院向受送达人主动提供或者确认的电子地址进行送达的，送达信息到达受送达人指定系统时，即为送达’，因此A选项正确。B选项，《最高人民法院关于互联网法院审理案件若干问题的规定》第4条第2款规定：‘当事人对广州互联网法院作出的判决、裁定提起上诉的案件，由广州市中级人民法院审理，但互联网著作权属纠纷和侵权纠纷、互联网域名纠纷的上诉案件，由广州知识产权法院审理’，因此B选项错误。C选项，《最高人民法院关于互联网法院审理案件若干问题的规定》第13条规定：‘互联网法院可以视情决定采取下列方式简化庭审程序：……（三）……对于简单民事案件，庭审可以直接围绕诉讼请求或者案件要素进行’，C选项缺少‘简单民事案件’的前提，因此C选项错误。D选项，《最高人民法院关于互联网法院审理案件若干问题的规定》第18条规定：‘对需要进行公告送达的事实清楚、权利义务关系明确的简单民事案件，互联网法院可以适用简易程序审理’，因此D选项错误。", "type": "single", "topic": "专题一 民法典总则编", "page": 115, "subject": "相关法", "id": "xg_134"},
  {"question": "关于行政复议代理人的行为效力，以下哪些说法是正确的？（多选）", "options": ["A. 代表人参加行政复议的所有行为对其代表的申请人均发生效力", "B. 代表人变更行政复议请求应当经被代表的申请人同意", "C. 代表人承认第三人请求应当经被代表的申请人同意", "D. 代表人承认被申请人提出证据的真实性应当经被代表的申请人同意"], "answer": "BC", "explanation": "《复议法》第15条规定：‘同一行政复议案件申请人人数众多的，可以由申请人推选代表人参加行政复议。代表人参加行政复议的行为对其所代表的申请人发生效力，但是代表人变更行政复议请求、撤回行政复议申请、承认第三人请求的，应当经被代表的申请人同意’，因此A、D选项错误，B、C选项正确。（新编）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 131, "subject": "相关法", "id": "xg_135"},
  {"question": "关于行政复议中的委托代理人，以下说法正确的有？（多选）", "options": ["A. 申请人或第三人最多可以委托2名代理人代理参加复议", "B. 申请人或第三人只能委托律师、基层法律服务工作者、近亲属代为参加复议", "C. 委托代理人应当向复议机构提交授权委托书，委托人以及被委托人的身份证明文件", "D. 委托书应当载明委托事项的权限和期限"], "answer": "ACD", "explanation": "《复议法》第17条规定：‘申请人、第三人可以委托一至二名律师、基层法律服务工作者或者其他代理人代为参加行政复议。申请人、第三人委托代理人的，应当向行政复议机构提交授权委托书、委托人及被委托人的身份证明文件。授权委托书应当载明委托事项、权限和期限……’，因此A、C、D选项正确，B选项错误。【提示】在行政复议程序可委托的代理人范围比民事诉讼和行政诉讼的范围宽，例如还可委托专利代理机构的工作人员代为参加行政复议。（新编）", "type": "multiple", "topic": "专题一 民法典总则编", "page": 131, "subject": "相关法", "id": "xg_136"},
  {"question": "某公司就某行政机关对其作出的罚款5000元的行政处罚决定向人民法院提起诉讼。在诉讼中，该行政机关变更了原处罚决定，将罚款数额改为3000元，并书面告知了人民法院，但该公司仍要求确认原行政行为违法。根据行政诉讼法及相关规定，下列说法哪项是正确的？", "options": ["A. 人民法院应当裁定终结诉讼，并告知该公司另行起诉", "B. 人民法院应当对变更后的行政处罚决定进行审理", "C. 人民法院应当依法作出确认判决", "D. 人民法院应当对变更后的行政处罚决定和原行政处罚决定一并进行审理"], "answer": "D", "explanation": "人民法院应当对变更后的行政处罚决定和原行政处罚决定一并进行审理。", "type": "single", "topic": "专题一 民法典总则编", "page": 179, "subject": "相关法", "id": "xg_137"},
  {"question": "根据行政诉讼法及相关规定，关于人民法院调查取证，下列说法哪些是正确的？(多选)", "options": ["A. 涉及商业秘密的证据，原告或者第三人不能自行收集的，可以申请人民法院调取", "B. 人民法院可以为证明行政行为的合法性调取被告作出行政行为时未收集的证据", "C. 涉及个人隐私的证据，原告或者第三人不能自行收集的，可以申请人民法院调取", "D. 由国家机关保存而须由人民法院调取的证据，原告或者第三人不能自行收集的，可以申请人民法院调取"], "answer": "ACD", "explanation": "A、C、D选项，《行政诉讼法》第41条规定：\"与本案有关的下列证据，原告或者第三人不能自行收集的，可以申请人民法院调取：（一）由国家机关保存而须由人民法院调取的证据；（二）涉及国家秘密、商业秘密和个人隐私的证据……\"，因此A、C、D选项正确。B选项，《行政诉讼法》第40条规定：\"人民法院有权向有关行政机关以及其他组织、公民调取证据。但是，不得为证明行政行为的合法性调取被告作出行政行为时未收集的证据\"，因此B选项错误。(新编)", "type": "multiple", "topic": "专题一 民法典总则编", "page": 169, "subject": "相关法", "id": "xg_138"},
  {"question": "胡某在自家菜园里发现一只甲虫 ,非常 付某出价 30万元购买。后来发现该甲虫是濒 动物。此种情形违反以下民法的也一个原则?(", "options": ["A. 公序良俗原则", "B. 自愿原则", "C. 绿色原则", "D. 诚信原则"], "answer": "AC", "explanation": "ARS HEAARKH ERI IUP HM RT OF WR PY AM RT OHO | PABA, BO RRA OHTA L ERP LAMM AR TRE | 则。(法考 2024) |", "type": "multiple", "topic": "专题一 民法典总则编", "page": 3, "subject": "相关法", "id": "xg_139"},
  {"question": "1. 甲丢了一只小狗，发了高价寻狗启事。乙不知道这件事，捡到小狗后归还。甲给了乙200元答谢，乙表示不用。后乙知道了高价寻狗启事，找甲索要报酬，被甲拒绝。关于本案，下列说法正确的有？（多选）", "options": ["A. 乙已经拒绝，不得索要报酬", "B. 乙有权索要报酬", "C. 甲发布寻狗启事时，该悬赏广告生效", "D. 不论乙是否知晓寻狗启事的内容，甲均应支付报酬"], "answer": "BCD", "explanation": "甲发布的寻狗启事属于悬赏广告，根据《民法典》第499条的规定，悬赏人以公开方式声明对完成特定行为的人支付报酬的，完成该行为的人可以请求其支付。甲丢狗后发布寻狗启事，乙捡到狗后归还，作为完成特定行为人的乙有权索要报酬，即使乙不知道寻狗启事的内容均不影响其向甲索要报酬。因此，A选项错误，B、D选项正确。根据《民法典》第139条的规定，以公告方式作出的意思表示，公告发布时生效。因此C选项正确。（法考2024改编）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 36, "subject": "相关法", "id": "xg_140"},
  {"question": "2. 根据民法典合同编及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 要约是希望和他人订立合同的意思表示", "B. 要约邀请是希望他人向自己发出要约的意思表示", "C. 要约在发出时生效", "D. 要约以对话方式发出的，相对人知道其内容时生效"], "answer": "AD", "explanation": "A选项，根据《民法典》第472条的规定，要约是希望与他人订立合同的意思表示，因此A选项正确。B选项，根据《民法典》第473条第1款的规定，要约邀请是希望他人向自己发出要约的表示，并非意思表示，因此B选项错误。C、D选项，根据《民法典》第137、第474条的规定，要约在到达受要约人时生效，要约以对话方式发出的，相对人知道其内容时生效，因此C选项错误，D选项正确。（2012改编）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 36, "subject": "相关法", "id": "xg_141"},
  {"question": "3. 根据民法典合同编及相关规定，下列哪些选项属于要约？（多选）", "options": ["A. 超市货架上的商品标价陈列", "B. 自动售货机上标明可口可乐2.5元一罐", "C. 在拍卖现场，举牌竞拍", "D. 发布招股说明书，募集股份"], "answer": "ABC", "explanation": "A、B、C选项符合要约构成条件。D选项，《民法典》第473条第1款规定：“要约邀请是希望他人向自己发出要约的表示。拍卖公告、招标公告、招股说明书、债券募集办法、基金招募说明书、商业广告和宣传、寄送的价目表等为要约邀请”，D选项构成要约邀请。（2019）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 36, "subject": "相关法", "id": "xg_142"},
  {"question": "4. 甲公司欲出售一批货物给乙公司，甲公司向乙公司发出要约后，因进货渠道发生困难而欲撤回要约。根据民法典合同编及相关规定，下列哪些情形下，甲公司发出的要约可以被撤回？（多选）", "options": ["A. 撤回要约的通知在该要约到达乙公司之前到达乙公司", "B. 撤回要约的通知在乙公司发出承诺通知之前到达乙公司", "C. 撤回要约的通知与该要约同时到达乙公司", "D. 撤回要约的通知在乙公司发出承诺通知的同时到达乙公司"], "answer": "AB", "explanation": "根据《民法典》第475条的规定，撤回要约的通知应当在要约到达受要约人之前或者与要约同时到达受要约人。因此，只有在撤回通知早于或与要约同时到达乙公司时，要约才可以被撤回。C和D选项中，撤回通知在乙公司作出承诺之后或承诺前但已收到要约的情况下，无法撤回。故正确答案为AB。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 36, "subject": "相关法", "id": "xg_143"},
  {"question": "5. 甲公司发布招标公告，选择专利代理机构办理专利复审事务。乙专利代理机构根据该招标公告制作并提交了投标书参加投标。根据民法典合同编及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 甲公司发布的招标公告是要约邀请", "B. 甲公司发布的招标公告是要约", "C. 乙专利代理机构提交的投标书可以撤回，撤回该投标书的通知应当在甲公司发出承诺通知之前到达甲公司", "D. 乙专利代理机构提交的投标书可以撤销，撤销该投标书的通知应当在甲公司发出承诺通知之前到达甲公司"], "answer": "AD", "explanation": "A、B选项，根据《民法典》第473条的规定，招标公告为要约邀请，因此A选项正确，B选项错误。C选项，撤回要约的通知应当在要约到达受要约人之前或者与要约同时到达受要约人，乙的投标书构成要约，撤回通知应当在投标书到达甲公司之前或者与投标书同时到达甲公司，因此C选项错误。D选项，《民法典》第477条规定：“撤销要约的意思表示以非对话方式作出的，应当在受要约人作出承诺之前到达受要约人”，撤销通知应当在甲公司发出承诺通知之前到达甲公司，因此D选项正确。(2017)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 37, "subject": "相关法", "id": "xg_144"},
  {"question": "6. 根据民法典合同编及相关规定，在下列哪些情形下，要约不得撤销？（多选）", "options": ["A. 要约已经到达受要约人", "B. 要约人确定了承诺期限", "C. 要约人明示要约不可撤销", "D. 受要约人有理由认为要约是不可撤销的，并已经为履行合同做了合理准备工作"], "answer": "BCD", "explanation": "A选项，根据《民法典》第477条的规定，撤销要约应当在受要约人作出承诺之前到达受要约人，因此A选项要约可以撤销。B、C、D选项，《民法典》第476条规定：“要约可以撤销，但是有下列情形之一的除外：（一）要约人以确定承诺期限或者其他形式明示要约不可撤销；（二）受要约人有理由认为要约是不可撤销的，并已经为履行合同做了合理准备工作”，因此B、C、D选项要约不可撤销。(2014)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 37, "subject": "相关法", "id": "xg_145"},
  {"question": "7. 根据民法典合同编及相关规定，有下列哪些情形之一的，要约失效？（多选）", "options": ["A. 要约被拒绝", "B. 要约被依法撤回", "C. 承诺期限届满，受要约人未作出承诺", "D. 受要约人对要约的内容做出实质性变更"], "answer": "ACD", "explanation": "《民法典》第478条规定：“有下列情形之一的，要约失效：（一）要约被拒绝；（二）要约被依法撤销；（三）承诺期限届满，受要约人未作出承诺；（四）受要约人对要约的内容作出实质性变更”，因此A、C、D选项正确，B选项", "type": "multiple", "topic": "专题二 民法典合同编", "page": 37, "subject": "相关法", "id": "xg_146"},
  {"question": "8. 根据民法典合同编的规定，下列哪些情形下要约失效？（多选）", "options": ["A. 甲对乙讲：“我有八成新电脑一台，5000元卖给你，买吗？”乙表示不买", "B. 甲发传真给乙，表明“现有大米1万吨，批发价格每斤1元，款到发货，请于收到传真后一周内答复”。乙收到该传真后一直未 - 36 -"], "answer": "ABD", "explanation": "A选项属于要约被拒绝，该要约失效。B选项属于承诺期限届满，受要约人未作出承诺，该要约失效。D选项属于受要约人对要约的内容作出实质性变更，要约失效。C选项，要约已明确承诺期限，不可撤销，未失效。(2018改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 37, "subject": "相关法", "id": "xg_147"},
  {"question": "9. 甲公司向乙公司去函表示，“我公司生产的W型路由器，每台单价200元。如果需要请与我公司联系。”乙公司回函，“我公司愿向贵公司订购W型路由器500台，每台单价150元，如无异议，请于一个月内供货。”十天后，甲公司向乙公司发出500台路由器，并要求乙公司按照每台200元的价格付款，乙公司拒收。根据民法典合同编及相关规定，下列哪些说法是正确的？(多选)", "options": ["A. 甲公司向乙公司的去函是要约", "B. 甲公司向乙公司的去函是要约邀请", "C. 乙公司向甲公司的回函是新要约", "D. 乙公司向甲公司的回函是承诺"], "answer": "AC", "explanation": "根据《民法典》第472条规定，要约是希望与他人订立合同的意思表示，且内容具体确定，因此甲公司向乙公司的去函是要约而不是要约邀请，A选项正确，B选项错误。《民法典》第488条规定：“承诺的内容应当与要约的内容一致。受要约人对要约的内容作出实质性变更的，为新要约。有关合同标的、数量、质量、价款或者报酬、履行期限、履行地点和方式、违约责任和解决争议方法等的变更，是对要约内容的实质性变更”。C、D选项，乙公司回函变更了价格，属于对要约的内容作出实质性变更，构成新要约，因此C选项正确，D选项错误。(2016改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 38, "subject": "相关法", "id": "xg_148"},
  {"question": "10. 甲公司于6月10日向乙公司发出要约订购一批红木，要求乙公司于6月15日前答复。6月12日，甲公司欲改向丙公司订购红木，遂向乙公司发出撤销要约的信件，于6月14日到达乙公司。而6月13日，甲公司收到乙公司的回复，乙公司表示红木缺货，问甲公司能否用杉木代替。甲公司的要约于何时失效？(单选)", "options": ["A. 6月12日", "B. 6月13日", "C. 6月14日", "D. 6月15日"], "answer": "B", "explanation": "由于甲公司的要约中规定了承诺期限，因此要约不可撤销，6月14日的撤销要约达到乙公司，并不能发生要约失效的结果。6月13日乙公司的回复中变更了合同标的，对要约的内容作出实质性变更，到达甲公司时，甲公司要约失效。因此B选项正确。(法考2008)", "type": "single", "topic": "专题二 民法典合同编", "page": 38, "subject": "相关法", "id": "xg_149"},
  {"question": "11. 根据民法典合同编的规定，下列哪些情形中，合同已经成立？(多选)", "options": ["A. 张某对杨某说：“我这块手表1000块钱卖给你，要不要？”杨某说：“好，一言为定。”", "B. 某电脑公司与某销售公司签订了销售500台电脑的合同，双方就合同的全部条款都已经协商完毕，打印好后各执一份，但没"], "answer": "AB", "explanation": "A选项，张某对杨某发出的是要约，杨某对张某的回复为承诺，承诺一经作出即生效，合同成立。B选项，《民法典》第490条第1款规定：“……在签名、盖章或者按指印之前，当事人一方已经履行主要义务，对方接受", "type": "multiple", "topic": "专题二 民法典合同编", "page": 38, "subject": "相关法", "id": "xg_150"},
  {"question": "12. 甲在某大学摆设饮料自动贩卖机，乙投入两枚硬币购买了一罐咖啡，咖啡出来后，两枚硬币因机器故障跳出。乙见四处无人，乃取两枚硬币放入口袋。这一场景恰好被甲的职员丙发现，遂产生纠纷。关于本案，下列哪些说法是正确的？(多选)", "options": ["A. 甲摆设自动贩卖机的行为属于要约", "B. 乙投币购买咖啡的行为属于承诺", "C. 乙将两枚硬币放入口袋的行为构成不当得利", "D. 甲有权请求乙返还该两枚硬币"], "answer": "ABCD", "explanation": "甲摆设自动贩卖机的行为属于要约，乙投入硬币的行为属于承诺，合同成立。因此A、B选项正确。C、D选项，乙购买咖啡的两枚硬币已经归属于甲所有，因机器故障跳出，乙将其归为己有，没有法律上的根据，甲因此财产受损，乙构成不当得利，甲有权请求乙返还不当利益，因此C、D选项正确。(法考2018)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 39, "subject": "相关法", "id": "xg_151"},
  {"question": "13. 甲6月10日向乙发信，表示欲购某型号钢材。6月13日乙与甲通话表示同意，并与之商定了钢材的型号、单价和数量，并约定签订合同确认书，乙随即制作了合同确认书并寄出，甲于6月16日在确认书上签字后寄往乙处，乙收到后于6月19日签字，6月22日双方经商议签订了合同书。甲乙之间的合同于何时成立？(单选)", "options": ["A. 6月13日", "B. 6月16日", "C. 6月19日", "D. 6月22日"], "answer": "C", "explanation": "《民法典》第491条第1款规定：“当事人采用信件、数据电文等形式订立合同要求签订确认书的，签订确认书时合同成立”。乙于6月19日在确认书签字，合同成立，因此C选项正确。\n(新编)", "type": "single", "topic": "专题二 民法典合同编", "page": 39, "subject": "相关法", "id": "xg_152"},
  {"question": "14. 京东商家出售某品牌电脑，张三根据网站页面提交了购买订单，随后收到了京东商家发送的订单信息，京东商家于次日发货。关于该合同，下列说法正确有哪些？(多选)", "options": ["A. 购物网站页面标价出售电脑属于要约邀请", "B. 购物网站页面标价出售电脑属于要约", "C. 张三提交订单成功时，买卖合同成立", "D. 京东商家发送订单信息时，买卖合同成立"], "answer": "BC", "explanation": "A、B选项，购物网站标价出售电脑，能够确定电脑的价格、配置、特定品牌等，应认定内容具体确定，属于要约，因此A选项错误，B选项正确。C、D选项，《民法典》第491条第2款规定：“当事人一方通过互联网等信息网络发布的商品或者服务信息符合要约条件的，对方选择该商品或者服务并提交订单成功时合同成立，但是当事人另有约定的除外”。张三提交订单成功后，买卖合同即成立，因此C选项正确，D选项错误。(新编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 39, "subject": "相关法", "id": "xg_153"},
  {"question": "15. 根据民法典合同编及相关规定,关于合同的成立,下列说法正确的是?(多选)", "options": ["A. 受要约人在承诺期限内作出承诺,该承诺因送达原因而迟到的,除要约人及时通知受要约人因承诺超过期限不接受该承诺的以外,该承诺有效", "B. 采用数据电文形式订立合同的,收件人没有主营业地的,其住所地为合同成立的地点", "C. 采用数据电文形式订立合同的,发件人有主营业地的,其主营业地为合同成立的地点", "D. 法律规定采用书面形式订立合同,当事人没有采用书面形式,但一方履行了主要义务,对方也接受的,合同成立"], "answer": "ACD", "explanation": "应当采用书面形式订立，当事人未采用书面形式但是一方已经履行主要义务，对方接受时，该合同成立”，因此D选项正确。（2019）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 40, "subject": "相关法", "id": "xg_154"},
  {"question": "16. 根据民法典合同编及相关规定,下列关于格式条款的说法正确的是?(多选)", "options": ["A. 格式条款是当事人为了重复使用而预先拟定,并在订立合同时未与对方协商确定的条款", "B. 提供格式条款一方限制对方主要权利的条款一律无效", "C. 对格式条款有两种以上解释的,应当作出有利于提供格式条款一方的解释", "D. 格式条款和非格式条款不一致的,应当采用非格式条款"], "answer": "AD", "explanation": "A选项,《民法典》第496条第1款规定:“格式条款是当事人为重复使用而预先拟定,并在订立合同时未与对方协商的条款”,因此A选项正确。B选项,《民法典》第497条规定,提供格式条款一方不合理地免除或者减轻其责任、加重对方责任、限制对方主要权利的格式条款无效。因此对对方主要权利的限制需要达到不合理程度的格式条款才是无效的,并不是一律无效,B选项错误。C、D选项,《民法典》第498条规定:“对格式条款的理解发生争议的,应当按照通常理解予以解释。对格式条款有两种以上解释的,应当作出不利于提供格式条款一方的解释。格式条款和非格式条款不一致的,应当采用非格式条款”,因此C选项错误,D选项正确。(2019改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 40, "subject": "相关法", "id": "xg_155"},
  {"question": "17. 根据民法典合同编及相关规定,下列哪些选项属于无效的格式条款?(单选)", "options": ["A. 提供格式条款的一方所提供的格式条款含有加重对方责任的内容", "B. 提供格式条款的一方采取合理方式提请对方注意减轻其责任的内容", "C. 违反法律、行政法规强制性规定的", "D. 内容不够具体确定的"], "answer": "C", "explanation": "A选项,加重对方责任需要", "type": "single", "topic": "专题二 民法典合同编", "page": 40, "subject": "相关法", "id": "xg_156"},
  {"question": "19. 根据民法典合同编及相关规定,关于格式条款的合同,下列说法哪些是正确的?(多选)", "options": ["A. 提供格式条款一方不合理地加重对方责任的,该格式条款无效", "B. 提供格式条款一方排除对方主要权利的,该格式条款无效", "C. 合同中造成对方人身损害的免责条款无效", "D. 合同中因一般过失造成对方财产损失的免责条款无效"], "answer": "ABC", "explanation": "A、B选项,《民法典》第497条规定:“有下列情形之一的,该格式条款无效:......(二)提供格式条款一方不合理地免除或者减轻其责任、加重对方责任、限制对方主要权利;(三)提供格式条款一方排除对方主要权利”,因此A、B选项正确。C、D选项,《民法典》第506条规定:“合同中的下列免责条款无效:(一)造成对方人身损害的;(二)因故意或者重大过失造成对方财产损失的”,因此C选项正确,D选项错误。(新编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 41, "subject": "相关法", "id": "xg_157"},
  {"question": "20. 甲驾车起步时不小心撞死了坐在院子里甲的外婆。甲向保险公司索赔,保险公司拒绝赔付,并指出保险合同中约定:“保险车辆造成被保险人或其允许的驾驶员及他们的家庭成员人身伤亡,保险公司均不赔偿”。经查实,在签订保险合同时保险公司并未提示甲注意该格式条款。甲可以主张该条款?(单选)", "options": ["A. 可撤销", "B. 无效", "C. 效力待定", "D. 不成为合同内容"], "answer": "D", "explanation": "根据《民法典》第496条的规定,提供格式条款的一方未履行提示或者说明义务,致使对方没有注意或者理解与其有重大利害关系的条款的,对方可以主张该条款不成为合同的内容。", "type": "single", "topic": "专题二 民法典合同编", "page": 41, "subject": "相关法", "id": "xg_158"},
  {"question": "21. 刘某在订票网站上提前两周以600元订购了海鸥航空公司全价1000元的六折机票,在订单生成页面,网站提示起飞前2小时内退票按机票价格收取30%手续费,并重点提示因遇天气原因飞机颠簸造成旅客身体损伤的,一律不承担赔偿责任。后刘某因临时改变行程,刘某于航班起飞前1小时在订票网站办理退票手续。下", "options": ["A. 退票手续费的规定未尽提示注意与说明义务，是无效格式条款", "B. 因天气原因飞机颠簸造成旅客身体损伤的，一律不承担赔偿责任，属于免除人身损害责任的条款，该格式条款无效", "C. 对机票价格的解释有争议，应当按照不利于提供格式条款的一方进行解释", "D. 刘某以600元订购了机票，其退票手续费应为600×30%=180元"], "answer": "CD", "explanation": "A选项，航空公司关于退票手续费的规定已提示注意与说明，并非无效条款，A选项错误。因遇天气原因飞机颠簸造成旅客身体损伤的，一律不承担赔偿责任，属于免除人身损害责任的条款，该格式条款无效，D选项正确。B、C选项，对机票价格的解释有争议，应当按照不利于提供格式条款的一方进行解释，刘某以600元订购了机票，其退票手续费应为600×30%=180元，因此C、D选项正确。", "type": "single", "topic": "专题二 民法典合同编", "page": 41, "subject": "相关法", "id": "xg_159"},
  {"question": "22. 根据民法典合同编及相关规定,合同中出现的下列免责条款,哪些条款会被认定为无效?(多选)", "options": ["A. 造成对方人身伤害的", "B. 因意外事件造成对方财产损失的", "C. 因故意造成对方财产损失的", "D. 因过失造成对方财产损失的"], "answer": "AC", "explanation": "《民法典》第506条规定:“合同中的下列免责条款无效:(一)造成对方人身损害的;(二)因故意或者重大过失造成对方财产损失的”,因此A、C选项正确。(2018改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 42, "subject": "相关法", "id": "xg_160"},
  {"question": "23. 某日,甲公司与乙公司订立《合作意向书》,约定待甲公司取得某地建设用地使用权后双方订立《合作开发合同》,并初步约定了出资比例、收益分享等事宜,当日乙公司依《合作意向书》向甲公司支付了100万元预付款。甲公司取得建设用地使用权后,因决定与其他公司合作而拒绝与之签订《合作开发合同》。以下说法正确的是?(单选)", "options": ["A. 乙公司有权请求甲公司承担违约责任", "B. 《合作意向书》不具有法律约束力", "C. 乙公司有权请求甲公司支付《合作开发合同》项下的违约金", "D. 甲公司应向乙公司双倍返还预付款"], "answer": "A", "explanation": "《民法典》第495条规定:“当事人约定在将来一定期限内订立合同的认购书、订购书、预订书等,构成预约合同。当事人一方不履行预约合同约定的订立合同义务的,对方可以请求其承担预约合同的违约责任”。本题中,甲公司与乙公司签订的《合作意向书》属于预约合同,《合作开发合同》为本约合同,预约合同具有法律约束力,一方不订立本约合同,另外一方有权追究违约责任,因此A选项正确,B选项错误;甲公司拒绝与乙公司签订《合作开发合同》,构成对预约合同的违约,应当承担预约合同的违约责任,不承担本约合同", "type": "single", "topic": "专题二 民法典合同编", "page": 42, "subject": "相关法", "id": "xg_161"},
  {"question": "24. 甲、乙同为儿童玩具生产商。六一节前夕,丙与甲商谈进货事宜。乙知道后向丙提出更优惠条件,并指使丁假借订货与甲接洽,报价高于丙以阻止甲与丙签约。丙经比较与乙签约,丁随即终止与甲的谈判,甲因此遭受损失。对此,下列哪一说法是正确的? (单选)", "options": ["A. 乙应对甲承担缔约过失责任", "B. 丙应对甲承担缔约过失责任", "C. 丁应对甲承担缔约过失责任", "D. 乙、丙、丁无须对甲承担缔约过失责任"], "answer": "C", "explanation": "A选项，乙始终未曾与甲磋商，甲、乙之间不存在缔约关系，因而不存在缔约过失责任，因此A选项错误。B选项，丙终止与甲的磋商，并经比较与乙签约，是正常的商业行为，并不违反诚信原则，不须承担缔约过失责任，因此B选项错误。C、D选项，丁假借订立合同，与甲恶意磋商，应向甲承担缔约过失责任，因此C选项正确，D选项错误。（法考2010）", "type": "single", "topic": "专题二 民法典合同编", "page": 42, "subject": "相关法", "id": "xg_162"},
  {"question": "1. 甲乙两公司签订了一份购销合同，该合同标的是法律禁止流通的物品，其余条款均齐备并符合规定，并有独立", "options": ["A. 该合同所有条款均无效", "B. 该合同有效，但无法履行", "C. 该合同无效，但不影响合同中独立存在的有关争议的条款的效力", "D. 该合同的效力待定"], "answer": "C", "explanation": "根据《民法典》第153条第1款的规定，违反法律、行政法规的强制性规定的民事法", "type": "single", "topic": "专题二 民法典合同编", "page": 43, "subject": "相关法", "id": "xg_163"},
  {"question": "25. 甲公司于6月5日以传真方式向乙公司求购一台机床，要求“立即回复”。乙公司当日回复“收到传真”。6月10日，甲公司电话催问，乙公司表示同意按甲公司报价出售，要其于6月15日来人签订合同书。6月15日，甲公司前往签约，乙公司要求加价，未获同意，乙公司遂拒绝签约。对此，下列哪一种说法是正确的？(单选)", "options": ["A. 买卖合同于6月5日成立", "B. 买卖合同于6月10日成立", "C. 买卖合同于6月15日成立", "D. 甲公司有权要求乙公司承担缔约过失责任"], "answer": "D", "explanation": "A、B、C选项，甲、乙就售价已经达成一致，双方商定要签合同书，但由于乙拒绝签字，合同的形式要件并未具备，所以甲乙间的合同并未成立，因此A、B、C选项均错误。D选项，乙与甲达成合意后又反悔，属于违背诚信原则的行为，应承担缔约过失责任，因此D选项正确。（法考2005）", "type": "single", "topic": "专题二 民法典合同编", "page": 43, "subject": "相关法", "id": "xg_164"},
  {"question": "26. 德凯公司拟为新三板上市造势，在无真实交易意图的情况下，短期内以业务合作为由邀请多家公司来其主要办公地点洽谈。其中，真诚公司安排授权代表往返十余次，每次都准备了详尽可操作的合作方案，德凯公司佯装感兴趣并屡次表达将签署合同的意愿，但均在最后一刻推脱拒签。其间，德凯公司还将知悉的真诚公司的部分商业秘密不当泄露。对此，下列哪些说法是错误的？(多选)", "options": ["A. 未缔结合同，则德凯公司就磋商事宜无需承担责任", "B. 虽未缔结合同，但德凯公司构成恶意磋商，应赔偿损失", "C. 未缔结合同，则商业秘密属于真诚公司自愿披露，不应禁止外泄", "D. 德凯公司也付出了大量的工作成本，可向真诚公司主张赔偿 第三章 合同的效力"], "answer": "ACD", "explanation": "本题中，德凯公司恶意磋商，且泄露商业秘密构成缔约过失，应承担赔偿责任，对德凯公司所付出的工作成本，真诚公司并无过错，无需赔偿，因此A、C、D选项错误，B选项正确。（法考2017）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 43, "subject": "相关法", "id": "xg_165"},
  {"question": "2. 李某在二手车市场向王某购买了一辆二手车,并签订了车辆买卖合同。该车里程表显示行驶里程3万公里,但实际上该车已经行驶了20万公里。王某明知里程有误,却故意隐瞒该事实,以较高价格将该车卖给李某。李某购买该二手车后发现上述问题,与王某产生纠纷,向人民法院提起诉讼。根据民法典总则编、合同编及相关规定,下列说法哪些是正确的?(多选)", "options": ["A. 如果李某请求撤销车辆买卖合同,可以同时请求王某承担违约责任", "B. 李某有权请求人民法院予以撤销车辆买卖合同", "C. 如果李某请求撤销车辆买卖合同,可以同时请求王某承担缔约过失责任", "D. 车辆买卖合同中有仲裁条款的,李某有权请求仲裁机构予以撤销该合同"], "answer": "BCD", "explanation": "A、C选项,《民法典》第157条规定：“民事法律行为无效、被撤销或者确定不发生效力后,行为人因该行为取得的财产,应当予以返还;不能返还或者没有必要返还的,应当折价补偿。有过错的一方应当赔偿对方由此所受到的损失……”,该买卖合同被撤销后,自始无效,不能再请求承担违约责任,但可以请求王某承担缔约过失责任,A选项错误,C选项正确。B、D选项,《民法典》第148条规定：“一方以欺诈手段,使对方在违背真实意思的情况下实施的民事法律行为,受欺诈方有权请求人民法院或者仲裁机构予以撤销”,因此B、D选项正确。(新编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 44, "subject": "相关法", "id": "xg_166"},
  {"question": "3. 关于合同效力,下列说法正确的有哪项?(单选)", "options": ["A. 甲是蓝天公司的法定代表人,甲代表蓝天公司订立的所有合同均对蓝天公司发生效力", "B. 乙是白云公司员工,超越该公司的经营范围与黄沙公司签订合同,该合同无效", "C. 丙在未被紫云公司授权的情况下,以紫云公司的名义与绿田公司签订电脑买卖合同,绿田公司向紫云公司发货,紫云公司收到货后向绿田公司付款,电脑买卖合同对紫云公司和绿田公司发生效力", "D. 丁与黑石公司签订土地买卖合同,约定相关手续由"], "answer": "C", "explanation": "《民法典》第504条规定：“法人的法定代表人或者非法人组织的负责人超越权限订立的合同,除相对人知道或者应当知道其超越权限外,该代表行为有效,订立的合同对法人或者非法人组织发生效力”,因此并不是所有代表行为都发生效力,A选项错误。《民法典》第505条规定：“当事人超越经营范围订立的合同的效力,应当依照《民法典》总则编中有关民事法律行为效力的规定以及合同编中的其他相关规定确定,不得仅以超越经营范围确认合同无效”,因此B选项错误。《民法典》第503条规定：“无权代理人以被代理人的名义订立合同,被代理人已经开始履行合同义务或者接受相对人履行的,视为对合同的追认”,紫云公司接受绿田公司的电脑并付款视为对合同的追认,C选项正确。《民法典》第502条第2款规定：“……应当办理申请批准等手续的当事人未履行义务的,对", "type": "single", "topic": "专题二 民法典合同编", "page": 44, "subject": "相关法", "id": "xg_167"},
  {"question": "1. 甲酒厂欲从乙粮库购买一千吨高粱,业务员因为疏忽在买卖合同中未写明高粱质量。关于该合同,下列哪些说法是正确的?(多选)", "options": ["A. 质量是民法典合同编规定的合同条款,欠缺该条款的合同不成立", "B. 该合同明确了买卖标的物但未明确质量,因此成立但未生效", "C. 该合同已经生效,但甲乙仍可就质量条款进行进一步协"], "answer": "CD", "explanation": "A、B、C选项,《民法典》第510条规定:“合同生效后,当事人就质量、价款或者报酬、履行地点等内容没有约定或者约定不明确的,可以协议补充;不能达成补充协议的,按照合同相关条款或者交易习惯确定”,因此未明确质量可通过协议补充确定,不会导致合同不成立或未生效,因此A、B选项错误,C选项正确。D选项,《民法典》第", "type": "multiple", "topic": "专题二 民法典合同编", "page": 45, "subject": "相关法", "id": "xg_168"},
  {"question": "4. 甲在校园网站发布出售一辆二手自行车的广告,标价1000元。乙认识甲,到甲的宿舍表示以900元购买,甲不同意。乙于是对甲说:“行! 就按你说的,1100元。”乙通过手机给甲转账1000元后,甲要求乙再付100元,乙表示刚才口误,本欲说1000元说成了1100元,甲不同意。关于甲、乙间的这一二手自行车的买卖,下列表述正确的是?(单选)", "options": ["A. 甲在校园网站发布的广告属于要约邀请", "B. 甲、乙未达成合意,自行车买卖合同不成立", "C. 甲、乙间成立售价为1100元的自行车买卖合同", "D. 甲、乙间成立售价为1000元的自行车买卖合同"], "answer": "D", "explanation": "A选项商业广告和宣传原则上属于要约邀请,但是,内容具体确定则属于要约。甲在校内二手平台上发布的出售自行车的信息内容具体确定,属于要约而非要约邀请。故A选项错误。B、C、D选项,甲发布的商业广告和宣传属于要约,价款1000元。乙出价900元,甲不同意。后乙又给甲发微信“就按你说的价来,1100元”。其中,如果以“就按你说的价来”解释乙的意思表示含义,则价款为1000元,且乙明确表示是自己打错了。因此,应当认定两人间成立了1000元的合同。故B、C项错误,D项正确。(法考2023,思维扩展)", "type": "single", "topic": "专题二 民法典合同编", "page": 45, "subject": "相关法", "id": "xg_169"},
  {"question": "5. 甲公司和乙公司签订钢材购销合同,双方法定代表人经董事会授权签字盖章,后发现甲公司的章是假的。对此,下列说法正确的是?(单选)", "options": ["A. 合同效力待定", "B. 有效", "C. 无效", "D. 合同不成立 第四章 合同的履行"], "answer": "B", "explanation": "《合同编司法解释》第22条规定“法定代表人、负责人或者工作人员以法人、非法人组织的名义订立合同且未超越权限,法人、非法人组织仅以合同加盖的印章不是备案印章或者系伪造的印章为由主张该合同对其不发生效力的,人民法院不予支持。”法定代表人在合同上签字并加盖公章的行为,表明其是以法人名义签订合同,是真实的意思表示,属于有权代表,因此合同已生效,不能仅以公章是假的为由否认合同效力。(法考2024,思维扩展)", "type": "single", "topic": "专题二 民法典合同编", "page": 45, "subject": "相关法", "id": "xg_170"},
  {"question": "2. 湖南A工厂向四川B公司购买一批物品，合同对付款地点和交货期限没有约定，事后未能达成补充协议，并且按照合同有关条款或交易习惯也不能确定。根据民法典合同编的规定，下列哪些说法是正确的?(多选)", "options": ["A. 湖南A工厂付款给四川B公司应在湖南履行", "B. 湖南A工厂付款给四川B公司应在四川履行", "C. 四川B公司可以随时交货给湖南A工厂，A工厂不得有异议", "D. 四川B公司可以随时交货给湖南A工厂，但是应当给该厂必要的准备时间"], "answer": "BD", "explanation": "根据《民法典》第511条的规定，履行地点不明确，给付货币的，在接受货币一方所在地履行；履行期限不明确的，债务人可以随时履行，债权人也可以随时请求履行，但是应当给对方必要的准备时间。因此A、C选项错误，B、D选项正确。(2006)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 46, "subject": "相关法", "id": "xg_171"},
  {"question": "5. 甲公司与乙公司签订了一份手机买卖合同，约定：甲公司供给乙公司某型号手机1000部，每部单价1000元，乙公司支付定金30万元，任何一方违约应向对方支付合同总价款30%的违约金。合同签订后，乙公司向甲公司支付了30万元定金，并将该批手机转售给丙公司，每部单价1100元，指明由甲公司直接交付给丙公司。但甲公司未按约定期间交货。关于甲、乙、丙公司间违约责任的承担，下列表述正确的是：(多选)", "options": ["A. 如乙公司未向丙公司承担违约责任，则丙公司有权请求甲公司向自己承担违约责任", "B. 如乙公司未向丙公司承担违约责任，则丙公司无权请求甲公司向自己承担违约责任", "C. 如甲公司迟延向丙公司交货，则丙公司有权请求乙公司承担迟延交货的违约责任", "D. 如甲公司迟延向丙公司交货，则丙公司无权请求乙公司承担迟延交货的违约责任"], "answer": "BC", "explanation": "《民法典》第523条规定：“当事人约定由第三人向债权人履行债务，第三人不履行债务或者履行债务不符合约定的，债务人应当向债权人承担违约责任”。本题中，就乙、丙间的买卖合同而言，是一个由第三人甲履行的合同，若甲未履行或延迟履行，应由乙向丙承担违约责任，丙不能向甲主张违约责任，因此A、D选项错误，B、C选项正确。(法考2010改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 47, "subject": "相关法", "id": "xg_172"},
  {"question": "6. 甲欠丙100吨钢材，为偿还该债务，甲与乙订立了100吨钢材的买卖合同，约定由乙向丙直接交付钢材，丙也可以直接向乙请求履行，丙对此知情，也未拒绝，以下说法正确的是？(单选)", "options": ["A. 如乙不交付，丙可请求其履行且要求承担违约责任", "B. 甲对乙已经没有任何义务", "C. 乙不能向丙主张其对甲的抗辩", "D. 因合同相对性，丙不能直接向乙请求履行交付义务"], "answer": "A", "explanation": "甲与乙签订钢材买卖合同，约定第三人丙可以直接请求债务人乙向其履行，第三人丙对此情且未拒绝。因此，第三人丙基于债权人甲、债务人乙之间的约定取得了独立的请求权，第三人丙可以请求债务人乙向其履行100吨钢材，如债务人乙不交付，第三人丙可以直接追究债务人乙的违约责任。债务人乙基于买卖合同对债权人甲的抗辩，可以向第三人丙主张。因此A选项正确，C、D选项错误。虽然第三人丙取得独立的请求权，但并不会导致合同直接当事人甲丧失相应的权利和义务。如乙不交付100吨钢材，甲亦可追究乙的违约责任。因此B选项错误。(法考2020)", "type": "single", "topic": "专题二 民法典合同编", "page": 47, "subject": "相关法", "id": "xg_173"},
  {"question": "7. 根据民法典合同编及相关规定，下列关于合同履行的哪些说法是正确的？(多选)", "options": ["A. 当事人应当按照约定全面履行自己的义务", "B. 当事人互负债务，没有先后履行顺序的，应当同时履行", "C. 当事人互负债务，有先后履行顺序，先履行一方未履行"], "answer": "ABCD", "explanation": "A选项，《民法典》第509条第1款规定：“当事人应当按照约定全面履行自己的义务”，因此A选项正确。B选项，《民法典》第525条规定：“当事人互负债务，没有先后履行顺序的，应当同时履行……”，因此B选项正确。C选项，《民法典》第526条规定：“当事人互负债务，有先后履行顺序，应当先履行债务一方未履行的，后履行一方有权拒绝其履行请求……”，因此C选项正确。D选项，《民法典》第527条第1款规定：“应当先履行债务的当事人，有确切证", "type": "multiple", "topic": "专题二 民法典合同编", "page": 47, "subject": "相关法", "id": "xg_174"},
  {"question": "8. 甲公司与乙公司签订合同,由甲公司为乙公司翻译一批技术资料,约定完成全部翻译工作后再支付报酬。后甲公司有确切证据证明乙公司经营状况严重恶化,濒临破产。根据民法典合同编及相关规定,下列哪种说法是错误的?(多选)", "options": ["A. 甲公司应当无条件地继续履行该合同", "B. 甲公司可以中止履行该合同,并及时通知对方", "C. 甲公司可以直接解除该合同", "D. 甲公司可以要求乙公司承担违约责任"], "answer": "ACD", "explanation": "《民法典》第527条规定:“应当先履行债务的当事人,有确切证据证明对方有下列情形之一的,可以中止履行:(一)经营状况严重恶化……”,《民法典》第528条规定:“当事人依据前条规定中止履行的,应当及时通知对方……”,因此A、C、D选项错误,当选。(2013改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 48, "subject": "相关法", "id": "xg_175"},
  {"question": "9. 甲公司与乙公司达成买卖合同,约定甲公司有偿向乙公司供应原料。根据民法典合同编及相关规定,下列关于合同履行抗辩权的哪些说法是正确的?(多选)", "options": ["A. 合同未明确履行顺序,甲公司在乙公司付款之前有权拒绝其履行要求", "B. 合同约定先供货后付款,甲公司未按时供货,乙公司有权拒付货款", "C. 合同约定先供货后付款,甲公司有确切证据证明乙公司经营状况严重恶化,可以中止履行合同", "D. 合同约定先供货后付款,甲公司有确切证据证明乙公司丧失商业信誉,可以中止履行合同"], "answer": "ABCD", "explanation": "A选项,甲公司、乙公司互负债务且没有先后履行顺序的,应当同时履行。甲公司在乙公司履行之前有权拒绝其履行请求,因此A选项正确。B选项,合同约定先供货后付款,应当先履行的甲公司未履行,则后履行一方乙公司有权拒绝其履行请求,因此B选项正确。C、D选项,根据《民法典》第527条的规定,应当先履行债务的当事人,有确切证据证明对方有经营状况严重恶化,丧失商业信誉的情形,可以中止履行,因此C、D选项正确。(2015)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 48, "subject": "相关法", "id": "xg_176"},
  {"question": "10. 甲乙两公司订立合同,约定甲公司送货到乙公司住所。后乙公司变更住所,未及时通知甲公司,导致甲公司无法按照约定地点交货。根据民法典合同编及相关规定,下列哪些说法是正确的?(多选)", "options": ["A. 甲公司应当及时联络乙公司并继续履行合同", "B. 甲公司可以解除合同", "C. 甲公司可以中止履行"], "answer": "CD", "explanation": "《民法典》第529条规定:“债权人分立、合并或者变更住所没有通知债务人,致使履行债务发生困难的,债务人可以中止履行或者将标的物提存”,因此A、B选项错误,C、D选项正确。(2015,思维扩展)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 48, "subject": "相关法", "id": "xg_177"},
  {"question": "1. 根据民法典合同编及相关规定，债权人代位行使债务人的债权，应当同时符合哪些条件？(多选)", "options": ["A. 债权人对债务人的债权合法", "B. 债务人怠于行使其到期债权，对债权人造成损害", "C. 债务人的债权已经到期", "D. 债务人的债权不是专属于债务人自身的债权 - 48 -"], "answer": "ABCD", "explanation": "《民法典》第535条第1、2款规定：“因债务人怠于行使其债权或者与该债权有关的从权利，影响债权人的到期债权实现的，债权人可以向人民法院请求以自己的名义代位行使债务人对相对人的权利，但是该权利专属于债务人自身的除外。代位", "type": "multiple", "topic": "专题二 民法典合同编", "page": 49, "subject": "相关法", "id": "xg_178"},
  {"question": "11. 甲公司向乙公司购买小轿车，约定7月1日预付10万元，10月1日预付20万元，12月1日乙公司交车时付清尾款。甲公司按时预付第一笔款。乙公司于9月30日发函称因原材料价格上涨，需提高小轿车价格。甲公司于10月1日拒绝，等待乙公司答复未果后于10月3日向乙公司汇去20万元。乙公司当即拒收，并称甲公司迟延付款构成违约，要求解除合同，甲公司则要求乙公司继续履行。下列哪一表述是正确的？(单选)", "options": ["A. 甲公司不构成违约", "B. 乙公司有权解除合同", "C. 乙公司可行使先履行抗辩权", "D. 乙公司可要求提高合同价格"], "answer": "A", "explanation": "A选项正确，在乙公司表示要涨价的情况下，甲公司有理由认为自己支付价款后，乙公司有可能不交付汽车，甲公司有权行使不安抗辩权，中止支付第二期价款，不构成违约。B选项错误，乙公司并未催告甲公司支付第二期价款，且在乙公司主张解除合同之前，甲公司已经支付了第二期价款，乙公司不得解除合同。C选项错误，甲公司已经交付了第二期价款，乙公司不得主张先履行抗辩权。D选项错误，乙公司主张涨价的理由是原材料价格上涨，当事人订立合同时应当预见到原材料价格的正常波动，属于正常市场风险，乙公司不得主张涨价。", "type": "single", "topic": "专题二 民法典合同编", "page": 49, "subject": "相关法", "id": "xg_179"},
  {"question": "12. 甲置业公司与乙建筑公司因某小区业务缔结建设工程承包合同，甲置业公司为发包人，乙建筑公司为总承包人，双方约定了固定款额事项以及不适用的特殊事项。施工期间，因受全球疫情影响，某施工原材料价格上涨至150%，乙建筑公司提出调整申请，遭到甲置业公司拒绝。关于乙建筑公司的主张，下列说法正确的是：(单选)", "options": ["A. 符合自愿原则", "B. 违背公序良俗", "C. 适用情势变更", "D. 符合商业自担风险 第五章 合同的保全"], "answer": "C", "explanation": "A选项，在合同关系中，自愿原则是指双方的自愿并达成合意，而非一方当事人的单方自愿，因此A选项错误。B选项，建设工程合同对于工程款的约定，以及疫情对工程款的影响等，均不涉及公共利益和善良风俗，因此B选项错误。C选项，《民法典》第533条规定：“合同的基础条件发生了当事人在订立合同时无法预见的、不属于商业风险的重大变化，继续履行合同对于当事人一方明显不公平的，受不利影响的当事人可以与对方重新协商；在合理期限内协商不成的，当事人可以请求人民法院或者仲裁机构变更或者解除合同。人民法院或者仲裁机构应当结合案件的实际情况，根据公平原则变更或者解除合同”，因疫情导致原材料价格大幅上涨，后果是合同履行明显不公平，不能实现乙建筑公司的缔约目的，属于情势变更的范畴，因此C选项正确。D选项，情势变更本身即意味着商业风险自负是有例外的，因此D选项错误。(新编，思维扩展)", "type": "single", "topic": "专题二 民法典合同编", "page": 49, "subject": "相关法", "id": "xg_180"},
  {"question": "2. 甲公司欠乙公司工程款50万元，债务到期后甲公司因资金不足久拖不还。同时，李某欠甲公司的80万元货款也已到期，但甲公司未以任何方式催促李某还款，对乙公司造成了损害。根据民法典合同编及相关规定，下列关于乙公司行使代位权的哪些说法是正确的?(多选)", "options": ["A. 乙公司可以向人民法院请求以自己的名义代位行使甲公司对李某的债权", "B. 乙公司可以向人民法院请求以甲公司的名义代位行使甲公司对李某的债权", "C. 乙公司代位权行使的范围为80万元", "D. 乙公司行使代位权的必要费用，由甲公司负担"], "answer": "AD", "explanation": "根据《民法典》第535条的规定，甲公司欠乙公司工程款50万元已到期，同时李某欠甲公司80万元货款也已到期，甲公司怠于行使其债权从而影响了乙公司债权的实现。乙公司可以以自己的名义代位行使甲公司对李某的债权，代位权行使的范围为50万元，乙公司行使代位权的必要费用，由债务人甲公司负担，因此A、D选项正确，B、C选项错误。(2014)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 50, "subject": "相关法", "id": "xg_181"},
  {"question": "3. 王某享有对张某的到期债权100万元，同时，王某欠李某80万元，该债务已到期。此时，王某没有其他财产偿还给李某，但为逃避该笔债务，王某一直不积极催讨对张某的到期债权。根据民法典合同编及相关规定，下列关于李某行使代位权的说法错误的是?(多选)", "options": ["A. 李某可以以自己的名义起诉张某", "B. 李某的诉讼请求为100万元", "C. 李某既可以以自己的名义起诉张某，也可以以王某的名义起诉张某", "D. 李某可以以张某为被申请人向仲裁机构申请仲裁"], "answer": "BCD", "explanation": "A、C选项，李某可以以自己的名义起诉张某，不能以王某名义起诉张某，因此A选项正确，C选项错误。B选项，李某诉讼请求数额为80万元，因此B选项错误。D选项，代位权只能向法院起诉，不能仲裁，因此D选项错误。(2019)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 50, "subject": "相关法", "id": "xg_182"},
  {"question": "4. 甲为乙的债权人。对乙享有的已经到期的下列哪项债权，甲可以向人民法院请求以自己的名义代位行使?(单选)", "options": ["A. 乙的儿子应当给付的赡养费", "B. 丙欠乙的劳动报酬", "C. 丁欠乙的人身伤害赔偿费", "D. 戊欠乙的货款"], "answer": "D", "explanation": "赡养费、劳动报酬、人身伤害赔偿费均为专属于债务人自身的权利，不可代位行使，因此A、B、C选项错误，D选项正确。(2008)", "type": "single", "topic": "专题二 民法典合同编", "page": 50, "subject": "相关法", "id": "xg_183"},
  {"question": "5. 甲公司欠乙公司工程款100万元，债务到期后甲公司因资金不足久拖不还。同时，甲公司将价值200万元的200件产品", "options": ["A. 乙公司可以请求人民法院撤销甲公司的无偿转让行为", "B. 乙公司在其知道或者应当知道撤销事由之日起5年内均可行使撤销权", "C. 乙公司撤销权行使的范围为200万元", "D. 乙公司行使撤销权的必要费用，由甲公司负担"], "answer": "AD", "explanation": "A选项，《民法典》第538条规定：“债务人以放弃其债权、放弃债权担保、无偿转让财产等方式无偿处分财产权益，或者恶意延长其到期债权的履行期限，影响债权人的债权实现的，债权人可以请求人民法院撤销债务人的行为”，债务人甲公司将其财产无偿转让给丙公司，给债权人乙公司造成了损害，乙公司可以行使其撤销权，因此A选项正确。B选项，《民法典》第541条规定：“撤销权自债权人知道或者应当知道撤销事由之日起一年内行使。自债务人的行为发生之日起五年内没有行使撤销权的，该撤销权消灭”，因此B选项错误。C、D选项，《民法典》第540条规定：“撤销权的行使范围\n- 49 -\nCS 扫描全能王\n3亿人都在用的扫描App", "type": "single", "topic": "专题二 民法典合同编", "page": 50, "subject": "相关法", "id": "xg_184"},
  {"question": "5. 甲公司和乙公司签订了一份服务器买卖合同。在合同履行期间，甲公司拟将其在合同中的全部权利义务转让给丙公司，根据民法典合同编及相关规定，下列哪些说法是正确的？(多选)", "options": ["A. 该转让需要经过乙公司同意", "B. 该转让需要通知乙公司，但无需经其同意", "C. 转让后，乙公司有权向丙公司主张其对甲公司的抗辩", "D. 转让后，乙公司不得向丙公司主张其对甲公司的抗辩"], "answer": "AC", "explanation": "A、B选项，《民法典》第555条规定：“当事人一方经对方同意，可以将自己在合同中的权利和义务一并转让给第三人”，因此A选项正确,B选项错误。C、D选项，《民法典》第548条规定：“债务人接到债权转让通知后，债务人对让与人的抗辩，可以向受让人主张”，《民法典》第553条规定：“债务人转移债务的，新债务人可以主张原债务人对债权人的抗辩”，因此乙公司有权向丙公司主张其对甲公司的抗辩，C选项正确,D选项错误。(2016改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 53, "subject": "相关法", "id": "xg_185"},
  {"question": "6. 甲欠乙10万元,后乙通知甲将该债权转让给丙。甲接到该通知时,乙欠甲5万元,并且甲的债权先于转让的债权到期。根据民法典合同编的规定,下列说法哪些是正确的?(多选)", "options": ["A. 本案中乙的债权转让对甲发生效力", "B. 本案中乙的债权转让不对甲发生效力", "C. 甲可以向乙主张抵销", "D. 甲可以向丙主张抵销"], "answer": "AD", "explanation": "A、B选项，《民法典》第546条第1款规定：“债权人转让债权，未通知债务人的，该转让对债务人不发生效力”，乙转让债权通知了甲，对甲发生效力，因此A选项正确,B选项错误。C、D选项，《民法典》第549条规定：“有下列情形之一的，债务人可以向受让人主张抵销：(一)债务人接到债权转让通知时，债务人对让与人享有债权，且债务人的债权先于转让的债权到期或者同时到期……”，在甲欠乙的10万元中，其中5万元可以主张抵销，债务人甲主张抗辩时，可以向新债权人丙主张，因此C选项错误,D选项正确。(2018改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 53, "subject": "相关法", "id": "xg_186"},
  {"question": "7. 乙公司欠甲公司30万元,于2020年9月20到期。同时甲公司须在2020年9月20日清偿对乙公司的20万元货款。甲公司在同年9月18日与丙公司签订书面协议,转让其对乙公司的30万元债权。同年9月24日,乙公司接到甲公司关于转让债权的通知后,便主张20万元的抵销权。下列说法哪些是正确的?(多选)", "options": ["A. 甲公司与丙公司之间的债权转让合同于9月24日生效", "B. 乙公司接到债权转让通知后,即负有向丙公司清偿30万元的义务", "C. 乙公司可以向丙公司主张20万元的抵销权", "D. 丙公司可以就30万元债务的清偿,要求甲公司和乙公司承担连带责任"], "answer": "BC", "explanation": "A选项，甲、丙公司之间依法成立的债权转让协议在甲、丙公司自签订时9月18日即生效，因此A选项错误。B选项，乙公司接收通知后，债权转让对乙公司生效，因此B选项正确。C选项，《民法典》第549条规定：“有下列情形之一的，债务人可以向受让人主张抵销：(一)债务人接到债权转让通知时，债务人对让与人享有债权，且", "type": "multiple", "topic": "专题二 民法典合同编", "page": 53, "subject": "相关法", "id": "xg_187"},
  {"question": "8. 梁某与甲旅游公司签订合同，约定梁某参加甲公司组织的旅游团赴某地旅游。旅游出发前15日，梁某因出差通知甲公司，由韩某替代跟团旅游。到达履行地后，为保证游客更好体验当地风情，未征得韩某同意，甲公司将其旅游业务转给当地的乙公司。下列哪些表述是正确的？(多选)", "options": ["A. 由于梁某与甲公司之间签订的合同并未约定不得转让，因此梁某通知甲公司即发生合同转让效力", "B. 由于梁某与甲公司之间签订的合同并未约定不得转让，因此梁某应当与甲公司协商一致后合同转让才生效", "C. 为保证游客更好地体验当地风情，甲公司将其旅游业务转给当地的乙公司，转让有效", "D. 甲公司未与韩某协商，甲公司将其旅游业务转给当地的乙公司不生效"], "answer": "AD", "explanation": "A、B选项，根据《民法典》第546条第1款的规定，债权人转让债权，通知债务人，对债务人发生效力，梁某转让属于合同权利转让，通知即生效，因此A选项正确，B选项错误。C、D选项，根据《民法典》第551条第1款的规定，债务人将债务转移给第三人的，应当经债权人同意，旅行公司转让属于合同义务转让，需要征得权利人韩某的同意才能生效，因此C选项错误，D选项正确。（新编）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 54, "subject": "相关法", "id": "xg_188"},
  {"question": "9. 2021年2月1日，甲、乙签订买卖合同并约定半个月后同时履行。合同到期后，甲延迟一周交货，乙收到货物后未付货款10万元。2021年3月1日，甲与丙签订合同，将甲对乙的10万元债权转让给丙。2021年3月3日甲就转让通知乙。根据《民法典》的相关规定，乙的哪些主张符合法律规定：(多选)", "options": ["A. 乙向丙提出只支付6万元，因为甲交付的货物有40%不合格", "B. 乙提出因甲欠乙4万元债务，且于2021年2月15日到期，因此只需支付丙6万元", "C. 乙主张只需支付6万元，因为合同约定，如果延迟履行合同，甲应当承担4万元违约金", "D. 乙提出因甲并未与其协商即转让债权，转让无效，只能按照合同约定向甲偿还"], "answer": "ABC", "explanation": "A选项，《民法典》第548条规定：“债务人接到债权转让通知后，债务人对让与人的抗辩，可以向受让人主张”，因此A选项符合法律规定。B选项，根据《民法典》第549条的规定，债务人对让与人享有的债权，且债务人的债权先于转让的债权到期，债务人可以向受让人主张抵销，因此B选项符合法律规定。C选项，债务人的债权和转让的债权是基于同一合同产生的，因此C选项符合法律规定。D选项，债权人甲转让债权不需要债务人乙同意，通知即生效，因此D选项不符合法律规定。（新编）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 54, "subject": "相关法", "id": "xg_189"},
  {"question": "1. 根据民法典合同编及相关规定,关于合同解除的效力,下列哪些说法是正确的?(多选)", "options": ["A. 合同解除的,合同的权利义务关系终止", "B. 合同的权利义务关系终止不影响合同中结算和清理条款的效力", "C. 合同解除后,已经履行的,当事人必须恢复原状", "D. 合同解除后,尚未履行的,终止履行"], "answer": "ABD", "explanation": "A选项,《民法典》第557条第2款规定:“合同解除的,该合同的权利义务关系终止”,因此A选项正确。B选项,《民法典》第567条规定:“合同的权利义务关系终止,不影响合同中结算和清理条款的效力”,因此B选项正确。C、D选项,《民法典》第566条第1款规定:“合同解除后,尚未履行的,终止履行;已经履行的,根据履行情况和合同性质,当事人可以请求恢复原状或者采取其他补救措施,并有权请求赔偿损失”,因此C选项错误,D选项正确。(2015改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 55, "subject": "相关法", "id": "xg_190"},
  {"question": "11. 甲公司欠乙公司200万元货款,甲公司与丙公司约定丙公司加入甲公司对乙公司的债务,但只承诺还100万元,并及时将情况通知了乙公司,乙公司表示同意,后丙公司偿还了50万元。根据《民法典》,下列哪些选项是正确的?(多选)", "options": ["A. 该债务承担协议自通知乙公司时对乙公司有效", "B. 乙公司有权请求丙再支付50万元", "C. 乙公司有权请求丙支付150万元", "D. 该债务承担协议自乙公司同意时对乙公司有效 第七章 合同的权利义务终止"], "answer": "AB", "explanation": "在甲公司与丙公司约定丙公司加入甲公司对乙公司的债务。该债务承担协议自通知乙公司时对乙公司有效。因此,A选项正确,D选项错误。甲公司与丙公司约定丙公司加入甲公司对乙公司的债务,但只承诺还100万元。因此,第三人丙公司仅在100万元范围内和债务人甲公司一起对债权人乙公司承担连带责任。后丙公司偿还了50万元。因此,乙公司有权请求丙再支付50万元而非150万元。因此,B选项正确,C选项错误。(法考2020,思维扩展)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 55, "subject": "相关法", "id": "xg_191"},
  {"question": "3. 根据民法典合同编及相关规定,有下列哪些情形之一的,当事人可以解除合同?(多选)", "options": ["A. 因不可抗力致使不能实现合同目的", "B. 当事人一方迟延履行主要债务,经催告后在合理期限内仍未履行", "C. 当事人一方不完全履行,但不影响合同目的的实现", "D. 在履行期限届满之前,当事人一方明确表示或者以自己的行为表明不履行主要债务"], "answer": "ABD", "explanation": "《民法典》第563条第1款规定：“有下列情形之一的,当事人可以解除合同：(一)因不可抗力致使不能实现合同目的；(二)在履行期限届满之前,当事人一方明确表示或者以自己的行为表明不履行主要债务；(三)当事人一方迟延履行主要债务,经催告后在合理期限内仍未履行；(四)当事人一方迟延履行债务或者有其他违约行为致使不能实现合同目的；(五)法律规定的其他情形”,因此A、B、D选项属于解除合同的情形,C选项不符合解除合同的条件。(2019)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 56, "subject": "相关法", "id": "xg_192"},
  {"question": "4. 根据民法典合同编及相关规定,下列哪些情况下,一方当事人无权解除合同?(多选)", "options": ["A. 甲、乙签订钢材购销合同,约定甲在11月1日前向乙交付钢材500吨,货到付款。当过了11月1日,甲仍未向乙履行交付义务", "B. 甲、乙签订钢材购销合同,约定甲在11月1日前向乙交付钢材500吨,货到付款。11月1日,甲向乙交付钢材450吨,剩余50吨经催告后,仍未予交付", "C. 甲从商店购买电视机一台,回家后发现图像正常,但没有声音", "D. 甲从商店购买电视机一台,回家发现品质良好,只是画面边角处有一个“坏点”"], "answer": "ABD", "explanation": "A选项,在尚未导致不能实现合同目的的状况下,甲延迟履行主要债务,乙应当先向甲催告,未催告情形下乙无权解除合同。B选项,合同主要债务已经履行,合同目的已经实现,一方当事人无权解除合同。C选项,电视机没有声音致使不能实现合同目的,一方当事人有权解除合同。D选项,电视机屏幕有坏点可以要求更换,不会致使不能实现合同目的,一方当事人无权解除合同。(2018改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 56, "subject": "相关法", "id": "xg_193"},
  {"question": "6. 甲商场为在中秋节前销售月饼，与乙食品厂签订了一份月饼供销合同，约定乙食品厂在农历八月初五交货。后乙食品厂因人员变动等原因，未能按照约定及时交货。甲商场到农历八月十五时仍未收到月饼。对此，下列哪些说法是正确的？ （多选）", "options": ["A. 甲商场可以解除合同，但必须征得乙食品厂同意", "B. 甲商场可以解除合同，但是应当通知乙食品厂", "C. 甲商场不得解除合同，因为未向乙食品厂进行催告", "D. 甲商场可以要求乙食品厂承担违约责任"], "answer": "BD", "explanation": "本题中，因甲商场到农历八月十五时仍未收到月饼，致使不能实现合同目的的，甲商场可以解除合同，但是应当通知乙食品厂，解除合同后，甲商场可以要求乙食品厂承担违约责任，因此A、C选项错误，B、D选项正确。(2008)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 57, "subject": "相关法", "id": "xg_194"},
  {"question": "7. 东北某农场和某粮食加工厂于2021年2月签订稻谷购销合同，约定农场于2021年12月底向加工厂供应稻谷1000吨，货到后付款。后农场因当地在2021年发生异常干旱而导致颗粒无收，无法履行供货合同。在此情形下，下列说法哪项是正确的？（单选）", "options": ["A. 农场可以单方中止履行合同", "B. 农场可以单方解除合同", "C. 粮食加工厂可以单方变更合同", "D. 粮食加工厂可以要求农场继续履行合同"], "answer": "B", "explanation": "根据《民法典》第563条第1款的规定，因不可抗力致使不能实现合同目的的，当事人可以解除合同，农场因发生异常干旱颗粒无收属于因不可抗力致使不能实现合同目的，因此农场可以单方解除合同，A选项错误，B选项正确。C选项，合同变更需要当事人协商一致，粮食加工厂不能单方变更合同，C选项错误。D选项，《民法典》第580条第1款规定：“当事人一方不履行非金钱债务或者履行非金钱债务不符合约定的，对方可以请求履行，但是有下列情形之一的除外：（一）法律上或者事实上不能履行；（二）债务的标的不适于强制履行或者履行费用过高；（三）债权人在合理期限内未请求履行。”本题中属于事实上不能履行的情形，因此，粮食加工厂不能要求农场继续履行，D选项错误。(新编)", "type": "single", "topic": "专题二 民法典合同编", "page": 57, "subject": "相关法", "id": "xg_195"},
  {"question": "8. 甲公司欠乙商场货款12万元，同时乙商场应付甲公司装修费12万元。现甲公司欠款到期，甲公司欲以已到期的装修费冲抵货款。根据民法典合同编及相关规定，下列说法哪些是正确的？（多选）", "options": ["A. 甲公司可以将自己的债务与乙商场的债务抵销", "B. 双方债务性质不同，不得抵销", "C. 甲公司主张抵销的，须经乙商场同意"], "answer": "AD", "explanation": "《民法典》第568条规定：“当事人互负债务，该债务的标的物种类、品质相同的，任何一方可以将自己的债务与对方的到期债务抵销；但是，根据债务性质、按照当事人约定或者依照法律规定不得抵销的除外。当事人主张抵销的，应当通知对方。通知自到达对方时生效。抵销不得附条件或者附期限”。本题中，甲公司欠乙商场的货款和乙商场欠甲公司的装修费都属于金钱债务，债务性质相同，可以主张抵销，甲公司", "type": "multiple", "topic": "专题二 民法典合同编", "page": 57, "subject": "相关法", "id": "xg_196"},
  {"question": "9. 甲与乙签订销售空调100台的合同，但当甲向乙交付时，乙以空调市场疲软为由，拒绝受领，要求甲返还货款。下列说法哪些是正确的？(多选)", "options": ["A. 甲可以向有关部门提存这批空调", "B. 空调在向当地公证机关提存后，因遇火灾，烧毁5台，其损失应由甲承担", "C. 提存费用应由乙支付", "D. 若自提存之日起5年内乙不领取空调，则归甲所有 第八章 违约责任"], "answer": "AC", "explanation": "A选项，乙以空调市场疲软为由拒绝受领的行为属于无正当理由拒绝受领，甲可以提存，因此A选项正确。B、C选项，提存后的风险以及提存费用应当由乙承担，因此B选项错误，C选项正确。D选项，若自提存之日起5年内乙不领取空调，要视情况决定空调归甲所有或者归国家所有，因此D选项错误。(法考2003)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 58, "subject": "相关法", "id": "xg_197"},
  {"question": "6. 甲公司与乙公司签订了一份购销合同，合同总价款为20万元，双方约定，一方违约的，需支付总价款3%的违约金。甲公司还依照约定向乙公司支付了定金1万元。后乙公司未履行合同约定的义务。根据民法典合同编及相关规定，下列说法哪些是正确的？（多选）", "options": ["A. 甲公司可以要求乙公司双倍返还定金", "B. 甲公司只能要求乙公司支付违约金", "C. 甲公司可以要求乙公司双倍返还定金，同时支付违约金", "D. 甲公司可以选择适用定金或者违约金条款"], "answer": "AD", "explanation": "《民法典》第588条第1款规定：‘当事人既约定违约金，又约定定金的，一方违约时，对方可以选择适用违约金或者定金条款’；《民法典》第587条规定：‘债务人履行债务的，定金应当抵作价款或者收回。给付定金的一方不履行债务或者履行债务不符合约定，致使不能实现合同目的的，无权请求返还定金；收受定金的一方不履行债务或者履行债务不符合约定，致使不能实现合同目的的，应当双倍返还定金’。违约金和定金可以择其一，不能同时适用，收受定金的一方乙公司不履行债务，致使不能实现合同目的的，应当双倍返还定金，因此A、D选项正确，B、C选项错误。（2010改编）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 60, "subject": "相关法", "id": "xg_198"},
  {"question": "7. 根据民法典合同编及相关规定，下列哪些属于可以并用的违约责任承担方式？（多选）", "options": ["A. 继续履行与赔偿损失", "B. 继续履行与支付违约金", "C. 采取补救措施与赔偿损失", "D. 双倍返还定金与支付违约金"], "answer": "ABC", "explanation": "根据《民法典》第588条第1款的规定，双倍返还定金与支付违约金不能同时适用，其余违约责任承担方式均可以并用，因此A、B、C选项正确，D选项错误。（2017）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 60, "subject": "相关法", "id": "xg_199"},
  {"question": "8. 2022年9月1日，李某在网站上购买甲公司的商品，同年9月2日，甲公司将该商品交付承运人乙公司，要求乙公司于同年9月7日前将该商品送达李某。乙公司迟至同年9月8日开始运输，同年9月9日，乙公司在运输过程中因突遇山洪导致该商品灭失。根据民法典合同编的规定，下列说法哪些是正确的？（多选）", "options": ["A. 甲公司应当向李某承担违约责任", "B. 乙公司不得免除违约责任", "C. 乙公司可以部分或者全部免除违约责任", "D. 甲公司和乙公司应当向李某承担违约责任"], "answer": "AB", "explanation": "A、D选项，《民法典》第593条规定：“当事人一方因第三人的原因造成违约的，应当依法向对方承担违约责任……”，因乙公司的原因导致甲公司对李某违约的，应由甲公司向李某承担违约责任，因此A选项正确，D选项错误。B、C选项，《民法典》第590条规定：“当事人一方因不可抗力不能履行合同的，根据不可抗力的影响，部分或者全部免除责任，但是法律另有规定的除外。因不可抗力不能履行合同的，应当及时通知对方，以减轻可能给对方造成的损失，并应当在合理期限内提供证明。当事人迟延履行后发生不可抗力的，不免除其违约责任。”，突遇山洪属于不可抗力因素，但乙公司晚于甲公司要求的时间开始运输，属于迟延履行，不能免除其违约责任，因此B选项正确，C选项错误。（新编）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 60, "subject": "相关法", "id": "xg_200"},
  {"question": "9. 北京甲公司和上海乙公司签订汽车买卖合同，约定甲公司组装生产并向乙公司出售500辆汽车。甲公司", "options": ["A. 乙公司有权请求甲公司承担违约责任", "B. 乙公司有权请求丙公司承担违约责任", "C. 乙公司有权请求丁公司承担违约责任", "D. 乙公司有权请求丁公司驾驶员承担违约责任"], "answer": "A", "explanation": "《民法典》第593条规定：“当事人一方因第三人的原因造成违约的，应当依法向对方承担违约责任。当事人一方和第三人之间的纠纷，依照法律规定或者按照约定处理”。本题中，汽车买卖合同的当事人双方为甲公司和乙公司，因此当甲公司无法交货，乙公司有权请求甲公司承担违约责任，甲公司可以按照零部件买卖合同要求丙公司承担违约责任，丙公司可以按照运输合同要求丁公司承担违约责任，因此A选项正确，B、C、D选项错误。（2017）", "type": "single", "topic": "专题二 民法典合同编", "page": 60, "subject": "相关法", "id": "xg_201"},
  {"question": "10. 甲公司向乙公司购买价值100万元的货物。合同约定由甲公司向乙公司支付定金10万元,甲公司支付定金15万元。后乙公司未交货,致使不能实现合同目的。根据民法典合同编的规定,甲公司能请求乙公司返还的定金数额是?(单选)", "options": ["A. 10万元", "B. 15万元", "C. 30万元", "D. 20万元"], "answer": "B", "explanation": "根据《民法典》第586条第2款规定，定金的数额由当事人约定，但不得超过主合同标的额的20%。本题中，实际交付定金15万元，并未超过合同的20%，以实际交付定金15万元为准。", "type": "single", "topic": "专题二 民法典合同编", "page": 61, "subject": "相关法", "id": "xg_202"},
  {"question": "11. 甲与乙签订一份货款为人民币50万元的买卖合同,并依约定交付给乙定金人民币15万元。后乙违约没有履行该合同。乙应返还给甲人民币?(单选)", "options": ["A. 10万元", "B. 20万元", "C. 25万元", "D. 30万元"], "answer": "C", "explanation": "根据《民法典》第586条、587规定:“……定金的数额由当事人约定;但是,不得超过主合同标的的额的20%,超过部分不产生定金的效力。实际交付的定金数额多于或者少于约定数额的,视为变更约定的定金数额。债务人履行债务的,定金应当抵作价款或者收回。给付定金的一方不履行债务或者履行债务不符合约定,致使不能实现合同目的的,无权请求返还定金;收受定金的一方不履行债务或者履行债务不符合约定,致使不能实现合同目的的,应当双倍返还定金。”本题中甲交付给乙的15万元定金超过合同标的的20%,仅有10万元认定为定金,另外5万元不发生定金效力,在乙违约后双倍退还定金应当退还20万定金,加上5万元,共计应当退还25万元。因此C选项正确。\n(新编)", "type": "single", "topic": "专题二 民法典合同编", "page": 61, "subject": "相关法", "id": "xg_203"},
  {"question": "12. 詹某将房屋租给音乐生小翠,约定小翠教詹某儿子小詹弹钢琴,每晚一小时,课时费抵房租。上了几个月的课后,小翠消失了一个月,詹某只能另请洪老师上课,一个月课时费2000元。一个月后小翠回来,詹某可以向小翠主张多少数额的违约责任?(单选)", "options": ["A. 詹某支出的课酬2000元", "B. 当地音乐生的平均课酬3000元", "C. 当地平均房租4000元", "D. 小翠无须支付任何费用"], "answer": "A", "explanation": "A、D选项,詹某与小翠之间成立合同关系,小翠无正当理由未履行一个月的钢琴授课合同义务,应当承担违约责任。根据《民法典》第581条规定:“当事人一方不履行债务或者履行债务不符合约定,根据债务的性质不得强制履行的,对方可以请求其负担由第三人替代履行的费用。”据此,小翠无正当理由未对詹某履行提供钢琴授课的合同义务,詹某可请求第三人履行该义务,并请求小翠承担相应的费用。因此A项正确,D项错误。B、C选项,根据《民法典》第584条规定:“当事人一方不履行合同义务或者履行合同义务不符合约定,造成对方损失的,损失赔偿额应当相当于因违约所造成的损失,包括合同履行后可以获得的利益;但是,不得超过违约一方订立合同时预见到或者应当预", "type": "single", "topic": "专题二 民法典合同编", "page": 61, "subject": "相关法", "id": "xg_204"},
  {"question": "13. 李某在古玩店发现刘某以1万元出售一只清代紫烟壶，李某知道这壶是一对。收藏家胡某寻求另一只正以10万元报价在古玩园内收购，李某与刘某达成协议以1万元购买，于3日后付款，并向刘某支付5000元定金。李某前往胡某家中以10万元达成协议，3日内交货，胡某向李某支付2万元定金。3日后刘某取出时不小心将紫烟壶摔碎。关于本案，下列哪一说法是正确的？（多选）", "options": ["A. 刘某只需将定金返还给李某", "B. 刘某应当向李某返还5000元双倍定金", "C. 刘某应当向李某返还7000元定金", "D. 李某应当向胡某返还20000元双倍定金"], "answer": "CD", "explanation": "定金的数额由当事人约定；但是，不得超过主合同标的额的20%，超过部分不产生定金的效力。刘某和李某之间的买卖合同标的额为1万元，定金最多为2000元，而李某向刘某支付5000元定金。因此，5000元中，2000元产生定金的效力，3000元不产生定金的效力。后刘某不小心将紫烟壶摔碎，导致根本违约，依法应当承担双倍返还定金的罚则，即4000元，再加上不产生定金效力的3000元，刘某应当向李某返还7000元。因此，A、B选项错误，C选项正确。D选项，根据《民法典》第593条规定“当事人一方因第三人的原因造成违约的，应当依法向对方承担违约责任。”李某因刘某的原因造成对胡某的违约，依法应当向胡某承担违约责任，即双倍返还胡某向李某给付的2万元定金。因此，D选项正确。（法考2022改编，思维扩展）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 62, "subject": "相关法", "id": "xg_205"},
  {"question": "14. 喜好网球和游泳的赵某从某房地产公司购买某小区商品房一套，交房时发现购房时该公司售楼部所展示的该小区模型中的网球场和游泳池并不存在。经查，该小区设计中并无网球场和游泳池。根据民法典合同编及相关规定，下列说法正确的是？（多选）", "options": ["A. 因房地产公司的行为构成欺诈，赵某有权要求退房", "B. 赵某如不要求退房，有权请求该房地产公司承担违约责任", "C. 赵某如要求退房，有权请求该房地产公司双倍返还购房款", "D. 赵某如要求退房，有权请求该房地产公司承担缔约过错责任"], "answer": "ABD", "explanation": "A选项，房地产公司展示的模型与小区实际设计不符，构成对赵某的欺诈，因此购房合同属于可撤销合同，赵某有权要求退房，A选项正确。B、D选项，撤销后有过错的房地产公司应承担缔约过失责任，如果赵某不申请撤销，则可以违约为由，请求房地产公司承担违约责任，因此B、D选项正确。C选项，买卖合同的解除或者撤销均无双倍返还的规定，因此C选项错误。（新编）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 62, "subject": "相关法", "id": "xg_206"},
  {"question": "1. 下列哪些合同属于《民法典》中规定的有名合同? (多选)", "options": ["A. 合作经营合同", "B. 融资租赁合同", "C. 劳务派遣合同", "D. 技术合同"], "answer": "BD", "explanation": "根据《民法典》所确定的有名合同共有19种, 具体包括: 买卖合同, 供用电、水、气、热力合同, 赠与合同, 借款合同, 保证合同, 租赁合同, 融资租赁合同, 保理合同, 承揽合同, 建设工程合同, 运输合同, 技术合同, 保管合同, 仓储合同, 委托合同, 物业服务合同, 行纪合同, 中介合同, 合伙合同, 因此B、D选项正确, A、C选项错误。(2018)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 63, "subject": "相关法", "id": "xg_207"},
  {"question": "2. 根据民法典合同编的规定, 下列哪些技术合同无效?(多选)", "options": ["A. 甲公司与乙公司签订的技术开发合同, 约定就开发完成的发明创造申请专利的权利属于甲公司", "B. 丙公司与丁公司签订的技术服务合同, 约定丁公司不得从其他公司获得类似技术或者其他竞争性技术", "C. 戊公司与己公司签订的技术转让合同, 约定己公司购买与实施该技术无关的大型设备五台", "D. 庚公司与辛公司签订的专利实施许可合同, 约定辛公司不得对该专利提出无效宣告请求"], "answer": "BCD", "explanation": "A选项, 根据《民法典》第859、860条的规定, 当事人之间可以约定申请专利的权利, 以约定优先, 因此A选项技术合同有效。B、C、D选项,《民法典》第850条规定: “非法垄断技术或者侵害他人技术成果的技术合同无效”,《最高人民法院关于审理技术合同纠纷案件适用法律若干问题的解释》第10条规定: “下列情形, 属于民法典第850条所称的‘非法垄断技术’: ……(二)限制当事人一方从其他来源获得与技术提供方类似技术或者与其竞争的技术……(四)要求技术接受方接受并非实施技术必不可少的附带条件, 包括购买非必需的技术、原材料、产品、设备、服务以及接收非必需的人员等……(六)禁止技术接受方对合同标的技术知识产权的有效性提出异议或者对提出异议附加条件”, 因此B、C、D选项中技术合同均无效。(2008改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 63, "subject": "相关法", "id": "xg_208"},
  {"question": "3. 甲公司向乙公司转让了一项技术秘密。技术转让合同履行完毕后, 经查该技术秘密是甲公司通过不正当手段从丙公司获得的, 但乙公司对此并不知情, 且支付了合理对价。下列哪项说法是正确的?(单选)", "options": ["A. 乙公司有权要求甲公司返还其支付的对价, 但不能要求甲公司赔偿其因此受到的损失", "B. 乙公司可在其取得时的范围内继续使用该技术秘密, 但应向丙公司支付合理的使用费", "C. 技术转让合同无效, 甲公司和乙公司应向丙公司承担连带责任", "D. 技术转让合同有效, 但甲公司应向丙公司承担侵权责任"], "answer": "B", "explanation": "《民法典》第850条规定: “非法垄断技术或者侵害他人技术成果的技术合同无效”。A选项, 技术转让合同标的为他人技术秘密, 属于侵害他人技术成果的技术合同, 合同无效, 因此甲公司应当承担缔约过失责任, 除返还乙公司支付的对价, 还应当赔偿乙公司因此受到的损失, A选项错误。《最高人民法院关于审理技术合同纠纷案件适用法律若干问题的解释》第12条规定: “根据民法典第850条的规定, 侵害他人技术秘密的技术合同", "type": "single", "topic": "专题二 民法典合同编", "page": 63, "subject": "相关法", "id": "xg_209"},
  {"question": "4. 甲公司委托乙研究所为其开发一种技术，并签订了技术开发合同，但双方没有约定技术成果的归属。乙研究所按约定交付了符合要求的技术成果，甲公司按约定支付了研究开发经费和报酬。后乙研究所就该技术成果提交了专利申请。根据民法典合同编及相关规定，下列哪些说法是正确的?(多选)", "options": ["A. 乙研究所就该技术成果申请专利的行为侵犯了甲公司就该技术成果申请专利的权利", "B. 乙研究所享有就该技术成果申请专利的权利，但若乙研究所转让该专利申请权，则甲公司享有以同等条件优先受让的权利", "C. 如果乙研究所的该专利申请被授予专利权，则甲公司未经乙研究所许可，不得以生产经营为目的实施该专利", "D. 如果乙研究所的该专利申请被授予专利权，则甲公司可以依法实施该专利"], "answer": "BD", "explanation": "《民法典》第859条规定：“委托开发完成的发明创造，除法律另有规定或者当事人另有约定外，申请专利的权利属于研究开发人。研究开发人取得专利权的，委托人可以依法实施该专利。研究开发人转让专利申请权的，委托人享有以同等条件优先受让的权利”。本题中，乙研究所为受托人，实际完成了研发，在甲公司和乙研究所没有约定的前提下，申请专利的权利属于乙研究所，若乙研究所的该专利申请被授予专利权，则甲公司可以依法实施该专利，若乙研究所转让该专利申请权，则甲公司享有以同等条件优先受让的权利，因此A、C选项错误，B、D选项正确。(2013改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 64, "subject": "相关法", "id": "xg_210"},
  {"question": "5. 张某和李某合作开发完成一项发明创造，但未约定权利归属。该项发明创造完成后，张某想要申请专利，而李某则想通过商业秘密保护，不同意申请专利。根据民法典合同编及相关规定，下列哪种说法是正确的?(单选)", "options": ["A. 张某不得申请专利", "B. 张某可以申请专利，获得授权后专利权归张某和李某共有", "C. 张某可以申请专利，获得授权后专利权归张某所有，李某可以免费实施该专利", "D. 张某可以申请专利，获得授权后专利权归张某所有，但获得的收益应在两人之间分配"], "answer": "A", "explanation": "《民法典》第860条规定：“合作开发完成的发明创造，申请专利的权利属于合作开发的当事人共有；当事人一方转让其共有的专利申请权的，其他各方享有以同等条件优先受让的权利。但是，当事人另有约定的除外……合作开发的当事人一方不同意申请专利的，另一方或者其他各方不得申请专利”，因此A选项正确，B、C、D选项错误。(2015)", "type": "single", "topic": "专题二 民法典合同编", "page": 64, "subject": "相关法", "id": "xg_211"},
  {"question": "13. 甲单位委托乙研究所就某技术项目提供可行性论证。双方在合同中约定乙研究所在三个月内提供咨询报告，甲单位在收到符合约定要求的报告后应支付乙研究所10万元报酬。根据民法典合同编及相关规定，下列哪种说法是正确的?(多选)", "options": ["A. 该合同属于技术咨询合同", "B. 如果乙研究所未按期提供咨询报告，则应当承担减收或者免收报酬等违约责任", "C. 如果双方没有约定，则乙研究所利用甲单位提供的技术资料和工作条件完成的新的技术成果，属于甲单位", "D. 如果双方没有约定，则甲单位按照乙研究所符合约定要求的咨询报告和意见作出决策所造成的损失，由乙研究所承担 第十章 委托合同"], "answer": "AB", "explanation": "A选项，《民法典》第878条第1款规定：“技术咨询合同是当事人一方以技术知识为对方就特定技术项目提供可行性论证、技术预测、专题技术调查、分析评价报告等所订立的合同”，该合同属于技术咨询合同，因此A选项正确。B选项，《民法典》第881条第2款规定：“技术咨询合同的受托人未按期提出咨询报告或者提出的咨询报告不符合约定的，应当承担减收或者免收报酬等违约责任”，因此B选项正确。C选项，《民法典》第885条规定：“技术咨询合同、技术服务合同履行过程中，受托人利用委托人提供的技术资料和工作条件完成的新的技术成果，属于受托人……”，因此C选项错误。D选项，《民法典》第881条第3款规定：“技术咨询合同的委托人按照受托人符合约定要求的咨询报告和意见作出决策所造成的损失，由委托人承担，但是当事人另有约定的除外”，因此D选项错误。(2012改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 67, "subject": "相关法", "id": "xg_212"},
  {"question": "3. 甲农场委托乙运输公司将农场的水果运往某市水果市场。合同签订后，乙运输公司有更大的运输业务，欲将运输甲农场水果的任务委托给丙运输公司。根据民法典合同编及相关规定，下列哪些说法是正确的?(多选)", "options": ["A. 乙运输公司经甲农场同意，可以转委托丙运输公司运输甲农场的水果", "B. 乙运输公司有权转委托丙运输公司，仅需事后通知甲农场", "C. 转委托未经甲农场同意的，乙运输公司应当对丙运输公司的行为承担责任", "D. 转委托未经甲农场同意的，乙运输公司仅需就其对丙运输公司的指示承担责任"], "answer": "AC", "explanation": "《民法典》第923条规定：“受托人应当亲自处理委托事务。经委托人同意，受托人可以转委托。转委托经同意或者追认的，委托人可以就委托事务直接指示转委托的第三人，受托人仅就第三人的选任及其对第三人的指示承担责任。转委托未经同意或者追认的，受托人应当对转委托的第三人的行为承担责任；但是，在紧急情况下受托人为了维护委托人的利益需要转委托第三人的除外”，因此A、C选项正确，B、D选项错误。(2015改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 68, "subject": "相关法", "id": "xg_213"},
  {"question": "4. 王某委托胡某销售一批货物，双方约定胡某不收取报酬。根据民法典合同编及相关规定，下列说法哪些是正确的?(多选)", "options": ["A. 胡某有权请求王某偿还为处理委托事务垫付的必要费用及其利息", "B. 胡某因为故意给王某造成损失的，王某可以要求胡某赔偿", "C. 胡某因为重大过失给王某造成损失的，王某可以要求胡某赔偿", "D. 如果胡某转委托第三人处理王某委托的事务，应经过王某同意"], "answer": "ABCD", "explanation": "A选项，《民法典》第921条规定：“委托人应当预付处理委托事务的费用。受托人为处理委托事务垫付的必要费用，委托人应当偿还该费用并支付利息”，因此A选项正确。B、C选项，《民法典》第929条第1款规定：“……无偿的委托合同，因受托人的故意或者重大过失造成委托人损失的，委托人可以请求赔偿损失”，因此B、C选项正确。D选项，根据《民法典》第923条的规定，经委托人同意，受托人可以转委托，因此D选项正确。(2010改编)", "type": "multiple", "topic": "专题二 民法典合同编", "page": 68, "subject": "相关法", "id": "xg_214"},
  {"question": "5. 甲公司委托乙专利代理机构代为处理本公司专利", "options": ["A. 即使合同没有提及乙处理相关事务的费用负担，甲公司仍有义务支付乙所为处理委托事务而垫付的费用", "B. 经甲公司同意，乙可以转委托，同时对第三人的行为承担责任", "C. 乙可以随时解除与甲公司的合同", "D. 因不可归责于乙的事由，委托事务不能完成的，甲公司应当向乙支付相应的报酬"], "answer": "ACD", "explanation": "A选项，《民法典》第921条规定：“委托人应当预付处理委托事务的费用。受托人为处理委托事务垫付的必要费用，委托人应当偿还该费用并支付利息”，因此A选项正确。B选项，《民法典》第923条规定：“……转委托经同意或者追认的，委托人可以就委托事务直接指示转委托的第三人，受托人仅就第三人的选任及其对第三人的指示", "type": "single", "topic": "专题二 民法典合同编", "page": 68, "subject": "相关法", "id": "xg_215"},
  {"question": "6. 甲公司委托姚某购买一批化肥。在甲公司的授权范围内，姚某以自己的名义与乙公司签订了一份化肥买卖合同，并在订立合同的过程中，将他与甲公司之间的代理关系告诉了乙公司。根据民法典合同编及相关规定，下列关于该买卖合同的说法哪项是正确的？(单选)", "options": ["A. 该合同直接约束姚某和乙公司，但有确切证据证明该合同只约束甲公司和乙公司的除外", "B. 该合同直接约束甲公司和乙公司，但有确切证据证明该合同只约束姚某和乙公司的除外", "C. 该合同直接约束甲公司、乙公司和姚某", "D. 该合同无效，对甲公司、乙公司和姚某均没有约束力"], "answer": "B", "explanation": "《民法典》第925条规定：“受托人以自己的名义，在委托人的授权范围内与第三人订立的合同，第三人在订立合同时知道受托人与委托人之间的代理关系的，该合同直接约束委托人和第三人；但是，有确切证据证明该合同只约束受托人和第三人的除外”。本题中，姚某以自己的名义，在甲公司的授权范围内与乙公司订立合同，并且姚某将他与甲公司之间的代理关系告诉了乙公司，因此该合同直接约束甲公司和乙公司，但有确切证据证明该合同只约束姚某和乙公司的除外，因此A、C、D选项错误，B选项正确。(2010改编)", "type": "single", "topic": "专题二 民法典合同编", "page": 69, "subject": "相关法", "id": "xg_216"},
  {"question": "7. 甲委托乙购买一批货物，但要求以乙的名义签订合同，乙同意，遂与丙签订了买卖合同。后由于甲的原因，乙不能按时向丙支付货款。乙向丙说明了自己是受甲委托向丙购买货物。对此，下列哪项说法是正确的？(单选)", "options": ["A. 丙只能要求甲支付货款", "B. 丙只能要求乙支付货款", "C. 丙选定甲作为相对人要求其支付货款后，不得再变更为乙", "D. 丙选定乙作为相对人要求其支付货款后，乙的财产不足以清偿债务的，可以重新选择甲作为相对人"], "answer": "C", "explanation": "《民法典》第926条第2款规定：“受托人因委托人的原因对第三人不履行义务，受托人应当向第三人披露委托人，第三人因此可以选择受托人或者委托人作为相对人主张其权利，但是第三人不得变更选定的相对人”。本题中，甲为委托人，乙为受托人，丙为第三人，乙以自己的名义与丙签订合同，但因为甲的原因未能按时履行合同义务，在乙向丙披露了委托人甲后，丙有权选择甲或者乙作为相对人主张其权利，但丙不得变更选定的相对人，因此A、B、D选项错误，C选项正确。(2008)", "type": "single", "topic": "专题二 民法典合同编", "page": 69, "subject": "相关法", "id": "xg_217"},
  {"question": "2. 根据民法典合同编的规定，下列关于委托合同的说法哪些是正确的?(多选) - 66 -", "options": ["A. 委托合同可以采用非书面形式", "B. 委托合同可以是无偿的", "C. 委托合同可以就一项或数项事务特别委托受托人处理，也可以概括委托受托人处理一切事务", "D. 受托人处理委托事务取得的财产，应当转交给委托人"], "answer": "ABCD", "explanation": "A选项，委托合同原则上属于不要式合同，当事人可以采用口头形式或书面形式，因此A选项正确。B选项，《民法典》第929条第1款规", "type": "multiple", "topic": "专题二 民法典合同编", "page": 67, "subject": "相关法", "id": "xg_218"},
  {"question": "袁某和祖某系夫妻，后二人吵架，袁某离家出走。2年后，依祖某申请，法院宣告袁某失踪。四年后，因袁某一一直未偿还借款债务，债权人胡某申请法院宣告袁某死亡。关于本案，下列说法正确的有？（多选）", "options": ["A. 袁某被宣告失踪后，丧失民事行为能力", "B. 胡某的宣告申请，法院不应予以支持", "C. 袁某父母不同意，可以申请撤回失踪宣告", "D. 祖某提出离婚诉讼的，法院应当准许"], "answer": "BD", "explanation": "A选项，袁某被宣告失踪后，其民事行为能力不受影响，因此A选项错误。B选项，《总则编司法解释》第16条规定，被申请人的债权人、债务人、合伙人等民事主体不能认定为宣告死亡的利害关系人，债权人胡某无权向法院申请宣告袁某死亡，因此B选项正确。C选项，自然人下落不明满2年的，利害关系人可以向人民法院申请宣告该自然人为失踪人。其中，配偶和父母均为利害关系人且申请宣告失踪无顺序先后的限制。袁某的配偶祖某有权申请袁某失踪，袁某父母不同意的，不可以申请撤回失踪宣告，因此C选项错误。D选项，《民法典》第1079条规定，一方被宣告失踪，另一方提起离婚诉讼的，应当准予离婚，因此祖某提出离婚诉讼，法院应当准许，D选项正确。（法考2022）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 17, "subject": "相关法", "id": "xg_219"},
  {"question": "甲公司分立为乙丙两公司，约定由乙公司承担甲公司全部债务的清偿责任，丙公司受甲公司全部债务。关于该协议的效力，下列哪一项是正确的？(单选)", "options": ["A. 该协议仅对乙丙两公司具有约束力，对甲公司的债权人", "B. 即便丙公司未成立，某科技园就租赁权，仍可向黄大等3人主张", "C. 如黄金黄研究会未成立，则某科技园的租赁权消灭，黄大等3人承担连带债务", "D. 黄金黄研究会成立后，某印刷厂就租赁权，既可向黄金黄研究会主张，也可向黄大等3主张"], "answer": "A", "explanation": "根据《民法典》第67条第2款规定，法人分立后，分立的法人享有连带债权，承担连带债务，但债权人和债务人另有约定的除外。本题中，甲公司分立为乙丙两公司后的约定对内有效，对外并不当然有效，除非债权人和债务人另有约定。", "type": "single", "topic": "专题二 民法典合同编", "page": 20, "subject": "相关法", "id": "xg_220"},
  {"question": "甲公司法定代表人胡某被灌醉后，订立了一份无益于公司的合同。关于该合同的性质，下列表述正确的是？（单选）", "options": ["A. 恶意串通", "B. 乘人之危", "C. 无权代理", "D. 显失公平"], "answer": "D", "explanation": "胡某与相对人订立合同，不存在胡某与相对人通谋损害甲公司利益的事实，不构成恶意串通，因此A选项错误。胡某醉酒并非危难，所以本合同不构成乘人之危，因此B选项错误。胡某为代理人，其为甲公司订立合同，并不构成代理，因此C选项不选。胡某醉酒情况下，相对人在意识上比胡某清醒，且相对人利用了这一优势，所以本合同构成显失公平，因此D选项正确。", "type": "single", "topic": "专题二 民法典合同编", "page": 31, "subject": "相关法", "id": "xg_221"},
  {"question": "根据民法典合同编及相关规定，下列哪种情形适用合同编的规定？（单选）", "options": ["A. 商标权人林某与某公司签订的商标权转让协议", "B. 张某与某福利院签订的收养该福利院孤儿的协议", "C. 房屋征收部门对被征收人郑某作出的征收决定及其补偿决定", "D. 刘某与徐某签订的解除婚姻关系协议"], "answer": "A", "explanation": "根据民法典合同编的规定，合同是民事主体之间设立、变更、终止民事法律关系的协议。婚姻、收养、监护等有关身份关系的协议，适用有关身份关系的法律规定；没有规定的，可以依据其性质参照本编规定。因此，商标权转让协议属于民事主体之间的协议，适用合同编的规定。", "type": "single", "topic": "专题二 民法典合同编", "page": 44, "subject": "相关法", "id": "xg_222"},
  {"question": "根据民法典合同编及相关规定，下列说法正确的是？（多选）", "options": ["A. 合同关系是发生在平等的民事主体之间的法律关系", "B. 当事人缔结合同应当遵循诚实信用原则", "C. 合同关系应当为有偿关系", "D. 合同关系的缔结以当事人间的自愿为基础"], "answer": "ABD", "explanation": "合同关系是发生在平等的民事主体之间的法律关系，当事人缔结合同应当遵循诚实信用原则，合同关系的缔结以当事人间的自愿为基础。合同关系并不一定是有偿关系，无偿合同也是合同的一种形式。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 44, "subject": "相关法", "id": "xg_223"},
  {"question": "根据民法典合同编及相关规定，当事人对合同条款的理解有争议的，应当按照下列哪些因素确定该条款的真实意思？（多选）", "options": ["A. 合同所使用的词句", "B. 合同的有关条款", "C. 合同的目的", "D. 交易习惯以及诚实信用原则"], "answer": "ABCD", "explanation": "根据民法典第466条第1款的规定，当事人对合同条款的理解有争议的，应当按照合同所使用的词句、合同的有关条款、合同的目的、交易习惯以及诚实信用原则等因素确定该条款的真实意思。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 44, "subject": "相关法", "id": "xg_224"},
  {"question": "甲用伪造的乙公司公章，以乙公司名义与不知情的丙公司签订了买卖合同，以次充好，将劣质食用油卖给丙公司。关于该合同，下列哪一表述是正确的？（单选）", "options": ["A. 如乙公司追认，则丙公司有权通知乙公司撤销", "B. 如乙公司追认，则丙公司有权请求法院撤销", "C. 无论乙公司是否追认，丙公司均有权通知乙公司撤销", "D. 无论乙公司是否追认，丙公司均有权要求乙公司履行"], "answer": "B", "explanation": "甲的行为属于无权代理，且构成欺诈。如果乙公司追认，丙公司可以请求法院撤销合同，因为合同是在欺诈的情况下签订的。", "type": "single", "topic": "专题二 民法典合同编", "page": 38, "subject": "相关法", "id": "xg_225"},
  {"question": "北京市的甲公司和上海市的乙公司采用合同书形式订立合同。在合同订立过程中，双方在深圳市谈妥合同主要条款后，在广州市盖章。根据民法典合同编及相关规定，该合同成立的地点为下列哪个城市？（单选）", "options": ["A. 北京市", "B. 上海市", "C. 深圳市", "D. 广州市"], "answer": "D", "explanation": "《民法典》第493条规定：‘当事人采用合同书形式订立合同的，最后签名、盖章或者按指印的地点为合同成立的地点，但是当事人另有约定的除外’，因此该合同成立的地点为广州市，A、B、C选项错误，D选项正确。（2014）", "type": "single", "topic": "专题二 民法典合同编", "page": 48, "subject": "相关法", "id": "xg_226"},
  {"question": "撤回要约的通知在该要约到达乙公司之前到达乙公司", "options": ["A. 撤回要约的通知在该要约到达乙公司之前到达乙公司", "B. 撤回要约的通知在乙公司发出承诺通知之前到达乙公司", "C. 撤回要约的通知与该要约同时到达乙公司", "D. 撤回要约的通知在乙公司发出承诺通知的同时到达乙公司"], "answer": "D", "explanation": "根据《民法典》第477条规定：‘撤销要约的意思表示以非对话方式作出的，应当在受要约人作出承诺之前到达受要约人’，撤销通知应当在甲公司发出承诺通知之前到达甲公司，因此D选项正确。(2017)", "type": "single", "topic": "专题二 民法典合同编", "page": 46, "subject": "相关法", "id": "xg_227"},
  {"question": "根据民法典合同编及相关规定，在没有约定的情况下，对于采用数据电文形式订立合同，下列说法哪些是正确的？（多选）", "options": ["A. 发件人有主营业地的，其主营业地为合同成立的地点", "B. 发件人没有主营业地的，其住所地为合同成立的地点", "C. 收件人有主营业地的，其主营业地为合同成立的地点", "D. 收件人没有主营业地的，其住所地为合同成立的地点"], "answer": "CD", "explanation": "《民法典》第492条第2款规定：‘采用数据电文形式订立合同的，收件人的主营业地为合同成立的地点；没有主营业地的，其住所地为合同成立的地点。当事人另有约定的，按照其约定’，因此A、B选项错误，C、D选项正确。（201改编）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 49, "subject": "相关法", "id": "xg_228"},
  {"question": "某家具制造商与批发商签订的合同是该家具制造商为了重复使用而预先拟定的合同书，订立合同时并未与该批发商协商相关条款。该合同书中规定，如果因为家具质量原因给消费者造成损害的，家具制造商概不负责。且该责任条款并没有采取合理的方式提请批发商注意。根据民法典合同编及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 该责任条款是格式条款", "B. 如果家具因为质量原因给消费者造成损害，该家具制造商应当承担责任", "C. 该责任条款有效", "D. 如果家具因为质量原因给消费者造成损害，该家具制造商应当承担责任"], "answer": "AB", "explanation": "A选项，《民法典》第496条第1款规定：‘格式条款是当事人为了重复使用而预先拟定，并在订立合同时未与对方协商的条款’，因此A选项正确。B选项，《民法典》第497条规定：‘有下列情形之一的，该格式条款无效：……（二）提供格式条款一方不合理地免除或者减轻其责任等与对方有重大利害关系的条款，按照对方的要求，对该条款予以说明。提供格式条款的一方未履行提示或者说明义务，致使对方没有注意或者理解与其有重大利害关系的条款的，对方可以主张该条款不成为合同的内容’；家具制造商没有采取合理的方式提请批发商注意，批发商可以主张该条款不成为合同的内容，因此B选项正确，C、D选项错误。（2016改编）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 49, "subject": "相关法", "id": "xg_229"},
  {"question": "根据民法典合同编及相关规定，当事人在订立合同过程中有下列哪些情形给对方造成损失的，应当承担损害赔偿责任？（多选）", "options": ["A. 故意提供虚假情况", "B. 假借订立合同，恶意进行磋商", "C. 不正当地使用在订立合同过程中知悉的商业秘密", "D. 泄露在订立合同过程中知悉的商业秘密"], "answer": "ABCD", "explanation": "A、B选项，《民法典》第500条规定：‘当事人在订立合同过程中有下列情形之一，造成对方损失的，应当承担赔偿责任：（一）假借订立合同，恶意进行磋商；（二）故意隐瞒与订立合同有关的重要事实或者提供虚假情况；（三）有其他违背诚信原则的行为’，因此A、B选项正确。C、D选项，《民法典》第501条规定：‘当事人在订立合同过程中知悉的商业秘密或者其他应当保密的信息，无论合同是否成立，不得泄露或者不正当地使用；泄露、不正当地使用该商业秘密或者信息，造成对方损失的，应当承担赔偿责任’，因此C、D选项正确。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 51, "subject": "相关法", "id": "xg_230"},
  {"question": "张某又来问李某是否愿意出售车辆，李某拒绝。关于本案，下列选项正确的是？(单选)", "options": ["A. 李某应当承担违约责任", "B. 李某对张某构成违约", "C. 张某对李某构成违约", "D. 李某对张某构成违约"], "answer": "B", "explanation": "李某拒绝出售车辆，并未与张某形成合同关系，因此不承担违约责任。选项B正确，因为李某对张某的询问做出了拒绝的回应，但并未构成违约，因为没有合同存在。", "type": "single", "topic": "专题二 民法典合同编", "page": 54, "subject": "相关法", "id": "xg_231"},
  {"question": "根据《民法典》合同编及相关规定，下列说法哪些是正确？", "options": ["A. 合同当事人约定由债务人向第三人履行债务的，债务人未向第三人履行债务，应当向债权人承担违约责任", "B. 合同当事人约定由债务人向第三人履行债务的，且约定第三人可以向债务人履行债务，第三人未向债务人履行债务，应当向债权人承担违约责任", "C. 合同当事人约定由第三人向债权人履行债务的，债务人未向第三人履行债务，应当向债权人承担违约责任", "D. 合同当事人约定由第三人向债权人履行债务的，债务人未向第三人履行债务，应当向债权人承担违约责任"], "answer": "AC", "explanation": "根据《民法典》合同编的规定，合同当事人可以约定由债务人向第三人履行债务，如果债务人未履行，则应当向债权人承担违约责任。同样，如果合同当事人约定由第三人向债权人履行债务，债务人未向第三人履行债务，也应当向债权人承担违约责任。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 57, "subject": "相关法", "id": "xg_232"},
  {"question": "甲从乙电器商店购买丙公司生产的空调一台。甲乙约定，乙于次日送货，并由丙公司员工在第三日进行安装。后丙公司员工在安装过程中操作不当，对甲所购空调造成损坏。对此，下列哪些说法是正确的？", "options": ["A. 该买卖合同的当事人甲和乙电器商店", "B. 该买卖合同的当事人甲和丙公司", "C. 丙公司员工安装不当造成空调的损坏，应当由丙公司向甲承担违约责任", "D. 丙公司员工安装不当造成空调的损坏，应当由乙电器商店向丙公司承担违约责任"], "answer": "AC", "explanation": "根据合同相对性原则，甲与乙电器商店之间存在买卖合同关系，乙电器商店负责将空调交付给甲。丙公司作为乙电器商店的履行辅助人，其员工在安装过程中造成的损害，应由乙电器商店承担违约责任，但乙电器商店可以向丙公司追偿。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 57, "subject": "相关法", "id": "xg_233"},
  {"question": "李某想将自己的汽油车更换为新能源车辆，欲以8万元的价格出售其汽油车，邻座的张某听见后，表示愿意购买此车。但李某与张某向来不睦，便对张某说次日再考虑一下。第二日，张某表示拒绝。因此，李某对张某不构成要约。", "options": ["A. 李某对张某构成要约", "B. 张某对李某构成要约", "C. 李某对张某不构成要约", "D. 张某对李某不构成要约"], "answer": "C", "explanation": "李某欲以8万元出售自己汽油车的内心意思并未想与张某订立买卖合同，因此，李某对张某不构成要约，D选项错误。第二日，张某内心确实想以8万元购买李某的汽油车，想与李某订立汽油车买卖合同，因此，张某对李某构成要约，C选项正确。第二日，对于张某意欲购买汽油车的意愿，李某表示拒绝。因此，李某对张某不构成承诺。", "type": "single", "topic": "专题二 民法典合同编", "page": 53, "subject": "相关法", "id": "xg_234"},
  {"question": "方某为送汤某生日礼物，特向余某定做一件玉器。订货单上，方某指示余某将玉器交给汤某，并当场将订货情况告知汤某，且商量好汤某可以直接和余某联系以保证玉器能完好无损的送到汤某处。玉器制好后，余某委托朱某将玉器交给汤某，运送途中朱某不慎将玉器碰坏。下列哪一表述是正确的？（多选）", "options": ["A. 汤某有权要求余某承担违约责任", "B. 汤某有权要求朱某承担违约责任", "C. 方某有权要求朱某承担违约责任", "D. 方某有权要求余某承担违约责任"], "answer": "AD", "explanation": "《民法典》第522条第2款规定：‘法律规定或者当事人约定第三人可以直接请求债务人向其履行债务，第三人未在合理期限内明确拒绝，债务人未向第三人履行债务或者履行债务不符合约定的，第三人可以请求债务人承担违约责任；债务人对债权人的抗辩，可以向第三人主张’。本题中，方某指示余某将玉器交给汤某，并将订货情况告知汤某，属于当事人约定由债务人向第三人履行债务，第三人可以直接请求债务人向其履行合同，当事人一方因第三人的原因造成违约的，合同相对方和第三人均可以请求承担违约责任，而余某委托朱某运输合同中，朱某违约，并未有突破合同相对性的条件，因此汤某和方某都不能直接追究朱某的违约责任，A、D选项正确，B、C选项错误。（法考2014改编）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 58, "subject": "相关法", "id": "xg_235"},
  {"question": "用于丙公司装修使用，约定货到付款。但是货运到后，甲公司未付款。乙公司向甲公司催款，甲、丙向乙联合发函：丙公司同意就10万元建材款承担还款责任。乙公司收到函件后，未进行回应。根据民法典的相关规定，以下说法哪些是正确：（多选）", "options": ["A. 乙公司可以就其债权向甲公司主张偿还", "B. 乙公司可以就其债权向丙公司主张偿还", "C. 乙公司可以要求甲、丙承担连带债务", "D. 由于乙公司未同意丙公司还款，基于合同相对性，只能请求甲公司偿还债务"], "answer": "AB", "explanation": "根据民法典的相关规定，债权人可以向债务人主张偿还，也可以向保证人主张偿还。如果债务人和保证人共同承担债务，债权人可以要求债务人和保证人承担连带债务。在本题中，丙公司同意承担还款责任，因此乙公司可以向丙公司主张偿还。同时，乙公司也可以向甲公司主张偿还，因为甲公司是原始债务人。由于乙公司未明确拒绝丙公司的还款承诺，因此乙公司可以要求甲、丙承担连带债务。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 66, "subject": "相关法", "id": "xg_236"},
  {"question": "根据民法典合同编及相关规定，关于违约责任，下列说法哪些是正确的？（多选）", "options": ["A. 合同对违约责任没有约定或约定不明确的，可以协议补充；不能达成补充协议的，应当按照合同约定履行；合同对违约责任没有约定或约定不明确的，可以合理选择请求对方承担违约责任。", "B. 合同对违约责任没有约定或约定不明确的，可以合理选择请求对方承担违约责任。", "C. 合同对违约责任没有约定或约定不明确的，可以合理选择请求对方承担违约责任。", "D. 合同对违约责任没有约定或约定不明确的，可以合理选择请求对方承担违约责任。"], "answer": "ABD", "explanation": "《民法典》第510条规定：“合同生效后，当事人就质量、价款或者报酬、履行地点等未约定或者约定不明确的，可以协议补充；不能达成补充协议的，按照合同约定履行；合同对违约责任没有约定或者约定不明确的，可以合理选择请求对方承担违约责任。”", "type": "multiple", "topic": "专题二 民法典合同编", "page": 71, "subject": "相关法", "id": "xg_237"},
  {"question": "根据民法典合同编及相关规定，下列关于违约责任的说法是正确的？（多选）", "options": ["A. 当事人一方不履行合同义务的，应当承担违约责任。", "B. 当事人一方履行合同义务不符合约定的，应当承担违约责任。", "C. 承担违约责任的方式包括继续履行、采取补救措施、赔偿损失等。", "D. 当事人可以约定一方违约时应当根据违约情况向对方支付一定数额的违约金，也可以约定因违约产生的损失的赔偿额。"], "answer": "ABD", "explanation": "《民法典》第577条规定：“当事人一方不履行合同义务或者履行合同义务不符合约定的，应当承担违约责任。”《民法典》第580条规定：“当事人一方履行非金钱债务或者履行非金钱债务不符合约定的，对方可以请求履行，但是下列情形之一的除外：（一）法律上或者事实上不能履行；（二）债务的标的的不满足履行条件；（三）债务人在合理期限内未履行。”", "type": "multiple", "topic": "专题二 民法典合同编", "page": 71, "subject": "相关法", "id": "xg_238"},
  {"question": "当事人订立合同后合并的，由合并后的法人行使合同权利，履行合同义务", "options": ["A. 当事人订立合同后合并的，由合并后的法人行使合同权利，履行合同义务", "B. 债权人转让权利的，应当通知债务人，债务人接到债权转让通知后，债务人对让与人的抗辩，可以向受让人主张", "C. 债务人将债务全部转移给第三人的，应当经债权人同意", "D. 债务人转移债务的，新债务人不得主张原债务人对债权人的抗辩"], "answer": "B", "explanation": "该转让对债务人不发生效力，债务人接到债权转让通知后，债务人对让与人的抗辩，可以向受让人主张，因此B选项正确。C选项，《民法典》第551条规定：‘债务人将债务的全部或者部分转移给第三人的，应当经债权人同意’，因此C选项正确。D选项，《民法典》第553条规定：‘债务人转移债务的，新债务人可以主张原债务人对债权人的抗辩……’，因此D选项错误。（2013）", "type": "single", "topic": "专题二 民法典合同编", "page": 64, "subject": "相关法", "id": "xg_239"},
  {"question": "甲经乙公司股东丙介绍购买乙公司矿粉，甲依约预付了100万元货款，乙公司仅交付部分矿粉，经结算欠甲50万元货款。乙公司与丙商议，由乙公司和丙以欠款人的身份向甲出具欠条。其后，乙公司未按期支付。关于丙在欠条上签名的行为，下列哪一选项是正确的？（单选）", "options": ["A. 构成第三人代为清偿", "B. 构成免责的债务承担", "C. 构成并存的债务承担", "D. 构成无因管理"], "answer": "C", "explanation": "A选项，第三人代为清偿是指债务人以外的第三人，以消灭债务人对债权人负担的债务为目的向债权人清偿，经债权人受领，债务人对债权人的债务因清偿而全部或部分消灭的制度，丙未向甲实施清偿债务的行为，乙对甲的债务未因清偿而全部或部分消灭，不构成第三人代为清偿，因此A选项错误。B选项，乙、丙约定不会导致原债务人乙公司免责的法律效果，其应继续承担履行责任，不构成免责的债务承担，因此B选项错误。C选项，在原债务人乙公司不退出法律关系的情况下，丙加入到债务履行的法律关系中，由原债务人乙公司和丙共同向债权人承担责任，乙和丙向甲出具的欠条构成并存的债务承担，因此C选项正确。D选项，丙与乙商议后承担债务，丙承担债务的", "type": "single", "topic": "专题二 民法典合同编", "page": 64, "subject": "相关法", "id": "xg_240"},
  {"question": "甲因开饭馆向乙借款10万元，2016年8月借款期限届满。因经营不善，甲的饭馆濒临倒闭。为逃避对乙的债务，2016年9月5日，甲将店内的冰柜等物赠与丙，将市值10万元的店面以5万元的价格卖给其亲戚丁，并以两倍于市价的高价收购戊的厨房设备。丙、丁不知道该情形，戊知情。现甲无力清偿欠乙的借款。对此，下列哪些说法是正确的？（多选）", "options": ["A. 即使丙不知情，乙也能对甲的赠与行为行使撤销权", "B. 因为丁不知情，故乙不能对甲将其中一间店面卖给丁的行为行使撤销权", "C. 若乙于2017年11月8日知道甲高价收购戊的厨房设备，则乙可以自知道之日起1年内向法院申请行使撤销权", "D. 若乙于2022年3月5日知道甲高价收购戊的厨房设备，则乙可以自知道之日起1年内行使撤销权"], "answer": "ABC", "explanation": "A选项正确，因为《民法典》第541条规定：'撤销权自债权人知道或者应当知道撤销事由之日起一年内行使。自债务人的行为发生之日起五年内没有行使撤销权的，该撤销权消灭。'无论丙是否知情，乙均可行使撤销权。B选项正确，因为丁不知情，且交易价格合理，属于善意第三人，乙不能撤销该行为。C选项正确，乙在2017年11月8日知道后，可在1年内申请撤销。D选项错误，因为从2016年9月5日起算，至2022年3月5日已超过5年，撤销权消灭。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 62, "subject": "相关法", "id": "xg_241"},
  {"question": "甲公司和乙公司双方订立合同后，债权人甲公司欲将其债权转让给丙公司。根据民法典合同编及相关规定，下列哪些说法是正确的？", "options": ["A. 债权人可以将债权的全部或者部分转让给第三人", "B. 债权人转让债权的，应当通知债务人", "C. 债务人接到债权转让通知后，债务人对让与人的抗辩，可以向受让人主张", "D. 债权人转让债权的，必须经债务人同意"], "answer": "BD", "explanation": "根据《民法典》第545条规定：'债权人可以将债权的全部或者部分转让给第三人，但是有下列情形之一的除外：（一）根据债权性质不得转让；（二）按照当事人约定不得转让；（三）依照法律规定不得转让。债权人转让债权的，应当通知债务人。未经通知，该转让对债务人不发生效力。'因此，A选项错误，因为并非所有债权都可以自由转让；D选项错误，因为不需要债务人同意，只需通知即可。B、C选项正确。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 62, "subject": "相关法", "id": "xg_242"},
  {"question": "说法是正确的（多选）", "options": ["A. 甲公司只能将债权全部转让给丙公司，不能部分转让", "B. 如果依照法律规定该债权不得转让，甲公司就不能转让", "C. 如果甲公司转让债权未经债务人乙公司同意，甲公司就不能转让", "D. 如果甲公司将债权转让给丙公司，应当通知债务人乙公司，否则该转让对乙公司不发生效力"], "answer": "BD", "explanation": "根据《民法典》第546条第1款规定，如果法律规定债权不得转让，则甲公司不能转让债权。同时，根据《民法典》第546条第1款规定，债权人转让权利的，未通知债务人的，该转让对债务人不发生效力。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 63, "subject": "相关法", "id": "xg_243"},
  {"question": "根据民法典合同编及相关规定，下列关于合同转让的说法是正确的（多选）", "options": ["A. 债权人转让权利的，所有与债权有关的从权利亦受让人取得", "B. 债权人转让权利的，应当通知债务人，否则该转让对债务人不发生效力", "C. 债务人将合同的义务全部转移给第三人的，应当经债权人同意", "D. 债务人将合同的义务部分转移给第三人的，可以不经债权人同意"], "answer": "ABC", "explanation": "根据《民法典》第546条第1款规定，债权人转让权利时，所有与债权有关的从权利亦随同转移给受让人。同时，根据《民法典》第546条第1款规定，债权人转让权利的，应当通知债务人，否则该转让对债务人不发生效力。根据《民法典》第551条第1款规定，债务人将债务的全部或者部分转移给第三人的，应当经债权人同意。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 63, "subject": "相关法", "id": "xg_244"},
  {"question": "根据民法典合同编的规定，下列哪项合同的转让是合法（单选）", "options": ["A. 甲公司委托乙公司演出，邀请歌手乙演唱歌曲，乙表示同意，后甲公司演出当天乙另有演出任务，便自行决定让歌手丙代为演出", "B. 专利权人甲与乙公司签订专利实施许可合同，后乙公司未经甲同意，将合同权利义务一并转让给丙公司", "C. 债权人甲因出国急需用钱便将债务人乙欠自己的两万元债转以1万元5元的价格转给了丙，并将此事打电话通知了乙", "D. 甲委托乙公司运输货物，后乙公司未经甲同意，将该货物转由丙公司运输"], "answer": "C", "explanation": "选项C描述了债权人甲将债权转让给丙公司，并且通知了债务人乙，符合《民法典》关于债权转让的规定。", "type": "single", "topic": "专题二 民法典合同编", "page": 63, "subject": "相关法", "id": "xg_245"},
  {"question": "根据民法典合同编及相关规定，下列关于合同权利义务的哪些说法是正确的（多选）", "options": ["A. 债权人转让权利的，所有与债权有关的从权利亦受让人取得", "B. 债权人转让权利的，应当通知债务人，否则该转让对债务人不发生效力", "C. 债务人将合同的义务全部转移给第三人的，应当经债权人同意", "D. 债务人将合同的义务部分转移给第三人的，可以不经债权人同意"], "answer": "ABC", "explanation": "根据《民法典》第546条第1款规定，债权人转让权利时，所有与债权有关的从权利亦随同转移给受让人。根据《民法典》第546条第1款规定，债权人转让权利的，应当通知债务人，否则该转让对债务人不发生效力。根据《民法典》第551条第1款规定，债务人将债务的全部或者部分转移给第三人的，应当经债权人同意。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 63, "subject": "相关法", "id": "xg_246"},
  {"question": "年12月底归还8000元，未做任何说明。根据民法典的规定，哪期借款得到了部分清偿？（单选）", "options": ["A. 第一次借款", "B. 第二次借款", "C. 第三次借款", "D. 第四次借款"], "answer": "B", "explanation": "线款部分清偿第二次借款本金，A、C、D选项错误，B选项正确。（新编）", "type": "single", "topic": "专题二 民法典合同编", "page": 67, "subject": "相关法", "id": "xg_247"},
  {"question": "张某购房时发现小区没有健身房，下列哪些表述是正确的？（多选）", "options": ["A. 甲公司不守诚信，构成根本违约，张某有权退房", "B. 甲公司构成欺诈，张某有权请求甲公司承担缔约过失责任", "C. 甲公司恶意误导，张某有权请求甲公司双倍返还购房款", "D. 张某不能滥用权利，在退房和要求甲公司承担违约责任之间只能选择一种"], "answer": "AB", "explanation": "A选项，根据《民法典》第563条的规定，张某有权解除合同，主张退房，并追究甲公司的违约责任，因此A选项正确。B选项，甲公司谎称小区内有健身馆，构成欺诈，张某有权诉请法院撤销合同，主张退房，并追究甲公司的缔约过失责任，因此B选项正确。C选项，买卖合同的解除或者撤销均无双倍返还的规定，因此C选项错误。D选项，根据《民法典》第563条、第566条的规定，张某可以解除合同，主张退房，并追究甲公司的违约责任，因此D选项错误。（法考2014）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 76, "subject": "相关法", "id": "xg_248"},
  {"question": "甲摩托车厂因厂房扩建，请乙单位施工。厂房建成投入使用后，甲厂发现二层漏雨，一层墙体有裂缝需要加固。甲厂要求乙单位维修并追究违约责任。在纠纷中，甲对一层进行了加固，维修花费10万元，但是二层漏雨一直未加维修。雨季来临，造成二层库存货物损失30万元。由于乙拒绝维修，甲遂另外租房，支付房租200万元。甲可以追究乙的哪些赔偿责任？（多选）", "options": ["A. 因施工质量问题，要求乙单位修理", "B. 为减少损失支出的维修费10万元", "C. 因漏雨造成的损失30万元", "D. 房租支出200万元"], "answer": "AB", "explanation": "A、B选项，根据《民法典》第582、583条的规定，履行不符合约定的，应当按照当事人的约定承担违约责任，受损害方根据标的的性质以及损失的大小，可以合理选择请求对方承担修理、重作、等违约责任，在履行义务或者采取补救措施后，对方还有其他损失的，应当赔偿损失，因此A、B选项正确。C、D选项，根据《民法典》第591条的规定，当事人一方违约后，对方应当采取适当措施防止损失的扩大，没有采取适当措施致使损失扩大的，不得就扩大的损失请求赔偿，当事人因防止损失扩大而支出的合理费用，由违约方负担，C、D选项没有采取适当措施致使损失扩大，因此不能请求违约方赔偿。（新编）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 76, "subject": "相关法", "id": "xg_249"},
  {"question": "根据民法典合同编及相关规定，下列关于专利实施许可合同的哪种说法是正确的？（单选）", "options": ["A. 专利实施许可合同可以采用口头形式", "B. 专利权有效期届满的，专利权人仍然可以就该专利与他人订立专利实施许可合同", "C. 专利权被宣布无效的，专利权人仍然可以就专利与他人订立专利实施许可合同", "D. 专利实施许可合同的许可人应当按照约定实施专利，交付实施专利有关的技术资料，提供必要的技术指导"], "answer": "A", "explanation": "专利实施许可合同可以采用口头形式。", "type": "single", "topic": "专题二 民法典合同编", "page": 80, "subject": "相关法", "id": "xg_250"},
  {"question": "根据民法典合同编的规定，下列关于技术转让合同的说法哪些是正确的？（多选）", "options": ["A. 技术转让合同既可以采用书面形式，也可采用口头形式", "B. 技术转让合同可以约定与受让人实施专利或者使用技术秘密的范围，但不得限制技术竞争和技术发展", "C. 专利实施许可合同的有效期可以由双方当事人任意约定", "D. 专利实施许可合同的受让人应当按照约定实施专利，交付实施专利有关的技术资料，提供必要的技术指导"], "answer": "BD", "explanation": "技术转让合同可以约定与受让人实施专利或者使用技术秘密的范围，但不得限制技术竞争和技术发展。专利实施许可合同的受让人应当按照约定实施专利，交付实施专利有关的技术资料，提供必要的技术指导。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 80, "subject": "相关法", "id": "xg_251"},
  {"question": "根据民法典合同编及相关规定，下列关于提存的说法哪些是正确的？（多选）", "options": ["A. 标的物提存费用过高的，债务人依法可以拍卖或者变卖标的物，提存所得的价款", "B. 标的物不适于提存的，债务人依法可以拍卖或者变卖标的物，提存所得的价款", "C. 标的物提存后，毁损、灭失的风险由债权人承担", "D. 提存期间，标的物的孳息归债务人所有，提存费用由债务人负担"], "answer": "ABC", "explanation": "A、B选项，《民法典》第570条第2款规定：‘标的物不适于提存或者提存费用过高的，债务人依法可以拍卖或者变卖标的物，提存所得的价款’，因此A、B选项正确。C、D选项，《民法典》第573条规定：‘标的物提存后，毁损、灭失的风险由债权人承担。提存期间，标的物的孳息归债权人所有。提存费用由债权人负担’，因此C选项正确，D选项错误。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 69, "subject": "相关法", "id": "xg_252"},
  {"question": "张某不能向赵某交付瓷器，构成违约，违约责任应由张某承担", "options": ["A. 张某不能向赵某交付瓷器，构成违约，违约责任应由张某承担", "B. 张某不能向赵某交付瓷器，构成违约，违约责任应由李某承担", "C. 赵某追究违约责任时，可以要求同时适用违约金和定金条款", "D. 赵某追究违约责任时，可以选择适用违约金或者定金条款"], "answer": "A", "explanation": "根据民法典合同编的相关规定，违约责任应由违约方承担，本题中张某不能交付瓷器，构成违约，因此违约责任应由张某承担。", "type": "single", "topic": "专题二 民法典合同编", "page": 74, "subject": "相关法", "id": "xg_253"},
  {"question": "根据民法典合同编及相关规定，下列说法哪些是正确的？（多选）", "options": ["A. 因不可抗力不能履行合同的，应当全部免除责任", "B. 当事人迟延履行后发生不可抗力的，不能免除责任", "C. 当事人就迟延履行约定违约金的，违约方支付违约金后，还应当履行债务", "D. 约定的违约金低于造成的损失的，当事人可以请求人民法院或者仲裁机构予以增加"], "answer": "D", "explanation": "D选项，《民法典》第585条第2款规定：‘约定的违约金低于造成的损失的，人民法院或者仲裁机构可以根据当事人的请求予以增加……’，因此D选项正确。（2011改编）", "type": "single", "topic": "专题二 民法典合同编", "page": 73, "subject": "相关法", "id": "xg_254"},
  {"question": "张某将珍藏多年的古董瓷器转让给赵某。两人在合同中约定，如果一方违约，需要支付给对方违约金，同时约定赵某支付一定数额的定金给张某作为债权的担保。交付前，张某的朋友李某不慎将该瓷器摔碎。根据民法典合同编及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 张某因李某将瓷器摔碎造成违约，应由张某承担违约责任", "B. 张某因李某将瓷器摔碎造成违约，应由李某承担违约责任", "C. 张某因李某将瓷器摔碎造成违约，应由张某承担违约责任", "D. 张某因李某将瓷器摔碎造成违约，应由李某承担违约责任"], "answer": "AD", "explanation": "A、B选项，《民法典》第593条规定：‘当事人一方因第三人的原因造成违约的，应当依法向对方承担违约责任……’，张某因李某将瓷器摔碎造成违约，应由张某承担违约责任，因此A选项正确，B选项错误。C、D选项，《民法典》第588条第1款规定：‘当事人既约定违约金，又约定定金的，一方违约时，对方可以选择适用违约金或者定金条款’，违约金或定金可以择其一适用，不能同时适用，因此C选项错误，D选项正确。（2014）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 73, "subject": "相关法", "id": "xg_255"},
  {"question": "根据民法典合同编及相关规定，合同当事人一方不履行非金钱债务的，下列哪些情形下，另一方当事人不能要求其继续履行？（多选）", "options": ["A. 该债务的标的不适于强制履行", "B. 债权人在合理期限内未要求履行", "C. 该债务在法律上不能履行", "D. 该债务在事实上不能履行"], "answer": "ABCD", "explanation": "A选项，《民法典》第577条规定：‘当事人一方不履行合同义务或者履行合同义务不符合约定的，应当承担继续履行、采取补救措施或者赔偿损失等违约责任’，乙公司履行义务不符合约定，甲公司有权要求继续履行并支付违约金，因此A选项正确。B、D选项，《民法典》第563条第1款规定：‘有下列情形之一的，当事人可以解除合同：……（四）当事人一方迟延履行债务或者有其他违约行为致使不能实现合同目的……’，因此B选项正确，D选项错误。C选项，《民法典》第566条第1、2款规定：‘合同解除后，尚未履行的，终止履行；已经履行的，根据履行情况和合同性质，当事人可以请求恢复原状或者采取其他补救措施，并有权请求赔偿损失。合同因违约解除的，解除权人可以请求违约方承担违约责任，但是当事人另有约定的除外’，因此C选项正确。（2008）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 72, "subject": "相关法", "id": "xg_256"},
  {"question": "甲公司和乙公司签订合同，约定：由乙公司按照要求为甲公司制造专用机床一台，甲公司预付款300万元，一方违约的应当向另一方支付违约金。机床交付后，经多次调试，仍不能实现合同目的。据此，下列哪些说法是正确的？（多选）", "options": ["A. 甲公司有权要求乙公司继续履行合同并支付违约金", "B. 因无法实现合同目的，甲公司有权要求解除合同", "C. 甲公司要求解除合同的，有权要求乙公司返还预付款并赔偿损失", "D. 合同已经履行完毕，甲公司无权要求解除合同"], "answer": "ABC", "explanation": "A选项，《民法典》第577条规定：‘当事人一方不履行合同义务或者履行合同义务不符合约定的，应当承担继续履行、采取补救措施或者赔偿损失等违约责任’，乙公司履行义务不符合约定，甲公司有权要求继续履行并支付违约金，因此A选项正确。B、D选项，《民法典》第563条第1款规定：‘有下列情形之一的，当事人可以解除合同：……（四）当事人一方迟延履行债务或者有其他违约行为致使不能实现合同目的……’，因此B选项正确，D选项错误。C选项，《民法典》第566条第1、2款规定：‘合同解除后，尚未履行的，终止履行；已经履行的，根据履行情况和合同性质，当事人可以请求恢复原状或者采取其他补救措施，并有权请求赔偿损失。合同因违约解除的，解除权人可以请求违约方承担违约责任，但是当事人另有约定的除外’，因此C选项正确。（2008）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 72, "subject": "相关法", "id": "xg_257"},
  {"question": "甲乙签订一份买卖合同，约定违约方应向对方支付18万元违约金。后甲违约，给乙造成损失15万元。下列哪一表述是正确的？（单选）", "options": ["A. 甲应向乙支付违约金18万元，不再支付其他费用或者赔偿损失", "B. 甲应向乙赔偿损失15万元，不再支付其他费用或者赔偿损失", "C. 甲应向乙赔偿损失15万元并支付违约金18万元，共计33万元", "D. 甲应向乙赔偿损失15万元及其利息"], "answer": "A", "explanation": "A选项，根据《民法典》第585条规定：‘约定的违约金超过造成损失的30%的，人民法院一般可以认定为过分高于造成的损失。’本题中约定的违约金为18万元，未超过实际损失15万元的30%，不构成约定的违约金过分高于造成的损失的情形，因此甲应向乙支付18万元违约金。违约金本身就有赔偿损失、支付其他费用的作用，且已涵盖15万元的损失，支付18万元违约金后，无需再赔偿其他损失，因此A选项正确，B、C、D选项错误。（法考2013）", "type": "single", "topic": "专题二 民法典合同编", "page": 72, "subject": "相关法", "id": "xg_258"},
  {"question": "甲公司利用从乙公司受让的一项专利技术所生产专利产品被丙公司指控为侵权，人民法院判决侵权成立，并要求甲公司赔偿损失2000万元。根据民法典合同编及相关规定，下列说法正确的是？（多选）", "options": ["A. 如果甲乙公司之间对损害赔偿没有约定，应由乙公司向丙公司承担赔偿责任", "B. 如果甲乙公司之间对损害赔偿没有约定，应由甲公司向丙公司承担赔偿责任", "C. 如果甲乙公司之间对损害赔偿没有约定，由甲公司、乙公司承担连带责任", "D. 如果甲乙公司之间对损害赔偿有约定，则按照约定进行赔偿"], "answer": "AD", "explanation": "《民法典》第874条规定：‘受让人或者被许可人按照约定实施专利、使用技术秘密侵害他人合法权益的，由让与人或者许可人承担责任，但是当事人另有约定的除外’，如果甲乙公司之间对损害赔偿有约定，则按照约定进行赔偿，如果甲乙公司之间对损害赔偿没有约定，应由让与人乙公司向丙公司承担赔偿责任。因此A、D选项正确，B、C选项错误。（2019）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 81, "subject": "相关法", "id": "xg_259"},
  {"question": "甲公司委托乙研究所研发一项新技术，双方签订了技术开发合同，但没有约定研发成果申请专利的权利的归属。根据民法典合同编及相关规定，下列哪种说法是正确的？（单选）", "options": ["A. 该研发成果申请专利的权利属于甲公司和乙研究所共有，当事人一方转让其共有的专利申请权的，另一方享有以同等条件优先受让的权利", "B. 该研发成果申请专利的权利属于甲公司和乙研究所共有，当事人一方声明放弃其共有的专利申请权的，可以由另一方单独申请", "C. 该研发成果申请专利的权利属于乙研究所，乙研究所取得专利权的，甲公司可以依法实施该专利", "D. 该研发成果申请专利的权利属于甲公司，甲公司取得专利权的，乙研究所可以依法实施该专利"], "answer": "C", "explanation": "《民法典》第859条第1款规定：‘委托开发完成的发明创造，除法律另有规定或者当事人另有约定外，申请专利的权利属于研究开发人。研究开发人取得专利权的，委托人可以依法实施该专利’，该研发成果申请专利的权利属于乙研究所，乙研究所取得专利权的，甲公司可以依法实施该专利，因此A、B、D选项错误，C选项正确。（2014年改编）", "type": "single", "topic": "专题二 民法典合同编", "page": 78, "subject": "相关法", "id": "xg_260"},
  {"question": "有履行该合同。乙应返还给甲人民币？(单选)", "options": ["A. 10万元", "B. 20万元", "C. 25万元", "D. 30万元"], "answer": "A", "explanation": "根据债务的性质不得强制履行的，对方可以请求其负担由第三人替代履行的费用。据此，小翠无正当理由未对詹某履行提供钢琴授课的合同义务，詹某可请求第三人履行该义务，并请求小翠承担相应的费用。因此A项正确，D项错误。B、C选项，根据《民法典》第584条规定：‘当事人一方不履行合同义务或者履行合同义务不符合约定，造成对方损失的，损失赔偿额应当相当于因违约所造成的损失，包括合同履行后可以获得的利益；但是，不得超过违约一方订立合同时预见到或者应当预见到的因违约可能造成的损失。’本题中，小翠违约给詹某造成的只有直接损失（詹某支出的课酬2000元），无可得利益损失。同时，洪老师向小詹提供钢琴授课与小翠向小詹提供钢琴授课，均符合债务本旨，均能达到相同的清偿效果，詹某未因此遭受损失。因此，小翠应对詹某承担违约损害赔偿范围仅为2000元。", "type": "single", "topic": "专题二 民法典合同编", "page": 75, "subject": "相关法", "id": "xg_261"},
  {"question": "15. 甲房产开发公司在交给购房人张某的某小区平面图和项目说明书中都标明有一个健身馆。张某看中小区平面图和项目说明书中的健身馆，遂购买了该小区的房屋。入住后发现并无健身馆。关于本案，下列哪一说法是正确的？(多选)", "options": ["A. 甲公司构成欺诈", "B. 张某有权请求甲公司承担违约责任", "C. 张某有权请求甲公司承担缔约过失责任", "D. 张某有权请求甲公司承担侵权责任"], "answer": "AB", "explanation": "A选项，小区平面图和项目说明书属于要约邀请，但若其内容具体明确且足以影响买方决策，可视为要约。甲公司未按承诺建设健身馆，构成违约。B选项，张某基于对开发商承诺的信任购买房屋，开发商未履行承诺，构成违约，张某有权请求其承担违约责任。C选项，缔约过失责任适用于合同订立过程中一方违反诚实信用原则导致对方损失的情形，本案中合同已成立，故不适用。D选项，侵权责任需存在过错行为并造成人身或财产损害，本案中无证据表明存在侵权行为。因此，A、B选项正确。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 75, "subject": "相关法", "id": "xg_262"},
  {"question": "甲、乙两公司约定：甲公司向乙公司付5万元研发费用，乙公司完成某专用设备的研发生产后双方订立买卖合同，将该设备出售给甲公司，价格暂定为100万元，具体条款另行商定。乙公司完成研发生产后，却将该设备以120万元卖给丙公司，甲公司得知后提出异议。下列哪些选项是正确的？（多选）", "options": ["A. 甲、乙两公司之间的协议为技术开发合同", "B. 甲、乙两公司之间的协议系附条件的买卖合同", "C. 乙公司将设备出卖给丙公司，不违反法律规定，合同有效", "D. 乙公司将设备出卖给丙公司，导致无法与甲公司订立买卖合同，构成违约"], "answer": "AC", "explanation": "A选项，《民法典》第851条规定：‘技术开发合同是当事人之间就新技术、新产品、新工艺、新品种或者新材料及其系统的研究开发所订立的合同。技术开发合同包括委托开发合同和合作开发合同’，甲公司委托乙公司完成技术开发，为委托技术开发合同，因此A选项正确。B选项，甲、乙公司约定于未来订立设备买卖合同，为买卖合同的预约，买卖合同尚未成立，不属于附条件的合同，因此B选项错误。C选项，乙公司将设备出卖给丙公司，不违反法律规定的合同有效要件，其合同有效，因此C选项正确。D选项，乙公司将设备出卖给丙公司，导致无法与甲公司订立买卖合同，但因原协议仅为技术开发合同，并非买卖合同，因此不构成违约，D选项错误。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 79, "subject": "相关法", "id": "xg_263"},
  {"question": "某律师事务所指派吴律师担任某案件的一、二审委托代理人。第一次开庭后，吴律师感觉案件复杂，本人和该事务所均难以胜任，建议不再继续代理。但该事务所坚持代理。一审判决委托人败诉。下列哪些表述是正确的？（多选）", "options": ["A. 律师事务所所有权单方解除委托合同，但须承担赔偿责任", "B. 律师事务所所在委托人一审败诉后不能单方解除合同", "C. 即使一审胜诉，委托人也可解除委托合同，但须承担赔偿责任", "D. 只有存在故意或者重大过失时，该律师事务所才对败诉承担赔偿责任"], "answer": "AC", "explanation": "《民法典》第933条规定：‘委托人或者受托人可以随时解除委托合同。因解除合同造成对方损失的，除不可归责于该当事人的事由外，无偿委托合同的解除方应当赔偿因解除时间不当造成的直接损失，有偿委托合同的解除方应当赔偿对方的直接损失和合同履行后可以获得的利益’，律师事务所（受托人）和委托人均有权单方解除委托合同，但须承担赔偿责任，因此A、C选项正确，B选项错误。D选项，《民法典》第929条规定：‘有偿的委托合同，因受托人的过错造成委托人损失的，委托人可以请求赔偿损失。无偿的委托合同，因受托人的故意或者重大过失造成委托人损失的，委托人可以请求赔偿损失。受托人超越权限造成委托人损失的，应当赔偿损失’，委托人与律师事务所之间的委托合同一般属于有偿委托合同，只要律师事务所存在过错，委托人即可请求赔偿损失，因此D选项错误。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 84, "subject": "相关法", "id": "xg_264"},
  {"question": "某电商平台需要大量采购各出版社图书以备在双11活动中打折促销，于是电商平台委托甲公司代为采购。甲公司以自己的名义与乙图书批发公司签订购销合同，乙公司并不知道该合同直接约束甲公司和乙公司，但有确切证据证明该合同只约束姚某和乙公司的除外", "options": ["A. 该合同直接约束甲公司和乙公司", "B. 该合同直接约束甲公司、乙公司和姚某", "C. 该合同直接约束甲公司和乙公司，但有确切证据证明该合同只约束姚某和乙公司的除外", "D. 该合同无效，对甲公司、乙公司和姚某均没有约束力"], "answer": "B", "explanation": "根据《民法典》第925条的规定，受托人以自己的名义与第三人订立合同时，如果第三人不知道受托人与委托人之间的代理关系，则该合同直接约束受托人与第三人。但如果受托人能够证明第三人明知其与委托人之间的代理关系，则该合同可直接约束委托人与第三人。本题中，甲公司以自己的名义与乙公司签订合同，乙公司并不知道甲公司与委托人之间的代理关系，因此该合同直接约束甲公司和乙公司。但若存在确切证据证明该合同只约束姚某和乙公司，则应视为姚某与乙公司之间存在直接法律关系。因此，A、C、D选项错误，B选项正确。（2010改编）", "type": "single", "topic": "专题二 民法典合同编", "page": 84, "subject": "相关法", "id": "xg_265"},
  {"question": "根据民法典合同编及相关规定，下列关于委托合同的哪些说法是正确的？（多选）", "options": ["A. 委托合同是委托人和受托人约定，由受托人处理委托人事务的合同", "B. 受托人应当亲自处理委托事务，经委托人同意，受托人可以转委托", "C. 受托人应当按照委托人的要求，报告委托事务的处理情况", "D. 有偿的委托合同，因受托人的过错给委托人造成损失的，委托人可以要求赔偿损失"], "answer": "ABCD", "explanation": "A选项，《民法典》第919条规定：‘委托合同是委托人和受托人约定，由受托人处理委托人事务的合同’，因此A选项正确。B选项，《民法典》第923条规定：‘受托人应当亲自处理委托事务。经委托人同意，受托人可以转委托……’，因此B选项正确。C选项，《民法典》第924条规定：‘受托人应当按照委托人的要求，报告委托事务的处理情况……’，因此C选项正确。D选项，《民法典》第929条第1款规定：‘有偿的委托合同，因受托人的过错造成委托人损失的，委托人可以请求赔偿损失……’，因此D选项正确。（2012改编）", "type": "multiple", "topic": "专题二 民法典合同编", "page": 82, "subject": "相关法", "id": "xg_266"},
  {"question": "个体经营户王小小从事理发服务业，使用“一剪剪”作为未注册商标长期使用，享有较高声誉。王小小通过签订书面合同许可其同一区域的表妹张薇薇使用“一剪剪”作为理发业务。后张薇薇以自己的名义申请“一剪剪”商标从事理发业务并获得注册。下列说法正确的是？(单选)", "options": ["A. 该商标使用许可合同自双方签字之日起生效", "B. 该商标使用许可合同备案后生效", "C. 王小小有权“一剪剪”注册之日起5年内申请宣告该注册商标无效", "D. 王小小无权请求宣告该注册商标无效"], "answer": "C", "explanation": "王小小作为未注册商标的长期使用者，享有较高声誉，因此在商标被注册后，她有权在一定期限内申请宣告该注册商标无效。", "type": "single", "topic": "专题二 民法典合同编", "page": 207, "subject": "相关法", "id": "xg_267"},
  {"question": "著作权转让合同应当采取书面形式", "options": ["A. 著作权转让合同应当采取书面形式", "B. 著作权人许可录音录像制作者专有使用其作品的，应当订立书面许可使用合同", "C. 著作权转让合同中著作权人未明确转让的权利，视为一转授", "D. 与著作权人订立专有许可使用合同的，可以向著作权行政管理部门备案"], "answer": "A", "explanation": "根据著作权法的相关规定，著作权转让合同应当采取书面形式。", "type": "single", "topic": "专题二 民法典合同编", "page": 233, "subject": "相关法", "id": "xg_268"},
  {"question": "根据著作权法及相关规定，下列关于著作权转让合同的说法哪项是错误的？", "options": ["A. 著作权转让合同应当采用书面形式", "B. 著作权中的署名权不得转让", "C. 著作权中的改编权可以转让", "D. 著作权转让合同向著作权行政管理部门备案之日起生效"], "answer": "D", "explanation": "著作权转让合同的生效并不以向著作权行政管理部门备案为条件，备案是可选的，不是合同生效的必要条件。", "type": "single", "topic": "专题二 民法典合同编", "page": 233, "subject": "相关法", "id": "xg_269"},
  {"question": "根据著作权法及相关规定，著作权许可使用合同包括下列哪些内容？", "options": ["A. 许可使用的权利种类", "B. 许可使用的权利是专有使用权或者非专有使用权", "C. 许可使用的地域范围、期间", "D. 付酬标准和办法"], "answer": "ABCD", "explanation": "著作权许可使用合同应当包括许可使用的权利种类、权利性质（专有或非专有）、地域范围、期间以及付酬标准和办法。", "type": "multiple", "topic": "专题二 民法典合同编", "page": 233, "subject": "相关法", "id": "xg_270"},
  {"question": "1. 根据民事诉讼法及相关规定,下列哪些说法是正确的?(多选)", "options": ["A. 民事诉讼当事人有平等的诉讼权利", "B. 当事人有权在法律规定的范围内处分自己的民事权利和诉讼权利", "C. 在少数民族聚居的地区,人民法院应当一律使用汉语言文字审理和发布法律文书", "D. 人民法院审理民事案件,应当根据自愿和合法的原则进行调解;调解不成的,应当及时判决"], "answer": "ABD", "explanation": "A选项,《民诉法》第8条规定:“民事诉讼当事人有平等的诉讼权利……”,因此A选项正确。B选项,《民诉法》第13条第2款规定:“当事人有权在法律规定的范围内处分自己的民事权利和诉讼权利”,因此B选项正确。C选项,《民诉法》第11条第2款规定:“在少数民族聚居或者多民族共同居住的地区,人民法院应当用当地民族通用的语言、文字进行审理和发布法律文书”,因此C选项错误。D选项,《民诉法》第9条规定:“人民法院审理民事案件,应当根据自愿和合法的原则进行调解;调解不成的,应当及时判决”,因此D选项正确。(2015)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 71, "subject": "相关法", "id": "xg_271"},
  {"question": "2. 某县人民法院对王某诉张某侵权纠纷一案未经开庭审理即作出了判决,该审判行为直接违反了民事诉讼法哪一项原则或者制度?(单选)", "options": ["A. 违反了辩论原则", "B. 违反了处分原则", "C. 违反了合议制度", "D. 违反了回避制度"], "answer": "A", "explanation": "《民诉法》第12条规定:“人民法院审理民事案件时,当事人有权进行辩论”。本题中,未经开庭即作出判决违反了辩论原则,因此A选项正确,B、C、D选项错误。(2019)", "type": "single", "topic": "专题三 民事诉讼法", "page": 71, "subject": "相关法", "id": "xg_272"},
  {"question": "3. 关于民事诉讼法基本原则在民事诉讼中的具体体现,下列哪一说法是正确的?(单选)", "options": ["A. 当事人有权决定是否委托代理人代为进行诉讼,是诉讼权利平等原则的体现", "B. 当事人均有权委托代理人代为进行诉讼,是处分"], "answer": "D", "explanation": "A选项,委托代理人是当事人的诉讼权利,当事人有权决定是否委托,是处分原则的体现,因此A选项错误。B选项,当事人均有权委托,说明当事人权利相同,是平等原则的体现,因此B选项错误。C选项,原告与被告权利虽然不同,但是相对应,是平等原则的体现,而不是同等原则,因此C选项错误。D选项,调解原则包括自愿和合法,因此D选项正确。(法考2011)", "type": "single", "topic": "专题三 民事诉讼法", "page": 71, "subject": "相关法", "id": "xg_273"},
  {"question": "4. 根据民事诉讼法及相关规定,下列关于辩论原则的说法哪些是正确的?(多选)", "options": ["A. 督促程序不适用辩论原则", "B. 当事人辩论权的行使局限于一、二审程序中开庭审理的法庭辩论阶段", "C. 当事人向法院提出起诉状和答辩状是其行使辩论权的一种表现", "D. 证人出庭陈述证言是证人行使辩论权的一种表现"], "answer": "CD", "explanation": "A选项，《民诉法》第96条规定：“人民法院审理民事案件，根据当事人自愿的原则，在事实清楚的基础上，分清是非，进行调解”，因此调解以当事人同意为前提，并不是一律先行调解，A选项错误。B选项，《民诉法》第145条规定：“法庭辩论终结，应当依法作出判决。判决前能够调解的，还可以进行调解，调解不成的，应当及时判决”，因此B选项错误。C选项，《民诉法》第179条规定：“第二审人民法院审理上诉案件，可以进行调解……”，因此C选项正确。D选", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 72, "subject": "相关法", "id": "xg_274"},
  {"question": "5. 吴某通过网络购物平台购买了甲公司销售的电热毯,后来因为电热毯质量问题,吴某起诉甲公司。法院受理案件后就开庭方式征求当事人意见,甲公司明确表示同意通过线上方式开庭,而吴某拒绝通过线上方式开庭。关于本案表述正确的是?(单选)", "options": ["A. 由于本案是发生在互联网上的纠纷,故应当由互联网法院专属管辖", "B. 法院可以依职权决定通过在线方式开庭审理", "C. 法院可以组织甲公司在线上开庭,吴某线下开庭的方式进行审理", "D. 既然吴某不同意线上开庭,故本案不能通过在线开庭方式审理"], "answer": "C", "explanation": "根据《民事诉讼法》第16条规定,经当事人同意,民事诉讼活动可以通过信息网络平台在线进行。如果一方当事人同意在线诉讼,另外一方当事人不同意在线诉讼,则对同意的一方采取在线方式,对不同意的一方采取线下方式。甲公司同意线上开庭,吴某不同意线上开庭,则法院对甲公司组织线上开庭,对吴某组织线下开庭方式审理即可,因此C选项正确,B、D选项错误。互联网法院不存在专属管辖的问题。互联网法院的管辖称为集中管辖。具体的,互联网法院集中管辖所在市(北京、广州、杭州)的辖区内应当由基层法院管辖的发生在互联网上的合同纠纷、侵权纠纷等。因此,A选项错误。(法考2022)", "type": "single", "topic": "专题三 民事诉讼法", "page": 72, "subject": "相关法", "id": "xg_275"},
  {"question": "6. 根据民事诉讼法的规定,下列说法中哪些说法是正确的?(多选)", "options": ["A. 人民法院审理第二审民事案件,不能由一名审判人员独任审理", "B. 人民法院审理第一审民事案件,只有简易程序才"], "answer": "CD", "explanation": "A选项,《民诉法》第41条第2款规定:“中级人民法院对第一审适用简易程序审结或者不服裁定提起上诉的第二审民事案件,事实清楚、权利义务关系明确的,经双方当事人同意,可以由审判员一人独任审理”,因此二审也可以适用独任制。B选项,《民诉法》第40条第2款规定:“适用简易程序审理的民事案件,由审判员一人独任审理。基层人民法院审理的基本事实清楚、权利义务关系明确的第一审民事案件,可以由审判员一人适用普通程序独任审理”,因此不只有简易程序才适用独任制。C选项,《民诉法》第40条第3款规定:", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 72, "subject": "相关法", "id": "xg_276"},
  {"question": "10. 甲公司因为合同纠纷起诉乙公司，某县人民法院适用简易程序审理后判决甲公司败诉。甲公司不服一审判决，提起上诉，二审法院指定吴法官对本案独任审理，乙公司当庭表示异议，关于本案，下列说法正确的是？(单选)", "options": ["A. 二审只能组成合议庭审理，不能适用独任制", "B. 简易程序一审终审，不得上诉", "C. 二审法院有权直接指定法官适用独任制审理", "D. 二审法院应裁定转为合议庭审理"], "answer": "D", "explanation": "《民诉法》第41条规定，人民法院审理第二审民事案件，由审判员组成合议庭。合议庭的成员人数，必须是单数。中级人民法院对第一审适用简易程序审结或者不服裁定提起上诉的第二审民事案件，事实清楚、权利义务关系明确的，经双方当事人同意，可以由审判员一人独任审理。因此，二审程序如果符合条件的可以适用独任制，A选项错误。本题乙公司当庭对二审法院适用独任制提出异议，即表明未取得双方当事人同意，故本案二审不得适用独任制，C选项错误。法院在审理过程中，发现案件不宜由审判员一人独任审理的，应当裁定转由合议庭审理。本题中，二审不能适用独任制审理，乙公司的异议成立，法院应当裁定将案件转为合议庭审理，D选项正确。简易程序不存在一审终审的相关规定，B选项错误。(法考2022)", "type": "single", "topic": "专题三 民事诉讼法", "page": 74, "subject": "相关法", "id": "xg_277"},
  {"question": "11. 根据民事诉讼法及相关规定，下列哪些情况下，当事人可以申请回避？(多选)", "options": ["A. 鉴定人陈某，其与本案有利害关系", "B. 审判人员李某，担任过本案的鉴定人的", "C. 律师韩某是本案当事人近亲属的", "D. 人民陪审员赵某接受过本案当事人宴请的"], "answer": "ABD", "explanation": "A选项，根据《民诉法》及《民诉法解释》的规定，担任过本案的证人、鉴定人、辩护人、诉讼代理人、翻译人员的审判人员，当事人有权申请其回避；与本案有利害关系的鉴定人，当事人有权申请其回避；接受本案当事人及其受托人宴请，或者参加由其支付费用的活动的审判人员，当事人有权申请其回避，因此A、B、D选项正确。C选项，律师属于诉讼代理人，不适用回避的规定。(新编)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 74, "subject": "相关法", "id": "xg_278"},
  {"question": "12. 某民事案件审理过程中，当事人对合议庭组成人员提出回避请求，根据民事诉讼法及相关规定，下列说法正确的是？(多选)", "options": ["A. 当事人申请审判人员回避的，应由审判委员会决定", "B. 当事人申请陪审员回避的，应由审判长决定", "C. 当事人对人民法院驳回回避申请的决定不服，可以向原人民法院申请复议一次", "D. 人民法院驳回当事人的回避申请，当事人不服申请复议的，复议期间被申请人不停止参与本案的审理 - 73 -"], "answer": "CD", "explanation": "A、B选项，根据《民诉法》第49条的规定，审判人员的回避，由院长决定，因此审判员、陪审员的回避均由院长决定，A、B选项错误。C、D", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 74, "subject": "相关法", "id": "xg_279"},
  {"question": "13. 某区法院审理原告诉许某与被告某饭店食物中毒纠纷一案。审前，法院书面告知许某合议庭由审判员甲、乙和人民陪审员丙组成时，许某未提出回避申请。开庭后，许某始知人民陪审员丙与被告法定代表人是亲兄弟，遂提出回避申请。关于本案的回避，下列哪一说法是正确的?(单选)", "options": ["A. 许某可在知道丙与被告法定代表人是亲兄弟时提出回避申请", "B. 法院对回避申请作出决定前，丙不停止参与本案审理", "C. 应由审判长决定丙是否应回避", "D. 法院作出回避决定后，许某可对此提出上诉"], "answer": "A", "explanation": "A选项，根据《民诉法》第47条的规定，审判人员是本案当事人近亲属的，当事人有权申请他们回避；根据《民事诉讼法》第48条第1款的规定，回避事由在案件开始审理后知道的，可以在法庭辩论终结前提出；A选项中，人民陪审员丙属于审判人员，丙与被告法定代表人是亲兄弟属于近亲属，许某在开庭后得知时可以提出回避申请，因此A选项正确。B选项，《民诉法》第48条第2款规定：“被申请回避的人员在人民法院作出是否回避的决定前，应当暂停参与本案的工作，但案件需要采取紧急措施的除外”，因此丙应当暂停参与本案的工作，B选项错误。C选项，根据《民诉法》第49条的规定，丙作为审判人员的回避，应由院长决定，因此C选项错误。D选项，根据《民诉法》第50条的规定，申请人对决定不服的，可以在接到决定时申请复议一次，因此对于回避决定不服，救济途径是申请复议，而不是上诉，因此D选项错误。(法考2015)", "type": "single", "topic": "专题三 民事诉讼法", "page": 75, "subject": "相关法", "id": "xg_280"},
  {"question": "14. 王某诉马某侵权损害赔偿纠纷一案，经审理后，合议庭经评议，拟支持王某的诉讼请求。法院通知双方当事人8月1日进行宣判，马某发现本案书记员张某是原告的表妹夫，遂于7月31日向法院提出书记员张某回避的申请。关于本案，表述正确的是?(单选)", "options": ["A. 以书记员不属于应当回避人员为由，驳回马某的回避申请", "B. 以马某的申请不符合法定回避的情形为由，驳回马某的回避申请", "C. 因为马某超过了法定申请回避的期限，法院对马某的申请不予审查", "D. 法院应当决定延期宣判，对马某提出的回避申请予以审查"], "answer": "C", "explanation": "《民事诉讼法》第47条规定：“审判人员有下列情形之一的，应当自行回避，当事人有权用口头或者书面方式申请他们回避：（一）是本案当事人或者当事人、诉讼代理人近亲属的……前三款规定，适用于法官助理、书记员……”，A、B选项错误。根据《民事诉讼法》第48条的规定，回避申请最迟在法庭辩论终结前提出，本案法庭辩论已经终结，故马某不能申请回避，法院对马某的回避申请应当不予审查，因此C选项正确、D选项错误。(法考2023)", "type": "single", "topic": "专题三 民事诉讼法", "page": 75, "subject": "相关法", "id": "xg_281"},
  {"question": "15. 根据民事诉讼法及相关规定，下列说法哪项是正确的?(单选)", "options": ["A. 涉及商业秘密案件不得公开审理", "B. 涉及离婚案件是否公开审理由当事人协商决定"], "answer": "D", "explanation": "《民诉法》第137条规定：“人民法院审理民事案件，除涉及国家秘密、个人隐私或者法律", "type": "single", "topic": "专题三 民事诉讼法", "page": 75, "subject": "相关法", "id": "xg_282"},
  {"question": "1. 根据民事诉讼法及相关规定，关于第一审民事案件的级别管辖，下列哪个表述是正确的？(单选)", "options": ["A. 基层人民法院管辖所有第一审民事案件", "B. 中级人民法院管辖所有涉外的第一审民事案件", "C. 高级人民法院管辖在本辖区有重大影响的第一审民事案件", "D. 最高人民法院仅管辖在全国有重大影响的第一审民事案件"], "answer": "C", "explanation": "A、B选项，根据《民诉法》第18、19条的规定，基层人民法院可以管辖一审案件，但是专利纠纷一审和重大涉外等民事案件基层法院没有管辖权，也不是所有的涉外案件一审都在中级法院，只有重大涉外案件才需要中级法院管辖，因此A、B选项说法过于绝对。C选项，《民诉法》第20条规定：“高级人民法院管辖在本辖区有重大影响的第一审民事案件”，因此C选项正确。D选项，根据《民诉法》第21条的规定，最高人民法院不仅管辖在全国有重大影响的案件，还认为应当由本院审理的案件，因此D选项说法错误。(新编)", "type": "single", "topic": "专题三 民事诉讼法", "page": 76, "subject": "相关法", "id": "xg_283"},
  {"question": "2. 根据民事诉讼法及相关司法解释，下列关于中级人民法院的哪项说法是正确的？(单选)", "options": ["A. 对案件所作出的判决均为终审判决", "B. 审理案件均须以开庭审理的方式进行", "C. 既可受理一审涉外案件，也可受理一审非涉外案件", "D. 审理案件组成合议庭时，均不可邀请人民陪审员参加"], "answer": "C", "explanation": "A选项，当中院作为一审法院时，当事人有权对其作出的判决提起上诉，因此A选项错误。B选项，根据《民诉法》第176条第1款的规定，第二审人民法院认为不需要开庭审理的，可以不开庭审理。因此中院作为二审法院时，可以不开庭审理案件，B选项错误。C选项，《民诉法》第19条规定：“中级人民法院管辖下列第一审民事案件：（一）重大涉外案件；（二）在本辖区有重大影响的案件；（三）最高人民法院确定由中级人民法院管辖的案件”，因此C选项正确。D选项，根据《民诉法》第40条的规定，人民法院审理第一审民事案件，由审判员、人民陪审员共同组成合议庭或者由审判员组成合议庭，中院作为一审法院时，可以由审判员、人民陪审员共同组成合议庭，因此", "type": "single", "topic": "专题三 民事诉讼法", "page": 76, "subject": "相关法", "id": "xg_284"},
  {"question": "3. 根据最高人民法院关于第一审知识产权民事、行政案件管辖的若干规定，下列说法哪个是正确的？(单选)", "options": ["A. 外观设计专利第一审行政案件，经最高人民法院批准，可以由基层人民法院管辖", "B. 外观设计专利的侵权纠纷第一审民事案件，经最高人民法院批准，可以由基层人民法院管辖", "C. 实用新型专利的权属纠纷第一审民事案件可以由最高人民法院确定的基层人民法院管辖", "D. 技术秘密的侵权纠纷第一审民事案件可以由最高人民"], "answer": "C", "explanation": "根据《民诉法》第19条规定：‘中级人民法院管辖下列第一审民事案件：（一）重大涉外案件；（二）在本辖区有重大影响的案件；（三）最高人民法院确定由中级人民法院管辖的案件’，结合相关司法解释，实用新型专利的权属纠纷第一审民事案件可以由最高人民法院确定的基层人民法院管辖，因此C选项正确。A、B选项不符合现行法律规定。", "type": "single", "topic": "专题三 民事诉讼法", "page": 76, "subject": "相关法", "id": "xg_285"},
  {"question": "4. 王某欲以刘某和赵某为共同被告提起民事诉讼。经查，王某的住所地和经常居住地均为甲地；刘某的住所地为乙地，经常居住地为丙地；赵某的住所地和经常居住地均为丁地。根据民事诉讼法及相关规定，下列哪些人民法院对该案有管辖权？ （多选）", "options": ["A. 甲地人民法院", "B. 乙地人民法院", "C. 丙地人民法院", "D. 丁地人民法院"], "answer": "CD", "explanation": "《民诉法》第22条规定：“对公民提起的民事诉讼，由被告住所地人民法院管辖；被告住所地与经常居住地不一致的，由经常居住地人民法院管辖……同一诉讼的几个被告住所地、经常居住地在两个以上人民法院辖区的，各该人民法院都有管辖权”，因此被告刘某和赵某的经常居住地丙地和丁地均有管辖权，A、B选项错误，C、D选项正确。(2014)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 77, "subject": "相关法", "id": "xg_286"},
  {"question": "5. 根据民事诉讼法及相关规定，下列哪些案件由原告住所地或者经常居住地人民法院管辖？（多选）", "options": ["A. 对宣告失踪的人提起的有关财产关系的诉讼", "B. 对下落不明的人提起的有关身份关系的诉讼", "C. 对不在中华人民共和国领域内居住的人提起的有关身份关系的诉讼", "D. 对不在中华人民共和国领域内居住的人提起的有关财产关系的诉讼"], "answer": "BC", "explanation": "《民事诉讼法》第23条规定：“下列民事诉讼，由原告住所地人民法院管辖；原告住所地与经常居住地不一致的，由原告经常居住地人民法院管辖：（一）对不在中华人民共和国领域内居住的人提起的有关身份关系的诉讼；（二）对下落不明或者宣告失踪的人提起的有关身份关系的诉讼；（三）对被采取强制性教育措施的人提起的诉讼；（四）对被监禁的人提起的诉讼”，因此A、D选项错误，B、C选项正确。(新编)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 77, "subject": "相关法", "id": "xg_287"},
  {"question": "6. 根据民事诉讼法及相关规定，关于地域管辖，下列说法正确的是？（多选）", "options": ["A. 因侵权行为提起的诉讼，由侵权行为地或者被告住所地人民法院管辖", "B. 因合同纠纷提起的诉讼，由被告住所地或者合同履行地人民法院管辖", "C. 因继承遗产纠纷提起的诉讼，由被继承人死亡时住所地或者主要遗产所在地人民法院管辖", "D. 因公司设立纠纷提起的诉讼，由公司住所地人民法院管辖"], "answer": "ABCD", "explanation": "A选项，《民诉法》第29条规", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 77, "subject": "相关法", "id": "xg_288"},
  {"question": "8. 根据民事诉讼法及相关规定，与信息网络管辖说法正确有哪些？(多选)", "options": ["A. 信息网络方式订立的买卖合同，通过信息网络交付标的的，以买受人住所地为合同履行地", "B. 信息网络方式订立的买卖合同，通过信息网络以外的方式交付标的的，收货地为合同履行地", "C. 信息网络侵权中，实施被诉侵权行为的计算机等信息设备所在地不属于侵权行为实施地", "D. 信息网络侵权中，侵权结果发生地包括被侵权人住所地"], "answer": "ABD", "explanation": "A、B选项，根据《民诉法解释》第20条规定：“以信息网络方式订立的买卖合同，通过信息网络交付标的的，以买受人住所地为合同履行地；通过其他方式交付标的的，收货地为合同履行地。合同对履行地有约定的，从其约定”，因此A、B选项正确。C、D选项，根据《民诉法解释》第25条规定：“信息网络侵权行为实施地包括实施被诉侵权行为的计算机等信息设备所在地，侵权结果发生地包括被侵权人住所地”，因此C选项错误，D选项正确。(新编)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 78, "subject": "相关法", "id": "xg_289"},
  {"question": "9. 甲和乙是同乡，现都在北京市海淀区工作。甲在深圳市南山区有一套住房，经协商，同意以400万元的价格将房屋卖给乙。双方在北京签订了合同，乙一次性支付了房款，后办理了房屋产权过户手续。现甲之妻以卖房未经其同意为由，要求乙返还房产。据此，本案应当由哪个人民法院管辖？(单选)", "options": ["A. 北京市海淀区人民法院", "B. 深圳市南山区人民法院", "C. 北京市海淀区人民法院或者深圳市南山区人民法院", "D. 最先受理甲之妻起诉的人民法院"], "answer": "B", "explanation": "根据《民诉法解释》第28条的规定，不动产纠纷是指因不动产的权利确认、分割、相邻关系等引起的物权纠纷。本题的诉讼是对房屋所有权权利的确认，属于专属管辖。B选项正确。(2018)", "type": "single", "topic": "专题三 民事诉讼法", "page": 78, "subject": "相关法", "id": "xg_290"},
  {"question": "11. 家住天津市河东区的李某，在七夕情人节当天在某宝网上购买了位于天津市西青区的“玫瑰有约”花店的99朵玫瑰花，送给位于天津市和平区的女友，直接由花店送达女友住处。女友收到后发现玫瑰花已经枯萎，经与花店协商未果，李某向天津市河东区法院起诉该花店。法院受理后认为没有管辖权，遂将案件移送天津市和平区法院。关于本案的管辖，下列哪些说法是正确的？(多选)", "options": ["A. 天津市河东区法院有管辖权", "B. 天津市西青区法院有管辖权", "C. 天津市和平区法院有管辖权", "D. 天津市河东区法院移送管辖不符合法律规定"], "answer": "BC", "explanation": "A、B、C选项，《民诉法》第24条规定：“因合同纠纷提起的诉讼，由被告住所地或者合同履行地人民法院管辖”，《民诉法解释》第20条规定：“以信息网络方式订立的买卖合同，通过信息网络交付标的的，以买受人住所地为合同履行地；通过其他方式交付标的的，收货地为合同履行地。合同对履行地有约定的，从其约定”，A选项为原告所在地法院，无管辖权，B选项为被告所在地、C选项为合同履行地，均有管辖权，因此A选项错误，B、C选项正确。D选项，根据《民诉法》第37条的规定，人民法院发现受理的案件不属于本院管辖的，应当移送有管辖权的人民法院。因此，天津市河东区法院移送符合规定，D选项错误。(新编)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 79, "subject": "相关法", "id": "xg_291"},
  {"question": "12. 根据民事诉讼法及相关规定，在不违反民事诉讼法对级别管辖和专属管辖规定的情况下，合同双方当事人可以就合同纠纷通过书面协议选择下列哪些人民法院管辖？(多选)", "options": ["A. 被告住所地人民法院", "B. 合同履行地人民法院", "C. 合同签订地人民法院", "D. 标的物所在地人民法院"], "answer": "ABCD", "explanation": "《民诉法》第35条规定：“合同或者其他财产权益纠纷的当事人可以书面协议选择被告住所地、合同履行地、合同签订地、原告住所地、标的物所在地等与争议有实际联系的地点的人民法院管辖，但不得违反本法对级别管辖和专属管辖的规定”，因此A、B、C、D选项均正确。(2012)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 79, "subject": "相关法", "id": "xg_292"},
  {"question": "13. 甲公司与乙公司签订了家具买卖合同，并欲就发生合同纠纷时的管辖问题进行约定。根据民事诉讼法及相关规定，在不违反级别管辖和专属管辖规定的情况下，下列哪些约定符合规定？(多选)", "options": ["A. 双方书面约定由合同签订地人民法院管辖", "B. 双方口头约定由合同签订地人民法院管辖", "C. 双方书面约定由原告住所地人民法院管辖", "D. 双方口头约定由原告住所地人民法院管辖"], "answer": "AC", "explanation": "根据《民诉法》第35条的规定，协议管辖应当采用书面协议，而不是口头协议，并可以选择合同签订地或原告住所地人民法院管辖，因此A、C选项正确，B、D选项错误。(2013)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 79, "subject": "相关法", "id": "xg_293"},
  {"question": "2. 10岁的张某在公交车上玩耍，不慎将手中的玩具砸到邻座8岁的王某致其受伤，双方父母对损害赔偿问题发生争议，王某的父母决定向法院提起诉讼，关于本案当事人的说法，下列哪些说法正确？(多选)", "options": ["A. 王某是原告", "B. 王某和王某的父母是共同原告", "C. 张某是被告", "D. 张某和张某的父母是共同被告"], "answer": "AD", "explanation": "《民事诉讼法》第60条规定：“无诉讼行为能力人由他的监护人作为法定代理人代为诉讼”，《民事诉讼法解释》第67条规定：“无民事行为能力人、限制民事行为能力人造成他人损害的，无民事行为能力人、限制民事行为能力人和其监护人为共同被告”，王某作为侵权法律关系中的受害人，为适格原告；由于起诉时王某尚未成年，应当由其监护人作为法定代理人提起诉讼。因此本案王某是原告，王某的父母是原告的法定代理人。张某为未成年人，应当以侵权人张某和其监护人为共同被告。因此本案中张某和张某的父母为共同被告。因此A、D选项正确。(新编)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 81, "subject": "相关法", "id": "xg_294"},
  {"question": "3. 根据民事诉讼法及相关规定，下列关于民事诉讼第三人的说法哪些是正确的？(多选)", "options": ["A. 对当事人双方的诉讼标的，第三人认为有独立请求权的，有权提起诉讼", "B. 有独立请求权的第三人有权向人民法院提出诉讼请求和事实、理由，成为当事人", "C. 对当事人双方的诉讼标的，第三人虽然没有独立请求权，但案件处理结果同他有法律上的利害关系的，可以申请参加诉讼", "D. 人民法院判决承担民事责任的第三人，有当事人的诉讼权利义务"], "answer": "ABCD", "explanation": "A选项，《民诉法》第59条第1款规定：“对当事人双方的诉讼标的，第三人认为有独立请求权的，有权提起诉讼”，因此A选项正确。B选项，根据《民诉法解释》第81条第1款的规定，有独立请求权的第三人有权向人民法院提出诉讼请求和事实、理由，成为当事人，因此B选项正确。C、D选项，《民诉法》第59条第2款规定：“对当事人双方的诉讼标的，第三人虽然没有独立请求权，但案件处理结果同他有法律上的利害关系的，可以申请参加诉讼，或者由人民法院通知他参加诉讼。人民法院判决承担民事责任的第三人，有当事人的诉讼权利义务”，因此C、D选项正确。(2010)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 81, "subject": "相关法", "id": "xg_295"},
  {"question": "4. 根据民事诉讼法及相关规定，在民事诉讼一审程序中，无独立请求权的第三人不享有下列哪项诉讼权利？(多选)", "options": ["A. 申请撤诉", "B. 提出回避申请", "C. 变更诉讼请求", "D. 对案件的管辖权提出异议"], "answer": "ACD", "explanation": "《民诉法解释》第82条规定：“在一审诉讼中，无独立请求权的第三人无权提出管辖异议，无权放弃、变更诉讼请求或者申请撤诉，被判决承担民事责任的，有权提起上诉”，诉讼参加人都有提出回避的权利，包括无独立请求权的第三人，因此A、C、D选项正确，B选项错误。(2011改编)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 81, "subject": "相关法", "id": "xg_296"},
  {"question": "6. 赵某与刘某将共有商铺出租给陈某。刘某瞒着赵某，与陈某签订房屋买卖合同，将商铺转让给陈某，后因该合同履行发生纠纷，刘某将陈某诉至法院。赵某得知后，坚决不同意刘某将商铺让与陈某。关于本案相关人的诉讼地位，下列哪一说法是正确的?(单选)", "options": ["A. 法院应依职权追加赵某为共同原告", "B. 赵某应以刘某侵权起诉，陈某为无独立请求权第三人", "C. 赵某应作为无独立请求权第三人", "D. 赵某应作为有独立请求权第三人"], "answer": "D", "explanation": "本题中，房屋买卖合同双方当事人是刘某和陈某，刘某作为原告，陈某作为被告，赵某不能作为共同原告参加诉讼，但赵某对于陈某和刘某之间争执的标的物主张所有权，应作为有独立请求权的第三人参与诉讼，因此A、B、C选项错误，D选项正确。(法考2018)", "type": "single", "topic": "专题三 民事诉讼法", "page": 82, "subject": "相关法", "id": "xg_297"},
  {"question": "7. 甲公司对乙公司有100万元债权到期，乙公司对丙公司有100万债权。甲公司对丙公司提起代位权诉讼，法院依法将乙公司列为第三人。诉讼中甲、丙达成调解协议，约定丙公司将价值100万一批货物交付给甲，用于清偿该笔债务，法院依法制作调解书送达当事人。丁主张货物是自己的，欲提出第三人撤销之诉，该撤销之诉中，下列关于当事人地位的说法哪些是正确的?(多选)", "options": ["A. 乙是被告", "B. 丙是被告", "C. 乙是第三人", "D. 丙是第三人"], "answer": "BC", "explanation": "《民诉法解释》第296条规定：“第三人提起撤销之诉，人民法院应当将该第三人列为原告，生效判决、裁定、调解书的当事人列为被告，但生效判决、裁定、调解书中没有承担责任的无独立请求权的第三人列为第三人”。本题中，原审甲是原告，丙是被告，乙是无独立请求权的第三人，所以在第三人撤销之诉中，应当以原审原告甲和原审被告丙为被告，而原审无独立请求权的第三人乙在第三人撤销之诉中的诉讼地位应当视其在生效裁判文书中是否承担义务而定，原生效调解书约定的内容是“丙将价值100万元的货物交付给甲”，显然无独立请求权的第三人乙不承担责任，因此在第三人撤销之诉中乙应当作为第三人，不能作为被告，A、D选项错误，B、C选项正确。(法考2006，思维扩展)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 82, "subject": "相关法", "id": "xg_298"},
  {"question": "8. 关于必要共同诉讼与普通共同诉讼的区别，下列哪项说法是正确的?(多选)", "options": ["A. 必要共同诉讼的诉讼标的是共同的，普通共同诉讼的诉讼标的是同种类的", "B. 必要共同诉讼的诉讼标的只有一个，普通共同诉讼的诉讼标的有多于一个", "C. 必要共同诉讼的诉讼标的是同种类的，普通共同诉讼的诉讼标的是同种类的", "D. 必要共同诉讼的诉讼标的是同种类的，普通共同诉讼的诉讼标的是同种类的"], "answer": "AB", "explanation": "《民诉法》第55条规定：“当事人一方或者双方为二人以上，其诉讼标的是共同的，或者诉讼标的是同一种类、人民法院认为可以合并审理并经当事人同意的，为共同诉讼。共同诉讼的一方当事人对诉讼标的有共同权利义务的，其中一人的诉讼行为经其他共同诉讼人承认，对其他共同诉讼人发生效力；对诉讼标的没有共同权利义务的，其中一人的诉讼行为对其他共同诉讼人不发生效力”。由此可知，共同诉讼包括必要共同诉讼和普通共同诉讼，必要共同诉讼当事人的诉讼标的是共同的（只有一个），普通共同诉讼当事人的诉讼标的为同一种类（有若干个），因此A、B选", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 82, "subject": "相关法", "id": "xg_299"},
  {"question": "12. 张某因为合同纠纷起诉甲公司，在诉讼中张某突发脑梗，经抢救后，张某仍然丧失行为能力。张某的父亲希望撤回起诉，以专心为张某治疗；张某的妻子表示希望继续诉讼。本案法院应当如何处理?(单选)", "options": ["A. 法院应当追加张某的妻子为共同原告", "B. 法院应当变更张某的妻子为原告，诉讼继续进行", "C. 追加张某的妻子为法定代理人，诉讼继续进行", "D. 根据张某父亲的请求，裁定准予撤回起诉"], "answer": "C", "explanation": "《民诉法》第60条规定：无诉讼行为能力人由他的监护人作为法定代理人代为诉讼。张某丧失行为能力，应当由其法定代理人代为诉讼。根据《民法典》第28条规定，无、限制民事行为能力的成年人，由下列有监护能力的人的按顺序担任监护人：(一)配偶；(二)父母、子女；(三)其他近亲属；(四)其他愿意担任监护人的个人和组织，但必须经过被监护人所在地的居民委员会、村民委员会或者民政部门同意。故张某的妻子是第一顺位，应当由张某的妻子担任代理人。因此，本案应当追加张某的妻子为法定代理人，诉讼继续进行，C选项正确，D选项错误。张某的妻子应当是原告张某的法定代理人，不是当事人，不能追加其为共同原告或者原告，A、B选项错误。(法考2021)", "type": "single", "topic": "专题三 民事诉讼法", "page": 84, "subject": "相关法", "id": "xg_300"},
  {"question": "13. 王某因与甲公司发生合同纠纷，遂委托李律师全权代理诉讼，但未作具体的授权。此种情况下，李律师在诉讼中无权实施下列哪些行为?(多选)", "options": ["A. 提出管辖权异议", "B. 提起反诉", "C. 提起上诉", "D. 部分变更诉讼请求"], "answer": "BCD", "explanation": "《民诉法》第62条第1、2款规定：“委托他人代为诉讼，必须向人民法院提交由委托人签名或者盖章的授权委托书。授权委托书必须记明委托事项和权限。诉讼代理人代为承认、放弃、变更诉讼请求，进行和解，提起反诉或者上诉，必须有委托人的特别授权”，全权委托代理视为无特别授权，A选项提出管辖权异议不需要特别授权，B、C、D选项的行为需要特别授权。(2019)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 84, "subject": "相关法", "id": "xg_301"},
  {"question": "14. 根据民事诉讼法及相关规定，律师作为诉讼代理人，应当向人民法院提交下列哪些材料?(多选)", "options": ["A. 律师执业证", "B. 本人身份证件", "C. 律师事务所证明材料", "D. 授权委托书"], "answer": "ACD", "explanation": "《民诉法解释》第88条规定：“诉讼代理人除根据民事诉讼法第62条规定提交授权委托书外，还应当按照下列规定向人民法院提交相关材料：(一)律师应当提交律师执业证、律师事务所证明材料……”，律师作为诉讼代理人不要求提交本人身份证件，因此A、C、D选项正确。(新编)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 84, "subject": "相关法", "id": "xg_302"},
  {"question": "1. 关于民事诉讼证据的理解,下列选项中正确的有? (单选)", "options": ["A. 存储在电子介质上的录音资料,适用电子数据的相关规定", "B. 民事诉讼中的证人只能是自然人", "C. 法院责令对方当事人提交相关书证,则因提交书证所产生的费用,应当由申请人垫付,由对方当事人最终承担", "D. 书证应当提交原件,但如果原件在对方当事人控制之下,则可以提交复制品"], "answer": "A", "explanation": "A选项,《民诉法解释》第116条第3款规定:“存储在电子介质中的录音资料和影像资料,适用电子数据的规定”,因此A选项正确。B选项,《民诉法》第75条第1款规定:“凡是知道案件情况的单位和个人,都有义务出庭作证……”,因此单位和个人都可以作为证人,B选项错误。C选项,《民诉法解释》第112条规定:“书证在对方当事人控制之下的,承担举证证明责任的当事人可以在举证期限届满前书面申请人民法院责令对方当事人提交。申请理由成立的,人民法院应当责令对方当事人提交,因提交书证所产生的费用,由申请人负担……”,因此C选项错误。D选项,《民诉法》第73条规定:“书证应当提交原件……提交原件或者原物确有困难的,可以提交复制品……”,根据《民诉法解释》第111条的规定,提交书证原件有困难的条件包括原件在对方当事人控制之下,经合法通知提交而拒不提交的情形,因此对于原件在对方当事人控制之下的书证,需经合法通知提交而拒不提交的,才可提交复制品,D选项错误。(2018)", "type": "single", "topic": "专题三 民事诉讼法", "page": 85, "subject": "相关法", "id": "xg_303"},
  {"question": "2. 根据民事诉讼法及相关规定,当事人的下列哪些做法符合关于证据的规定?(多选)", "options": ["A. 原告赵某以电子数据作为证据来证明提出自己的主张", "B. 原告张某因在人民法院确定的期限内提供证据确有困难,向人民法院申请延长期限", "C. 被告李某因提交某书证原件确有困难,提交了经人民法院核对无异的复制件", "D. 被告王某提交外文书证作为证据,未附中文译本"], "answer": "ABC", "explanation": "A选项,《民诉法》第66条规定:“证据包括:……(五)电子数据……”,因此电子数据可作为民事诉讼证据,A选项正确。B选项,《民诉法》第68条第2款规定:“……当事人在该期限内提供证据确有困难的,可以向人民法院申请延长期限,人民法院根据当事人的申请适当延长……”,因此B选项正确。C选项,根据《民诉法》第73条的规定,书证提交原件或者原物确有困难", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 85, "subject": "相关法", "id": "xg_304"},
  {"question": "4. 在一起专利侵权诉讼中，原告申请由其弟袁某（某大学计算机系教授）作为专家辅助人出庭对专业技术问题予以说明。下列哪些表述是正确的？（多选）", "options": ["A. 被告以袁某是原告的近亲属为由申请其回避，法院应批准", "B. 袁某在庭上的陈述是一种法定证据", "C. 被告可对袁某进行询问", "D. 袁某出庭的费用，由败诉方当事人承担"], "answer": "BC", "explanation": "A选项，有专门知识的人的作用是帮助申请方当事人对鉴定意见进行质证或者就专业问题发表意见，无需保持中立，故不适用回避制度，A选项错误。《民诉法解释》第122条第2款规定：“具有专门知识的人在法庭上就专业问题提出的意见，视为当事人陈述”，当事人陈述属于法定证据种类之一，B选项正确。《民诉法解释》第123条第1款规定：“经法庭准许，当事人可以对出庭的具有专门知识的人进行询问”，C选项正确。《民诉法解释》第122条第3款规定：“人民法院准许当事人申请的，相关费用由提出申请的当事人负担”，而非败诉方当事人承担，D选项错误。因此，B、C选项正确。（法考2014）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 86, "subject": "相关法", "id": "xg_305"},
  {"question": "5. 甲、乙两公司因合同纠纷提起诉讼，甲公司申请丙运输公司的赵某作为证人出庭作证，乙公司申请本公司的仓库保管员钱某作为证人出庭作证，以下表述正确的是？（多选）", "options": ["A. 因钱某是乙公司员工，需经过甲公司同意方具有证人资格", "B. 为提高效率，赵某提前写好证词当庭宣读", "C. 法院可安排赵某和钱某当庭对质", "D. 赵某因路途遥远申请视频作证，法院未询问乙公司意见直接同意"], "answer": "CD", "explanation": "A选项，作为证人需要满足两个条件，一是了解案件事实，二是能够正确表达，本案中钱某虽然是乙公司的工作人员，但其具有证人资格，且无需经过对方当事人同意，A选项错误。B选项，证人应当客观陈述其亲身感受的事实，不得宣读事先准备的书面材料，B选项错误。C选项，证人作证应当分别进行，其他证人不得在场，但必要时法院可以安排证人之间进行对质，C选项正确。D选项，《民诉法》第76条规定：“有下列情形之一的，经人民法院许可，可以通过书面证言、视听传输技术或者视听资料等方式作证：……（二）因路途遥远，交通不便不能出庭的……”，本案中证人赵某因为路途遥远不能出庭作证，经法院同意后", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 86, "subject": "相关法", "id": "xg_306"},
  {"question": "6. 杨某（15岁）与何某（14岁）两人经常打闹，一次，杨某失手将何某推倒，致何某成为了植物人，当时在场的还有何某的弟弟何小某（11岁）。法院审理时，何小某以证人身份出庭。关于何小某作证，下列哪些说法不能成立？（多选）", "options": ["A. 何小某只有11岁，不具有证人资格", "B. 何小某是何某的弟弟，应回避", "C. 何小某作为未成年人，其所有证言依法都不具有证明力", "D. 何小某作为何某的弟弟，证言具有明显的倾向性，其证言不能单独作为定案依据"], "answer": "ABC", "explanation": "A选项，《证据规定》第67条第2款规定：‘待证事实与其年龄、智力状况或者精神健康状况相适应的无民事行为能力人和限制民事行为能力人，可以作为证人’，何小某虽然为限制民事行为能力人，但是可以作为证人，A选项错误。证人不适用回避制度，B选项错误。《证据规定》第90条规定：‘无民事行为能力人或者限制民事行为能力人所作的与其年龄、智力状况或者精神健康状况不相当的证言，与一方当事人或者其代理人有利害关系的证人陈述的证言，不能单独作为认定案件事实的根据’，何小某作为限制民事行为能力人，即便其所作证言与其年龄智力状况不相当，依旧具有证明力，只是证明力较小，不能单独作为认定案件事实的根据，C选项错误，D选项正确。本题选择不正确的选项，因此A、B、C选项当选。（法考2017）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 86, "subject": "相关法", "id": "xg_307"},
  {"question": "7. 根据民事诉讼法及相关规定，下列哪些关于鉴定的说法正确的是?(多选)", "options": ["A. 当事人可以就查明事实的专门性问题向人民法院申请鉴定", "B. 当事人对鉴定意见有异议的，鉴定人不出庭作证，是否采纳该鉴定意见由法院决定", "C. 人民法院准许当事人鉴定申请的，应当在名录中指定鉴定人", "D. 当事人可以申请人民法院通知有专门知识的人出庭，就鉴定人作出的鉴定意见或者专业问题提出意见"], "answer": "AD", "explanation": "A、C选项，《民诉法》第79条第1款规定：“当事人可以就查明事实的专门性问题向人民法院申请鉴定。当事人申请鉴定的，由双方当事人协商确定具备资格的鉴定人;协商不成的，由人民法院指定”，因此A选项正确，C选项错误。B选项，《民诉法》第81条规定：“当事人对鉴定意见有异议或者人民法院认为鉴定人有必要出庭的，鉴定人应当出庭作证。经人民法院通知，鉴定人拒不出庭作证的，鉴定意见不得作为认定事实的根据……”，因此B选项错误。D选项，《民诉法》第82条规定：“当事人可以申请人民法院通知有专门知识的人出庭，就鉴定人作出的鉴定意见或者专业问题提出意见”，因此D选项正确。(2018)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 87, "subject": "相关法", "id": "xg_308"},
  {"question": "8. 在某专利侵权诉讼中，原告张某依法向人民法院申请鉴定。具备资格的某鉴定人依法出具了鉴定意见，张某支付了鉴定费用。案件审理过程中，被告王某对该鉴定意见有异议，人民法院通知该鉴定人出庭作证，但其拒不出庭作证。据此，根据民事诉讼法及相关规定，下列哪些说法是正确的?(多选)", "options": ["A. 人民法院应当拘传该鉴定人出庭作证", "B. 该鉴定意见不得作为认定事实的根据", "C. 张某可以要求该鉴定人返还鉴定费用", "D. 人民法院应当责令张某确定其他鉴定人重新作出鉴定"], "answer": "BC", "explanation": "A、B、C选项，《民诉法》第81条规定：“当事人对鉴定意见有异议或者人民法院认为鉴定人有必要出庭的，鉴定人应当出庭作证。经人民法院通知，鉴定人拒不出庭作证的，鉴定意见不得作为认定事实的根据;支付鉴定费用的当事人可以要求返还鉴定费用”，因此A选项错误，B、C选项正确。D选项，如果鉴定意见未被采纳，由负有", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 87, "subject": "相关法", "id": "xg_309"},
  {"question": "10. 刘月购买甲公司的化肥，使用后农作物生长异常。刘月向法院起诉，要求甲公司退款并赔偿损失。诉讼中甲公司否认刘月的损失是因其出售的化肥质量问题造成的，刘月向法院提供了本村吴某起诉甲公司损害赔偿案件的判决书，以证明甲公司出售的化肥有质量问题且与其所受损害有因果关系。关于本案刘月所受损害与使用甲公司化肥因果关系的证明责任分配，下列哪一选项是正确的?(单选)", "options": ["A. 应由刘月负担有因果关系的证明责任", "B. 应由甲公司负担无因果关系的证明责任", "C. 应由法院依职权裁量分配证明责任", "D. 应由双方当事人协商分担证明责任"], "answer": "B", "explanation": "A、B选项，根据《民诉法解释》第93条的规定，已为人民法院发生法律效力的裁判所确认的事实，当事人无须举证证明，但是有相反证据足以推翻的除外。关于化肥质量与损害结果之间的因果关系，已有生效的法律文书确认，刘月无须对此事承担举证责任，甲公司可以用相反证据推翻生效判决认定的因果关系这一事实。甲公司应当提供证据证明化肥质量问题与农作物生长异常不存在因果关系，因此A选项错误，B选项正确。C、D选项，证明责任只能由法律、司法解释预先规定，不存在法院依职权裁量以及当事人协议分配的可能，因此，C、D选项错误。(法考2016，思维扩展)", "type": "single", "topic": "专题三 民事诉讼法", "page": 88, "subject": "相关法", "id": "xg_310"},
  {"question": "12. 关于民事诉讼证据交换，下列说法哪些是正确的?(多选)", "options": ["A. 人民法院在开庭前可以组织交换证据", "B. 证据交换可以在审判人员或书记员的主持下进行", "C. 交换证据的时间可由人民法院指定"], "answer": "ACD", "explanation": "A、C、D选项，《证据规定》第56条规定：“人民法院依照民事诉讼法第133条第4项", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 88, "subject": "相关法", "id": "xg_311"},
  {"question": "1. 关于民事诉讼中的调解，下列哪些说法是正确的？(多选)", "options": ["A. 调解应当根据自愿和合法的原则进行", "B. 人民法院进行调解的，应当由合议庭主持", "C. 调解协议的内容不得违反法律的规定", "D. 调解书送达前一方反悔的，人民法院应当及时判决"], "answer": "ACD", "explanation": "A选项，《民诉法》第9条规定：“人民法院审理民事案件，应当根据自愿和合法的原则进行调解……”，因此A选项正确。B选项，《民诉法》第97条第1款规定：“人民法院进行调解，可以由审判员一人主持，也可以由合议庭主持……”，因此B选项错误。C选项，《民诉法》第99条规定：“……调解协议的内容不得违反法律规定”，因此C选项正确。D选项，《民诉法》第102", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 89, "subject": "相关法", "id": "xg_312"},
  {"question": "2. 根据民事诉讼法及相关规定，下列有关调解的说法哪些 - 88 -", "options": ["A. 人民法院调解案件时，当事人本人不能出庭的，经特别授权，可由其委托代理人参加调解", "B. 人民法院受理案件后，经审查，认为法律关系明确、事实清楚，可以径行调解", "C. 人民法院进行调解，可以邀请有关单位和个人协助", "D. 调解书经双方当事人签收后，即具有法律效力"], "answer": "ACD", "explanation": "A选项，《民诉法解释》第147条第1款规定：‘人民法院调解案件时，当事人不能出庭的，经其特别授权，可由其委托代理人参加调解……’，因此A选项正确。B选项，《民诉法解释》第142条规定：‘人民法院受理案件后，经审查，认为法律关系明确、事实清楚，在征得当事人双方同意后，可以径行调解’，径行调解应先征得双方当事人同意，因此B选项错误。C选项，《民诉法》第98条规定：‘人民法院进行调解，可以邀请有关单位和个人协助……’，因此C选项正确。D选项，《民诉法》第100条第3款规定：‘调解书经双方当事人签收后，即具有法律效力’，因此D选项正确。(2009)", "type": "single", "topic": "专题三 民事诉讼法", "page": 89, "subject": "相关法", "id": "xg_313"},
  {"question": "13. 根据民事诉讼法及相关规定，下列哪种说法是错误的？(单选)", "options": ["A. 证据应当在法庭上出示，由当事人质证", "B. 未经质证的证据，不能作为认定案件事实的根据", "C. 涉及商业秘密的证据，不得在开庭时公开质证", "D. 未出庭作证的证人证言不能作为认定案件事实的依据"], "answer": "D", "explanation": "A、B选项，根据《民诉法解释》第103条的规定，证据应当在法庭上出示，由当事人互相质证。未经当事人质证的证据，不得作为认定案件事实的根据。涉及国家秘密、商业秘密、个人隐私或者法律规定应当保密的证据，不得公开质证。因此A、B、C选项正确。D选项，根据《民诉法》第76条的规定，对于确有出庭困难的证人，经人民法院许可，可以通过书面证言、视听传输技术或者视听资料等方式作证，因此D选项说法过于绝对，D选项错误。(新编)", "type": "single", "topic": "专题三 民事诉讼法", "page": 89, "subject": "相关法", "id": "xg_314"},
  {"question": "14. 根据民事诉讼法及相关规定，下列关于证据保全的哪些说法是正确的？(多选)", "options": ["A. 在证据可能灭失的情况下，当事人可以在诉讼过程中申请保全证据", "B. 证据保全只能依当事人申请进行，人民法院不得主动采取保全措施", "C. 当事人申请证据保全的，可以在举证期限届满前书面提出", "D. 证据保全可能对他人造成损失的，人民法院应当责令申请人提供相应的担保 第五章 调解"], "answer": "ACD", "explanation": "《民诉法》第84条第1款规定：“在证据可能灭失或者以后难以取得的情况下，当事人可以在诉讼过程中向人民法院申请保全证据，人民法院也可以主动采取保全措施”因此A选项正确，B选项错误。C选项，《民诉法解释》第98条第1款规定：“当事人根据民事诉讼法第84条规定申请证据保全的，可以在举证期限届满前书面提出”，因此C选项正确。D选项，《民诉法解释》第98条第2款规定：“证据保全可能对他人造成损失的，人民法院应当责令申请人提供相应的担保”，因此D选项正确。(2017)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 89, "subject": "相关法", "id": "xg_315"},
  {"question": "2. 根据民事诉讼法及相关规定,下列关于诉前财产保全的说法,正确的是?(多选)", "options": ["A. 人民法院可以依职权主动采取诉前财产保全措施", "B. 利害关系人因情况紧急,不立即申请财产保全将会使其合法权益受到难以弥补的损害的,可以申请诉前财产保全", "C. 人民法院接受申请后,必须在48小时内作出裁定", "D. 申请人可以不提供担保"], "answer": "BC", "explanation": "A、B选项,人民法院不能主动采取诉前保全措施,可以依申请采取诉前保全,因此A选项错误,B选项正确。C选项,《民诉法》第104条第2款规定:“人民法院接受申请后,必须在48小时内作出裁定……”,因此C选项正确。D选项,诉前保", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 91, "subject": "相关法", "id": "xg_316"},
  {"question": "1. 根据民事诉讼法及相关规定，就发明专利侵权提起民事诉讼的，起诉必须符合下列哪些条件？(多选)", "options": ["A. 原告是与本案有直接利害关系的公民、法人和其他组织", "B. 被告是与本案有直接利害关系的公民、法人和其他组织", "C. 属于人民法院受理民事诉讼的范围和受诉人民法院管辖", "D. 有具体的诉讼请求和事实、理由"], "answer": "ACD", "explanation": "《民诉法》第122条规定：“起诉必须符合下列条件：(一)原告是与本案有直接利害关系的公民、法人和其他组织；(二)有明确的被告；(三)有具体的诉讼请求和事实、理由；(四)属于人民法院受理民事诉讼的范围和受诉人民法院管辖”，因此A、C、D选项正确。对于被告的要求只要求明确，不要求适格，因此B选项错误(新编)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 92, "subject": "相关法", "id": "xg_317"},
  {"question": "3. 根据民事诉讼法及相关规定，下列关于财产保全相关事项说法错误的是：(多选)", "options": ["A. 财产保全采取查封、扣押、冻结或者法律规定的其他方法", "B. 法院可以指定被保全人负责保管被查封、扣押、冻结的财产", "C. 被查封、扣押、冻结的财产，其上的质权、留置权因采取保全措施而消灭", "D. 由人民法院指定被保全人保管的财产，被保全人不得继续使用"], "answer": "CD", "explanation": "A选项，《民诉法》第106条规定第1款：“财产保全采取查封、扣押、冻结或者法律规定的其他方法”，因此A选项正确。B、C选项，《民诉法解释》第154条第1款规定：“人民法院在财产保全中采取查封、扣押、冻结财产措施时，应当妥善保管被查封、扣押、冻结的财产。不宜由人民法院保管的，人民法院可以指定被保全人负责保管；不宜由被保全人保管的，可以委托他人或者申请保全人保管。查封、扣押、冻结担保物权人占有的担保财产，一般由担保物权人保管；由人民法院保管的，质权、留置权不因采取保全措施而消灭”，因此B选项正确，C选项错误。D选项，《民诉法解释》第155条规定：“由人民法院指定被保全人保管的财产，如果继续使用对该财产的价值无重大影响，可以允许被保全人继续使用……”，因此D选项错误。(2018)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 92, "subject": "相关法", "id": "xg_318"},
  {"question": "4. 王某早年丧妻，独自一人抚养儿子王小某。王小某成年后，从未支付赡养费。王某起诉王小某支付赡养费，诉讼过程中，王某生病，急需支付住院费。王小某把自己存款 3 万元转到一个朋友的账户上。对此，王某可以向法院申请采取的措施是？(多选)", "options": ["A. 对妨害民事诉讼的强制措施", "B. 诉讼保全措施", "C. 证据保全措施", "D. 先予执行措施 第七章 民事审判第一审普通程序"], "answer": "BD", "explanation": "A选项，王小某并未实施妨碍诉讼或者执行的行为，不能对其采取强制措施，因此A选项错误。B、C、D选项，王某急需支付住院费，属于情况紧急的情形，王某可以申请法院先予执行。王小某将钱转到朋友账户上，可能导致将来判决难以执行，王某有权向法院申请财产保全，而不是证据保全，因此B、D选项正确，C选项错误。(法考2009，思维扩展)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 92, "subject": "相关法", "id": "xg_319"},
  {"question": "2. 根据民事诉讼法及相关规定，对于下列哪些情形，法院应当裁定不予受理？（多选）", "options": ["A. 李某起诉王某，人民法院发现王某已于起诉前死亡", "B. 李某起诉王某，要求王某支付精神损害赔偿金一亿元", "C. 甲公司起诉乙公司，人民法院发现乙公司已经注销", "D. 甲公司起诉乙公司，人民法院发现乙公司与本案没有直接利害关系"], "answer": "AC", "explanation": "如果被告在起诉前已经死亡，或者被告公司已经注销，法院应当裁定不予受理，因为无法对已不存在的主体进行诉讼。精神损害赔偿金的金额大小不影响法院受理案件的决定，而乙公司与本案没有直接利害关系则需要进一步的事实来判断。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 93, "subject": "相关法", "id": "xg_320"},
  {"question": "4. 我国实行立案登记制，关于民事第一审普通程序，下列表述正确的是？（多选）", "options": ["A. 原告必须提交书面起诉状", "B. 被告具有诉讼权利能力", "C. 原告应与案件有直接利害关系", "D. 原告应提供支持自己诉讼请求的证据"], "answer": "BC", "explanation": "《民诉法》中规定的起诉条件一共有4项：①原告适格；②有明确的被告；③有具体的诉讼请求和事实、理由；④属于法院主管和受诉法院管辖。A选项，根据《民诉法》第123条的规定，起诉并不要求提交书面起诉状，也可以口头起诉，由法院记入笔录，并告知对方当事人，因此A选项错误。B选项，起诉条件中要求有明确的被告，即被告需要具备诉讼权利能力，无诉讼权利能力的被告，如已经死亡的自然人或者已经注销的公司，属于没有明确的被告，因此B选项正确。C选项，起诉条件中要求原告适格，即原告是与本案有直接利害关系的公民、法人和其他组织，C选项正确。D选项，起诉条件中仅要求有具体的诉讼请求和事实、理由，未要求该事实、理由有证据证明，也不要求该诉讼请求能够得到法律支持，因此D选项错误。（法考2022，思维扩展）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 93, "subject": "相关法", "id": "xg_321"},
  {"question": "5. 根据民事诉讼法及相关规定，有关管辖权异议的下列哪些说法是正确的？（多选）", "options": ["A. 人民法院受理案件后，当事人对管辖权有异议的，应当在提交答辩状期间提出", "B. 当事人未提出管辖权异议，并应诉答辩或者提出反诉的，视为受诉人民法院有管辖权，但违反级别管辖和专属管辖规"], "answer": "BCD", "explanation": "A选项,如果调解违反自愿原则或者调解协议的内容违反法律的,可以申请再审,因此A选项错误。B选项,《民诉法》第213条规定:“当事人对已经发生法律效力的解除婚姻关系的判决、调解书,不得申请再审”,B选项正确。C选项,《民诉法》第217条规定:“按照审判监督程序决定再审的案件,裁定中止原判决、裁定、调解书的执行……”,因此C选项正确。D选项,《民诉法》第218条第2款规定:“人民法院审理", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 93, "subject": "相关法", "id": "xg_322"},
  {"question": "6. 根据民事诉讼法及相关规定，下列关于民事诉讼第一审普通程序的哪些说法是正确的？(多选)", "options": ["A. 人民法院审理民事案件，一律应当公开进行", "B. 人民法院审理民事案件，一律公开宣告判决", "C. 人民法院审理民事案件，应当在开庭三日前通知当事人和其他诉讼参与人", "D. 人民法院审理民事案件，根据需要进行巡回审理、就地办案"], "answer": "BCD", "explanation": "A选项，《民诉法》第137条第1款规定：“人民法院审理民事案件，除涉及国家秘密、个人隐私或者法律另有规定的以外，应当公开进行”，因此A选项错误。B选项，《民诉法》第151条第1款规定：“人民法院对公开审理或者不公开审理的案件，一律公开宣告判决”，因此B选项正确。C选项，《民诉法》第139条规定：“人民法院审理民事案件，应当在开庭3日前通知当事人和其他诉讼参与人”，因此C选项正确。D选项，《民诉法》第138条规定：“人民法院审理民事案件，根据需要进行巡回审理，就地办案”，因此D选项正确。(2017)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 94, "subject": "相关法", "id": "xg_323"},
  {"question": "8. 根据民事诉讼法及相关规定，关于第一审普通程序，下列说法哪些是正确的？(多选)", "options": ["A. 原告经传票传唤，无正当理由拒不到庭的，应当缺席判决", "B. 被告未经法庭许可中途退庭的，可以缺席判决", "C. 宣判前，原告申请撤诉的，人民法院应当准许", "D. 宣判前，原告申请撤诉的，是否准许，由人民法院裁定"], "answer": "BD", "explanation": "A选项，根据《民诉法》第146条的规定，原告经传票传唤，无正当理由拒不到庭的，可以按撤诉处理，因此A选项错误。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 94, "subject": "相关法", "id": "xg_324"},
  {"question": "10. 根据民事诉讼法及相关规定，下列哪些情形下可以延期开庭审理?(多选)", "options": ["A. 必须到庭的当事人有正当理由没有到庭的", "B. 当事人临时提出回避申请的", "C. 需要通知新的证人到庭的", "D. 本案必须以另一案的审理结果为依据，而另一案又尚未审结的"], "answer": "ABC", "explanation": "《民诉法》第149规定：“有下列情形之一的，可以延期开庭审理：(一)必须到庭的当事人和其他诉讼参与人有正当理由没有到庭的；(二)当事人临时提出回避申请的；(三)需要通知新的证人到庭，调取新的证据，重新鉴定、勘验，或者需要补充调查的；(四)其他应当延期的情形”，因此A、B、C选项正确。D选项属于中止诉讼的情形。(2012)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 95, "subject": "相关法", "id": "xg_325"},
  {"question": "11. 根据民事诉讼法及相关规定，人民法院适用普通程序审理民事诉讼案件的期限为六个月，但该期限不包括下列哪些期间?(多选)", "options": ["A. 公告期间", "B. 鉴定期间", "C. 审理当事人提出的管辖权异议期间", "D. 处理人民法院之间的管辖权争议期间"], "answer": "ABCD", "explanation": "《民诉法解释》第243条规定：“民事诉讼法第152规定的审限，是指从立案之日起至裁判宣告、调解书送达之日止的期间，但公告期间、鉴定期间、双方当事人和解期间、审理当事人提出的管辖异议以及处理人民法院之间的管辖争议期间不应计算在内”，因此A、B、C、D选项均正确。(2009)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 95, "subject": "相关法", "id": "xg_326"},
  {"question": "3. 根据《民事诉讼法》及相关司法解释中关于小额诉讼的规定，下列说法正确的有：（多选）", "options": ["A. 人民法院审理小额诉讼案件，实行一审终审", "B. 标的额为各省、自治区、直辖市上年度就业人员年平均工资百分之三十以下的，适用小额诉讼的程序审理", "C. 小额诉讼程序可以免去举证期限和答辩期间", "D. 小额诉讼案件的举证期限，当事人协商一致即可确定"], "answer": "AC", "explanation": "根据《民诉法》第165条规定，基层人民法院和它派出的法庭审理事实清楚、权利义务关系明确、争议不大的简单金钱给付民事案件，标的额为各省、自治区、直辖市上年度就业人员年平均工资百分之五十以下的，适用小额诉讼的程序审理，实行一审终审，因此A选项正确，B选项错误。C、D选项，根据《民诉法解释》第275条的规定，小额诉讼案件的举证期限由人民法院确定，也可以由当事人协商一致并经人民法院准许，但一般不超过7日。当事人到期后表示不需要举证期限和答辩期间的，人民法院可立即开庭审理。因此C选项正确，D选项忽略了法院的审查准许，因此错误。（新编）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 98, "subject": "相关法", "id": "xg_327"},
  {"question": "4. 根据人民法院在线诉讼规则及相关规定，下列案件哪些不得适用在线庭审？（多选）", "options": ["A. 需要通过庭审现场查明身份、核对原件、查验实物的", "B. 案件疑难复杂、证据繁多，适用在线庭审不利于查明事实和适用法律的", "C. 案件涉及国家安全、国家秘密的", "D. 案件具有重大社会影响，受到广泛关注的"], "answer": "ABCD", "explanation": "《人民法院在线诉讼规则》第21条第1款规定：“人民法院开庭审理的案件，应当根据当事人意愿、案件情况、社会影响、技术条件等因素，决定是否采取视频方式在线庭审，但具有下列情形之一的，不得适用在线庭审：……（三）需要通过庭审现场查明身份、核对原件、查验实物的；（四）案件疑难复杂、证据繁多，适用在线庭审不利于查明事实和适用法律的；（五）案件涉及国家安全、国家秘密的；（六）案件具有重大社会影响，受到广泛关注的……”，因此A、B、C、D选项均正确。（新编）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 98, "subject": "相关法", "id": "xg_328"},
  {"question": "5. 某省上年度就业人员年平均工资为8万元。张某诉李某归还借款6万元，该省某基层法院受理案件后，张某和李某均同意适用小额诉讼的程序审理。在审理过程中，李某对张某提出反诉，要求张某归还欠款8万元，法院应当如何处理？（多选）", "options": ["A. 法院应当继续适用小额诉讼的程序审理", "B. 如果张某、李某同意适用小额诉讼的程序审理的，法院应当适用小额诉讼的程序审理", "C. 当事人可以对法院适用小额诉讼的程序审理"], "answer": "CD", "explanation": "《民诉法》第165条规定，基层人民法院和它派出的法庭审理上述民事案件，标的额超过各省、自治区、直辖市上年度就业人员年平均工资50%但在2倍以下的，当事人双方也可以约定适用小额诉讼的程序。张某起诉李某归还借款6万元，标的额超过了该省上年度就业人员年平均工资的50%，但在2倍以下，当事人可以协议适用小额诉讼的程序，故法院在张某、李某同意适用小额诉讼的程序审理的情况下，法院可以适用小额诉讼的程序审理。但审理过程中李某对张某提出了反诉，根据《民诉法》第166条规定，当事人提出反诉的案件不得适用小额诉讼的程序审理，因此本案不能继续适用小额诉讼的程序审理，应当适用简易程序的其他规定审理或者裁定将案件转为普通程序。当然，当事人也可以对法院适用小额诉讼的程序提出异议。因此，C、D选项正", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 98, "subject": "相关法", "id": "xg_329"},
  {"question": "6. 甲起诉乙归还借款200元,某区法院受理后适 用小额诉讼的程序审理。关于本案,下列说法正确的 是?(多选)", "options": ["A. 法院可以采用短信方式传唤当事人", "B. 法院可以采用短信送达裁判文书", "C. 本案不得适用小额诉讼的程序审理", "D. 本案法院所作判决一审终审 第九章 第二审程序"], "answer": "ABD", "explanation": "A、B选项,《民诉法解释》第261条规定:\n“适用简易程序审理案件,人民法院可以采取捎口信、电\n话、短信、传真、电子邮件等简便方式传唤双方当事人、\n通知证人和送达诉讼文书”,小额诉讼程序作为特殊的\n简易程序,适用简易程序的一般规定,A、B选项正确。\nC、D选项,《民诉法》第165条规定:“基层人民法院和它\n派出的法庭审理事实清楚、权利义务关系明确、争议不\n大的简单金钱给付民事案件,标的额为各省、自治区、直\n辖市上年度就业人员年平均工资百分之五十以下的,适\n用小额诉讼的程序审理,实行一审终审”,本案属于简单\n金钱给付案件,标的额为200元,法院可以适用小额诉讼\n程序审理,实行一审终审,C选项错误,D选项正确。因\n此,A、B、D选项正确。(法考2022)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 99, "subject": "相关法", "id": "xg_330"},
  {"question": "4. 民事诉讼第二审人民法院对上诉案件进行调解后达成协议，并依法制作了调解书。根据民事诉讼法及相关规定，对于原审人民法院的判决，下列哪种说法是正确的？(单选)", "options": ["A. 第二审人民法院应作出裁定，撤销原审人民法院的判决", "B. 第二审人民法院应在调解书中注明撤销原审人民法院的判决", "C. 原审人民法院应主动撤销原判决", "D. 调解书送达后，原审人民法院的判决即视为撤销"], "answer": "D", "explanation": "《民诉法》第179条规定：“第二审人民法院审理上诉案件，可以进行调解。调解达成协议，应当制作调解书……调解书送达后，原审人民法院的判决即视为撤销”，因此A、B、C选项错误，D选项正确。(2013)", "type": "single", "topic": "专题三 民事诉讼法", "page": 100, "subject": "相关法", "id": "xg_331"},
  {"question": "5. 关于民事诉讼二审程序的表述，下列哪一选项是错误的？(单选)", "options": ["A. 二审案件的审理，遇有二审程序没有规定的情形，应当适用一审普通程序的相关规定", "B. 二审案件的审理，以开庭审理为原则", "C. 二审案件调解的结果变更了一审判决内容的，应当在调解书中写明“撤销原判”", "D. 二审案件的审理，应当由法官组成的合议庭进行审理 - 99 -"], "answer": "C", "explanation": "A选项，一审普通程序是《民诉法》规定最为完善的程序，在二审、再审程序中，没有作出特别规定的，都应当适用一审普通程序的规定，因此A选项正确。B选项，《民诉法》第176条第1款规定：“第二审人民法院对上诉案件应当开庭审理。经过阅卷、调查和询问当事人，对没有提出新的事实、证据或者理由，人民法院认为不需要开庭审理的，可以不开庭审理”，因此B选项正确。C选项，《民诉法》第179条规定：“……调解书送达后，原审人民法院的判决即视为撤销”，即二审调解书有撤销一审判决的效力，但不是在调解书中写明撤销原判，因此C选项错误。D选项，《民诉法》第41条第1款规定：“人民法院审理第二审民事案件，由审判员组成合议庭。合议庭的成员人数，必须是单数”，因此D选项正确。(法考 2012)", "type": "single", "topic": "专题三 民事诉讼法", "page": 100, "subject": "相关法", "id": "xg_332"},
  {"question": "1. 根据民事诉讼法及相关规定，当事人的再审申请符合下列哪些情形的，人民法院应当再审？(多选)", "options": ["A. 有新的证据，足以推翻原判决的", "B. 原判决认定事实的主要证据未经质证的", "C. 据以作出原判决的法律文书被撤销的", "D. 原判决超出诉讼请求的"], "answer": "ABCD", "explanation": "《民诉法》第211条规定：“当事人的申请符合下列情形之一的，人民法院应当再审：(一)有新的证据，足以推翻原判决、裁定的；…… (四)原判决、裁定认定事实的主要证据未经质证的；…… (十一)原判决、裁定遗漏或者超出诉讼请求的；(十二)据以作出原判决、裁定的法律文书被撤销或者变更的；……”因此A、B、C、D选项", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 102, "subject": "相关法", "id": "xg_333"},
  {"question": "10. 经审理，一审法院判决被告王某支付原告刘某欠款本息共计22万元，王某不服提出上诉。二审中，双方达成和解协议，约定：王某分三个月向刘某偿付20万元，刘某放弃利息请求。案件经王某申请撤回上诉而终结。约定期限届满后，王某只支付了15万元。刘某应当如何救济？(单选)", "options": ["A. 向一审法院重新起诉", "B. 向一审法院申请执行判决", "C. 向一审法院申请执行和解协议", "D. 向二审法院提出上诉"], "answer": "B", "explanation": "双方当事人在二审中达成和解协议，当事人一方撤回上诉，则一审判决为生效判决。对方当事人王某不履行和解协议，刘某可以申请执行生效的一审判决，B选项正确。A选项，该纠纷已经一审法院审理并作出了生效判决，不得重新起诉，A选项错误。和解协议不具有执行力，C选项错误。D选项，撤回上诉并得到第二审法院的裁定准许即视为放弃了上诉的权利，故撤回上诉后，上诉人不能再次提起上诉，除非有极特殊情况（被迫撤诉、发现了新的证据或理由），D选项错误。因此，B选项正确。(法考2012, 思维扩展)", "type": "single", "topic": "专题三 民事诉讼法", "page": 102, "subject": "相关法", "id": "xg_334"},
  {"question": "11. 张某因为侵权纠纷起诉李某，要求被告李某赔偿损失2万元，并赔礼道歉，一审法院判决李某向张某赔偿1.2万元，对赔礼道歉的诉讼请求未作判决。张某不服一审判决，提起上诉，请求法院改判李某向张某赔偿损失2万元。二审法院维持1.2万的判项，同时判决李某向张某赔礼道歉。关于本案表述正确的是？(多选)", "options": ["A. 二审法院只能对上诉请求进行审理并作出判决", "B. 二审法院超出上诉请求作出判决的做法错误", "C. 二审法院应当对上诉请求作出判决，对一审遗漏的诉讼请求进行调解，调解不成撤销原判发回重审", "D. 因为一审法院遗漏诉讼请求，故二审法院应当直接撤销原判，发回重审 第十章 审判监督程序"], "answer": "ABC", "explanation": "《民诉法解释》第321条规定：“第二审人民法院应当围绕当事人的上诉请求进行审理。当事人没有提出请求的，不予审理，但一审判决违反法律禁止性规定，或者损害国家利益、社会公共利益、他人合法权益的除外。”因此，二审法院只能对上诉请求进行审理并作出判决，本题中二审法院超出上诉请求作出判决的做法错误。A、B选项正确。《民诉法解释》第324条规定：“对当事人在第一审程序中已经提出的诉讼请求，原审人民法院未作审理、判决的，第二审人民法院可以根据当事人自愿的原则进行调解；调解不成的，发回重审。”对于一审遗漏的赔礼道歉的诉讼请求，二审法院可以组织当事人调解，调解不成的，撤销原判，发回重审。故C选项正确，D选项错误。(法考2020)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 102, "subject": "相关法", "id": "xg_335"},
  {"question": "2. 甲公司诉乙公司侵害发明专利权纠纷一案,一审法院判决驳回甲公司的全部诉讼请求,甲公司不服提起上诉,二审法院改判乙公司停止被控侵权行为并赔偿甲公司经济损失及合理费用。根据民事诉讼法及相关规定,乙公司的申请符合以下哪些情形的,人民法院应当再审?(多选)", "options": ["A. 有新的证据", "B. 二审判决认定事实的主要证据未经质证的", "C. 二审判决适用法律确有错误的", "D. 二审判决遗漏或者超出诉讼请求的"], "answer": "BCD", "explanation": "有新证据不一定再审,需要新的证据达到足以推翻原判决、裁定的程度,法院才会再审,A选项不属于再审的情形。B、C、D选项为《民诉法》第211条规定的再审的情形,当选。(2018)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 103, "subject": "相关法", "id": "xg_336"},
  {"question": "4. 郑某与王某因专利权属纠纷诉至北京知识产权法院。北京知识产权法院作出的一审判决发生法律效力后,郑某认为一审判决适用法律错误,欲申请再审。根据民事诉讼法及相关规定,下列说法正确的是?(多选)", "options": ["A. 郑某可以向北京知识产权法院申请再审", "B. 郑某可以向北京知识产权法院的上一级法院申请再审", "C. 郑某申请再审的,应当在一审判决发生法律效力后六个月内提出", "D. 郑某申请再审的,人民法院应当裁定停止原判决的执行"], "answer": "ABC", "explanation": "A、B、D选项,《民诉法》第210条规定:“当事人对已经发生法律效力的判决、裁定,认为有错误的,可以向上一级人民法院申请再审,当事人一方人数众多或者当事人双方为公民的案件,也可以向原审人民法院申请再审。当事人申请再审的,不停止判决、裁定的执行”,原被告双方均为公民,可以向原审法院申请,也可以向上一级法院申请,因此A、B选项正确,D选项错误。C选项,《民诉法》第216条规定:“当事人申请再审,应当在判决、裁定发生法律效力后6个月内提出”,因此C选项正确。(2019)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 103, "subject": "相关法", "id": "xg_337"},
  {"question": "1. 根据民事诉讼法及相关规定，下列关于发生法律效力的民事判决执行的说法哪些是正确的？（多选）", "options": ["A. 发生法律效力的民事判决，应当由被执行的财产所在地基层人民法院执行", "B. 当事人认为执行行为违反法律规定的，可以向负责执行的人民法院提出书面异议", "C. 在执行中，双方当事人自行达成的和解协议无效", "D. 在执行中，被执行人向人民法院提供担保，并经申请执行人同意的，人民法院可以决定暂缓执行及暂缓执行的期限"], "answer": "BD", "explanation": "A选项，《民诉法》第235条第1款规定：“发生法律效力的民事判决、裁定，以及刑事判决、裁定中的财产部分，由第一审人民法院或者与第一审人民法院同级的被执行的财产所在地人民法院执行”，因此A选项错误。B选项，《民诉法》第236条规定：“当事人、利害关系人认为执行行为违反法律规定的，可以向负责执行的人民法院提出书面异议……”，因此B选项正确。C选项，《民诉法》第241条第1款规定：“在执行中，双方当事人自行和解达成协议的，执行员应当将协议内容记入笔录，由双方当事人", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 105, "subject": "相关法", "id": "xg_338"},
  {"question": "9. 周某因合同纠纷起诉，江苏省徐州市的县市两级法院均驳回其诉讼请求。周某申请再审，但被驳回。周某又向检察院申请抗诉，检察院以原审主要证据系伪造为由提出抗诉，法院裁定再审。关于启动再审的表述，下列哪些说法是正确的？（多选）", "options": ["A. 周某可以向江苏省高院申请再审", "B. 检察院抗诉后，应当由接受抗诉的法院审查后，作出是否再审的裁定", "C. 法院应当在裁定再审的同时，裁定撤销原判", "D. 法院应当在裁定再审的同时，裁定中止执行 第十一章 执行程序"], "answer": "AD", "explanation": "《民诉法》第210条规定：“当事人对已经发生法律效力的判决、裁定，认为有错误的，可以向上一级人民法院申请再审；当事人一方人数众多或者当事人双方为公民的案件，也可以向原审人民法院申请再审”，本案中，江苏省高院是作出生效判决的徐州中院的上一级法院，故当事人可以向上一级人民法院申请再审，A选项正确。《民诉法》第222条规定：“人民检察院提出抗诉的案件，接受抗诉的人民法院应当自收到抗诉书之日起三十日内作出再审的裁定”，B选项错误。《民诉法》第217条规定：“按照审判监督程序决定再审的案件，裁定中止原判决、裁定、调解书的执行”，裁定再审的同时并不撤销原判，在再审的审理阶段经过审理，原判确有错误才可以裁定撤销原判，C选项错误，D选项正确。因此，A、D选项正确。（法考2013，思维扩展）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 105, "subject": "相关法", "id": "xg_339"},
  {"question": "1. 外国人黄某在中国没有住所, 但在海口有一处房产, 其加入外国国籍前住在南宁。中国公民温某与黄某在长沙签订货物买卖合同, 约定交货地点为深圳。后黄某因货源紧张, 未按照合同约定交货。如果温某向", "options": ["A. 海口", "B. 南宁", "C. 长沙", "D. 深圳"], "answer": "ABC", "explanation": "《民诉法》第276条规定: “因涉外民事纠纷, 对在中华人民共和国领域内没有住所的被告提起除身份关系以外的诉讼, 如果合同签订地、合同履行地、诉讼标的物所在地、可供扣押财产所在地、侵权行", "type": "single", "topic": "专题三 民事诉讼法", "page": 107, "subject": "相关法", "id": "xg_340"},
  {"question": "6. 根据民事诉讼法及相关规定, 在执行过程中出现下列哪些情形的, 人民法院裁定终结执行?(多选)", "options": ["A. 作为被执行人的公民因生活困难无力偿还借款, 无收入来源, 又丧失劳动能力的", "B. 追索抚育费案件的权利人死亡的", "C. 申请人撤销执行申请的", "D. 据以执行的法律文书被撤销的"], "answer": "ABCD", "explanation": "《民诉法》第268条规定: “有下列情形之一的, 人民法院裁定终结执行:(一)申请人撤销申请的;(二)据以执行的法律文书被撤销的;……(四)追索赡养费、扶养费、抚育费案件的权利人死亡的;(五)作为被执行人的公民因生活困难无力偿还借款, 无收入来源, 又丧失劳动能力的……”, 因此A、B、C、D选项均正确。(2010)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 107, "subject": "相关法", "id": "xg_341"},
  {"question": "7. 在民事执行中, 被执行人朱某申请暂缓执行, 提出由吴某以自有房屋为其提供担保, 申请执行人刘某同意。法院作出暂缓执行裁定, 期限为6个月。对于暂缓执行期限届满后朱某仍不履行义务的情形, 下列哪一选项是正确的?(单选)", "options": ["A. 刘某应起诉吴某, 取得执行依据可申请执行吴某的担保房产", "B. 朱某财产不能清偿全部债务时刘某方能起诉吴某, 取得执行依据可申请执行吴某的担保房产", "C. 朱某财产不能清偿刘某债权时法院方能执行吴某的担保房产", "D. 刘某可申请法院执行吴某的担保房产 第十二章  涉外民事诉讼程序"], "answer": "D", "explanation": "《民诉法》第242条规定: “在执行中, 被执行人向人民法院提供担保, 并经申请执行人同意的, 人民法院可以决定暂缓执行及暂缓执行的期限。被执行人逾期仍不履行的, 人民法院有权执行被执行人的担保财产或者担保人的财产”。本题中, 在执行担保人的财产时无需另行起诉, 执行人的财产是否能清偿债权人的财产并不是执行担保人财产的前提, 只要暂缓执行期间届满没有履行, 即可以恢复执行, 因此D选项正确。\n(法考2009改编, 思维扩展)", "type": "single", "topic": "专题三 民事诉讼法", "page": 107, "subject": "相关法", "id": "xg_342"},
  {"question": "3. 根据民事诉讼法及相关规定,下列关于具有专门知识的人出庭的哪些说法是正确的?(多选) - 84 -", "options": ["A. 人民法院可以对出庭的具有专门知识的人进行询问", "B. 经法庭准许，当事人可以对出庭的具有专门知识的人进行询问", "C. 经法庭准许，当事人各自申请的具有专门知识的人可以就案件中的有关问题进行质询", "D. 具有专门知识的人可以参与专业问题之外的法庭审理活动"], "answer": "ABC", "explanation": "人民法院、经法庭准许的当事人以及当事人各自申请的具有专门知识的人均可以对出庭的具有专门知识的人进行询问或质询。但专门知识的人不能参与专业问题之外的法庭审理活动。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 85, "subject": "相关法", "id": "xg_343"},
  {"question": "某区法院审理原告许某与被告某饭店食物中毒纠纷一案。审前，法院书面告知许某与被告某饭店食物中毒纠纷一案。开庭后，许某首次向法院提出回避申请。关于本案，下列哪一说法是正确的？", "options": ["A. 许某可在知道被告法定代表人是亲兄弟时提出回避申请", "B. 法院对回避申请作出决定前，两不停止参与本案审理", "C. 应由审判长决定是否回避", "D. 法院作出回避决定后，许某可对此提出上诉"], "answer": "B", "explanation": "根据民事诉讼法的规定，当事人在诉讼过程中有权申请回避，但法院对回避申请作出决定前，诉讼不停止进行。审判长的决定是关于是否回避的，而不是由当事人提出上诉。", "type": "single", "topic": "专题三 民事诉讼法", "page": 89, "subject": "相关法", "id": "xg_344"},
  {"question": "6. 《民诉法》第29条规定：“因侵权行为提起的诉讼，由侵权行为所适用的法律管辖。”因此A选项正确。", "options": ["A. 选项", "B. 选项", "C. 选项", "D. 选项"], "answer": "A", "explanation": "《民诉法》第29条规定了因侵权行为提起的诉讼的管辖原则。", "type": "single", "topic": "专题三 民事诉讼法", "page": 92, "subject": "相关法", "id": "xg_345"},
  {"question": "7. 《民诉法》第29条规定：“因侵权行为提起的诉讼，由侵权行为所适用的法律管辖。”因此D选项正确。", "options": ["A. 选项", "B. 选项", "C. 选项", "D. 选项"], "answer": "D", "explanation": "《民诉法》第29条规定了因侵权行为提起的诉讼的管辖原则。", "type": "single", "topic": "专题三 民事诉讼法", "page": 92, "subject": "相关法", "id": "xg_346"},
  {"question": "8. 《民诉法》第28条规定：“不动产纠纷是指不动产权利人请求返还财产、赔偿损失的纠纷。”因此A选项正确。", "options": ["A. 选项", "B. 选项", "C. 选项", "D. 选项"], "answer": "A", "explanation": "《民诉法》第28条规定了不动产纠纷的定义。", "type": "single", "topic": "专题三 民事诉讼法", "page": 92, "subject": "相关法", "id": "xg_347"},
  {"question": "9. 《民诉法》第28条规定：“不动产纠纷是指不动产权利人请求返还财产、赔偿损失的纠纷。”因此B选项正确。", "options": ["A. 选项", "B. 选项", "C. 选项", "D. 选项"], "answer": "B", "explanation": "《民诉法》第28条规定了不动产纠纷的定义。", "type": "single", "topic": "专题三 民事诉讼法", "page": 92, "subject": "相关法", "id": "xg_348"},
  {"question": "李某在北京市海淀区新购一套住房，并请北京市大兴区的装修公司对其新房进行装修。在装修过程中，装修工人不慎将水管弄破，导致楼下住户的家具被淹毁。李某与该装修公司就赔偿问题交涉未果，遂向北京市大兴区法院起诉装修公司侵权。大兴区法院认为该案应由海淀区法院审理，于是裁定将该案移送至海淀区法院，海淀区法院认为该案应由大兴区法院审理，不接受移送，又将案件退回大兴区法院。关于本案的管辖，下列哪些选项是正确的？（多选）", "options": ["A. 北京市海淀、大兴区法院对该案都有管辖权", "B. 李某有权向北京市大兴区法院起诉"], "answer": "AB", "explanation": "A、B选项，《民诉法》第29条规定：‘因侵权行为提起的诉讼，由侵权行为地或者被告住所地人民法院管辖’；《民诉法》第36条规定：‘两个以上人民法院都有管辖权的诉讼，原告可以向其中一个人民法院起诉……’；本题中，海淀区是侵权行为地，大兴区是被告住所地，两地法院都有管辖权，李某可以选择向其中一个法院起诉，因此A、B选项正确。C选项，《民诉法解释》第36条规定：‘两个以上人民法院都有管辖权的诉讼，先立案的人民法院不得将案件移送另一个有管辖权的人民法院……’，因此大兴区法院立案后不能将案件移送海淀区法院，C选项正确。D选项，《民事诉讼法》第37条规定：‘人民法院受理案件后，当事人对管辖权有异议的，应当在提交答辩状期间提出。人民法院对当事人提出的异议，应当审查。异议成立的，裁定移送有管辖权的人民法院；异议不成立的，裁定驳回。’因此D选项正确。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 94, "subject": "相关法", "id": "xg_349"},
  {"question": "根据民事诉讼法的规定，下列哪些说法是正确的？（多选）", "options": ["A. 人民法院审理第一审民事案件，可以由审判员和人民陪审员组成合议庭审理", "B. 人民法院审理第二审民事案件，只能由审判员组成合议庭", "C. 发回重审的案件，原审人民法院应当按照第一审程序另行组成合议庭", "D. 人民法院审理再审案件，只能由审判员另行组成合议庭"], "answer": "ABC", "explanation": "A选项，《民诉法》第40条第1款规定：‘人民法院审理第一审民事案件，由审判员、人民陪审员共同组成合议庭或者由审判员组成合议庭……’，因此A选项正确。B选项，《民诉法》第41条第1款规定：‘人民法院审理第二审民事案件，由审判员组成合议庭……’，因此B选项正确。C选项，《民诉法》第41条第4款规定：‘发回重审的案件，原审人民法院应当按照第一审程序另行组成合议庭’，因此C选项正确。D选项，《民诉法》第41条第4款规定：‘审理再审案件，原来是第一审的，按照第一审程序另行组成合议庭；原来是第二审的或者是上级人民法院提审的，按照第二审程序另行组成合议庭’，因此如果按一审程序再审的案件，人民陪审员可以参加庭审，D选项错误。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 87, "subject": "相关法", "id": "xg_350"},
  {"question": "根据民事诉讼法及相关规定，下列哪类民事案件应当由合议庭审理？（单选）", "options": ["A. 适用简易程序审理的第一审民事案件", "B. 基层人民法院审理的基本事实清楚，权利义务关系明确的第一审民事案件", "C. 适用普通程序审理的第一审民事案件", "D. 中级人民法院审理的第一审民事案件"], "answer": "C", "explanation": "A选项，《民诉法》第40条第2款规定：‘适用简易程序审理的民事案件，由审判员一人独任审理。基层人民法院审理的基本事实清楚、权利义务关系明确的第一审民事案件，可以由审判员一人适用普通程序独任审理’，因此A选项错误。B选项，《民诉法》第40条第2款规定：‘适用简易程序审理的民事案件，由审判员一人独任审理。基层人民法院审理的基本事实清楚、权利义务关系明确的第一审民事案件，可以由审判员一人适用普通程序独任审理’，因此B选项错误。C选项，《民诉法》第41条第3款规定：‘发回重审的案件，原审人民法院应当按照第一审程序另行组成合议庭’，因此C选项正确。D选项，《民诉法》第41条第2款规定：‘中级人民法院对第一审适用简易程序审理或者不服裁定提起上诉的第二审民事案件，可以由审判员一人独任审理’，因此D选项错误。", "type": "single", "topic": "专题三 民事诉讼法", "page": 87, "subject": "相关法", "id": "xg_351"},
  {"question": "下列主体中，不可以作为民事诉讼委托代理人的是？（单选）", "options": ["A. 原告的岳父", "B. 公司的实习生", "C. 专利纠纷诉讼中，由中华全国代理师协会推荐的专利代理师", "D. 离婚诉讼中，某基层法律服务所的工作人员"], "answer": "B", "explanation": "根据《民诉法》第61条第2款规定，原告的岳父属于当事人的近亲属，可以成为委托代理人。专利代理师在专利纠纷案件中可以担任代理人，基层法律服务所的工作人员也可以成为委托代理人。公司的实习生不属于法定的委托代理人范围。", "type": "single", "topic": "专题三 民事诉讼法", "page": 98, "subject": "相关法", "id": "xg_352"},
  {"question": "根据民事诉讼法及相关规定，下列关于诉讼代理人的哪些说法是正确的？（多选）", "options": ["A. 律师可以被委托为诉讼代理人", "B. 当事人的工作人员可以被委托为诉讼代理人", "C. 有关社会团体推荐的公民可以被委托为诉讼代理人", "D. 专利代理师经中华全国专利代理师协会推荐，可以在专利纠纷案件中担任诉讼代理人"], "answer": "ABCD", "explanation": "A、B、C选项，《民诉法》第61条第2款规定：‘下列人员可以被委托为诉讼代理人：（一）律师、基层法律服务工作者；（二）当事人的近亲属或者工作人员；（三）当事人所在社区、单位以及有关社会团体推荐的公民’，因此A、B、C选项正确。D选项，《民诉法解释》第87条第2款规定：‘专利代理人经中华全国专利代理人协会推荐，可以在专利纠纷案件中担任诉讼代理人’，因此D选项正确。（2017改编）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 97, "subject": "相关法", "id": "xg_353"},
  {"question": "根据民事诉讼法及相关规定，下列哪些属于有关社会团体推荐公民担任诉讼代理人应当符合的条件？（多选）", "options": ["A. 社会团体属于依法登记设立或者依法免予登记设立的非营利性法人组织", "B. 被代理人属于该社会团体的成员，或者当事人一方住所地位于该社会团体的活动地域", "C. 代理事务属于该社会团体章程载明的业务范围", "D. 被推荐的公民是该社会团体的负责人或者与该社会团体有合法劳动人事关系的工作人员"], "answer": "ABCD", "explanation": "《民诉法解释》第87条第1款规定：‘根据民事诉讼法第61条第2款第（三）项规定，有关社会团体推荐公民担任诉讼代理人的，应当符合下列条件：（一）社会团体属于依法登记设立或者依法免予登记设立的非营利性法人组织；（二）被代理人属于该社会团体的成员，或者当事人一方住所地位于该社会团体的活动地域；（三）代理事务属于该社会团体章程载明的业务范围；（四）被推荐的公民是该社会团体的负责人或者与该社会团体有合法劳动人事关系的工作人员’，因此A、B、C、D选项均正确。（2016）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 97, "subject": "相关法", "id": "xg_354"},
  {"question": "将案件移送天津市和平区法院。关于本案的管辖，下列哪些说法是正确的？（多选）", "options": ["A. 天津市河东区法院有管辖权", "B. 天津市西青区法院有管辖权", "C. 天津市和平区法院有管辖权", "D. 天津市河东区法院移送管辖不符合法律规定"], "answer": "BC", "explanation": "根据《民事诉讼法》第24条规定：‘因合同纠纷提起的诉讼，由被告住所地或者合同履行地人民法院管辖’，《民诉法解释》第20条规定：‘以信息网络方式订立的买卖合同，通过信息网络交付标的的，以买受人住所地为合同履行地；通过其他方式交付标的的，收货地为合同履行地。合同对履行地有约定的，从其约定’，A选项为原告所在地法院，无管辖权，B选项为被告所在地、C选项为合同履行地，均有管辖权，因此A选项错误，B、C选项正确。D选项，《民诉法》第37条规定：‘人民法院发现受理的案件不属于本院管辖的，应当移送有管辖权的人民法院……’，天津市河东区法院移送符合规定，因此D选项错误。（新编）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 93, "subject": "相关法", "id": "xg_355"},
  {"question": "根据民事诉讼法及相关规定，原告向两个有管辖权的人民法院起诉的，由哪个人民法院管辖？（单选）", "options": ["A. 最先收到起诉状的人民法院", "B. 最先收到案件受理费的人民法院", "C. 最先立案的人民法院", "D. 该两个人民法院共同上级人民法院指定的人民法院"], "answer": "C", "explanation": "《民诉法》第36条规定：‘两个以上人民法院都有管辖权的诉讼，原告可以向其中一个人民法院起诉；原告向两个以上有管辖权的人民法院起诉的，由最先立案的人民法院管辖’，因此A、B、D选项错误，C选项正确。（2015）", "type": "single", "topic": "专题三 民事诉讼法", "page": 93, "subject": "相关法", "id": "xg_356"},
  {"question": "根据民事诉讼法及相关规定，对于两个以上人民法院都有管辖权的民事诉讼案件，下列说法正确的是？（多选）", "options": ["A. 原告可以向其中一个人民法院起诉", "B. 原告向两个以上有管辖权的人民法院起诉的，由最先立案的人民法院管辖", "C. 先立案的人民法院不得将案件移送", "D. 人民法院发现受理的案件不属于本院管辖的，应当移送有管辖权的人民法院"], "answer": "BCD", "explanation": "《民诉法》第36条规定：‘两个以上人民法院都有管辖权的诉讼，原告可以向其中一个人民法院起诉；原告向两个以上有管辖权的人民法院起诉的，由最先立案的人民法院管辖’，先立案的人民法院不得将案件移送，因此A、B、C、D选项中，A选项错误，B、C、D选项正确。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 93, "subject": "相关法", "id": "xg_357"},
  {"question": "前预装大量程序，并且未告知消费者卸载方式。该消费者权益保护协会以上述行为侵害众多消费者合法权益、损害社会公共利益为由提起公益诉讼。根据民事诉讼法及相关规定，下列哪种说法是正确的？（单选）", "options": ["A. 本案可以由侵权行为地或者被告住所地中级人民法院管辖", "B. 作为公益诉讼案件原告的该消费者权益保护协会一律不得申请撤诉", "C. 人民法院不得对该公益诉讼案件进行调解", "D. 该公益诉讼案件的当事人不能和解"], "answer": "A", "explanation": "正确。B选项，《民诉法解释》第288条规定：‘公益诉讼案件的原告在法庭辩论终结后申请撤诉的，人民法院不予准许’，因此公益诉讼案件的原告可以在法庭辩论终结前撤诉，B选项错误。C、D选项，《民诉法解释》第287条第1款规定：‘对公益诉讼案件，当事人可以和解，人民法院可以调解’，因此C、D选项错误。（2017）", "type": "single", "topic": "专题三 民事诉讼法", "page": 96, "subject": "相关法", "id": "xg_358"},
  {"question": "专利权人甲与乙公司签订了专利独占实施许可合同，又将专利转让给了丙公司，乙公司因与丙公司就实施许可发生纠纷向人民法院提起诉讼，甲作为第三人在该案中享有哪些权利？", "options": ["A. 申请撤诉", "B. 提出回避申请", "C. 变更诉讼请求", "D. 对案件的管辖权提出异议"], "answer": "BC", "explanation": "《民诉法》第59条第2款规定：‘对当事人双方的诉讼标的，第三人虽然没有独立请求权，但案件处理结果同他有法律上的利害关系的，可以申请参加诉讼，或者由人民法院通知他参加诉讼。人民法院判决承担民事责任的第三人，有当事人的诉讼权利义务’，《民诉法解释》第82条规定：‘在一审诉讼中，无独立请求权的第三人无权提出管辖异议，无权放弃、变更诉讼请求或者申请撤诉，被判决承担民事责任的，有权提起上诉’。本题中，争议双方主体是乙公司与丙公司，甲作为原专利权人，其权利义务可能受到判决影响，属于无独立请求权的第三人，因此可提出回避申请，若被判决承担责任，则享有当事人的诉讼权利义务，包括变更诉讼请求等。故答案为BC。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 96, "subject": "相关法", "id": "xg_359"},
  {"question": "根据民事诉讼法及相关规定，关于诉讼代理人，下列说法哪个是正确的？（单选）", "options": ["A. 律师之外的其他诉讼代理人有权调查收集证据，查阅本案有关材料", "B. 诉讼代理人的权限变更的，可以由诉讼代理人书面告知人民法院", "C. 当事人委托诉讼代理人全权代理的，诉讼代理人可以代为变更诉讼请求", "D. 离婚案件有诉讼代理人的，本人仍应出庭"], "answer": "A", "explanation": "A选项，《民事诉讼法》第64条规定：‘代理诉讼的律师和其他诉讼代理人有权调查收集证据，可以查阅本案有关材料……’，因此A选项正确。B选项，《民事诉讼法》第63条规定：‘诉讼代理人的权限如果变更或者解除，当事人应当书面告知人民法院，并由人民法院通知对方当事人’，因此B选项错误。C选项，全权委托代理视为无特别授权，代为变更诉讼请求也应当有特别授权，因此C选项错误。D选项，《民事诉讼法》第65条规定：‘离婚案件有诉讼代理人的，本人除不能表达意思的以外，仍应出庭；确因特殊情况无法出庭的，必须向人民法院提交书面意见’，D选项的表述过于绝对，因此D选项错误。（新编）", "type": "single", "topic": "专题三 民事诉讼法", "page": 99, "subject": "相关法", "id": "xg_360"},
  {"question": "在中国人张某与外国人珍妮的离婚诉讼中，张某委托李律师作为代理人，授权委托书中仅写明代理范围“全权代理”，以下哪些说法是正确的？（多选）", "options": ["A. 如果珍妮要委托代理人代为诉讼，必须委托中国公民", "B. 法院可以向李律师送达诉讼文书，其签收行为"], "answer": "B", "explanation": "A选项，《民诉法》第274条规定：‘外国人、无国籍人、外国企业和组织在人民法院起诉、应诉，需要委托律师代理诉讼的，必须委托中国律师’，因此A选项错误。B选项，根据《民事诉讼法》相关规定，诉讼代理人可以代为接收诉讼文书，因此法院可以向李律师送达诉讼文书，其签收行为有效，B选项正确。C选项，虽然授权委托书中写明“全权代理”，但未明确特别授权，因此不能代为承认、放弃、变更诉讼请求等，C选项正确。（新编）", "type": "single", "topic": "专题三 民事诉讼法", "page": 99, "subject": "相关法", "id": "xg_361"},
  {"question": "根据民事诉讼法及相关规定，下列哪些情况下当事人可以在诉讼过程中向人民法院申请保全证据？(多选)", "options": ["A. 证据涉及个人隐私", "B. 证据涉及商业秘密", "C. 证据可能灭失", "D. 证据以后难以取得"], "answer": "CD", "explanation": "《民事诉讼法》第84条第1款规定：‘在证据可能灭失或者以后难以取得的情况下，当事人可以在诉讼过程中向人民法院申请保全证据，人民法院也可以主动采取保全措施’因此A选项正确，B选项错误。C选项，《民事诉讼法解释》第98条第1款规定：‘当事人根据民事诉讼法第84条第1款规定申请证据保全的，可以在举证期限届满前书面提出’，因此C选项正确。D选项，《民事诉讼法解释》第98条第2款规定：‘证据保全可能对他人造成损失的，人民法院应当责令申请人提供相应的担保’，因此D选项正确。（2017）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 103, "subject": "相关法", "id": "xg_362"},
  {"question": "甲路过乙家门口，被乙放在门口的砖头砸伤，甲起诉要求乙赔偿。关于本案的证明责任分配，下列哪项说法是错误的？(单选)", "options": ["A. 乙有主观过错的事实，由甲承担证明责任", "B. 甲遭受损害的事实，由原告甲承担证明责任", "C. 乙撞砖头倒塌的事实，由甲承担证明责任", "D. 甲所遭受损害是由于乙撞砖头倒塌砸伤的事实，由甲承担证明责任"], "answer": "A", "explanation": "在侵权责任案件中，被告的主观过错通常由被告自己证明，除非法律另有规定。因此，乙是否有主观过错的事实，应由乙自己承担证明责任，A错误。", "type": "single", "topic": "专题三 民事诉讼法", "page": 104, "subject": "相关法", "id": "xg_363"},
  {"question": "刘月购买甲公司的化肥，使用后农作物生长异常，甲向法院起诉要求乙赔偿。关于本案的证明责任分配，下列哪项规定是正确的？(单选)", "options": ["A. 《民法典》第1235条规定：“推放物倒塌、倾覆或者滑落造成他人损害，推放人不能证明自己没有过错的，应当承担侵权责任。”，因此乙有主观过错的事实应当由乙承担证明责任，A选项正确。", "B. 《民法典》第1235条规定：“人民法院应当根据下列原则确定证明责任的承担，但法律另有规定的除外。”，因此根据法律规定，B选项正确。", "C. 《民法典》第1235条规定：“人民法院应当根据下列原则确定证明责任的承担，但法律另有规定的除外。”，因此根据法律规定，C选项正确。", "D. 《民法典》第1235条规定：“人民法院应当根据下列原则确定证明责任的承担，但法律另有规定的除外。”，因此根据法律规定，D选项正确。"], "answer": "A", "explanation": "根据《民法典》第1235条的规定，推放物倒塌造成他人损害的情况下，推放人不能证明自己没有过错的，应当承担侵权责任。因此，乙作为推放人，如果不能证明自己没有过错，则应承担侵权责任，A选项正确。", "type": "single", "topic": "专题三 民事诉讼法", "page": 104, "subject": "相关法", "id": "xg_364"},
  {"question": "根据民事诉讼法及相关规定，下列哪些情形当事人及其诉讼代理人可以申请人民法院调查取证？（多选）", "options": ["A. 当事人及其诉讼代理人因客观原因不能自行收集的证据", "B. 涉及国家秘密、商业秘密或者个人隐私的证据", "C. 证据由国家有关部门保存，当事人及其诉讼代理人无权查阅调取的", "D. 人民法院认为审理案件需要的证据"], "answer": "ABC", "explanation": "A、B、C选项，《民诉法》第67条第2款规定：‘当事人及其诉讼代理人因客观原因不能自行收集的证据，或者人民法院认为审理案件需要的证据，人民法院应当调查收集’，《民诉法解释》第94条第1款规定：‘民事诉讼法第67条第2款规定的当事人及其诉讼代理人因客观原因不能自行收集的证据包括：（一）证据由国家有关部门保存，当事人及其诉讼代理人无权查阅调取的；（二）涉及国家秘密、商业秘密或者个人隐私的；（三）当事人及其诉讼代理人因客观原因不能自行收集的其他证据’，因此A、B、C选项正确。D选项，《民诉法解释》第96条第1款规定：‘民事诉讼法第67条第2款规定的人民法院认为审理案件需要的证据包括：（一）涉及可能损害国家利益、社会公共利益的……’，因此D选项属于法院主动收集证据的情形，D选项错误。（2019）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 102, "subject": "相关法", "id": "xg_365"},
  {"question": "根据民事诉讼法及相关规定，下列关于民事诉讼调解的哪种说法是正确的？（单选）", "options": ["A. 能够即时履行的案件调解达成协议，人民法院可以不制作调解书", "B. 调解维持收养关系的案件调解达成协议，人民法院应当制作调解书", "C. 当事人对已经发生法律效力的解除婚姻关系的调解书，可以申请再审", "D. 调解书送达前一方反悔的，人民法院可以留置送达该调解书"], "answer": "A", "explanation": "A选项，《民诉法》第101条第1款规定：‘下列案件调解达成协议，人民法院可以不制作调解书：……（二）调解维持收养关系的案件；（三）能够即时履行的案件……’，因此A选项正确，B选项错误。C选项，《民诉法》第213条规定：‘当事人对已经发生法律效力的解除婚姻关系的判决、调解书，不得申请再审’，因此C选项错误。D选项，《民诉法》第102条规定：‘调解未达成协议或者调解书送达前一方反悔的，人民法院应当及时判决’，因此D选项错误。(2017)", "type": "single", "topic": "专题三 民事诉讼法", "page": 106, "subject": "相关法", "id": "xg_366"},
  {"question": "利害关系人因情况紧急，不立即申请保全将会使其合法权益受到难以弥补的损害的，可以在提起诉讼前向被保全财产所在地或被申请人住所地人民法院申请采取保全措施", "options": ["A. 利害关系人因情况紧急，不立即申请保全将会使其合法权益受到难以弥补的损害的，可以在提起诉讼前向被保全财产所在地或被申请人住所地人民法院申请采取保全措施", "B. 人民法院在民事诉讼中对于可能因一方当事人的原因使判决难以执行的案件，可以根据对方当事人的申请，作出财产保全的裁定", "C. 申请保全有错误的，申请人应当赔偿被申请人因保全所遭受的损失", "D. 申请人在人民法院采取诉前财产保全措施后10日内不起诉的，人民法院应当解除财产保全"], "answer": "B", "explanation": "根据《民诉法》第103条第1款规定：‘人民法院对于可能因当事人一方的行为或者其他原因，使判决难以执行或者造成当事人其他损害的案件，根据对方当事人的申请，可以裁定对其财产进行保全、责令其作出一定行为或者禁止其作出一定行为；当事人没有提出申请的，人民法院在必要时也可以裁定采取保全措施’，因此B选项正确。C选项，《民诉法》第108条规定：‘申请有错误的，申请人应当赔偿被申请人因保全所遭受的损失’，因此C选项正确。D选项，《民诉法》第104条第3款规定：‘申请人在人民法院采取保全措施后30日内不依法提起诉讼或者申请仲裁的，人民法院应当解除保全’，因此D选项错误。（2017改编）", "type": "single", "topic": "专题三 民事诉讼法", "page": 108, "subject": "相关法", "id": "xg_367"},
  {"question": "D. A项，《民诉法》第140条规定：“开庭审理时，由审判长或者审判员主持开庭审理，当庭宣判。”B项，法院依职权收集的证据应当在庭审中出示，听取当事人的意见，C选项错误。B项，法院依职权收集的证据应当在庭审中出示，听取当事人的意见，D选项错误。", "options": ["A. 选项A", "B. 选项B", "C. 选项C", "D. 选项D"], "answer": "D", "explanation": "B项描述错误，法院依职权收集的证据应当在庭审中出示，听取当事人的意见。", "type": "single", "topic": "专题三 民事诉讼法", "page": 113, "subject": "相关法", "id": "xg_368"},
  {"question": "长江公司向甲市A区法院起诉乙公司，区法院判决驳回甲公司的诉讼请求，长江公司不服一审判决，通过甲市A区法院提交上诉状，A区法院发现长江公司的上诉已经超过上诉期，应当如何处理？", "options": ["A. 不予接受上诉材料", "B. 提请上级法院裁定驳回上诉", "C. 裁定驳回上诉", "D. 将上诉状和上诉材料一并移交上级法院"], "answer": "C", "explanation": "根据民事诉讼法的相关规定，如果上诉超过上诉期，法院应当裁定驳回上诉。", "type": "single", "topic": "专题三 民事诉讼法", "page": 119, "subject": "相关法", "id": "xg_369"},
  {"question": "根据民事诉讼法及相关规定，当事人对人民法院在民事诉讼第一审程序中作出的下列哪些裁定不服的，可以提起上诉？（多选）", "options": ["A. 不予受理的裁定", "B. 不准许撤诉的裁定", "C. 中止诉讼的裁定", "D. 驳回起诉的裁定"], "answer": "AD", "explanation": "《民诉法》第157条规定：‘裁定适用于下列范围：（一）不予受理；（二）对管辖权有异议的；（三）驳回起诉……对前款第一项至第三项裁定，可以上诉’，因此A、D选项正确。（2019）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 112, "subject": "相关法", "id": "xg_370"},
  {"question": "外国人汤姆通过网络平台以人民币500元购买了中国人杨某销售的衬衫，后双方因为衬衫质量问题发生纠纷，汤姆向互联网法院起诉杨某要求赔偿，互联网法院依法受理此案。关于本案的审理，下列表述正确的是？（多选）", "options": ["A. 本案可以适用小额诉讼的程序审理", "B. 本案法院可以决定线下审理"], "answer": "B", "explanation": "A选项，《民事诉讼法》第166条规定：‘涉外案件不适用小额诉讼程序’，A选项错误。B选项，《互联网法院规定》第12条规定：‘互联网法院采取在线视频方式开庭。存在确需当庭查明身份、核对原件、查验实物等特殊情形的，互联网法院可以决定在线下开庭，但其他诉讼环节仍应当在线完成’，选项B正确。C选项，《互联网法院规定》第17条规定：‘经告知当事人权利义务，并征得其同意，互联网法院可以电子送达裁判文书’，C选项正确。D选项，互联网法院属于基层法院，不存在禁止适用独任制的情形，D选项正确。因此，B、C、D选项正确。", "type": "single", "topic": "专题三 民事诉讼法", "page": 115, "subject": "相关法", "id": "xg_371"},
  {"question": "根据民事诉讼法及相关规定，下列哪些情形下中止诉讼？（多选）", "options": ["A. 一方当事人丧失诉讼行为能力，尚未确定法定代理人的", "B. 本案必须以另一案的审理结果为依据，而另一案尚未审结的", "C. 一方当事人因不可抗拒的事由，不能参加诉讼的", "D. 解除收养关系案件的一方当事人死亡的"], "answer": "ABC", "explanation": "《民诉法》第153条规定：‘有下列情形之一的，中止诉讼：……（二）一方当事人丧失诉讼行为能力，尚未确定法定代理人的；……（四）一方当事人因不可抗拒的事由，不能参加诉讼的；（五）本案必须以另一案的审理结果为依据，而另一案尚未审结的……’，因此A、B、C选项正确，D选项属于终结诉讼的情形。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 111, "subject": "相关法", "id": "xg_372"},
  {"question": "某债务纠纷案件由甲县人民法院一审、乙市中级人民法院二审终结，二审判决已发生法律效力。现乙市人民检察院发现该判决确有错误，拟启动审判监督程序。根据民事诉讼法相关规定，下列说法哪项是正确的？", "options": ["A. 乙市人民检察院应当向甲县人民法院提出抗诉", "B. 乙市人民检察院应当向乙市中级人民法院提出抗诉", "C. 乙市人民检察院应当向上级人民检察院向乙市中级人民法院提出抗诉", "D. 乙市人民检察院应当向上级人民检察院向甲市中级人民法院提出抗诉"], "answer": "C", "explanation": "根据民事诉讼法相关规定，人民检察院发现已经发生法律效力的判决、裁定确有错误时，应当按照审判监督程序提出抗诉。抗诉应当向原审人民法院的上一级人民检察院提出，由上一级人民检察院向同级人民法院提出抗诉。", "type": "single", "topic": "专题三 民事诉讼法", "page": 122, "subject": "相关法", "id": "xg_373"},
  {"question": "甲公司诉乙公司合同纠纷案，广州市花都区人民法院进行了审理并作出驳回甲公司诉讼请求的判决，甲公司未提出上诉。判决生效后，甲公司因收集到的证据申请再审。下列哪些选项是正确的？", "options": ["A. 甲公司应当向花都区法院申请再审", "B. 甲公司应当向广州市中级人民法院申请再审", "C. 法院应当适用一审程序再审本案", "D. 法院应当适用二审程序再审本案"], "answer": "BD", "explanation": "根据《民诉法》第210条规定，当事人对已经发生法律效力的判决、裁定，认为有错误的，可以向上一级人民法院申请再审。本案中，甲公司应当向广州市中级人民法院申请再审，因此B选项正确。由于是申请再审，法院应当适用再审程序，而不是一审或二审程序，因此C和D选项均不正确。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 122, "subject": "相关法", "id": "xg_374"},
  {"question": "根据民事诉讼法的规定，第二审人民法院对上诉案件经过审理，认为原判决认定事实错误或者适用法律错误的，应当如何处理？（多选）", "options": ["A. 变更原判决", "B. 要求原审人民法院改判", "C. 裁定撤销原判决", "D. 依法改判"], "answer": "ACD", "explanation": "《民诉法》第177条规定：‘第二审人民法院对上诉案件，经过审理，按照下列情形，分别处理：……（二）原判决、裁定认定事实错误或者适用法律错误的，以判决、裁定方式依法改判、撤销或者变更……’，因此A、C、D选项正确，B选项错误。（2006）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 117, "subject": "相关法", "id": "xg_375"},
  {"question": "根据民事诉讼法及相关规定，对下列哪些上诉案件，第二审人民法院应当对上诉请求的有关事实和适用法律进行审查？（多选）", "options": ["A. 当事人只对部分事实提出上诉的", "B. 当事人只对部分法律适用提出上诉的", "C. 当事人既对事实又对法律适用提出上诉的", "D. 当事人未提出上诉请求的"], "answer": "ABC", "explanation": "《民诉法》第331条规定：‘第二审人民法院对下列上诉案件，依照民事诉讼法第一百七十七条的规定，应当对上诉请求的有关事实和适用法律进行审查’，因此A、B、C选项正确，D选项错误。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 117, "subject": "相关法", "id": "xg_376"},
  {"question": "根据民事诉讼法及相关规定，当事人不服地方人民法院第一审判决的，有权在判决书送达之日起十五日内提起上诉。下列哪些说法是正确的？（多选）", "options": ["A. 当事人应当在判决书送达之日起十五日内提起上诉", "B. 上诉状应当向第二审人民法院提出", "C. 第二审人民法院判决宣告前，上诉人不得撤回上诉", "D. 第二审人民法院的判决是终审的判决"], "answer": "AD", "explanation": "A选项《民诉法》第171条第1款规定：“当事人不服地方人民法院第一审判决的，有权在判决书送达之日起十五日内提起上诉。”因此A选项正确。B选项《民诉法》第173条第1款规定：“上诉状应当通过原审人民法院提交”，因此B选项错误。C选项《民诉法》第180条规定：“第二审人民法院判决宣告前，上诉人不得撤回上诉”，因此C选项错误。D选项《民诉法》第182条规定：“第二审人民法院的判决、裁定，是终审的判决、裁定”，因此D选项正确。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 116, "subject": "相关法", "id": "xg_377"},
  {"question": "根据民事诉讼法及相关规定，下列关于审判监督程序的哪种说法是错误的？（单选）", "options": ["A. 当事人对已经发生法律效力的调解书，一律不得申请再审", "B. 当事人对已经发生法律效力的解除婚姻关系的判决，不得申请再审", "C. 按照审判监督程序决定再审的案件，裁定中止原判决的执行", "D. 人民法院审理再审案件，应当另行组成合议庭"], "answer": "A", "explanation": "根据《民诉法》第217条规定：'按照审判监督程序决定再审的案件，裁定中止原判决、裁定、调解书的执行……'，因此C选项正确。D选项，《民诉法》第218条第2款规定：'人民法院审理再审案件，应当另行组成合议庭'，因此D选项正确。A选项错误，因为当事人对已经发生法律效力的调解书，在特定情况下可以申请再审。", "type": "single", "topic": "专题三 民事诉讼法", "page": 121, "subject": "相关法", "id": "xg_378"},
  {"question": "张某起诉王某违约并要求继续履行合同、支付迟延履行违约金，经县市两级人民法院审理均胜诉。王某以生效的二审判决适用法律错误为由申请再审。根据民事诉讼法及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 省高级人民法院按照审判监督程序提审的，按照第二审程序审理", "B. 省高级人民法院交原审人民法院再审的，原审人民法院应当按照第一审程序审理", "C. 省高级人民法院决定再审的，裁定中止原判决的执行", "D. 省高级人民法院驳回再审申请的，王某可以向人民检察院申请抗诉"], "answer": "ACD", "explanation": "根据《民诉法》第218条第1款规定：'……发生法律效力的判决、裁定是由第二审法院作出的，按照第二审程序审理，所作的判决、裁定，是发生法律效力的判决、裁定'；上级人民法院按照审判监督程序提审的，按照第二审程序审理，所作的判决、裁定是发生法律效力的判决、裁定'，原审案件已经过两审，省高级人民法院提审或者指定再审的，按照第二审程序审理，因此A选项正确，B选项错误。C选项，按照审判监督程序决定再审的案件，应当裁定中止原判决、裁定、调解书的执行，C选项正确。D选项，《民诉法》第220条第1款规定：'有下列情形之一的，当事人可以向人民检察院申请抗诉'，因此D选项正确。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 121, "subject": "相关法", "id": "xg_379"},
  {"question": "根据民事诉讼法及相关规定，下列关于执行过程中查封、扣押财产的哪些说法是正确的？（多选）", "options": ["A. 人民法院查封、扣押财产时，被执行人是公民的，应当通知被执行人或者其成年家属到场", "B. 人民法院查封、扣押财产时，被执行人是法人或其他组织的，应当通知其法定代表人或者主要负责人到场", "C. 被查封的财产，执行员可以指定被执行人负责保管", "D. 对被查封、扣押的财产，执行员必须造具清单，由在场人签名或者盖章后，交被执行人一份，被执行人是公民的，也可以交他的成年家属一份"], "answer": "ABCD", "explanation": "根据《民诉法》第256条第1款的规定：‘人民法院查封、扣押财产时，被执行人是公民的，应当通知被执行人或者他的成年家属到场；被执行人是法人或者其他组织的，应当通知其法定代表人或者主要负责人到场’，因此A、B选项正确。C选项，《民诉法》第257条规定：‘被查封的财产，执行员可以指定被执行人负责保管’，因此C选项正确。D选项，《民诉法》第256条第2款的规定：‘对被查封、扣押的财产，执行员必须造具清单，由在场人签名或者盖章后，交被执行人一份。被执行人是公民的，也可以交他的成年家属一份’，因此D选项正确。（2012）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 124, "subject": "相关法", "id": "xg_380"},
  {"question": "根据民事诉讼法及相关规定，以下哪些情形下，人民法院应当裁定中止执行？（多选）", "options": ["A. 申请人表示可以延期执行的", "B. 据以执行的法律文书被撤销的", "C. 案外人对执行标的提出确有理由的异议的", "D. 作为一方当事人的法人终止，尚未确定权利义务承受人的"], "answer": "ACD", "explanation": "《民诉法》第267条规定：‘有下列情形之一的，人民法院应当裁定中止执行：（一）申请人表示可以延期执行的；（二）案外人对执行标的提出确有理由的异议的；……；（四）作为一方当事人的法人或者其他组织终止，尚未确定权利义务承受人的……’，因此A、C、D选项正确，B选项属于执行终结的情形。（2018）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 124, "subject": "相关法", "id": "xg_381"},
  {"question": "二审人民法院可以不开庭审理?(多选)", "options": ["A. 原判决严重违反法定程序,需要发回重审的", "B. 当事人提出的上诉请求明显不能成立的", "C. 不服管辖权异议裁定的", "D. 原判决认定事实清楚,但适用法律错误的"], "answer": "ABCD", "explanation": "民事诉讼法第176条规定可以不开庭审理：(一)不服不予受理、管辖权异议和驳回起诉裁定的；(二)当事人提出的上诉请求明显不能成立的；(三)原判决、裁定认定事实清楚，但适用法律错误的；(四)原判决严重违反法定程序，需要发回重审的”，因此A、B、C、D选项均正确。(新编)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 118, "subject": "相关法", "id": "xg_382"},
  {"question": "杭州市甲公司运营的公众号“半月谈谈”内容涉及河南省许昌市某超市的经营管理策略，超市负责人汪某看到该篇文章后，认为其所发文章内容严重失实，损害了其名誉，使经营受到影响。于是超市向法院起诉要求甲公司赔偿损失50万元，并进行公开发帖道歉。一审法院仅判决甲公司赔偿超市30万元，未对“公开道歉”的请求进行处理。甲公司认为赔偿数额过高，不服一审判决提起上诉。关于二审法院对本案的处理，下列选项正确的是：(单选)", "options": ["A. 由于“公开道歉”的诉讼请求并不在上诉请求的范围之中，二审法院不得对其进行审理", "B. 针对一审中“公开道歉”的诉讼请求，二审法院应根据当事人自愿的原则进行调解，调解不成的，发回重审", "C. 针对一审中“公开道歉”的诉讼请求，二审法院应根据当事人自愿的原则进行调解，调解不成的，径行判决", "D. 针对一审中“公开道歉”的诉讼请求，二审法院应根据当事人自愿的原则进行调解，调解不成的，告知超市另行起诉"], "answer": "B", "explanation": "A项，虽然一审法院未对“赔礼道歉”作出判决，但当事人也并未对一审裁判的“公开道歉”进行上诉，从尊重当事人处分权和“不告不理”的原则来看，二审法院对于一审裁判的“公开道歉”请求，应当不予审理，A项正确。B选项迷惑性较大，根据《民诉法解释》第324条规定：“对当事人在第一审程序中已经提出的诉讼请求，原审人民法院未作审理、判决的，第二审人民法院可以根据当事人自愿的原则进行调解；调解不成的，发回重审”，该项规定针对的是上诉人对一审遗漏的诉讼请求提出上诉的审判要求，本题中许昌超市未上诉，因此B选项错误。(新编)", "type": "single", "topic": "专题三 民事诉讼法", "page": 118, "subject": "相关法", "id": "xg_383"},
  {"question": "关于民事诉讼二审程序，下列哪些选项是正确的？(多选)", "options": ["A. 二审既可因为当事人的上诉而发生，也可能因为检察院的抗诉而发生", "B. 二审既是事实审，也是法律审"], "answer": "B", "explanation": "A选项，二审程序是二审法院根据上诉人的上诉，就一审法院尚未发生法律效力的判决或裁定认定的事实和适用法律进行的审理，二审只能基于当事人的上诉而启动，检察院抗诉不能启动二审，而是启动再审，A选项错误。B选项，《民诉法》第175条规定：“第二审人民法院应当对上诉请求的有关事实和适用法律进行审查”，B选项正确。C选项，《民诉法》第179条规定：“调解书送达后，原审人民法院的判决即视为撤销”，故不用在调解书中写明撤销原判，C选项错误。D选项，第二审人民法院对上诉案件应当开庭审理，《民诉法解释》第331条规定：“经过阅卷、调查和询问当事人，对没有提出新的事实、证据或者理由，合议庭认为不需要开庭审理的，可以不开庭审理”。因此D选项正确。", "type": "single", "topic": "专题三 民事诉讼法", "page": 118, "subject": "相关法", "id": "xg_384"},
  {"question": "人民法院受理甲出版社、乙报社著作权纠纷案，判决乙赔偿甲十五万元，并登报赔礼道歉。判决生效后，乙交付十五万元，但未赔礼道歉，甲申请强制执行。执行中，甲、乙自行达成和解协议，约定乙免于赔礼道歉，但另付甲五万元。根据民事诉讼法及相关规定，下列关于人民法院做法的说法，哪个是正确的？（单选）", "options": ["A. 不允许，因协议内容超出判决范围，应当继续执行生效判决", "B. 允许，人民法院视为申请人撤销执行申请", "C. 允许，将当事人协议内容记入笔录，由甲、乙签字或盖章", "D. 允许，根据当事人协议内容制作调解书"], "answer": "C", "explanation": "《民诉法》第241条第1款规定：‘在执行中，双方当事人自行和解达成协议的，执行员应当将协议内容记入笔录，由双方当事人签名或者盖章’，因此执行程序中可以和解，C选项正确。（2019）", "type": "single", "topic": "专题三 民事诉讼法", "page": 123, "subject": "相关法", "id": "xg_385"},
  {"question": "根据民事诉讼法及相关规定，下列关于执行程序的哪些说法是正确的？（多选）", "options": ["A. 发生法律效力的民事判决、裁定，以及刑事判决、裁定中的财产部分，由第一审人民法院或者与第一审人民法院同级的被执行的财产所在地人民法院执行", "B. 人民法院自收到申请执行书之日起超过六个月未执行的，申请执行人可以向上一级人民法院申请执行", "C. 在执行中，双方当事人自行和解达成协议的，执行员应当将协议内容记入笔录，由双方当事人签名或者盖章"], "answer": "ABC", "explanation": "A选项正确，《民诉法》第235条规定：‘发生法律效力的民事判决、裁定，以及刑事判决、裁定中的财产部分，由第一审人民法院或者与第一审人民法院同级的被执行的财产所在地人民法院执行’，因此A选项正确。B选项正确，《民诉法》第237条规定：‘人民法院自收到申请执行书之日起超过六个月未执行的，申请执行人可以向上一级人民法院申请执行……’，因此B选项正确。C选项正确，《民诉法》第241条规定：‘在执行中，双方当事人自行和解达成协议的，执行员应当将协议内容记入笔录，由双方当事人签名或者盖章’，因此C选项正确。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 123, "subject": "相关法", "id": "xg_386"},
  {"question": "根据民事诉讼法及相关规定，下列哪些情况下，当事人可以申请审判人员回避？（多选）", "options": ["A. 是本案诉讼代理人近亲属的", "B. 担任过本案的翻译人员的", "C. 向本案当事人及其受托人借用款物的", "D. 其近亲属持有本案非上市公司当事人的股份或者股权的"], "answer": "ABCD", "explanation": "根据《民事诉讼法》第43条及《民诉法解释》相关规定，审判人员有下列情形之一的，应当自行回避，当事人有权申请其回避：（三）担任过本案的证人、鉴定人、辩护人、诉讼代理人、翻译人员的；（四）是本案诉讼代理人近亲属的；（五）本人或者其近亲属持有本案非上市公司当事人的股份或者股权的。因此A、B、D选项正确。C选项，《民诉法解释》第44条规定：‘审判人员有下列情形之一的，当事人有权申请其回避：……（五）向本案当事人及其受托人借用款物的……’，因此C选项正确。（2018）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 88, "subject": "相关法", "id": "xg_387"},
  {"question": "根据民事诉讼法及相关规定，下列关于民事诉讼中回避的说法哪项是正确的？（单选）", "options": ["A. 陪审员和书记员的回避均由审判长决定", "B. 陪审员的回避由人民法院院长决定，书记员的回避由审判长决定"], "answer": "B", "explanation": "根据《民事诉讼法》第49条规定：‘……审判人员的回避，由院长决定；其他人员的回避，由审判长或者独任审判员决定。’上述审判人员包括陪审员，因此陪审员的回避由院长决定，书记员的回避由审判长决定。因此B选项正确。", "type": "single", "topic": "专题三 民事诉讼法", "page": 88, "subject": "相关法", "id": "xg_388"},
  {"question": "关于涉外民事诉讼程序，下列说法正确的有哪些？（多选）", "options": ["A. 外国人在中国人民法院起诉、应诉，必须委托中华人民共和国的律师", "B. 对享有外交特权与豁免的外国人提起的民事诉讼，应当依照中华人民共和国有关法律和中华人民共和国缔结或者参加的国际条约的规定办理", "C. 涉外民事纠纷的当事人书面协议选择人民法院管辖的，可以由人民法院管辖", "D. 因与在中华人民共和国领域内审查授予的知识产权的有效性有关的纠纷提起的诉讼，由人民法院专属管辖"], "answer": "BCD", "explanation": "A选项，根据《民事诉讼法》第274条规定：‘外国人、无国籍人、外国企业和组织在人民法院起诉、应诉，需要委托律师代理诉讼的，必须委托中华人民共和国的律师’，除委托律师外，外国人还可以委托近亲属参加诉讼，因此A选项错误。B选项，根据《民事诉讼法》第272条规定：‘对享有外交特权与豁免的外国人、外国组织或者国际组织提起的民事诉讼，应当依照中华人民共和国有关法律和中华人民共和国缔结或者参加的国际条约的规定办理’，因此B选项正确。C选项，根据《民事诉讼法》第277条规定：‘涉外民事纠纷的当事人书面协议选择人民法院管辖的，可以由人民法院管辖’，因此C选项正确。D选项，根据《民事诉讼法》第279条规定：‘下列民事案件，由人民法院专属管辖：……（二）因与在中华人民共和国领域内审查授予的知识产权的有效性有关的纠纷提起的诉讼’，因此D选项正确。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 126, "subject": "相关法", "id": "xg_389"},
  {"question": "关于涉外民事诉讼程序的管辖，下列说法正确的有哪些？（多选）", "options": ["A. 因在中华人民共和国领域内履行中外合资经营企业合同、中外合作经营企业合同、中外合作勘探开发自然资源合同发生纠纷提起的诉讼，由人民法院专属管辖", "B. 因在中华人民共和国领域内设立的法人或者其他组织的设立、解散、清算，以及该法人或者其他组织作出的决议的效力等纠纷提起的诉讼，由人民法院专属管辖", "C. 涉外民事纠纷的当事人书面协议选择人民法院管辖的，可以由人民法院管辖", "D. 当事人未提出管辖异议，并应诉答辩或者提出反诉的，视为人民法院有管辖权"], "answer": "ABCD", "explanation": "A、B选项，根据《民事诉讼法》第279条规定：‘下列民事案件，由人民法院专属管辖：（一）因在中华人民共和国领域内设立的法人或者其他组织的设立、解散、清算，以及该法人或者其他组织作出的决议的效力等纠纷提起的诉讼；（二）因与在中华人民共和国领域内审查授予的知识产权的有效性有关的纠纷提起的诉讼；（三）因在中华人民共和国领域内履行中外合资经营企业合同、中外合作经营企业合同、中外合作勘探开发自然资源合同发生纠纷提起的诉讼’，因此A、B选项正确。C选项，根据《民事诉讼法》第277条规定：‘涉外民事纠纷的当事人书面协议选择人民法院管辖的，可以由人民法院管辖’，因此C选项正确。D选项，根据《民事诉讼法》第278条规定：‘当事人未提出管辖异议，并应诉答辩或者提出反诉的，视为人民法院有管辖权’，因此D选项正确。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 126, "subject": "相关法", "id": "xg_390"},
  {"question": "县级以上地方各级人民政府对下列哪些行政复议案件进行管辖？（多选）", "options": ["A. 对本级人民政府工作部门作出的行政行为不服", "B. 对下一级人民政府作出的行政行为不服", "C. 对本级人民政府依法设立的派出机关作出的行政行为不服", "D. 对本级人民政府或者其工作部门管理的法律、法规、规章授权的组织作出的行政行为不服"], "answer": "ABCD", "explanation": "《复议法》第24条第1款规定：‘县级以上地方各级人民政府管辖下列行政复议案件：（一）对本级人民政府工作部门作出的行政行为不服的；（二）对下一级人民政府作出的行政行为不服的；（三）对本级人民政府依法设立的派出机关作出的行政行为不服的；（四）对本级人民政府或者其工作部门管理的法律、法规、规章授权的组织作出的行政行为不服的’，因此A、B、C、D选项均正确。（新编）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 135, "subject": "相关法", "id": "xg_391"},
  {"question": "以下哪些属于行政复议机关审理行政复议案件的依据？", "options": ["A. 法律", "B. 法规", "C. 国务院部门规章"], "answer": "ABC", "explanation": "《复议法》第37条第1款规定：‘行政复议机关依照法律、法规、规章审理行政复议案件’。因此A、B、C、D选项均正确。（新编）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 141, "subject": "相关法", "id": "xg_392"},
  {"question": "郑飞诉万雷侵权纠纷一案，虽不属于事实清楚、权利义务关系明确、争议不大的案件，但双方当事人约定适用简易程序进行审理，法院同意并以电子邮件的方式向双方当事人通知了开庭时间（双方当事人均未回复）。开庭时被告万雷无正当理由不到庭，法院作出了缺席判决。送达判决书时法院通过各种方式均未联系上万雷，遂采取了公告送达方式送达了判决书。对此，法院下列的哪些行为是违法的？（多选）", "options": ["A. 同意双方当事人的约定，适用简易程序对案件进行审理", "B. 以电子邮件的方式向双方当事人通知开庭时间", "C. 作出缺席判决", "D. 采取公告方式送达判决书"], "answer": "CD", "explanation": "A选项，《民诉法》第160条规定：‘基层人民法院和它派出的法庭审理事实清楚，权利义务关系明确、争议不大的简单的民事案件，适用本章规定。基层人民法院和它派出的法庭审理前款规定以外的民事案件，当事人双方也可以约定适用简易程序’，因此简易程序可以由法院依职权适用，也可以由当事人协议适用，A选项符合规定。B选项，《民诉法解释》第261条规定：‘适用简易程序审理案件，人民法院可以依照民事诉讼法第90条、第162条的规定采取捎口信、电话、短信、传真、电子邮件等简便方式传唤双方当事人、通知证人和送达诉讼文书’，因此B选项符合规定。C选项，《民诉法解释》第261条第2款规定：‘以简便方式送达的开庭通知，未经当事人确认或者没有其他证据证明当事人已经收到的，人民法院不得缺席判决’，因此C选项违法。D选项，《民诉法解释》第140条规定：‘适用简易程序的案件，不适用公告送达’，因此D选项违法。（法考2015）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 114, "subject": "相关法", "id": "xg_393"},
  {"question": "在执行程序中，甲和乙自愿达成和解协议：将判决中确定的乙向甲偿还1万元人民币改为给付价值相当的化肥、农药。和解协议履行完毕后，甲以化肥质量不好向法院提出恢复执行程序。下列哪一选项是正确的？（单选）", "options": ["A. 和解协议无效，应恢复执行原判决", "B. 和解协议有效，但甲反悔后应恢复执行原判决", "C. 和解协议已履行完毕，应执行回转", "D. 和解协议已履行完毕，法院应作执行结案处理"], "answer": "D", "explanation": "《民诉法》第241条第1款规定：‘在执行中，双方当事人自行和解达成协议的，执行员应当将协议内容记入笔录，由双方当事人签名或者盖章’；《民诉法》第244条规定：‘执行完毕后，据以执行的判决、裁定和其他法律文书确有错误，被人民法院撤销的，对已被执行的财产，人民法院应当作出裁定，责令取得财产的人返还；拒不返还的，强制执行’。本题中，当事人达成的和解协议有效，且本案和解协议履行完毕，法院不能恢复对原判决的执行，应裁定执行终结，终结后不能恢复执行，如果是迟延履行或者瑕疵履行的，当事人可以另行起诉，执行的判决、裁定和其他法律文书确有错误，被人民法院撤销才可以发生执行回转，因此A、B、C选项错误，D选项正确。（法考2007）", "type": "single", "topic": "专题三 民事诉讼法", "page": 125, "subject": "相关法", "id": "xg_394"},
  {"question": "张某对县税务局的行政处罚不服，向市税务局申请行政复议，但复议机关维持了原处罚决定，张某逾期不履行该行政复议决定，也未向法院起诉，对此，下列说法正确的是？（单选）", "options": ["A. 由县税务局依法强制执行，或者申请人人民法院强制执行", "B. 由市税务局依法强制执行，或者申请人人民法院强制执行", "C. 县税务局不能强制执行，只能申请人人民法院强制执行", "D. 市税务局不能强制执行，只能申请人人民法院强制执行"], "answer": "A", "explanation": "根据《行政复议法》第78条，维持原行政行为的复议决定，由作出原行政行为的行政机关依法强制执行，或者申请人民法院强制执行。因此，A选项正确，B、C、D选项错误。", "type": "single", "topic": "专题三 民事诉讼法", "page": 153, "subject": "相关法", "id": "xg_395"},
  {"question": "根据行政复议法的规定，行政复议决定作出后申请人逾期不起诉又不履行行政复议决定、调解书的，应当如何处理？（多选）", "options": ["A. 由作出行政行为的行政机关强制执行", "B. 行政复议调解书由行政复议机关强制执行或申请人人民法院强制执行", "C. 维持行政行为的行政复议决定，由作出行政行为的行政机关依法强制执行，或者申请人人民法院强制执行", "D. 变更行政行为的行政复议决定，由行政复议机关依法强制执行，或者申请人人民法院强制执行"], "answer": "BCD", "explanation": "根据《行政复议法》第78条：（一）维持行政行为的行政复议决定书，由作出行政行为的行政机关依法强制执行，或者申请人人民法院强制执行；（二）变更行政行为的行政复议决定书，由行政复议机关依法强制执行，或者申请人人民法院强制执行；（三）行政复议调解书，由行政复议机关依法强制执行，或者申请人人民法院强制执行。因此，A选项缺少条件错误，B、C、D选项正确。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 153, "subject": "相关法", "id": "xg_396"},
  {"question": "根据行政诉讼法及相关规定，下列关于行政诉讼地域管辖的说法哪些是正确的？（多选）", "options": ["A. 因不动产提起的行政诉讼，由不动产所在地人民法院管辖", "B. 行政案件由最初作出具体行政行为的行政机关所在地人民法院管辖", "C. 经复议的行政案件，复议机关改变原具体行政行为的，应由复议机关所在地人民法院管辖", "D. 对限制人身自由的行政强制措施不服提起的诉讼，由被告所在地或者原告所在地人民法院管辖"], "answer": "ABD", "explanation": "A选项，《行政诉讼法》第20条规定：‘因不动产提起的行政诉讼，由不动产所在地人民法院管辖’，因此A选项正确。B、C选项，《行政诉讼法》第18条第1款规定：‘行政案件由最初作出行政行为的行政机关所在地人民法院管辖。经复议的案件，也可以由复议机关所在地人民法院管辖’，因此B选项正确，C选项错误。D选项，《行政诉讼法》第19条规定：‘对限制人身自由的行政强制措施不服提起的诉讼，由被告所在地或者原告所在地人民法院管辖’，因此D选项正确。（新编）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 161, "subject": "相关法", "id": "xg_397"},
  {"question": "动物卫生监督机构在监督检查过程中，发现甲某涂改了检疫证明的数量和日期，动物卫生监督管理机构对其进行了行政处罚。被涂改的检疫证明在证据的分类上属于？(单选)", "options": ["A. 书证", "B. 视听资料", "C. 物证", "D. 当事人陈述"], "answer": "C", "explanation": "在状况等未证明案件事实的物品或痕迹，被涂改的检疫证明是通过被涂改的痕迹来证明涂改的事实，属于物证，因此A、B、D选项错误，C选项正确。(新编)", "type": "single", "topic": "专题三 民事诉讼法", "page": 169, "subject": "相关法", "id": "xg_398"},
  {"question": "根据行政诉讼法及相关规定，下列哪些证据不能作为认定被诉具体行政行为合法的依据？(多选)", "options": ["A. 被告及其诉讼代理人在作出具体行政行为后自行收集的证据", "B. 被告及其诉讼代理人在诉讼程序中自行收集的证据", "C. 被告在行政程序中非法剥夺公民、法人或者其他组织依法享有的陈述、申辩或者听证权利所采用的证据", "D. 原告在诉讼程序中提供的、被告在行政程序中未作为具体行政行为依据的证据"], "answer": "ABCD", "explanation": "《最高人民法院关于行政诉讼证据若干问题的规定》第60条规定：\"下列证据不能作为认定被诉具体行政行为合法的依据：（一）被告及其诉讼代理人在作出具体行政行为后或者在诉讼程序中自行收集的证据；（二）被告在行政程序中非法剥夺公民、法人或者其他组织依法享有的陈述、申辩或者听证权利所采用的证据；（三）原告或者第三人在诉讼程序中提供的、被告在行政程序中未作为具体行政行为依据的证据\"，因此A、B、C、D选项均正确。(2012)", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 169, "subject": "相关法", "id": "xg_399"},
  {"question": "根据行政诉讼法及相关规定，下列关于审判监督程序的那些说法是正确的？（多选）", "options": ["A. 地方各级人民检察院发现同级人民法院已经发生法律效力的判决遗漏诉讼请求的，可以向同级人民法院提出抗诉", "B. 地方各级人民检察院发现同级人民法院已经发生法律效力的判决遗漏诉讼请求的，可以提请上级人民检察院向同级人民法院提出抗诉", "C. 上级人民检察院发现下级人民法院已经发生法律效力的判决遗漏诉讼请求的，应当提出抗诉", "D. 最高人民检察院发现各级人民法院已经发生法律效力的判决遗漏诉讼请求的，应当提出抗诉"], "answer": "BCD", "explanation": "根据《行政诉讼法》第91条规定：‘当事人申请符合下列情形之一的，人民法院应当再审：……（六）原判决、裁定遗漏诉讼请求的……’；《行政诉讼法》第93条第1、2款规定：‘最高人民检察院对各级人民法院已经发生法律效力的判决、裁定，上级人民检察院对下级人民法院已经发生法律效力的判决、裁定，发现有本法第91条规定情形之一，或者发现调解书损害国家利益、社会公共利益的，应当提出抗诉。地方各级人民检察院对同级人民法院已经发生法律效力的判决、裁定，发现有本法第91条规定情形之一，或者发现调解书损害国家利益、社会公共利益的，可以向同级人民法院提出检察建议，并报上级人民检察院备案；也可以提请上级人民检察院向同级人民法院提出抗诉’；因此A选项错误，B、C、D选项正确。（2016）", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 183, "subject": "相关法", "id": "xg_400"},
  {"question": "某县公安局干警张某在协助县林业局执行公务时，遇到往口有嫌隙的王某，张某借故将王某殴打致死，对王某的死亡承担赔偿义务的是？（单选）", "options": ["A. 该县公安局", "B. 该县人民政府", "C. 张某", "D. 该县林业局"], "answer": "C", "explanation": "《国家赔偿法》第5条规定：‘属于下列情形之一的，国家不承担赔偿责任：（一）行政机关工作人员与行使职权无关的个人行为……’，张某的行为属于个人行为，和职务无关，国家不承担赔偿责任，因此A、B、D选项错误，C选项正确。（2019）", "type": "single", "topic": "专题三 民事诉讼法", "page": 183, "subject": "相关法", "id": "xg_401"},
  {"question": "根据行政诉讼法及相关规定，下列说法哪些是正确的？（多选）", "options": ["A. 当事人对已经发生法律效力的判决、裁定，认为确有错误的，可以向原审人民法院提出再审。", "B. 当事人对已经发生法律效力的判决、裁定，认为确有错误的，可以向原审人民法院的上级人民法院提出再审。", "C. 人民法院院长对本院已经发生法律效力的判决、裁定，发现违反法律、法规规定的，有权决定再审。", "D. 上级人民法院对下级人民法院已经发生法律效力的判决、裁定，发现违反法律、法规规定的，有权提审或者指令下级人民法院再审。"], "answer": "BD", "explanation": "当事人对已经发生法律效力的判决、裁定，认为确有错误的，可以向原审人民法院的上级人民法院提出再审。人民法院院长对本院已经发生法律效力的判决、裁定，发现违反法律、法规规定的，有权决定再审。", "type": "multiple", "topic": "专题三 民事诉讼法", "page": 182, "subject": "相关法", "id": "xg_402"},
  {"question": "2. 关于涉外民事诉讼程序,下列说法正确的有哪些?(多选)", "options": ["A. 外国人在人民法院起诉、应诉,必须委托中华人民共和国的律师", "B. 对享有外交特权与豁免的外国人提起的民事诉讼,应当依照中华人民共和国有关法律和中华人民共和国缔结或者参加的国际条约的规定办理", "C. 涉外民事纠纷的当事人书面协议选择人民法院管辖的,可以由人民法院管辖", "D. 因与在中华人民共和国领域内审查授予的知识产权的有效性有关的纠纷提起的诉讼,由人民法院专属管辖"], "answer": "BCD", "explanation": "A选项,根据《民事诉讼法》第274条规定:“外国人、无国籍人、外国企业和组织在人民法院起诉、应诉,需要委托律师代理诉讼的,必须委托中华人民共和国的律师”,除委托律师外,外国人还可以委托近亲属参加诉讼,因此A选项错误。B选项,根据《民事诉讼法》第272条规定:“对享有外交特权与豁免的外国人、外国组织或者国际组织提起的民事诉讼,应当依照中华人民共和国有关法律和中华人民共和国缔结或者参加的国际条约的规定办理”,因此B选项正确。C选项,根据《民事诉讼法》第277条规定:“涉外民事纠纷的当事人书面协议选择人民法院管辖的,可以由人民法院管辖”,因此C选项正确。D选项,根据《民事诉讼法》第279条规定:“下列民事案件,由人民法院专属管辖:……(二)因与在中华人民共和国领域内审查授予的知识产权的有效性有关的纠纷提起的诉讼”,因此D选项正确。(新编, 思维扩展)", "type": "multiple", "topic": "专题四 行政复议法", "page": 108, "subject": "相关法", "id": "xg_403"},
  {"question": "3. 关于涉外民事诉讼程序的管辖,下列说法正确的有哪些?(多选)", "options": ["A. 因在中华人民共和国领域内履行中外合资经营企业合同、中外合作经营企业合同、中外合作勘探开发自然资源合同发生纠纷提起的诉讼,由人民法院专属管辖", "B. 因在中华人民共和国领域内设立的法人或者其他组织的设立、解散、清算,以及该法人或者其他组织作出的决议的效力等纠纷提起的诉讼,由人民法院专属管辖", "C. 涉外民事纠纷的当事人书面协议选择人民法院管辖的,可以由人民法院管辖", "D. 当事人未提出管辖异议,并应诉答辩或者提出反诉的,视为人民法院有管辖权"], "answer": "ABCD", "explanation": "A、B选项,根据《民事诉讼法》第279条规定:“下列民事案件,由人民法院专属管辖:(一)因在中华人民共和国领域内设立的法人或者其他组织的设立、解散、清算,以及该法人或者其他组织作出的决议的效力等纠纷提起的诉讼;(二)因与在中华人民共和国领域内审查授予的知识产权的有效性有关的纠纷提起的诉讼;(三)因在中华人民共和国领域内履行中外合资经营企业合同、中外合作经营企业合同、中外合作勘探开发自然资源合同发生纠纷提起的诉讼”,因此A、B选项正确。C选项,根据《民事诉讼法》第277条规定:“涉外民事纠纷的当事人书面协议选择人民法院管辖的,可以由人民法院管辖”,因此C选项正确。D选项,根据《民事诉讼法》第278条的规定:“当事人未提出管辖异议,并应诉答辩或者提出反诉的,视为人民法院有管辖权”,因此D选项正确。(新编, 思维扩展)", "type": "multiple", "topic": "专题四 行政复议法", "page": 108, "subject": "相关法", "id": "xg_404"},
  {"question": "1. 根据行政复议法及相关规定，下列说法哪些是正确的?(多选)", "options": ["A. 行政复议是解决行政争议的主要渠道", "B. 行政复议机构应当审查申请行政复议的行政行为所依据的规章是否合法", "C. 上级行政复议机构对下级行政复议机构的行政复议工作进行指导、监督", "D. 行政复议机关办理行政复议案件可以进行调解"], "answer": "ACD", "explanation": "A选项，《复议法》第1条规定：“为了防止和纠正违法的或者不当的行政行为，保护公民、法人和其他组织的合法权益，监督和保障行政机关依法行使职权，发挥行政复议化解行政争议的主渠道作用，推进法治政府建设，根据宪法，制定本法”，因此A选项正确。B选项，根据《复议法》第13条的规定，复议机关对其他规范性文件进行附带审查，无权对规章的合法性进行审查，因此B选项错误。C选项，根据《复议法》第4条的规定，行政复议机关办理行政复议事项的机构是行政复议机构，上级行政复议机构对下级行政复议机构的行政复议工作进行指导、监督，因此C选项正确。D选项，《复议法》第5条第1款规定：“行政复议机关办理行政复议案件，可以进行调解”，因此D选项正确。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 109, "subject": "相关法", "id": "xg_405"},
  {"question": "2. 下列哪些是行政复议机关在履行行政复议职责时必须遵循的原则?(多选)", "options": ["A. 合理、合法", "B. 公正、公开", "C. 公平、公正", "D. 高效、便民"], "answer": "BD", "explanation": "《复议法》第3条规定：“行政复议机关履行行政复议职责，应当遵循合法、公正、公开、高效、便民、为民的原则，坚持有错必纠，保障法律、法规的正确实施。”，因此B、D选项正确。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 109, "subject": "相关法", "id": "xg_406"},
  {"question": "3. 关于行政复议案件的调解，以下说法正确的有？(多选)", "options": ["A. 在行政复议受理过程和审查阶段，均可以进行调解", "B. 调解限于行政补偿、赔偿及自由裁量案件", "C. 行政复议案件的调解是行政复议的必经程序", "D. 行政复议案件的调解应当遵循合法、自愿的原则"], "answer": "AD", "explanation": "A选项，根据《复议法》第5条的规定，调解适用于行政复议案件办理的全过程，即在受理审查过程中和审理阶段，均可以进行调解，推动行政争议的实质性化解，因此A选项正确。B选项，原则上，所有的行政复议案件都可以进行调解，不限于行政补偿、赔偿及自由裁量案件，因此B选项错误。C选项，调解只是行政复议机关可以自", "type": "multiple", "topic": "专题四 行政复议法", "page": 109, "subject": "相关法", "id": "xg_407"},
  {"question": "4. 有关行政复议,下列哪项说法是正确的?(单选)", "options": ["A. 行政复议只审查具体行政行为是否合法", "B. 复议机构依法复议后,不得再提起行政诉讼", "C. 复议机关审理复议案件,可以适用调解", "D. 公民、法人或其他组织认为行政机关的行政行为侵犯其合法权益,不可以向该行政机关申请复议"], "answer": "C", "explanation": "A选项,行政复议既审查合法性又审查合理性,A选项错误。B选项,《复议法》第10条规定:“公民、法人或者其他组织对行政复议决定不服的,可以依照《中华人民共和国行政诉讼法》的规定向人民法院提起行政诉讼,但是法律规定行政复议决定为最终裁决的除外”,因此B选项错误。C选项,《复议法》第5条规定:“行政复议机关办理行政复议案件,可以进行调解。”因此C选项正确。D选项,根据《复议法》第24-25条的规定,省、自治区、直辖市人民政府同时管辖对本机关作出的行政行为不服的行政复议案件,国务院部门管辖对本部门作出的行政行为不服的行政复议案件,因此D选项错误。(新编)", "type": "single", "topic": "专题四 行政复议法", "page": 110, "subject": "相关法", "id": "xg_408"},
  {"question": "5. 根据行政复议法及相关规定,下列哪些情形申请人应当先向行政复议机关申请行政复议,对行政复议决定不服的,可以再依法向人民法院提起行政诉讼?(多选)", "options": ["A. 对当场作出的行政处罚决定不服", "B. 对行政机关作出的侵犯其已经依法取得的自然资源的使用权的决定不服", "C. 认为行政机关未履行其法定职责", "D. 对行政机关作出的确认自然资源的使用权的决定不服"], "answer": "ABC", "explanation": "A、B、C选项,《复议法》第23条第1款规定:“有下列情形之一的,申请人应当先向行政复议机关申请行政复议,对行政复议决定不服的,可以再依法向人民法院提起行政诉讼:(一)对当场作出的行政处罚决定不服;(二)对行政机关作出的侵犯其已经依法取得的自然资源的所有权或者使用权的决定不服;(三)认为行政机关存在本法第11条规定的未履行法定职责情形……”,因此A、B、C选项正确。D选项,只有已经依法取得的自然资源所有权或使用权受到行政行为侵害的,才属于复议前置情形,因此D选项不属于复议前置情形。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 110, "subject": "相关法", "id": "xg_409"},
  {"question": "6. 新锐公司兴建厂房需要一块土地。恰逢甲市政府出让一块土地,新锐公司和好客来公司同时提出申请,市政府拒绝了新锐公司的申请,向好客来公司颁发了国有土地使用权证。此后,丰年村认为政府向好客来公司发放的国有土地使用权证所认定的面积包括了该村的集体土地。下列说法正确的是?(多选)", "options": ["A. 新锐公司对政府拒绝其申请的行为,应当先申请行政复议才能提起诉讼", "B. 新锐公司对政府向好客来公司颁发国有土地使用权的行为,应当先申请复议才能提起诉讼", "C. 丰年村对政府向好客来公司颁发国有土地使用权的行为,应当先申请复议才能提起诉讼", "D. 集体土地使用权被侵犯的丰年村村民也可以以自己的名义申请行政复议"], "answer": "CD", "explanation": "《复议法》第23条第1款第(二)项所规定的侵犯土地资源所有权或使用权复议前置的情形,针对的是已经取得的土地所有权或使用权。本题中,新锐公司尚未取得土地所有权或使用权,不属于复议前置的情形,A、B选项属于对申请行政许可决定不服,当事人可以复议,也可以直接向人民法院提起行政诉讼。C、D选项属于行政机关侵犯已经取得的土地资源所有权、使用权,应当先复议,后起诉,D选项中集体土地使用权被侵犯的,村", "type": "multiple", "topic": "专题四 行政复议法", "page": 110, "subject": "相关法", "id": "xg_410"},
  {"question": "7. 根据行政复议法及相关规定，下列哪些情形可以申请行政复议？(多选)", "options": ["A. 李某对某行政机关作出的行政强制措施执行决定不服", "B. 齐某向某行政机关申请行政许可，在法定期限内，行政机关未予答复", "C. 何某对某行政机关作出的征收征用决定不服", "D. 孙某对某市场监督管理局就其与黄某之间的专利侵权纠纷作出的赔偿调解不服"], "answer": "ABC", "explanation": "A、B、C选项，根据《复议法》第11条的规定，对行政机关作出的行政强制措施、行政强制执行决定不服的；申请行政许可，行政机关拒绝或者在法定期限内不予答复的；对行政机关作出的征收征用决定及其补偿决定不服的，均属于行政复议的受案范围，因此A、B、C选项正确。D选项，根据《复议法》第12条的规定，行政机关对民事纠纷作出的调解不属于行政复议的受案范围，因此D选项错误。(2011改编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 111, "subject": "相关法", "id": "xg_411"},
  {"question": "9. 根据行政复议法及相关规定，下列哪些情形不可以申请行政复议？(多选)", "options": ["A. 王某对县政府解除特许经营协议不服", "B. 公务员李某对其所在的行政机关对其作出的记大过行政处分不服", "C. 赵某对某行政机关就其与周某之间的民事纠纷作出的调解不服", "D. 曾某对国家知识产权局《专利审查指南》中有关创造性判断方法相关规定不服"], "answer": "BCD", "explanation": "A选项，属于《复议法》第11条中规定的，认为行政机关不依法订立、不依法履行、未按照约定履行或者违法变更、解除政府特许经营协议、土地房屋征收补偿协议等行政协议的情形，属于行政复议受案范围，因此A选项正确。B、C、D选项，《复议法》第12条规定：“下列事项不属于行政复议范围：……(二)行政法规、规章或者行政机关制定、发布的具有普遍约束力的决定、命令等规范性文件；(三)行政机关对行政机关工作人员的奖惩、任免等决定；(四)行政机关对民事纠纷作出的调解”；B选项属于行政机关对工作人员的惩罚决定，C选项属于对民事纠纷作出的调解，D选项《专利审查指南》属于规章，B、C、D选项均不属于行政复议受案范围。(2017改编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 111, "subject": "相关法", "id": "xg_412"},
  {"question": "2. 根据行政复议法及相关规定,下列关于复议申请人的说法哪些是正确的?(多选)", "options": ["A. 合伙企业申请行政复议的,应当以核准登记的企业为申请人", "B. 合伙企业以外的其他合伙组织申请行政复议的,由其合伙人共同申请行政复议", "C. 股份制企业的股东会认为行政机关作出的具体行政行为侵犯该企业合法权益的,可以以该企业的名义申请行政复议", "D. 股份制企业的董事会认为行政机关作出的行政行为侵犯企业合法权益的,可以以董事会的名义申请行政复议"], "answer": "ABC", "explanation": "A、B选项,《复议条例》第6条第1款规定:“合伙企业申请行政复议的,应当以核准登记的企业为申请人,由执行合伙事务的合伙人代表该企业参加行政复议;其他合伙组织申请行政复议的,由合伙人共同申请行政复议”,因此A、B选项正确。C选项,根据《复议条例》第7条的规定,股份制企业的股东会、董事会认为行政机关作出的具体行政行为侵犯企业合法权益的,可以以企业的名义申请行政复议,因此C选项正确,D选项错误。(2011)", "type": "multiple", "topic": "专题四 行政复议法", "page": 113, "subject": "相关法", "id": "xg_413"},
  {"question": "3. 关于行政复议代表人的行为效力,以下哪些说法是正确的?(多选)", "options": ["A. 代表人参加行政复议的所有行为对其代表的申请人均发生效力", "B. 代表人变更行政复议请求应当经被代表的申请人同意", "C. 代表人承认第三人请求应当经被代表的申请人同意", "D. 代表人承认被申请人提出证据的真实性应当经被代表的申请人同意"], "answer": "BC", "explanation": "《复议法》第15条规定:“同一行政复议案件申请人人人数众多的,可以由申请人推选代表人参加行政复议。代表人参加行政复议的行为对其所代表的申请人发生效力,但是代表人变更行政复议请求、撤回行政复议申请、承认第三人请求的,应当经被代表的申请人同意”,因此A、D选项错误,B、C选项正确。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 113, "subject": "相关法", "id": "xg_414"},
  {"question": "1. 根据某地级市人民政府关于保护水域生态环境、打击涉渔违法行为的部署安排，某县农业农村局和该县森林公安局对某水库开展联合执法巡查。在巡查过程中，两部门以共同名义对李某非法捕鱼的设备进行了收缴。李某不服，拟申请行政复议。根据行政复议法及相关规定，李某应当向下列哪个机关申请行政复议？（单选）", "options": ["A. 该市人民政府", "B. 该县人民政府", "C. 该市农业农村局", "D. 该市森林公安局"], "answer": "B", "explanation": "根据《复议法》第24条的规定，县级以上地方各级人民政府管辖对本级人民政府工作部门作出的行政行为不服的行政复议案件。本题中，县农业农村局和县森林公安局以共同名义作出处罚，应向其所在县人民政府申请行政复议，因此A、C、D选项错误，B选项正确。（新编）", "type": "single", "topic": "专题四 行政复议法", "page": 115, "subject": "相关法", "id": "xg_415"},
  {"question": "2. 张某对某市辖区教育局作出的一项行政行为不服，欲申请行政复议。根据行政复议法及相关规定，下列哪项说法是正确的？（单选）", "options": ["A. 张某可向该区教育局申请行政复议", "B. 张某可向该区政府申请行政复议", "C. 张某可向该市教育局申请行政复议", "D. 张某可向该市政府申请行政复议"], "answer": "B", "explanation": "本题中，区教育局属于人民政府工作部门，对其行政行为不服，根据《复议法》第24条的规定，可以向该部门的本级人民政府即该区政府申请复议，因此A、C、D选项错误，B选项正确。（2012改编）", "type": "single", "topic": "专题四 行政复议法", "page": 115, "subject": "相关法", "id": "xg_416"},
  {"question": "8. 根据行政复议法及相关规定，有关行政复议第三人，下列说法哪些是正确的？（多选）", "options": ["A. 行政复议机构可以通知第三人参加复议程序", "B. 第三人可以向行政复议机构申请参加行政复议", "C. 第三人同申请行政复议的具体行政行为应当有利害关系", "D. 第三人不参加行政复议会影响复议案件的申请 第二节 行政复议机关"], "answer": "ABC", "explanation": "《行政复议法实施条例》第9条规定：“行政复议期间，行政复议机构认为申请人以外的公民、法人或者其他组织与被审查的具体行政行为有利害关系的，可以通知其作为第三人参加行政复议。行政复议期间，申请人以外的公民、法人或者其他组织与被审查的具体行政行为有利害关系的，可以向行政复议机构申请作为第三人参加行政复议。第三人不参加行政复议，不影响行政复议案件的审理”，因此A、B、C选项正确，D选项错误。（新编）", "type": "multiple", "topic": "专题四 行政复议法", "page": 115, "subject": "相关法", "id": "xg_417"},
  {"question": "5. 对省级人民政府的复议决定不服的, 下列哪项说法是正确的?(单选)", "options": ["A. 只能向人民法院提起诉讼", "B. 先向国务院申请裁决,如果仍然不服的,向人民法院提起诉讼", "C. 只能向国务院申请作出最终裁决", "D. 向人民法院提起行政诉讼或者申请国务院作出最终裁决"], "answer": "D", "explanation": "根据《复议法》第26条的规定,对省人民政府、国务院部门作出的(限于省级政府机关或国务院本部门作出的行政行为)行政复议决定不服的,可以向人民法院提起行政诉讼;也可以向国务院申请裁决,国务院依照本法的规定作出最终裁决,因此D选项正确。(新编)", "type": "single", "topic": "专题四 行政复议法", "page": 116, "subject": "相关法", "id": "xg_418"},
  {"question": "6. 大兴安岭地区行政公署是黑龙江省人民政府设立的派出机关,张某对其下属的加格达奇区人民政府作出的强制拆除房屋附属设施的行政行为不服,应当向下列哪个机关申请复议? (单选)", "options": ["A. 黑龙江省人民政府", "B. 大兴安岭地区行政公署", "C. 加格达奇区人民政府", "D. 呼伦贝尔市人民政府"], "answer": "B", "explanation": "《复议法》第24条第3款规定:“省、自治区人民政府依法设立的派出机关参照设区的市级人民政府的职责权限,管辖相关行政复议案件”,大兴安岭地区行政公署是黑龙江省人民政府设立的派出机关,对该派出机关下属的区人民政府行政行为不服,应向该派出机关即大兴安岭地区行政公署申请行政复议,因此B选项正确。(新编)", "type": "single", "topic": "专题四 行政复议法", "page": 116, "subject": "相关法", "id": "xg_419"},
  {"question": "9. 根据行政复议法及相关规定，下列关于行政复议受理机关的说法哪些是正确的？（多选）", "options": ["A. 对外汇管理行政机关的行政行为不服的，向其上一级主管部门申请行政复议", "B. 对县级公安机关的行政行为不服的，可以向该县人民政府申请行政复议，也可以向上一级公安机关申请行政复议", "C. 对海关的行政行为不服的，向其上一级主管部门申请行政复议", "D. 对省级人民政府的行政行为不服的，可以向省人民政府申请行政复议，也可以向国务院申请行政复议"], "answer": "AC", "explanation": "A、C选项，《复议法》第27条规定：“对海关、金融、外汇管理等实行垂直领导的行政机关、税务和国家安全机关的行政行为不服的，向上一级主管部门申请行政复议”，因此A、C选项正确。B选项，根据《复议法》第24条的规定，县级以上地方各级人民政府管辖对本级人民政府工作部门作出的行政行为不服的行政复议案件，县级公安机关属于县政府的工作部门，应当向县政府申请复议，不能向上一级公安机关申请复议，因此B选项错误。D选项，根据《复议法》第24条的规定，省、自治区、直辖市人民政府管辖对本机关作出的行政行为不服的行政复议案件，不能向国务院申请行政复议，因此D选项错误。（2011改编）", "type": "multiple", "topic": "专题四 行政复议法", "page": 117, "subject": "相关法", "id": "xg_420"},
  {"question": "10. 天津市河西区司法局是河西区政府受理的行政复议的复议机构，对河西区司法局针对某律师事务所作出的处罚决定，该律师事务所不服，可以向下列哪些机关申请复议？（多选）", "options": ["A. 天津市人民政府", "B. 天津市河西区人民政府", "C. 天津市司法局", "D. 天津市河西区司法局"], "answer": "BC", "explanation": "《复议法》第28条规定：“对履行行政复议机构职责的地方人民政府司法行政部门的行政行为不服的，可以向本级人民政府申请行政复议，也可以向上一级司法行政部门申请行政复议”，河西区司法局是河西区政府的司法行政部门，并且负责处理河西区政府的行政复议案件，对该部门作出的行政行为，可以向本级政府即河西区政府申请复议，也可以向上一级司法行政部门即天津市司法局申请复议，因此A、D选项错误，B、C选项正确。（新编）", "type": "multiple", "topic": "专题四 行政复议法", "page": 117, "subject": "相关法", "id": "xg_421"},
  {"question": "1. 根据行政复议法及相关规定,以下哪些符合行政复议的受理条件?(多选)", "options": ["A. 申请人明确", "B. 行政复议请求和理由具体", "C. 属于复议机关的管辖范围", "D. 行政复议机关就同一行政行为受理过申请人提出的行政复议申请"], "answer": "ABC", "explanation": "《复议法》第30条第1款规定:\n“行政复议机关收到行政复议申请后,应当在五日内进行审查。对符合下列规定的,行政复议机关应当予以受理;(一)有明确的申请人和符合本法规定的被申请人;……(三)有具体的行政复议请求和理由;……(六)属于本机关的管辖范围;(七)行政复议机关未受理过该申请人就同一行政行为提出的行政复议申请,并且人民法院未受理过该申请人就同一行政行为提起的行政诉讼”,因此A、B、C选项符合受理条件,D选项不符合受", "type": "multiple", "topic": "专题四 行政复议法", "page": 119, "subject": "相关法", "id": "xg_422"},
  {"question": "2. 复议机关收到复议申请之后,应当在()日内进行审查,", "options": ["A. 3日", "B. 5日", "C. 7日", "D. 10日"], "answer": "B", "explanation": "根据《复议法》第30条第1款的规定，行政复议机关收到行政复议申请后，应当在5日内进行审查，因此B选项正确。", "type": "single", "topic": "专题四 行政复议法", "page": 119, "subject": "相关法", "id": "xg_423"},
  {"question": "3. 林某不服县教育局对其作出的某行政行为,欲向行政复议机关申请行政复议。根据行政复议法及相关规定,下列哪些说法是正确的?(多选)", "options": ["A. 林某若书面申请有困难,可以口头申请行政复议", "B. 林某可以通过互联网渠道以电子方式书面申请行政复议", "C. 林某可以通过传真方式申请行政复议", "D. 林某对县教育局两个以上行政行为不服的,可以一同申请行政复议"], "answer": "ABC", "explanation": "A、B选项,根据《复议法》第22条的规定,申请人申请行政复议,可以书面申请;书面申请有困难的,也可以口头申请。书面申请的,可以通过邮寄或者行政复议机关指定的互联网渠道等方式提交行政复议申请书,也可以当面提交行政复议申请书,因此A、B选项正确。C选项,《复议条例》第18条第1款规定:“申请人书面申请行政复议的,可以采取当面递交、邮寄或者传真等方式提出行政复议申请”,因此C选项正确。D选项,《复议法》第22条第4款规定:“申请人对两个以上行政行为不服的,应当分别申请行政复议”,因此D选项错误。\n(2013改编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 119, "subject": "相关法", "id": "xg_424"},
  {"question": "4. 关于行政复议的申请方式,下列说法哪些是正确的?(多选)", "options": ["A. 申请人可以采取当面递交方式提出行政复议申请", "B. 有条件的行政复议机构可以接受以电子邮件形式提出的行政复议申请", "C. 申请人可以采取邮寄方式提出行政复议申请", "D. 申请人可以采取传真方式提出行政复议申请 第二节  行政复议的受理"], "answer": "ABCD", "explanation": "《复议条例》第18条规定:“申请人书面申请行政复议的,可以采取当面递交、邮寄或者传真等方式提出行政复议申请。有条件的行政复议机构可以接受以电子邮件形式提出的行政复议申请”,因此A、B、C、D选项均正确。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 119, "subject": "相关法", "id": "xg_425"},
  {"question": "3. 关于行政复议机关收到行政复议申请后，对材料进行审查，以下做法正确的有？(多选)", "options": ["A. 行政复议机关认为不属于本机关管辖，应当作出驳回行政复议申请的决定", "B. 行政复议机关认为不属于本机关管辖，应当作出不予受理的决定", "C. 行政复议机关认为复议申请材料表述不清楚，无法判断是否符合受理条件，通知申请人进行补正", "D. 行政复议申请人收到补正通知书后，无正当理由不补正的，行政复议机关应当作出不予受理的决定"], "answer": "BC", "explanation": "A、B选项，《复议法》第30条第2款规定：“对不符合规定的行政复议申请，行政复议机关应当在审查期限内决定不予受理并说明理由；不属于本机关管辖的，还应当在不予受理决定中告知申请人有管辖权的行政复议机关”，因此A选项错误，B选项正确。C、D选项，《复议法》第31条规定：“行政复议申请材料不齐全或者表述不清楚，无法判断行政复议申请是否符合《复议法》有关受理条件规定的，行政复议机关应当自收到申请之日起5日内书面通知申请人补正……申请人应当自收到补正通知之日起10日内提交补正材料。有正当理由不能按期补正的，行政复议机关可以延长合理的补正期限。无正当理由逾期不补正的，视为申请人放弃行政复议申请，并记录在案”，因此C选项正确，D选项错误。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 120, "subject": "相关法", "id": "xg_426"},
  {"question": "4. 张某对北京市公安局交通管理局依据电子技术监控设备记录的违法事实作出的行政处罚决定不服申请行政复议，以下说法哪些是正确的？(多选)", "options": ["A. 张某可以直接向北京市政府提交行政复议申请", "B. 张某可以通过北京市公安局交通管理局向北京市政府提交行政复议申请", "C. 北京市公安局交通管理局收到复议申请后，认为需要维持行政处罚决定的，应当自收到行政复议申请之日起5日内转送北京市政府", "D. 北京市公安局交通管理局收到复议申请后，认为决定不合法的，应当变更或撤销原行政处罚决定"], "answer": "ABCD", "explanation": "《复议法》第32条规定：“对当场作出或者依据电子技术监控设备记录的违法事实作出的行政处罚决定不服申请行政复议的，可以通过作出行政处罚决定的行政机关提交行政复议申请。行政机关收到行政复议申请后，应当及时处理；认为需要维持行政处罚决定的，应当自收到行政复议申请之日起五日内转送行政复议机关”。本题中，张某除可以直接向复议机关北京市政府提交行政复议申请外，也可以通过原行政机关北京市公安局交通管理局向北京市政府提交行政复议申请，因此A、B、C选项均正确。D选项，北京市公安局交通管理局收到复议申请后，认为决定不合法的，应当及", "type": "multiple", "topic": "专题四 行政复议法", "page": 120, "subject": "相关法", "id": "xg_427"},
  {"question": "5. 某行政复议机关受理王某提出的行政复议申请后，发现王某在申请行政复议之前已向人民法院提起行政诉讼并被受理。根据行政复议法及相关规定，该行政复议机关应当如何处理？(单选)", "options": ["A. 通知人民法院中止审理该行政诉讼", "B. 将该案移送人民法院一并审理", "C. 中止审理，在人民法院作出生效判决后继续审理", "D. 驳回该行政复议申请"], "answer": "D", "explanation": "《复议条例》第48条第1款规定：‘有下列情形之一的，行政复议机关应当决定驳回行政复议申请：……（二）受理行政复议申请后，发现该行政复议申请不符合行政复议法和本条例规定的受理条件的’，王某在申请行政复议之前已向人民法院提起行政诉讼并被受理，不符合行政复议申请条件，但行政复议机关是在受理该申请后才发现其不符合受理条件，应驳回该行政复议申请。", "type": "single", "topic": "专题四 行政复议法", "page": 120, "subject": "相关法", "id": "xg_428"},
  {"question": "1. 以下哪些属于行政复议机关审理行政复议案件的依据？(多选)", "options": ["A. 法律", "B. 法规", "C. 国务院部门规章", "D. 地方各级人民政府规章"], "answer": "ABCD", "explanation": "《复议法》第37条第1款规定:“行政复议机关依照法律、法规、规章审理行政复议案件”,因此A、B、C、D选项均正确。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 122, "subject": "相关法", "id": "xg_429"},
  {"question": "2. 对于行政复议审理过程中举证责任的分配,以下说法正确的有?(多选)", "options": ["A. 被申请人只对其作出的行政行为的合法性负有举证责任", "B. 被申请人对其作出的行政行为的合法性、适当性都负有举证责任", "C. 申请人不承担举证责任", "D. 申请人认为被申请人不履行法定职责的,负有举证责任"], "answer": "BD", "explanation": "A、B选项,《复议法》第44条第1款规定:“被申请人对其作出的行政行为的合法性、适当性负有举证责任”,因此A选项错误,B选项正确。根据《复议法》第44条第2款的规定,申请人认为被申请人不履行法定职责或者提出行政赔偿请求的,申请人负有举证责任,因此C选项错误,D选项正确。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 122, "subject": "相关法", "id": "xg_430"},
  {"question": "3. 下列有关行政复议机关调查取证说法正确的有?(多选)", "options": ["A. 行政复议机关可以主动调查取证", "B. 行政复议机关可以根据申请人的申请调查取证", "C. 行政复议机关可以根据行政机关的申请调查取证", "D. 行政复议机关调查取证时,行政复议人员不得少于3人"], "answer": "AB", "explanation": "A、B选项,行政复议机关调查取证方式有两种,一是主动调查取证,二是根据申请人的申请调查取证,因此A、B选项正确。C选项,由于行政机关本身具有较强的调查取证能力,且应当在行政行为作出之前就完成调查取证,因此行政机关不能申请复议机关调查取证,C选项错误。D选项,《复议法》第45条第2款规定:“调查取证时,行政复议人员不得少于两人……”,因此D选项错误。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 122, "subject": "相关法", "id": "xg_431"},
  {"question": "4. 根据行政复议法及相关规定,下列哪些说法是正确的?(多选)", "options": ["A. 行政复议决定作出前,申请人可以撤回行政复议申请", "B. 在行政复议期间,只有申请人才可以查阅、复制被申请人提出的有关材料", "C. 在行政复议期间,申请人可以查阅、复制所有的证据、"], "answer": "AD", "explanation": "A选项,《复议法》第41条规定:“行政复议期间有下列情形之一的,行政复议机关决定终止行政复议:(一)申请人撤回行政复议申请,行政复议机构准予撤回……”,因此行政复议申请可以撤回,A选项正确。B、C、D选项,《复议法》第47条规定:“行政复议期间,申请人、第三人及其委托代理人可以按照规定查阅、复制被申请人提出的书面答复、作出行政行为的证据、依...", "type": "multiple", "topic": "专题四 行政复议法", "page": 122, "subject": "相关法", "id": "xg_432"},
  {"question": "1. 甲市乙区卫健委因韩某未取得《医疗机构执业许可证》擅自执业,经研究,作出没收违法所得1200元和罚款7000元的决定。韩某不服,申请行政复议。关于此案,下列说法正确的是:(多选)", "options": ["A. 乙区政府应当在3日内进行审查,决定是否予以受理", "B. 乙区政府应当自受理之日起5日内将申请书副本发送给乙区卫健局", "C. 韩某申请复议材料不齐全的,自收到该行政复议申请之日起5日内书面通知韩某补正", "D. 乙区卫健局应当自收到行政复议申请副本之日起10日内提交作出行政行为的证据、依据和其他有关材料"], "answer": "CD", "explanation": "A选项,行政复议机关应当在收到行政复议申请的5日内审查是否符合受理条件,因此A选项错误。B选项,本题不符合适用简易程序的条件,应当适用普通程序,行政复议机构应当自行行政复议申请受理之日起7日内将申请书副本或笔录复印件发送给被申请人,因此B选项错误。C选项,《复议法》第31条第1款规定:“行政复议申请材料不齐全或者表述不清楚,无法判断行政复议申请是否符合本法第30条第1款规定的,行政复议机关应当自收到申请之日起5日内书面通知申请人补正……”,因此C选项正确。D选项,《复议法》第48条规定:“被申请人应当自收到行政复议申请书副本或者行政复议申请笔录复印件之日起10日内,提出书面答复,并提交作出行政行为的证据、依据和其他有关材料”,因此对于适用普通程序的案件,D选项正确。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 123, "subject": "相关法", "id": "xg_433"},
  {"question": "2. 关于行政复议委员会,以下说法正确的有?(多选)", "options": ["A. 行政复议机构认为审理的行政复议案件案情重大、复杂、疑难,应当提请行政复议委员会作出复议决定", "B. 省政府对本机关作出的行政行为进行复议,应当提请行政复议委员会作出咨询意见", "C. 国务院工作部门应当建立行政复议委员会", "D. 行政复议委员会除对行政复议案件提供咨询意见外,还可以就行政复议工作中的共性问题研究提出意见"], "answer": "BD", "explanation": "《复议法》第52条规定:“县级以上各级人民政府应当建立相关政府部门、专家、学者等参与的行政复议委员会,为办理行政复议案件提供咨询意见,并就行政复议工作中的重大事项和共性问题研究提出意见。行政复议委员会的组成和开展工作的具体办法,由国务院行政复议机构制定。审理行政复议案件涉及下列情形之一的,行政复议机构应当提请行政复议委员会提出咨询意见:(一)案情重大、疑难、复杂;……(三)省、自治区、直辖市对本机关作出的行政行为不服进行管辖的行政复议案件;……”,A选项复议委员会只能作出咨询意见,不能作出复议决定;B选项属于提请复议委员会作出咨询意见的情形;C选项目前并未要求国务院工作部门也成立行政复议委员会;D", "type": "multiple", "topic": "专题四 行政复议法", "page": 123, "subject": "相关法", "id": "xg_434"},
  {"question": "5. 根据行政复议法及相关规定，下列哪些情形下行行政复议中止？(多选)", "options": ["A. 作为申请人的公民丧失参加行政复议的行为能力，尚未确定法定代理人参加行政复议", "B. 作为申请人的公民下落不明", "C. 案件审理需要以其他案件的审理结果为依据，而其他案件尚未审结", "D. 作为申请人的法人或者其他组织终止，其权利义务的承受人放弃行政复议权利"], "answer": "ABC", "explanation": "《复议法》第39条第1款规定：“行政复议期间有下列情形之一的，行政复议中止：……（二）作为申请人的公民丧失参加行政复议的行为能力，尚未确定法定代理人参加行政复议；（三）作为申请人的公民下落不明……（八）行政复议案件审理需要以其他案件的审理结果为依据，而其他案件尚未审结……”，因此A、B、C选项属于复议中止情形，D选项属于复议终止情形。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 124, "subject": "相关法", "id": "xg_435"},
  {"question": "6. 行政复议期间出现哪种情形后，行政复议终止？(多选)", "options": ["A. 申请人撤回行政复议申请，行政复议机构准予撤回", "B. 作为申请人的公民死亡，其近亲属放弃行政复议"], "answer": "ABC", "explanation": "《复议法》第41条规定：“行政复议期间有下列情形之一的，行政复议机关决定终止行", "type": "multiple", "topic": "专题四 行政复议法", "page": 124, "subject": "相关法", "id": "xg_436"},
  {"question": "7. 某县公安局以钟某扰乱社会秩序为由对其作出行政处罚决定，钟某不服，向县政府申请行政复议。根据行政复议法及相关规定，关于行政复议期间该行政处罚决定的执行，下列哪些说法是正确的？(多选)", "options": ["A. 该行政处罚决定应当停止执行", "B. 该县公安局认为需要停止执行的，应当停止执行该行政处罚决定", "C. 该县政府认为需要停止执行的，应当停止执行该行政处罚决定", "D. 钟某申请停止执行，该县政府认为其要求合理决定停止执行的，应当停止执行该行政处罚决定"], "answer": "BCD", "explanation": "《复议法》第42条规定：“行政复议期间行政行为不停止执行；但是有下列情形之一的，应当停止执行：(一)被申请人认为需要停止执行；(二)行政复议机关认为需要停止执行；(三)申请人、第三人申请停止执行，行政复议机关认为其要求合理，决定停止执行……”，A选项中的说法过于绝对，因此A选项错误，B、C、D选项正确。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 125, "subject": "相关法", "id": "xg_437"},
  {"question": "8. 关于行政复议案件的审理和决定，下列哪些说法是正确的？(多选)", "options": ["A. 行政复议期间涉及专门事项需要鉴定的，当事人可自行委托鉴定机构进行鉴定", "B. 审理行政复议案件，申请人提出采取听证方式审理的，行政复议机构应当采取听证方式审理", "C. 申请人在行政复议决定作出前自愿撤回行政复议申请的，经行政复议机构同意，可以撤回", "D. 行政复议人员调查取证时应向当事人或者有关人员出示证件 第三节 行政复议附带审查程序"], "answer": "ACD", "explanation": "A选项，《复议条例》第37条规定：“行政复议期间涉及专门事项需要鉴定的，当事人可以自行委托鉴定机构进行鉴定，也可以申请行政复议机构委托鉴定机构进行鉴定”，A选项正确。B选项，《复议法》第50条第2款规定：“行政复议机构认为有必要听证，或者申请人请求听证的，行政复议机构可以组织听证”，B选项错误。C选项，根据《复议法》第41条的规定，申请人自愿撤回复议申请，经行政复议机构同意，可以撤回，行政复议终止，C选项正确。D选项，《复议法》第45条第2款规定：“调查取证时，行政复议人员不得少于两人，并应当出示行政复议工作证件”，D选项正确。因此，A、C、D选项正确。(法考2017，思维扩展)", "type": "multiple", "topic": "专题四 行政复议法", "page": 125, "subject": "相关法", "id": "xg_438"},
  {"question": "1. 适用普通程序审理的行政复议案件,行政复议机关应当自受理申请之日起最长(  )日内作出行政复议决定?(单选)", "options": ["A. 30", "B. 60", "C. 90", "D. 45"], "answer": "C", "explanation": "根据《复议法》第62条的规定,适用普通程序审理的行政复议案件,行政复议机关应当自受理申请之日起60日内作出行政复议决定,不能在规定期限内作出行政复议决定的,经批准,可以延长,延长期限最多不得超过30日,故最多为90日,因此C选项正确。(新编)", "type": "single", "topic": "专题四 行政复议法", "page": 126, "subject": "相关法", "id": "xg_439"},
  {"question": "2. 适用简易程序审理的行政复议案件,行政机关应当自受理申请之日起(  )日内作出行政复议决定?(单选)", "options": ["A. 30", "B. 60", "C. 15", "D. 10"], "answer": "A", "explanation": "《复议法》第62条第2款规定:“适用简易程序审理的行政复议案件,行政复议机关应当自受理申请之日起30日内作出行政复议决定”,因此A选项正确。(新编)", "type": "single", "topic": "专题四 行政复议法", "page": 126, "subject": "相关法", "id": "xg_440"},
  {"question": "4. 定中公司在某县建立了一家生鸡养殖场,通过暗管的方式违法排污,县生态环境局对其罚款50万元。定中公司不服,向县政府申请行政复议。本案的下列做法违反法律规定的有: (多选)", "options": ["A. 县政府指定县政府法制办干部胡某单独审理此案", "B. 县政府在60日内作出了复议决定", "C. 县政府认为处罚过轻,将罚款变更为60万元", "D. 县政府认为本案疑难复杂,主动组织听证"], "answer": "AC", "explanation": "A选项,《复议条例》第32条规定:“行政复议机构审理行政复议案件,应当由2名以上行政复议人员参加”,因此A选项违反规定。B选项,《复议法》第62条第1款规定:“适用普通程序审理的行政复议案件,行政复议机关应当自受理申请之日起60日内作出行政复议决定……”,因此B选项符合规定。C选项,《复议法》第63条第2款规定:“行政复议机关不得作出对申请人更为不利的变更决定……”,因此C选项违反规定。D选项,《复议法》第50条第1款规定:“审理重大、疑难、复杂的行政复议案件,行政复议机构应当组织听证”,因此D选项符合规定。(2018改编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 127, "subject": "相关法", "id": "xg_441"},
  {"question": "5. 根据行政复议法及相关规定,以下哪些情形复议机关应当变更行政行为?(多选)", "options": ["A. 事实清楚,证据确凿,适用依据正确,程序合法,但是内容不适当", "B. 事实清楚,证据确凿,程序合法,但是未正确适用依据", "C. 事实不清、证据不足,经行政复议机关查清事实和证据", "D. 违反法定程序"], "answer": "ABC", "explanation": "《复议法》第63条第1款规定:“行政行为有下列情形之一的,行政复议机关决定变更该行政行为:(一)事实清楚,证据确凿,适用依据正确,程序合法,但是内容不适当;(二)事实清楚,证据确凿,程序合法,但是未正确适用依据;(三)事实不清、证据不足,经行政复议机关查清事实和证据”,因此A、B、C选项正确,D选项属于应当撤销行政行为的情形。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 127, "subject": "相关法", "id": "xg_442"},
  {"question": "6. 根据行政复议法及相关规定,行政行为具有下列哪些情形的,行政复议机关可以决定撤销该行政行为,并可以责令被申请人在一定期限内重新作出行政行为?(多选)", "options": ["A. 主要事实不清、证据不足", "B. 违反法定程序", "C. 滥用职权", "D. 适用的依据不合法"], "answer": "ABCD", "explanation": "《复议法》第64条第1款规定:“行政行为有下列情形之一的,行政复议机关决定撤销或者部分撤销该行政行为,并可以责令被申请人在一定期限内重新作出行政行为:(一)主要事实不清、证据不足;(二)违反法定程序;(三)适用的依据不合法;(四)超越职权或者滥用职权”,因此A、B、C、D选项均正确。(2016改编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 127, "subject": "相关法", "id": "xg_443"},
  {"question": "9. 河北省石家庄市市场监督管理局在市场调查过程中，认为某商户所销售的化妆品为假冒专利产品，对该产品予以没收并进行处罚，该商户不服，向石家庄市人民政府提出行政复议请求，在行政复议申请过程中，该商户提交了专利证明文件，石家庄市市场监督管理局取消了处罚决定，并对没收的产品予以归还，关于行政复议机关的处理，以下说法正确的有？(多选)", "options": ["A. 由于行政机关已经改变了其行政行为，因此行政复议机关应当终止审理", "B. 行政复议机关应当撤销原行政行为", "C. 如果申请人要求撤销原行政行为的，行政复议机关应当确认该行政行为违法", "D. 如果申请人要求确认该行政行为违法的，行政复议机关应当确认该行政行为违法"], "answer": "CD", "explanation": "A选项，《复议条例》第39条规定：“行政复议期间被申请人改变原具体行政行为的，不影响行政复议案件的审理。但是，申请人依法撤回行政复议申请的除外”，因此A选项错误。根据《复议法》第65条的规定，被申请人改变原违法行政行为，申请人仍要求撤销或者确认该行政行为违法的，行政复议机关确认该行政行为违法。本题中，石家庄市市场监督管理局取消了处罚决定，并对没收的产品予以归还，已经改变原违法行政行为，申请人仍要求撤销或者确认该行政行为违法，行政复议机关应当确认该行政行为违法，并不需要撤销原行政行为，因此B选项错误，C、D选项正确。（新编）", "type": "multiple", "topic": "专题四 行政复议法", "page": 128, "subject": "相关法", "id": "xg_444"},
  {"question": "10. 甲公司通过暗管的方式直接将污水排入地下，被区生态环境局吊销排污许可证，罚款500万元。甲公司对此不服，申", "options": ["A. 复议机关若认定该行为违反法定程序，可以决定变更", "B. 复议机关若认定罚款500万合法但不适当，可以决定变更", "C. 复议机关若认定吊销排污许可证和罚款均合法且适当，作出维持决定", "D. 复议机关可以对双方进行调解"], "answer": "BCD", "explanation": "A选项中违反法定程序复议机关可以选择决定撤销或者部分撤销该行政行为，并可以责令被申请人在一定期限内重新作出行政行为，不能进行变更。B选项中行政行为不适当可以变更。C选项中行政行为如果合法且适当可以作出维持决定。D选项，行政复议机关办理行政复议案件，可以进行调解，因此D选项正确。（2018改编）", "type": "single", "topic": "专题四 行政复议法", "page": 128, "subject": "相关法", "id": "xg_445"},
  {"question": "11. 王某认为某行政机关不履行法定职责而申请行政复议，行政复议机关受理后发现该行政机关没有相应法定职责。根据行政复议法及相关规定，该行政复议机关应当如何处理？(单选)", "options": ["A. 作出确认原行政行为无效的决定", "B. 作出终止该行政复议的决定", "C. 作出该行政复议申请视为撤回的决定", "D. 作出驳回该行政复议请求的决定"], "answer": "D", "explanation": "《复议法》第69条规定：“行政复议机关受理申请人认为被申请人不履行法定职责的行政复议申请后，发现被申请人没有相应法定职责或者在受理前已经履行法定职责的，决定驳回申请人的行政复议请求”，因此A、B、C选项错误，D选项正确。(2012)", "type": "single", "topic": "专题四 行政复议法", "page": 129, "subject": "相关法", "id": "xg_446"},
  {"question": "12. 行政复议机关在受理行政复议申请后，将有关材料转送至被申请人，要求被申请人在收到材料之日起10日内提出书面答复、提交作出行政行为的证据、依据和有关材料，期满后被申请人未提交，行政复议机关可以作出下列哪些决定?(多选)", "options": ["A. 视为该行政行为没有证据、依据，行政复议机关决定撤销或者部分撤销该行政行为", "B. 视为该行政行为没有证据、依据，行政复议机关确认该行政行为违法", "C. 视为该行政行为没有证据、依据，行政复议机关确认该行政行为无效", "D. 如果该行政行为涉及第三人合法权益，第三人提供了被申请人作出行政行为的证据和依据，行政复议机关仍应视为该行政行为没有证据、依据"], "answer": "ABC", "explanation": "《复议法》第70条规定：“被申请人不按照本法第48条、第54条的规定提出书面答复、提交作出行政行为的证据、依据和其他有关材料的，视为该行政行为没有证据、依据，行政复议机关决定撤销、部分撤销该行政行为，确认该行政行为违法、无效或者决定被申请人在一定期限内履行，但是行政行为涉及第三人合法权益，第三人提供证据的除外”，因此A、B、C选项正确。D选项，第三人提交了行政机关作出行政行为的证据，如果能够证明行政行为合法的，应当作为行政行为合法的依据，因此D选项错误。(新编)", "type": "multiple", "topic": "专题四 行政复议法", "page": 129, "subject": "相关法", "id": "xg_447"},
  {"question": "13. 根据行政复议法及相关规定，下列说法正确的是？ (多选) - 128 -", "options": ["A. 申请人在申请行政复议时可以一并提出行政赔偿请求", "B. 申请人在申请行政复议时没有提出行政赔偿请求的，对财产权的行政行为，行政复议机关也可作出行政赔偿决定", "C. 行政复议决定书一经送达，即发生法律效力", "D. 行政复议决定书送达后，15个工作日后未起诉的，发生法律效力"], "answer": "ABC", "explanation": "A选项，根据《复议法》第72条第1款的规定，申请行政复议时可以一并提出行政赔偿请求，因此A选项正确。B选项，《复议法》第72条第2款规定：“申请人在申请行政复议时没有提出行政赔偿请求的，行政复议机关在依法决定撤销或者部分撤销、变更罚款，撤销或者部分撤销违法集资、没收财物、征收征用、摊派费用以及对财产", "type": "multiple", "topic": "专题四 行政复议法", "page": 129, "subject": "相关法", "id": "xg_448"},
  {"question": "根据行政复议法及相关规定，公民、法人或者其他组织认为行政机关的行政行为所依据的下列哪些规范性文件不合法，在对行政行为申请行政复议时，可以一并向行政复议机关提出对该规范性文件的附带审查申请？（多选）", "options": ["A. 国务院部、委员会规章", "B. 地方人民政府规章", "C. 县级以上地方各级人民政府及其工作部门的规范性文件", "D. 国务院部门的规范性文件"], "answer": "CD", "explanation": "根据《行政复议法》第13条规定，公民、法人或者其他组织认为行政机关的行政行为所依据的下列规范性文件不合法，可以一并向行政复议机关提出对该规范性文件的附带审查申请：（一）国务院部门的规范性文件；（二）县级以上地方各级人民政府及其工作部门的规范性文件；（三）乡、镇人民政府的规范性文件；（四）法律、法规、规章授权的组织的规范性文件。但规章不能附带审查，因此A、B选项的规章不能附带审查，C、D选项的规范性文件可以附带审查。", "type": "multiple", "topic": "专题四 行政复议法", "page": 129, "subject": "相关法", "id": "xg_449"},
  {"question": "当事人对某省知识产权局的行政行为不服提起行政复议时，可以一并请求行政复议机关对该行政行为所依据的下列哪一文件进行审查？（单选）", "options": ["A. 《中华人民共和国专利法实施细则》", "B. 该省人大常委会制定的《专利保护条例》", "C. 国家知识产权局制定的《专利行政执法办法》", "D. 该省知识产权局制定的《关于加强专利保护的规定》"], "answer": "D", "explanation": "A选项《中华人民共和国专利法实施细则》属于行政法规；B选项《专利保护条例》属于地方性法规；C选项《专利行政执法办法》属于国家知识产权局制定的部门规章；D选项《关于加强专利保护的规定》属于县级以上地方各级人民政府及其工作部门的规范性文件，可以一并向行政复议机关提出附带审查申请。因此D选项正确。", "type": "single", "topic": "专题四 行政复议法", "page": 129, "subject": "相关法", "id": "xg_450"},
  {"question": "行政复议期间，申请人以外的公民管某与被审查的行政行为有利害关系。根据行政复议法及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 行政复议机构可以追加管某为行政复议申请人，通知其参加行政复议", "B. 行政复议机构可以通知管某作为第三人参加行政复议", "C. 管某不参加行政复议的，该行政复议终止", "D. 管某不参加行政复议的，不影响该行政复议案件的审理"], "answer": "BD", "explanation": "《复议法》第16条规定：‘申请人以外的同被申请行政复议的行政行为或者行政复议案件处理结果有利害关系的公民、法人或者其他组织，可以作为第三人申请参加行政复议，或者由行政复议机构通知其作为第三人参加行政复议。第三人不参加行政复议，不影响行政复议案件的审理’，因此A、C选项错误，B、D选项正确。（2013改编）", "type": "multiple", "topic": "专题四 行政复议法", "page": 131, "subject": "相关法", "id": "xg_451"},
  {"question": "审查通过后，将甲医院的申请材料及相关资料上报科技部，科技部审核后，对外作出了不予批准的决定。下列说法正确的是？（多选）", "options": ["A. 科技部可以要求甲医院重复提供申请材料", "B. 如果甲医院提起诉讼，省科技厅和科技部为共同被告", "C. 如果甲医院提起复议，复议被申请人是科技部", "D. 本案应当先行政复议，才能提起行政诉讼"], "answer": "BC", "explanation": "根据行政复议法的相关规定，行政机关作出具体行政行为后，当事人不服的，可以申请行政复议。如果复议决定仍不服，可以提起行政诉讼。因此，选项D错误。选项A中，科技部在审核过程中可以要求补充材料，但不是在作出不予批准决定之后。选项B正确，如果甲医院提起诉讼，科技部作为作出具体行政行为的机关，是被告。选项C正确，复议被申请人是作出具体行政行为的机关，即科技部。", "type": "multiple", "topic": "专题四 行政复议法", "page": 133, "subject": "相关法", "id": "xg_452"},
  {"question": "根据行政复议法及相关规定，下列关于提出行政复议申请的表述哪些是正确的？（多选）", "options": ["A. 除法律另有规定外，当事人认为行政行为侵犯其合法权益的，可以知道或者应当知道该行政行为之日起90日内提出行政复议申请", "B. 行政机关作出行政行为时，告知当事人行政复议申请的，当事人最迟可以知道或者应当知道该行政行为之日起1年内申请行政复议", "C. 当事人因不动产提出行政复议申请的，最长可以自行行为作出之日起20年内提出行政复议申请", "D. 除不动产以外，当事人提出行政复议申请的，最长自行行为作出之日起5年内提出行政复议申请"], "answer": "BCD", "explanation": "根据行政复议法的规定，当事人应当在知道或者应当知道行政行为之日起一定期限内提出行政复议申请。选项A中的90日是通常的申请期限，但法律另有规定时除外。选项B正确，如果行政机关告知了行政复议申请的权利，当事人有1年的申请期限。选项C和D分别规定了不动产和其他情况下的最长申请期限。", "type": "multiple", "topic": "专题四 行政复议法", "page": 133, "subject": "相关法", "id": "xg_453"},
  {"question": "因李某长期在外打工，其存放在路边的一辆车被道办事处当作无主物予以没收处理，以下说法哪些是正确的？（多选）", "options": ["A. 李某不服该决定的，应当知道或者应当知道该决定之日起60日内提出行政复议申请", "B. 行政机关作出行政行为时，告知当事人行政复议申请的，当事人最迟可以知道或者应当知道该行政行为之日起1年内申请行政复议", "C. 当事人因不动产提出行政复议申请的，最长可以自行行为作出之日起20年内提出行政复议申请", "D. 除不动产以外，当事人提出行政复议申请的，最长自行行为作出之日起5年内提出行政复议申请"], "answer": "ABCD", "explanation": "根据行政复议法的规定，李某应当在知道或者应当知道行政行为之日起60日内提出行政复议申请，因此选项A正确。选项B正确，如果行政机关告知了行政复议申请的权利，当事人有1年的申请期限。选项C和D分别规定了不动产和其他情况下的最长申请期限。", "type": "multiple", "topic": "专题四 行政复议法", "page": 133, "subject": "相关法", "id": "xg_454"},
  {"question": "市场监管管理总局针对甲公司收购乙公司达到经营者集中申报标准而未进行申报的情况作出行政处罚决定书，对甲公司处以20万元罚款。根据行政复议法及相关规定，甲公司可以通过下列哪些途径寻求救济？（多选）", "options": ["A. 向市场监督管理总局申请行政复议", "B. 向国务院申请行政复议", "C. 依法申请行政复议后，对复议决定不服的，可以向人民法院起诉", "D. 依法申请行政复议后，对复议决定不服的，可以向国务院申请最终裁决"], "answer": "ACD", "explanation": "根据《复议法》第25、26条的规定，对市场监督管理总局的行政行为不服的，应向市场监督管理总局申请行政复议，对复议决定不服的，可以向人民法院起诉或向国务院申请最终裁决，因此A、C、D选项正确，B选项错误。", "type": "multiple", "topic": "专题四 行政复议法", "page": 137, "subject": "相关法", "id": "xg_455"},
  {"question": "某专利申请人对国家知识产权局不予受理其申请的决定不服，根据行政复议法及相关规定，他可以通过下列哪些途径寻求救济？（多选）", "options": ["A. 向国家知识产权局申请行政复议", "B. 向国务院申请行政复议", "C. 依法申请行政复议后，对复议决定仍然不服的，可以向人民法院起诉", "D. 依法申请行政复议后，对复议决定仍然不服的，可以向国务院申请最终裁决"], "answer": "ACD", "explanation": "根据《复议法》第25条规定：'国务院部门管辖下列行政复议案件：（一）对本部门作出的行政行为不服的……'；《复议法》第26条规定：'对……国务院部门……作出的行政复议决定不服的，可以向人民法院提起行政诉讼；也可以向国务院申请裁决，国务院依照本法的规定作出最终裁决'。本题中，国家知识产权局属于国务院部门，申请人可以向国家知识产权局申请行政复议，对行政复议决定不服的，可以向人民法院提起行政诉讼，也可以向国务院申请最终裁决，因此A、C、D选项正确，B选项错误。", "type": "multiple", "topic": "专题四 行政复议法", "page": 137, "subject": "相关法", "id": "xg_456"},
  {"question": "根据行政复议法及相关规定，下列关于行政复议被申请人的哪些说法是正确的？（多选）", "options": ["A. 两个以上行政机关以共同的名义作出同一行政行为的，其中任何一个行政机关可以单独作为被申请人", "B. 法律、法规、规章授权的组织作出行政行为的，该组织是被申请人", "C. 行政机关委托的组织作出行政行为的，被委托的组织是被申请人", "D. 作出行政行为的行政机关被撤销或者职权变更的，继续行使其职权的行政机关是被申请人"], "answer": "AC", "explanation": "两个以上行政机关以共同的名义作出同一行政行为的，共同作出行政行为的行政机关是被申请人。行政机关委托的组织作出行政行为的，委托的行政机关是被申请人。作出行政行为的行政机关被撤销或者职权变更的，继续行使其职权的行政机关是被申请人，因此A、C选项错误，B、D选项正确。（新编）", "type": "multiple", "topic": "专题四 行政复议法", "page": 132, "subject": "相关法", "id": "xg_457"},
  {"question": "对于复议申请人委托代理人参加复议的，以下哪些文件应当提交至行政复议机构？（多选）", "options": ["A. 载明委托事项、权限和期限的授权委托书", "B. 委托人身份证明文件", "C. 变更代理人权限的书面文件", "D. 被委托人身份证明文件"], "answer": "ABCD", "explanation": "根据《行政复议法》第17条，申请人、第三人委托代理人的，应当向行政复议机构提交授权委托书，委托人及被委托人的身份证明文件。授权委托书应当载明委托事项、权限和期限。申请人、第三人变更或者解除代理人权限的，应当书面告知行政复议机构。因此A、B、C、D选项正确。（新编）", "type": "multiple", "topic": "专题四 行政复议法", "page": 132, "subject": "相关法", "id": "xg_458"},
  {"question": "某行政复议机关受理行政复议申请后，发现该行政复议申请不符合行政复议法和行政复议法实施条例规定的受理条件。根据行政复议法及相关规定，该行政复议机关应当如何处理？（单选）", "options": ["A. 作出中止行政复议的决定", "B. 作出终止行政复议的决定"], "answer": "B", "explanation": "根据《行政复议法》相关规定，若行政复议机关在受理后发现申请不符合受理条件，应当作出终止行政复议的决定，而非中止。中止适用于暂时无法继续审理的情形，而终止则适用于不具备受理条件的情况。", "type": "single", "topic": "专题四 行政复议法", "page": 140, "subject": "相关法", "id": "xg_459"},
  {"question": "北京市朝阳区公安分局以李某制造噪声干扰他人正常生活为由，处以500元罚款。李某不服，可以向哪些机关申请复议？（多选）", "options": ["A. 朝阳区公安分局", "B. 朝阳区政府", "C. 北京市公安局", "D. 北京市政府"], "answer": "BD", "explanation": "《复议法》第24条第4款规定：‘对省级以上地方各级人民政府工作部门依法设立的派出机构依照法律、法规、规章规定，以派出机构的名义作出的行政行为不服的行政复议案件，由本级人民政府管辖；其中，对直辖市、设区的市人民政府工作部门按照行政区划设立的派出机构作出的行政行为不服的，也可以由其所在地的人民政府管辖’。本题中，朝阳公安分局是北京市公安局的派出机构，对政府工作部门派出机构不服的案件，可以由本级政府管辖（即北京市政府），也可以由派出机构所在地政府管辖（即朝阳区政府），因此B、D选项正确。", "type": "multiple", "topic": "专题四 行政复议法", "page": 138, "subject": "相关法", "id": "xg_460"},
  {"question": "国务院自然资源部东海局是国务院自然资源部的派出机构，在开展例行检查过程中，发现辽宁省阜新市彰武县大德村股份经济合作社存在未经批准占用耕地建设风景区的问题，遂以自己的名义作出处罚决定，该合作社不服，应当向下列哪个机构提出行政复议？（单选）", "options": ["A. 辽宁省阜新市彰武县人民政府", "B. 辽宁省阜新市人民政府", "C. 国务院", "D. 国务院自然资源部"], "answer": "D", "explanation": "根据《复议法》第25条第（二）项的规定，对国务院部门依法设立的派出机构依照法律、行政法规、部门规章规定，以派出机构的名义作出的行政行为不服的，向该国务院部门申请行政复议。本题中，国务院自然资源部东海局是国务院自然资源部的派出机构，对该派出机构的行政行为不服，应当向国务院部门即国务院自然资源部申请复议，因此D选项正确。", "type": "single", "topic": "专题四 行政复议法", "page": 138, "subject": "相关法", "id": "xg_461"},
  {"question": "肖某提出农村宅基地用地申请，乡政府审核后报县政府审批，县政府批准后，肖某认为审批程序违法，欲申请行政复议，应向哪个机关申请？（单选）", "options": ["A. 县政府", "B. 乡政府", "C. 市政府", "D. 省政府"], "answer": "A", "explanation": "根据《复议法》相关规定，对县级以上地方各级人民政府工作部门的具体行政行为不服的，由申请人选择，可以向该部门的本级人民政府申请行政复议，也可以向上一级主管部门申请行政复议。本案中，县政府是作出具体行政行为的机关，因此应向县政府申请行政复议。故A选项正确。", "type": "single", "topic": "专题四 行政复议法", "page": 138, "subject": "相关法", "id": "xg_462"},
  {"question": "公民、法人或者其他组织依法提出行政复议申请，行政复议机关无正当理由不予受理的情况下，下列说法正确的是？", "options": ["A. 上级行政机关应当责令其纠正，但不可以直接受理", "B. 上级行政机关应当责令其纠正，必要时，上级行政机关也可以直接受理", "C. 上级行政机关无权责令其纠正，必要时，上级行政机关可以直接受理", "D. 上级行政机关无权责令其纠正，也不能直接受理"], "answer": "B", "explanation": "《复议法》第35条规定：‘公民、法人或者其他组织依法提出行政复议申请，行政复议机关无正当理由不予受理、驳回申请或者受理后超过行政复议期限不作答复的，申请人有权向上级行政机关反映，上级行政机关应当责令其纠正；必要时，上级行政复议机关也可以直接受理’。因此A、C、D选项错误，B选项正确。（2019改编）", "type": "single", "topic": "专题四 行政复议法", "page": 141, "subject": "相关法", "id": "xg_463"},
  {"question": "行政复议申请材料不齐全或者表述不清楚，无法判断行政复议申请是否符合受理条件的，行政复议机关应当书面通知申请人补正，申请人收到行政机关发出的补正通知书后，应当自收到补正通知之日起（）日内提交补正材料？", "options": ["A. 10", "B. 7", "C. 15", "D. 30"], "answer": "A", "explanation": "《复议法》第31条第2款规定：‘申请人应当自收到补正通知之日起10日内提交补正材料’。因此，A选项正确。（新编）", "type": "single", "topic": "专题四 行政复议法", "page": 141, "subject": "相关法", "id": "xg_464"},
  {"question": "某外国芯片公司涉嫌纵向垄断，国家市场监督管理总局对其作出罚款1亿元的处罚决定，该公司不服，提起行政复议，下列说法正确的是？（多选）", "options": ["A. 如果复议过程中，国家市场监督管理总局将罚款变更为8000万元，复议应当中止", "B. 复议机关是国家市场监督管理总局", "C. 芯片公司对复议决定不服，可以向国务院申请裁决", "D. 复议机关应当组织听证"], "answer": "BCD", "explanation": "A选项，《复议条例》第39条规定：‘行政复议期间被申请人改变原具体行政行为的，不影响行政复议案件的审理。但是，申请人依法撤回行政复议申请的除外’，芯片公司并未撤回复议申请，不影响复议案件的审理，A选项错误。B选项，《复议法》第25条规定：‘国务院部门管辖下列行政复议案件：（一）对本部门作出的行政行为不服的……’，本案的复议机关为国家市场监督管理总局，B选项正确。C选项，《复议法》第26条规定：‘对省、自治区、直辖市人民政府依照本法第二十四条第二款的规定、国务院部门依照本法第二十五条第一项的规定作出的行政复议决定不服的，可以向人民法院提起行政诉讼，可以向人民法院提起行政诉讼；也可以向国务院申请裁决，国务院依照《行政复议法》的规定作出最终裁决’，C选项正确。D选项，《复议法》第50条第1款规定：‘审理重大、疑难、复杂的行政复议案件，行政复议机构应当组织听证’，本案标的额为1亿元，属于重大、复杂的复议案件，属于应当组织听证的情形，D选项正确。因此，B、C、D选项正确。", "type": "multiple", "topic": "专题四 行政复议法", "page": 146, "subject": "相关法", "id": "xg_465"},
  {"question": "根据《治安管理处罚法》第64条，偷开他人机动车的，处500元以上1000元以下罚款；情节严重的，处10日以上15日以下拘留，并处罚款800元。小王因偷开单位的车被县公安局处以拘留12日，并处罚款800元。小王承认自己确实偷开单位的轿车，但认为县公安局的处罚太重而向县政府申请复议。在复议过程中的下列哪一做法是正确的？", "options": ["A. 在复议过程中，小王申请县政府调解，县政府决定复议终止小王的罚款800元的口头调解协议", "B. 选项B", "C. 选项C", "D. 选项D"], "answer": "A", "explanation": "解析内容", "type": "single", "topic": "专题四 行政复议法", "page": 152, "subject": "相关法", "id": "xg_466"},
  {"question": "某生态环境局以甲公司在生产过程中使用不符合国家标准的锅炉设备，超排排放污染物为由，查封甲公司用以生产的锅炉，后对甲公司罚款8万元，甲公司不服，向县政府申请复议。下列哪一说法是正确的？（单选）", "options": ["A. 紧急情况下，查封可以不听取甲公司的陈述申辩", "B. 如果县政府认为本案事实清楚，证据确凿，适用法律正确，程序合法，但是内容不适当，将对甲公司罚款改为罚款10万元", "C. 在复议决定作出前当事人达成和解协议，复议程序自动终止", "D. 如果县政府认为本案事实不清，经审核事实清楚后，可以作出改变决定"], "answer": "D", "explanation": "《行政复议法》第32条第1款规定：“行政复议决定作出前当事人达成和解协议，复议程序自动终止。”", "type": "single", "topic": "专题四 行政复议法", "page": 155, "subject": "相关法", "id": "xg_467"},
  {"question": "某市知识产权局在行政执法中，向假冒专利的企业甲作出罚款3万元的行政处罚决定。企业甲不服，申请行政复议，下列说法正确的是？（多选）", "options": ["A. 当事人经调解达成协议的，行政复议机关应当制作行政复议调解书", "B. 行政调解书经行政复议机关盖章后即具有法律效力", "C. 在行政复议中，如果复议机关认为罚款明显偏轻，其可以变更被申请复议的行政行为，将行政处罚改为罚款4万元", "D. 本案可以进行行政调解"], "answer": "AD", "explanation": "A、B选项，《复议条例》第50条规定：\"……当事人经调解达成协议的，行政复议机关应当制作行政复议调解书……行政复议调解书经双方当事人签字，即具有法律效力……\"，因此A选项正确，B选项错误。C选项，复议机关不能作出对申请人更为不利的变更决定，因此C选项错误。D选项，行政复议机关办理行政复议案件，可以进行调解，因此D选项正确。（2019改编）", "type": "multiple", "topic": "专题四 行政复议法", "page": 151, "subject": "相关法", "id": "xg_468"},
  {"question": "局拒绝进行重新登记。田某可以采取下列哪一项措施？（单选）", "options": ["A. 申请法院强制执行", "B. 对某县公安局的行为申请行政复议", "C. 向法院提起行政诉讼", "D. 请求某县政府责令某县公安局登记"], "answer": "C", "explanation": "根据《行政复议法》相关规定，行政机关不依法履行法定职责的，公民、法人或者其他组织可以依法申请行政复议或提起行政诉讼。但本题中，田某已无法通过行政复议解决，应直接向法院提起行政诉讼。因此，C选项正确。", "type": "single", "topic": "专题四 行政复议法", "page": 153, "subject": "相关法", "id": "xg_469"},
  {"question": "商务部对某一企业作出处以30万元罚款的行政处罚，该企业不服，申请行政复议，下列说法正确的是？（多选）", "options": ["A. 该企业可以向国务院申请复议", "B. 该企业可以向商务部申请复议", "C. 该企业如果对行政复议决定不服，可以提起行政诉讼", "D. 如在复议过程中，企业自愿撤回复议申请的，不得再以同一事实和理由提出行政复议申请"], "answer": "BCD", "explanation": "A选项错误，因为国务院不是行政复议机关，企业不能向国务院申请复议；B选项正确，商务部是作出处罚的部门，企业可向其申请复议；C选项正确，根据《行政复议法》，对复议决定不服可提起行政诉讼；D选项正确，《行政复议条例》第38条第2款规定，申请人撤回复议申请的，不得再以同一事实和理由提出行政复议申请。因此，B、C、D选项正确。", "type": "multiple", "topic": "专题四 行政复议法", "page": 153, "subject": "相关法", "id": "xg_470"},
  {"question": "国家金融监督管理总局以其银行金融机构未按照规定提供报表、报告等资料，依据《银行业监督管理法》对其处以20万元罚款。该机构不服，申请行政复议，下列说法不正确的是？（多选）", "options": ["A. 如果复议期间国家金融监督管理总局将罚款数额改为10万元，行政复议中止", "B. 复议机关应当是国家金融监督管理总局", "C. 如果该机构与国家金融监督管理总局在复议决定作出前自愿达成和解协议，行政复议中止", "D. 申请行政复议期间为行政行为作出之日起6个月"], "answer": "ACD", "explanation": "A选项，《复议条例》第39条规定：‘行政复议期间被申请人改变原具体行政行为的，不影响行政复议案件的审理。但是，申请人依法撤回行政复议申请的除外’，行政机关改变原行政行为，复议程序并不当然中止，A选项错误。B选项，《复议法》第25条规定：‘国务院部门管辖下列行政复议案件：（一）对本部门作出的行政行为不服的……’，国家金融监督管理总局作为国务院部门，复议机关应当为国家金融监督管理总局，B选项正确。C选项，《复议法》第39条第1款规定：‘行政复议期间有下列情形之一的，行政复议中止：……（六）依照《行政复议法》规定进行调解、和解，申请人和被申请人同意中止……’，达成和解协议并不当然中止复议程序，还要求当事人同意中止，C选项错误。D选项，《复议法》第20条第1款规定：‘公民、法人或者其他组织认为行政行为侵犯其合法权益的，可以自知道或者应当知道该行政行为之日起60日内提出行政复议申请；但是法律规定的申请期限超过60日的除外’，D选项错误。本题选择不正确的选项，因此A、C、D选项当选。", "type": "multiple", "topic": "专题四 行政复议法", "page": 154, "subject": "相关法", "id": "xg_471"},
  {"question": "某区市场监督管理局对一公司未取得出版物经营许可证销售电子出版物100套的行为，予以取缔，并罚款6000元。该公司向区政府申请复议。下列哪些说法是正确的？（多选）", "options": ["A. 公司可委托代理人代为参加行政复议", "B. 在复议过程中区市场监督管理局不得自行向申请人和其他有关组织或个人收集证据", "C. 区政府应采取开庭审理方式审查此案", "D. 如果区市场监督管理局的决定明显不当，区政府应予以撤销"], "answer": "AB", "explanation": "A选项，《复议法》第17条规定：‘申请人、第三人可以委托一至二名律师、基层法律服务工作者或者其他代理人代为参加行政复议’，A选项正确。B选项，《复议法》第46条第1款规定：‘行政复议期间，被申请人不得自行向申请人和其他有关单位或者个人收集证据；自行收集的证据不作为认定行政行为合法性、适当性的依据’，B选项正确。C选项，《复议法》第49条规定：‘适用普通程序审理的行政复议案件，行政复议机构应当当面或者通过互联网、电话等方式听取当事人的意见，并将听取的意见记录在案。因当事人原因不能听取意见的，可以书面审理’，开庭审理为行政诉讼的审理方式，C选项错误。D选项，《复议法》第63条规定：‘行政行为有下列情形之一的，行政复议机关决定变更该行政行为：（一）事实清楚，证据确凿，适用依据正确，程序合法，但是内容不适当……’，本题中行政处罚内容不适当的，复议机关应当决定变更，D选项错误。因此，A、B选项正确。", "type": "multiple", "topic": "专题四 行政复议法", "page": 154, "subject": "相关法", "id": "xg_472"},
  {"question": "根据行政复议法、行政诉讼法及相关规定，关于行政复议和行政诉讼，下列说法哪些是正确的？(多选)", "options": ["A. 行政复议案件和行政诉讼案件都可以由一人进行审理", "B. 行政复议案件和行政诉讼案件的审理期限不同", "C. 行政复议机关收复的复议费用和人民法院收复的诉讼费用相同", "D. 提出行政复议申请的期限和提起行政诉讼的期限不同"], "answer": "BD", "explanation": "行政复议案件和行政诉讼案件的审理期限不同，提出行政复议申请的期限和提起行政诉讼的期限也不同。行政复议案件一般由行政复议机关审理，而行政诉讼案件由人民法院审理，所以A项错误。行政复议机关和人民法院收取的费用可能不同，因此C项也不正确。", "type": "multiple", "topic": "专题四 行政复议法", "page": 159, "subject": "相关法", "id": "xg_473"},
  {"question": "甲行政机关以违反法律相关规定为由对某公司进行了处罚。该公司不服，向乙复议机关申请行政复议。乙复议机关作出维持原具体行政行为的复议决定。该公司仍不服，欲向人民法院提起诉讼。根据行政诉讼法及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 应以甲行政机关为被告", "B. 应以乙复议机关为被告", "C. 甲行政机关所在地人民法院对此案有管辖权", "D. 乙复议机关所在地人民法院对此案有管辖权"], "answer": "CD", "explanation": "《行政诉讼法》第26条第2款规定：‘经复议的案件，复议机关决定维持原行政行为的，作出原行政行为的行政机关和复议机关是共同被告……’，《行政诉讼法》第18条第1款规定：‘……经复议的案件，也可以由复议机关所在地人民法院管辖’。本题中，乙复议机关作出维持的复议决定，应以甲乙为共同被告，甲、乙地人民法院均有管辖权，因此A、B选项错误，C、D选项正确。", "type": "multiple", "topic": "专题四 行政复议法", "page": 163, "subject": "相关法", "id": "xg_474"},
  {"question": "某县公安局对张某作出了一项行政处罚决定。张某不服，遂向该县人民政府申请行政复议，但该县人民政府未在法定期限内作出复议决定。张某欲向人民法院提起行政诉讼。根据行政诉讼法及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 张某因对该行政处罚决定不服提起诉讼的，应当以该县公安局为被告", "B. 张某因对该行政处罚决定不服提起诉讼的，应当以该县人民政府为被告", "C. 张某因对该县人民政府不作为不服提起诉讼的，应当以该县人民政府为被告"], "answer": "AC", "explanation": "《行政诉讼法》第26条第3款规定：‘复议机关在法定期限内未作出复议决定，公民、法人或者其他组织起诉原行政行为的，作出原行政行为的行政机关是被告；起诉复议机关不作为的，复议机关是被告’。若张某对该行政处罚决定提起诉讼，应以作出原具体行政行为的县公安局为被告；若张某对县人民政府不作为提起诉讼，应以复议机关县人民政府为被告，因此A、C选项正确，B、D选项错误。", "type": "multiple", "topic": "专题四 行政复议法", "page": 163, "subject": "相关法", "id": "xg_475"},
  {"question": "《行政复议法》规定，行政复议机关应当自收到行政复议申请之日起多长时间内作出行政复议决定？", "options": ["A. 一个月内", "B. 两个月内", "C. 三个月内", "D. 六个月内"], "answer": "C", "explanation": "根据《行政复议法》的规定，行政复议机关应当自收到行政复议申请之日起六个月内作出行政复议决定。", "type": "single", "topic": "专题四 行政复议法", "page": 173, "subject": "相关法", "id": "xg_476"},
  {"question": "23. 县生态环境局以甲公司在生产过程中使用不符合国家标准的锅炉设备,超标排放污染物质为由,查封甲公司用以生产的锅炉,后对甲公司罚款8万元,甲公司不服,向县政府申请复议,下列哪一说法是正确的?(单选)", "options": ["A. 紧急情况下,查封可以不听取甲公司的陈述申辩", "B. 如果县政府认为本案事实清楚,证据确凿,适用法律正确,程序合法,但是内容不适当,将对甲公司罚款改为罚款10万元", "C. 在复议决定作出前当事人达成和解协议,复议程序自动终止", "D. 如果县政府认为本案事实不清,经审核事实清楚后,可以变更决定"], "answer": "D", "explanation": "A选项,《行政处罚法》第32条第1款规定:“当事人有权进行陈述和申辩。行政机关必须充分听取当事人的意见,对当事人提出的事实、理由和证据进行复核,并采纳合理的部分”,该权利任何时候都不得被剥夺,A选项错误。B选项,《复议法》第63条第2款规定:“行政复议机关不得作出对申请人更为不利的变更决定,但是第三人提出相反请求的除外”,变更为10万元罚款属于对申请人更为不利的变更决定,B选项错误。C选项,根据《复议法》第74条的规定,当事人达成和解后,由申请人向行政复议机构撤回行政复议申请。和解并不是一种复议的结案方式,C选项错误。D选项,根据《复议法》第63条的规定,行政行为事实不清、证据不足,经行政复议机关查清事实和证据,行政复议机关决定变更该行政行为,D选项正确。(新编,思维扩展)", "type": "single", "topic": "专题五 行政诉讼法", "page": 133, "subject": "相关法", "id": "xg_477"},
  {"question": "1. 下列哪些是行政诉讼法的基本功能?(多选)", "options": ["A. 打击行政领域的犯罪现象，维护社会治安", "B. 保证法院公正、及时地审理行政案件", "C. 保障公民、法人或者其他组织的合法权益", "D. 维护和监督行政机关依法行使行政职权"], "answer": "BC", "explanation": "《行政诉讼法》第1条规定：“为保证人民法院公正、及时审理行政案件，解决行政争议，保护公民、法人和其他组织的合法权益，监督行政机关依法行使职权，根据宪法，制定本法”，因此A、D选项错误，B、C选项正确。(新编)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 134, "subject": "相关法", "id": "xg_478"},
  {"question": "2. 关于行政诉讼中的合法性审查原则，下列哪些说法是正确的?(多选)", "options": ["A. 只对被诉请的行政行为实体上是否合法进行审查", "B. 只对被诉请的行政行为做合法性审查，不做合理性审查", "C. 审查的主体是人民法院", "D. 只对具体行政行为进行审查，不对抽象行政行为进行审查"], "answer": "CD", "explanation": "《行政诉讼法》第6条规定：“人民法院审理行政案件，对行政行为是否合法进行审查”，合法性审查是人民法院对被诉具体行政行为合法性的全面审查，既审查程序上的合法性，也审查实体上的合法性，因此A选项错误，C选项正确。B选项表述过于绝对，原则上人民法院做合法性审查，但是也不排除在特定情况下进行合理性审查。D选项，《行政诉讼法》第6条所表达的含义为人民法院审查对象为具体行政行为，D选项表述也过于绝对，但是考虑到本题为多选，D选项正确的概率更高。(新编，思维扩展)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 134, "subject": "相关法", "id": "xg_479"},
  {"question": "3. 根据行政诉讼法及相关规定，关于人民法院审理行政案件应当遵循的基本原则，下列说法哪些是正确的?(多选)", "options": ["A. 当事人在行政诉讼中的法律地位平等", "B. 人民法院审理所有行政案件都不适用调解", "C. 人民法院审理行政案件，对行政行为是否合理进行审查", "D. 人民法院审理行政案件，以事实为依据，以法律为准绳"], "answer": "AD", "explanation": "A选项，《行政诉讼法》第8条规定：“当事人在行政诉讼中的法律地位平等”，因此A选项正确。B选项，《行政诉讼法》第60条第1款规定：“人民法院审理行政案件，不适用调解。但是，行政赔偿、补偿以及行政机关行使法律、法规规定的自由裁量权的案件可以调解”，因此B选项错误。C选项，《行政诉讼法》第6条规定：“人民法院", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 134, "subject": "相关法", "id": "xg_480"},
  {"question": "4. 下列当事人提起的诉讼，属于行政诉讼受案范围的有? (多选)", "options": ["A. 张某和王某是邻居，因生活琐事产生纠纷，打架斗殴，经公安局调解达成调解协议", "B. 李某向生态环境局申请设立垃圾焚烧站，环保局以影响环境为由作出不予准许的决定。李某不服提起诉讼", "C. 张某因卖淫被县公安局处以10日行政拘留，1个月后张某向县政府申请行政复议，县政府不予受理。张某不服起诉", "D. 某公司与县政府签订天然气特许经营协议，双方发生纠纷"], "answer": "BC", "explanation": "A选项属于行政机关调解行为，不属于行政诉讼受案范围。B选项属于行政机关作出的具体行政行为，且涉及行政许可，属于行政诉讼受案范围。C选项中，县政府不予受理行政复议申请的行为属于行政行为，可以提起行政诉讼。D选项中，特许经营协议属于行政协议，若发生争议可提起行政诉讼，但需具体分析是否符合受案条件。综合判断，B、C选项属于行政诉讼受案范围。", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 134, "subject": "相关法", "id": "xg_481"},
  {"question": "5. 当事人不服下列行为提起诉讼的，不属于行政诉讼受案范围的有？(多选)", "options": ["A. 根据法院的生效判决，国家知识产权局专利局变更了专利权人姓名", "B. 北京市海淀区市场监督管理局作出的没收违法所得的行政处罚决定", "C. 根据已作出的行政决定，北京市海淀区市场监督管理局作出了行政决定履行催告书", "D. 北京市海淀区市场监督管理局作出了撤销行政许可(登记)听证告知书"], "answer": "ACD", "explanation": "A、D选项，《行政诉讼解释》第1条第2款规定：“下列行为不属于人民法院行政诉讼的受案范围：……（六）行政机关为作出行政行为而实施的准备、论证、研究、层报、咨询等过程性行为；（七）行政机关根据人民法院的生效裁判、协助执行通知书作出的执行行为，但行政机关扩大执行范围或者采取违法方式实施的除外……”，A选项属于上述第（七）项情形，D选项属于上述第（六）项情形，均不属于行政诉讼受案范围。C选项，行政决定履行催告书不是行政决定，不属于行政诉讼受案范围。B选项行政处罚属于行政诉讼受案范围。(2019)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 135, "subject": "相关法", "id": "xg_482"},
  {"question": "6. 根据行政诉讼法及相关规定，下列哪些不属于行政诉讼的受案范围？(多选)", "options": ["A. 公民王某对全国人大常委会修改专利法的决定不服的", "B. 商标局不受理张某的商标注册申请，张某不服的", "C. 乙公司对本市知识产权局责令其停止侵犯丙公司专利权的决定不服的", "D. 对北京市知识产权局作出的权属纠纷调解不服的"], "answer": "AD", "explanation": "A选项，全国人大常委会修改专利法的决定属于具有普遍约束力的决定，不属于行政诉讼的受案范围。D选项，为行政调解行为，不属于行政诉讼的受案范围。（新编）", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 135, "subject": "相关法", "id": "xg_483"},
  {"question": "7. 人民法院应当受理公民、法人或者其他组织对下列哪些事项提起的行政诉讼？(多选)", "options": ["A. 公安机关对李某作出的刑事拘留的决定", "B. 地方知识产权执法部门作出的对假冒专利的处罚", "C. 专利管理部门对专利代理机构的违法行为作出的警告"], "answer": "BCD", "explanation": "根据《行政诉讼解释》第1条的规定，公安、国家安全等机关依照刑事诉讼法的明确授权实施的行为不属于人民法院行政诉讼的受案范围，因此A选项错误。B、C选项，根据《行政诉讼法》第13条的规定，对行政拘留、暂扣或者吊销许可证和执照、责令停产停业、没收违法所得、没收非法财物、罚款、警告等行政处罚不服的，属于行政诉讼的受案范围，因此，B、C选项正确。D选项，根据《最高人民法院关于审理行政协议案件若干问题的规定》第2条的规定，土", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 135, "subject": "相关法", "id": "xg_484"},
  {"question": "8. 当事人对下列哪些事项既可以申请行政复议又可以提起行政诉讼（多选）", "options": ["A. 对行政机关作出民事纠纷调解不服的", "B. 对公安机关作出的行政拘留决定不服的", "C. 专利权人对国家知识产权局作出的宣告专利权全部无效的决定不服的", "D. 对国务院部门作出的具体行政行为不服的"], "answer": "BD", "explanation": "A选项，对民事纠纷调解不服既不能申请行政复议也不能提起行政诉讼，A选项错误。B、D选项既可以申请行政复议，也可以提起行政诉讼。C选项，根据《专利法》中相关规定，对无效决定不服只能诉讼，不能申请行政复议。(新编)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 136, "subject": "相关法", "id": "xg_485"},
  {"question": "9. 当事人对下列哪些事项既可以申请行政复议也可以提起行政诉讼？（多选）", "options": ["A. 行政机关对民事纠纷的调解", "B. 出入境边防检查机关对外国人采取的遣送出境措施", "C. 对申请宅基地不予批准的决定", "D. 对专利局作出的专利申请不予受理的决定"], "answer": "CD", "explanation": "A选项，对民事纠纷调解不服既不能申请行政复议也不能提起行政诉讼。B选项，《出境入境管理法》第64条第1款规定：“外国人对依照本法规定对其实施的继续盘问、拘留审查、限制活动范围、遣送出境措施不服的，可以依法申请行政复议，该行政复议决定为最终决定”，因此B选项可以复议但不可以提起行政诉讼，B选项错误。C选项，对行政机关作出的关于确认自然资源的所有权或者使用权的决定不服的可以申请行政复议，也可以提起行政诉讼，因此C选项正确。D选项，对国家知识产权局作出的有关专利申请、专利权的行政行为不服可以申请行政复议也可以提起行政诉讼，因此D选项正确。(新编)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 136, "subject": "相关法", "id": "xg_486"},
  {"question": "10. 根据行政诉讼法及相关规定，关于人民法院审理行政案件应当遵循的制度，下列哪些说法是正确的？（多选）", "options": ["A. 依法实行合议制度", "B. 依法实行回避制度", "C. 依法实行公开审判制度", "D. 依法实行两审终审制度"], "answer": "ABCD", "explanation": "《行政诉讼法》第7条规定，人民法院审理行政案件，依法实行合议、回避、公开审判和两审终审制度，因此A、B、C、D选项均正确。 (2015)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 136, "subject": "相关法", "id": "xg_487"},
  {"question": "11. 江某对某行政机关作出的行政处罚决定不服，向人民法院提起行政诉讼。江某认为本案书记员张某、审判员李某与该行政机关有利益关系可能会影响公正审判。根据行政诉讼法及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 江某有权申请李某回避", "B. 江某无权申请张某回避", "C. 李某的回避，由院长决定", "D. 张某的回避，由审判长决定 - 135 -"], "answer": "ACD", "explanation": "《行政诉讼法》第55条规定：“当事人认为审判人员与本案有利害关系或者有其他关系可能影响公正审判，有权申请审判人员回避……前两款规定，适用于书记员、翻译人员、鉴定人、勘验人……审判人员的回避，由院长决定。其他人员的回避，由审判长决定”，因此审判员李某的回避由院长决定，书记员张某的回避由审判长决定，A、C、D选项正确，B选项错误。(2016)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 136, "subject": "相关法", "id": "xg_488"},
  {"question": "6. 关于对限制人身自由的行政强制措施不服提起的行政 诉讼，下列哪些说法是正确的？(多选)", "options": ["A. 可以在原告的户籍所在地提起诉讼", "B. 可以在被告所在地提起诉讼", "C. 可以在原告的经常居住地提起诉讼", "D. 可以在被限制人身自由所在地提起诉讼"], "answer": "ABCD", "explanation": "《行政诉讼法》第19条规定：\n“对限制人身自由的行政强制措施不服提起\n的诉讼，由被告所在地或者原告所在地人民\n法院管辖”，《行政诉讼解释》第8条规定：\n“行政诉讼法第19条规定的‘原告所在地’，\n包括原告的户籍所在地、经常居住地和被限\n制人身自由地”，因此A、B、C、D选项均正\n确。(新编)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 138, "subject": "相关法", "id": "xg_489"},
  {"question": "7. 根据行政诉讼法及相关规定，下列关于行政诉讼管辖的 哪些说法是正确的？(多选)", "options": ["A. 两个以上人民法院都有管辖权的案件，原告可以选择其 中一个人民法院提起诉讼", "B. 原告向两个以上有管辖权的人民法院提起诉讼的，由最 先收到起诉状的人民法院管辖", "C. 人民法院发现受理的案件不属于本院管辖的，应当移送 有管辖权的人民法院，受移送的人民法院应当受理", "D. 两个以上人民法院都有管辖权的案件，原告应当向其共 同的上级人民法院起诉"], "answer": "AC", "explanation": "A、B、D选项，《行政诉讼法》第\n21条规定：“两个以上人民法院都有管辖权\n的案件，原告可以选择其中一个人民法院起\n诉，原告向两个以上有管辖权的人民法院提\n起诉讼的，由最先立案的人民法院管辖”，因\n此A选项正确，B、D选项错误。C选项，《行\n政诉讼法》第22条规定：“人民法院发现受\n理的案件不属于本院管辖的，应当移送有管\n辖权的人民法院，受移送的人民法院应当受\n理”，因此C选项正确。(新编)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 138, "subject": "相关法", "id": "xg_490"},
  {"question": "8. 根据行政诉讼法及相关规定，下列关于管辖的哪些说法 是正确的？(多选)", "options": ["A. 上级人民法院有权审判由下级人民法院管辖的第一审 行政案件", "B. 两个以上人民法院都有管辖权的案件，原告应当向其共"], "answer": "ACD", "explanation": "A选项，《行政诉讼法》第24\n条规定：“上级人民法院有权审理下级人民\n法院管辖的第一审行政案件”，因此A选项\n正确。B选项，《行政诉讼法》第21条规定：\n“两个以上人民法院都有管辖权的案件，原\n告可以选择其中一个人民法院提起诉讼”，\n因此B选项错误。C选项，《行政诉讼法》第\n23条规定：“有管辖权的人民法院由于特殊", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 138, "subject": "相关法", "id": "xg_491"},
  {"question": "1. 根据行政诉讼法及相关规定，下列哪些主体可以依法提起行政诉讼？（多选）", "options": ["A. 与被诉的行政复议决定有法律上利害关系的公民", "B. 被诉的具体行政行为涉及其公平竞争权的法人", "C. 在复议程序中被追加为第三人的法人", "D. 要求主管行政机关依法追究加害人法律责任的公民"], "answer": "ABCD", "explanation": "A选项，《行政诉讼法》第25条第1款规定：“行政行为的相对人以及其他与行政行为有利害关系的公民、法人或者其他组织，有权提起诉讼”，因此A选项正确。B、C、D选项，《行政诉讼解释》第12条规定：“有下列情形之一的，属于行政诉讼法第25条第1款规定的‘与行政行为有利害关系’：（一）被诉的行政行为涉及其相邻权或者公平竞争权的；（二）在行政复议等行政程序中被追加为第三人的；（三）要求行政机关依法追究加害人法律责任的……”，因此B、C、D选项正确。（2011）", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 139, "subject": "相关法", "id": "xg_492"},
  {"question": "2. 下列可以作为行政诉讼中的原告的是？（多选）", "options": ["A. 行政行为的相对人", "B. 已经死亡的有权提起行政诉讼的公民的近亲属", "C. 与具体行政行为有利害关系的公民、法人或者其他组织", "D. 人民检察院"], "answer": "ABCD", "explanation": "A、B、C选项，《行政诉讼法》第25条第1、2款规定：“行政行为的相对人以及其他与行政行为有利害关系的公民、法人或者其他组织，有权提起诉讼。有权提起诉讼的公民死亡，其近亲属可以提起诉讼”，因此A、B、C选项正确。D选项，《行政诉讼法》第25条第4款规定：“人民检察院在履行职责中发现生态环境和资源保护、食品药品安全、国有财产保护、国", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 139, "subject": "相关法", "id": "xg_493"},
  {"question": "3. 根据行政诉讼法及相关规定，合伙企业向人民法院提起诉讼的，下列哪种说法是正确的？（单选）", "options": ["A. 应当以核准登记的字号为原告", "B. 应当以所有合伙人为共同原告", "C. 应当以执行合伙企业事务的合伙人为原告 - 138 -"], "answer": "ABD", "explanation": "A、B选项,《行政诉讼法》第92条第2款规定:“……,上级人民法院对下级人民法院已经发生法律效力的判决、裁定,发现有本法第91条规定情形之一,或者发现调解违反自愿原则或者调解书内容违法的,有权提审或者指令下级人民法院再审”,因此A、B选项正确。C、D选项,根据《行政诉讼法》第93条的规定,上级人民检察院对下级人民法院已经发生法律效力的判决、裁定,发现有本法第91条规定情形之", "type": "single", "topic": "专题五 行政诉讼法", "page": 139, "subject": "相关法", "id": "xg_494"},
  {"question": "9. 人民法院对行政诉讼案件的管辖权发生争议，由争议双方协商解决，协商不成的，报（ ）指定管辖。（单选）", "options": ["A. 共同上级人民法院", "B. 先立案的法院", "C. 当地高级人民法院", "D. 最高人民法院 第三章 行政诉讼参加人"], "answer": "A", "explanation": "《行政诉讼法》第23条第2款规定：“人民法院对管辖权发生争议，由争议双方协商解决。协商不成的，报它们的共同上级人民法院指定管辖”，因此A选项正确。\n（新编）", "type": "single", "topic": "专题五 行政诉讼法", "page": 139, "subject": "相关法", "id": "xg_495"},
  {"question": "4. 中外合资企业甲认为其企业权益受行政行为侵害的,下列说法正确的是?(多选)", "options": ["A. 外方投资者可以以自己的名义提起行政诉讼", "B. 企业甲可以以自己的名义提起行政诉讼", "C. 外方投资者若以保护企业权益为由提起行政诉讼,其应以企业甲的名义提起行政诉讼", "D. 外方投资者以保护自己的权益为由提起行政诉讼的,其应以企业甲的名义提起行政诉讼"], "answer": "AB", "explanation": "根据《行政诉讼解释》第16条的规定,联营企业、中外合资或者合作企业的联营、合资、合作各方,认为联营、合资、合作企业权益或者自己一方合法权益受行政行为侵害的,可以自己的名义提起诉讼。因此A、B选项正确,C、D选项错误。(2019)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 140, "subject": "相关法", "id": "xg_496"},
  {"question": "5. 根据行政诉讼法及相关规定,下列哪些人员可以被委托为诉讼代理人?(多选)", "options": ["A. 当事人所在社区、单位推荐的公民", "B. 在专利行政案件中,经中华全国专利代理师协会推荐的专利代理师", "C. 基层法律服务工作者", "D. 律师"], "answer": "ABCD", "explanation": "A、C、D选项,《行政诉讼法》第31条第2款规定:“下列人员可以被委托为诉讼代理人:(一)律师、基层法律服务工作者……(三)当事人所在社区、单位以及有关社会团体推荐的公民”,因此A、C、D选项正确。B选项,《行政诉讼解释》第33条第2款规定:“专利代理人经中华全国专利代理人协会推荐,可以在专利行政案件中担任诉讼代理人”,因此D选项正确。(新编)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 140, "subject": "相关法", "id": "xg_497"},
  {"question": "6. 根据行政诉讼法及相关规定,下列关于行政诉讼被告的说法哪些是正确的?(多选)", "options": ["A. 公民、法人或者其他组织直接向人民法院提起诉讼的,作出具体行政行为的行政机关是被告", "B. 经复议的案件,复议机关决定维持原具体行政行为的,复议机关是被告", "C. 由行政机关委托的组织所作的具体行政行为,该组织是被告", "D. 两个以上行政机关作出同一具体行政行为的,共同作出具体行政行为的行政机关是共同被告"], "answer": "AD", "explanation": "《行政诉讼法》第26条规定:“公民、法人或者其他组织直接向人民法院提起诉讼的,作出行政行为的行政机关是被告。经复议的案件,复议机关决定维持原行政行为的,作出原行政行为的行政机关和复议机关是共同被告……两个以上行政机关作出同一行政行为的,共同作出行政行为的行政机关是共同被告。行政机关委托的组织所作的行政行为,委托的行政机关是被告”,因此A、D选项正确,B、C选项错误。(2011)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 140, "subject": "相关法", "id": "xg_498"},
  {"question": "15. 根据行政诉讼法及相关规定,下列关于行政诉讼参加人的哪些说法是正确的?(多选)", "options": ["A. 公民、法人或者其他组织同被诉行政行为有利害关系但没有提起诉讼,不得作为第三人申请参加诉讼", "B. 公民、法人或者其他组织同案件处理结果有利害关系的,可以由人民法院通知参加诉讼", "C. 人民法院判决第三人承担义务的,第三人有权依法提起上诉", "D. 人民法院判决减损第三人权益的,第三人有权依法提起上诉"], "answer": "BCD", "explanation": "《行政诉讼法》第29条规定:“公民、法人或者其他组织同被诉行政行为有利害关系但没有提起诉讼,或者同案件处理结果有利害关系的,可以作为第三人申请参加诉讼,或者由人民法院通知参加诉讼。人民法院判决第三人承担义务或者减损第三人权益的,第三人有权依法提起上诉”,因此A选项错误,B、C、D选项正确。(2017)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 143, "subject": "相关法", "id": "xg_499"},
  {"question": "16. 甲、乙、丙三友人一同在某餐厅就餐。由于餐品质量与餐厅经理郭某产生纠纷。纠纷过程中,将餐厅经理郭某打伤。区公安局将甲拘留10日,乙拘留5日。甲不服,提起", "options": ["A. 法院可以通知乙作为第三人参加诉讼", "B. 法院可以通知丙作为第三人参加诉讼", "C. 法院可以通知郭某作为第三人参加诉讼", "D. 若甲不服向区人民政府复议的，区人民政府可以通知郭某作为第三人参加复议"], "answer": "ACD", "explanation": "《行政诉讼解释》第30条规定:“行政机关的同一行政行为涉及两个以上利害关系人,其中一部分利害关系人对行政行为不服提起诉讼,人民法院应当通知没有起诉的其他利害关系人作为第三人参加诉讼。与行政案件处理结果有利害关系的第三人,可以申请参加诉讼,或者由人民法院通知其参加诉讼。”。本题中,甲、乙两人被拘留,甲作为原告起诉区公安局,郭某是受害人,属于行政行为中未起诉的利害关系人,法院应当通知郭某作为第三人参加诉讼。乙与甲的诉讼案件处理结果有利害关系,法院可以通知乙作为第三人参加诉讼。丙在该案中没有受到行政处罚,与甲的诉讼裁判结果没有利害关系,不应作为第三人参加诉讼。因此,A、C选项正确,B选项错误。《行政复议法》第16条规定,申请人以外的同被申请行政复议的行政行为或者行政复议案件处理结果有利害关系的公民、法人或者其他组织,可以作为第三人申请参加行政复议,或者由行政复议机构通知其作为第三人参加行政复议,因此,行政复议机关可以通知郭某作为第三人参加行政复议,D选项正确。(2018改编)", "type": "single", "topic": "专题五 行政诉讼法", "page": 143, "subject": "相关法", "id": "xg_500"},
  {"question": "20. 李某对某省公安厅对其作出的行政行为不服,向省人民政府申请行政复议,省人民政府作出的复议决定维持原行政行为。李某仍不服,向人民法院提起诉讼,下列哪些说法是正确的?(多选)", "options": ["A. 该行政诉讼案件中某省公安厅和省人民政府是共同被告", "B. 李某可以向省公安厅所在地的基层人民法院提起诉讼", "C. 李某可以向省人民政府所在地的基层人民法院提起诉讼", "D. 李某可以向省人民政府所在地的中级人民法院提起诉讼"], "answer": "ABC", "explanation": "A选项,根据《行政诉讼法》第26条的规定,复议机关决定维持原行政行为的,作出原行政行为的行政机关和复议机关是共同被告,省人民政府作出维持原行政行为的复议决定,省公安厅和省人民政府是共同被告,因此A选项正确。B、C、D选项,根据《行政诉讼法》第18条的规定,经复议的案件,由最初作出行政行为的行政机关所在地或复议机关所在地人民法院管辖,根据《行政诉讼解释》第134条的规定,作出原行政行为的行政机关和复议机关为共同被告的,以作出原行政行为的行政机关确定案件的级别管辖。原行政机关是省公安厅,属于省政府部门,应由基层法院管辖。同时,本题属于经复议的案件,因此,可由该省公安厅所在地或者省政府所在地的基层法院管辖,因此B、C选项正确,D选项错误。(新编)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 145, "subject": "相关法", "id": "xg_501"},
  {"question": "21. 贝果公司在生产经营中存在用非食品原料生产食品的违法行为。区市监局对其作出没收用于违法生产经营的非食品原料、没收违法所得、罚款10万元的行政处罚。贝果公司不服,向区政府申请复议,区政府将罚款改为8万元后,维持了其他处罚。贝果公司不服,提起诉讼,下列说法哪些是错误的?(多选)", "options": ["A. 本案被告是区市监局", "B. 本案可以由区市监局所在地的中院管辖", "C. 本案被告是区政府", "D. 如果贝果公司以区政府为被告提起诉讼且拒绝追加被告,法院应当追加区市监局为共同被告"], "answer": "ABC", "explanation": "A、C选项,《行政诉讼解释》第134条第2款规定:“行政复议决定既有维持原行政行为内容,又有改变原行政行为内容或者不予受理申请内容的,作出原行政行为的行政机关和复议机关为共同被告”,本案复议决定既有维持,又有改变,则区市监局和区政府为共同被告,A、C选项错误。B选项,复议机关作共同被告的案件,以作出原行政行为的行政机关确定案件的级别管辖,本案中,作出原行政行为的行政机关为市监局,则为基层法院管辖,B选项错误。D选项,根据《行政诉讼解释》第134条的规定,法院应当告知原告追加被告,原告不同意追加的,法院应当将另一机关列为共同被告。因此D选项正确。本题选择错误选项,则A、B、C选项当选。(法考2022改编)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 145, "subject": "相关法", "id": "xg_502"},
  {"question": "5. 根据行政诉讼法及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 行政诉讼被告对作出的行政行为负有举证责任，应当提供作出该行政行为的证据和所依据的规范性文件", "B. 行政诉讼被告无正当理由不提供证据的，人民法院应当依职权调查收集相应证据", "C. 原告在行政诉讼中提出了其在行政处理程序中没有提出的证据的，经人民法院准许，被告可以补充证据", "D. 原告可以提供证明行政行为违法的证据，原告提供的证据不成立的，不免除被告的举证责任"], "answer": "ACD", "explanation": "A、B选项，《行政诉讼法》第34条规定：“被告对作出的行政行为负有举证责任，应当提供作出该行政行为的证据和所依据的规范性文件。被告不提供或者无正当理由逾期提供证据，视为没有相应证据……”，因此A选项正确，B选项错误。C选项，《行政诉讼法》第36条第2款规定：“原告或者第三人提出了其在行政处理程序中没有提出的理由或者证据的，经人民法院准许，被告可以补充证据”，因此C选项正确。D选项，《行政诉讼法》第37条规定：“原告可以提供证明行政行为违法的证据。原告提供的证据不成立的，不免除被告的举证责任”，因此D选项正确。(2017)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 147, "subject": "相关法", "id": "xg_503"},
  {"question": "6. 根据行政诉讼法及相关规定，行政诉讼的被告应当在何时就其作出的具体行政行为向人民法院提供证据？（单选）", "options": ["A. 收到起诉状副本之日起15日内", "B. 第一审庭审结束前", "C. 第一审法庭辩论终结前", "D. 第一审判决作出前"], "answer": "A", "explanation": "《行政诉讼法》第67条第1款规定：“……被告应当在收到起诉状副本之日起15日内向人民法院提交作出行政行为的证据和所依据的规范性文件，并提出答辩状……”，因此A选项正确，B、C、D选项错误。(新编)", "type": "single", "topic": "专题五 行政诉讼法", "page": 147, "subject": "相关法", "id": "xg_504"},
  {"question": "9. 根据行政诉讼法及相关规定,下列哪些与本案有关的证据,原告或者第三人不能自行收集的,可以申请人民法院调取? (多选)", "options": ["A. 由国家机关保存而须由人民法院调取的证据", "B. 涉及国家秘密的证据", "C. 涉及商业秘密的证据", "D. 涉及个人隐私的证据"], "answer": "ABCD", "explanation": "《行政诉讼法》第41条规定:\n“与本案有关的下列证据,原告或者第三\n人不能自行收集的,可以申请人民法院调取:\n(一)由国家机关保存而须由人民法院调取\n的证据;(二)涉及国家秘密、商业秘密和个\n人隐私的证据……”,因此A、B、C、D选项均\n正确。(2015)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 148, "subject": "相关法", "id": "xg_505"},
  {"question": "10. 某药厂以本厂过期药品作为主原料,更改生产日期和批号生产出售。甲市乙县药监局以该厂违反《药品管理法》第49条第1款关于违法生产药品规定,决定没收药品并处罚款20万元。药厂不服向县政府申请复议,县政府依据《药品管理法》第49条第3款关于生产劣药行为的规定,决定维持处罚决定。药厂起诉。关于本案的举证与审理裁判,下列说法正确的有? (多选)", "options": ["A. 法院应对被诉行政行为和药厂的行为是否合法一并审理和裁判", "B. 药厂提供的证明被诉行政行为违法的证据不成立的,不免除被告对被诉行政行为合法性的举证责任", "C. 如在本案庭审过程中,药厂要求证人出庭作证的,法院不予准许", "D. 法院对本案的裁判,应当以证据证明的案件事实为依据"], "answer": "BD", "explanation": "A选项,法院审理行政案件,\n只有被诉行政行为才可以成为法院的审理\n对象,当事人行为不是法院审理对象,因此\n法院只审查行政处罚的合法性,不审查药厂\n行为的合法性,A选项错误。B选项,《行政\n诉讼法》第37条规定:“原告可以提供证明\n行政行为违法的证据。原告提供的证据不\n成立的,不免除被告的举证责任”,因此B选\n项正确。C选项,《行政诉讼证据规定》第43\n条规定:“当事人申请证人出庭作证的,应当\n在举证期限届满前提出,并经人民法院许\n可。人民法院准许证人出庭作证的,应当在\n开庭审理前通知证人出庭作证。当事人在\n庭审过程中要求证人出庭作证的,法庭可以\n根据审理案件的具体情况,决定是否准许以\n及是否延期审理”,C选项的表述过于绝对,\n因此C选项错误。D选项,法院裁判行政案\n件,应当以证据证明的案件事实为依据的说\n法正确。(法考2012,思维扩展)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 148, "subject": "相关法", "id": "xg_506"},
  {"question": "1. 根据行政诉讼法及相关规定，对于下列哪些诉讼请求，人民法院不予受理？(多选)", "options": ["A. 法律、法规规定应当先申请行政复议，公民、法人或其他组织未申请复议而直接提起诉讼的", "B. 法律规定由行政机关最终裁决的具体行政行为，公民、法人或其他组织不服该具体行政行为，向人民法院提起诉讼的", "C. 复议机关在法定期限内不作出复议决定，公民、法人或其他组织不服，依法向人民法院提起诉讼的", "D. 人民法院裁定准许原告撤诉后，原告以同一事实和理由重新提起诉讼的"], "answer": "ABD", "explanation": "A选项，《行政诉讼解释》第56条第1款规定：“法律、法规规定应当先申请复议，公民、法人或者其他组织未申请复议直接提起诉讼的，人民法院裁定不予立案”，即不予受理，因此A选项正确。B选项，根据《行政诉讼法》第13条的规定，法律规定由行政机关最终裁决的行政行为，人民法院不予受理，因此B选项正确。C选项，根据《行政诉讼法》第45条的规定，复议机关逾期不作决定的，申请人可以在复议期满之日起15日内向人民法院提起诉讼，因此C选项错误。D选项，《行政诉讼解释》第60条第1款规定：“人民法院裁定准许原告撤诉后，原告以同一事实和理由重新起诉的，人民法院不予立案”，即不予受理，因此D选项正确。(2012)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 149, "subject": "相关法", "id": "xg_507"},
  {"question": "2. 当事人王某不服某市知识产权局作出的行政处罚决定，直接向人民法院提起诉讼，下列说法正确的是？(单选)", "options": ["A. 其应当自知道或者应当知道作出行政行为之日起15日内提出", "B. 其应当自知道或者应当知道作出行政行为之日起1个月内提出", "C. 其应当自知道或者应当知道作出行政行为之日起3个月内提出", "D. 其应当自知道或者应当知道作出行政行为之日起6个月内提出"], "answer": "D", "explanation": "《行政诉讼法》第46条第1款规定：“公民、法人或者其他组织直接向人民法院提起诉讼的，应当自知道或者应当知道作出行政行为之日起6个月内提出……”，因此A、B、C选项错误，D选项正确(2019)", "type": "single", "topic": "专题五 行政诉讼法", "page": 149, "subject": "相关法", "id": "xg_508"},
  {"question": "4. 刘某向某人民法院提起行政诉讼，受诉人民法院在7日内既不立案，又不作出裁定，根据行政诉讼法及相关规定，刘某可以如何处理?(多选)", "options": ["A. 向上一级人民法院投诉", "B. 向上一级人民法院起诉", "C. 向上一级人民检察院抗诉", "D. 请求同级人民检察院抗诉"], "answer": "AB", "explanation": "根据《行政诉讼法》第51条第4款的规定，对于不接收起诉状、接收起诉状后不出具书面凭证，以及不一次性告知当事人需要补正的起诉状内容的，当事人可以向上一级人民法院投诉。根据《行政诉讼法》第52条的规定，人民法院既不立案，又不作出不予立案裁定的，当事人可以向上一级人民法院起诉，因此A、B选项正确，C、D选项错误。(2017)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 150, "subject": "相关法", "id": "xg_509"},
  {"question": "5. 关于行政诉讼案件，下列说法哪些是正确的?(多选)", "options": ["A. 在行政诉讼过程中，被告无权请求调解", "B. 在行政诉讼过程中，被告无权自行向原告和证人收集证据", "C. 在行政诉讼过程中，被告无权作出停止执行原具体行政行为的决定", "D. 在行政诉讼过程中，被告无权改变自己所作的具体行政行为"], "answer": "AB", "explanation": "A选项，《行政诉讼法》第60条第1款规定：“人民法院审理行政案件，不适用调解……”，因此A选项正确。B选项，《行政诉讼法》第35条规定：“在诉讼过程中，被告及其诉讼代理人不得自行向原告、第三人和证人收集证据”，因此B选项正确。C选项，根据《行政诉讼法》第56条的规定，诉讼期间，被告认为需要停止执行的，可以裁定停止执行，因此C选项错误。D选项，《行政诉讼法》第62条规定：“人民法院对行政案件宣告判决或者裁定前，原告申请撤诉的，或者被告改变其所作的行政行为，原告同意并申请撤诉的，是否准许，由人民法院裁定”，因此D选项错误。(2006)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 150, "subject": "相关法", "id": "xg_510"},
  {"question": "6. 某派出所以扰乱公共秩序为由扣押了高某的拖拉机。高某不服，以派出所为被告提起行政诉讼。诉讼中，法院认为被告应是县公安局，要求变更被告，高某不同意。法院下列哪种做法是正确的?(单选)", "options": ["A. 以派出所为被告继续审理本案", "B. 以县公安局为被告审理本案", "C. 裁定驳回起诉", "D. 裁定终结诉讼"], "answer": "C", "explanation": "《行政诉讼法解释》第26条第1款规定：“原告所起诉的被告不适格，人民法院应当告知原告变更被告；原告不同意变更的，裁定驳回起诉”，法院认为被告应是县公安局，而原告起诉时认为被告是派出所，法院应当告知原告变更被告，原告不同意变更的，裁定驳回起诉，因此C选项正确。(法考2007)", "type": "single", "topic": "专题五 行政诉讼法", "page": 150, "subject": "相关法", "id": "xg_511"},
  {"question": "1. 张某不服某市税务局作出的行政处罚决定,起诉至人民法院,根据行政诉讼法及相关规定,下列说法正确的是?(多选)", "options": ["A. 人民法院应当在立案之日起5日内,将起诉状副本发送某市税务局", "B. 该市税务局应当在收到起诉状副本之日起15日内向人民法院提交作出行政行为的证据和所依据的规范性文件", "C. 如果该市税务局不提交答辩状的,不影响人民法院审理", "D. 合议庭可以全部由审判员组成,也可以由审判员、陪审员组成,或者全部由陪审员组成"], "answer": "ABC", "explanation": "A、B选项,根据《行政诉讼法》第67条的规定,人民法院应当在立案之日起5日内,将起诉状副本发送被告。被告应当在收到起诉状副本之日起15日内向人民法院提交作出行政行为的证据和所依据的规范性文件,并提出答辩状,因此A、B选项正确。C选项,《行政诉讼法》第67条第2款规定:“被告不提出答辩状的,不影响人民法院审理”,因此C选项正确。D选项,《行政诉讼法》第68条规定:“人民法院审理行政案件,由审判员组成合议庭,或者由审判员、陪审员组成合议庭……”,合议庭不能仅由陪审员组成,因此D选项错误。(2019)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 151, "subject": "相关法", "id": "xg_512"},
  {"question": "3. 行政诉讼期间，不停止行政行为的执行，但是下列哪些情况，人民法院应当停止执行？（多选）", "options": ["A. 行政行为的执行会给国家利益造成重大损失的", "B. 被告申请停止执行，人民法院认为该行政行为的执行会给社会公共利益造成重大损害的", "C. 被告认为需要停止执行的", "D. 原告申请停止执行，人民法院认为该行政行为的执行会造成难以弥补的损失的"], "answer": "ABCD", "explanation": "《行政诉讼法》第56条第1款规定：“诉讼期间，不停止行政行为的执行。但有下列情形之一的，裁定停止执行：（一）被告认为需要停止执行的；（二）原告或者利害关系人申请停止执行，人民法院认为该行政行为的执行会造成难以弥补的损失，并且停止执行不损害国家利益、社会公共利益的；（三）人民法院认为该行政行为的执行会给国家利益、社会公共利益造成重大损害的；（四）法律、法规规定停止执行的”，因此A、B、C、D选项均正确。（新编）", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 152, "subject": "相关法", "id": "xg_513"},
  {"question": "4. 根据行政诉讼法的规定，下列说法哪些是正确的？（多选）", "options": ["A. 人民法院审理行政案件，参照行政法规", "B. 人民法院审理行政案件，参照地方性法规", "C. 人民法院审理行政案件，参照国务院部委根据法律或者行政法规制定、发布的规章", "D. 人民法院审理行政案件，参照直辖市人民政府根据法律或者行政法规制定、发布的规章"], "answer": "CD", "explanation": "根据《行政诉讼法》第63条的规定，人民法院审理行政案件，以法律和行政法规、地方性法规为依据，参照规章，因此C、D选项正确。（2018）", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 152, "subject": "相关法", "id": "xg_514"},
  {"question": "5. 根据行政诉讼法及相关规定，基层人民法院有特殊情况不能在立案之日起6个月内作出第一审行政判决，需要延长期限的，应如何处理？（单选）", "options": ["A. 由该基层人民法院院长批准", "B. 由上一级人民法院批准", "C. 由高级人民法院批准", "D. 由最高人民法院批准"], "answer": "C", "explanation": "《行政诉讼法》第81条规定：“人民法院应当在立案之日起6个月内作出第一审判决。有特殊情况需要延长的，由高级人民法院批准，高级人民法院审理第一审案件需要延长的，由最高人民法院批准”。本题中，作出第一审行政判决的为基层人民法院，因此A、B、D选项错误，C选项正确。（2015）", "type": "single", "topic": "专题五 行政诉讼法", "page": 152, "subject": "相关法", "id": "xg_515"},
  {"question": "8. 行政诉讼过程中，在下列哪项情形下，人民法院可以按照撤诉处理？(单选)", "options": ["A. 外地原告开庭前一天收到传票无法出庭的", "B. 上诉人认为人民法院偏袒被上诉人，未经法庭许可中途退庭的", "C. 原告申请撤诉，人民法院裁定不予准许，经合法传唤无正当理由拒不到庭的", "D. 被告改变原具体行政行为，原告不撤诉的"], "answer": "B", "explanation": "A选项，根据《行政诉讼解释》第71条的规定，人民法院适用普通程序审理案件，应当在开庭三日前用传票传唤当事人。当事人或者其他诉讼参与人在外地的，应当留有必要的在途时间。因此A选项错误。B选项，根据《行政诉讼法》第58条的规定，经人民法院传票传唤，原告无正当理由拒不到庭，或者未经法庭许可中途退庭的，可以按照撤诉处理。上诉人未经法庭许可中途退庭应当比照一审原告处理，因此B选项正确。C选项，《行政诉讼解释》第79条规定：“原告或者上诉人申请撤诉，人民法院裁定不予准许的，原告或者上诉人经传票传唤无正当理由拒不到庭，或者未经法庭许可中途退庭的，人民法院可以缺席判决”，因此C选项错误。D选项，根据《行政诉讼解释》第81条第3款的规定，原告不撤诉的，法院应当依法作出确认判决，不会按照撤诉处理，因此D选项错误。（2018）", "type": "single", "topic": "专题五 行政诉讼法", "page": 153, "subject": "相关法", "id": "xg_516"},
  {"question": "9. 根据行政诉讼法及相关规定，下列说法哪些是正确的？", "options": ["A. 当李某作为第三人参加诉讼，其经传票传唤无正当理由拒不到庭，或者未依法申请中途中退庭的，案件审理中止的，李某有权提起上诉。", "B. 李某可以向人民法院通知其作为第三人参加诉讼。", "C. 李某可以作为第三人申请参加诉讼。", "D. 李某作为第三人参加诉讼，人民法院判决撤销其权益的，李某有权提起上诉。"], "answer": "ABCD", "explanation": "《行政诉讼法》第58条规定：“经人民法院传票传唤，原告无正当理由拒不到庭，或者未经法庭许可中途退庭的，可以按照撤诉处理；被告无正当理由拒不到庭，或者未经法庭许可中途退庭的，可以缺席判决”，因此A、B、C、D选项均正确。（新编）", "type": "single", "topic": "专题五 行政诉讼法", "page": 153, "subject": "相关法", "id": "xg_517"},
  {"question": "10. 根据行政诉讼法及相关规定，在下列哪些情形下，人民法院中止行政诉讼?(多选)", "options": ["A. 原告死亡，须等待其近亲属表明是否参加诉讼的", "B. 案件的审判须以相关民事案件的审理结果为依据，而相关案件尚未审结的", "C. 原告死亡，没有近亲属或者近亲属放弃诉讼权利的", "D. 作为原告的法人或者其他组织终止后，其权利义务的承受人放弃诉讼权利的"], "answer": "AB", "explanation": "根据行政诉讼法的规定，原告死亡且需要等待其近亲属表明是否参加诉讼的，以及案件的审理结果以相关民事案件的审理结果为依据，而相关案件尚未结的，人民法院应当中止行政诉讼。", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 154, "subject": "相关法", "id": "xg_518"},
  {"question": "11. 关于行政诉讼中的财产保全，下列哪些说法是正确的?(多选)", "options": ["A. 对于因一方当事人的行为，可能使人民法院生效裁判难以执行的案件，人民法院可以根据对方当事人的申请作出财产保全的裁定", "B. 对于因一方当事人的行为，可能使被诉具体行政行为难以执行的案件，人民法院可以根据对方当事人的申请作出财产保全的裁定", "C. 当事人没有提出财产保全申请的，人民法院在必要时可以依法采取财产保全措施", "D. 当事人对财产保全的裁定不服的，可以上诉"], "answer": "ABC", "explanation": "A、B、C选项，《行政诉讼解释》第76条第1款规定:“人民法院对于因一方当事人的行为或者其他原因，可能使行政行为或者人民法院生效裁判不能或者难以执行的案件，根据对方当事人的申请，可以裁定对其财产进行保全、责令其作出一定行为或者禁止其作出一定行为;当事人没有提出申请的，人民法院在必要时也可以裁定采取上述保全措施”，因此A、B、C选项正确。D选项，根据《行政诉讼解释》第101条第1、2款的规定，只有不予立案、驳回起诉、管辖异议这三种裁定可以上诉，财产保全裁定不能上诉，因此D选项错误。(2007)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 154, "subject": "相关法", "id": "xg_519"},
  {"question": "13. 根据行政诉讼法及相关规定,行政行为有下列哪些情形的,人民法院判决撤销或者部分撤销,并可以判决被告重新作出行政行为?(多选)", "options": ["A. 主要证据不足的", "B. 适用法律、法规错误的", "C. 行政程序轻微违法,但对原告权利不产生实际影响的", "D. 明显不当的"], "answer": "ABD", "explanation": "A、B、D选项，《行政诉讼法》第70条规定：‘行政行为有下列情形之一的，人民法院判决撤销或者部分撤销，并可以判决被告重新作出行政行为：（一）主要证据不足的；（二）适用法律、法规错误的……（六）明显不当的’，因此A、B、D选项正确。C选项，根据《行政诉讼法》第74条的规定，行政行为程序轻微违法，但对原告权利不产生实际影响的，人民法院判决确认违法，但不需要撤销或者判决履行的，因此C选项错误。（2016）", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 155, "subject": "相关法", "id": "xg_520"},
  {"question": "14. 甲某对国家知识产权局作出的宣告其专利权全部无效的审查决定不服提起行政诉讼,经审理查明,无效宣告请求人乙某的身份被盗用,授权委托书上的签名系伪造,下列裁判方式正确的是?(单选)", "options": ["A. 撤销无效宣告审查决定,并判令国家知识产权局就该无效请求重新作出审查决定", "B. 撤销无效宣告审查决定", "C. 鉴于专利法规定任何人均可以提出无效宣告请求,判决驳回甲的诉讼请求", "D. 鉴于专利法规定任何人均可以提出无效宣告请求,判决维持无效宣告审查决定"], "answer": "B", "explanation": "《行政诉讼法》第70条规定:“行政行为有下列情形之一的,人民法院判决撤销或者部分撤销,并可以判决被告重新作出行政行为;……(三)违反法定程序的……”。本题中,乙某的身份被盗用,属于违反法定程序的情形,应予撤销,撤销无效决定后,因无效申请人不符合请求人资格条件,国家知识产权局应当作出不予受理决定,而不是重新作出无效决定,因此A、C、D选项错误,B选项正确。(2018改编)", "type": "single", "topic": "专题五 行政诉讼法", "page": 155, "subject": "相关法", "id": "xg_521"},
  {"question": "15. 根据行政诉讼法及相关规定,有关法院判决变更,下列说法正确的是?(多选)", "options": ["A. 行政处罚明显不当,法院可以判决变更", "B. 涉及对款额的确定确有错误的行政行为,法院可以判决变更", "C. 法院判决变更,通常不得加重原告的义务"], "answer": "ABCD", "explanation": "《行政诉讼法》第77条规定:“行政处罚明显不当,或者其他行政行为涉及对款额的确定、认定确有错误的,人民法院可以判决变更。人民法院判决变更,不得加重原告的义务或者减损原告的权益……”,因此A、B、C、D选项均正确。(2019)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 155, "subject": "相关法", "id": "xg_522"},
  {"question": "16. 根据行政诉讼法及相关规定，下列哪些情况，法院应判决确认违法但不撤销或不需要撤销行政行为？（多选）", "options": ["A. 行政行为依法应当撤销，但撤销会给国家利益、社会公共利益造成重大损害的", "B. 行政行为程序轻微违法，但对原告权利不产生实际影响的", "C. 被告改变原违法行政行为，原告仍要求确认原行政行为违法的", "D. 行政行为违法，但不具有可撤销内容的"], "answer": "ABCD", "explanation": "《行政诉讼法》第74条规定：‘行政行为有下列情形之一的，人民法院判决确认违法，但不撤销行政行为：（一）行政行为依法应当撤销，但撤销会给国家利益、社会公共利益造成重大损害的；（二）行政行为程序轻微违法，但对原告权利不产生实际影响的。行政行为有下列情形之一，不需要撤销或者判决履行的，人民法院判决确认违法：（一）行政行为违法，但不具有可撤销内容的；（二）被告改变原违法行政行为，原告仍要求确认原行政行为违法的……’，因此A、B、C、D选项均正确。（2019）", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 156, "subject": "相关法", "id": "xg_523"},
  {"question": "17. 行政诉讼案件有下列哪些情形的，人民法院应当判决驳回原告的诉讼请求？（多选）", "options": ["A. 行政行为证据确凿，适用法律、法规正确", "B. 符合法定程序", "C. 合法但明显不当", "D. 原告申请被告履行法定职责或者给付义务理由不成立"], "answer": "ABD", "explanation": "A、B、D选项，《行政诉讼法》第69条规定：‘行政行为证据确凿，适用法律、法规正确，符合法定程序的，或者原告申请被告履行法定职责或者给付义务理由不成立的，人民法院判决驳回原告的诉讼请求’，因此A、B、D选项正确。C选项，根据《行政诉讼法》第70条的规定，合法但明显不当的，人民法院判决撤销或者部分撤销，并可以判决被告重新作出行政行为，因此C选项错误。（2008）", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 156, "subject": "相关法", "id": "xg_524"},
  {"question": "18. 某镇政府以一公司所建钢架大棚未取得乡村建设规划许可证为由责令限期拆除。该公司逾期不拆除，镇政府现场向其送达强拆通知书，组织人员拆除了大棚。该公司向法院起诉要求撤销强拆行为。如一审法院审理认为强拆行为违反法定程序，可作出的判决有：（单选）", "options": ["A. 撤销判决", "B. 确认违法判决", "C. 履行判决", "D. 变更判决"], "answer": "B", "explanation": "《行政诉讼法》第74条第2款规定：“行政行为有下列情形之一，不需要撤销或者判决履行的，人民法院判决确认违法：（一）行政行为违法，但不具有可撤销内容的……”。本题中，强拆行为违反法定程序，房屋已经被拆除，强拆决定已经实施完毕，无法撤销和变更，应判决确认违法，因此A、C、D选项错误，B选项正确。（法考2015）", "type": "single", "topic": "专题五 行政诉讼法", "page": 156, "subject": "相关法", "id": "xg_525"},
  {"question": "20. 根据行政诉讼法的规定，如果不存在需要延长审理期限的特殊情况，人民法院应当在下列哪个期限内作出行政案件的第一审判决？（单选）", "options": ["A. 收到起诉状之日起6个月", "B. 立案之日起6个月", "C. 收到起诉状之日起3个月", "D. 立案之日起3个月"], "answer": "D", "explanation": "人民法院应当在立案之日起3个月内作出行政案件的第一审判决。", "type": "single", "topic": "专题五 行政诉讼法", "page": 157, "subject": "相关法", "id": "xg_526"},
  {"question": "21. 对下列哪些行政裁判，当事人可以提起上诉？（多选）", "options": ["A. 裁定不停止执行行政行为", "B. 裁定不予立案", "C. 裁定中止诉讼", "D. 判决驳回原告的诉讼请求"], "answer": "D", "explanation": "对于判决不服可以提起上诉。", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 157, "subject": "相关法", "id": "xg_527"},
  {"question": "22. 王某将沈某打成轻微伤，区公安分局给予王某行政拘留5日并罚款2000元的处罚。王某向区政府申请行政复议，区政府经听证以区公安分局超期办案为由作出确认违法决定。王某不服，提起行政诉讼，法院通知沈某作为第三人参加诉讼，下列说法正确的是？", "options": ["A. 被告应为区政府", "B. 区公安分局负责人应当参加复议听证", "C. 应由区政府所在地中院管辖", "D. 沈某未经许可中途退庭，法院应中止审理"], "answer": "B", "explanation": "根据《行政诉讼解释》第22条的规定，复议机关确认原行政行为违法，属于改变原行政行为，但复议机关以违反法定程序为由确认原行政行为违法的除外。以程序违法为由确认原行为违法应将其视为维持。因此，原机关区公安分局和复议机关区政府是共同被告，A选项错误。根据《行政复议法》第51条的规定，被申请人的负责人应当参加听证。不能参加的，应当说明理由并委托相应的工作人员参加听证。因此，被申请人区公安分局的负责人应当参加听证，B选项正确。根据《行政诉讼解释》第134条的规定，复议机关作共同被告的案件，以作出原行政行为的行政机关确定案件的级别管辖。应以区公安分局为确定案件的级别管辖为基层法院，因此C选项错误。根据《行政诉讼解释》第79条的规定，第三人经传票传唤无正当理由拒不到庭，或者未经法庭许可中途退庭的，不发生阻止案件审理的效果。因此D选项错误。（法考2024）", "type": "single", "topic": "专题五 行政诉讼法", "page": 157, "subject": "相关法", "id": "xg_528"},
  {"question": "2. 根据行政诉讼法及相关规定，下列关于行政诉讼第二审程序的说法哪项是正确的?(单选)", "options": ["A. 第二审人民法院对没有提出新的事实、证据或者理由，合议庭认为不需要开庭审理的，可以不开庭审理", "B. 第二审人民法院对行政上诉案件应当一律开庭审理", "C. 第二审人民法院审理行政上诉案件，只限于审查原审人民法院作出的裁判是否合法", "D. 第二审人民法院审理行政上诉案件，只限于审查被诉行政行为是否合法"], "answer": "A", "explanation": "A、B选项，《行政诉讼法》第86条规定：“人民法院对上诉案件，应当组成合议庭，开庭审理。经过阅卷、调查和询问当事人，对没有提出新的事实、证据或者理由，合议庭认为不需要开庭审理的，也可以不开庭审理”，因此A选项正确，B选项错误。C、D选项，《行政诉讼法》第87条规定：“人民法院审理上诉案件，应当对原审人民法院的判决、裁定和被诉行政行为进行全面审查”，因此C、D选项错误。(2017)", "type": "single", "topic": "专题五 行政诉讼法", "page": 159, "subject": "相关法", "id": "xg_529"},
  {"question": "3. 人民法院审理行政上诉案件，在下列哪些情形下可以裁定撤销原判，发回重审?(多选)", "options": ["A. 原判决认定事实清楚，但适用法律错误", "B. 原判决遗漏了当事人", "C. 原判决认定基本事实不清，证据不足", "D. 原判决是对发回重审的案件作出的"], "answer": "BC", "explanation": "《行政诉讼法》第89条规定：“人民法院审理上诉案件，按照下列情形，分别处理：……（二）原判决、裁定认定事实错误或者适用法律、法规错误的，依法改判、撤销或者变更；（三）原判决认定基本事实不清、证据不足的，发回原审人民法院重审，或者查清事实后改判；（四）原判决遗漏当事人或者违法缺席判决等严重违反法定程序的，裁定撤销原判决，发回原审人民法院重审。原审人民法院对发回重审的案件作出判决后，当事人提起上诉的，第二审人民法院不得再次发回重审……”，因此B、C选项正确，A选项应依法变更，无必要发回重审，D选项原判决是对发回重审的案件作出的，不能再次发回重审。(2018)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 159, "subject": "相关法", "id": "xg_530"},
  {"question": "4. 根据行政诉讼法及相关规定，关于法院审理上诉案件，下列说法正确的是?(多选)", "options": ["A. 原审判决遗漏当事人，第二审法院应裁定撤销原判决，发回原审人民法院重审", "B. 原审判决违法缺席判决，第二审法院应裁定撤销原判决，发回原审人民法院重审", "C. 原审判决遗漏行政赔偿请求，第二审法院应裁定撤销原判决，发回原审人民法院重审", "D. 原审判决中应当回避的审判人员未回避的，第二审法院应裁定撤销原判决，发回原审人民法院重审"], "answer": "ABD", "explanation": "A、B、D选项都属于违反法定程序，应撤销原判，发回重审，因此A、B、D选项正确。C选项，《行政诉讼解释》第109条第4、5款规定：“原审判决遗漏行政赔偿请求，第二审人民法院经审查认为依法不应当予以赔偿的，应当判决驳回行政赔偿请求。原审判决遗漏行政赔偿请求，第二审人民法院经审理认为依法应当予以赔偿的，在确认被诉行政行为违法的同时，可以就行政赔偿", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 159, "subject": "相关法", "id": "xg_531"},
  {"question": "6. 根据民事诉讼法和行政诉讼法的规定，下列哪些说法是正确的？(多选)", "options": ["A. 民事诉讼可以申请诉前证据保全，而行政诉讼只能在诉讼中提出", "B. 基层法院一审，双方协商一致可以适用简易程序", "C. 都遵循谁主张谁举证的原则", "D. 民事诉讼中当事人的法律地位平等，行政诉讼中当事人的法律地位不平等"], "answer": "AB", "explanation": "A选项，根据《民事诉讼法》的相关规定，当事人可以在诉讼过程中向法院申请保全证据，利害关系人可以在提起诉讼前向法院申请保全证据。而行政诉讼中证据保全只能在诉讼中提出，因此A选项正确。B选项，不论民事诉讼还是行政诉讼，基层法院一审的案件当事人双方可以约定适用简易程序，因此B选项正确。C选项，民事诉讼中遵循谁主张谁举证的原则，行政诉讼中被告对作出的行政行为负有举证责任，因此C选项错误。D选项，《行政诉讼法》第8条规定：“当事人在行政诉讼中的法律地位平等”，因此D选项错误。(新编)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 160, "subject": "相关法", "id": "xg_532"},
  {"question": "1. 根据行政诉讼法及相关规定,下列说法哪些是正确的? (多选)", "options": ["A. 当事人对已经发生法律效力的判决、裁定,认为确有错误的,可以向原审人民法院提出再审", "B. 当事人对已经发生法律效力的判决、裁定,认为确有错误的,可以向原审人民法院的上一级人民法院提出再审", "C. 人民法院院长对本院已经发生法律效力的判决、裁定,发现违反法律、法规规定认为需要再审的,有权决定再审", "D. 上级人民法院对下级人民法院已经发生法律效力的判决、裁定,发现违反法律、法规规定的,有权提审或者指令下级人民法院再审"], "answer": "BD", "explanation": "A、B选项,《行政诉讼法》第90条规定:“当事人对已经发生法律效力的判决、裁定,认为确有错误的,可以向上一级人民法院申请再审……”,因此A选项错误,B选项正确。C、D选项,《行政诉讼法》第92条规定:“各级人民法院院长对本院已经发生法律效力的判决、裁定,认为需要再审的,应当提交审判委员会讨论决定……上级人民法院对下级人民法院已经发生法律效力的判决、裁定,有权提审或者指令下级人民法院再审”,因此C选项错误,D选项正确。(2011)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 161, "subject": "相关法", "id": "xg_533"},
  {"question": "3. 根据行政诉讼法及相关规定,下列哪些说法是正确的? (多选)", "options": ["A. 上级人民法院对下级人民法院已经发生法律效力的判决,发现违反法律、法规规定的,有权提审", "B. 上级人民法院对下级人民法院已经发生法律效力的判决,发现违反法律、法规规定的,有权指令下级人民法院再审", "C. 人民检察院对人民法院已经发生法律效力的判决,裁定"], "answer": "ABD", "explanation": "A、B选项,《行政诉讼法》第92条第2款规定:“……,上级人民法院对下级人民法院已经发生法律效力的判决、裁定,发现有本法第91条规定情形之一,或者发现调解违反自愿原则或者调解书内容违法的,有权提审或者指令下级人民法院再审”,因此A、B选项正确。C、D选项,根据《行政诉讼法》第93条的规定,上级人民检察院对下级人民法院已经发生法律效力的判决、裁定,发现有本法第91条规定情形之", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 161, "subject": "相关法", "id": "xg_534"},
  {"question": "1. 某县公安局干警张某在协助县林业局执行公务时，遇到往日有嫌隙的王某，张某借故将王某殴打致死，对王某的死亡承担赔偿义务的是？(单选)", "options": ["A. 该县公安局", "B. 该县人民政府", "C. 张某", "D. 该县林业局"], "answer": "C", "explanation": "《国家赔偿法》第5条规定：“属于下列情形之一的，国家不承担赔偿责任：（一）行政机关工作人员与行使职权无关的个人行为……”，张某的行为属于个人行为，和职务无关，国家不承担赔偿责任，因此A、B、D选项错误，C选项正确。(2019)", "type": "single", "topic": "专题五 行政诉讼法", "page": 162, "subject": "相关法", "id": "xg_535"},
  {"question": "4. 根据行政诉讼法及相关规定，下列关于审判监督程序的哪些说法是正确的？(多选)", "options": ["A. 地方各级人民检察院发现同级人民法院已经发生法律效力的判决遗漏诉讼请求的，可以向同级人民法院提出抗诉", "B. 地方各级人民检察院发现同级人民法院已经发生法律效力的判决遗漏诉讼请求的，可以提请上级人民检察院向同级人民法院提出抗诉", "C. 上级人民检察院发现下级人民法院已经发生法律效力的判决遗漏诉讼请求的，应当提出抗诉", "D. 最高人民检察院发现各级人民法院已经发生法律效力的判决遗漏诉讼请求的，应当提出抗诉 第九章  国家赔偿"], "answer": "BCD", "explanation": "《行政诉讼法》第91条规定：“当事人的申请符合下列情形之一的，人民法院应当再审：……（六）原判决、裁定遗漏诉讼请求的……”；《行政诉讼法》第93条第1、2款规定：“最高人民检察院对各级人民法院已经发生法律效力的判决、裁定，上级人民检察院对下级人民法院已经发生法律效力的判决、裁定，发现有本法第91条规定情形之一，或者发现调解书损害国家利益、社会公共利益的，应当提出抗诉。地方各级人民检察院对同级人民法院已经发生法律效力的判决、裁定，发现有本法第91条规定情形之一，或者发现调解书损害国家利益、社会公共利益的，可以向同级人民法院提出检察建议，并报上级人民检察院备案；也可以提请上级人民检察院向同级人民法院提出抗诉”；因此A选项错误，B、C、D选项正确。(2016)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 162, "subject": "相关法", "id": "xg_536"},
  {"question": "4. 根据国家赔偿法的规定，行政机关及其工作人员在行使行政职权时，有下列哪些情形时，受害人有取得赔偿的权利？(多选)", "options": ["A. 违法实施罚款的", "B. 违法对财产采取冻结的", "C. 违法采取限制公民人身自由的行政强制措施的", "D. 行政机关工作人员与行使职权无关的个人行为"], "answer": "ABC", "explanation": "A、B选项，《国家赔偿法》第4条规定：“行政机关及其工作人员在行使行政职权时有下列侵犯财产权情形之一的，受害人有取得赔偿的权利：(一)违法实施罚款、吊销许可证和执照、责令停产停业、没收财物等行政处罚的；(二)违法对财产采取查封、扣押、冻结等行政强制措施的……”，因此A、B选项正确。C选项，《国家赔偿法》第3条规定：“行政机关及其工作人员在行使行政职权时有下列侵犯人身权情形之一的，受害人有取得赔偿的权利：(一)违法拘留或者违法采取限制公民人身自由的行政强制措施的……”，因此C选项正确。D选项，《国家赔偿法》第5条规定：“属于下列情形之一的，国家不承担赔偿责任：(一)行政机关工作人员与行使职权无关的个人行为……”，因此D选项错误。(新编)", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 163, "subject": "相关法", "id": "xg_537"},
  {"question": "5. 根据国家赔偿法的规定，行政机关及其工作人员在行使行政职权时有下列哪些情形的，受害人有取得赔偿的权利？(多选)", "options": ["A. 非法拘禁的", "B. 唆使、放纵他人殴打造成公民身体伤害的", "C. 唆使、放纵他人虐待造成公民身体伤害的", "D. 违法征用财产的"], "answer": "ABCD", "explanation": "A、B、C选项，《国家赔偿法》第3条规定：“行政机关及其工作人员在行使行政职权时有下列侵犯人身权情形之一的，受害人有取得赔偿的权利：……(二)非法拘禁或者以其他方法非法剥夺公民人身自由的；(三)以殴打、虐待等行为", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 163, "subject": "相关法", "id": "xg_538"},
  {"question": "民事诉讼的被告为公民、法人或其他组织，行政诉讼的被告为行政机关或法律法规授权的组织", "options": ["A. 人民法院审理行政案件，依法实行两审终审制度", "B. 人民法院审理行政案件，对具体行政行为是否合法进行审查", "C. 当事人的法律地位平等", "D. 各民族公民都有用本民族语言、文字进行行政诉讼的权利"], "answer": "BD", "explanation": "民事诉讼的被告可以是公民、法人或其他组织，而行政诉讼的被告通常是行政机关或法律法规授权的组织。行政诉讼中当事人的法律地位是平等的，且各民族公民都有用本民族语言、文字进行行政诉讼的权利。人民法院审理行政案件，依法实行两审终审制度，对具体行政行为是否合法进行审查。", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 157, "subject": "相关法", "id": "xg_539"},
  {"question": "人民法院审理行政案件，依法实行两审终审制度", "options": ["A. 人民法院审理行政案件，以事实为依据，以法律为准绳", "B. 人民法院审理行政案件，对行政行为是否合法进行审查", "C. 人民检察院有权对行政诉讼实行法律监督", "D. 当事人在行政诉讼中有权进行辩论"], "answer": "ABCD", "explanation": "人民法院审理行政案件，确实依法实行两审终审制度，以事实为依据，以法律为准绳，并对行政行为是否合法进行审查。人民检察院有权对行政诉讼实行法律监督，当事人在行政诉讼中有权进行辩论。", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 157, "subject": "相关法", "id": "xg_540"},
  {"question": "人民法院审理行政案件应当遵循的制度", "options": ["A. 依法实行合议制度", "B. 依法实行回避制度", "C. 依法实行公开审判制度", "D. 依法实行两审终审制度"], "answer": "ABCD", "explanation": "人民法院审理行政案件应当依法实行合议制度、回避制度、公开审判制度，并实行两审终审制度。", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 157, "subject": "相关法", "id": "xg_541"},
  {"question": "江某对某行政机关作出的行政处罚决定不服，向人民法院提起诉讼", "options": ["A. 依法实行合议制度", "B. 依法实行回避制度", "C. 依法实行公开审判制度", "D. 依法实行两审终审制度"], "answer": "ABCD", "explanation": "江某提起诉讼时，人民法院应当依法实行合议制度、回避制度、公开审判制度，并实行两审终审制度。", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 157, "subject": "相关法", "id": "xg_542"},
  {"question": "下列哪些案件属于中级人民法院管辖的第一审行政案件？（多选）", "options": ["A. 对国务院部门所作的行政行为提起诉讼的案件", "B. 对县级以上地方人民政府所作的行政行为提起诉讼的案件", "C. 海关处理的案件", "D. 本辖区内重大、复杂的案件"], "answer": "ABCD", "explanation": "《行政诉讼法》第15条规定：“中级人民法院管辖下列第一审行政案件：（一）对国务院部门或者县级以上地方人民政府所作的行政行为提起诉讼的案件；（二）海关处理的案件；（三）本辖区内重大、复杂的案件……”，因此A、B、C、D选项均正确。", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 160, "subject": "相关法", "id": "xg_543"},
  {"question": "根据行政诉讼法及相关规定，中级人民法院对下列哪些一审案件具有管辖权？（多选）", "options": ["A. 对省人民政府所作的具体行政行为不服的案件", "B. 对国家知识产权局作出的专利申请不服的案件", "C. 本辖区内社会影响重大的集团诉讼案件", "D. 辖区内甲县人民法院与乙县人民法院就管辖权产生争议的案件"], "answer": "AC", "explanation": "A、C选项，《行政诉讼法》第15条规定：“中级人民法院管辖下列第一审行政案件：（一）对国务院部门或者县级以上地方人民政府所作的行政行为提起诉讼的案件；（二）海关处理的案件；（三）本辖区内重大、复杂的案件……”，因此A、C选项均正确。", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 160, "subject": "相关法", "id": "xg_544"},
  {"question": "对省人民政府工作部门所作的具体行政行为不服提起诉讼的，由下列哪级人民法院管辖？（单选）", "options": ["A. 基层人民法院", "B. 中级人民法院", "C. 高级人民法院", "D. 最高人民法院"], "answer": "A", "explanation": "对省人民政府工作部门所作的具体行政行为不服提起诉讼，应由基层人民法院管辖，如果被告是省人民政府或者国务院工作部门，则由中级人民法院管辖，因此A选项正确。", "type": "single", "topic": "专题五 行政诉讼法", "page": 160, "subject": "相关法", "id": "xg_545"},
  {"question": "甲、乙两村分别位于某市两县境内，因土地权属纠纷向市政府申请解决，市政府裁决争议土地属于甲村所有。乙村不服行政复议决定，提起行政诉讼。下列哪个法院对本案有管辖权？（单选）", "options": ["A. 争议土地所在的基层人民法院", "B. 争议土地所在的中级人民法院", "C. 市政府所在的基层人民法院", "D. 省政府所在的中级人民法院"], "answer": "A", "explanation": "根据行政诉讼法，行政案件一般由被告所在地的基层人民法院管辖，除非法律另有规定。", "type": "single", "topic": "专题五 行政诉讼法", "page": 167, "subject": "相关法", "id": "xg_546"},
  {"question": "区公安局将甲拘留10日，乙拘留5日。甲不服，提起行政诉讼。区公安局出庭应诉，下列说法正确的是：（多选）", "options": ["A. 区公安局负责人出庭的，应当由区公安局局长出庭应诉", "B. 区公安局局长出庭应诉的，可以另行委托1-2名诉讼代理人", "C. 区公安局负责人和工作人员不出庭，委托2名律师出庭", "D. 主管相关业务的副局长属于行政机关负责人"], "answer": "BD", "explanation": "本题中，区公安局负责人不仅限于区公安局局长，还可以包括副局长以及参与分管的负责人，行政机关的负责人和工作人员不出庭，不得仅委托律师出庭，因此A、C选项错误，B、D选项正确。（2018）", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 166, "subject": "相关法", "id": "xg_547"},
  {"question": "李某从田某处购得一辆轿车，但未办理过户手续。在一次查验过程中，某市公安局认定该车系走私车，予以没收。李某不服，向市人民政府申请复议，后者维持了没收决定。李某提起行政诉讼。下列哪些选项是正确的？（多选）", "options": ["A. 市人民政府为本案的被告", "B. 田某不能成为本案的第三人", "C. 市公安局所在地的法院对本案有管辖权", "D. 市人民政府所在地的法院对本案有管辖权"], "answer": "CD", "explanation": "A选项，李某不服某市公安局没收决定，向市人民政府申请复议，市人民政府维持了某市公安局的没收决定，因此某市公安局和市人民政府为共同被告，A选项错误。B选项，李某从田某处购得走私车，田某同被诉行政行为及同案件处理结果有利害关系，可以成为本案的第三人，因此B选项错误。C、D选项，市公安局所在地的法院和市人民政府所在地的法院均有管辖权，C、D选项正确。（法考2009改编）", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 168, "subject": "相关法", "id": "xg_548"},
  {"question": "行政诉讼中，原告要求相关行政执法人员作为证人出庭说明，在下列何种情形下，法院通常不予准许？(单选)", "options": ["A. 对现场笔录的合法性或者真实性有异议的", "B. 对行政执法人员的身份的合法性有异议的", "C. 对行政执法人员的执法程序有异议的", "D. 对行政执法人员的执法权限有异议的"], "answer": "D", "explanation": "《最高人民法院关于行政诉讼证据若干问题的规定》第44条规定：\"有下列情形之一，原告或者第三人可以要求相关行政执法人员作为证人出庭作证：（一）对现场笔录的合法性或者真实性有异议的……（四）对行政执法人员的身份的合法性有异议的……\"，因此A、B、C选项法院予以准许，D选项不符合规定，法院通常不予准许。", "type": "single", "topic": "专题五 行政诉讼法", "page": 169, "subject": "相关法", "id": "xg_549"},
  {"question": "某环保联合会对某公司提起环境民事公益诉讼，因在诉讼中需要该公司的相关环保资料，遂向县生态环境局提出申请公开该公司的排污许可证、排污口数量和位置等有关环境信息。申请书中载明了单位名称、住所地、联系人及电话并加盖了公章、获取信息的方式等。县生态环境局收到申请后，要求环保联合会提供申请人身份的证明材料。环保联合会提供了社会团体登记证复印件。县生态环境局以申请公开的内容不明确为由拒绝公开，该环保联合会遂提起行政诉讼。关于本案的起诉，下列说法正确的是：（多选）", "options": ["A. 本案由县生态环境局所在地法院或者环保联合会所在地的法院管辖", "B. 起诉期限为6个月", "C. 如法院当场不能判定起诉是否符合条件的，应接受起诉状，出具注明收到日期的书面凭证，并在7日内决定是否立案", "D. 如法院当场不能判定起诉是否符合条件，经7日内仍不能作出判断的，应裁定暂缓立案"], "answer": "BC", "explanation": "A选项，本案遵循原告就被告的地域管辖原则，只能由被告县生态环境局所在地法院管辖，因此A选项错误。B选项，《行政诉讼法》第46条第1款规定：‘公民、法人或者其他组织直接向人民法院提起诉讼的，应当自知道或者应当知道作出行政行为之日起6个月内提出。法律另有规定的除外’，因此B选项正确。C选项，《行政诉讼法》第51条第2款规定：‘对当场不能判定是否符合本法规定的起诉条件的，应当接收起诉状，出具注明收到日期的书面凭证，并在7日内决定是否立案……’，因此C选项正确。D选项，《行政诉讼解释》第53条第2款规定：‘……7日内仍不能作出判断的，应当先予立案’，因此D选项错误。（法考2017）", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 174, "subject": "相关法", "id": "xg_550"},
  {"question": "县政府以某化工厂不符合国家产业政策、污染严重为由，决定强制关闭该厂。该厂向法院起诉要求撤销该决定，并提出赔偿请求。一审法院认定县政府决定违法，予以撤销，但未对赔偿请求作出裁判，县政府提出上诉。下列说法正确的是：（多选）", "options": ["A. 本案第一审应由县法院管辖", "B. 二审法院不得以不开庭方式审理该上诉案件", "C. 二审法院应对一审法院的判决和被诉行政行为进行全面审查", "D. 如二审法院经审查认为依法不应给予该厂赔偿的，应判决驳回其赔偿请求"], "answer": "BCD", "explanation": "A选项，对于县政府提起的行政诉讼，一审应由中级人民法院管辖，A选项错误。B选项，一审遗漏赔偿请求，二审重新提出，属于有新的理由，二审应当开庭审理，B选项正确。C选项，《行政诉讼法》第87条规定：‘人民法院审理上诉案件，应当对原审人民法院的判决、裁定和被诉行政行为进行全面审查’，因此C选项正确。D选项，《行政诉讼法解释》第109条第4款规定：‘原审判决遗漏行政赔偿请求，第二审人民法院经审查认为依法不应当予以赔偿的，应当判决驳回行政赔偿请求’，因此D选项正确。（法考2017）", "type": "multiple", "topic": "专题五 行政诉讼法", "page": 181, "subject": "相关法", "id": "xg_551"},
  {"question": "1. 下列可以在我国申请注册的商标种类有?(多选)", "options": ["A. 证明商标", "B. 服务商标", "C. 集体商标", "D. 商品商标"], "answer": "ABCD", "explanation": "《商标法》第3条第1款中规定,经国务院商标管理部门核准注册的商标为注册商标,包括商品商标、服务商标和集体商标、证明商标,因此A、B、C、D选项均正确。(新编)", "type": "multiple", "topic": "专题六 商标法", "page": 165, "subject": "相关法", "id": "xg_552"},
  {"question": "2. 根据商标法及相关规定,下列关于证明商标的说法哪些是正确的?(多选)", "options": ["A. 由对某种商品或者服务具有监督能力的组织所控制", "B. 由对某种商品或者服务具有监督能力的组织成员内的单位或者个人使用于其商品或者服务", "C. 用以证明该商品或者服务的原产地、原料、制造方法、质量或者其他特定品质", "D. 以团体、协会或者其他组织名义注册,供该组织成员在商事活动中使用,以表明使用者在该组织中的成员资格"], "answer": "AC", "explanation": "A、B、C选项,《商标法》第3条第3款规定:“本法所称证明商标,是指由对某种商品或者服务具有监督能力的组织所控制,而由该组织以外的单位或者个人使用于其商品或者服务,用以证明该商品或者服务的原产地、原料、制造方法、质量或者其他特定品质的标志”,因此A、C选项正确,B选项错误。D选项,《商标法》第3条第2款规定:“本法所称集体商标,是指以团体、协会或者其他组织名义注册,供该组织成员在商事活动中使用,以表明使用者在该组织中的成员资格的标志”,因此D选项描述的是集体商标,D选项错误。(2011)", "type": "multiple", "topic": "专题六 商标法", "page": 165, "subject": "相关法", "id": "xg_553"},
  {"question": "3. 根据商标法及相关规定,下列哪些可以作为商标申请注册?(多选)", "options": ["A. 三维标志", "B. 声音", "C. 气味"], "answer": "ABD", "explanation": "A、B、D选项,《商标法》第8条规定:“任何能够将自然人、法人或者其他组织的商品与他人的商品区别开的标志,包括文字、图形、字母、数字、三维标志、颜色组合和声音等,以及上述要素的组合,均可以作为商标申请注册”,因此A、B、D选项正确。C选项,气味不可以作为商标申请注册,因此C选项错误。(2015)", "type": "multiple", "topic": "专题六 商标法", "page": 165, "subject": "相关法", "id": "xg_554"},
  {"question": "4. 根据商标法及相关规定，下列哪些商标不能在我国获准注册？(多选)", "options": ["A. 单一颜色商标", "B. 立体商标", "C. 位置商标", "D. 声音商标"], "answer": "ABCD", "explanation": "根据《商标法》第11条第1款规定：‘下列标志不得作为商标注册：（一）仅有本商品的通用名称、图形、型号的……（三）其他缺乏显著特征的’，因此A选项不得作为商标注册。B、C、D选项，《商标法》第12条规定：‘以三维标志申请注册商标的，仅由商品自身的性质产生的形状、为获得技术效果而需有的商品形状或者使商品具有实质性价值的形状，不得注册’，因此B、C、D选项不得作为商标注册。（新编）", "type": "multiple", "topic": "专题六 商标法", "page": 166, "subject": "相关法", "id": "xg_555"},
  {"question": "5. 根据商标法及相关规定，下列关于证明商标、集体商标的哪些说法是正确的？(多选)", "options": ["A. 地理标志可以作为证明商标申请注册", "B. 地理标志可以作为集体商标申请注册", "C. 集体商标只能是服务商标", "D. 证明商标只能是商品商标"], "answer": "AB", "explanation": "A、B选项，《商标条例》第4条第1款规定，“商标法第16条规定的地理标志，可以依照商标法和本条例的规定，作为证明商标或者集体商标申请注册”，因此A、B选项正确。C、D选项，商品商标和服务商标是按指定使用对象分类，集体商标和证明商标是按持有人主体分类，集体商标、证明商标均可以是商品商标或服务商标，因此C、D选项错误。(2012)", "type": "multiple", "topic": "专题六 商标法", "page": 166, "subject": "相关法", "id": "xg_556"},
  {"question": "6. 根据商标法及相关规定，关于地理标志的说法正确的是：(单选)", "options": ["A. 地理标志注册为商标必须为集体商标或证明商标", "B. 商标中有商品的地理标志，误导公众的，不予注册但可以使用", "C. 商标中有商品的地理标志，由于该商品并非来源于该标志所标示的地区，误导公众，即便已经善意取得注册仍可宣告无效", "D. 地理标志商标与普通商标之间不能进行近似性比较"], "answer": "A", "explanation": "A选项，《商标条例》第4条第1款规定：“商标法第16条规定的地理标志，可以依照商标法和本条例的规定，作为证明商标或者集体商标申请注册”，因此A选项正确。B、C选项，《商标法》第16条第1款规定：“商标中有商品的地理标志，而该商品并非来源于该标志所标示的地区，误导公众的，不予注册并禁止使用；但是，已经善意取得注册的继续有效”，因此B、C选项错误。D选项，《商标法》第30条中规定，申请注册的商标，凡不符合本法有关规定或者同他人在同一种商品或者类似商品上已经注册的或者初步审定的商标相同或者近似的，由国务院商标管理部门驳回申请，不予公告，该规定并未排除地理标志，因此D选项错误。(2018)", "type": "single", "topic": "专题六 商标法", "page": 166, "subject": "相关法", "id": "xg_557"},
  {"question": "7. “慈溪蜜梨”产于浙江省宁波市慈溪市，因其不同于一般梨子，果大，水分特别充足，营养极为丰富而出名。现该地区欲对“慈溪蜜梨”地理标志进行注册保护，在商标法体系下可以如何申请注册？(单选)", "options": ["A. 申请注册普通商标", "B. 申请注册地名商标"], "answer": "D", "explanation": "《商标条例》第4条第1款规定：“商标法第16条的地理标志，可以依照商标法和本条例的规定，作为证明商标或者集体商标申请注册”，因此A、B、C选项错误，D选项正确。(2019)", "type": "single", "topic": "专题六 商标法", "page": 166, "subject": "相关法", "id": "xg_558"},
  {"question": "8. 根据商标法及相关规定,下列哪些不得作为商标注册的三维标志?(多选)", "options": ["A. 仅有指定使用商品的通用形状、无显著特征的", "B. 仅由商品自身的性质产生的形状", "C. 使商品具有实质性价值的形状", "D. 为获取技术效果而需有的商品形状"], "answer": "ABCD", "explanation": "A选项，红新月不得作为商标使用。B选项，“叫只鸡”用在餐饮等服务中无不良影响，但用在酒店、桑拿等服务中存在不良影响、有害社会主义道德风尚，不得作为商标使用。C选项，国家知识产权局的标志属于中央国家机关的标志，不得作为商标使用。D选项，“中国强制性产品认证(CCC)”标志属于与实施控制、予以保证的官方标志相同或近似的标记，不能作为商标使用。(2018)", "type": "multiple", "topic": "专题六 商标法", "page": 167, "subject": "相关法", "id": "xg_559"},
  {"question": "9. 根据商标法及相关规定,下列哪些标志可以作为商标使用?(多选)", "options": ["A. 同中华人民共和国国歌近似的", "B. 同政府间国际组织的名称近似,但经该组织同意的", "C. 缺乏显著特征的标志", "D. 同“红十字”的名称近似的"], "answer": "D", "explanation": "A、C选项，由于2020年新冠疫情的影响，以雷神山、钟南山注册商标属于《商标法》第10条第1款第(八)项规定的有害于社会主义道德风尚或者有其他不良影响的情形，因此A、C选项不可以注册商标。B选项，根据《商标法》第10条第2款的规定，昆山属于县级以上行政区划的地名，不可以注册商标。D选项，泰山可以注册商标。(新编)", "type": "multiple", "topic": "专题六 商标法", "page": 167, "subject": "相关法", "id": "xg_560"},
  {"question": "10. 根据商标法及相关规定,下列哪些标志不得作为商标使用?(多选)", "options": ["A. 带有民族歧视性的", "B. 带有欺骗性,容易使公众对商品的产地产生误认的", "C. 仅直接表示商品的质量、主要原料、功能、用途、重量、数量及其他特点的", "D. 同某国的国旗近似且未获得该国政府同意的"], "answer": "ABD", "explanation": "A、B、D选项,《商标法》第10条第1款规定:“下列标志不得作为商标使用:……(二)同外国的国家名称、国旗、国徽、军旗等相同或者近似的,但经该国政府同意的除外……(六)带有民族歧视性的;(七)带有欺骗性,容易使公众对商品的质量等特点或者产地产生误认的……”,因此A、B、D选项不得作为商标使用。C选项,《商标法》第11条第1款规定:“下列标志不得作为商标注册:……(二)仅直接表示商品的质量、主要原料、功能、用途、重量、数量及其他特点的……”,因此C选项不得作为商标注册,但可以使用。(2016)", "type": "multiple", "topic": "专题六 商标法", "page": 167, "subject": "相关法", "id": "xg_561"},
  {"question": "11. 声音商标如何才能取得显著特征?(单选)", "options": ["A. 可以用文字进行描述的声音", "B. 长期使用", "C. 设计独特", "D. 注册"], "answer": "B", "explanation": "一般情况下,声音商标需经长期使用才能取得显著特征,因此A、C、D选项错误,B选项正确。(新编)", "type": "single", "topic": "专题六 商标法", "page": 167, "subject": "相关法", "id": "xg_562"},
  {"question": "12. 根据商标法的规定，下列哪些说法是正确的？ （多选）", "options": ["A. 申请注册的商标应当有新颖性", "B. 申请注册的商标应当有显著特征，便于识别", "C. 申请注册的商标应当有实用性，富有美感", "D. 申请注册的商标不得与他人在先取得的合法权利相冲突"], "answer": "BD", "explanation": "A选项错误，因为商标法并未要求商标具有新颖性；B选项正确，显著性是商标注册的基本要求；C选项错误，实用性不是商标注册的法定要求；D选项正确，不能侵犯他人在先权利。", "type": "multiple", "topic": "专题六 商标法", "page": 168, "subject": "相关法", "id": "xg_563"},
  {"question": "13. 河北省魏县出产的鸭梨营养丰富，口感独特，远近闻名，当地有关单位拟对其采取的保护措施中，哪些是不符合商标法规定的？(多选)", "options": ["A. 将“魏县鸭梨”申请注册为集体商标，使用于鸭梨上", "B. 将“魏县鸭梨”申请注册为证明商标，使用于鸭梨上", "C. 将鸭梨的形状申请注册为立体商标，使用于鸭梨上", "D. 将“香梨”申请注册为文字商标，使用于鸭梨上"], "answer": "CD", "explanation": "A选项正确，地理标志产品可申请集体商标；B选项正确，地理标志也可申请证明商标；C选项错误，产品的通用形状不能注册为立体商标；D选项错误，“香梨”属于商品通用名称，不能注册。", "type": "multiple", "topic": "专题六 商标法", "page": 168, "subject": "相关法", "id": "xg_564"},
  {"question": "14. 河川县盛产荔枝，远近闻名。该县成立了河川县荔枝协会，申请注册了“河川”商标，核定使用在荔枝商品上，许可本协会成员使用。加入该荔枝协会的农户将有“河川”商标包装的荔枝批发给盛联超市销售。超市在销售该批荔枝时，在荔枝包装上还加贴了自己的注册商标“盛联”。下列哪些说法是正确的？(多选)", "options": ["A. “河川”商标是集体商标", "B. “河川”商标是证明商标", "C. “河川”商标使用了县级以上行政区划名称，应被宣告无效", "D. 盛联超市的行为没有侵犯商标权"], "answer": "AD", "explanation": "A、B选项，证明商标是开放的，直接证明品质，集体商标是封闭的，证明身份。“河川”商标是由河川县荔枝协会申请注册，核定使用在荔枝商品上，许可本协会成员使用，属于集体商标而不是证明商标，因此A选项正确，B选项错误。C选项，“河川”商标虽然使用了县级以上行政区划名称，但由于“河川”有其他含义，且已经注册为商标，可以继续使用，因此C选项错误。D选项，超市作为商品的经营者，为了加以区别，对于自己销售的商品可以另行注册商标，使用在产品的包装上，因此D选项正确。(法考2015)", "type": "multiple", "topic": "专题六 商标法", "page": 168, "subject": "相关法", "id": "xg_565"},
  {"question": "15. 根据《商标法》及相关规定，下列哪些标识不得作为商标使用？(多选)", "options": ["A. 注册商标需要在核定使用范围之外的商品上取得商标专用权的，应当提出变更申请", "B. 注册商标需要改变其标志的，应当提出变更申请", "C. 注册商标需要变更注册人地址的，应当提出变更申请", "D. 注册商标需要变更注册人名义的，应当提出变更申请"], "answer": "ABCD", "explanation": "A选项，红新月不得作为商标使用。B选项，“叫只鸡”用在餐饮等服务中无不良影响，但用在酒店、桑拿等服务中存在不良影响、有害社会主义道德风尚，不得作为商标使用。C选项，国家知识产权局的标志属于中央国家机关的标志，不得作为商标使用。D选项，“中国强制性产品认证(CCC)”标志属于与实施控制、予以保证的官方标志相同或近似的标记，不能作为商标使用。\n（2018，思维扩展）", "type": "multiple", "topic": "专题六 商标法", "page": 168, "subject": "相关法", "id": "xg_566"},
  {"question": "16. 根据商标法及相关规定,下列哪项名称可以注册商标?(单选)", "options": ["A. 雷神山", "B. 昆山", "C. 钟南山", "D. 泰山"], "answer": "A", "explanation": "《商标法》第39条规定：‘注册商标的有效期为10年，自核准注册之日起计算’，因此A、B选项错误。C选项，《商标法》第40条规定：‘注册商标有效期限届满，需要继续使用的，商标注册人应当在期满前十二个月内按照规定办理续展手续’，故C选项错误。D选项未提及，不符合法律规定。因此正确答案为A。", "type": "single", "topic": "专题六 商标法", "page": 169, "subject": "相关法", "id": "xg_567"},
  {"question": "17. 下列哪些标记不能作为商标注册?(多选)", "options": ["A. 国家知识产权局对其局徽申请商标", "B. 扬州市烹饪协会申请“扬州炒饭”作为地理标志集体商标,指定服务为饭店、餐厅", "C. 中国烹饪协会申请“烹饪名师”作为证明商标", "D. 某眼镜店申请“屠呦呦”商标,指定商品为眼镜"], "answer": "ABC", "explanation": "A选项，国家知识产权局作为国家机关不能申请商标，因此A选项不能作为商标注册。B选项，“扬州炒饭”是中餐菜肴通用名称，因此B选项不能作为商标注册。C选项，中国烹饪协会申请“烹饪名师”作为证明商标不具有显著性，因此C选项不能作为商标注册。", "type": "multiple", "topic": "专题六 商标法", "page": 169, "subject": "相关法", "id": "xg_568"},
  {"question": "18. 根据商标法及相关规定,某企业在其生产的人用药品上使用“我不是药神”作为商标使用,但未进行注册,下列哪些说法是错误的;(多选)", "options": ["A. 该商标未经注册,不得在市场销售", "B. 该商标损害他人在先权利,不能获得注册", "C. 该商标不具备显著性,不能注册", "D. 该商标不需要经过注册即可使用,也可以在市场上销售"], "answer": "ACD", "explanation": "A选项,一般商品在市场销售,不一定使用注册商标,目前只有烟草类产品必须使用注册商标,因此A选项错误。B选项,《我不是药神》为电影名称,享有著作权,该商标损害其在先权利,不能获得注册,因此B选项正确。C选项,“我不是药神”作为商标能区分出商品或服务的提供者,具有显著性,因此C选项错误。D选项,由于“我不是药神”享有著作权,一旦在市场上销售,将会侵犯著作权,因此D选项错误。(2018,思维扩展)", "type": "multiple", "topic": "专题六 商标法", "page": 169, "subject": "相关法", "id": "xg_569"},
  {"question": "19. 某企业未经许可将迪士尼公司的米老鼠形象擅自作为商标申请注册使用在白酒上,该企业的行为属于?(单选)", "options": ["A. 侵犯他人的著作权进行注册", "B. 虚构事实真相申请注册"], "answer": "A", "explanation": "《商标法》第32条规定:“申请商标注册不得损害他人现有的在先权利,也不得以不正当手段抢先注册他人已经使用并有一定影响的商标”。本题中,米老鼠形象属于迪士尼公司的作品,因此侵犯他人的著作权,A选项正确。(新编)", "type": "single", "topic": "专题六 商标法", "page": 169, "subject": "相关法", "id": "xg_570"},
  {"question": "20. 根据商标法的规定，下列说法哪些是正确的？（多选）", "options": ["A. 商标注册申请人应当是已经在我国生产商品或者提供服务的经营者", "B. 商标注册申请人应当有生产经营活动的资格", "C. 商标注册申请人可以是在中国没有经常居所的外国人", "D. 商标注册申请人可以是两个或两个以上的自然人"], "answer": "BCD", "explanation": "A选项错误，因为《商标法》第19条第2款规定：‘委托人申请注册的商标可能存在本法规定不得注册情形的，商标代理机构应当明确告知委托人’，因此A选项错误。B选项，《商标法》第19条第2款规定：‘委托人申请注册的商标可能存在本法规定不得注册情形的，商标代理机构应当明确告知委托人’，因此B选项正确。C选项，《商标法》第19条第4款规定：‘商标代理机构除对其代理服务申请商标注册外，不得申请注册其他商标’，因此C选项正确。D选项，《商标法》第19条第1款规定：‘商标代理机构……对在代理过程中知悉的被代理人的商业秘密，负有保密义务’，因此D选项正确。（2014）", "type": "multiple", "topic": "专题六 商标法", "page": 170, "subject": "相关法", "id": "xg_571"},
  {"question": "22. 根据商标法及相关规定，下列关于商标代理机构的哪些说法是正确的？（多选）", "options": ["A. 申请商标注册或者办理其他商标事宜，应当委托商标代理机构办理", "B. 委托人申请注册的商标可能存在商标法规定不得注册情形的，商标代理机构应当明确告知委托人", "C. 商标代理机构除对其代理服务申请商标注册外，不得申请注册其他商标", "D. 商标代理机构对在代理过程中知悉的被代理人的商业秘密，负有保密义务"], "answer": "BCD", "explanation": "A选项，《商标法》第18条规定：“申请商标注册或者办理其他商标事宜，可以自行办理，也可以委托依法设立的商标代理机构办理。外国人或者外国企业在中国申请商标注册和办理其他商标事宜的，应当委托依法设立的商标代理机构办理”，因此A选项错误。B选项，《商标法》第19条第2款规定：“委托人申请注册的商标可能存在本法规定不得注册情形的，商标代理机构应当明确告知委托人”，因此B选项正确。C选项，《商标法》第19条第4款规定：“商标代理机构除对其代理服务申请商标注册外，不得申请注册其他商标”，因此C选项正确。D选项，《商标法》第19条第1款规定：“商标代理机构……；对在代理过程中知悉的被代理人的商业秘密，负有保密义务”，因此D选项正确。（2014）", "type": "multiple", "topic": "专题六 商标法", "page": 170, "subject": "相关法", "id": "xg_572"},
  {"question": "23. 根据商标法及相关规定，在中国申请注册商标或办理其他商标事宜的，下列哪些应当委托国家认可的具有商标代理资格的组织代理？（多选）", "options": ["A. 在中国没有经常居所的美国人", "B. 在中国没有营业所的英国企业", "C. 在中国有经常居所的美国人", "D. 在中国有营业所的英国企业"], "answer": "AB", "explanation": "《商标法》第18条第2款规定：“外国人或者外国企业在中国申请商标注册和办理其他商标事宜的，应当委托依法设立的商标代理机构办理”，《商标法实施条例》第5条第4款规定：“商标法第18条所称外国人或者外国企业，是指在中国没有经常居所或者营业所的外国人或者外国企业”，因此A、B选项需要委托代理机构，C、D选项无需委托代理机构。（2012）", "type": "multiple", "topic": "专题六 商标法", "page": 170, "subject": "相关法", "id": "xg_573"},
  {"question": "24. 商标代理机构有下列哪些情形的，需要承担法律责任?(多选)", "options": ["A. 以诋毁其他商标代理机构等手段招徕商标代理业务或者其他不正当手段扰乱商标代理市场秩序的", "B. 代理不以使用为目的的恶意商标注册申请", "C. 商标代理机构知道或者应当知道委托人申请注册的商标属于不得接受委托情形，接受其委托的", "D. 商标代理机构除对其代理服务申请商标注册外，申请注册其他商标"], "answer": "AB", "explanation": "根据《商标法》第19条第3款的规定，商标代理机构知道或者应当知道委托人申请注册的商标属于商标法第4条（不以使用为目的的恶意商标注册申请）、第15条（就同一商品或者类似商品申请注册的商标与他人在先使用的未注册商标相同或者近似，申请人与该他人具有前款规定以外的合同、业务往来关系或者其他关系而明知该他人商标存在）和第32条（损害他人现有在先权利的）规定的情形的，不得接受其委托。因此A、B、C、D选项说法均正确。（新编）", "type": "multiple", "topic": "专题六 商标法", "page": 171, "subject": "相关法", "id": "xg_574"},
  {"question": "25. 关于商标代理机构，下列哪些说法是正确的？(多选)", "options": ["A. 商标代理从业人员可以以个人名义自行接受委托", "B. 商标代理机构除对其代理服务申请商标注册外，不得申请注册其他商标", "C. 商标代理机构对在代理过程中知悉的被代理人的商业秘密，没有保密义务", "D. 委托人申请注册的商标可能存在商标法不得注册情形的，商标代理机构应当明确告知委托人"], "answer": "BD", "explanation": "A选项，根据《商标条例》第85条的规定，商标代理从业人员不得以个人名义自行接受委托，因此A选项错误。B选项，《商标法》第19条第4款规定：“商标代理机构除对其代理服务申请商标注册外，不得申请注册其他商标”，因此B选项正确。C选项，根据《商标法》第19条的规定，商标代理机构对在代理过程中知悉的被代理人的商业秘密，负有保密义务，因此C选项错误。D选项，《商标法》第19条第2款规定：“委托人申请注册的商标可能存在本法规定不得注册情形的，商标代理机构应当明确告知委托人”，因此D选项正确。(新编)", "type": "multiple", "topic": "专题六 商标法", "page": 171, "subject": "相关法", "id": "xg_575"},
  {"question": "26. 商标代理机构应当遵循诚实信用原则，知道或者应当知道委托人申请商标注册属于下列哪些情形，不得接受其委托?(多选)", "options": ["A. 申请人申请注册商标属于不以使用为目的的恶意申请注册的", "B. 恶意抢注他人在先具有一定知名度商标的", "C. 申请人与他人存在合同或业务往来关系，就同一种商品或者类似商品申请注册的商标与他人在先使用的"], "answer": "ABC", "explanation": "根据《商标法》第19条第3款的规定，商标代理机构知道或者应当知道委托人申请注册的商标属于商标法第4条（不以使用为目的的恶意申请）、第15条（代理人、代表人或其他特定关系人的抢注）和第32条（损害他人现有的在先权利或抢注已经使用并有一定影响的商标）规定情形的，不得接受其委托，因此A、B、C选项正确，D选项错误。(新编)", "type": "multiple", "topic": "专题六 商标法", "page": 171, "subject": "相关法", "id": "xg_576"},
  {"question": "27. 根据商标法及相关规定,关于商标代理机构申请国际注册的说法,下列哪些是正确的?(多选)", "options": ["A. 商标代理机构的股东可以以其他公司的名义申请商标", "B. 商标代理机构可以接受委托人所有自愿申请商标的委托", "C. 商标代理机构只能申请代理服务上的商标", "D. 商标代理机构从业人员可以以个人名义接受委托"], "answer": "ABCD", "explanation": "A选项，《商标条例》第13条第1款中规定，每一件商标注册申请应当向国家知识产权局提交《商标注册申请书》1份、商标图样1份，因此A选项正确。B选项，《商标条例》第13条第7款规定：“商标为外文或者包含外文的，应当说明含义”，因此B选项正确。C选项，《商标条例》第15条第2款规定：“商标注册申请等有关文件以纸质方式提出的，应当打字或者印刷”，因此C选项正确。D选项，《商标条例》第14条第1款规定：“申请商标注册的，申请人应当提交其身份证明文件……”，因此D选项正确。(2012)", "type": "multiple", "topic": "专题六 商标法", "page": 172, "subject": "相关法", "id": "xg_577"},
  {"question": "28. 以下关于商标代理机构备案说法正确的是?(多选)", "options": ["A. 商标代理机构从事国家知识产权局主管的商标事宜代理业务的,应当依法及时向国家知识产权局备案,备案的有效期为3年", "B. 商标代理机构备案信息发生变化的,应当自实际发生变化或者有关主管部门登记、批准之日起3个月内向国家知识产权局办理变更备案,并提交相应材料", "C. 商标代理机构应当在申请市场主体注销登记或者自行决定不再从事商标代理业务前,按照法律法规规定和合同约定妥善处理未办结的商标代理业务", "D. 商标代理机构每次延续备案的有效期为3年,自办理备案之日起计算"], "answer": "AC", "explanation": "A、D选项,根据《商标代理监督管理规定》第5条的规定,商标代理机构从事国家知识产权局主管的商标事宜代理业务的,应当依法及时向国家知识产权局备案。商标代理机构备案的有效期为3年。每次延续备案的有效期为3年,自原备案有效期满次日起计算,因此A选项正确,D选项错误。B选项,《商标代理监督管理规定》第7条规定:“商标代理机构备案信息发生变化的,应当自实际发生变化或者有关主管部门登记、批准之日起30日内向国家知识产权局办理变更备案,并提交相应材料”,因此B选项错误。C选项,《商标代理监督管理规定》第8条第3款规定:“商标代理机构应当在申请市场主体注销登记或者自行决定不再从事商标代理业务前,或者自接到撤销、吊销决定书、永久停止受理其办理商标代理业务决定之日起30日内,按照法律法规规定和合同约定妥善处理未办结的商标代理业务……”,因此C选项正确。(新编)", "type": "multiple", "topic": "专题六 商标法", "page": 172, "subject": "相关法", "id": "xg_578"},
  {"question": "29. 以下关于对商标代理机构的监管说法正确的是?(多选)", "options": ["A. 对商标代理机构和商标代理从业人员受到行政处罚的信息,应记入信用档案", "B. 商标代理机构应当按照国家有关规定报送年度报告"], "answer": "ABCD", "explanation": "A选项,《商标代理监督管理规定》第21条规定:“以下信息应当记入商标代理机构和商标代理从业人员信用档案:(一)商标代理机构和商标代理从业人员受到行政处罚的信息……”,因此A选项正确。B选项,《商标代理监督管理规定》第22条规定:“商标代理机构应当按照国家有关规定报送年度报告”,因此B选项正确。C选项,《商标代理监督管理规定》第24条规定:“知识产权管理部门依法对商标代理机构和商标代理从业人员代理行为进行监督检查……商标代理机构和商标代理从业人员应当予以协助配合”,《商标代理监督管理规定》第25条第2款规定:“对存在商标代理违法违规行为的商标代理机构或者商标代理从业人员,知识产权管理部门可以依职责对其进行约谈、提出意见,督促其及时整改”,因此C选项正确。D选项,《商标代理监督管理规定》第23条规定:“商标代理机构故意侵犯知识产权,", "type": "multiple", "topic": "专题六 商标法", "page": 172, "subject": "相关法", "id": "xg_579"},
  {"question": "1. 根据商标法及相关规定,下列关于商标注册申请的哪些说法是正确的?(多选)", "options": ["A. 申请商标注册应当提交《商标注册申请书》和商标图样", "B. 申请注册的商标为外文或者包含外文的,应当说明其含义", "C. 商标注册申请等有关文件以纸质方式提出的,应当打字或者印刷", "D. 商标注册申请人应当提交其身份证明文件"], "answer": "ABCD", "explanation": "A选项,《商标条例》第13条第1款中规定,每一件商标注册申请应当向国务院商标管理部门提交《商标注册申请书》1份、商标图样1份,因此A选项正确。B选项,《商标条例》第13条第7款规定:“商标为外文或者包含外文的,应当说明含义”,因此B选项正确。C选项,《商标条例》第15条第2款规定:“商标注册申请等有关文件以纸质方式提出的,应当打字或者印刷”,因此C选项正确。D选项,根据《商标条例》第14条的规定,申请商标注册的,申请人应当提交其身份证明文件,因此D选项正确。(2012)", "type": "multiple", "topic": "专题六 商标法", "page": 173, "subject": "相关法", "id": "xg_580"},
  {"question": "3. 根据商标法及相关规定,商标注册申请等有关文件可以什么方式提出?(多选)", "options": ["A. 由申请人本人录音录像", "B. 书面方式", "C. 在商标受理窗口口头提出 - 172 -"], "answer": "BD", "explanation": "《商标法》第22条第3款规定:“商标注册申请等有关文件,可以以书面方式或者数据电文方式提出”,因此B、D选项正确。(新编)", "type": "multiple", "topic": "专题六 商标法", "page": 173, "subject": "相关法", "id": "xg_581"},
  {"question": "5. 根据商标法及相关规定，在下列哪些情形下，应当提出新的商标注册申请?（多选）", "options": ["A. 注册商标需要在核定使用范围之外的商品上取得商标专用权的", "B. 商标注册申请人变更其名义的", "C. 注册商标需要改变其标志的", "D. 商标注册申请人删减指定的商品的"], "answer": "AC", "explanation": "A选项，《商标法》第23条规定：“注册商标需要在核定使用范围之外的商品上取得商标专用权的，应当另行提出注册申请”，因此A选项正确。B、D选项，《商标条例》第17条第1款规定：“申请人变更其名义、地址、代理人、文件接收人或者删减指定的商品的，应当向商标局办理变更手续”，因此B、D选项错误。C选项，《商标法》第24条规定：“注册商标需要改变其标志的，应当重新提出注册申请”，因此C选项正确。(新编)", "type": "multiple", "topic": "专题六 商标法", "page": 174, "subject": "相关法", "id": "xg_582"},
  {"question": "6. 根据商标法的规定，下列哪些情形下，巴黎公约成员国的商标注册申请人可以在中国享有优先权?（多选）", "options": ["A. 申请人自其商标在巴黎公约成员国第一次提出商标注册申请之日起6个月内，又在中国就相同商品以同一商标提出商标注册申请的", "B. 申请人自其商标在巴黎公约成员国第一次提出商标注册申请之日起6个月内，又在中国就类似商品以同一商标提出商标注册申请的", "C. 申请人在中国政府主办的国际展览会会展出的商品上首次使用的商标，自该商品展出之日起6个月内，在中国就相同商品以同一商标提出商标注册申请的", "D. 申请人在中国政府承认的国际展览会会展出的商品上首次使用的商标，自该商品展出之日起6个月内，在中"], "answer": "ACD", "explanation": "A、B选项，《商标法》第25条规定：“商标注册申请人自其商标在外国第一次提出商标注册申请之日起6个月内，又在中国就相同商品以同一商标提出商标注册申请的，依照该外国同中国签订的协议或者共同参加的国际条约，或者按照相互承认优先权的原则，可以享有优先权”，享有优先权必须就相同商品以同一商标提出申请的，因此A选项正确，B选项错误。C、D选项，《商标法》第26条规定：“商标在中国政府主办的或者承认的国际展览会会展出的商品上首次使用的，自该商品展出之日起6个月内，该商标的注册申请人可以享有优先权”，因此C、D选项正确。(2006)", "type": "multiple", "topic": "专题六 商标法", "page": 174, "subject": "相关法", "id": "xg_583"},
  {"question": "9. 甲乙两企业都拟在其所生产的服装商品上注册“蓝调”牌商标，均递交了注册申请。下列哪些说法是正确的？(多选)", "options": ["A. 如果二者同一天申请且均未使用或同日使用的，应自行协商确定，协商不成的，将驳回双方申请", "B. 如果二者在同一天申请的，初步审定并公告使用在先的"], "answer": "BD", "explanation": "A、B、C选项，《商标条例》第19条中规定，两个或者两个以上的申请人，在同一种商品或者类似商品上，分别以相同或者近似的商标在同一天申请注册的，应当自收到国务院商标管理部门通知之日起30日内提交使用证据。同日使用或者均未使用的，可以自收到通知之日起30日内自行协商，并将书面协议报送国务院商标管理部门；不愿协商或者协商不成的，国务院商标管理部门通知各申请人以抽签的方式确定一个申请人，驳回其他人的注册申请，国务院商标管理部门已经通知但申请人未参加抽签的，视为放弃申请。因此A、C选项错误，B选项正确。D选项，根据《商标法》第31条的规定，两个或者两个以上的商标注册申请人，在同一种商品或者类似商品上，以相同或者近似的商标申请注册的，初步审定并公告申请在先的商标，因此D选项正确。(新编)", "type": "multiple", "topic": "专题六 商标法", "page": 175, "subject": "相关法", "id": "xg_584"},
  {"question": "13. 李某对驳回其商标注册申请的决定不服。根据商标法及相关规定，下列说法哪项是正确的？(单选)", "options": ["A. 李某可以自收到通知之日起十五日内提出行政复议", "B. 李某可以自收到通知之日起十五日内申请复审", "C. 李某可以自收到通知之日起三个月内申请复审", "D. 李某可以自收到通知之日起三个月内向北京知识产权法院提起行政诉讼"], "answer": "C", "explanation": "A选项错误，因为只有在先权利人或利害关系人才能提出异议，不是任何人；B选项错误，经裁定异议不成立而核准注册的，异议人不服的，可以向商标评审部门申请复审，而非申请人；C选项正确，外国人提出异议必须委托代理机构；D选项错误，异议审理期限最长为12个月，特殊情况下可延长6个月，最多18个月，但题干中未说明特殊情况，故D选项错误。", "type": "single", "topic": "专题六 商标法", "page": 177, "subject": "相关法", "id": "xg_585"},
  {"question": "14. 澳大利亚人汤姆逊认为我国初步审定并予以公告的某商标和其拥有的中国商标相近，欲提出异议。根据商标法及相关规定，下列说法哪些是正确的？(多选)", "options": ["A. 汤姆逊无权对该商标提出异议", "B. 汤姆逊有权提出异议，提出异议的时间期限为自公告之日起三个月内", "C. 汤姆逊有权提出异议，但应委托代理机构代为提出", "D. 汤姆逊有权提出异议，其异议审理期限最长为12个月"], "answer": "BCD", "explanation": "根据《商标法》第33条的规定，对初步审定公告的商标，自公告之日起3个月内，在先权利人、利害关系人认为违反商标法第13条第2款（就相同或者类似商品申请注册的商标是复制、摹仿或者翻译他人未在中国注册的驰名商标，容易导致混淆的）和第3款、第15条、第16条第1款、第30条、第31条、第32条（申请商标注册不得损害他人现有的在先权利，或不得以不正当手段抢先注册他人已经使用并有一定影响的商标的）规定的，可以向国家知识产权局提出异议。因此A、B、C、D选项均正确。", "type": "multiple", "topic": "专题六 商标法", "page": 177, "subject": "相关法", "id": "xg_586"},
  {"question": "15. 根据商标法及相关规定，对初步审定公告的商标，自公告之日起三个月内，在先权利人、利害关系人可以基于下列哪些理由提起异议？(多选)", "options": ["A. 就类似商品申请注册的商标是摹仿他人未在中国注册的驰名商标，容易导致混淆的", "B. 就相同商品申请注册的商标是翻译他人未在中国注册的驰名商标，容易导致混淆的", "C. 申请商标注册损害他人现有的在先权利的"], "answer": "ABCD", "explanation": "根据《商标法》第33条的规定，对初步审定公告的商标，自公告之日起3个月内，在先权利人、利害关系人认为违反商标法第13条第2款和第3款(复制、摹仿、翻译他人驰名商标)、第15条、第16条第1款、第30条、第31条、第32条(损害他人现有的在先权利或抢注已经使用并有一定影响的商标)规定的，可以向国务院商标管理部门提出异议。因此A、B、C、D选项均正确。(2016)", "type": "multiple", "topic": "专题六 商标法", "page": 177, "subject": "相关法", "id": "xg_587"},
  {"question": "16. 根据商标法及相关规定，下列关于异议程序的说法哪项是正确的？(单选)", "options": ["A. 初步审定的商标，先予以公告，自公告之日起三个月内，任何人均可以对其提出异议", "B. 经裁定异议不成立而核准注册的，商标注册申请人取得商标专用权的时间自异议裁定生效之日起计算", "C. 经裁定异议不成立而核准注册的，商标注册申请人取得商标专用权的时间自初审公告三个月期满之日起计算", "D. 当事人不服异议裁定的，可以自收到通知之日起三十日内向人民法院起诉"], "answer": "ABC", "explanation": "A、D选项，《商标法》第59条的规定：\"注册商标中含有的本商品的通用名称、图形、型号，或者直接表示商品的质量、主要原料、功能、用途、重量、数量及其他特点，或者含有地名，注册商标专用权人无权禁止他人正当使用……商标注册人申请商标注册前，他人已经在同一种商品或者类似商品上先于商标注册人使用与注册商标相同或者近似并有一定影响的商标的，注册商标专用权人无权禁止该使用人在原使用范围内继续使用该商标，但可以要求其附加适当区别标识\"，因此A选项正确，D选项错误。B选项，《商标法》第56条规定：\"注册商标的专用权，以核准注册的商标和核定使用的商品为限\"，因此B选项正确。C选项，《商标法》第63条第1款规定：\"侵犯商标专用权……赔偿数额应当包括权利人为制止侵权行为所支付的合理开支\"，因此C选项正确。（2019）", "type": "single", "topic": "专题六 商标法", "page": 178, "subject": "相关法", "id": "xg_588"},
  {"question": "17. 根据商标法及相关规定，下列哪些选项属于不予受理的商标异议申请的情形？(多选)", "options": ["A. 申请人无明确异议理由", "B. 在先权利人、利害关系人共同提出异议申请", "C. 同一异议人为补充证据材料以相同的理由针对同一商标再次提出异议申请的", "D. 在商标初审公告之日起三个月后提出异议申请"], "answer": "ABC", "explanation": "《商标法》第59条第1款规定：“注册商标中含有的本商品的通用名称、图", "type": "multiple", "topic": "专题六 商标法", "page": 178, "subject": "相关法", "id": "xg_589"},
  {"question": "18. 根据商标法及相关规定，经审查对商标异议案件作出决定后，当事人不服的，下列关于救济程序的哪种说法是正确的？(单选)", "options": ["A. 作出准予注册决定的，异议人不服的，可以申请复审", "B. 作出准予注册决定的，异议人不服的，可以申请行政复议", "C. 作出不予注册决定的，被异议人不服的，可以申请复审", "D. 作出不予注册决定的，被异议人不服的，可以向人"], "answer": "C", "explanation": "根据《商标法》第35条第2、3款的规定，国务院商标管理部门做出准予注册决定的，发给商标注册证，并予公告。异议人不服的，可以依照本法第44条、第45条的规定向商标评审部门请求宣告该注册商标无效。被异议人不服的，可以自收到通知之日起15日内向商标评审部门申请复审，被异议人对商标评审部门的决定不服的，可以自收到通知之日起30日内向人民法院起诉，因此A、B、D选项错误，C选项正确。(新编)", "type": "single", "topic": "专题六 商标法", "page": 178, "subject": "相关法", "id": "xg_590"},
  {"question": "24. 下列哪些注册申请应当依法予以驳回?(多选)", "options": ["A. 将“红旗”文字商标使用于油漆商品上", "B. 将“灭蚊”文字商标使用于驱蚊商品上", "C. 将“光明”文字商标使用于灯泡商品上", "D. 将“红高粱”文字商标使用于高粱酿制的白酒类商品上"], "answer": "BD", "explanation": "A选项，相关公众可以区分红旗与我国的国旗、八一军旗，“红旗”文字商标使用于油漆商品上可以注册，A选项不当选。B选项，“灭蚊”文字商标使用于驱蚊商品上仅仅直接表示商品的功能，因此不可以注册，应当驳回。C选项，“光明”并非直接表示灯泡商品的功能，可以注册。D选项，红高粱是高粱酿制白酒的主要原料，不能作为文字商标注册，应当驳回，D选项正确。(法考2007)", "type": "multiple", "topic": "专题六 商标法", "page": 180, "subject": "相关法", "id": "xg_591"},
  {"question": "25. 根据商标法及相关规定，下列说法哪个是正确的?(单选)", "options": ["A. 集体商标注册人对使用管理规则的任何修改，自修改之日起生效", "B. 证明商标注册人可以准许他人使用其证明商标", "C. 集体商标注册人可以许可非本集体成员使用其集体商标", "D. 证明商标注册人可以在自己提供的商品上使用该证明商标"], "answer": "ACD", "explanation": "A选项，《最高人民法院关于审理商标民事纠纷案件适用法律若干问题的解释》第22条第1款规定：\"人民法院在审理商标纠纷案件中，根据当事人的请求和案件的具体情况，可以对涉及的注册商标是否驰名依法作出认定\"，因此A选项正确。B选项，根据《商标法》第14条的规定，只有国家知识产权局和最高人民法院指定的人民法院可以进行认定，因此B选项错误。C、D选项，根据《商标法》第14条第2、3款规定，在商标注册审查、商标争议处理或者查处商标违法案件过程中，当事人主张驰名商标权利的，国务院知识产权行政部门根据审查、处理案件的需要，可以对商标驰名情况作出认定。因此C、D选项正确。（2011改编）", "type": "single", "topic": "专题六 商标法", "page": 180, "subject": "相关法", "id": "xg_592"},
  {"question": "26. 根据商标法及相关规定，下列说法哪些是正确的?(多选)", "options": ["A. 申请以地理标志作为集体商标注册的团体，应当由来自该地理标志标示的地区范围内的成员组成", "B. 以地理标志作为集体商标注册的，其商品符合使用该地理标志条件的自然人，可以要求参加以该地理标志作为集体商标注册的团体", "C. 申请以地理标志作为集体商标的，还应当附送管辖该地理标志所标示地区的人民政府或者行业主管部门的批准文件", "D. 作为集体商标申请注册的地理标志，可以是该地理标志标示地区的名称，也可以是能够标示某商品来源于该地区的其他可视性标志"], "answer": "ABCD", "explanation": "A选项，《集体商标、证明商标注册和管理规定》第3条第2款规定：“申请以地理标志作为集体商标注册的团体、协会或者其他组织，其成员应当来自该地理标志标示的地区范围内。”，因此A选项正确。B选项，根据《商标条例》第4条第2款规定：“……以地理标志作为集体商标注册的，其商品符合使用该地理标志条件的自然人、法人或者其他组织，可以要求参加以该地理标志作为集体商标注册的团体、协会或者其他组织……”，因此B选项正确。C选项，根据《集体商标、证明商标注册和管理规定》第5条规定：“申请以地理标志作为证明商标、集体商标注册的，应当附送管辖该地理标志所标示地区的县级以上人民政府或者主管部门的批准文件”，因此C选项正确。D选项，根据《集体商标、证明商标注册和管理办法》第7条规定：“以地理标志作为证明商标、集体商标注册的，可以是该地理标志标示地区的名称，也可以是能够标示某商品来源于该地区的其他标志”，因此D选项说法正确。\n（新编）", "type": "multiple", "topic": "专题六 商标法", "page": 180, "subject": "相关法", "id": "xg_593"},
  {"question": "2. 某食品厂于2011年6月5日在其生产的糕点上使用了X商标。2015年10月20日该厂正式申请注册该商标。2017年3月5日该商标经初步审定并予公告。2017年6月5日公告期满，该商标被核准注册。据此，该注册商标有效期自何时起计算？（单选）", "options": ["A. 2011年6月5日", "B. 2015年10月20日", "C. 2017年3月5日", "D. 2017年6月5日"], "answer": "D", "explanation": "根据《商标法》第39条的规定，注册商标的有效期为10年，自核准注册之日起计算。本题中，该商标于2017年6月5日公告期满，即该日被核准注册，因此自该日起有效，A、B、C选项错误，D选项正确。(2018)", "type": "single", "topic": "专题六 商标法", "page": 181, "subject": "相关法", "id": "xg_594"},
  {"question": "3. 某公司注册商标的有效期将于2025年6月1日届满，该公司需要继续使用该商标。对此，下列说法哪项是正确的？（单选）", "options": ["A. 某公司可以在2025年6月1日前的12个月内申请续展注册", "B. 对于某公司在2025年6月1日之后提出的续展注册申请，该申请不予受理，并注销其注册商标", "C. 续展注册申请送达后即予以公告", "D. 每次续展注册的有效期为10年，自核准续展注册之日起计算"], "answer": "A", "explanation": "A、B、D选项，《商标法》第40条规定：“注册商标有效期满，需要继续使用的，商标注册人应当在期满前12个月内按照规定办理续展手续；在此期间未能办理的，可以给予6个月的宽展期。每次续展注册的有效期为10年，自该商标上一届有效期满次日起计算。期满未办理续展手续的，注销其注册商标”。本题注册商标的届满日为2025年6月1日，某公司可以在该日前12个月期间提出续展注册申请，未办理的，还有6个月宽展期，商标权自该商标上一届有效期满次日起计算，不是从核准续展注册日起算，因此A选项正确，B、D选项错误。C选项，根据《商标条例》第33条规定，注册商标需要续展注册的，应当向国务院商标管理部门提交商标续展注册申请书。国务院商标管理部门核准商标注册续展申请的，发给相应证明并予以公告，因此需要经过国家知识产权局核准，不能收到续展注册申请后直接予以公告，C选项错误。(新编)", "type": "single", "topic": "专题六 商标法", "page": 181, "subject": "相关法", "id": "xg_595"},
  {"question": "8. 甲公司与乙公司签订许可合同,许可乙公司独占使用甲公司的“木禾”注册商标,但该合同未进行备案。后乙公司发现丙公司未经许可在相同商品上使用“禾木”商标。对此,下列哪些说法是正确的?(多选)", "options": ["A. 因未进行备案,该许可合同不发生效力", "B. 乙公司无权向人民法院起诉丙公司侵权", "C. 乙公司可以与甲公司作为共同原告向人民法院起诉丙公司侵权", "D. 乙公司可以单独向人民法院起诉丙公司侵权"], "answer": "CD", "explanation": "A选项,《最高人民法院关于审理商标民事纠纷案件适用法律若干问题的解释》第19条规定:“商标使用许可合同未经备案的,不影响该许可合同的效力……”,因此A选项错误。B、D选项,《最高人民法院关于审理商标民事纠纷案件适用法律若干问题的解释》第4条第2款规定:“在发生注册商标专用权被侵害时,独占使用许可合同的被许可人可以向人民法院提起诉讼……”,乙公司作为独占被许可人可以单独向人民法院起诉,因此B选项错误,D选项正确。C选项,如无特殊约定,甲公司作为商标注册人有权利向人民法院提起诉讼,乙公司作为独占被许可人可以与甲公司共同提起诉讼,因此C选项正确。(2008)", "type": "multiple", "topic": "专题六 商标法", "page": 183, "subject": "相关法", "id": "xg_596"},
  {"question": "9. 甲公司享有“友善熊”注册商标的专用权,核定在玩具上使用。甲公司许可乙公司在其生产玩具上使用该注册商标。对此,下列说法哪些是正确的?(多选)", "options": ["A. 甲公司对乙公司的商标使用许可备案后生效", "B. 乙公司应当保证使用该商标的玩具的质量", "C. 甲公司应当监督乙公司使用该商标的玩具的质量", "D. 乙公司应当在使用该商标的玩具上,标明乙公司的名称和玩具产地"], "answer": "BCD", "explanation": "A选项,《最高人民法院关于审理商标民事纠纷案件适用法律若干问题的解释》第19条规定:“商标使用许可合同未经备案的,不影响该许可合同的效力……”,因此A选项错误。B、C、D选项,《商标法》第43条规定:“……许可人应当监督被许可人使用其注册商标的商品质量。被许可人应当保证使用该注册商标的商品质量。经许可使用他人注册商标的,必须在使用该注册商标的商品上标明被许可人的名称和商品产地……”,因此B、C、D选项正确。(2018)", "type": "multiple", "topic": "专题六 商标法", "page": 183, "subject": "相关法", "id": "xg_597"},
  {"question": "10. 根据商标法及相关规定,商标注册人可以通过签订商标使用许可合同,许可他人使用其注册商标。这里规定的商标使用许可包括哪些类型?(多选)", "options": ["A. 分割使用许可", "B. 独占使用许可", "C. 排他使用许可", "D. 普通使用许可"], "answer": "BCD", "explanation": "《最高人民法院关于审理商标民事纠纷案件适用法律若干问题的解释》第3条第1款规定:“商标法第43条规定的商标使用许可包括以下三类:(一)独占使用许可……(二)排他使用许可……(三)普通使用许可”,因此A选项错误,B、C、D选项正确。(2019)", "type": "multiple", "topic": "专题六 商标法", "page": 183, "subject": "相关法", "id": "xg_598"},
  {"question": "1. 根据商标法及相关规定，对于已经注册的商标，下列哪些属于任何单位或个人可以请求宣告该注册商标无效的理由？(多选)", "options": ["A. 有害于社会主义道德风尚的", "B. 其标志与我国国旗相同的", "C. 以欺骗手段或者其他不正当手段取得注册的", "D. 申请商标注册损害他人现有的在先权利的"], "answer": "ABC", "explanation": "A、B、C选项，根据《商标法》第44条第1款规定，已经注册的商标，违反本法第10条规定的，或者以欺骗手段或者其他不正当手段取得注册的，由国务院商标管理部门宣告该注册商标无效；其他单位或者个人可以请求商标评审部门宣告该注册商标无效。A、B选项均属于违反商标法第10条规定的情形，因此A、B、C选项可以由其他单位或者个人请求宣告无效。D选项，根据《商标法》第45条第1款规定，已经注册的商标，违反本法第32条规定的，自商标注册之日起5年内，在先权利人或者利害关系人可以请求商标评审部门宣告该注册商标无效。D选项属于违反商标法第32条规定的情形，因此应由在先权利人或者利害关系人请求商标评审部门宣告无效。(2015)", "type": "multiple", "topic": "专题六 商标法", "page": 184, "subject": "相关法", "id": "xg_599"},
  {"question": "3. 某商标代理机构未经授权，以自己的名义将被代理人甲公司的商标进行注册，在获得核准注册后，甲公司可以自该商标注册之日起五年内采取下列哪种措施维护自身合法权益？(单选)", "options": ["A. 请求撤销该注册商标", "B. 请求注销该注册商标", "C. 请求宣告该注册商标无效", "D. 对该注册商标提出异议申请"], "answer": "C", "explanation": "《商标法》第45条中规定，已经注册的商标，违反本法第13条第2款和第3款、第15条、第16条第1款、第30条、第31条、第32条规定的，自商标注册之日起5年内，在先权利人或者利害关系人可以请求商标评审部门宣告该注册商标无效，商标代理机构未经授权，以自己的名义将被代理人甲公司的商标进行注册，属于违反商标法第15条规定的情形，因此在先权利人或者利害关系人可以请求商标评审部门宣告该注册商标无效。因此C选项正确。", "type": "single", "topic": "专题六 商标法", "page": 184, "subject": "相关法", "id": "xg_600"},
  {"question": "9. 根据商标法相关规定，商标注册人可以在其商品上标明以下哪些内容表示其已经注册?(多选)", "options": ["A. “注册商标”", "B. “国家知识产权局商标局”", "C. ®", "D. ©"], "answer": "AC", "explanation": "A、C选项，《商标条例》第63条规定：“使用注册商标，可以在商品、商品包装、说明书或者其他附着物上标明‘注册商标’或者注册标记。注册标记包括㊟和®。使用注册标记，应当标注在商标的右上角或者右下角”，因此A、C选项正确。B选项无标注含义，D选项为享有著作权的标记，因此B、D选项错误。(2019)", "type": "multiple", "topic": "专题六 商标法", "page": 186, "subject": "相关法", "id": "xg_601"},
  {"question": "10. 根据商标法及相关规定，商标注册人在使用注册商标的过程中，具有下列哪些情形的，由负责商标执法的部门责令限期改正，期满不改正的，可撤销其注册商标?（多选）", "options": ["A. 自行改变注册商标", "B. 自行改变注册人名义", "C. 注册商标成为其核定使用的商品的通用名称", "D. 没有正当理由连续三年不使用"], "answer": "AB", "explanation": "根据《商标法》第49条规定，商标注册人在使用注册商标的过程中，自行改变注册商标、注册人名义、地址或者其他注册事项的，由地方负责商标执法的部门责令限期改正；期满不改正的，由国务院商标管理部门撤销其注册商标。注册商标成为其核定使用的商品的通用名称或者没有正当理由连续3年不使用的，任何单位或者个人可以向国务院商标管理部门申请撤销该注册商标，因此A、B选项正确。C、D选项的情形可直接向国家知识产权局申请撤销注册商标，无需经负责商标执法的部门责令限期改正，因此，C、D选项错误。(2018改编)", "type": "multiple", "topic": "专题六 商标法", "page": 186, "subject": "相关法", "id": "xg_602"},
  {"question": "11. 根据商标法及相关规定，对于下列哪些裁定或者决定不服的，当事人可以直接向人民法院起诉?(多选)", "options": ["A. 国家知识产权局针对商标异议作出的决定", "B. 国家知识产权局作出的撤销注册商标的决定", "C. 商标评审部门作出的撤销注册商标的复审决定", "D. 商标评审部门宣告注册商标无效的裁定"], "answer": "CD", "explanation": "A选项，根据《商标法》第35条的规定，国务院商标管理部门做出准予注册决定，异议人不服的，可以向商标评审部门请求宣告该注册商标无效；国务院商标管理部门做出不予注册决定，被异议人不服的，可以自收到通知之日起15日内向商标评审部门申请复审，就商标异议的决定不能直接向人民法院起诉，因此A选项错误。B选项，《商标法》第54条中规定，对国务院商标管理部门撤销或者不予撤销注册商标的决定，当事人不服的，可以自收到通知之日起15日内向商标评审部门申请复审。当事人对商标评审部门的决定不服的，可以自收到通知之日起30日内向人民法院起诉。因此B选项错误，C选项正确。D选项，根据", "type": "multiple", "topic": "专题六 商标法", "page": 186, "subject": "相关法", "id": "xg_603"},
  {"question": "12. 根据商标法及相关规定，当事人对下列哪些决定不服可在收到通知之日起十五日内申请复审?(多选)", "options": ["A. 对驳回申请、不予公告不服的", "B. 对不予撤销注册商标的决定不服的", "C. 对经过异议程序中异议不成立，决定被异议商标准予注册不服的", "D. 被异议人对商标不予注册决定不服的"], "answer": "ABD", "explanation": "A选项，根据《商标法》第34条的规定，对驳回申请、不予公告的商标，商标注册申请人不服的，可以自收到通知之日起15日内向商标评审部门申请复审，因此A选项正确。B选项，根据《商标法》第54条的规定，对国家知识产权局撤销或者不予撤销注册商标的决定，当事人不服的，可以自收到通知之日起15日内向商标评审部门申请复审，因此B选项正确。C选项，根据《商标法》第35条第2款规定，国家知识产权局做出准予注册决定的，发给商标注册证，并予公告。异议人不服的，可以依照商标法第44条、第45条的规定向商标评审部门请求宣告该注册商标无效。对于不予注册决定，被异议人不服的，可以自收到通知之日起15日内向商标评审部门申请复审。因此C选项错误，D选项正确。（新编）", "type": "multiple", "topic": "专题六 商标法", "page": 186, "subject": "相关法", "id": "xg_604"},
  {"question": "13. 根据商标法及相关规定，下列有关注册商标撤销和无效的哪些说法是正确的？(多选)", "options": ["A. 被撤销的注册商标，应予以公告，该注册商标专用权自公告之日起终止", "B. 被撤销的注册商标，应予以公告，该注册商标专用权视为自始即不存在", "C. 被宣告无效的注册商标，应予以公告，该注册商标专用权自公告之日起终止", "D. 被宣告无效的注册商标，应予以公告，该注册商标专用权视为自始即不存在"], "answer": "AD", "explanation": "A、B选项，根据《商标法》第55条第2款规定，被撤销的注册商标，由国务院商标管理部门予以公告，该注册商标专用权自公告之日起终止，因此A选项正确，B选项错误。C、D选项，根据《商标法》第47条第1款规定，依照商标法第44条、第45条的规定宣告无效的注册商标，由国务院商标管理部门予以公告，该注册商标专用权视为自始即不存在，因此C选项错误，D选项正确。(2014)", "type": "multiple", "topic": "专题六 商标法", "page": 187, "subject": "相关法", "id": "xg_605"},
  {"question": "14. 根据商标法及相关规定，下列哪些说法是正确的？(多选)", "options": ["A. 注册商标被撤销的，自撤销之日起一年内，与该商标相同的商标注册申请，不予核准", "B. 被撤销的注册商标，撤销理由仅及于部分指定商品的，在其他部分指定商品上使用的商标注册视为一并撤销", "C. 注册商标期满不再续展的，自注销之日起一年内，与该商标相同的商标注册申请，不予核准", "D. 当事人对撤销注册商标的决定不服的，可以自收到通知之日起30日内向人民法院起诉"], "answer": "AC", "explanation": "A、C选项，《商标法》第50条中规定，注册商标被撤销、被宣告无效或者期满不再续展的，自撤销、宣告无效或者注销之日起1年内，国务院商标管理部门对与该商标相同或者近似的商标注册申请，不予核准，因此A、C选项正确。B选项，《商标条例》第68条规定，国务院商标管理部门撤销注册商标或者宣告注册商标无效、撤销或者宣告无效的理由仅及于部分指定商品的，对该部分指定商品上使用的商标注册予以撤销或者宣告无效，因此B选项错误。D选项，根据《商标法》第54条的规定，对国务院商标管理部门撤销或者不予撤销注册商标的决定，当事人不服的，可以自收到通知之日起15日内向商标评审部门申请复审；", "type": "multiple", "topic": "专题六 商标法", "page": 187, "subject": "相关法", "id": "xg_606"},
  {"question": "15. 某县甲公司未经漫画家乙许可，将其创作的一幅漫画作品作为商标申请，并于2020年3月3日被核准注册。乙认为其著作权受到侵害，与甲发生纠纷。乙应当采取下列哪种方式保护自己的合法权益？(单选)", "options": ["A. 向甲公司所在地基层法院提起侵犯著作权之诉", "B. 向有管辖权的法院提起撤销甲公司的注册商标之诉", "C. 请求宣告该注册商标无效", "D. 请求撤销该注册商标 - 186 -"], "answer": "B", "explanation": "乙可以向有管辖权的法院提起撤销甲公司的注册商标之诉，因为甲公司未经许可使用了乙的创作作品作为商标。", "type": "single", "topic": "专题六 商标法", "page": 187, "subject": "相关法", "id": "xg_607"},
  {"question": "16. 个体经营户王小小从事理发服务业，使用“一剪没”作为未注册商标长期使用，享有较高声誉。王小小通过签订书面合同许可其同一城区的表妹张薇薇使用“一剪没”商标从事理发业务。后张薇薇以自己的名义申请“一剪没”商标使用于理发业务并获得注册。下列说法正确的是？（单选）", "options": ["A. 该商标使用许可合同自双方签字之日起生效", "B. 该商标使用许可合同备案后生效", "C. 王小小有权自“一剪没”注册之日起5年内请求宣告该注册商标无效", "D. 王小小无权请求宣告该注册商标无效"], "answer": "C", "explanation": "A、B选项，“一剪没”并非注册商标，王小小与张薇薇签订的合同并不是商标使用许可合同，因此A、B选项错误。C、D选项，“一剪没”被王小小长期使用，享有较高声誉，已具有一定影响，张薇薇属于抢注已经使用并有一定影响的商标的行为，王小小作为利害关系人，可以自商标注册之日起5年内请求宣告该注册商标无效，因此C选项正确，D选项错误。（法考2011改编）", "type": "single", "topic": "专题六 商标法", "page": 188, "subject": "相关法", "id": "xg_608"},
  {"question": "17. 下列哪些商标在申请注册时，有可能会被商标注册部门认定为不以使用为目的恶意注册申请？（多选）", "options": ["A. 某旅游公司在多个类别商品上申请百余件商标注册申请，其中大量为“终南山”、“安地斯”、“棕榈岛”、“铜锣湾”字样的注册商标申请", "B. 某贸易公司在多个类别商品上申请多件商标注册申请，其中一半以上为“十七街”、“宸光文具”、“威斯汀”字样的注册商标申请", "C. 某地产公司为其开发的楼盘申请“桂语听澜”、“意境渊庭”、“清溪”、“云舒”等注册商标", "D. 某餐饮公司已经注册“李小老”作为其商标，后在相同的类别上又大量申请“张小老”、“王小老”、“刘小老”等不同姓氏百余件商标申请 第五章 注册商标专用权的保护"], "answer": "AB", "explanation": "A选项，旅游公司大量注册著名风景区，属于不以使用为目的恶意注册申请。B选项，“十七街”与天津老字号“十八街”近似，“宸光文具”与知名企业“晨光文具”近似，“威斯汀”是美国知名国际性连锁酒店品牌，属于不以使用为目的恶意注册申请。C选项，地产公司为其开发楼盘申请的注册商标不属于不以使用为目的恶意注册申请。D选项，餐饮公司是基于防御目的申请与其注册商标标识相同或者近似的商标，不属于不以使用为目的恶意注册申请。（新编，思维扩展）", "type": "multiple", "topic": "专题六 商标法", "page": 188, "subject": "相关法", "id": "xg_609"},
  {"question": "2. 甲公司在衬衫商品上注册了“百合”文字商标。根据商标法及相关规定，下列哪些行为侵犯其注册商标专用权？(多选)", "options": ["A. 乙公司未经甲公司许可，在衬衫商品上使用与甲公司“百合”注册商标相近似的文字作为商标", "B. 丙公司将“百合”注册为域名，并通过该域名进行衬衫商品交易的电子商务，使相关公众产生误认", "C. 丁公司购入甲公司生产的“百合”牌衬衫后，未经甲公司同意将商标更换为“茉莉”并将该更换商标的衬衫商品又投入市场销售", "D. 戊公司伪造甲公司的“百合”注册商标标识，但并未将该伪造标识与衬衫商品结合投入市场销售"], "answer": "ABCD", "explanation": "A、C、D 选项属于《商标法》第 57 条规定的侵犯注册商标专用权的情形。B 选项，《最高人民法院关于审理商标民事纠纷案件适用法律若干问题的解释》第 1 条规定：“下列行为属于商标法第 57 条第（七）项规定的给他人注册商标专用权造成其他损害的行为：……（三）将与他人注册商标相同或者相近似的文字注册为域名，并且通过该域名进行相关商品交易的电子商务，容易使相关公众产生误认的”，因此 B 选项属于侵犯注册商标专用权的情形。（2011）", "type": "multiple", "topic": "专题六 商标法", "page": 189, "subject": "相关法", "id": "xg_610"},
  {"question": "3. 甲公司为其生产的啤酒申请注册了“冬雨之恋”商标，但在使用商标时没有在商标标识上加注“注册商标”字样或注册标记。下列哪些行为侵犯甲公司的商标权？(多选)", "options": ["A. 乙公司误认为该商标属于未注册商标，故在自己生产的啤酒产品上也使用“冬雨之恋”商标", "B. 丙公司不知某公司假冒“冬雨之恋”啤酒而予以运输", "C. 丁饭店将购买的甲公司“冬雨之恋”啤酒倒入自制啤酒桶，自制“侠客”牌散装啤酒出售", "D. 戊公司明知某企业生产假冒“冬雨之恋”啤酒而向其出租仓库"], "answer": "ACD", "explanation": "A 选项，乙公司主观上虽无恶意，但仍然构成了《商标法》第 57 条第（一）、（三）项规定的侵权情形。C 选项，丁饭店的行为属于《商标法》第 57 条第（五）项规定的侵权情形。B 选项，丙为运输者，主观上无故意，不属于《商标法》第 57 条中规定的侵权情形。D 选项，戊公司主观有故意，其仓储行为属于《商标法》第 57 条第（六）项规定的侵权情形。（法考 2013 改编）", "type": "multiple", "topic": "专题六 商标法", "page": 189, "subject": "相关法", "id": "xg_611"},
  {"question": "5. 根据商标法及相关规定，下列哪些情形属于国家知识产权局商标局主动撤销其注册商标的理由？（多选）", "options": ["A. 商标注册人在使用注册商标的过程中，自行改变注册商标", "B. 注册商标成为其核定使用的商品的通用名称", "C. 注册商标没有正当理由连续三年不使用", "D. 商标注册人在使用注册商标的过程中，自行改变注册人名义"], "answer": "AD", "explanation": "A、D选项，根据《商标法》第49条的规定，商标注册人在使用注册商标的过程中，自行改变注册商标、注册人名义、地址或者其他注册事项的，由负责商标执法的部门责令限期改正；期满不改正的，由国务院商标管理部门撤销其注册商标。因此A、D选项正确。B、C选项，根据《商标法》第49条的规定，注册商标成为其核定使用的商品的通用名称或者没有正当理由连续3年不使用的，任何单位或者个人可以向国务院商标管理部门申请撤销该注册商标。B、C选项须经申请才可撤销，不属于商标局主动撤销的情形，因此B、C选项错误。（新编）", "type": "multiple", "topic": "专题六 商标法", "page": 190, "subject": "相关法", "id": "xg_612"},
  {"question": "7. 根据商标法及相关规定，下列哪些情形属于商标的正当使用，不构成商标侵权：（多选）", "options": ["A. 使用注册商标中含有的“有机”文字，但书写方式和注册商标中不同", "B. 使用注册商标中含有的菱形图形", "C. 使用注册商标中含有的“100%”，但表现形式不同于注"], "answer": "ABC", "explanation": "《商标法》第59条第1款规定：“注册商标中含有的本商品的通用名称、图", "type": "multiple", "topic": "专题六 商标法", "page": 190, "subject": "相关法", "id": "xg_613"},
  {"question": "8. 甲公司是某注册商标的专用权人。在甲公司申请该商标注册前，乙公司已经在同一种商品上先于甲公司使用与该注册商标相同并有一定影响的商标。根据商标法及相关规定，下列哪种说法是正确的?(单选)", "options": ["A. 甲公司有权禁止乙公司继续使用该商标并要求其赔偿损失", "B. 甲公司有权禁止乙公司继续使用该商标，但无权要求其赔偿损失", "C. 甲公司无权禁止乙公司在原使用范围内继续使用该商标，但可以要求其支付一定的使用费", "D. 甲公司无权禁止乙公司在原使用范围内继续使用该商标，但可以要求其附加适当区别标识"], "answer": "D", "explanation": "《商标法》第59条第3款规定：“商标注册人申请商标注册前，他人已经在同一种商品或者类似商品上先于商标注册人使用与注册商标相同或者近似并有一定影响的商标的，注册商标专用权人无权禁止该使用人在原使用范围内继续使用该商标，但可以要求其附加适当区别标识”，因此A、B、C选项错误，D选项正确。(2014)", "type": "single", "topic": "专题六 商标法", "page": 191, "subject": "相关法", "id": "xg_614"},
  {"question": "9. 甲公司将其生产的白酒独创性地取名为“逍遥乐”，并在该酒的包装、装潢和广告中突出宣传酒名，致“逍遥乐”被消费者熟知，声誉良好。乙公司知道甲公司没有注册“逍遥乐”后，将其作为自己所产白酒的商标使用并抢先注册。该商标注册申请经初步审定后公告。下列哪些说法是正确的?(多选)", "options": ["A. 甲公司有权在异议期内提出异议，反对核准乙公司的注册申请", "B. 如“逍遥乐”被核准注册，甲公司有权主张先用权", "C. 如“逍遥乐”被核准注册，甲公司有权请求撤销该商标", "D. 甲公司有权向法院起诉请求乙公司停止使用并赔偿损失"], "answer": "AB", "explanation": "A选项，“逍遥乐”被消费者熟知，声誉良好，具有一定影响，乙公司的行为属于恶意注册，甲公司可以在异议期内向国家知识产权局提出异议，A选项正确。B选项，《商标法》第59条第3款规定：“商标注册人申请商标注册前，他人已经在同一种商品或者类似商品上先于商标注册人使用与注册商标相同或者近似并有一定影响的商标的，注册商标专用权人无权禁止该使用人在原使用范围内继续使用该商标，但可以要求其附加适当区别标识”，因此甲公司享有先用权，可以在原有范围内继续使用该商标，B选项正确。C选项，甲公司有权申请宣告该注册商标无效，而不是向国家知识产权局请求撤销该商标，C选项错误。D选项，甲公司的“逍遥乐”属于未注册商标，甲公司没有商标的专用权，对于未注册的商标是不予赔偿的，因此D选项错误。(法考2012)", "type": "multiple", "topic": "专题六 商标法", "page": 191, "subject": "相关法", "id": "xg_615"},
  {"question": "10. 甲公司在纸手帕等纸制产品上注册了“茉莉花”文字商标。下列哪项未经许可的行为构成侵权?(单选)", "options": ["A. 乙公司在其制造的纸手帕包装上突出使用“茉莉花”图形", "B. 丙商场将假冒“茉莉花”牌纸手帕作为赠品进行促销"], "answer": "B", "explanation": "A选项使用茉莉花图形不会对文字商标构成侵权。B选项作为赠品进行促销活动仍属于销售行为，构成商标侵权。C选项，《商标法》第59条第1款规定：“注册商标中含有的本商品的通用名称、图形、型", "type": "single", "topic": "专题六 商标法", "page": 191, "subject": "相关法", "id": "xg_616"},
  {"question": "11. 甲公司许可乙公司独占使用其注册商标,在合同履行期间,市场上出现大量侵犯该注册商标专用权的商品。对此,下列关于侵权诉讼的说法哪些是正确的?(多选)", "options": ["A. 甲公司可以自行提起诉讼", "B. 乙公司可以自行提起诉讼", "C. 甲和乙应当共同起诉", "D. 在甲不起诉的情况下,乙才可以自行提起诉讼"], "answer": "AB", "explanation": "《最高人民法院关于审理商标民事纠纷案件适用法律若干问题的解释》第4条第2款规定:“在发生注册商标专用权被侵害时,独占使用许可合同的被许可人可以向人民法院提起诉讼……”,因此A、B选项正确,C、D选项错误。(2018)", "type": "multiple", "topic": "专题六 商标法", "page": 192, "subject": "相关法", "id": "xg_617"},
  {"question": "12. 甲公司为其牛奶产品注册了“润语”商标后,通过签订排他许可合同许可乙公司使用。丙公司在其酸奶产品上使用“润雨”商标,甲公司遂起诉丙公司停止侵害并赔偿损失,法院判决支持了甲公司的请求。在该判决执行完毕后,“润语”注册商标因侵犯丁公司的著作权被依法宣告无效。下列哪些选项是错误的?(多选)", "options": ["A. 甲公司和乙公司可以作为共同原告起诉丙公司", "B. 甲公司与乙公司的许可合同应当认定为无效合同,乙公司应当申请返还许可费", "C. 甲公司获得的侵权赔偿费构成不当得利,应当返还给丙公司", "D. 甲公司获得的侵权赔偿费应当转付给丁公司"], "answer": "BCD", "explanation": "A选项,根据《最高人民法院关于审理商标民事纠纷案件适用法律若干问题的解释》第4条第2款的规定,在发生注册商标专用权被侵害时,排他使用许可合同的被许可人可以和商标注册人共同起诉,也可以在商标注册人不起诉的情况下,自行提起诉讼,因此A选项正确。B、C选项,《商标法》第47条第2款规定:“宣告注册商标无效的决定或者裁定,对宣告无效前人民法院做出并已执行的商标侵权案件的判决、裁定、调解书和工商行政管理部门做出并已执行的商标侵权案件的处理决定以及已经履行的商标转让或者使用许可合同不具有追溯力。但是,因商标注册人的恶意给他人造成的损失,应当给予赔偿”,注册商标被宣告无效所产生的效力对于此前已经完结的商标侵权赔偿、商标许可使用费原则上不具有追溯力,乙公司无权请求返还许可费,丙公司也无权请求返还侵权赔偿费,因此B、C选项错误。D选项,甲公司的注册商标侵犯了丁公司的著作权,应当承担相应的侵权责任,但甲公司获得的侵权赔偿费与侵犯丁公司的著作权之间并不具有因果关系,也没有直接的联系,因此甲公司获得的侵权赔偿费不应转付给丁公司,D选项错误。(法考2008)", "type": "multiple", "topic": "专题六 商标法", "page": 192, "subject": "相关法", "id": "xg_618"},
  {"question": "13. 根据商标法及相关规定,对于保全的哪些说法是正确的:(多选)", "options": ["A. 为制止侵权行为,在证据可能灭失的情况下,商标注册人可以依法在起诉前向法院申请证据保全", "B. 为制止侵权行为,在证据以后难以取得的情况下,注册"], "answer": "ABCD", "explanation": "A、B选项,《商标法》第66", "type": "multiple", "topic": "专题六 商标法", "page": 192, "subject": "相关法", "id": "xg_619"},
  {"question": "1. 根据商标法及相关规定，关于驰名商标的认定，下列说法哪些是正确的？(多选)", "options": ["A. 人民法院在审理商标纠纷案件中，根据当事人的请求和案件的具体情况，可以对涉及的注册商标是否驰名依法作出认定", "B. 在名牌推进战略实施过程中，可由相关行业协会进行认定", "C. 在商标注册过程中产生争议时，有关当事人认为其商标构成驰名商标的，国务院商标管理部门可以对商标驰名情况作出认定", "D. 在商标评审过程中产生争议时，有关当事人认为其商标构成驰名商标的，国务院商标管理部门可以对商标驰名情况作出认定"], "answer": "ACD", "explanation": "A选项，《最高人民法院关于审理商标民事纠纷案件适用法律若干问题的解释》第22条第1款规定：“人民法院在审理商标纠纷案件中，根据当事人的请求和案件的具体情况，可以对涉及的注册商标是否驰名依法作出认定”，因此A选项正确。B选项，根据《商标法》第14条的规定，只有国务院商标管理部门和最高人民法院指定的人民法院可以进行认定，因此B选项错误。C、D选项，根据《商标法》第14条第2、3款规定，在商标注册审查、商标争议处理或者查处商标违法案件过程中，当事人主张驰名商标权利的，国务院商标管理部门根据审查、处理案件的需要，可以对商标驰名情况作出认定。因此C、D选项正确。（2011改编）", "type": "multiple", "topic": "专题六 商标法", "page": 195, "subject": "相关法", "id": "xg_620"},
  {"question": "3. 下列哪些选项属于认定驰名商标应当考虑的因素?(多选)", "options": ["A. 该商标的持续使用时间", "B. 该商标投放广告的持续时间、程度和地理范围", "C. 该商标作为驰名商标受保护的记录", "D. 相关公众对该商标的知晓程度"], "answer": "ABCD", "explanation": "《商标法》第14条第1款规定：‘驰名商标应当根据当事人的请求，作为处理涉及商标案件需要认定的事实进行认定。认定驰名商标应当考虑下列因素：（一）相关公众对该商标的知晓程度；（二）该商标使用的持续时间；（三）该商标的任何宣传工作的持续时间、程度和地理范围；（四）该商标作为驰名商标受保护的记录……’，因此A、B、C、D选项均正确。（新编）", "type": "multiple", "topic": "专题六 商标法", "page": 196, "subject": "相关法", "id": "xg_621"},
  {"question": "4. 针对经初步审定公告的某商标,某公司认为该商标摹仿其已经在中国注册的驰名商标,误导公众并致使公司利益受到损害。根据商标法及相关规定,该公司可以如何处理?(单选)", "options": ["A. 自公告之日起三个月内提出异议", "B. 自公告之日起三个月内申请复审", "C. 自公告之日起三个月内申请行政复议", "D. 自公告之日起三个月内向法院起诉"], "answer": "A", "explanation": "根据《商标法》第33条的规定,对初步审定公告的商标,自公告之日起3个月内,在先权利人、利害关系人认为违反本法第13条第3款(就不相同或者不相类似商品申请注册的商标是复制、摹仿或者翻译他人已经在中国注册的驰名商标)规定的,可以向国务院商标管理部门提出异议,因此A选项正确,B、C、D选项错误。(2014改编)", "type": "single", "topic": "专题六 商标法", "page": 196, "subject": "相关法", "id": "xg_622"},
  {"question": "2. 关于马德里国际商标注册下列哪些说法是正确的？(多选)", "options": ["A. 以中国为原属国申请商标国际注册的可以直接向世界知识产权组织国际局申请办理", "B. 以中国为原属国，与马德里协定有关的商标国际注册的后期指定可以直接向世界知识产权组织国际局申请办理", "C. 商标国际注册申请指定的商品或服务不得超过国内基础申请或基础注册商品或服务范围", "D. 未按照规定填写的商标国际注册申请书的商标申请不予受理"], "answer": "CD", "explanation": "A选项，根据《商标条例》第37条的规定，以中国为原属国申请商标国际注册的，应当通过国家知识产权局向世界知识产权组织国际局申请办理，因此A选项错误。B选项，根据《商标条例》第37条的规定，以中国为原属国的，与马德里协定有关的商标国际注册的后期指定、放弃、注销，应当通过国家知识产权局向国际局申请办理，因此B选项错误。C选项，根据《商标条例》第39条的规定，商标国际注册申请指定的商品或者服务不得超出国内基础申请或者基础注册的商品或者服务的范围，因此C选项正确。D选项，根据《商标条例》第40条的规定，商标国际注册申请手续不齐备或者未按照规定填写申请书的，国家知识产权局不予受理，申请日不予保留，因此D选项正确。\n(新编)", "type": "multiple", "topic": "专题六 商标法", "page": 197, "subject": "相关法", "id": "xg_623"},
  {"question": "3. 根据商标法及相关规定，下列哪个事务可以直接向世界知识产权组织国际局申请办理？(单选)", "options": ["A. 以中国为原属国的，与马德里协定有关的商标国际注册的后期指定", "B. 以中国为原属国的，与马德里协定有关的商标国际注册的转让", "C. 以中国为原属国申请商标国际注册的", "D. 以中国为原属国的，与马德里协定有关的商标国际注册的放弃 第八章 地理标志产品"], "answer": "B", "explanation": "A、B、D选项，《商标条例》第37条第2款中规定以中国为原属国的，与马德里协定有关的商标国际注册的后期指定、放弃、注销，应当通过国家知识产权局向国际局申请办理；与马德里协定有关的商标国际注册的转让、删减、变更、续展，可以通过国家知识产权局向国际局申请办理，也可以直接向国际局申请办理”，因此A、D选项错误，B选项正确。C选项，《商标条例》第37条第1款规定，以中国为原属国申请商标国际注册的，应当通过国家知识产权局向世界知识产权组织国际局申请办理”，因此C选项错误。(新编)", "type": "single", "topic": "专题六 商标法", "page": 197, "subject": "相关法", "id": "xg_624"},
  {"question": "2. 下列关于地理标志产品申请的规定，哪些说法是正确的（多选）", "options": ["A. 地理标志产品保护申请可以由县级以上政府提出", "B. 地理标志产品保护申请材料应向省级知识产权管理部门提交", "C. 地理标志产品的保护申请材料包括有关地方人民政府关于划定地理标志产品产地范围的建议", "D. 地理标志产品的保护申请材料包括与产地的自然因素和人文因素之间关系的说明"], "answer": "ABCD", "explanation": "《地理标志产品保护办法》第9条规定：“地理标志产品保护申请，由提出产地范围的县级以上人民政府或者其指定的具有代表性的社会团体、保护申请机构（以下简称申请人）提出”，因此A选项正确。《地理标志产品保护办法》第11条规定：“地理标志产品的保护申请材料应当向省级知识产权管理部门提交。申请材料包括：（一）有关地方人民政府关于划定地理标志产品产地范围的建议……（三）地理标志产品的相关材料，包括：……与产地的自然因素和人文因素之间关系的说明……”，因此，因此B、C、D选项正确。（新编）", "type": "multiple", "topic": "专题六 商标法", "page": 198, "subject": "相关法", "id": "xg_625"},
  {"question": "3. 下列关于地理标志产品的规定，哪些说法是正确的（多选）", "options": ["A. 地理标志产品保护申请由国家知识产权局进行形式审查", "B. 地理标志产品保护申请由国家知识产权局组织开展技术审查", "C. 地方知识产权管理部门负责本行政区域内的地理标志产品以及专用标志的管理和保护工作", "D. 国家知识产权局负责全国地理标志产品以及专用标志的管理和保护工作"], "answer": "ABCD", "explanation": "《地理标志产品保护办法》第13条规定：“国家知识产权局对收到的申请进行形式审查……”，因此A选项正确。《地理标志产品保护办法》第14条规定：“对受理的地理标志产品保护申请，国家知识产权局组织开展技术审查……”，因此B选项正确。《地理标志产品保护办法》第5条规定：“国家知识产权局负责全国地理标志产品以及专用标志的管理和保护工作；统一受理和审查地理标志产品保护申请，依法认定地理标志产品。地方知识产权管理部门负责本行政区域内的地理标志产品以及专用标志的管理和保护工作”，因此C、D选项正确。（新编）", "type": "multiple", "topic": "专题六 商标法", "page": 198, "subject": "相关法", "id": "xg_626"},
  {"question": "下列哪组商标不构成近似商标？(单选)", "options": ["A. “精卫鸟”与“精卫”", "B. “花中王”与“花中玉”", "C. “酷儿”与“酷儿”"], "answer": "AB", "explanation": "", "type": "multiple", "topic": "专题六 商标法", "page": 199, "subject": "相关法", "id": "xg_627"},
  {"question": "根据商标法及相关规定，被异议人对不予注册的复审决定不服的，向人民法院起诉，下列哪种说法是正确的？（单选）", "options": ["A. 人民法院应当通知异议人作为原告参加诉讼", "B. 人民法院应当通知异议人作为被告参加诉讼", "C. 人民法院应当通知异议人作为第三人参加诉讼"], "answer": "C", "explanation": "根据《商标法》第35条第3款规定，国家知识产权局作出不予注册决定，被异议人不服的，可以自收到通知之日起15日内向商标评审部门申请复审，被异议人对商标评审部门的决定不服的，可以自收到通知之日起30日内向人民法院起诉。人民法院应当通知异议人作为第三人参加诉讼。因此，C选项正确。", "type": "single", "topic": "专题六 商标法", "page": 198, "subject": "相关法", "id": "xg_628"},
  {"question": "2018年3月23日，甲公司获得“明辉”商标的核准注册，核定使用在金属合页商品上。乙公司于2018年6月3日开始在金属合页商品上使用“明辉”商标。甲公司欲续展其“明辉”商标。根据商标法及相关规定，下列说法哪项是正确的？（单选）", "options": ["A. 甲公司应当在2027年9月23日至2028年3月23日期间内提出续展注册申请", "B. 若甲公司的续展申请获得核准，则该商标的有效期自2028年3月24日起计算", "C. 在甲公司提出续展申请后获得核准前，甲公司以乙公司侵犯其注册商标专用权提起诉讼的，人民法院可以不予受理", "D. 若甲公司在商标有效期满后未续展，则对于乙公司2028年10月对其金属合页商品提出“明辉”商标的注册申请，应不予核准注册"], "answer": "D", "explanation": "A选项错误。根据《商标法》相关规定，续展申请应在有效期届满前12个月内提出，逾期可在6个月内补办，因此甲公司应在2027年3月23日至2028年9月22日之间提出续展申请。B选项错误，续展后的有效期应自原有效期届满之日起计算，即从2028年3月23日起算。C选项错误，依据《最高人民法院关于审理商标民事纠纷案件适用法律若干问题的解释》第5条，即使尚未获准续展，只要在续展期内提出申请，法院仍应受理侵权诉讼。D选项正确，根据《商标法》第50条，注册商标被撤销、宣告无效或期满不再续展的，自撤销、宣告无效或注销之日起1年内，他人不得申请注册相同或近似商标。", "type": "single", "topic": "专题六 商标法", "page": 202, "subject": "相关法", "id": "xg_629"},
  {"question": "注册商标的有效期自申请之日起计算", "options": ["A. 注册商标的有效期自申请之日起计算", "B. 注册商标的有效期为20年", "C. 注册商标有效期满，未办理续展手续的，可以给予6个月的宽展期", "D. 注册商标续展注册最多不得超过5次"], "answer": "C", "explanation": "根据《商标法》规定，注册商标的有效期为10年，自核准注册之日起计算。有效期满需要继续使用的，应当在期满前12个月内申请续展；在此期间未能办理的，可以给予6个月的宽展期。每次续展注册的有效期为10年。因此，C选项正确。D选项错误，因为续展次数没有限制。", "type": "single", "topic": "专题六 商标法", "page": 201, "subject": "相关法", "id": "xg_630"},
  {"question": "甲公司于2009年5月8日提交了一份商标注册申请，该商标于2010年2月8日获准注册，目前该商标仍为有效商标。如果甲公司需要继续使用该商标，最迟应于哪天提交注册商标续展申请？", "options": ["A. 2030年2月7日", "B. 2030年2月8日"], "answer": "A", "explanation": "根据《商标法》规定，注册商标的有效期为10年，自核准注册之日起算。本题中，商标于2010年2月8日核准注册，有效期至2020年2月7日，加上6个月宽展期，办理续展手续截止于2030年2月7日。因此，A选项正确，B选项错误。", "type": "single", "topic": "专题六 商标法", "page": 201, "subject": "相关法", "id": "xg_631"},
  {"question": "第10项规定的不能作为商标使用的情形", "options": ["A. 以不正当手段抢先注册他人已经使用并有一定影响的商品标志", "B. 两个或者两个以上的申请人，在同一种商品或者类似商品上，分别以相同或者近似的商标在同一天申请注册，且均未使用", "C. 不以使用为目的的恶意商标注册申请", "D. 以不得作为商标使用的标志申请注册商标"], "answer": "A", "explanation": "商标法明确禁止以不正当手段抢先注册他人已经使用并有一定影响的商品标志。这种行为侵犯了他人的合法权益，损害了公平竞争的市场秩序。", "type": "single", "topic": "专题六 商标法", "page": 196, "subject": "相关法", "id": "xg_632"},
  {"question": "根据商标法及相关规定，宣告注册商标无效的判决或者裁定，对哪些法律文书不具有追溯力？（多选）", "options": ["A. 对宣告无效前人民法院做出并执行的商标侵权案件的判决不具有追溯力", "B. 对宣告无效前人民法院做出并执行的商标侵权案件的裁定不具有追溯力", "C. 对已经具备履行条件的使用许可合同不具有追溯力", "D. 对已经具备履行条件的使用许可合同具有追溯力"], "answer": "ABC", "explanation": "宣告注册商标无效的判决或裁定通常不具有追溯力，这意味着它不会影响在宣告无效之前已经发生并执行的法律文书，包括商标侵权案件的判决和裁定，以及已经具备履行条件的使用许可合同。", "type": "multiple", "topic": "专题六 商标法", "page": 204, "subject": "相关法", "id": "xg_633"},
  {"question": "下列哪组商标不构成近似商标?(多选)", "options": ["A. “珠穆朗玛”与“珠穆朗玛峰”", "B. “北美风情”与“北欧风情”", "C. “好哥”与“好歌”", "D. “球王”和“球”"], "answer": "BD", "explanation": "B选项中“北美风情”和“北欧风情”文字读音、字形明显不同，不属于近似商标。C选项虽然读音相同，但是含义区别较大，不属于近似商标。D选项“球王”和“球”含义区别明显，不属于近似商标。(新编)", "type": "multiple", "topic": "专题六 商标法", "page": 200, "subject": "相关法", "id": "xg_634"},
  {"question": "下列哪些属于相同或近似的商标?(多选)", "options": ["A. “凤凰”和“凤凰”", "B. “Susanna”和“SUSANNA”", "C. “亚美航空”和“美亚医疗”", "D. “新康得”和“新得康”"], "answer": "ABD", "explanation": "A选项，“凤凰”和“凤凰”仅为简体和繁体的区别，属于相同商标。B选项，“Susanna”和“SUSANNA”仅为大写和小写的区别，属于相同商标。C选项，“亚美航空”和“美亚医疗”的商标含义或呼叫区别明显，不易使相关公众对商品或者服务的来源产生混淆，既不是相同商标也不是近似商标。D选项，“新康得”和“新得康”的汉字构成相同，排列顺序不同，属于近似商标。(新编)", "type": "multiple", "topic": "专题六 商标法", "page": 200, "subject": "相关法", "id": "xg_635"},
  {"question": "下列哪项属于近似的商标?(多选)", "options": ["A. “CATANA”和“KATANA”", "B. “喜马辣鸭”和“喜马拉雅”", "C. “LOVE”和“EOVE”", "D. “蒙拉丽莎”和“梦拉丽莎”"], "answer": "AD", "explanation": "A选项，“CATANA”和“KATANA”虽然首字母不同，但读音及整体外观近似，属于近似商标。B选项，“喜马辣鸭”和“喜马拉雅”虽然读音近似，但“喜马拉雅”为公众所熟知，而“喜马辣鸭”包含特定设计寓意，二者整体外观区别明显，不属于近似商标。C选项，“LOVE”和“EOVE”首字母发音及字形明显不同，区别明显，不易使相关公众产生混淆，不属于近似商标。D选项，“蒙拉丽莎”和“梦拉丽莎”虽然首字不同，但读音相近且含义无明显差异，为近似商标。(新编)", "type": "multiple", "topic": "专题六 商标法", "page": 200, "subject": "相关法", "id": "xg_636"},
  {"question": "根据商标法及相关规定，使用未注册商标有下列哪些情形的，由负责商标执法的部门予以制止，限期改正？（多选）", "options": ["A. 冒充注册商标", "B. 商标标志缺乏显著特征", "C. 带有欺骗性容易使公众产生误认", "D. 同中央国家机关的名称相同"], "answer": "ABD", "explanation": "根据《商标法》第52条，将未注册商标冒充注册商标使用的，或者使用未注册商标违反本法第10条规定的，由负责商标执法的部门予以制止，限期改正。因此A选项正确，C、D选项均属于《商标法》第10条规定的不得作为商标使用的情形，因此C、D选项正确。B选项，缺乏显著特征属于《商标法》第11条规定的不得作为商标注册的情形，因此B选项错误。（2019）", "type": "multiple", "topic": "专题六 商标法", "page": 205, "subject": "相关法", "id": "xg_637"},
  {"question": "关于商标法所称的“商品商标的使用”，以下说法正确的是：（单选）", "options": ["A. 商标的使用必须将商标贴附在商品上", "B. 商标的使用不能脱离商品而使用", "C. 商标的使用可以在非商业活动中", "D. 商标的使用是指商标能够识别商品来源的行为"], "answer": "D", "explanation": "根据《商标法》第48条，‘商标法所称商标的使用，是指将商标用于商品、商品包装或者容器以及商品交易文书上，或者将商标用于广告宣传、展览以及其他商业活动中，用于识别商品来源的行为’，使用商标不一定要将商标贴附在商品上，广告宣传时，商标可以脱离商品而使用，商标使用仅限于商业活动，因此A、B、C选项错误，D选项正确。（2018）", "type": "single", "topic": "专题六 商标法", "page": 205, "subject": "相关法", "id": "xg_638"},
  {"question": "根据商标法及相关规定，下列哪项不属于负责商标执法的部门对涉嫌商标侵权行为进行查处时可以行使的职权？（单选）", "options": ["A. 询问有关当事人", "B. 对当事人涉嫌从事侵犯他人注册商标专用权活动的场所实施现场检查", "C. 检查与侵权活动有关的物品", "D. 对涉嫌侵权人予以拘留"], "answer": "D", "explanation": "《商标法》第62条第1款中规定，负责商标执法的部门根据已经取得的违法嫌疑证据或者举报，对涉嫌侵犯他人注册商标专用权的行为进行查处时，可以行使下列职权：（一）询问有关当事人，调查与侵犯他人注册商标专用权有关的情况……（三）对当事人涉嫌从事侵犯他人注册商标专用权活动的场所实施现场检查；（四）检查与侵权活动有关的物品；对有证据证明是侵犯他人注册商标专用权的物品，可以查封或者扣押。A、B、C选项属于负责商标执法的部门查处商标侵权可以行使的职权，D选项不属于负责商标执法的部门查处商标侵权可以行使的职权，因此D选项正确。（2016）", "type": "single", "topic": "专题六 商标法", "page": 212, "subject": "相关法", "id": "xg_639"},
  {"question": "根据商标法及相关规定，在侵犯商标专用权纠纷案件中，权利人因被侵权所受到的实际损失、侵权人因侵权所获得的利益、注册商标许可使用费难以确定的，赔偿数额应当如何确定？（单选）", "options": ["A. 由法院根据侵权行为的情节判决给予五十万元以下的赔偿", "B. 由法院根据侵权行为的情节判决给予一百万元以下的赔偿", "C. 由法院根据侵权行为的情节判决给予三百万元以下的赔偿", "D. 由法院根据侵权行为的情节判决给予五百万元以下的赔偿"], "answer": "C", "explanation": "《商标法》第63条第3款规定：‘权利人因被侵权所受到的实际损失、侵权人因侵权所获得的利益、注册商标许可使用费难以确定的，由人民法院根据侵权行为的情节判决给予三百万元以下的赔偿。’因此，正确答案是C。", "type": "single", "topic": "专题六 商标法", "page": 212, "subject": "相关法", "id": "xg_640"},
  {"question": "规定：“国家知识产权局负责全国地理标志产品以及专用标志的管理和保护工作；统一受理和审查地理标志产品保护申请，依法认定地理标志产品。”", "options": ["B. 地理标志产品保护申请由国家知识产权局组织开展技术审查", "C. 地方知识产权管理部门负责本行政区域内的地理标志产品以及专用标志的管理和保护工作", "D. 国家知识产权局负责全国地理标志产品以及专用标志的管理和保护工作"], "answer": "D", "explanation": "根据规定，国家知识产权局负责全国地理标志产品以及专用标志的管理和保护工作，统一受理和审查地理标志产品保护申请，并依法认定地理标志产品。", "type": "single", "topic": "专题六 商标法", "page": 218, "subject": "相关法", "id": "xg_641"},
  {"question": "甲公司以乙公司侵犯其注册商标专用权为由请求负责商标执法的部门处理。对此，负责商标执法的部门的下列做法中哪些是合法的？（多选）", "options": ["A. 以商标侵权纠纷为民事纠纷、应当由人民法院处理为由拒绝受理甲公司的请求", "B. 认定侵权行为成立后，责令乙公司立即停止侵权，没收侵权商品以及主要用于制造侵权商品的工具，并处以罚款", "C. 认定侵权行为成立后，责令乙公司应向甲公司赔偿50万元人民币", "D. 认定侵权行为成立后，根据当事人的请求对赔偿数额进行调解"], "answer": "BD", "explanation": "A选项，负责商标执法的部门有权处理商标侵权纠纷，A选项错误。B选项，根据《商标法》第60条第2款规定，负责商标执法的部门处理时，认定侵权行为成立的，责令立即停止侵权行为，没收、销毁侵权商品和主要用于制造侵权商品、伪造注册商标标识的工具，并可以进行罚款，因此B选项符合规定。C、D选项，负责商标执法的部门可以对赔偿数额进行调解，但没有责令赔偿的职权，C选项不符合规定，D选项符合规定。（2018改编）", "type": "multiple", "topic": "专题六 商标法", "page": 213, "subject": "相关法", "id": "xg_642"},
  {"question": "在某商标侵权案件中，注册商标专用权人请求赔偿的，被控侵权人以什么理由提出抗辩可能会免于承担赔偿责任？（单选）", "options": ["A. 注册商标专用权人未使用注册商标", "B. 注册商标专用权人未合理使用注册商标", "C. 注册商标专用权人使用注册商标未满三年", "D. 使用该注册商标的产品质量不达标"], "answer": "A", "explanation": "注册商标专用权人不能证明此前三年内实际使用过该注册商标，也不能证明因侵权行为受到其他损失的，被控侵权人不承担赔偿责任。销售不知道是侵犯注册商标专用权的商品，能证明该商品是自己合法取得并说明提供者的，不承担赔偿责任”，因此A选项正确，B、C、D选项错误。（2019）", "type": "single", "topic": "专题六 商标法", "page": 214, "subject": "相关法", "id": "xg_643"},
  {"question": "根据商标法及相关规定，销售不知道是侵犯注册商标专用权的商品，能证明该商品是自己合法取得并说明提供者的，不承担赔偿责任。下列哪些情形属于能证明该商品是自己合法取得的情形？（多选）", "options": ["A. 有供货单位合法签章的供货清单和货款收据且经查证属实的", "B. 有供销双方签订的进货合同且经查证已真实履行的", "C. 有合法进货发票且发票记载事项与涉案商品对应的", "D. 以上都是"], "answer": "ABCD", "explanation": "《商标条例》第79条规定：\"下列情形属于商标法第64条规定的情形：（一）有供货单位合法签章的供货清单和货款收据且经查证属实或者供货单位认可的；（二）有供销双方签订的进货合同且经查证已真实履行的；（三）有合法进货发票且发票记载事项与涉案商品对应的；（四）其他能够证明合法取得涉案商品的情形\"。因此A、B、C、D选项均正确。（2019）", "type": "multiple", "topic": "专题六 商标法", "page": 214, "subject": "相关法", "id": "xg_644"},
  {"question": "1. 下列各项中，哪些属于我国著作权法规定的作品？（多选）", "options": ["A. 口述作品", "B. 摄影作品", "C. 曲艺作品", "D. 戏剧作品"], "answer": "ABCD", "explanation": "《著作权法》第3条规定：“本法所称的作品，是指文学、艺术和科学领域内具有独创性并能以一定形式表现的智力成果，包括：……；（二）口述作品；（三）音乐、戏剧、曲艺、舞蹈、杂技艺术作品……；（五）摄影作品……”，因此A、B、C、D选项均正确。（2012）", "type": "multiple", "topic": "专题七 著作权法", "page": 200, "subject": "相关法", "id": "xg_645"},
  {"question": "2. 根据著作权法及相关规定，下列有关作品的说法正确的是？（多选）", "options": ["A. 作品应当具有独创性并能以一定形式表现", "B. 文字作品，是指小说、诗词、散文、论文等以文字形式表现的作品", "C. 反映地理现象、说明事物原理或者结构的地图属于美术作品", "D. 为展示、试验或者观测等用途，根据物体的形状和结构按照一定比例制成的立体模型属于模型作品"], "answer": "ABD", "explanation": "A选项符合《著作权法》第3条的规定。B选项，《著作权条例》第4条第（一）项规定：“文字作品，是指小说、诗词、散文、论文等以文字形式表现的作品”，因此B选项正确。C选项，根据《著作权条例》第4条第（十二）项的规定，C选项描述的属于图形作品，因此C选项错误。D选项，根据《著作权条例》第4条第（十三）项的规定，为展示、试验或者观测等用途，根据物体的形状和结构按照一定比例制成的立体作品属于模型作品，因此D选项正确。（2019）", "type": "multiple", "topic": "专题七 著作权法", "page": 200, "subject": "相关法", "id": "xg_646"},
  {"question": "3. 下列哪些不适用我国著作权法的规定？（多选）", "options": ["A. 某9岁儿童创作的短篇小说", "B. 某电视台报道的单纯事实消息", "C. 某城市交通电子地图", "D. 某法律的官方英文译文"], "answer": "BD", "explanation": "A选项的小说属于文字作品，C选项的地图属于图形作品，均适用著作权法规定。B、D选项，《著作权法》第5条规定：“本法不适用于：（一）法律、法规，国家机关的决议、决定、命令和其他具有立法、行政、司法性质的文件，及其官方正式译文；（二）单纯事实消息；……”，因此B、D选项不适用著作权法规定。（2014）", "type": "multiple", "topic": "专题七 著作权法", "page": 200, "subject": "相关法", "id": "xg_647"},
  {"question": "2. 作家张某撰写一部短篇小说《专利代理师的幸福生活》，2016年8月9日开始创作,2016年9月9日创作完成,2016年10月9日办理了作品登记,2016年10月30日该作品在杂志上发表。根据著作权法及相关规定，该作品著作权从何时起产生?(单选)", "options": ["A. 2016年8月9日", "B. 2016年9月9日", "C. 2016年10月9日", "D. 2016年10月30日"], "answer": "B", "explanation": "《著作权条例》第6条规定：“著作权自作品创作完成之日起产生”。本题中，张某作品创作完成之日为2016年9月9日，因此A、C、D选项错误,B选项正确。(2016)", "type": "single", "topic": "专题七 著作权法", "page": 202, "subject": "相关法", "id": "xg_648"},
  {"question": "3. 甲小学主持起草2015年学校工作总结并上报区教育局。其间，校办公室主任张某接受该小学指派承担了具体撰写工作。根据著作权法及相关规定，下列哪种说法是正确的?(单选)", "options": ["A. 甲小学视为该工作总结的作者", "B. 该工作总结的作者是张某，该工作总结的著作权人是甲小学", "C. 该工作总结的署名权由张某享有，该工作总结的复制权由甲小学享有", "D. 该工作总结的著作权由张某享有"], "answer": "A", "explanation": "《著作权法》第11条第3款规定：“由法人或者非法人组织主持，代表法人或者非法人组织意志创作，并由法人或者非法人组织承担责任的作品，法人或者非法人组织视为作者”。本题中，工作总结由甲小学主持，代表甲小学的意志创作，并由甲小学承担责任，因此甲小学视为该工作总结的作者并且享有著作权，A选项正确，B、C、D选项错误。(2016)", "type": "single", "topic": "专题七 著作权法", "page": 202, "subject": "相关法", "id": "xg_649"},
  {"question": "4. 某公司主持起草新的绩效考核办法，该公司人力资源部王某接受公司指派承担了具体撰写工作，并上报该公司董事会审议通过。根据著作权法及相关规定，下列哪种说法是正确的?(单选)", "options": ["A. 该公司视为该绩效考核办法的作者", "B. 该绩效考核办法的作者是王某，该绩效考核办法的著作权人也是王某", "C. 该绩效考核办法的作者是王某，该绩效考核办法的著作权人是该公司", "D. 该绩效考核办法的署名权由王某享有，该绩效考核办法的复制权由该公司享有"], "answer": "A", "explanation": "本题中，绩效考核办法是由公司主持，代表公司意志创作，由公司承担责任的作品，因此该公司视为该绩效考核办法的作者并享有著作权，A选项正确,B、C、D选项错误。(2017)", "type": "single", "topic": "专题七 著作权法", "page": 202, "subject": "相关法", "id": "xg_650"},
  {"question": "7. 甲提供资金，乙组织丙和丁以乡村教师戊为原型创作小说《小河弯弯》。在创作中丙写提纲，丁写初稿，丙修改，戊提供了生活素材，乙提供了一些咨询意见。下列哪些选项是错误的？(多选)", "options": ["A. 甲提供资金是完成创作的保障，应为作者", "B. 乙作为组织者并提供咨询意见，应为作者", "C. 戊提供了生活素材，应为作者", "D. 丁有权不经甲、乙、丙的同意发表该小说"], "answer": "ABC", "explanation": "甲、乙、戊都不是作者，完成初稿的丁和修改的丙是作者，丁和丙享有著作权。《著作权法》第14条第2款规定：“合作作品的著作权由合作作者通过协商一致行使；不能协商一致，又无正当理由的，任何一方不得阻止他方行使除转让、许可他人专有使用、出质以外的其他权利，但是所得收益应当合理分配给所有合作作者”，因此丁有权不经甲、乙、丙的同意行使发表权，A、B、C选项错误，D选项正确。（法考2007）", "type": "multiple", "topic": "专题七 著作权法", "page": 203, "subject": "相关法", "id": "xg_651"},
  {"question": "8. 根据著作权法及相关规定，下列关于著作权集体管理组织的哪些说法是正确的？(多选)", "options": ["A. 著作权人可以授权著作权集体管理组织行使著作权", "B. 著作权集体管理组织被授权后，可以以自己的名义为与著作权有关的权利人主张权利", "C. 著作权集体管理组织可以作为当事人进行涉及著作权的诉讼活动", "D. 著作权集体管理组织只能作为诉讼代理人进行涉及与著作权有关的权利的诉讼活动"], "answer": "ABC", "explanation": "《著作权法》第8条第1款规定：“著作权人和与著作权有关的权利人可以授权著作权集体管理组织行使著作权或者与著作权有关的权利。依法设立的著作权集体管理组织是非营利法人，被授权后可以以自己的名义为著作权人和与著作权有关的权利人主张权利，并可以作为当事人进行涉及著作权或者与著作权有关的权利的诉讼、仲裁、调解活动”，因此A、B、C选项正确，D选项错误。（2017）", "type": "multiple", "topic": "专题七 著作权法", "page": 203, "subject": "相关法", "id": "xg_652"},
  {"question": "10. 甲、乙、丙、丁四人合作创作一部小说，甲欲将该小说许可给某电影制片厂改编后拍成电影，乙则想把它许可给某网站在网络上传播，丙对这两种做法均表示反对，丁则不置可否。对此，下列哪一选项是正确的？(单选)", "options": ["A. 如果丙坚持反对，甲、乙均不能将作品许可他人使用", "B. 甲、乙有权不顾丙的反对，将作品许可他人使用", "C. 如果丁同意，则甲、乙可以不顾丙的反对将作品许可他人使用", "D. 如果丁也表示反对，则甲、乙不能将作品许可他人使用"], "answer": "B", "explanation": "根据《著作权法》第13条规定：‘改编、翻译、注释、整理已有作品而产生的作品，其著作权由改编、翻译、注释、整理人享有，但行使著作权时不得侵犯原作品的著作权’。因此张某对其改编的电影剧本享有著作权，B选项正确。C、D选项，《著作权法》第17条第1款规定：‘视听作品中的电影作品、电视剧作品的著作权由制作者享有，但编剧、导演、摄影、作词、作曲等作者享有署名权，并有权按照与制作者签订的合同获得报酬’，因此该电影作品的著作权由制作者甲公司享有，C选项正确，D选项错误。（2014）", "type": "single", "topic": "专题七 著作权法", "page": 204, "subject": "相关法", "id": "xg_653"},
  {"question": "11. 金某于2012年12月24日创作完成了某小说，并于2013年2月14日发表于某网络文学网站。经金某许可，张某将该小说改编为电影剧本，甲公司作为电影制作者将该剧本拍摄成电影，导演为周某。根据著作权法及相关规定，下列哪些说法是正确的？(多选)", "options": ["A. 金某自2013年2月14日起对该小说享有著作权", "B. 该电影剧本的著作权由张某享有", "C. 该电影作品的著作权由甲公司享有", "D. 该电影作品的著作权由张某和周某共同享有"], "answer": "BC", "explanation": "A选项，《著作权条例》第6条规定：“著作权自作品创作完成之日起产生”，金某于2012年12月24日创作完成了该小说，因此A选项错误。B选项，《著作权法》第13条规定：“改编、翻译、注释、整理已有作品而产生的作品，其著作权由改编、翻译、注释、整理人享有，但行使著作权时不得侵犯原作品的著作权”，因此张某对其改编的电影剧本享有著作权，B选项正确。C、D选项，《著作权法》第17条第1款规定：“视听作品中的电影作品、电视剧作品的著作权由制作者享有，但编剧、导演、摄影、作词、作曲等作者享有署名权，并有权按照与制作者签订的合同获得报酬”，因此该电影作品的著作权由制作者甲公司享有，C选项正确，D选项错误。(2014)", "type": "multiple", "topic": "专题七 著作权法", "page": 204, "subject": "相关法", "id": "xg_654"},
  {"question": "13. 根据著作权法及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 汇编若干作品的片段，对其内容的选择或者编排体现独创性的作品，属于汇编作品", "B. 汇编作品不包括对不构成作品的数据或者其他材料进行的汇编", "C. 汇编作品的著作权由汇编人和原作品的著作权人共同享有", "D. 汇编作品的著作权由汇编人享有，但行使著作权时不得侵犯原作品的著作权 14.《专利代理师的成长历程》是由李某编剧、张某导演的一部电影，制作者为甲公司，音乐人周某创作了可以单独使用的电影音乐。根据著作权法及相关规定，下列哪些说法是正确的？（多选）", "A. 甲公司是该电影的著作权人", "B. 张某是该电影的著作权人", "C. 李某享有署名权，并有权按照与甲公司签订的合同获得报酬", "D. 周某有权单独行使电影音乐的著作权"], "answer": "AD", "explanation": "汇编作品是指汇编若干作品、作品的片段或者不构成作品的数据或者其他材料，对其内容的选择或者编排体现独创性的作品。汇编作品的著作权由汇编人享有，但行使著作权时不得侵犯原作品的著作权。", "type": "multiple", "topic": "专题七 著作权法", "page": 205, "subject": "相关法", "id": "xg_655"},
  {"question": "15. 黄某请李某执笔以黄某的人生经历为素材创作一本自传体小说。在小说写作过程中，黄某给李某提供了素材，在小说完成后，黄某向李某支付了5万元，但双方并未约定著作权的归属。根据著作权法及相关规定，下列说法哪些是正确的？（单选）", "options": ["A. 该小说的著作权应当由黄某享有", "B. 该小说的著作权应当由李某享有", "C. 该小说的著作权应当由黄某和李某共同享有", "D. 该小说的著作权应当由李某享有，黄某可以无偿使用"], "answer": "A", "explanation": "《著作权纠纷解释》第14条规定：“当事人合意以特定人物经历为题材完成的自传体作品，当事人对著作权权属有约定的，依其约定；没有约定的，著作权归该特定人物享有，执笔人或整理人对作品完成付出劳动的，著作权人可以向其支付适当的报酬”，因此A选项正确，B、C、D选项错误。(2011)", "type": "single", "topic": "专题七 著作权法", "page": 205, "subject": "相关法", "id": "xg_656"},
  {"question": "16. 美术学院教授王某受某公司委托，创作了一件象征该公司文化和精神的雕塑，并按照合同约定将该雕塑原件交付给该公司，但双方未约定该雕塑著作权的归属。根据著作权法及相关规定，下列哪些说法是正确的？(多选)", "options": ["A. 王某享有该雕塑的著作权", "B. 该公司享有该雕塑的著作权", "C. 王某享有该雕塑原件的展览权", "D. 该公司享有该雕塑原件的展览权"], "answer": "CD", "explanation": "《著作权法》第20条第1款规定：‘作品原件所有权的转移，不改变作品著作权的归属，但美术、摄影作品原件的展览权由原件所有人享有’，雕塑属于美术作品，原件所有人该公司享有雕塑原件的展览权，因此C选项错误，D选项正确。（2012）", "type": "multiple", "topic": "专题七 著作权法", "page": 206, "subject": "相关法", "id": "xg_657"},
  {"question": "17. 张某是一名优秀的传记作家，笔下传记人物深受读者喜爱。某出版社准备出版一本关于古代人物曾国藩的传记，自然人王某拟出版一本关于自己成长历程的传记，二者分别向张某约稿，但均未明确约定著作权归属。对此，下列说法正确的是：(多选)", "options": ["A. 曾国藩传记著作权归出版社所有", "B. 曾国藩传记著作权归张某所有", "C. 王某传记著作权归张某所有", "D. 王某传记著作权归王某所有"], "answer": "BD", "explanation": "A、B选项，根据《著作权法》第19条的规定，曾国藩传记属于委托作品，未约定权利归属的，完成人张某为著作权人，因此A选项错误，B选项正确。C、D选项，王某传记属于特定人物自传体作品，未约定权利归属的，特定人物王某为著作权人，因此C选项错误，D选项正确。(2018)", "type": "multiple", "topic": "专题七 著作权法", "page": 206, "subject": "相关法", "id": "xg_658"},
  {"question": "18. 唐某创作了一幅国画，交给某慈善机构拍卖，所得款项全部用于救助失学儿童。齐某在拍卖会上以80万元的价格购得该画。根据著作权法及相关规定，下列哪些说法是正确的？(多选)", "options": ["A. 齐某享有该画的复制权", "B. 齐某享有该画原件的所有权", "C. 齐某享有该画原件的展览权", "D. 齐某享有该画的发表权"], "answer": "BC", "explanation": "《著作权法》第20条第1款规定：“作品原件所有权的转移，不改变作品著作权的归属，但美术、摄影作品原件的展览权由原件所有人享有”。本题中，齐某享有该画原件的所有权和展览权，唐某享有除展览权之外著作权中的其他权利，因此A、D选项错误，B、C选项正确。(2016)", "type": "multiple", "topic": "专题七 著作权法", "page": 206, "subject": "相关法", "id": "xg_659"},
  {"question": "19. 甲公司设计师张某为完成该公司的工作任务，主要利用该公司的物质技术条件创作了产品设计图，并由该公司承担责任。根据著作权法及相关规定，下列哪些说法是正确的？(多选)", "options": ["A. 张某享有该产品设计图的复制权", "B. 甲公司享有该产品设计图的复制权", "C. 张某享有该产品设计图的署名权", "D. 甲公司享有该产品设计图的署名权"], "answer": "BC", "explanation": "《著作权法》第18条规定：“自然人为完成法人或者非法人组织工作任务所创作的作品是职务作品……有下列情形之一的职务作品，作者享有署名权，著作权的其他权利由法人或者非法人组织享有，法人或者非法人组织可以给予作者奖励：(一)主要是利用法人或者非法人组织的物质技术条件创作，并由法人或者非法人组织承担责任的工程设计图、产品设计图、地图、示意图、计算机软件等职务作品……”。本题中，产品设计图为职务作品，张某享有该产品设计图的署名权，包括复制权在内的著作权的其他权利由甲公司享有，因此A、D选项错误，B、C选项正确。(2017)", "type": "multiple", "topic": "专题七 著作权法", "page": 206, "subject": "相关法", "id": "xg_660"},
  {"question": "20. 某设计公司的设计师王某接受该公司指派，绘制了一张产品设计图。该设计图主要是利用设计公司的物质技术条件创作，并由该设计公司承担责任。王某与该设计公司没有就设计图的著作权归属进行约定。根据著作权法及相关规定，下列说法正确的是？(单选)", "options": ["A. 王某享有该设计图的著作权，该设计公司可无偿使用", "B. 王某享有该设计图的署名权，该设计公司享有该设计图著作权的其他权利", "C. 王某享有该设计图的发表权、署名权、修改权和保护作品完整权，该设计公司享有该设计图著作权的其他权利", "D. 该设计公司享有该设计图除发表权以外的所有著作权，同时应当给予王某相应的奖励"], "answer": "B", "explanation": "根据《著作权法》第18条的规定，本题中的产品设计图作品为职务作品，王某仅享有署名权和获得奖励的权利，其他权利归单位。因此A、C、D选项错误，B选项正确。（2019）", "type": "single", "topic": "专题七 著作权法", "page": 207, "subject": "相关法", "id": "xg_661"},
  {"question": "21. 中华全国专利代理师协会为提高专利代理师的执业水平，促进我国专利代理行业的健康发展，将2001-2020年国内学者已发表的有关创造性的论文之中的佳作，按照论文发表的时间、创造性判断的顺序等汇编而成了《创造性判断论文选》。下列哪些说法是错误的；(多选)", "options": ["A. 被选编入论文选的论文已经发表，故代理师协会不需征得论文著作权人的同意", "B. 该论文选具有公益性，故代理师协会不需向论文著作权人支付报酬", "C. 他人复制该论文选只需征得代理师协会同意并支付报酬", "D. 如代理师协会未经论文著作权人同意而将有关论文收录，代理人协会对该论文集仍享有著作权"], "answer": "ABC", "explanation": "本题中，该论文选属于汇编作品，专利代理师协会是汇编人，享有著作权，但其行使著作权时，不得侵犯原作品的著作权，即汇编权的产生需要征得原论文著作权人的同意，且需要支付报酬，他人复制该论文选的同时复制了论文，还应当取得论文作者的同意，是否侵犯他人的权利和是否对自己的作品享有权利是两个不同的问题，如果代理师协会未经论文著作权人同意而收录有关论文，则侵犯了作者的著作权，但该侵权行为并不影响代理师协会对该论文选享有著作权，因此A、B、C选项错误，D选项正确。（2018）", "type": "multiple", "topic": "专题七 著作权法", "page": 207, "subject": "相关法", "id": "xg_662"},
  {"question": "22. 居住在美国的我国公民甲创作一部英文小说，乙经许可将该小说翻译成中文小说，丙经许可将该翻译的中文小说改编成电影文学剧本，并向丁杂志社投稿。下列哪些说法是错误的？(多选)", "options": ["A. 甲的小说必须在我国或美国发表才能受我国著作权法保护", "B. 乙翻译的小说和丙改编的电影文学剧本均属于演绎作品", "C. 丙只需征得乙的同意并向其支付报酬"], "answer": "ACD", "explanation": "A选项，《著作权法》第2条第1款规定：“中国公民、法人或者非法人组织的作品，不论是否发表，依照本法享有著作权”，甲虽然居住在美国，但仍然是我国公民，其著作权自作品创作完成时自动保护，无需发表，因此A选项错误。B选项，《著作权法》第13条规定：“改编、翻译、注释、整理已有作品而产生的作品，其著作权由改编、翻译、注释、整理人享有，但行使著作权时不得侵犯原作品的著作权”，翻译、改编均属于对原作品的演绎，因此乙翻译的小说、丙改编的电影文学剧本均属于演绎作品，B选项正确。C、D选项，《著作权法》第16条规定：“使用改编、翻译、注释、整理、汇编已有作品而产生的作品进行出版、演出和制作录音录像制品，应当取得该作品的著作权人和原作品的著作权人许可，并支付报酬”，因此丙需要征得演绎作品著作权人乙和原作品著作权人甲的同意并向其支付报酬，丁杂志社需要征得甲、乙、丙均同意并向其支付费用，C、D选项错误。(法考2012)", "type": "multiple", "topic": "专题七 著作权法", "page": 207, "subject": "相关法", "id": "xg_663"},
  {"question": "1. 根据著作权法及相关规定，关于著作权的继承，下列哪 些说法是正确的？（多选）", "options": ["A. 作者死亡后，其著作权无人继承又无人受遗赠的，其署 名权、修改权和保护作品完整权不再受著作权法保护", "B. 作者死亡后，其著作权无人继承又无人受遗赠的，其署 名权、修改权和保护作品完整权由著作权行政管理部门保护", "C. 作者生前未发表的作品，如作者未明确表示不发表，且 没有继承人又无人受遗赠的，作者死亡后50年内，其发表权由 作品原件的所有人行使", "D. 合作作品作者之一死亡的，其对合作作品享有的著作权 中的财产权无人继承又无人受遗赠的，由其他合作作者享有"], "answer": "BCD", "explanation": "A、B选项，《著作权条例》第\n15条第2款规定：“著作权无人继承又无人\n受遗赠的，其署名权、修改权和保护作品完\n整权由著作权行政管理部门保护”，因此A\n选项错误，B选项正确。C选项，《著作权条\n例》第17条规定：“作者生前未发表的作品，\n如果作者未明确表示不发表，作者死亡后\n50年内，其发表权可由继承人或者受遗赠\n人行使；没有继承人又无人受遗赠的，由作\n品原件的所有人行使”，因此C选项正确。D\n选项，根据《著作权条例》第14条的规定，合\n作者之一死亡后，其对合作作品享有的著\n作权法第10条第1款第五项至第十七项规\n定的权利（均属于财产权）无人继承又无人\n受遗赠的，由其他合作作者享有，因此D选\n项正确。（2012）", "type": "multiple", "topic": "专题七 著作权法", "page": 208, "subject": "相关法", "id": "xg_664"},
  {"question": "3. 根据著作权法及相关规定，下列说法哪些是正确的？(多选)", "options": ["A. 只有视听作品才享有出租权", "B. 展览权是指公开陈列美术作品、摄影作品原件或者复制件的权利", "C. 发表权是决定作品是否公之于众的权利", "D. 修改权是指改变作品，创作出具有独创性的新作品的权利"], "answer": "BC", "explanation": "《著作权法》第10条第1款规定：“著作权包括下列人身权和财产权：（一）发表权，即决定作品是否公之于众的权利……（三）修改权，即修改或者授权他人修改作品的权利……（七）出租权，即有偿许可他人临时使用视听作品、计算机软件的原件或者复制件的权利，计算机软件不是出租的主要标的的除外；（八）展览权，即公开陈列美术作品、摄影作品的原件或者复制件的权利……”，视听作品和计算机软件都享有出租权，因此A、D选项错误，B、C选项正确。（2010）", "type": "multiple", "topic": "专题七 著作权法", "page": 209, "subject": "相关法", "id": "xg_665"},
  {"question": "4. 根据著作权法及相关规定，下列哪项属于著作权中的财产权?(单选)", "options": ["A. 决定作品是否公之于众的权利", "B. 授权他人修改作品的权利", "C. 公开陈列美术作品复制件的权利", "D. 表明作者身份，在作品上署名的权利"], "answer": "C", "explanation": "根据《著作权法》第10条第1款的规定，A选项的发表权（决定作品是否公之于众的权利）、B选项的修改权（修改或者授权他人修改作品的权利）、D选项的署名权（表明作者身份，在作品上署名的权利）均属于人身权。C选项的展览权（公开陈列美术作品、摄影作品的原件或者复制件的权利）属于财产权。（2013）", "type": "single", "topic": "专题七 著作权法", "page": 209, "subject": "相关法", "id": "xg_666"},
  {"question": "5. 书法家王某为甲饭店题了一幅字，同意其在店内展示。乙食品公司未经王某和甲饭店许可，将该字幅拍摄照片后印制在其生产的产品包装上。根据著作权法及相关规定，下列哪项说法是正确的?(单选)", "options": ["A. 乙食品公司侵犯了王某的发表权", "B. 乙食品公司侵犯了王某的复制权", "C. 乙食品公司侵犯了王某的展览权", "D. 乙食品公司侵犯了甲饭店的复制权"], "answer": "B", "explanation": "《著作权法》第10条第1款第（五）项规定：“复制权，即以印刷、复印、拓印、录音、录像、翻录、翻拍、数字化等方式将作品制作一份或者多份的权利”。《著作权法》第20条第1款规定：“作品原件所有权的转移，不改变作品著作权的归属，但美术、摄影作品原件的展览权由原件所有人享有”。本题中，王某将字送给甲饭店，除展览权以外的著作权仍归王某享有，因此乙食品公司侵犯", "type": "single", "topic": "专题七 著作权法", "page": 209, "subject": "相关法", "id": "xg_667"},
  {"question": "6. 根据著作权法及相关规定，下列关于著作人身权的哪些说法是正确的?(多选)", "options": ["A. 署名权是表明作者身份，在作品上署名的权利", "B. 修改权是修改或者授权他人修改作品的权利"], "answer": "AB", "explanation": "根据《著作权法》第10条第1款规定，署名权是表明作者身份，在作品上署名的权利；修改权是修改或者授权他人修改作品的权利。因此A、B选项正确。", "type": "multiple", "topic": "专题七 著作权法", "page": 209, "subject": "相关法", "id": "xg_668"},
  {"question": "7. 根据著作权法及相关规定,下列哪种行为侵犯了著作权 人的出租权?(单选)", "options": ["A. 甲未经著作权人许可,开设店铺出租其购买的武侠小说", "B. 乙未经著作权人许可,开设店铺出租其购买的电视剧 光盘", "C. 丙未经著作权人许可,从出租商店租借武侠小说个人 阅读", "D. 丁未经著作权人许可,从出租商店租借电视剧光盘个人 观看"], "answer": "B", "explanation": "《著作权法》第10条第1款第(七)\n项规定:“出租权,即有偿许可他人临时使用\n视听作品、计算机软件的原件或者复制件的\n权利,计算机软件不是出租的主要标的的除\n外”,只有视听作品、计算机软件享有出租\n权,小说不享有出租权;电视剧光盘属于视\n听作品之一,出租电视剧光盘构成侵犯出租\n权,但租借供个人观看不构成侵犯出租权;\n因此A、C、D选项错误,B选项正确。(2016)", "type": "single", "topic": "专题七 著作权法", "page": 210, "subject": "相关法", "id": "xg_669"},
  {"question": "8. 根据著作权法及相关规定,下列哪种作品的著作权人享 有出租权?(单选)", "options": ["A. 武侠小说", "B. 戏剧剧本", "C. 计算机软件", "D. 美术作品"], "answer": "C", "explanation": "《著作权法》第10条第1款第(七)\n项规定:“出租权,即有偿许可他人临时使用\n视听作品、计算机软件的原件或者复制件的\n权利,计算机软件不是出租的主要标的的除\n外”,因此只有视听作品和计算机软件享有\n出租权,A、B、D选项错误,C选项正确。\n(2017)", "type": "single", "topic": "专题七 著作权法", "page": 210, "subject": "相关法", "id": "xg_670"},
  {"question": "9. 王某将画家张某赠送给自己的20幅绘画作品,署名王某 自己送出版社出版,取得10万元稿酬。王某的行为侵犯了张 某的下列哪些权利?(多选)", "options": ["A. 张某对其作品的财产所有权", "B. 张某对其作品的发行权", "C. 张某对其作品的署名权", "D. 张某对其作品的复制权"], "answer": "BCD", "explanation": "本题中,张某已经将美术作\n品送给王某,王某不侵犯所有权;王某将绘\n画作品送出版社出版,侵犯了张某的发行权\n和复制权;王某将绘画作品署名自己,侵犯\n了张某的署名权;因此A选项错误,B、C、D\n选项正确。(2019)", "type": "multiple", "topic": "专题七 著作权法", "page": 210, "subject": "相关法", "id": "xg_671"},
  {"question": "10. 某网络公司未经许可将张某刚刚创作完成的一幅绘画 作品放到其网站上,供在线浏览和下载。根据著作权法及相关 规定,该网络公司的行为侵犯了张某的下列哪些权利?(多选)", "options": ["A. 发表权", "B. 表演权"], "answer": "AD", "explanation": "本题中,网络公司将张某的\n绘画作品放到网站上,是发表作品的行为,\n侵权作者的发表权;将绘画作品放到网站上\n供在线浏览下载,是网络传播行为,侵权作\n者的信息网络传播权;因此A、D选项正确，", "type": "multiple", "topic": "专题七 著作权法", "page": 210, "subject": "相关法", "id": "xg_672"},
  {"question": "11. 文学家张某收集了近现代著名作家的作品，并按照其独特的文学理论进行分类，将上述作品的片段汇集成册，编写了《名人名家写人》《名人名家写景》《名人名家写事》等三本书。某出版社未经张某的许可复制上述三本书，向社会公开发行。根据著作权法及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 该出版社侵犯了张某的复制权", "B. 该出版社侵犯了张某的发行权", "C. 该出版社侵犯了张某的改编权", "D. 该出版社侵犯了张某的汇编权"], "answer": "AB", "explanation": "本题中，张某为汇编作品的著作权人，出版社未经张某许可复制并发行的行为，侵犯了张某的复制权和发行权，未侵犯张某的改编权和汇编权，因此A、B选项正确，C、D选项错误。(2015)", "type": "multiple", "topic": "专题七 著作权法", "page": 211, "subject": "相关法", "id": "xg_673"},
  {"question": "12. 周某在甲网站发表小说《公民的名义》，该网站以故事情节设计不合理为由将小说删除。周某交涉无果后，不得已以“木森”为笔名向乙网站投稿，乙网站认为作者原名更有利于作品的传播，遂直接将小说署名更改为作者原名周某并提供在线阅读。丙编剧征得乙网站许可后，将小说改编为电视剧本，最后由著名导演李大路执导拍摄同名电视剧。该剧播出后，迅速走红。对此，下列哪一说法是正确的？（单选）", "options": ["A. 甲网站删除小说的行为侵犯了周某发表权", "B. 乙网站更改署名的行为侵犯了周某署名权", "C. 丙编剧改编小说的行为符合著作权法规定", "D. 同名电视剧的著作权人归属于导演李大路"], "answer": "B", "explanation": "A选项，周某在网站发表小说已经行使发表权，因此网站删除小说不侵犯发表权，A选项错误。B选项，网站擅自更改署名侵犯了作者的署名权，因此B选项正确。C选项，改编作品还应获得作者许可，因此C选项错误。D选项，电视剧的著作权人应当为制作者而非导演，D选项错误。(2018)", "type": "single", "topic": "专题七 著作权法", "page": 211, "subject": "相关法", "id": "xg_674"},
  {"question": "13. 李某在二手市场购得一张照片，照片上标明其拍摄日期为2022年1月1日，但未标明作者，根据著作权法及相关规定，在作者身份确定之前，李某享有下列哪些权利？（多选）", "options": ["A. 发表权", "B. 复制权", "C. 展览权"], "answer": "ABC", "explanation": "《著作权法实施条例》第13条规定：“作者身份不明的作品，由作品原件的所有人行使除署名权以外的著作权。作者身份确定后，由作者或者其继承人行使著作权”，因此A、B、C选项正确，D选项错误。(新编)", "type": "multiple", "topic": "专题七 著作权法", "page": 211, "subject": "相关法", "id": "xg_675"},
  {"question": "15. 美术馆收藏了一幅山水画的原件,该幅画是1993年创作完成,但原作者不详。美术馆打算举办一场线上展览活动,请摄影师张某将包括该幅山水画在内的50幅画作拍摄并在网上展出,并加了水印“作者:佚名、拍摄者:张某,美术馆收藏”,李某将山水画下载去掉水印后,在自己的公众号发布,下列说法正确的是?(单选)", "options": ["A. 李某侵犯了张某的信息网络传播权", "B. 李某侵犯了张某的署名权", "C. 李某侵犯了张某的发表权", "D. 李某侵犯了美术馆的信息网络传播权"], "answer": "D", "explanation": "根据《著作权条例》第13条规定：“作者身份不明的作品，由作品原件的所有人行使除署名权以外的著作权。作者身份确定后，由作者或者其继承人行使著作权”，美术馆作为原件所有者，享有除署名权之外的著作权。摄影师张某只是将画作翻拍成照片，没有加入摄影的独创性因素，应当认定为对画作的复制，张某不是著作权人。因此，A、B、C选项错误，D选项正确。（法考2023）", "type": "single", "topic": "专题七 著作权法", "page": 212, "subject": "相关法", "id": "xg_676"},
  {"question": "16. 根据著作权法及相关规定,下列说法哪些是正确的?(多选)", "options": ["A. 作者的署名权的保护期不受限制", "B. 自然人的作品,发表权与发行权保护期一致", "C. 视听作品自创作完成后五十年内未发表的,其放映权不再受著作权法保护", "D. 署名权由作者享有、著作权的其他权利由法人享有的职务作品,保护期为作者终生及死亡后五十年"], "answer": "ABC", "explanation": "A选项,《著作权法》第22条规定:“作者的署名权、修改权、保护作品完整权的保护期不受限制”,因此A选项正确。B选项,自然人的作品,其发表权、财产权(发行权属于财产权之一)的保护期为作者终生及其死亡后50年,B选项正确。C选项,《著作权法》第23条第3款规定:“视听作品,其……本法第十条第一款第五项至第十七项规定的权利(包括放映权)的保护期为50年,截止于作品首次发表后第50年的12月31日,但作品自创作完成后50年内未发表的,本法不再保护”,C选项正确。D选项,《著作权法》第23条第2款规定:“法人或者非法人组织的作品、著作权(署名权除外)由法人或者非法人组织享有的职务作品,其发表权的保护期为50年,截止于作品创作完成后第50年的12月31日……”,因此D选项错误。(2010)", "type": "multiple", "topic": "专题七 著作权法", "page": 212, "subject": "相关法", "id": "xg_677"},
  {"question": "17. 根据著作权法及相关规定，下列哪项权利的保护期不受限制?(单选)", "options": ["A. 修改权", "B. 发表权", "C. 改编权", "D. 发行权"], "answer": "BCD", "explanation": "根据《著作权法》第22条规定：‘作者的署名权、修改权、保护作品完整权的保护期不受限制’，因此B、C、D选项正确。A选项错误，发行权属于财产权，有保护时间的限制。", "type": "single", "topic": "专题七 著作权法", "page": 213, "subject": "相关法", "id": "xg_678"},
  {"question": "18. 2012年1月1日，张某、韩某共同构思一部小说《波涛汹涌的专利战》。2014年6月1日，张某、韩某共同创作完成该小说。韩某于2016年7月1日去世，张某于2017年10月1日去世。根据著作权法及相关规定，以下说法正确的是?(多选)", "options": ["A. 该作品著作权自2012年1月1日起产生", "B. 该作品著作权自2014年6月1日起产生", "C. 该作品复制权的保护期截止到2067年10月1日", "D. 该作品复制权的保护期截止到2067年12月31日"], "answer": "BD", "explanation": "A、B选项，著作权自作品创作完成之日起产生，因此该作品著作权自2014年6月1日完成起产生，A选项错误，B选项正确。C、D选项，著作财产权的保护期截止到张某死亡后第50年的12月31日，即2067年12月31日，因此C选项错误，D选项正确。", "type": "multiple", "topic": "专题七 著作权法", "page": 213, "subject": "相关法", "id": "xg_679"},
  {"question": "21. 根据著作权法及相关规定，下列哪些情况下使用作品，可以不经过著作权人许可，不向其支付报酬，但不能侵犯著作权人依照著作权法享有的其他权利?(多选)", "options": ["A. 为个人欣赏使用他人已经发表的作品", "B. 将中国公民已经发表的以少数民族语言文字创作的作品翻译成国家通用语言文字作品在国内出版发行", "C. 将已经发表的作品改成以阅读障碍者能够感知的无障碍方式提供", "D. 为实施义务教育和国家教育规划而编写出版教科书"], "answer": "ACD", "explanation": "根据《著作权法》第25条第1款的规定，为实施义务教育和国家教育规划而编写出版教科书，可以不经著作权人许可，但应当按照规定向著作权人支付报酬，因此D选项错误。A、C选项符合合理使用的条件，A选项正确。B选项使用“他人未发表的作品”需要获得许可，B选项错误。C选项“美国公民”以及“英文论文”不符合翻译成少数民族语言的合理使用的情形，C选项错误。", "type": "multiple", "topic": "专题七 著作权法", "page": 214, "subject": "相关法", "id": "xg_680"},
  {"question": "22. 根据著作权法及相关规定，下列哪项行为可以不经著作权人许可，不向其支付报酬?(单选)", "options": ["A. 某大学教授张某为研究某课题，少量复制了已经发表的某篇论文供课题组内部使用", "B. 王某为说明某一问题，在作品中引用他人未发表的作品", "C. 某出版社将美国公民李某已经发表的英文论文翻译成少数民族语言文字在我国国内出版", "D. 某出版社为编写出版大学教科书，汇编已经发表的单幅美术作品"], "answer": "A", "explanation": "A选项符合合理使用的条件，A选项正确。B选项使用“他人未发表的作品”需要获得许可，B选项错误。C选项“美国公民”以及“英文论文”不符合翻译成少数民族语言的合理使用的情形，C选项错误。D选项条件不全，但即便D选项出版教科书属于国家教育规划，也属于法定许可，应支付报酬，D选项错误。(2015)", "type": "single", "topic": "专题七 著作权法", "page": 214, "subject": "相关法", "id": "xg_681"},
  {"question": "25. 根据著作权法的规定,关于国家机关为执行公务在合 理范围内使用已经发表的作品,下列说法正确的是?(多选)", "options": ["A. 可以不经著作权人许可", "B. 应当向著作权人支付报酬", "C. 可以不向著作权人支付报酬", "D. 应当指明作者姓名、作品名称"], "answer": "ACD", "explanation": "《著作权法》第24条第1款规\n定:“在下列情况下使用作品,可以不经著作\n权人许可,不向其支付报酬,但应当指明作者\n姓名或者名称、作品名称,并且不得影响该\n作品的正常使用,也不得不合理地损害著\n作权人的合法权益:……(七)国家机关为执\n行公务在合理范围内使用已经发表的作\n品……”,因此A、C、D选项正确,B选项错\n误。(2019)", "type": "multiple", "topic": "专题七 著作权法", "page": 215, "subject": "相关法", "id": "xg_682"},
  {"question": "26. 根据著作权法及相关规定,下列哪些说法是正确的? (多选)", "options": ["A. 著作权转让合同应当采取书面形式", "B. 著作权人许可录音录像制作者专有使用其作品的,应当 订立书面许可使用合同", "C. 著作权转让合同中著作权人未明确转让的权利,视为一 并转让", "D. 与著作权人订立专有许可使用合同的,可以向著作权行 政管理部门备案"], "answer": "ABD", "explanation": "A选项,《著作权法》第27条\n第1款规定:“转让本法第10条第1款第\n(五)项至第(十七)项规定的权利,应当订立\n书面合同”,因此A选项正确。B选项,《著\n作权条例》第23条规定:“使用他人作品应\n当同著作权人订立许可使用合同,许可使用\n的权利是专有使用权的,应当采取书面形\n式,但是报社、期刊社刊登作品除外”,因此\nB选项正确。C选项,《著作权法》第29条规\n定:“许可使用合同和转让合同中著作权人\n未明确许可、转让的权利,未经著作权人同\n意,另一方当事人不得行使”,因此C选项错\n误。D选项,《著作权条例》第25条规定:“与", "type": "multiple", "topic": "专题七 著作权法", "page": 215, "subject": "相关法", "id": "xg_683"},
  {"question": "1. 根据著作权法及相关规定，下列哪些属于著作权法所称与著作权有关的权益？(多选)", "options": ["A. 电视台对其播放的电视节目享有的权利", "B. 录音录像制作者对其制作的录音录像制品享有的权利", "C. 出版者对其出版的图书的版式设计享有的权利", "D. 广播电台对其播放的广播节目享有的权利"], "answer": "ABCD", "explanation": "《著作权条例》第26条规定：“著作权法和本条例所称与著作权有关的权益，是指出版者对其出版的图书和期刊的版式设计享有的权利，表演者对其表演享有的权利，录音录像制作者对其制作的录音录像制品享有的权利，广播电台、电视台对其播", "type": "multiple", "topic": "专题七 著作权法", "page": 216, "subject": "相关法", "id": "xg_684"},
  {"question": "27. 根据著作权法及相关规定，下列关于著作权转让的哪些说法是正确的？(多选)", "options": ["A. 著作权转让合同中著作权人未明确转让的权利，未经著作权人同意，另一方当事人不得行使", "B. 著作权人只可以转让其依法享有的著作权中的财产权", "C. 著作权人可以全部或者部分转让其著作权中的财产权", "D. 著作权转让合同应当采用书面形式"], "answer": "ABCD", "explanation": "A选项，《著作权法》第29条规定：“许可使用合同和转让合同中著作权人未明确许可、转让的权利，未经著作权人同意，另一方当事人不得行使”，因此A选项正确。B、C选项，《著作权法》第10条第3款规定：“著作权人可以全部或者部分转让本条第1款第(五)项至第(十七)项规定的权利，并依照约定或者本法有关规定获得报酬”，上述法条规定的第(五)项至第(十七)项权利属于著作权中的财产权，因此B、C选项正确。D选项，《著作权法》第27条第1款：“转让本法第10条第1款第(五)项至第(十七)项规定的权利，应当订立书面合同”，因此D选项正确。(新编)", "type": "multiple", "topic": "专题七 著作权法", "page": 216, "subject": "相关法", "id": "xg_685"},
  {"question": "28. 根据著作权法及相关规定，下列关于著作权转让合同的说法哪项是错误的？(单选)", "options": ["A. 著作权转让合同应当采用书面形式", "B. 著作权中的署名权不得转让", "C. 著作权中的改编权可以转让", "D. 著作权转让合同自向著作权行政管理部门备案之日起生效"], "answer": "D", "explanation": "A选项，著作权转让应当订立书面合同，正确。B选项，署名权属于人身权，不能转让。C选项，改编权属于财产权，可以转让。D选项，一般情况下，合同自成立时生效，D选项错误。(2014)", "type": "single", "topic": "专题七 著作权法", "page": 216, "subject": "相关法", "id": "xg_686"},
  {"question": "29. 根据著作权法及相关规定，著作权许可使用合同包括下列哪些内容？(多选)", "options": ["A. 许可使用的权利种类", "B. 许可使用的权利是专有使用权或者非专有使用权", "C. 许可使用的地域范围、期间", "D. 付酬标准和办法 第四章 与著作权相关的权利"], "answer": "ABCD", "explanation": "《著作权法》第26条第2款规定：“许可使用合同包括下列主要内容：(一)许可使用的权利种类；(二)许可使用的权利是专有使用权或者非专有使用权；(三)许可使用的地域范围、期间；(四)付酬标准和办法……”，因此A、B、C、D选项均正确。\n(2017)", "type": "multiple", "topic": "专题七 著作权法", "page": 216, "subject": "相关法", "id": "xg_687"},
  {"question": "2. 李某将自己创作的一部小说交某出版社出版。根据著作权法及相关规定，下列说法哪些是正确的？(多选)", "options": ["A. 该出版社应当与李某订立出版合同，并支付报酬", "B. 经李某许可，该出版社可以对小说进行删节", "C. 该出版社有权禁止其他出版社使用该小说的版式设计", "D. 该出版社再版该小说的，可以不通知李某，但应支付报酬"], "answer": "ABC", "explanation": "A选项，《著作权法》第32条规定：“图书出版者出版图书应当和著作权人订立出版合同，并支付报酬”，因此A选项正确。B选项，《著作权法》第36条第1款规定：“图书出版者经作者许可，可以对作品修改、删节”，因此B选项正确。C选项，《著作权法》第37条第1款规定：“出版者有权许可或者禁止他人使用其出版的图书、期刊的版式设计”，因此C选项正确。D选项，《著作权法》第34条第3款规定：“图书出版者重印、再版作品的，应当通知著作权人，并支付报酬……”，因此D选项错误。(2011)", "type": "multiple", "topic": "专题七 著作权法", "page": 217, "subject": "相关法", "id": "xg_688"},
  {"question": "3. 王某将其撰写的一篇论文向某期刊社投稿，且双方没有任何约定。根据著作权法及相关规定，下列说法哪些是正确的？(多选)", "options": ["A. 自稿件发出之日起十五日内未收到该期刊社通知决定刊登的，王某可以将该论文向其他期刊社投稿", "B. 自稿件发出之日起三十日内未收到该期刊社通知决定刊登的，王某可以将该论文向其他期刊社投稿", "C. 如果该期刊社刊登了该论文，且王某未声明不得转载，则其他期刊社可以不经王某许可转载该论文，不需向其支付报酬", "D. 该期刊社刊登该论文的，可以对该论文作文字性删节，无需经王某许可"], "answer": "BD", "explanation": "A、B选项，《著作权法》第35条第1款规定：“著作权人向报社、期刊社投稿的，自稿件发出之日起15日内未收到报社通知决定刊登的，或者自稿件发出之日起30日内未收到期刊社通知决定刊登的，可以将同一作品向其他报社、期刊社投稿。双方另有约定的除外”，因此A选项错误，B选项正确。C选项，《著作权法》第35条第2款规定：“作品刊登后，除著作权人声明不得转载、摘编的外，其他报刊可以转载或者作为文摘、资料刊登，但应当按照规定向著作权人支付报酬”，因此C选项错误。D选项，《著作权法》第36条第2款规定：“报社、期刊社可以对作品作文字性修改、删节。对内容的修改，应当经作者许可”，因此D选项正确。(2009)", "type": "multiple", "topic": "专题七 著作权法", "page": 217, "subject": "相关法", "id": "xg_689"},
  {"question": "4. 刘某授权某期刊社刊登其一篇文章。根据著作权法及相关规定，下列哪些说法是正确的？(多选)", "options": ["A. 该期刊社对该文章进行文字性删节，可以不经刘某许可", "B. 该期刊社对该文章内容的修改，可以不经刘某许可", "C. 该期刊社对该文章进行文字性修改，可以不经刘某许可", "D. 该期刊社对该文章内容的修改，应当经刘某许可"], "answer": "ACD", "explanation": "《著作权法》第36条第2款规定：“报社、期刊社可以对作品作文字性修改、删节。对内容的修改，应当经作者许可”，因此A、C、D选项正确，B选项错误。(新编)", "type": "multiple", "topic": "专题七 著作权法", "page": 217, "subject": "相关法", "id": "xg_690"},
  {"question": "9. 根据著作权法及相关规定,下列哪些属于表演者对其表演享有的权利?(多选)", "options": ["A. 表明表演者身份", "B. 保护表演形象不受歪曲", "C. 许可他人从现场直播和公开传送其现场表演,并获得报酬", "D. 许可他人出租录有其表演的录音录像制品,并获得报酬"], "answer": "ABCD", "explanation": "《著作权法》第39条第1款规定:“表演者对其表演享有下列权利:(一)表明表演者身份;(二)保护表演形象不受歪曲;(三)许可他人从现场直播和公开传送其现场表演,并获得报酬……(五)许可他人复制、发行、出租录有其表演的录音录像制品,并获得报酬……”,因此A、B、C、D选项均正确。(2016)", "type": "multiple", "topic": "专题七 著作权法", "page": 219, "subject": "相关法", "id": "xg_691"},
  {"question": "11. 某影视中心在一电视连续剧中为衬托剧情,使用了某正版唱片中的局部音乐作品作为背景音乐。中国音乐著作权协会是该唱片授权行使著作权及相关权利组织,以该使用行为未经许可为由要求该影视中心支付酬劳。该协会的要求被拒绝后,遂向法院起诉。以下说法哪些是正确的?(多选)", "options": ["A. 播放行为侵犯了音乐表演者的权利", "B. 播放行为侵犯了音乐作品著作权人的权利", "C. 播放行为侵犯了录音制品制作者的权利", "D. 中国音乐著作权协会不是正当原告 - 218 -"], "answer": "ABC", "explanation": "A、B、C选项,电视连续剧中使用音乐作品作为背景音乐,属于复制行为。音乐作品的著作权人、表演者、录音制", "type": "multiple", "topic": "专题七 著作权法", "page": 219, "subject": "相关法", "id": "xg_692"},
  {"question": "12. 根据著作权法及相关规定，关于广播电台电视台播放者的权利义务，下列哪些说法是正确的？（多选）", "options": ["A. 广播电台播放他人未发表的作品，应当取得著作权人许可，并支付报酬", "B. 广播电台播放他人未发表的作品，应当取得著作权人许可，但无需支付报酬", "C. 电视台播放他人已发表的作品，可以不经著作权人许可，但应当支付报酬", "D. 电视台播放他人的录像制品，可以不经著作权人许可，但应当支付报酬"], "answer": "AC", "explanation": "A、B选项，《著作权法》第46条第1款规定：“广播电台、电视台播放他人未发表的作品，应当取得著作权人许可，并支付报酬”，因此A选项正确，B选项错误。\nC选项，《著作权法》第46条第2款规定：“广播电台、电视台播放他人已发表的作品，可以不经著作权人许可，但应当按照规定支付报酬”，因此C选项正确。\nD选项，《著作权法》第48条规定：“电视台播放他人的视听作品、录像制品，应当取得视听作品著作权人或者录像制作者许可，并支付报酬；播放他人的录像制品，还应当取得著作权人许可，并支付报酬”，因此D选项错误。（2019）", "type": "multiple", "topic": "专题七 著作权法", "page": 220, "subject": "相关法", "id": "xg_693"},
  {"question": "13. 李某于2016年8月4日创作完成小说《别来烦我》，2017年3月5日发表于某文学刊物后被张某改编成剧本，甲公司根据该剧本拍成同名电视剧，乙电视台将该电视剧进行播放。对此，下列哪一选项是错误的？（单选）", "options": ["A. 李某从2017年3月5日起对小说享有著作权", "B. 张某对剧本享有著作权", "C. 甲公司将该剧本拍成电视剧应当取得李某和张某的许可并支付报酬", "D. 乙电视台播放该电视剧应当取得甲公司许可并支付报酬"], "answer": "A", "explanation": "A选项，李某从2016年8月4日创作完成之日起对小说享有著作权，A选项错误。\nB选项，张某对其改编的剧本享有著作权，B选项正确。\nC选项，甲公司将张某改编的剧本拍成电视剧应取得演绎作品著作权人张某以及原作品作者李某的许可并支付报酬，C选项正确。\nD选项，乙电视台播放该电视剧（视听作品）应当取得著作权人甲公司许可并支付报酬，D选项正确。（法考2008）", "type": "single", "topic": "专题七 著作权法", "page": 220, "subject": "相关法", "id": "xg_694"},
  {"question": "14. 甲创作并演唱了《都是玫瑰惹的祸》，乙公司擅自将该歌曲制成彩铃在网络上供免费下载。乙公司侵犯了甲的哪些权利？（多选）", "options": ["A. 信息网络传播权", "B. 广播权", "C. 表演者权", "D. 发行权"], "answer": "AC", "explanation": "本题中，甲既是作者又是表演者，乙公司擅自将该歌曲制成彩铃在网络上提供免费下载的行为，侵犯了甲的信息网络传播权和表演者权，因此A、C选项正确，B、D选项错误。（法考2007）", "type": "multiple", "topic": "专题七 著作权法", "page": 220, "subject": "相关法", "id": "xg_695"},
  {"question": "15. 袁某创作完成了一部小说，并发表在某杂志上。此后，经许可，赵某将该小说改编成舞台剧本，陈某在某剧院公开演出该舞台剧，某电视台对该演出进行了现场录像并制作成光盘。", "options": ["A. 袁某对该小说的发行权保护期截止于首次发表后第五十年的12月31日", "B. 赵某对该舞台剧剧本的修改权保护期截止于首次公演后第五十年的12月31日", "C. 陈某享有许可电视台对其表演的该舞台剧进行录像并获得报酬的权利，此项权利的保护期限截止于该表演发生后第五十年的12月31日", "D. 该电视台享有许可他人对其制作的该光盘进行复制并获得报酬的权利，此项权利的保护期限截止于该光盘首次制作完成后第五十年的12月31日"], "answer": "CD", "explanation": "A选项，发行权属于著作权财产权，保护期为作者终生及其死亡后50年，截止于作者死亡后第50年的12月31日，A", "type": "single", "topic": "专题七 著作权法", "page": 220, "subject": "相关法", "id": "xg_696"},
  {"question": "16. 甲创作了一首歌曲《告白气球》，乙获得许可后在个人演唱会上进行演唱，丙唱片公司制成录音制品并公开发行。针对该录音制品，下列哪些属于侵权行为？(多选)", "options": ["A. 某公司翻录后进行销售，同时向甲、乙、丙寄送报酬", "B. 某航空公司购买正版唱片后在飞机上广播供乘客欣赏，仅经过甲的许可", "C. 某电影公司将其作为电影插曲使用，同时经过乙和丙的许可", "D. 某学生购买正版唱片试听后将其上传到网上供网友个人欣赏"], "answer": "ABCD", "explanation": "A选项，某公司复制唱片并发行，需要经过著作权人、演唱者、录像制作者的许可并付费，某公司没有经过著作权人的许可，属于侵权行为。B选项，某航空公司购买正版录音制品在飞机上播放供乘客欣赏经过了著作权人甲的许可，并未侵犯作品的表演权，但是播放录音制品，录音制作者有收取报酬的权利，航空公司仅获得著作权人许可，未向录音制作者支付报酬，仍属于侵权行为。C选项，电影公司将歌曲作为插曲，应同时经过甲、乙、丙三人许可，仅经过乙、丙许可，侵犯甲的复制权。D选项，某学生侵犯了著作权人、录音制作者以及表演者的信息网络传播权。(2018)", "type": "multiple", "topic": "专题七 著作权法", "page": 221, "subject": "相关法", "id": "xg_697"},
  {"question": "17. 甲电视台获得了某歌星演唱会的现场直播权，乙电视台未经许可对甲电视台直播的演唱会实况进行转播，丙广播电台经过许可将现场演唱制作成CD，丁音像店从正规渠道购买到CD用于出租，戊未经许可将丙广播电台播放的演唱会录音录下后上传到网站上传播。下列哪些选项是正确的？(多选)", "options": ["A. 甲电视台有权禁止乙电视台的转播", "B. 乙电视台侵犯了该歌星的表演者权", "C. 丁音像店应取得该歌星或丙广播电台的许可并向其支付报酬", "D. 戊的行为只需取得丙广播电台的许可并应向其支付"], "answer": "AB", "explanation": "A选项，广播电台、电视台有转播权，乙电视台未经许可转播，甲电视台有权禁止，A选项正确。B选项，表演者有许可他人从现场直播和公开传送其现场表演的权利，乙电视台未经许可转播其演唱的行为侵犯了其表演者权，因此B选项正确。C选项，音像店出租录音录像制品，应当取得表演者以及录音录像制作者丙的许可并支付报酬，不能只获得二者之一的许可，C选项错误。D选项，音乐作品的著作权人、表演者、录音录像制作者均享有信息网络传播权，因此戊通过信息网络向公众传播仅取得", "type": "multiple", "topic": "专题七 著作权法", "page": 221, "subject": "相关法", "id": "xg_698"},
  {"question": "1. 根据著作权法的规定，在下列哪些情形下，个人或者组织可以避开技术措施，但不得向他人提供避开技术措施的技术、装置或者部件，也不得侵犯权利人依法享有的其他权利?(多选)", "options": ["A. 为学校课堂教学，向少数教学人员提供少量已经发表的作品，而该作品无法通过正常途径获取", "B. 不以营利为目的，以阅读障碍者能够感知的无障碍方式向其提供已经发表的作品，而该作品无法通过正常途径获取", "C. 国家机关依照行政、司法程序执行公务", "D. 对计算机及其系统或者网络的安全性能进行测试 -221-"], "answer": "ABCD", "explanation": "《著作权法》第50条第1款规定:“下列情形可以避开技术措施,但不得向他人提供避开技术措施的技术、装置或者部件,不得侵犯权利人依法享有的其他权利: (一)为学校课堂教学或者科学研究,提供少量已经发表的作品,供教学或者科研人员使用,而该作品无法通过正常途径获取;(二) 不以营利为目的,以阅读障碍者能够感知的无障碍方式向其提供已经发表的作品,而该", "type": "multiple", "topic": "专题七 著作权法", "page": 222, "subject": "相关法", "id": "xg_699"},
  {"question": "18. 叶某创作《星光灿烂》词曲并发表于音乐杂志，郝某在个人举办的赈灾义演中演唱该歌曲，南极熊唱片公司录制并发了行郝某的演唱会唱片，星星电台购买该唱片并播放了该歌曲。下列哪些说法是正确的?(多选)", "options": ["A. 郝某演唱《星光灿烂》应征得叶某同意并支付报酬", "B. 南极熊唱片公司录制该歌曲应当征得郝某同意并支付报酬", "C. 星星电台播放该歌曲应征得叶某同意", "D. 星星电台播放该歌曲应征得南极熊唱片公司同意"], "answer": "AB", "explanation": "A选项，赈灾义演只是不向演员支付报酬，仍然需要观众支付费用，因此不属于合理使用情形,郝某应征得叶某同意并支付报酬,A选项正确。B选项,南极熊唱片公司录制该歌曲应当征得叶某、郝某同意并支付报酬,B选项正确。C、D选项,星星电台播放该唱片不需要向著作权人、录音制作者许可,但需要向著作权人、录音制作者支付报酬,因此无需经叶某和南极熊唱片公司同意,C、D选项错误。(法考2009)", "type": "multiple", "topic": "专题七 著作权法", "page": 222, "subject": "相关法", "id": "xg_700"},
  {"question": "19. 陈某创作一部戏剧剧本《等待》，甲剧团安排本单位的演员进行了演出，但没有约定著作权相关的权利归属。东方卫视经授权对该歌舞剧进行了现场直播，咕噜网未经许可将东方卫视播出的歌舞剧同步至网络供用户付费点播和下载。下列有关说法正确的是?(多选)", "options": ["A. 咕噜网侵犯了陈某的信息网络传播权", "B. 咕噜网侵犯了甲剧团演员们的信息网络传播权", "C. 咕噜网侵犯了甲剧团的信息网络传播权", "D. 咕噜网侵犯了东方卫视的广播组织者权 第五章 著作权及其相关权利的保护"], "answer": "ACD", "explanation": "陈某是剧本的作者,对剧本享有著作权,有权禁止他人将剧本通过信息网络传播,A选项正确。甲剧团演员为完成单位的演出任务而进行的表演活动为职务表演,表演者权由甲剧团享有,甲剧团有权禁止他人未经许可将该剧通过信息网络传播,B选项错误,C正确。东方卫视对于该剧播放形成的信号,享有广播组织者权,咕噜网未经许可将其电视信号上传至网络,侵犯了东方卫视的广播组织者权,D选项正确。综上所述,A、C、D选项正确。(法考2023)", "type": "multiple", "topic": "专题七 著作权法", "page": 222, "subject": "相关法", "id": "xg_701"},
  {"question": "2. 根据著作权法及相关规定，下列哪些行为侵犯了著作权或与著作权有关的权利？（多选）", "options": ["A. 张某未经王某许可，发表了王某创作完成的小说", "B. 郑某为谋取个人名利，在许某创作完成的作品上署名", "C. 甲出版社未经乙出版社的许可，使用了其出版的图书的版式设计", "D. 丙电视台未经歌星张某许可，录制了其表演"], "answer": "ABCD", "explanation": "《著作权法》第 52 条规定：“有下列侵权行为的，应当根据情况，承担停止侵害、消除影响、赔礼道歉、赔偿损失等民事责任：（一）未经著作权人许可，发表其作品的……（三）没有参加创作，为谋取个人名利，在他人作品上署名的……（九）未经出版者许可，使用其出版的图书、期刊的版式设计的；（十）未经表演者许可，从现场直播或者公开传送其现场表演，或者录制其表演的……”，因此 A、B、C、D 选项均正确。\n（2013）", "type": "multiple", "topic": "专题七 著作权法", "page": 223, "subject": "相关法", "id": "xg_702"},
  {"question": "3. 根据著作权法及相关规定，下列哪些侵权行为损害公共利益的，可由主管著作权的部门给予行政处罚？（多选）", "options": ["A. 孙某未经舞蹈家王某许可，现场录制其舞蹈表演并上传到互联网提供免费下载", "B. 赵某未经作家李某许可，擅自复制、发行其小说", "C. 甲出版社出版乙出版社享有专有出版权的图书", "D. 钱某未经丙音像公司许可复制、发行其音像制品"], "answer": "ABCD", "explanation": "根据《著作权法》第 53 条的规定，损害公共利益的，可由主管著作权的部门给予行政处罚。A 选项属于未经表演者许可，通过信息网络向公众传播其表演；B 选项属于未经著作权人许可，复制、发行其作品；C 选项属于出版他人享有专有出版权的图书；D 选项属于未经录音录像制作者许可，复制、发行录音录像制品；上述 A、B、C、D 选项均属于著作权法 53 条规定的情形。（新编）", "type": "multiple", "topic": "专题七 著作权法", "page": 223, "subject": "相关法", "id": "xg_703"},
  {"question": "5. 甲公司委托乙公司设计并制作产品包装盒，未签订书面合同。丙在市场上发现该产品包装盒上未经其许可使用了其画《翠竹》作为背景图案。如果该产品包装盒的整体设计也构成美术图案，下列哪些选项是正确的？（多选）", "options": ["A. 产品包装盒的版权属于甲公司", "B. 乙公司侵害了丙的复制权", "C. 甲公司对乙公司的侵权行为不知情，但仍构成侵权", "D. 甲公司不能对产品包装盒获得外观设计专利申请权"], "answer": "BCD", "explanation": "A、D 选项，甲公司和乙公司对产品包装盒的著作权、专利权归属没有约定，著作权、申请专利的权利应属于受托人乙公司，因此 A 选项错误、D 选项正确。B 选项，乙在设计、制作包装盒的过程中，未经丙许可复制了丙的画《翠竹》作为背景图案，侵", "type": "multiple", "topic": "专题七 著作权法", "page": 223, "subject": "相关法", "id": "xg_704"},
  {"question": "6. 根据著作权法及相关规定，下列哪些属于侵犯著作权承担的民事责任？(多选)", "options": ["A. 停止侵害", "B. 赔偿损失", "C. 消除影响", "D. 赔礼道歉"], "answer": "ABCD", "explanation": "《著作权法》第52条规定：“有下列侵权行为的，应当根据情况，承担停止侵害、消除影响、赔礼道歉、赔偿损失等民事责任……”，因此A、B、C、D选项均正确。（2016）", "type": "multiple", "topic": "专题七 著作权法", "page": 224, "subject": "相关法", "id": "xg_705"},
  {"question": "7. 根据著作权法及相关规定，因侵犯著作权行为提起的民事诉讼，可以由哪些人民法院管辖？(多选)", "options": ["A. 侵权行为的实施地人民法院", "B. 侵权复制品储藏地人民法院", "C. 侵权复制品查封扣押地人民法院", "D. 被告住所地人民法院"], "answer": "ABCD", "explanation": "《著作权纠纷解释》第4条第1款规定：“因侵害著作权行为提起的民事诉讼，由著作权法第52条、第53条规定侵权行为的实施地、侵权复制品储藏地或者查封扣押地、被告住所地人民法院管辖”，因此A、B、C、D选项均正确。（2016）", "type": "multiple", "topic": "专题七 著作权法", "page": 224, "subject": "相关法", "id": "xg_706"},
  {"question": "8. 甲制作、出售了大量冒用乙署名的作品，其承担责任的方式可能为：(多选)", "options": ["A. 根据情况，甲需承担停止侵害、消除影响、赔礼道歉、赔偿损失等民事责任", "B. 若甲的行为损害了公共利益，可以由主管著作权的部门责令停止侵权行为，没收违法所得，没收、无害化销毁侵权复制品，并可处以罚款", "C. 若甲的行为损害了公共利益，可以由主管著作权的部门没收主要用于制作侵权复制品的材料、工具、设备等", "D. 若构成犯罪的，可依法追究甲的刑事责任"], "answer": "ABCD", "explanation": "《著作权法》第53条规定：“有下列侵权行为的，应当根据情况，承担本法第52条规定的民事责任（停止侵害、消除影响、赔礼道歉、赔偿损失）；侵权行为同时损害公共利益的，由主管著作权的部门责令停止侵权行为，予以警告，没收违法所得，没收、无害化销毁处理侵权复制品以及主要用于制作侵权复制品的材料、工具、设备等，违法经营额5万元以上的，可以并处违法经营额1倍以上5倍以下的罚款；没有违法经营额、违法经营额难以计算或者不足5万元的，可以并处25万元以下的罚款；构成犯罪的，依法追究刑事责任；……（八）制作、出售假冒他人署名的作品的”，因此A、B、C、D选项均正确。（2018）", "type": "multiple", "topic": "专题七 著作权法", "page": 224, "subject": "相关法", "id": "xg_707"},
  {"question": "9. 甲公司开发了一套财务管理软件，乙公司未经甲公司同意复制了大量该软件进行销售。甲公司向人民法院提起诉讼要求乙公司赔偿。下列关于赔偿数额的说法哪些是正确的？(多选)", "options": ["A. 赔偿数额应当按照甲公司因此受到的实际损失或者乙公司的违法所得计算", "B. 甲公司的实际损失或者乙公司的违法所得难以计算的，"], "answer": "ABCD", "explanation": "《著作权法》第54条第1、2、3款规定：“侵犯著作权或者与著作权有关的权利的，侵权人应当按照权利人因此受到的实际损失或者侵权人的违法所得给予赔偿；权利人的实际损失或者侵权人的违法所得", "type": "multiple", "topic": "专题七 著作权法", "page": 224, "subject": "相关法", "id": "xg_708"},
  {"question": "10. 在某案审理中，人民法院确认了以下事实：甲公司侵犯乙公司的著作权，乙公司因此遭受到的实际损失为200万元，乙公司为制止侵权行为所支付的合理开支为10万元。根据著作权法及相关规定，甲公司应当给予乙公司的赔偿数额是多少？（单选）", "options": ["A. 100万元", "B. 200万元", "C. 210万元", "D. 310万元"], "answer": "C", "explanation": "《著作权法》第54条规定：“侵犯著作权或者与著作权有关的权利的，侵权人应当按照权利人因此受到的实际损失或者侵权人的违法所得给予赔偿……赔偿数额还应当包括权利人为制止侵权行为所支付的合理开支……”，因此甲公司应当给予乙公司的赔偿数额为乙公司的实际损失与乙公司为制止侵权行为所支付合理开支的总额，即200万元+10万元=210万元，A、B、D选项错误，C选项正确。（2019）", "type": "single", "topic": "专题七 著作权法", "page": 225, "subject": "相关法", "id": "xg_709"},
  {"question": "11. 甲公司有证据证明乙网络公司正在非法传播其享有著作权的某部影视作品，如不及时制止将会使其合法权益受到难以弥补的损害。根据著作权法及相关规定，甲公司可以在起诉前向人民法院申请采取下列哪些措施？（多选）", "options": ["A. 责令乙网络公司停止传播行为", "B. 对乙网络公司采取财产保全措施", "C. 责令乙网络公司先行赔付", "D. 没收乙网络公司的服务器"], "answer": "AB", "explanation": "《著作权法》第56条第1款规定：“著作权人或者与著作权有关的权利人有证据证明他人正在实施或者即将实施侵犯其权利、妨碍其实现权利的行为，如不及时制止将会使其合法权益受到难以弥补的损害的，可以在起诉前依法向人民法院申请采取财产保全、责令作出一定行为或者禁止作出一定行为等措施”，因此A、B选项正确，C、D选项错误。（2010）", "type": "multiple", "topic": "专题七 著作权法", "page": 225, "subject": "相关法", "id": "xg_710"},
  {"question": "12. 根据著作权法及相关规定，当事人可以通过下列哪些途径解决著作权侵权纠纷？（多选）", "options": ["A. 根据著作权合同中的仲裁条款，向仲裁机构申请仲裁", "B. 调解", "C. 向国家著作权主管部门申请裁决", "D. 向人民法院起诉"], "answer": "ABD", "explanation": "《著作权法》第60条规定：“著作权纠纷可以调解，也可以根据当事人达成的书面仲裁协议或者著作权合同中的仲裁条款，向仲裁机构申请仲裁。当事人没有书面仲裁协议，也没有在著作权合同中订立仲裁条款的，可以直接向人民法院起诉”，因此A、B、D选项正确，C选项错误。（新编）", "type": "multiple", "topic": "专题七 著作权法", "page": 225, "subject": "相关法", "id": "xg_711"},
  {"question": "1. 根据计算机软件保护条例的规定,计算机软件著作权的保护不延及下列哪些内容?(多选)", "options": ["A. 开发软件所用的思想", "B. 开发软件所用的处理过程", "C. 开发软件所用的操作方法", "D. 开发软件所用的数学概念"], "answer": "ABCD", "explanation": "《软件条例》第6条规定:“本条例对软件著作权的保护不延及开发软件所用的思想、处理过程、操作方法或者数学概念等”,因此A、B、C、D选项均正确。(2016)", "type": "multiple", "topic": "专题七 著作权法", "page": 226, "subject": "相关法", "id": "xg_712"},
  {"question": "2. 根据计算机软件保护条例的规定,下列哪些说法是正确的?(多选)", "options": ["A. 计算机软件要获得著作权保护,应当是权利人独立开发的,剽窃他人的计算机软件不能获得著作权保护", "B. 计算机软件要获得著作权保护,应当按照规定进行著作权登记", "C. 计算机软件要获得著作权保护,应当已被固定在某种有形物体上", "D. 计算机软件要获得著作权保护,首先需要公开"], "answer": "AC", "explanation": "A、C选项,《软件条例》第4条规定:“受本条例保护的软件必须由开发者独立开发,并已固定在某种有形物体上”,因此A、C选项正确。B、D选项,《软件条例》第14条第1款规定:“软件著作权自软件开发完成之日起产生”,无需登记和公开,因此B、D选项错误。(2020)", "type": "multiple", "topic": "专题七 著作权法", "page": 226, "subject": "相关法", "id": "xg_713"},
  {"question": "4. 下列不属于软件著作权人享有的权利的是:(单选)", "options": ["A. 署名权", "B. 保护作品完整权"], "answer": "B", "explanation": "《软件条例》第8条第1款规定:“软件著作权人享有下列各项权利:(一)发表权……(二)署名权……(三)修改权……(四)复制权……(五)发行权……(六)出租权……(七)信息网络传播权……(八)翻译权……(九)应当由软件著作权人享有的其他权利”,因此A、C、D选项正确。B选项的", "type": "single", "topic": "专题七 著作权法", "page": 226, "subject": "相关法", "id": "xg_714"},
  {"question": "5. 根据计算机软件保护条例的规定，计算机软件的合法复制品所有人享有下列哪些权利？（多选）", "options": ["A. 根据使用的需要把该计算机软件装入计算机等具有信息处理能力的装置内", "B. 为了防止复制品损坏而制作备份复制品", "C. 为了改进计算机软件功能、性能而进行必要的修改", "D. 为了把该计算机软件用于实际的计算机应用环境而进行必要的修改"], "answer": "ABCD", "explanation": "《软件条例》第16条规定：“软件的合法复制品所有人享有下列权利：（一）根据使用的需要把该软件装入计算机等具有信息处理能力的装置内；（二）为了防止复制品损坏而制作备份复制品……；（三）为了把该软件用于实际的计算机应用环境或者改进其功能、性能而进行必要的修改；但是，除合同另有约定外，未经该软件著作权人许可，不得向任何第三方提供修改后的软件”，因此A、B、C、D选项均正确。(2007)", "type": "multiple", "topic": "专题七 著作权法", "page": 227, "subject": "相关法", "id": "xg_715"},
  {"question": "6. 甲公司委托乙公司开发库存产品信息追踪软件，付费50万元，没有明确约定著作权的归属。后甲公司以高价向善意的丙公司出售了该软件的复制品。丙公司安装使用5年后，丙公司自行开发的同类软件已经在试运行中，此时乙公司起诉要求丙公司停止使用并销毁该软件。下列哪些表述是正确的：（多选）", "options": ["A. 该软件的著作权属于乙公司", "B. 乙公司的起诉已超过诉讼时效", "C. 丙公司可不承担赔偿责任", "D. 丙公司应停止使用并销毁该软件"], "answer": "ACD", "explanation": "A选项，未约定著作权归属，完成者乙公司享有著作权，A选项正确。B选项，丙公司的侵权行为在起诉时仍在持续，因此未过时效，B选项错误。C、D选项，《软件条例》第30条规定：“软件的复制品持有人不知道也没有合理理由应当知道该软件是侵权复制品的，不承担赔偿责任；但是，应当停止使用、销毁该侵权复制品……”，丙公司可以不承担侵权赔偿责任，但应停止使用并销毁软件，因此C、D选项正确。(2018)", "type": "multiple", "topic": "专题七 著作权法", "page": 227, "subject": "相关法", "id": "xg_716"},
  {"question": "7. 根据计算机软件保护条例的规定，下列说法哪些是正确的？（多选）", "options": ["A. 软件著作权人应当向国务院著作权行政管理部门认定的软件登记机构办理登记", "B. 计算机软件著作权自计算机软件登记之日起产生，保护期为自软件登记之日起50年", "C. 软件登记机构发放的登记证明文件是登记事项的初步证明", "D. 法人或者其他组织的软件著作权，自开发完成之日起50年内未发表的不再受保护"], "answer": "CD", "explanation": "A、C选项，《软件条例》第7条第1款规定：“软件著作权人可以向国务院著作权行政管理部门认定的软件登记机构办理登记。软件登记机构发放的登记证明文件是登记事项的初步证明”，因此A选项错误，C选项正确。B、D选项，《软件条例》第14条规定：“软件著作权自软件开发完成之日起产生……法人或者其他组织的软件著作权，保护期为50年，截止于软件首次发表后第50年的12月31日，但软件自开发完成之日起50年内未发表的，本条例不再保护”，因此B选项错误，D选项正确。(2010改编)", "type": "multiple", "topic": "专题七 著作权法", "page": 227, "subject": "相关法", "id": "xg_717"},
  {"question": "1. 根据信息网络传播权保护条例的规定,下列哪些是信息网络传播权的权利人?(多选)", "options": ["A. 著作权人", "B. 表演者", "C. 录音录像制作者", "D. 网络用户"], "answer": "ABC", "explanation": "《网络传播条例》第1条规定：“为保护著作权人、表演者、录音录像制作者（以下统称权利人）的信息网络传播权，……，制定本条例”，A、B、C选项正确，D选项不受本条例保护。(2015)", "type": "multiple", "topic": "专题七 著作权法", "page": 228, "subject": "相关法", "id": "xg_718"},
  {"question": "2. 甲网站与乙唱片公司签订录音制品的信息网络传播权许可使用合同,按约定支付报酬后,即开展了网上原版音乐下载业务。对甲网站的行为应如何认定?(单选)", "options": ["A. 是合法使用行为", "B. 构成侵权行为,因为该行为应取得著作权人的许可,而不是取得录音制作者的许可", "C. 构成侵权行为,因为该行为还须取得著作权人、表演者的许可并支付报酬", "D. 构成侵权行为,因为该行为虽然无须取得著作权人的许可,但必须取得表演者的许可"], "answer": "C", "explanation": "《网络传播条例》第2条规定：“权利人享有的信息网络传播权受著作权法和本条例保护。除法律、行政法规另有规定的外，任何组织或者个人将他人的作品、表演、录音录像制品通过信息网络向公众提供，应当取得权利人许可，并支付报酬”。本题中甲网站没有取得著作权人、表演者的许可，也没有向其支付报酬，构成侵权行为，C选项正确。(2005)", "type": "single", "topic": "专题七 著作权法", "page": 228, "subject": "相关法", "id": "xg_719"},
  {"question": "3. 电视剧《一切为了人民》播出后迅速走红。在该电视剧在各大卫视分集热播阶段,甲聘请丙将播放画面中的“李大路出品,复制必究”的水印去除,然后将全集上传至乙网站供公众免费点播,乙网站为提高浏览量默许甲的行为。权利人江东电视台知晓后,要求乙网站断开链接、删除内容,乙网站接到通知立即采取了上述措施。下列哪一说法是错误的?(单选)", "options": ["A. 甲侵害了权利人的信息网络传播权", "B. 乙网站无须对权利人承担侵权责任", "C. 丙实施了删除权利管理电子信息的行为构成侵权", "D. 著作权行政管理部门有权要求乙网站提供甲的姓名和网络地址"], "answer": "B", "explanation": "A选项，甲未经许可上传至乙网站，侵害了著作权人的信息网络传播权，A选项说法正确。B选项，乙网站属于明知所链接内容侵权情况，应当承担共同侵权责任，B选项说法错误。C选项，丙的行为属于删除权利管理电子信息的行为，构成侵权，C选项说法正确。D选项，《网络传播条例》第13条规定：“著作权行政管理部门为了查处侵犯信息网络传播权的行为，可以要求网络服务提供者提供涉嫌侵权的服务对象的姓名（名称）、联系方式、网络地址等资料”，D选项说法正确。(2018)", "type": "single", "topic": "专题七 著作权法", "page": 228, "subject": "相关法", "id": "xg_720"},
  {"question": "邢某系世界陶艺大师。2016年4月1日，邢某在接受央视7套《乡约》栏目采访时，面对全国观众，拿出自己的作品——五层“吊球”夸下海口：这是我第一件作品，到现在还是世界之谜，这里面不是拿铁丝绑上的，是死环套扣，一个一个包在里面，到现在没人摸索出来。如果有人仿造出来，就把自已位于大连市中心的三层小楼，共计2000平方米，价值1600万元的“邢某艺术中心”送给他（她），还包括里面的资产。节目播出后，河南洛阳一陶瓷爱好者孙某（男）仿造出了此作品。关于邢某的行为应如何定性？（单选）", "options": ["A. 显失公平的合同", "B. 戏谑行为", "C. 赠与合同，大师可随时撤销", "D. 悬赏广告，大师应交付作品"], "answer": "B", "explanation": "本题中，在接受采访吋，邢某夸下海口不构成意思表示，其内心并不存在赠与财物或悬赏的意思，只能属于戏谑行为，因此A、C、D选项错误，B选项正确。（法考2018）", "type": "single", "topic": "专题七 著作权法", "page": 25, "subject": "相关法", "id": "xg_721"},
  {"question": "小韩从小 就显示出很高的文学天赋，九岁时写了小说《隐形翅膀》，并将该小说的网络传播权转让给某网站。小韩的父母反对该转让行为。下列哪一说法是正确的？（单选）", "options": ["A. 小韩父母享有该小说的著作权，因为小韩是无民事行为能力人", "B. 小韩及其父母均不享有著作权，因为该小说未发表", "C. 小韩对该小说享有著作权，但网络传播权转让合同无效", "D. 因小韩父母反对，网络传播权转让合同自反对意见送到某网站时无效"], "answer": "C", "explanation": "本题中，小韩的创作行为在性质上属于事实行为，与民事行为能力无关，小韩是该作品的作者，无论是否发表，都享有该作品的著作权，其父母不享有著作权，但由于九岁的小韩为限制民事行为能力人，其转让行为既不属于纯获利益的民事法律行为，也不属于与其年龄、智力相适应的民事法律行为，其父母作为法定代理人不同意该转让行为，则该网络传播权转让合同自始无效，因此A、B、D选项错误，C选项正确。", "type": "single", "topic": "专题七 著作权法", "page": 31, "subject": "相关法", "id": "xg_722"},
  {"question": "我国《著作权法》不适用于下列哪些选项？（多选）", "options": ["A. 法院判决书", "B. 《与贸易有关的知识产权协定》的官方中文译文", "C. 《伯尔尼公约》成员国国民的未发表且未经我国有关部门审批的境外影视作品", "D. 奥运会开幕式火炬点燃仪式的创意"], "answer": "ABD", "explanation": "A、B选项，法院判决书和《与贸易有关的知识产权协定》的官方中文译文均属于法律、法规，国家机关的决议、决定、命令和其他具有立法、行政、司法性质的文件，及其官方正式译文，不属于《著作权法》保护客体。C选项，《著作权法》第2条规定：‘中国公民、法人或者非法人组织的作品，不论是否发表，依照本法享有著作权。外国人、无国籍人的作品根据其作者所属国或者经常居住地国同中国签订的协议或者共同参加的国际条约享有的著作权，受本法保护’，C选项不当选。D选项，创意属于思想观念的范畴，其没有通过一定形式表现出来形成作品，不受《著作权法》的保护。因此，A、B、D选项正确（法考2011）。", "type": "multiple", "topic": "专题七 著作权法", "page": 220, "subject": "相关法", "id": "xg_723"},
  {"question": "甲的小说必须在我国或美国发表才能受我国著作权法保护", "options": ["A. 甲的小说必须在我国或美国发表才能受我国著作权法保护", "B. 乙翻译的小说和丙改编的电影文学剧本均属于演绎作品", "C. 丙只需征得乙的同意并支付报酬", "D. 丁杂志社如要使用丙的作品还应当分别征得甲、乙的同意，但只需向丙支付报酬"], "answer": "A", "explanation": "根据我国著作权法，作品自创作完成之日起即享有著作权，无需发表。发表权是著作权的一部分，但发表不是获得著作权保护的条件。", "type": "single", "topic": "专题七 著作权法", "page": 227, "subject": "相关法", "id": "xg_724"},
  {"question": "李某侵犯了周某的哪些权利？（多选）", "options": ["A. 姓名权", "B. 肖像权", "C. 名誉权", "D. 著作权"], "answer": "BD", "explanation": "李某使用了周某的视频内容，侵犯了周某的著作权。同时，由于李某使用了周某的肖像，也侵犯了周某的肖像权。姓名权和名誉权在此情境下并未被侵犯。", "type": "multiple", "topic": "专题七 著作权法", "page": 227, "subject": "相关法", "id": "xg_725"},
  {"question": "网络公司将张某的绘画作品放到网上，是发表作品的行为，侵犯了张某的发表权；将绘画作品放到网上供在线浏览下载，是网络传播行为，侵犯了张某的信息网络传播权；因此A、D选项正确，B、C选项错误。", "options": ["A. 正确", "B. 错误", "C. 错误", "D. 正确"], "answer": "AD", "explanation": "根据著作权法，作者享有发表权和信息网络传播权。网络公司未经作者同意将作品放到网上供人浏览下载，侵犯了作者的这两项权利。", "type": "multiple", "topic": "专题七 著作权法", "page": 230, "subject": "相关法", "id": "xg_726"},
  {"question": "《专利代理师的成长历程》是由李某编剧，张某导演的一部电影，制作者为甲公司，音乐人周某创作了可以单独使用的电影音乐。根据著作权法及相关规定，下列哪些说法是正确的？（多选）", "options": ["A. 甲公司是该电影的著作权人", "B. 张某是该电影的著作权人", "C. 李某享有署名权，并有权按照与甲公司签订的合同获得报酬", "D. 周某有权单独行使电影音乐的著作权"], "answer": "ACD", "explanation": "电影的著作权人通常是制片者，即甲公司。编剧李某享有署名权，并有权按照合同获得报酬。导演张某作为电影的创作者之一，也享有相应的权利。音乐人周某创作的电影音乐可以单独使用，因此他有权单独行使该音乐的著作权。", "type": "multiple", "topic": "专题七 著作权法", "page": 224, "subject": "相关法", "id": "xg_727"},
  {"question": "关于丙出版社的行为，下列哪一说法是错误的？", "options": ["A. 侵犯了甲的复制权", "B. 侵犯了乙的著作权", "C. 侵犯了丙的著作权", "D. 侵犯了丁的著作权"], "answer": "A", "explanation": "由于著作权已经超过保护期，因此不构成侵犯甲的复制权。", "type": "single", "topic": "专题七 著作权法", "page": 233, "subject": "相关法", "id": "xg_728"},
  {"question": "赵某和程某合作创作了一部不可分割使用的小说。某出版社与赵某联系欲出版该小说，程某表示坚决反对，两人不能协商一致。根据著作权法及相关规定，下列哪些说法是正确的？", "options": ["A. 赵某和程某为该小说的合作作者，共同享有著作权", "B. 未经程某同意，赵某不得许可该出版社出版该小说", "C. 程某无正当理由不得阻止赵某许可该出版社出版该小说"], "answer": "A", "explanation": "本题中，赵某和程某为该小说的合作作者，共同享有著作权，许可该出版社出版该小说不属于许可他人专有使用，程某无正当理由不得阻止赵某许可该出版社出版该小说，但赵某由此所得收益应当合理分配给程某，因此A、D选项正确，B、C选项错误。（2014）", "type": "single", "topic": "专题七 著作权法", "page": 222, "subject": "相关法", "id": "xg_729"},
  {"question": "根据《网络传播条例》第17条的规定，网络服务提供者接到服务对象的书面说明后，应当立即恢复被删除的作品，同时将服务对象的书面说明转送权利人。权利人不得再通知网络服务提供者删除该作品。下列选项中正确的是：", "options": ["A. 千度公司接到书面通知后，可在合理时间内删除涉嫌侵权作品，同时将通知书转送该作品的提供者", "B. 该影视作品提供者接到千度公司转送的书面通知后，认为提供的作品未侵犯唱片公司的权利的，可以向千度公司提出书面说明，要求恢复被删除作品", "C. 千度公司收到该影视作品提供者的书面说明后应立即恢复被删除作品，同时将该影视作品提供者的说明转送唱片公司", "D. 千度公司收到该影视作品提供者的书面说明后应立即恢复被删除作品，同时将该影视作品提供者的说明转送唱片公司的，则唱片公司不得再通知千度公司删除该作品"], "answer": "D", "explanation": "根据《网络传播条例》第17条的规定，网络服务提供者接到服务对象的书面说明后，应当立即恢复被删除的作品，同时将服务对象的书面说明转送权利人。权利人不得再通知网络服务提供者删除该作品。因此，D选项正确。", "type": "single", "topic": "专题七 著作权法", "page": 247, "subject": "相关法", "id": "xg_730"},
  {"question": "甲创作的一篇杂文，发表后引起较大轰动。该杂文被多家报刊、网站无偿转载。乙将该杂文译成法文，丙将其译成维文，均在国内出版，未征得甲的同意，也未支付报酬。下列哪一观点是正确的？", "options": ["A. 报刊和网站转载该杂文的行为不构成侵权", "B. 乙和丙的行为均不构成侵权", "C. 乙的行为不构成侵权，丙的行为构成侵权", "D. 乙的行为构成侵权，丙的行为不构成侵权"], "answer": "D", "explanation": "根据著作权法，报刊和网站转载作品需要获得著作权人的许可并支付报酬，否则构成侵权。翻译作品同样需要获得著作权人的许可并支付报酬，否则也构成侵权。", "type": "single", "topic": "专题七 著作权法", "page": 236, "subject": "相关法", "id": "xg_731"},
  {"question": "某诗人署名“漫卷的诗书”，在甲网站发表题为“天堂向左”的诗作，乙出版社的《现代诗集》收录该诗，丙义务教育教材编写单位将该诗作为范文编入《语文》教材，丁文学网站转载了该诗。下列哪一说法是正确的？", "options": ["A. 该诗人在甲网站署名方式不合法", "B. “天堂向左”在《现代诗集》中被正式发表", "C. 丙可以不经该诗人同意使用“天堂向左”，但应当按照规定支付报酬", "D. 丁网站未经该诗人和甲网站同意而转载，构成侵权行为"], "answer": "D", "explanation": "根据著作权法，作品的转载需要获得著作权人的许可。如果未获得许可，即使作品已经发表，转载行为也构成侵权。", "type": "single", "topic": "专题七 著作权法", "page": 236, "subject": "相关法", "id": "xg_732"},
  {"question": "卫视播出的歌舞剧同步至网络供用户付费点播和下载。下列有关说法正确的是?(多选)", "options": ["A. 咕噜网侵犯了陈某的信息网络传播权", "B. 咕噜网侵犯了甲剧团演员们的信息网络传播权", "C. 咕噜网侵犯了甲剧团的信息网络传播权", "D. 咕噜网侵犯了东方卫视的广播组织者权"], "answer": "ACD", "explanation": "咕噜网未经许可将其电视信号上传至网络，侵犯了东方卫视的广播组织者权，D选项正确。综上所述，A、C、D选项正确。(法考2023)", "type": "multiple", "topic": "专题七 著作权法", "page": 240, "subject": "相关法", "id": "xg_733"},
  {"question": "唱片公司认为百度公司作为存储服务提供者，其网站上提供的涉及唱片公司享有著作权的某歌曲侵犯了自己的信息网络传播权。唱片公司向百度公司提交书面通知要求其删除侵权作品。对此，下列哪些选项是正确的：（多选）", "options": ["A. 唱片公司的通知书应当包含该作品构成侵权的初步证明材料", "B. 网络服务提供者接到权利人的通知书后，应当立即删除涉嫌侵权作品，并同时将通知书转送提供作品、表演、录音录像制品的服务对象", "C. 服务对象接到网络服务提供者转送的通知书后，应当立即删除涉嫌侵权作品", "D. 网络服务提供者接到权利人的通知书后，应当立即删除涉嫌侵权作品"], "answer": "ACD", "explanation": "A选项，根据《网络传播条例》第14条第1款的规定，对提供信息存储空间或者提供搜索、链接服务的网络服务提供者，权利人认为其服务侵犯自己的信息网络传播权，可以向该网络服务提供者提交书面通知，通知书应当包含构成侵权的初步证明材料，A选项正确。B选项，根据《网络传播条例》第15条的规定，网络服务提供者接到权利人的通知书后，应当立即删除涉嫌侵权作品，并同时将通知书转送提供作品、表演、录音录像制品的服务对象，B选项错误。C选项，根据《网络传播条例》第16条第1款的规定，服务对象接到网络服务提供者转送的通知书后，应当立即删除涉嫌侵权作品，C选项正确。因此，正确答案为ACD。", "type": "multiple", "topic": "专题七 著作权法", "page": 246, "subject": "相关法", "id": "xg_734"},
  {"question": "1. 根据反不正当竞争法及相关规定，下列哪种行为属于不正当竞争行为？（多选）", "options": ["A. 将他人注册商标作为企业字号，但是并未引起误认为是他人商品或与他人存在特定联系", "B. 使用与他人有一定影响的商品名称、包装、装潢等相同或者近似的标识", "C. 使用他人有一定影响的新媒体账号名称", "D. 将他人未注册的驰名商标作为企业字号，引人误认为是他人商品或者与他人存在特定联系"], "answer": "BCD", "explanation": "《反不正当竞争法》第7条规定：“经营者不得实施下列混淆行为，引人误认为是他人商品或者与他人存在特定联系：（一）擅自使用与他人有一定影响的商品名称、包装、装潢等相同或者近似的标识；……（三）擅自使用他人有一定影响的域名主体部分、网站名称、网页、新媒体账号名称、应用程序名称或者图标等；……擅自将他人注册商标、未注册的驰名商标作为企业名称中的字号使用，或者将他人商品名称、企业名称（包括简称、字号等）、注册商标、未注册的驰名商标等设置为搜索关键词，引人误认为是他人商品或者与他人存在特定联系的，属于前款规定的混淆行为。……”，B、C、D选项属于不正当竞争行为。A选项，未引起误认或与他人存在特定联系的，不属于不正当竞争行为。（新编）", "type": "multiple", "topic": "专题八 其他相关法律", "page": 230, "subject": "相关法", "id": "xg_735"},
  {"question": "2. 甲公司在某地电视台投放广告，宣称“甲公司原装进口实木地板质量佳、服务好”，同时捏造虚伪事实宣称“乙公司生产的木地板甲醛严重超标”。此后，乙公司木地板销量锐减。经查明，甲公司生产的实木地板是用国内木材加工而成。根据反不正当竞争法及相关规定，下列关于该广告行为的哪些说法是正确的？（多选）", "options": ["A. 甲公司宣称“甲公司原装进口实木地板质量佳、服务好”的行为是不正当竞争行为", "B. 甲公司宣称“甲公司原装进口实木地板质量佳、服务好”的行为是正当竞争行为", "C. 甲公司宣称“乙公司生产的木地板甲醛严重超标”的行为是不正当竞争行为", "D. 甲公司宣称“乙公司生产的木地板甲醛严重超标”的行为是不正当竞争行为"], "answer": "AC", "explanation": "《反不正当竞争法》第9条第1款规定：“经营者不得对其商品的性能、功能、质量、销售状况、用户评价、曾获荣誉等作虚假或者引人误解的商业宣传，欺骗、误导消费者和其他经营者。”，甲公司宣称“甲公司原装进口实木地板质量佳、服务好”属于虚假宣传，A选项正确，B选项错误。《反不正当竞争法》第12条规定：“经营者不得编造、传播或者指使他人编造、传播虚假信息或者误导性信息，损害其他经营者的商业信誉、商品声誉。”，甲公司宣称“乙公司生产的木地板甲醛严重超标”属于编造、传播虚假信息，损害竞争对手的商业信誉等。", "type": "multiple", "topic": "专题八 其他相关法律", "page": 230, "subject": "相关法", "id": "xg_736"},
  {"question": "7. 甲公司的饮料配方是甲公司核心商业秘密,甲公司员工秘密窃取该饮料配方后,与甲公司竞争对手乙公司联系,乙公司以高薪聘请该员工,使用其提供的甲公司饮料配方开展生产,获取高额利润。下面说法正确的是? (多选)", "options": ["A. 该员工侵犯了甲公司商业秘密", "B. 该员工未侵犯甲公司商业秘密", "C. 乙公司的行为视为侵犯商业秘密行为", "D. 乙公司未直接窃取甲公司饮料配方,有雇佣员工的自由,乙公司行为不视为侵犯商业秘密行为"], "answer": "AC", "explanation": "根据《反不正当竞争法》第10条的规定,甲公司员工以窃取的手段获得配方,属于侵犯商业秘密,乙公司在明知的情况下使用该配方,视为侵犯商业秘密,A、C选项正确。(新编)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 232, "subject": "相关法", "id": "xg_737"},
  {"question": "8. 技术信息或者经营信息必须具备下列哪些要件,才能构成反不正当竞争法所称的商业秘密?(多选)", "options": ["A. 不为公众所知悉", "B. 具有实用性", "C. 权利人对其采取了保密措施", "D. 具有商业价值"], "answer": "ACD", "explanation": "根据《反不正当竞争法》第10条第4款的规定,商业秘密构成要件包括: 秘密性(不为公众所知悉)、保密性(权利人对其采取了相应保密措施)、价值性(具有商业价值),A、C、D选项正确。(新编)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 232, "subject": "相关法", "id": "xg_738"},
  {"question": "9. 甲公司与乙公司就数码相机购销协议进行洽谈,其间,乙的商业秘密被甲公司获悉。甲公司将该商业秘密泄露给乙公司的竞争对手,导致乙的市场份额锐减。据此,下列哪些说法是正确的?(多选)", "options": ["A. 甲的行为属于正常的商业行为", "B. 甲的行为侵犯了乙的商业秘密", "C. 甲应当承担违约责任", "D. 甲应当承担损害赔偿责任"], "answer": "BD", "explanation": "根据《反不正当竞争法》第10条的规定,违反保密义务或者违反权利人有关保守商业秘密的要求,披露、使用或者允许他人使用其所掌握的商业秘密,属于侵犯商业秘密的行为,A选项", "type": "multiple", "topic": "专题八 其他相关法律", "page": 232, "subject": "相关法", "id": "xg_739"},
  {"question": "10. 根据反不正当竞争法的规定,下列哪些行为属于", "options": ["A. 李某通过自行研发获得了某项技术，该技术与他人的技术秘密相同", "B. 孙某通过反向工程获得了他人的技术秘密", "C. 唐某违反权利人有关保守商业秘密的要求，向他人披露其掌握的商业秘密"], "answer": "C", "explanation": "根据《反不正当竞争法》第9条的规定，违反保密义务或者违反权利人有关保守商业秘密的要求，披露、使用或者允许他人使用其所掌握的商业秘密，属于侵犯商业秘密的行为，A选项错误，B选项错误，C选项正确。", "type": "single", "topic": "专题八 其他相关法律", "page": 232, "subject": "相关法", "id": "xg_740"},
  {"question": "11. 根据反不正当竞争法的规定,下列哪些采取了保密措施的信息属于商业秘密:(多选)", "options": ["A. 某社交网络公司将用户在互联网上公开的个人信息收集后形成的数据集合", "B. 某销售公司将自己多年经营的客户信息整理后形成的信息集合", "C. 某公司研发一种新的产品后将产品的技术特征写成专利申请文件后向国家知识产权局提交专利申请,在未授权之前专利申请文件中载明的信息属于商业秘密", "D. 某文化创意公司策划推出一部新的游戏作品,涉及游戏的具体设计、情节、装备、规则、人物等信息在未向社会披露之前属于商业秘密"], "answer": "BD", "explanation": "根据《反不正当竞争法》第10条第4款的规定,商业秘密构成要件之一为秘密性。A选项收集的公开数据不满足秘密性,不属于商业秘密。C选项中如果是发明专利申请,则公开前属于秘密,公开后就不属于秘密,题干中只表述\"未授权之前\",该技术可能已经先期公开,不满足秘密性的要求,不属于商业秘密。B,D选项正确。(2018)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 233, "subject": "相关法", "id": "xg_741"},
  {"question": "12. 根据反不正当竞争法的规定,对于侵犯商业秘密的法律责任,下列说法正确的是?(多选)", "options": ["A. 赔偿数额按照实际损失或者侵权所获得的利益确定", "B. 经营者故意实施侵犯商业秘密行为,情节严重的,可以在按照法定赔偿额的一倍以上三倍以下确定赔偿数额", "C. 经营者侵犯商业秘密的,由监督检查部门责令停止违法行为,没收违法所得,处以罚款", "D. 权利人受到的实际损失、侵权人所获得的利益难以确定的,由人民法院可以判决给予权利人500万元以下的赔偿 - 232 -"], "answer": "ACD", "explanation": "根据《反不正当竞争法》第22条的规定,因不正当竞争行为受到损害的经营者的赔偿数额,按照其因被侵权所受到的实际损失或者侵权人因侵权所获得的利益确定。经营者故意实施侵犯商业秘密行为,情节严重的,可以在按照上述方法确定数额的一倍以上五倍以下确定赔偿数额。经营者违反本法第七条、第十条规定,权利人因被侵权所受到的实际损失、侵权人因侵权所获得的利益难以确定的,由人民法院根据侵权行为的情节判决给予权利人500万元以下的赔偿。因此,A,D选项正确,B选项错误。根据《反不正当竞争法》第26条的规定,经营者以及其他自然人、法人和非法人组织违反本法第十条规定侵犯商业秘密的,由监督检查部门责令停止违法行为,没收违法所得,处十万元以上一百万元以下的罚款;情节严重的,处一百万元以上五百万元以下的罚款。因此,C选项正确。(新编)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 233, "subject": "相关法", "id": "xg_742"},
  {"question": "1. 根据植物新品种保护条例及相关规定，下列哪种说法是正确的？(多选)", "options": ["A. 申请品种权的植物新品种应当属于国家植物品种保护名录中列举的植物的属或者种", "B. 授予品种权的植物新品种的名称可以仅以数字组成", "C. 授予品种权的植物新品种应当具备适当的名称，并与相同或者相近的植物属或者种中已知品种的名称相区别", "D. 授予品种权的植物新品种应当具备的一致性，是指一个植物品种的特性，除可预期的自然变异外，群体内个体间相关的特征或者特性表现一致"], "answer": "ACD", "explanation": "A选项，根据《植物新品种条例》第14条的规定，申请品种权的植物新品种应当属于国家植物品种保护名录中列举的植物的属或者种，因此A选项正确。B选项，《植物新品种条例》第19条第2款规定：“下列名称不得用于品种命名：(一)仅以数字表示的……”，因此B选项错误。C选项，《植物新品种条例》第19条第1款规定：“授予品种权的植物新品种应当具备适当的名称，并与相同或者相近的植物属或者种中已知品种的名称相区别……”，因此C选项正确。D选项，《植物新品种条例》第17条规定：“授予品种权的植物新品种应当具备一致性。一致性，是指一个植物品种的特性，除可预期的自然变异外，群体内个体间相关的特征或者特性表现一致。”，因此D选项正确。(2012改编)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 234, "subject": "相关法", "id": "xg_743"},
  {"question": "2. 根据植物新品种保护条例及相关规定，下列哪些说法是正确的？(多选)", "options": ["A. 植物新品种是指经过人工选育的或者对发现的野生植物加以改良获得的新品种", "B. 未列入国家植物品种保护目录中的植物新品种不受植物新品种保护条例保护", "C. 授予品种权的植物新品种应当同时具备新颖性、创造性、一致性和稳定性", "D. 违反社会公德的名称不得用于授权品种的命名"], "answer": "ABD", "explanation": "A、C选项，《植物新品种条例》第2条规定：“本条例所称植物新品种，是指经过人工选育或者对发现的野生植物加以改良，具备新颖性、特异性、一致性和稳定性并适当命名的植物品种。”因此A选项正确，C选项错误。B选项，根据《植物新品种条例》第14条的规定，申请品种权的植物新品种应当属于国家植物品种保护名录中列举的植物的属或者种，因此B选项正确。D选项，根据《植物新品种条例》第19条第2款的规定，违反社会公德的名称不得用于授权品种的命名，因此D选项正确。(新编)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 234, "subject": "相关法", "id": "xg_744"},
  {"question": "3. 根据植物新品种保护条例及相关规定，下列哪些说法是错误的？(多选)", "options": ["A. 申请品种权的，应当提交请求书、说明书、该品种的照片以及权利要求书", "B. 申请人可以在品种权授予前修改或者撤回品种权申请", "C. 授予品种权的植物新品种应当具备的特异性，是"], "answer": "AD", "explanation": "A选项，《植物新品种条例》第22条第1款规定：“申请品种权的，应当向国务院农业农村、林业草原主管部门提交符合规定格式要求的申请文件。”主管部门规定的申请文件中不包含权利要求书，因此A选项错误。B选项，《植物新品种条例》第26条规定：“申请人可以在品种权授予前", "type": "multiple", "topic": "专题八 其他相关法律", "page": 234, "subject": "相关法", "id": "xg_745"},
  {"question": "4. 根据植物新品种保护条例的规定，下列哪些申请品种权的林木新品种具备新颖性?(多选)", "options": ["A. 在申请日前其繁殖材料、收获材料未被销售、推广", "B. 在申请日前，经申请权人许可，其繁殖材料、收获材料在中国境内销售、推广未超过1年", "C. 在境外，木本、藤本植物品种销售、推广未超过4年", "D. 在境外，除木本、藤本植物以外的植物品种销售、推广未超过4年"], "answer": "ABD", "explanation": "《植物新品种条例》第15条规定：“授予品种权的植物新品种应当具备新颖性。新颖性，是指申请品种权的植物新品种在申请日前该品种繁殖材料、收获材料未被销售、推广，或者经申请权人自行或者同意销售、推广该品种繁殖材料、收获材料，在中国境内未超过1年；在境外，木本、藤本植物品种未超过6年，其他植物品种未超过4年。”，因此A、B、D选项正确，C选项错误。(新编)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 235, "subject": "相关法", "id": "xg_746"},
  {"question": "5. 根据植物新品种保护条例及相关规定，在没有合同约定的情况下，下列哪些说法是正确的?(多选)", "options": ["A. 执行本单位的任务所完成的职务育种，植物新品种的申请权属于该单位", "B. 主要是利用本单位的物质条件所完成的职务育种，植物新品种的申请权属于完成育种的个人", "C. 合作育种，植物新品种的申请权属于共同完成育种的单位和个人", "D. 委托育种，植物新品种的申请权属于委托人"], "answer": "AC", "explanation": "A、B选项，根据《植物新品种条例》第9条第1款的规定，执行本单位的任务或者主要是利用本单位的物质技术条件所完成的职务育种，品种权的申请权属于该单位，因此A选项正确，B选项错误。C、D选项，《植物新品种条例》第9条第2款规定：“委托育种或者合作育种，当事人可以在合同中约定品种权的申请权归属；没有合同约定的，品种权的申请权属于受委托完成或者共同完成育种的单位或者个人。”，因此C选项正确，D选项错误。(2013)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 235, "subject": "相关法", "id": "xg_747"},
  {"question": "6. 张某于2025年10月11日独立完成了某植物新品种的育种，王某于2026年2月14日也独立完成了该植物新品种的育种。张某和王某均于2026年6月18日分别就该植物新品种申请品种权。如果张某和王某就该植物新品种提交的品种权申请均符合授予品种权的其他条件，则品种权应当授予何人?(单选)", "options": ["A. 张某", "B. 王某"], "answer": "A", "explanation": "《植物新品种条例》第10条规定：“一个植物新品种只能授予一项品种权。两个以上的申请人分别就同一个植物新品种申请品种权的，品种权授予最先申请的人；同时申请的，品种权授予最先完成该植物新品种育种的人。”。本题中，张某和王某于同日申请，但张某完成育种在先，品种权应当授予张某，A选项正确。(2017)", "type": "single", "topic": "专题八 其他相关法律", "page": 235, "subject": "相关法", "id": "xg_748"},
  {"question": "7. 根据《植物新品种条例》及相关规定，对于植物新品种申请需要初步审查哪些内容：(多选)", "options": ["A. 是否属于植物品种保护名录列举的植物属或者种的范围", "B. 是否符合新颖性的规定", "C. 植物新品种的命名是否适当", "D. 植物新品种是否具有稳定性"], "answer": "ABC", "explanation": "《植物新品种条例》第28条规定：“申请人缴纳申请费后，国务院农业农村、林业草原主管部门对品种权申请的下列内容进行初步审查：(一)是否属于植物品种保护名录列举的植物属或者种的范围；(二)是否符合本条例第二十一条的规定；(三)是否符合新颖性的规定；(四)植物新品种的命名是否适当。”，A、B、C选项正确。对于稳定性，无法通过初步审查得出结论，D选项错误。(2018)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 236, "subject": "相关法", "id": "xg_749"},
  {"question": "8. 王某对于审批机关驳回其品种权申请的决定不服，拟提起复审。根据植物新品种保护条例及相关规定，下列关于复审程序的说法哪些是正确的?(多选)", "options": ["A. 复审请求应当向植物新品种复审委员会提出", "B. 王某应当自收到通知之日起3个月内提出复审请求", "C. 植物新品种复审委员会应当在收到复审请求书的3个月内作出决定", "D. 申请人对复审决定不服的，应当在收到通知之日起3个月内向人民法院提起诉讼"], "answer": "AB", "explanation": "根据《植物新品种条例》第33条的规定，对驳回品种权申请的决定不服的，申请人可以自收到通知之日起3个月内，向复审委员会请求复审。复审请求符合规定的，复审委员会应当自收到之日起6个月内作出决定，并通知申请人。依法需要检测、测试鉴定的，所需时间不计算在规定期限内。申请人对复审委员会的复审决定不服的，可以依法提起诉讼。根据《行政诉讼法》的相关规定，对复议决定不服的，可以在收到复议决定书之日起15日内向人民法院提起诉讼，因此A、B选项正确，C、D选项错误。(2011改编)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 236, "subject": "相关法", "id": "xg_750"},
  {"question": "9. 根据植物新品种保护条例及相关规定，关于植物新品种权的无效，下列说法正确的是?(多选)", "options": ["A. 请求宣告品种权无效的期限为自公告授予品种权之日起6个月后", "B. 对于不具备一致性的植物新品种，植物新品种复审委员会可以依据职权宣告品种权无效", "C. 对于不具备稳定性的植物新品种，植物新品种复审委员会可以依据任何单位或个人的书面请求宣告品种权无效"], "answer": "BCD", "explanation": "根据《植物新品种条例》第38条规定，自公告授予品种权之日起，复审委员会可以依据职权或者依据任何单位或者个人的书面请求，对不符合《植物新品种条例》第15条(新颖性)、第16条(特异性)、第17条(一致性)和第18条(稳定性)规定的，宣告品种权无效。当事人对复审委员会的无效宣告决定不服的，可以依法提起诉讼。因此，自审批机关公告授予品种权之日起，即可请求无效，A选项错误，B、C、D选项正确。(2019)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 236, "subject": "相关法", "id": "xg_751"},
  {"question": "10. 根据植物新品种保护条例及相关规定，下列哪些使用授权品种的繁殖材料的生产行为，应经品种权人许可?(多选)", "options": ["A. 为商业目的重复使用授权品种进行生产或者繁殖的另一品种", "B. 未经许可使用授权品种的繁殖材料而获得的收获材料", "C. 未经许可使用授权品种的实质性派生品种的繁殖材料", "D. 未经许可使用授权与授权品种相比，不具备明显区别的品种"], "answer": "B", "explanation": "根据植物新品种保护条例，农民自繁自用侵权品种的繁殖材料可以不经品种权人许可，不向其支付使用费。其他选项涉及侵权行为，需要品种权人许可并支付使用费。", "type": "multiple", "topic": "专题八 其他相关法律", "page": 237, "subject": "相关法", "id": "xg_752"},
  {"question": "11. 根据植物新品种保护条例及相关规定，下列哪些行为应经品种权人许可?(多选)", "options": ["A. 许诺销售授权品种的繁殖材料", "B. 农民自繁自用授权品种的繁殖材料", "C. 出口授权品种的繁殖材料", "D. 储存为繁殖授权品种的繁殖材料"], "answer": "ACD", "explanation": "《植物新品种条例》第7条规定，除法律和本条例另有规定外，任何单位或者个人未经品种权人许可，不得对该授权品种的繁殖材料，实施下列行为：①生产、繁殖和为繁殖而进行处理；②许诺销售、销售；③进口、出口；④为实施本款第一项至第三项行为进行储存。因此，A、C、D选项的行为应经品种权人许可。《植物新品种条例》第12条规定：“在下列情况下使用授权品种的，可以不经品种权人许可，不向其支付使用费，但是不得侵犯品种权人依照本条例和有关法律、行政法规享有的其他权利：（一）利用授权品种进行育种及其他科研活动；（二）农民自繁自用授权品种的繁殖材料。”，因此B选项属于合理使用的情形。（2016改编）", "type": "multiple", "topic": "专题八 其他相关法律", "page": 237, "subject": "相关法", "id": "xg_753"},
  {"question": "12. 根据植物新品种保护条例及相关规定，下列关于品种权的保护期限的说法哪项是正确的?(多选)", "options": ["A. 木本的品种权保护期限为25年，自申请之日起算", "B. 木本的品种权保护期限为25年，自授权之日起算", "C. 草本植物的品种权保护期限为20年，自授权之日起算", "D. 藤本植物的品种权保护期限为25年，自申请之日起算"], "answer": "BC", "explanation": "《植物新品种条例》第35条规定：“品种权的保护期限，自授权公告之日起，木本、藤本植物为25年，其他植物为20年。”，因此A、D选项错误，B、C选项正确。（2011改编）", "type": "multiple", "topic": "专题八 其他相关法律", "page": 237, "subject": "相关法", "id": "xg_754"},
  {"question": "1. 根据集成电路布图设计保护条例及相关规定，下列说法哪些是正确的?(多选)", "options": ["A. 受保护的集成电路布图设计应当具有独创性", "B. 集成电路布图设计专有权经国务院知识产权行政部门登记产生", "C. 对集成电路布图设计的保护不延及思想、处理过程、操作方法或者数学概念等", "D. 集成电路布图设计专有权的保护期为十五年"], "answer": "ABC", "explanation": "A选项，《布图设计保护条例》第4条第1款规定：“受保护的布图设计应当具有独创性，即该布图设计是创作者自己的智力劳动成果，并且在其创作时该布图设计在布图设计创作者和集成电路制造者中不是公认的常规设计”，A选项正确。B选项，《布图设计保护条例》第8条第1款规定：“布图设计专有权经国务院知识产权行政部门登记产生”，B选项正确。C选项，《布图设计保护条例》第5条规定：“本条例对布图设计的保护，不延及思想、处理过程、操作方法或者数学概念等”，C选项正确。D选项，《布图设计保护条例》第12条规定：“布图设计专有权的保护期为10年，自布图设计登记申请之日或者在世界任何地方首次投入商业利用之日起计算，以较前日期为准。但是，无论是否登记或者投入商业利用，布图设计自创作完成之日起15年后，不再受本条例保护”，D选项错误。(2009)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 238, "subject": "相关法", "id": "xg_755"},
  {"question": "2. 关于集成电路布图设计的独创性，下列哪项说法是正确的?(单选)", "options": ["A. 布图设计是创作者自己独立创作的，也可能不具有独创性", "B. 是否具有独创性，应以提出登记时为判断时间点", "C. 是否具有独创性，应从本领域技术人员的角度判断", "D. 由常规设计组成的布图设计，不具有独创性"], "answer": "A", "explanation": "A选项，独创性的布图设计应该是创作者自己的智力劳动成果，但是自己独立创作的也可能不具有独创性，A选项正确。B、C选项，《布图设计保护条例》第4条第1款规定，“受保护的布图设计应当具有独创性，即该布图设计是创作者自己的智力劳动成果，并且在其创作时该布图设计在布图设计创作者和集成电路制造者中不是公认的常规设计”，因此判断是否具有独创性，应当以创作时为判断时间点，B选项错误；是否具有创造性应以布图设计创作者和集成电路制造者的角度判断，C选项错误。D选项，《布图设计保护条例》第4条第2款规定，“受保护的由常规设计组成的布图设计，其组合作为整体应当符合前款规定的条件”，因此由常规设计组成的布图设计，也可能具有独创性，D选项错误。(新编)", "type": "single", "topic": "专题八 其他相关法律", "page": 238, "subject": "相关法", "id": "xg_756"},
  {"question": "4. 根据集成电路布图设计保护条例及相关规定，申请人以书面形式申请集成电路布图设计登记的，应当提交下列哪些文件或者物品?(多选)", "options": ["A. 集成电路布图设计登记申请表", "B. 集成电路布图设计的说明书和权利要求书", "C. 集成电路布图设计的复制件或者图样", "D. 集成电路布图设计已投入商业利用的，提交含有该布图设计的集成电路样品"], "answer": "ACD", "explanation": "《布图设计保护条例》第16条规定：“申请布图设计登记，应当提交：(一)布图设计登记申请表；(二)布图设计的复制件或者图样；(三)布图设计已投入商业利用的，提交含有该布图设计的集成电路样品；(四)国务院知识产权行政部门规定的其他材料”，A、C、D选项正确。不需要提交权利要求书，B选项错误。(2009)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 239, "subject": "相关法", "id": "xg_757"},
  {"question": "5. 根据集成电路布图设计保护条例及相关规定，下列说法哪项是正确的?(单选)", "options": ["A. 布图设计专有权经国家知识产权局登记产生", "B. 布图设计专有权自创作完成之日起自动产生", "C. 布图设计专有权的保护期为15年，自布图设计登记申请之日起计算", "D. 布图设计专有权的保护期为15年，自布图设计创作完成之日起计算"], "answer": "A", "explanation": "A、B选项，根据《布图设计保护条例》第8条第1款的规定，布图设计专有权经国务院知识产权行政部门登记产生，A选项正确，B选项错误。C、D选项，根据《布图设计保护条例》第12条的规定，布图设计专有权的保护期为10年，自布图设计登记申请之日或者在世界任何地方首次投入商业利用之日起计算，以较前日期为准，C、D选项错误。(2011)", "type": "single", "topic": "专题八 其他相关法律", "page": 239, "subject": "相关法", "id": "xg_758"},
  {"question": "6. 根据《布图设计保护条例》及其他相关规定，下列哪些说法是正确的?(多选)", "options": ["A. 布图设计首次商业利用之日起2年内，未提出登记申请的，国家知识产权局不予登记", "B. 国家知识产权局应当对布图设计登记申请进行初步审查", "C. 国家知识产权局应当对布图设计登记申请进行实质审查", "D. 布图设计明显不符合该条例所规定的布图设计定义的，国家知识产权局应当作出驳回决定"], "answer": "ABD", "explanation": "A选项，《布图设计保护条例》第17条规定：“布图设计自其在世界任何地方首次商业利用之日起2年内，未向国务院知识产权行政部门提出登记申请的，国务院知识产权行政部门不再予以登记”，A选项正确。B选项，《布图设计保护条例》第18条规定：“布图设计登记申请经初步审查，未发现驳回理由的，由国务院知识产权行政部", "type": "multiple", "topic": "专题八 其他相关法律", "page": 239, "subject": "相关法", "id": "xg_759"},
  {"question": "7. 根据集成电路布图设计保护条例及相关规定，布图设计登记申请人对国家知识产权局驳回其登记申请的决定不服的，可以选择下列哪种救济途径?(单选)", "options": ["A. 自收到通知之日起3个月内向国家知识产权局申请行政复议", "B. 自收到通知之日起3个月内向国家知识产权局请求复审", "C. 自收到通知之日起3个月内向国家知识产权局申诉", "D. 自收到通知之日起3个月内直接向人民法院提起行政诉讼"], "answer": "B", "explanation": "根据《布图设计保护条例》第18条规定：\"布图设计登记申请经初步审查，未发现驳回理由的，由国务院知识产权行政部门予以登记，发给登记证明文件，并予以公告\"。因此，对于驳回决定不服的，应向国家知识产权局请求复审。选项B正确。选项A错误，因为行政复议不适用于此类情形；选项C错误，申诉不是法定救济途径；选项D错误，不能直接向法院提起行政诉讼。", "type": "single", "topic": "专题八 其他相关法律", "page": 239, "subject": "相关法", "id": "xg_760"},
  {"question": "8. 当事人对国家知识产权局作出的下列哪项具体行政行为不服的,不能申请复议?(单选)", "options": ["A. 不予受理布图设计申请的", "B. 驳回布图设计登记申请的", "C. 将布图设计申请视为撤回的", "D. 给予使用其布图设计的非自愿许可的"], "answer": "B", "explanation": "《布图设计保护条例细则》第28条规定:“当事人对国家知识产权局作出的下列具体行政行为不服或者有争议的,可以向国家知识产权局行政复议部门申请复议:(一)不予受理布图设计申请的;(二)将布图设计申请视为撤回的……;(四)其他侵犯当事人合法权益的具体行政行为”,A、C选项可以申请复议,D选项属于行政决定,是具体行政行为,可以申请复议。根据《布图设计保护条例》第19条的规定,对驳回登记申请的决定不服的只能复审,B选项不能申请复议。(2018)", "type": "single", "topic": "专题八 其他相关法律", "page": 240, "subject": "相关法", "id": "xg_761"},
  {"question": "9. 根据集成电路布图设计保护条例及相关规定,下列哪些说法是正确的?(多选)", "options": ["A. 布图设计自其在世界任何地方首次商业利用之日起1年内未向国务院知识产权行政部门提出登记申请的,国务院知识产权行政部门不再予以登记", "B. 布图设计自其在世界任何地方首次商业利用之日起2年内未向国务院知识产权行政部门提出登记申请的,国务院知识产权行政部门不再予以登记", "C. 无论是否登记或者投入商业利用,布图设计自其创作完成之日起满10年的,不再受保护", "D. 无论是否登记或者投入商业利用,布图设计自其创作完成之日起满15年的,不再受保护"], "answer": "BD", "explanation": "A、B选项,《布图设计保护条例》第17条规定:“布图设计自其在世界任何地方首次商业利用之日起2年内,未向国务院知识产权行政部门提出登记申请的,国务院知识产权行政部门不再予以登记”,A选项错误,B选项正确。C、D选项,《布图设计保护条例》第12条规定:“布图设计专有权的保护期为10年,自布图设计登记申请之日或者在世界任何地方首次投入商业利用之日起计算,以较前日期为准。但是,无论是否登记或者投入商业利用,布图设计自创作完成之日起15年后,不再受本条例保护”,C选项错误,D选项正确。(2012)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 240, "subject": "相关法", "id": "xg_762"},
  {"question": "10. 根据集成电路布图设计保护条例及相关规定,布图设计权利人享有下列哪些专有权?(多选)", "options": ["A. 将受保护的布图设计投入商业利用", "B. 将含有受保护布图设计的集成电路以及含有该集 - 239 -"], "answer": "ABCD", "explanation": "《布图设计保护条例》第7条规定:“布图设计权利人享有下列专有权:(一)对受保护的布图设计的全部或者其中任何具有独创性的部", "type": "multiple", "topic": "专题八 其他相关法律", "page": 240, "subject": "相关法", "id": "xg_763"},
  {"question": "1. 根据知识产权海关保护条例及相关规定，下列哪些知识产权的权利人可以请求海关实施知识产权海关保护？(多选)", "options": ["A. 注册商标专用权", "B. 著作权和与著作权有关的权利", "C. 集成电路布图设计专有权", "D. 专利权"], "answer": "ABD", "explanation": "《海关保护条例》第2条规定：“本条例所称知识产权海关保护，是指海关对与进出口货物有关并受中华人民共和国法律、行政法规保护的商标专用权、著作权和与著作权有关的权利、专利权(以下统称知识产权)实施的保护”，A、B、D选项正确，C选项不属于知识产权海关保护条例的保护范畴。(2012)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 242, "subject": "相关法", "id": "xg_764"},
  {"question": "2. 根据知识产权海关保护条例，下列哪些说法是正确的？(多选)", "options": ["A. 海关仅对与出口货物有关的知识产权实施保护", "B. 海关实施保护的知识产权包括专利权、商标专用权、著作权和与著作权有关的权利", "C. 知识产权权利人请求海关实施知识产权保护的，应当向海关提出采取保护措施的申请", "D. 海关实施知识产权保护时，应当保守有关当事人的商业秘密"], "answer": "BCD", "explanation": "A选项，根据《海关保护条例》第2条的规定，海关对与进口和出口货物有关的知识产权实施保护，A选项错误。B选项，海关实施保护的包括商标专用权、著作权和与著作权有关的权利、专利权，B选项正确。C选项，《海关保护条例》第4条规定：“知识产权权利人请求海关实施知识产权保护的，应当向海关提出采取保护措施的申请”，C选项正确。D选项，《海关保护条例》第6条规定：“海关实施知识产权保护时，应当保守有关当事人的商业秘密”，D选项正确", "type": "multiple", "topic": "专题八 其他相关法律", "page": 242, "subject": "相关法", "id": "xg_765"},
  {"question": "14. 关于集成电路布图设计的非自愿许可，下列哪些说法是正确的？(多选)", "options": ["A. 其范围应当限于为公共目的的非商业性使用", "B. 非自愿许可不得给予自然人", "C. 其原因可以是经人民法院、不正当竞争行为监督检查部门依法认定布图设计权利人有不正当竞争行为而需要给予的补救", "D. 非自愿许可的理由消除并不再发生时，国务院知识产权行政部门应当主动及时作出终止使用布图设计非自愿许可的决定 第四章 知识产权海关保护条例"], "answer": "ACD", "explanation": "非自愿许可的范围限于特定条件下的非商业性使用，可以因不正当竞争行为的补救而授予，且当理由消除时应终止使用。", "type": "multiple", "topic": "专题八 其他相关法律", "page": 242, "subject": "相关法", "id": "xg_766"},
  {"question": "4. 根据知识产权海关保护条例及相关规定，知识产权权利人可以将其知识产权向海关总署申请备案。申请备案的，应当提交申请书。申请书应当包括下列哪些内容？(多选)", "options": ["A. 知识产权许可行使状况", "B. 知识产权的名称、内容及其相关信息", "C. 知识产权权利人的名称或者姓名、注册地或者国籍等", "D. 知识产权稳定性初步证明文件"], "answer": "ABC", "explanation": "《海关保护条例》第7条第1款规定：“知识产权权利人可以依照本条例的规定，将其知识产权向海关总署申请备案；申请备案的，应当提交申请书。申请书应当包括下列内容：(一)知识产权权利人的名称或者姓名、注册地或者国籍等；(二)知识产权的名称、内容及其相关信息；(三)知识产权许可行使状况……”，因此A、B、C选项正确。海关备案不需要稳定性初步证明文件，D选项错误。(新编)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 243, "subject": "相关法", "id": "xg_767"},
  {"question": "5. 根据知识产权海关保护条例及相关规定，下列说法哪些是正确的？(多选)", "options": ["A. 个人携带或者邮寄进出境的物品，超出自用、合理数量，并侵犯知识产权的，按照侵权货物处理", "B. 知识产权备案情况发生改变的，知识产权权利人应当自发生改变之日起30个工作日内，向海关总署办理备案变更或者注销手续", "C. 在海关认定被扣留的侵权嫌疑货物为侵权货物之前，知识产权权利人撤回扣留侵权嫌疑货物的申请的，海关应当放行被扣留的侵权嫌疑货物", "D. 对被没收的无法用于社会公益事业且知识产权权利人无收购意愿的进口假冒商标货物，在清除货物上的商标标识后"], "answer": "ABC", "explanation": "A选项，《海关保护条例》第31条规定：“个人携带或者邮寄进出境的物品，超出自用、合理数量，并侵犯本条例第2条规定的知识产权的，按照侵权货物处理”，A选项正确。B选项，《海关保护条例》第11条第1款规定：“知识产权备案情况发生改变的，知识产权权利人应当自发生改变之日起30个工作日内，向海关总署办理备案变更或者注销手续”，B选项正确。C选项，《海关保护条例》第24条规定：“有下列情形之一的，海关应当放行被扣留的侵权嫌疑货物：……(五)在海关认定被扣留的侵权嫌疑货物为侵权货物之前，知识产权权利人撤回", "type": "multiple", "topic": "专题八 其他相关法律", "page": 243, "subject": "相关法", "id": "xg_768"},
  {"question": "1. 根据展会知识产权保护办法的规定，知识产权权利人向展会知识产权投诉机构投诉的，应当提交下列哪些材料？（多选）", "options": ["A. 合法有效的知识产权权属证明", "B. 涉嫌侵权当事人的基本信息", "C. 涉嫌侵权的理由和证据", "D. 财产担保证明"], "answer": "ABC", "explanation": "《展会知识产权保护办法》第8条规定：“知识产权权利人可以向展会知识产权投诉机构投诉也可直接向知识产权行政管理部门投诉。权利人向投诉机构投诉的，应当提交以下材料：（一）合法有效的知识产权权属证明；……（二）涉嫌侵权当事人的基本信息；（三）涉嫌侵权的理由和证据；（四）委托代理人投诉的，应提交授权委托书”，A、B、C选项正确。财产担保证明无需提交，D选项错误。（2009）", "type": "multiple", "topic": "专题八 其他相关法律", "page": 244, "subject": "相关法", "id": "xg_769"},
  {"question": "2. 根据展会知识产权保护办法的规定，下列哪些情形下，地方知识产权局对展品侵犯专利权的投诉或者处理请求不予受理？（多选）", "options": ["A. 投诉人或者请求人已经向人民法院提起专利侵权诉讼的", "B. 专利权正处于无效宣告请求程序之中的", "C. 专利权存在权属纠纷，正处于人民法院的审理程序之 - 243 -"], "answer": "ABCD", "explanation": "《展会知识产权保护办法》第17条规定：“有下列情形之一的，地方知识产权局对侵犯专利权的投诉或者处理请求不予受理：（一）投诉人或者请求人已经向人民法院提起专利侵权诉讼的；（二）专利权正", "type": "multiple", "topic": "专题八 其他相关法律", "page": 244, "subject": "相关法", "id": "xg_770"},
  {"question": "6. 根据知识产权海关保护条例及其实施办法的规定，下列哪些说法是正确的？（多选）", "options": ["A. 知识产权权利人申请扣留侵权嫌疑货物，海关依法扣留侵权嫌疑货物后，自扣留之日起15个工作日内未收到人民法院协助执行通知的，海关应当放行被扣留的侵权嫌疑货物", "B. 知识产权权利人接到海关发现涉嫌侵犯其备案知识产权的进出口货物的书面通知后，逾期未提出扣留侵权嫌疑货物申请或者未提供担保的，海关不得扣留货物", "C. 涉嫌侵犯专利权货物的收货人或者发货人在向海关提供与货物等值的担保金后，请求海关放行其货物的，海关应当放行被扣留的侵权嫌疑货物", "D. 海关认为收货人或者发货人有充分的证据证明其货物未侵犯知识产权权利人的知识产权的，应当放行被扣留的侵权嫌疑货物 第五章 展会知识产权保护"], "answer": "BCD", "explanation": "A选项，根据《海关保护条例》第24条的规定，海关依照本条例第15条的规定扣留侵权嫌疑货物，自扣留之日起20个工作日内未收到人民法院协助执行通知的，海关应当放行被扣留的侵权嫌疑货物。因此，A选项错误。B、C、D选项均属于放行条件。（2007）", "type": "multiple", "topic": "专题八 其他相关法律", "page": 244, "subject": "相关法", "id": "xg_771"},
  {"question": "1. 根据对外贸易法的规定，下列哪项说法是正确的?(单选)", "options": ["A. 进出口属于自由进出口的技术,无需办理任何手续", "B. 国务院对外贸易主管部门可以对自由进出口的技术实行进出口自动许可", "C. 进出口属于自由进出口的技术,应当办理合同备案登记", "D. 进出口属于限制进出口的技术,应当经省级对外贸易主管部门许可"], "answer": "C", "explanation": "A、B、C选项,《对外贸易法》第15条第3款规定:“进出口属于自由进出口的技术,应当向国务院对外贸易主管部门或者其委托的机构办理合同备案登记”,因此A、B选项错误,C选项正确。D选项,《对外贸易法》第19条第1、2款规定:“国家对限制进口或者出口的货物,实行配额、许可证等方式管理;对限制进口或者出口的技术,实行许可证管理。实行配额、许可证管理的货物、技术,应当按照国务院规定经国务院对外贸易主管部门或者经其会同国务院其他有关部门许可,方可进口或者出口”,因此D选项错误。(2007)", "type": "single", "topic": "专题八 其他相关法律", "page": 245, "subject": "相关法", "id": "xg_772"},
  {"question": "2. 根据技术进出口管理条例的规定,下列说法哪些是正确的?(多选)", "options": ["A. 属于限制出口的技术,实行许可证管理;未经许可,不得出口", "B. 对于限制出口的技术,应当先签订技术出口合同,然后再向外经贸主管部门申请技术出口许可意向书", "C. 技术出口经许可的,由外经贸主管部门颁发技术 – 244 –"], "answer": "ACD", "explanation": "A选项,《技术进出口管理条例》第31条规定:“属于限制出口的技术,实行许可证管理;未经许可,不得出口”,因此A选项正确。B选项,《技术进出口管理条例》第34条规定:“技术出口申请经批准的,由国务院外经贸主管部门发给技术出口许可意向书。申请人取得技术出口许可意向书后,方可对外进行实质性谈判,签订技术出口合同”,因此B选项错误。C、D选项,《技术进出", "type": "multiple", "topic": "专题八 其他相关法律", "page": 245, "subject": "相关法", "id": "xg_773"},
  {"question": "3. 根据展会知识产权保护办法的规定，有下列哪些情形的，地方知识产权行政管理部门对侵犯商标权的投诉或者处理请求不予受理?(多选)", "options": ["A. 商标权已经被撤销的", "B. 商标权已经无效的", "C. 投诉人或者请求人已经向人民法院提起商标侵权诉讼的", "D. 商标权存在权属纠纷,正处于人民法院的审理程序之中的 第六章  对外贸易法"], "answer": "ABC", "explanation": "《展会知识产权保护办法》第20条规定:“有下列情形之一的,地方工商行政管理部门对侵犯商标专用权的投诉或者处理请求不予受理:(一)投诉人或者请求人已经向人民法院提起商标侵权诉讼的;(二)商标权已经无效或者被撤销的”,因此A、B、C选项正确,D选项错误。(新编)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 245, "subject": "相关法", "id": "xg_774"},
  {"question": "3. 根据技术进出口管理条例及相关规定,对国务院外经贸主管部门作出的有关技术进出口的批准、许可、登记或者行政处罚决定不服的,下列哪些说法是正确的？ (多选)", "options": ["A. 提起诉讼前必须先复议", "B. 不可复议,只可诉讼", "C. 可以向人民法院提起诉讼", "D. 可以申请行政复议"], "answer": "CD", "explanation": "《技术进出口管理条例》第51条规定:“对国务院外经贸主管部门作出的有关技术进出口的批准、许可、登记或者行政处罚决定不服的,可以依法申请行政复议,也可以依法向人民法院提起诉讼”,因此A、B选项错误,C、D选项正确。\n(新编)", "type": "multiple", "topic": "专题八 其他相关法律", "page": 246, "subject": "相关法", "id": "xg_775"},
  {"question": "4. 根据技术进出口管理条例及相关规定,技术进出口所指的转移技术的行为不包括:(单选)", "options": ["A. 专利实施许可", "B. 技术服务", "C. 技术秘密转让", "D. 技术合作开发 第七章 刑法"], "answer": "D", "explanation": "《技术进出口管理条例》第2条规定:“本条例所称技术进出口,是指从中华人民共和国境外向中华人民共和国境内,或者从中华人民共和国境内向中华人民共和国境外,通过贸易、投资或者经济技术合作的方式转移技术的行为。前款规定的行为包括专利权转让、专利申请权转让、专利实施许可、技术秘密转让、技术服务和其他方式的技术转移”,转移技术的行为不包括技术合作开发,因此A、B、C选项错误,D选项正确。(新编)", "type": "single", "topic": "专题八 其他相关法律", "page": 246, "subject": "相关法", "id": "xg_776"},
  {"question": "2. 甲喝酒后驾车路过某检查站时，被交通执法部门拦住检查。检查人员乙正登车检查时，甲突然发动汽车夺路而逃。乙抓住汽车车门不放，甲为摆脱乙，在疾驶时突然急刹车，导致乙着地身亡。根据刑法及相关规定，甲对乙死亡的心理态度属于下列哪一选项?(单选)", "options": ["A. 直接故意", "B. 间接故意", "C. 过于自信的过失", "D. 疏忽大意的过失"], "answer": "B", "explanation": "《刑法》第14条第1款规定：明知自己的行为会发生危害社会的结果，并且希望或者放任这种结果发生，因而构成犯罪的，是故意犯罪。此题中甲为摆脱乙，在疾驶时突然急刹车，甲应该明知这一行为会造成乙死亡的严重后果，但为了摆脱乙的检查，并没有顾及到乙的生命安全，从而对这一结果持放任的主观态度，在主观上属于间接故意。因此，B选项正确。(新编)", "type": "single", "topic": "专题八 其他相关法律", "page": 247, "subject": "相关法", "id": "xg_777"},
  {"question": "3. 王某因婚外情产生杀害妻子张某的想法。某日早晨，王某在给张某炸油条时投放了可以致死的“毒鼠强”。王某为防止其5岁的儿子吃油条中毒，将其子送到幼儿园，并嘱咐其子等他来接。不料，张某当日提前下班后，将其子接回来一起吃油条。王某得知后，赶忙回到家中，其妻、子已中毒身亡。根据刑法及相关规定，本案中下列哪项说法是正确的?(单选)", "options": ["A. 王某对其妻、子的死亡具有直接故意", "B. 王某对其子的死亡具有间接故意", "C. 王某对其子的死亡具有过失", "D. 王某对其子的死亡属于意外事件"], "answer": "C", "explanation": "A、B选项，《刑法》第14条第1款规定：明知自己的行为会发生危害社会的结果，并且希望或者放任这种结果发生，因而构成犯罪的，是故意犯罪，本题中，王某为防止其6岁的儿子中毒，将其送到幼儿园，并嘱咐其子等他来接，这表明了他不希望儿子中毒，不具有直接故意和放任危害结果发生的间接故意，因此，A、B选项错误。C选项，《刑法》第15条规定：应当预见自己的行为可能发生危害社会的结果，因为疏忽大意而没有预见，或者已经预见而轻信能够避免，以致发生这种结果的，是过失犯罪，从题干表述得知，王某已经预见到可能发生其子死亡的危害结果，以为将其子送到幼儿园就能避免其子中毒，轻信能够避免危害结果发生，对其子死亡的主观心态应当认定为过于自信的过失，因此C选项正确。D选项，《刑法》第16条规定：行为在客观上虽然造成了损害结果，但不是出于故意或者过失，而是由于不能抗拒或者不能预见的原因所引起的，不是犯罪，本题中，王某对其子的死亡不属于意外事件，因此D选项错误。(新编)", "type": "single", "topic": "专题八 其他相关法律", "page": 247, "subject": "相关法", "id": "xg_778"},
  {"question": "4. 根据刑法及相关规定，下列哪种行为构成侵犯知识产权罪?(单选)", "options": ["A. 未经注册商标所有人许可，在同一种商品上使用与其注册商标近似的商标，情节严重的", "B. 以营利为目的，出版他人享有专有出版权的图书，违法所得数额巨大的", "C. 未经集成电路布图设计权利人许可，为商业目的销售受保护的布图设计，情节严重的"], "answer": "B", "explanation": "A选项，《刑法》第213条规定：“未经注册商标所有人许可，在同一种商品、服务上使用与其注册商标相同的商标，情节严重的，处3年以下有期徒刑，并处或者单处罚金；情节特别严重的，处3年以上10年以下有期徒刑，并处罚金”，A选项中为近似的商标，因此不构成侵犯知识产权罪。B选项，《刑法》第217条规定：“以营利为目的，有下列侵犯著作权或者与著作权有关的权利的情形之一，违法所得数额较大或者有其他严重情节的，处3年以下有期徒刑，并处或者单处罚金；违法所得数额巨大或者有其他特别严重情节的，处3年以", "type": "single", "topic": "专题八 其他相关法律", "page": 247, "subject": "相关法", "id": "xg_779"},
  {"question": "1. 根据《促进科技成果转化法》相关规定,以下关于职务科技成果收益分配的说法,正确的是:(单选)", "options": ["A. 国家设立的研究开发机构、高等院校转化科技成果所获得的收入需上交一部分至上级主管部门", "B. 职务科技成果转化后,由科技成果完成单位对所有参与人员给予奖励和报酬", "C. 科技成果完成单位制定奖励和报酬相关规定时,无需听取本单位科技人员意见", "D. 若国家设立的研究开发机构将某项职务科技成果作价投资,且未规定奖励报酬方式和数额,应从该项科技成果形成的股份或者出资比例中提取不低于50%的比例给予完成、转化该项成果的重要贡献人员"], "answer": "D", "explanation": "《促进科技成果转化法》第43条规定:“国家设立的研究开发机构、高等院校转化科技成果所获得的收入全部留归本单位”,因此,A选项错误。《促进科技成果转化法》第44条规定:“职务科技成果转化后,由科技成果完成单位对完成、转化该项科技成果做出重要贡献的人员给予奖励和报酬。科技成果完成单位可以规定或者与科技人员约定奖励和报酬的方式、数额和时限。单位制定相关规定,应当充分听取本单位科技人员的意见,并在本单位公开相关规定。”因此,B、C选项错误。《促进科技成果转化法》第44条规定:“科技成果完成单位未规定也未与科技人员约定奖励和报酬的方式和数额的,利用该项职务科技成果作价投资的,从该项科技成果形成的股份或者出资比例中", "type": "single", "topic": "专题八 其他相关法律", "page": 248, "subject": "相关法", "id": "xg_780"},
  {"question": "5. 根据刑法及相关规定,下列关于假冒注册商标罪、销售假冒注册商标的商品罪的说法正确的有?(多选)", "options": ["A. 只要商品名称不同,则不属于“在同一种商品、服务上使用与其注册商标相同的商标”", "B. 在注册商标上仅增加商品型号,并未增加注册商标的显著性特征,仍属于“在同一种商品、服务上使用与其注册商标相同的商标”", "C. 实施假冒注册商标犯罪,又销售该假冒注册商标的商品,构成犯罪的,应当实行数罪并罚", "D. 无正当理由以明显低于市场价格销售假冒注册商标的商品,属于销售假冒注册商标的商品罪中规定的“明知” 第八章 促进科技成果转化法"], "answer": "BD", "explanation": "根据《侵犯知识产权刑事案件的解释》第1条的规定,商品名称不同,但在功能、用途、主要原料、消费对象、销售渠道等方面相同或者基本相同,相关公众一般认为是同种商品的,应当认定为假冒注册商标罪中规定的“同一种商品、服务”。因此,A选项错误。根据《侵犯知识产权刑事案件的解释》第2条的规定,在注册商标上仅增加商品通用名称、型号等缺乏显著特征要素,不影响体现注册商标显著特征的,应当认定为假冒注册商标罪中规定的“与其注册商标相同的商标”。因此,B选项正确。根据《侵犯知识产权刑事案件的解释》第8条的规定,实施《刑法》第213条规定的假冒注册商标犯罪,又销售该假冒注册商标的商品,构成犯罪的,应当以假冒注册商标罪定罪处罚。因此,C选项错误,应以假冒注册商标罪定罪处罚。根据《侵犯知识产权刑事案件的解释》第4条的规定,销售假冒注册商标的商品,无正当理由以明显低于市场价格进货或者销售的,可以认定为销售假冒注册商标的商品罪中规定的“明知”。因此,D选项正确。", "type": "multiple", "topic": "专题八 其他相关法律", "page": 248, "subject": "相关法", "id": "xg_781"},
  {"question": "1. 根据刑法及相关规定,下列说法哪些是正确的？(多选)", "options": ["A. 已满12周岁不满18周岁的人犯罪,应当从轻或者减轻处罚", "B. 已满75周岁的人故意犯罪的,应当从轻或者减轻处罚", "C. 又聋又哑的人犯罪,可以从轻、减轻或者免除处罚", "D. 精神病人在不能控制自己行为的时候造成危害结果,经法定程序鉴定确认的,不负刑事责任"], "answer": "ACD", "explanation": "A选项,《刑法》第17条规定:“已满16周岁的人犯罪,应当负刑事责任。已满14周岁不满16周岁的人,犯故意杀人、故意伤害致人重伤或者死亡、强奸、抢劫、贩卖毒品、放火、爆炸、投放危险物质罪的,应当负刑事责任。已满12周岁不满14周岁的人,犯故意杀人、故意伤害罪,致人死亡或者以特别残忍手段致人重伤造成严重残疾,情节恶劣,经最高人民检察院核准追诉的,应当负刑事责任。对依照前3款规定追究刑事责任的不满18周岁的人,应当从轻或者减轻处罚”,因此A选项正确。B选项,《刑法》第17条之一规定:“已满75周岁的人故意犯罪的,可以从轻或者减轻处罚;过失犯罪的,应当从轻或者减轻处罚”,因此B选项错误。C选项,《刑法》第19条规定:“又聋又哑的人或者盲人犯罪,可以从轻、减轻", "type": "multiple", "topic": "专题八 其他相关法律", "page": 246, "subject": "相关法", "id": "xg_782"},
  {"question": "德凯公司拟为新三板上市造势，在无真实交易意图的情况下，短期内以业务合作为由邀请多家公司来其主要办公地点洽谈。其中，真诚公司安排授权代表往返十余次，每次都准备了详尽可操作的合作方案，德凯公司佯装兴趣并屡次表达将签署合同的意愿，但均在最后一刻推脱拒签。期间，德凯公司还将知悉的真诚公司的部分商业秘密不当泄露。对此，下列哪些说法是错误的？（多选）", "options": ["A. 未缔结合同，则德凯公司就磋商事宜无需承担责任", "B. 虽未缔结合同，但德凯公司构成恶意磋商，应赔偿损失", "C. 未缔结合同，则商业秘密属于真诚公司自愿披露，不应承担责任"], "answer": "AC", "explanation": "本题中，德凯公司恶意磋商，且泄露商业秘密构成缔约过失，应承担赔偿责任，对德凯公司所付出的工作成本，真诚公司并无过错，无需赔偿，因此A、C、D选项错误，B选项正确。（法考2017）", "type": "multiple", "topic": "专题八 其他相关法律", "page": 51, "subject": "相关法", "id": "xg_783"},
  {"question": "《反不正当竞争法》第二十九条规定，当事人对监督检查部门作出的决定不服的，可以依法申请行政复议或者提起行政诉讼。某县市场监督管理局认定某企业利用广告对商品作引人误解的虚假宣传，构成不正当竞争，处10万元罚款。该企业不服申请复议。下列哪些说法是正确的（多选）", "options": ["A. 复议机关应当为该县市场监督管理局的上级市场监管", "B. 申请复议期限为15日", "C. 如复议机关作出维持决定，该企业向法院起诉，起诉期限为15日", "D. 对罚款决定，该企业可以不经复议直接向法院起诉"], "answer": "ACD", "explanation": "复议机关应当为该县市场监督管理局的上级市场监管机关，申请复议期限为60日，如复议机关作出维持决定，该企业向法院起诉的期限为15日，对罚款决定，该企业可以不经复议直接向法院起诉。", "type": "multiple", "topic": "专题八 其他相关法律", "page": 173, "subject": "相关法", "id": "xg_784"},
  {"question": "AC. 反不正当竞争法第8条第1款规定：“经营者不得对其商品的性能、功能、质量、销售状况、用户评价、经营业绩等作虚假或者引人误解的商业宣传，欺骗、误导消费者；甲公司宣称“甲公司原装进口实木地板质量好，服务好”，同时捏造虚假事实宣称“乙公司生产的产品质量好，服务好”，同时捏造虚假事实宣称“甲公司生产的产品质量好，服务好”，同时捏造虚假事实宣称“乙公司生产的产品质量好，服务好”。”乙公司木地板销量锐减。经查，甲公司生产的实木地板是用国内木材加工而成。根据反不正当竞争法及相关规定，下列关于该广告行为的哪些说法是正确的？(多选)", "options": ["A. 甲公司宣称“甲公司原装进口实木地板质量好，服务好”的行为是不正当竞争行为", "B. 甲公司宣称“甲公司原装进口实木地板质量好，服务好”的行为是正当竞争行为", "C. 甲公司宣称“乙公司生产的木地板甲醛严重超标”的行为是不正当竞争行为", "D. 甲公司宣称“乙公司生产的木地板甲醛严重超标”的行为是正当竞争行为"], "answer": "AC", "explanation": "无需作答", "type": "multiple", "topic": "专题八 其他相关法律", "page": 248, "subject": "相关法", "id": "xg_785"},
  {"question": "根据反不正当竞争法规定，下列哪种行为属于不正当竞争行为？(单选)", "options": ["A. 对商品作虚假或者引人误解的商业宣传，欺骗、误导消费者", "B. 擅自在同类商品上使用与他人注册商标相同或近似的商标", "C. 抽奖式的有奖销售，奖金为40000元", "D. 因清偿债务、转产、歇业以低于成本价销售商品"], "answer": "A", "explanation": "根据《反不正当竞争法》第8条的规定，经营者不得对其商品作虚假或者引人误解的商业宣传，欺骗、误导消费者，A选项构成不正当竞争。B选项属于商标侵权，不构成不正当竞争。《反不正当竞争法》第10条规定：‘经营者进行有奖销售不得存在下列情形：……；（三）抽奖式的有奖销售，最高奖的金额超过五万元’，C选项不属于不正当竞争行为。D选项为合理降价，不属于不正当竞争行为。", "type": "single", "topic": "专题八 其他相关法律", "page": 249, "subject": "相关法", "id": "xg_786"},
  {"question": "王某窃取某技术开发公司的技术秘密后，将窃取一事告知了马某，并应马某的请求向其披露了该技术秘密。马某此后下列哪些行为属于侵犯商业秘密的行为？(多选)", "options": ["A. 将该技术秘密通过学术论文公开发表", "B. 将该技术秘密向其好友赵某披露", "C. 将该技术秘密用于生产经营", "D. 将该技术秘密以自己的名义向国家知识产权局申请专利"], "answer": "ABCD", "explanation": "《反不正当竞争法》第9条第1款规定：‘经营者不得实施下列侵犯商业秘密的行为：（一）以盗窃、贿赂、欺诈、胁迫、电子侵入或者其他不正当手段获取权利人的商业秘密；（二）披露、使用或者允许他人使用以前项手段获取的权利人的商业秘密；（三）违反保密义务或者违反权利人有关保守商业秘密的要求，披露、使用或者允许他人使用其所掌握的商业秘密；（四）教唆、引诱、帮助他人违反保密义务，获取、使用、披露权利人的商业秘密’。因此，A、B、C、D选项均属于侵犯商业秘密的行为。", "type": "multiple", "topic": "专题八 其他相关法律", "page": 249, "subject": "相关法", "id": "xg_787"},
  {"question": "根据集成电路布图设计保护及相关条例规定，侵犯布图设计专有权，引起纠纷的，布图设计权利人或者利害关系人可以向下列哪一部门请求处理？", "options": ["A. 国务院工商行政管理部门", "B. 国务院知识产权行政部门", "C. 国务院科学技术行政部门", "D. 省级管理专利工作的部门"], "answer": "B", "explanation": "根据相关法规，布图设计权利人或利害关系人应向国务院知识产权行政部门请求处理侵犯布图设计专有权的纠纷。", "type": "single", "topic": "专题八 其他相关法律", "page": 259, "subject": "相关法", "id": "xg_788"},
  {"question": "有专有出版权的图书……”因此B项构成侵犯知识产权罪。C项不属于《刑法》中规定的犯罪行为。", "options": ["A. 选项A", "B. 选项B", "C. 选项C", "D. 选项D"], "answer": "B", "explanation": "B项构成侵犯知识产权罪，而C项不属于《刑法》中规定的犯罪行为。", "type": "single", "topic": "专题八 其他相关法律", "page": 264, "subject": "相关法", "id": "xg_789"},
  {"question": "A. 选项《刑法》第17条规定：“已满16周岁的人犯罪，应当负刑事责任。已满14周岁不满16周岁的人，犯故意杀人、故意伤害致人重伤或者死亡、放火、爆炸、投毒罪的，应当负刑事责任。已满12周岁不满14周岁的人，犯故意杀人、故意伤害致人重伤或者死亡、放火、爆炸、投毒罪的，应当负刑事责任。已满75周岁的人故意犯罪的，应当从轻或者减轻处罚；过失犯罪的，应当减轻或者减轻处罚。”因此B项错误。C项，《刑法》第19条规定：“又聋又哑的人或者盲人犯罪，可以从轻、减轻或者免除处罚。”因此C项正确。D项，《刑法》第18条规定：“精神病人不能控制自己行为的时候造成危害结果，经法定程序鉴定确认的，不负刑事责任。”因此D项正确。", "options": ["A. 选项A", "B. 选项B", "C. 选项C", "D. 选项D"], "answer": "C", "explanation": "C项正确，因为《刑法》第19条规定聋哑人或盲人犯罪可以从轻、减轻或免除处罚。", "type": "single", "topic": "专题八 其他相关法律", "page": 264, "subject": "相关法", "id": "xg_790"},
  {"question": "1. 根据《科学技术进步法》的规定，利用财政性资金设立的科学技术计划项目所形成的专利，下列说法正确的是？（多选）", "options": ["A. 形成的专利应当首先在境内使用", "B. 形成的专利实施转化前，应当经项目管理机构批准", "C. 为了重大社会公共利益的需要，国家可以无偿实施", "D. 形成的专利归项目承担者所有"], "answer": "CD", "explanation": "根据《科学技术进步法》第34条的规定：“国家鼓励利用财政性资金设立的科学技术计划项目所形成的知识产权首先在境内使用。前款规定的知识产权向境外的组织或者个人转让，或者许可境外的组织或者个人独占实施的，应当经项目管理机构批准；法律、行政法规对批准机构另有规定的，依照其规定。”因此A选项错误。根据《科学技术进步法》第32条的规定：“利用财政性资金设立的科学技术计划项目所形成的科技成果，在不损害国家安全、国家利益和重大社会公共利益的前提下，授权项目承担者依法取得相关知识产权，项目承担者可以依法自行投资实施转化、向他人转让、联合他人共同实施转化、许可他人使用或者作价投资等。项目承担者应当依法实施前款规定的知识产权，同时采取保护措施，并就实施和保护情况向项目管理机构提交年度报告；在合理期限内没有实施且无正当理由的，国家可以无偿实施，也可以许可他人有偿实施或者无偿实施。项目承担者依法取得的本条第一款规定的知识产权，为了国家安全、国家利益和重大社会公共利益的需要，国家可以无偿实施，也可以许可他人有偿实施或者无偿实施。”因此B选项错误，C、D选项正确(新编)", "type": "multiple", "topic": "专题九 保护工业产权巴黎公约与马拉喀什条约", "page": 249, "subject": "相关法", "id": "xg_791"},
  {"question": "2. 根据《促进科技成果转化法》相关规定，下列不属于科技成果持有者可采用的科技成果转化方式的是： （单选）", "options": ["A. 将科技成果捐赠给公益组织", "B. 以科技成果作价投资，折算股份", "C. 许可他人使用该科技成果", "D. 自行投资实施科技成果转化 第九章 科学技术进步法"], "answer": "A", "explanation": "《促进科技成果转化法》第16条规定：“科技成果持有者可以采用下列方式进行科技成果转化：① 自行投资实施转化；② 向他人转让该科技成果；③ 许可他人使用该科技成果；④ 以该科技成果作为合作条件，与他人共同实施转化；⑤ 以该科技成果作价投资，折算股份或者出资比例；⑥ 其他协商确定的方式”，因此，A选项错误，B、C、D选项正确。(新编)", "type": "single", "topic": "专题九 保护工业产权巴黎公约与马拉喀什条约", "page": 249, "subject": "相关法", "id": "xg_792"},
  {"question": "1. 下列哪些是《巴黎公约》规定的工业产权?(多选)", "options": ["A. 专利权", "B. 商标权", "C. 版权", "D. 植物新品种权"], "answer": "AB", "explanation": "《巴黎公约》第1条(二)规定:“工业产权的保护对象是专利、实用新型、工业外观设计、商标、服务商标、厂商名称、货源标记或原产地名称以及制止不正当竞争”,A、B选项正确。注意著作权和与著作权相关的权利、以及新兴的知识产权例如植物新品种和集成电路布图设计不在《巴黎公约》保护范围内。(2013)", "type": "multiple", "topic": "专题九 保护工业产权巴黎公约与马拉喀什条约", "page": 250, "subject": "相关法", "id": "xg_793"},
  {"question": "2. 根据《巴黎公约》的规定,下列哪项不属于工业产权的保护对象?(单选)", "options": ["A. 外观设计", "B. 原产地名称", "C. 货源标记", "D. 集成电路布图设计"], "answer": "D", "explanation": "根据《巴黎公约》第1条(二)的规定,集成电路不属于工业产品的范围,D选项正确。(2014)", "type": "single", "topic": "专题九 保护工业产权巴黎公约与马拉喀什条约", "page": 250, "subject": "相关法", "id": "xg_794"},
  {"question": "3. 《巴黎公约》规定,本联盟任何国家的国民,在保护工业产权方面,在本联盟所有其他国家内应享有各该国法律现在授予或今后可能授予国民的各种利益;一切都不应损害本公约特别规定的权利。因此,他们应和国民享有同样的保护,对侵犯他们的权利享有同样的法律上的救济手段,但是他们遵守对国民规定的条件和手续为限。上述规定可以概括为什么原则?(单选)", "options": ["A. 对等原则", "B. 差别待遇原则", "C. 最惠国待遇原则", "D. 国民待遇原则"], "answer": "D", "explanation": "《巴黎公约》第2条(一)规定:“本联盟任何国家的国民,在保护工业产权方面,应在本同盟其他国家内享有各该国法律现在或今后可能给予国民的各种利益;……”,本题题干描述的是国民待遇原则,D选项正确。(2017)", "type": "single", "topic": "专题九 保护工业产权巴黎公约与马拉喀什条约", "page": 250, "subject": "相关法", "id": "xg_795"},
  {"question": "6. 根据《巴黎公约》，巴黎联盟成员国的法律可对下列哪些事项作出国民待遇原则的例外规定？(多选)", "options": ["A. 司法和行政程序管辖权", "B. 指定送达地址", "C. 委派代理人", "D. 权利受侵犯时法律上的救济手段"], "answer": "ABC", "explanation": "《巴黎公约》第2条(三)规定：“本联盟每一国家法律中关于司法和行政程序管辖权以及指定送达地址或委派代理人的规定等，工业产权法中可能有要求的，均明确地予以保留”，本题考查国民待遇的例外规定，因此A、B、C选项正确，D选项不属于例外规定对象。(2013)", "type": "multiple", "topic": "专题九 保护工业产权巴黎公约与马拉喀什条约", "page": 251, "subject": "相关法", "id": "xg_796"},
  {"question": "10. 根据《巴黎公约》的规定，下列关于优先权的说法哪些是正确的?(多选)", "options": ["A. 作为产生优先权的基础的首次申请可以是与正规的国家申请相当的任何申请", "B. 要求优先权的，应当在各成员国规定的期限内提出要求优先权的声明", "C. 根据实用新型申请的优先权而在另一成员国提出外观设计申请的，优先权的期间应当为12个月", "D. 成员国可以准许根据实用新型申请的优先权提出 - 251 -"], "answer": "ABD", "explanation": "A选项，根据《巴黎公约》第4条A(2)的规定，依照本联盟任何成员国国家的本国立法，或依照本联盟各国之间缔结的双边或多边条约，与正规的国家申请相当的任何申请，应被承认为产生优先权，A选项正确。B选项，根据《巴黎公约》第4条D(1)的规定，任何人希望利用以前提出的一项申请的优先权的，需要作出声明，说明提出该申请的日期和受理该申请的国家。每一国家应确定必须作出该项声明的最后日期，B选项正确。C选项，根据《巴黎公约》第四条C(1)的规定，外观设计的优先权期间为6个月；E(1)的规定，依靠以实用新型申请为基础的优先权而在一个国家提出工业品外观设计申请的，优先权的期间应与对工业品外观设计规定的优先权期间一样，即为6个月，C选项错误。D选项，根据《巴黎公约》第四条E(2)规定，依靠以专利申请为基础的优先权而在一个国家提出实用新型的申请是许可的，反之亦一样，D选项正确。(2007)", "type": "multiple", "topic": "专题九 保护工业产权巴黎公约与马拉喀什条约", "page": 252, "subject": "相关法", "id": "xg_797"},
  {"question": "18. 根据《巴黎公约》的规定，下列哪些说法是正确的？(多选)", "options": ["A. 缴纳规定的工业产权维持费的宽限期不得少于6个月", "B. 各成员国之间可签订关于保护工业产权的专门协定，其中与《巴黎公约》的规定相抵触的，则各成员国之间应遵照该专门协定的规定", "C. 美国的船舶暂时进入中国海域过境时，其船舶上配置的洒水吧台与中国某吧台的专利产品相同，该船舶上的吧台不视为侵犯专利权", "D. 在工商业事务中违反诚实的习惯做法的竞争行为构成不正当竞争的行为，各成员国应予以制止"], "answer": "AD", "explanation": "A选项，《巴黎公约》第5条之二(1)规定：“关于规定的工业产权维持费的缴纳，应给予不少于6个月的宽限期，但是如果本国法律有规定，应缴纳附加费”，因此A选项正确。B选项，《巴黎公约》第19条规定：“本联盟国家在与本公约的规定不相抵触的范围内，保留有相互间分别签订关于保护工业产权的专门协定的权利”，因此B选项错误。C选项，《巴黎公约》第5条之三规定：“在本联盟任何国家内，下列情况不应认为是侵犯专利权人的权利：1.本联盟其他国家的船舶暂时或偶然地进入上述国家的领水时，在该船的船身、机器、船具、装备及其他附件上使用构成专利对象的器械，但以专为该船的需要而使用这些器械为限……”，但船舶上的洒水吧台不是以专为该船的需要而使用，因此构成侵权，C选项错误。D选项，《巴黎公约》第10条之二规定：“(1)本联盟国家有义务对各该国国民保证给予制止不正当竞争的有效保护。(2)凡在工商业事务中违反诚实的习惯做法的竞争行为构成不正当竞争的行为……”，因此D选项正确。(新编)", "type": "multiple", "topic": "专题九 保护工业产权巴黎公约与马拉喀什条约", "page": 255, "subject": "相关法", "id": "xg_798"},
  {"question": "19. 根据马拉喀什条约及相关规定，下列说法哪个是正确的？(单选)", "options": ["A. 该条约中的“作品”仅指已出版的作品", "B. 该条约适用于中华人民共和国澳门特别行政区", "C. 该条约于2016年9月30日在中华人民共和国生效", "D. 与该条约有关的行政工作由世界知识产权组织国际局履行 - 254 -"], "answer": "D", "explanation": "A选项，《马拉喀什条约》第2条(一)规定：“‘作品’是指文学和艺术作品，形式为文字、符号和(或)相关图示，不论是已出版的作品，还是以其他方式通过任何媒介公开提供的作品”，因此A选项错误。B选项，香港特别行政区适用《马拉喀什条约》，但不适用于澳门特别行政区，因此B选项错误。C选项，《马拉喀什条约》于2013年6月27日在马拉喀什签署，于2016年9月30日生效，并于2022年5月5日对中国生效，因此C选项错误。D选项，《马拉喀什条约》第14条规定：“与本条约有关的行政工作应由世界知识产权组织国际局履行”，因此D选项正确。(新编)", "type": "single", "topic": "专题九 保护工业产权巴黎公约与马拉喀什条约", "page": 255, "subject": "相关法", "id": "xg_799"},
  {"question": "1. 根据《与贸易有关的知识产权协定》,下列说法哪些是正确的?(多选)", "options": ["A. 世界贸易组织成员应当实施该协定的规定,不得在其法律中规定比该协定的要求更为广泛的保护", "B. 世界贸易组织成员没有义务在其法律中规定比该协定的要求更为广泛的保护", "C. 世界贸易组织成员有自由在其法律制度和实践中确定实施该协定规定的适当方法", "D. 世界贸易组织成员应当将该协定规定的待遇给予其他成员的国民"], "answer": "BCD", "explanation": "A、B、C选项,《与贸易有关的知识产权协定》第1条第1款规定:“各成员应当实施本协定的规定。各成员可以,但没有义务,在其法律中规定比本协定的要求更为广泛的保护,只要此种保护不违反本协定的规定。各成员有权在其各自的法律制度和实践中确定实施本协定规定的适当方法”,A选项错误,B、C选项正确。D选项,《与贸易有关的知识产权协定》第1条第3款规定:“各成员应当将该协定规定的待遇给予其他成员的国民”,D选项正确。(2009)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 256, "subject": "相关法", "id": "xg_800"},
  {"question": "2. 根据《与贸易有关的知识产权协定》的规定,在知识产权保护方面,除该协定规定的特殊情形之外,每一成员给予其他成员国民的待遇不应比其给予本国国民的待遇较为不利。上述规定可以概括为什么原则?(单选)", "options": ["A. 对等原则", "B. 差别待遇原则", "C. 国民待遇原则", "D. 最惠国待遇原则"], "answer": "C", "explanation": "《与贸易有关的知识产权协定》第3条“国民待遇”规定:“……每一成员给予其他成员国民的待遇不应比其给予本国国民的待遇较为不利”,C选项正确。(2016)", "type": "single", "topic": "专题十 与贸易有关的知识产权协定", "page": 256, "subject": "相关法", "id": "xg_801"},
  {"question": "4. 下列关于《巴黎公约》和《与贸易有关的知识产权协定》的说法正确的是?(多选)", "options": ["A. 两者都规定了国民待遇原则", "B. 两者都规定了最惠国待遇原则", "C. 两者都规定了透明度原则", "D. 两者都规定了防止权利滥用的原则"], "answer": "ABC", "explanation": "A选项正确，《与贸易有关的知识产权协定》第27条2款规定了成员国可拒绝授予专利的情形；B选项正确，第32条规定任何撤销或宣告专利无效的决定应可进行司法审查；C选项正确，第29条2款规定各成员可要求申请人提供国外申请和授予情况信息。因此，A、B、C选项均正确。", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 257, "subject": "相关法", "id": "xg_802"},
  {"question": "5. 下列哪些属于《与贸易有关的知识产权协议》规定的知识产权的范围?(多选)", "options": ["A. 版权", "B. 工业品外观设计", "C. 地理标志", "D. 实用新型"], "answer": "BCD", "explanation": "A选项，《与贸易有关的知识产权协定》由与贸易有关的知识产权理事会管理，A选项错误。B、C选项，《与贸易有关的知识产权协定》第3条、第4条分别规定了国民待遇原则和最惠国待遇原则，B、C选项正确。D选项，根据《与贸易有关的知识产权协定》第8条第2款的规定，为了防止权利持有人滥用知识产权，或者采用不合理地限制贸易或不利于国际技术转让的做法，可以采取适当措施，但这些措施是以符合本协定规定为限，D选项正确。(2010，思维扩展)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 257, "subject": "相关法", "id": "xg_803"},
  {"question": "6. 根据《与贸易有关的知识产权协定》，下列哪些应当受版权或者和版权有关的权利的保护?(多选)", "options": ["A. 数学概念本身", "B. 以源代码表达的计算机程序", "C. 以目标代码表达的计算程序", "D. 录音制品"], "answer": "BCD", "explanation": "A选项,《与贸易有关的知识产权协定》第9条第2款规定:“版权的保护应当及于表达,而不及于构思、程序、操作方法或者数学概念本身”,A选项错误。B、C选项,《与贸易有关的知识产权协定》第10条第1款规定:“计算机程序,不论是以源代码还是以目标代码表达,应当根据《伯尔尼公约》(1971年)作为文字作品加以保护”,B、C选项正确。D选项,《与贸易有关的知识产权协定》第14条规定了对表演者、录音制品制作者和广播组织的保护,D选项正确。(2013)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 257, "subject": "相关法", "id": "xg_804"},
  {"question": "7. 根据《与贸易有关的知识产权协定》的规定，数据库满足下列哪项条件的，成员应当给予著作权保护?(单选)", "options": ["A. 该数据库的开发投入了相当的资金", "B. 该数据库包含相当数量的数据", "C. 该数据库的开发投入了相当的资金并且包含有相当数量的数据", "D. 对该数据库内容的选择或者安排构成智力创作"], "answer": "D", "explanation": "《与贸易有关的知识产权协定》第10条第2款规定:“数据或者其他资料的汇编,不论是用机器可读形式还是其他形式,由于对其内容的选择或者安排而构成智力创作,应当加以保护。这种保护不涉及数据或者资料本身,不应损害存在于数据或者资料本身的任何版权”,D选项正确,A、B、C选项错误。(2011)", "type": "single", "topic": "专题十 与贸易有关的知识产权协定", "page": 257, "subject": "相关法", "id": "xg_805"},
  {"question": "8. 根据《与贸易有关的知识产权协定》中关于出租权的规定，下列哪些说法是正确的？(多选)", "options": ["A. 成员有义务对以类似摄制电影的方法创作的作品提供出租权保护", "B. 录音制品本身是商业性出租的主要客体的，成员有义务对其提供出租权保护", "C. 计算机程序本身是商业性出租的主要客体的，成员有义务对其提供出租权保护", "D. 在电影作品的商业性出租已导致对作品的广泛复制，大大损害了权利人的复制排他权时，成员有义务对其提供出租权的保护"], "answer": "BCD", "explanation": "根据《与贸易有关的知识产权协定》规定，如果在1994年4月15日，成员在录音制品的出租方面已经实施对权利持有人给予公平报酬的制度，该成员可以维持这种制度，但以录音制品的商业性出租对权利持有人的复制排他权并未造成重大的损害为限。因此A选项错误，B、C、D选项正确。（2008）", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 258, "subject": "相关法", "id": "xg_806"},
  {"question": "9. 根据《与贸易有关的知识产权协定》的规定，下列关于商标的说法哪项是正确的？(单选)", "options": ["A. 任何标记或者标记的组合都可以构成商标", "B. 只有视觉可以感知的标记或者此类标记的组合才可以构成商标", "C. 只有数字或者文字以及这类标记的组合才可以构成商标", "D. 只要是能将一企业的商品或服务与其他企业的商品或服务区别开来的标记或者标记的组合都可以构成商标"], "answer": "D", "explanation": "《与贸易有关的知识产权协定》第15条第1款规定：“任何标记或标记的组合，能将一企业的商品或服务与其他企业的商品或服务区别开来的，就能构成商标。这类标记，尤其是文字（包括人名）、字母、数字、图形要素和色彩的组合，以及这类标记的任何组合，均适合于作为商标予以注册。如果标记缺乏区别有关商品或服务的固有能力，各成员可以将该标记可否注册取决于使用后所获得的显著性。各成员可以要求将视觉可以感知的标记作为注册的条件”，D选项正确，A、B、C选项说法过于绝对。(2011)", "type": "single", "topic": "专题十 与贸易有关的知识产权协定", "page": 258, "subject": "相关法", "id": "xg_807"},
  {"question": "10. 根据《与贸易有关的知识产权协定》的规定，下列哪些说法是正确的？(多选)", "options": ["A. 各成员可以将商标的实际使用作为提交商标注册申请的条件", "B. 各成员不应将商标的实际使用作为提交商标注册申请的条件", "C. 各成员可以规定使用是维持商标注册的必要条件", "D. 各成员不应规定使用是维持商标注册的必要条件"], "answer": "BC", "explanation": "A、B选项，《与贸易有关的知识产权协定》第15条第3款规定：“各成员可以将可否注册取决于使用。然而，不应将商标的实际使用作为提交注册申请的条件”，A选项错误，B选项正确。C、D选项，《与贸易有关的知识产权协定》第19条第1款规定：“如果使用是维持注册的必要条件，只有在至少连续3年不使用以后，才可以取消其注册……”，C选项正确，D选项错误。(2016)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 258, "subject": "相关法", "id": "xg_808"},
  {"question": "11. 根据《与贸易有关的知识产权协议》的规定，下列说法哪项是正确的？(单选)", "options": ["A. 在以登记为保护条件的成员中，布图设计的保护期限应自登记之日起10年", "B. 在不以登记为保护条件的成员中，布图设计的保护期限应自登记之日起10年", "C. 以登记为保护条件的成员可以规定，布图设计自创作后15年，保护应当终止", "D. 不以登记为保护条件的成员可以规定，布图设计自创作后15年，保护应当终止"], "answer": "A", "explanation": "《与贸易有关的知识产权协议》第18条规定：“商标的首次注册和每次续展保护期限不少于7年”，A选项正确，B、C、D选项错误。(2006)", "type": "single", "topic": "专题十 与贸易有关的知识产权协定", "page": 258, "subject": "相关法", "id": "xg_809"},
  {"question": "15. 根据《与贸易有关的知识产权协定》的规定，下列关于工业品外观设计的哪些说法是正确的？(多选)", "options": ["A. 各成员应当规定保护独立创作而且是新颖的或者原创的工业品外观设计", "B. 各成员可以规定，外观设计如果与已知的外观设计或者已知的外观设计特征的组合没有显著区别的，即不是新颖的或者原创的外观设计", "C. 各成员可以规定，工业品外观设计的保护不应延及主要是根据技术或功能的考虑而作出的外观设计", "D. 受保护的工业品外观设计的所有人，应当有权制止第三方未得所有人同意而为商业目的制造、销售或进口载有或体现受保护的外观设计的复制品或实质上是复制品的物品"], "answer": "ABD", "explanation": "根据《与贸易有关的知识产权协定》第26条第1款规定：‘受保护的工业品外观设计的所有人，应当有权制止第三方未得所有人同意而为商业目的制造、销售或进口载有或体现受保护的外观设计的复制品或实质上是复制品的物品’，D选项正确。A、C选项正确。B选项错误，因为该条款并未否定新颖性要求，而是允许成员对非新颖性进行限制。", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 260, "subject": "相关法", "id": "xg_810"},
  {"question": "16. 根据《与贸易有关的知识产权协定》的规定，受保护的工业品外观设计的所有人，对于载有或体现受保护的外观设计的复制品或者实质上是复制品的物品，应当有权制止第三方未经其同意而为商业目的进行下列哪些行为？(多选)", "options": ["A. 制造", "B. 进口", "C. 许诺销售", "D. 销售"], "answer": "ABD", "explanation": "《与贸易有关的知识产权协定》第26条第1款规定：“受保护的工业品外观设计所有人，应有权制止第三方未经许可而为商业目的制造、销售或进口带有或体现有受保护设计的复制品或实质性复制品之物品”，A、B、D选项正确，C选项错误。(2015)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 260, "subject": "相关法", "id": "xg_811"},
  {"question": "20. 根据《与贸易有关的知识产权协定》，如果成员的法律允许未经权利持有人许可即可由政府使用，或者由政府许可第三方使用专利，则这种使用应当遵守下列哪些规定？（多选）", "options": ["A. 这种使用的许可应当根据个案情况予以考虑", "B. 这种使用应当在合理的期限内通知权利持有人，但无需向其支付报酬", "C. 这种使用应当是独占的，权利持有人不得再许可其他人使用该专利", "D. 这种使用不得转让，除非是与享有这种使用的企业或者商誉一起转让"], "answer": "CD", "explanation": "A选项，根据《与贸易有关的知识产权协定》第31条的规定，这种使用不得转让，但与享有这种使用的企业或者商誉一起转让的不在此限，A选项错误。B选项，这种使用只有在使用前，意图使用的人曾经努力按合理的商业条款和条件请求权利持有人给予许可，但在合理的期间内这种努力没有成功的，才能允许。但在国家处于紧急状态或有其他极端紧急的情形，或者在公共的非商业性使用的情形，成员可以放弃这一要求，B选项错误。C选项，这种使用在半导体技术的情形下，只能限于为公共的非商业性使用，或者用于经司法或行政程序确定为反竞争行为而给予的补救，C选项正确。D选项，在对被许可人的合法利益给予足够保护的前提下，如果以及在导致这种许可的情况已不存在，并且不大可能再发生时，这种使用的许可应即终止，D选项正确。（2010）", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 262, "subject": "相关法", "id": "xg_812"},
  {"question": "21. 根据《与贸易有关的知识产权协定》的规定，如果成员的法律允许在未经权利持有人许可的情况下，对其专利的主题作经政府许可的第三方使用，则应当遵守下列哪些规定？（多选）", "options": ["A. 使用人可以自由转让或者再许可其他人使用，但应当向权利持有人支付足够的报酬", "B. 任何情况下，意图使用的人只有在使用前曾经努力按合理的商业条款和条件请求权利持有人给予许可，但在合理的期间内这种努力没有成功，才能允许这种使用", "C. 在涉及半导体技术的情形下，这种使用只能限于为公共的非商业性使用，或者用于经司法或行政程序确定为反竞争行为而给予的补救", "D. 在对被许可人的合法利益给予足够保护的前提下，如果以及在导致这种许可的情况已不存在，并且不大可能再发生时，这种使用的许可应即终止"], "answer": "CD", "explanation": "A选项，根据《与贸易有关的知识产权协定》第31条的规定，这种使用不得转让，但与享有这种使用的企业或者商誉一起转让的不在此限，A选项错误。B选项，这种使用只有在使用前，意图使用的人曾经努力按合理的商业条款和条件请求权利持有人给予许可，但在合理的期间内这种努力没有成功的，才能允许。但在国家处于紧急状态或有其他极端紧急的情形，或者在公共的非商业性使用的情形，成员可以放弃这一要求，B选项错误。C选项，这种使用在半导体技术的情形下，只能限于为公共的非商业性使用，或者用于经司法或行政程序确定为反竞争行为而给予的补救，C选项正确。D选项，在对被许可人的合法利益给予足够保护的前提下，如果以及在导致这种许可的情况已不存在，并且不大可能再发生时，这种使用的许可应即终止，D选项正确。（2010）", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 262, "subject": "相关法", "id": "xg_813"},
  {"question": "22. 根据《与贸易有关的知识产权协定》的规定，下列说法正确的是？（多选）", "options": ["A. 成员必须利用专利制度对植物新品种给予保护", "B. 成员可以利用专利制度以外的有效的专门制度对植物新品种给予保护", "C. 成员可以将专利制度和其他有效的专门制度相结合对"], "answer": "BC", "explanation": "《与贸易有关的知识产权协定》第27条第3款(b)规定：“……各成员应当规定依专利或依有效的特别制度，或依二者的结合，保护植物的品种……”，A、D选项错误，B、C选项正确。（2019）", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 262, "subject": "相关法", "id": "xg_814"},
  {"question": "23. 根据《与贸易有关的知识产权协定》的规定，下列关于集成电路布图设计保护期的说法哪些是正确的？(多选)", "options": ["A. 在以登记为保护条件的成员中，布图设计的保护期间应为自登记之日起10年", "B. 在不以登记为保护条件的成员中，布图设计的保护期间自其在世界上任何地方第一次商业利用之日算起不少于10年", "C. 以登记为保护条件的成员可以规定，布图设计自创作以后15年，保护应当终止", "D. 不以登记为保护条件的成员可以规定，布图设计自创作以后15年，保护应当终止。"], "answer": "ABC", "explanation": "A选项，根据《与贸易有关的知识产权协定》第27条第2款的规定，各成员可以拒绝某些发明授予专利，以这种拒绝并非仅因为法律禁止实施为限，A选项正确。B选项，《与贸易有关的知识产权协定》第29条规定：\"1. 各成员应当要求专利申请人以足够清楚和完整的方式公开发明，使熟悉有关技术的人能实施该发明\"，B选项正确。D选项，国外专利的审查情况仅作为授权的参考，不会直接决定是否授权，D选项错误。C选项，《与贸易有关的知识产权协定》第30条规定：\"各成员可以对专利所授予的排他权规定有限的例外，但是，在顾及第三方合法利益的情况下，这些例外以并未与专利的正常利用不合理地相冲突，而且也并未不合理地损害专利所有人的合法利益为限\"，C选项正确。（2018）", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 263, "subject": "相关法", "id": "xg_815"},
  {"question": "24. 根据《与贸易有关的知识产权协定》的规定，世界贸易组织成员可以针对下列哪些知识产权规定强制许可或者非自愿许可？(多选)", "options": ["A. 专利", "B. 商标", "C. 工业品外观设计", "D. 集成电路布图设计"], "answer": "AD", "explanation": "A选项，《与贸易有关的知识产权协定》第31条规定了专利的“未经权利持有人授权的其他使用”，即规定了对专利权的强制许可，A选项正确。B选项，根据《与贸易有关的知识产权协定》第21条的规定，商标的强制许可是不允许的，B选项错误。C选项，《与贸易有关的知识产权协定》未规定工业品外观设计的强制许可或非自愿许可，C选项错误。D选项，《与贸易有关的知识产权协定》第37条第2款规定：“布图设计遇有任何非自愿许可，或未经权利持有人许可而由政府或为政府而使用时，应当比照适用第31条(a)项至(k)项所列规定的条件”，D选项正确。(2012)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 263, "subject": "相关法", "id": "xg_816"},
  {"question": "25. 根据《与贸易有关的知识产权协定》的规定，未公开信息符合下列哪些条件的，各成员应当对其提供保护？(多选)", "options": ["A. 该信息的整体或者其各部分的确切排列和组合，并不是通常从事有关这类信息的人所普遍了解或容易获得的", "B. 已经呈送给政府机构登记备案", "C. 由于是保密信息而具有商业价值", "D. 合法控制该信息的人已经根据情况采取了合理的保密措施"], "answer": "ACD", "explanation": "《与贸易有关的知识产权协定》第39条第2款规定：“自然人和法人应有可能制止他人未得其同意，以违反诚实的商业做法的方式，将其合法控制下的信息向他人公开，或者获得或使用此种信息，只要这种信息符合下列条件：(1)符合这样意义的秘密，即该信息的整体或其部分的确切排列和组合，并不是通常从事有关这类信息的人所普遍了解或容易获得的；(2)由于是保密信息而具有商业上的价值；和(3)合法控制该信息的人已经根据情况采取了合理措施予以保密”，A、C、D选项正确。商业秘密没有登记备案要求，B选项错误。(2018)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 263, "subject": "相关法", "id": "xg_817"},
  {"question": "26. 根据《与贸易有关的知识产权协定》的规定，下列哪些", "options": ["A. 司法机关应当有权命令采取迅速和有效的临时措施以便：(a)制止任何侵犯知识产权行为的发生；(b)保存被指控侵权的有关证据", "B. 司法机关应当有权要求申请人提供足以保护被告和防止滥用临时措施的保证金或相当的担保", "C. 在任何迟延可能对权利持有人造成不可补救的损害时，或存在证据被销毁的显而易见的风险时，司法机关有权采取不作预先通知的临时措施", "D. 临时措施被撤销的，司法机关根据被告的请求，应当有权命令申请人向由于这些措施而受到损害的被告提供适当的补偿"], "answer": "ABC", "explanation": "《与贸易有关的知识产权协定》第40条第2款规定：“本协定的任何规定均不得阻止各成员在其立法中明确规定，在特定情况下可构成对知识产权的滥用……，例如，排他性返授条件、制止对知识产权有效性提出质疑的条件以及强制性一揽子授权许可”，A、B、C选项正确，D选项错误。(2019)", "type": "single", "topic": "专题十 与贸易有关的知识产权协定", "page": 263, "subject": "相关法", "id": "xg_818"},
  {"question": "27. 根据《与贸易有关的知识产权协定》的规定, 下列哪些属于针对侵权行为规定的民事救济措施?(多选)", "options": ["A. 监禁", "B. 责令停止侵权", "C. 损害赔偿", "D. 责令侵权人向权利持有人支付适当的律师费用"], "answer": "BCD", "explanation": "根据《与贸易有关的知识产权协定》第61条的规定，各成员应规定至少将适用于具有商业规模的蓄意假冒商标、盗版案件，特别是故意侵权并具有商业规模的案件的刑事程序和处罚，因此A、B选项正确，C、D选项错误。", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 264, "subject": "相关法", "id": "xg_819"},
  {"question": "28. 根据《与贸易有关的知识产权协定》的规定, 成员至少应当对下列哪些故意的、具有商业规模的案件规定刑事程序和处罚?(多选)", "options": ["A. 假冒商标案件", "B. 盗版案件", "C. 假冒专利案件", "D. 侵犯集成电路布图设计专有权的案件"], "answer": "AB", "explanation": "根据《与贸易有关的知识产权协定》第61条的规定，各成员应规定至少将适用于具有商业规模的蓄意假冒商标、盗版案件，特别是故意侵权并具有商业规模的案件的刑事程序和处罚，因此A、B选项正确，C、D选项错误。", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 264, "subject": "相关法", "id": "xg_820"},
  {"question": "29. 根据《与贸易有关的知识产权协定》的规定, 下列关于临时措施的说法哪些是正确的?(多选)", "options": ["A. 司法机关应当有权在任何迟延可能对权利持有人造成不可弥补损害的情况下, 不听取另一方的意见而即采取临时措施", "B. 司法机关应当有权要求申请人提供足以保护被告和防止滥用临时措施的保证金或相当的担保", "C. 执行临时措施的机关可以要求申请人提供用于辨认有关货物的必要的信息", "D. 临时措施被撤销的, 司法机关根据被告的请求, 应当有权命令申请人向由于这些措施而受到损害的被告提供适当的"], "answer": "ABCD", "explanation": "A选项, 根据《与贸易有关的知识产权协定》第50条第2款的规定, 司法机关应当有权在适当情况下, 尤其是在任何迟延可能对权利持有人造成不可弥补损害的情况下, 不作预先通知而即采取临时措施, A选项正确。B选项, 根据《与贸易有关的知识产权协定》第50条第3款的规定, 司法机关应当有权要求申请人提供可以合理地获得的任何证据, 并有权要求申请人提供足以保护被告和防止滥用此种措施的保证金或相当的担保, B选项正确。C选项, 根据《与贸易有关的知识产权协定》第50条第5款的规定, 执行临时措施的主管机关可要求申请人提供确认有关货物的其他必要信息, C选项正确。D选项, 根据《与贸易有关的知识产权协定》第50条第7款的规定, 如果临时措施被撤销, 则司法机关根据被告的请求, 应当有权命令申请人向由于这些措施而受到损害的被告提供适当的补偿, D选项正确。(2007)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 264, "subject": "相关法", "id": "xg_821"},
  {"question": "30. 根据《与贸易有关的知识产权协定》的规定，关于临时措施的规定哪些是正确的：（多选）", "options": ["A. 司法机关有权责令采取迅速和有效的临时措施以防止侵犯知识产权的行为", "B. 司法机关有权采取迅速和有效的临时措施保存关于被诉侵权的有关证据", "C. 在适当时，特别是在任何迟延可能对权利持有人造成不可补救的损害时，或存在证据被销毁的显而易见的风险时，司法机关有权采取不作预先通知的临时措施", "D. 司法机关有权责令申请人提供足以保护被告和防止滥用的保证金或相当的担保"], "answer": "C", "explanation": "《与贸易有关的知识产权协定》第51条规定：“各成员应当遵照规定制订程序，以便权利持有人在有确实根据的理由怀疑假冒商标货物或盗版货物可能进口时，能向行政或司法主管机关提出书面申请，要求海关当局对这种货物中止放行，以免进入自由流通”，《与贸易有关的知识产权协定》第58条规定：“允许各成员要求主管机关在获得初步证据证明知识产权正受到有关货物的侵犯时主动采取行动，中止该货物的放行”，A、B、D选项错误，C选项正确。(2012)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 265, "subject": "相关法", "id": "xg_822"},
  {"question": "31. 根据《与贸易有关的知识产权协定》，下列哪种说法是正确的？（单选）", "options": ["A. 世界贸易组织成员只能规定依当事人申请的知识产权海关边境措施", "B. 世界贸易组织成员只能规定海关当局依职权的知识产权海关边境措施", "C. 世界贸易组织成员有义务规定依当事人申请的知识产权海关边境措施，还可以规定海关当局依职权的知识产权海关边境措施", "D. 世界贸易组织成员没有规定知识产权海关边境措施的义务"], "answer": "C", "explanation": "《与贸易有关的知识产权协定》第51条规定：“各成员应当遵照规定制订程序，以便权利持有人在有确实根据的理由怀疑假冒商标货物或盗版货物可能进口时，能向行政或司法主管机关提出书面申请，要求海关当局对这种货物中止放行，以免进入自由流通”，《与贸易有关的知识产权协定》第58条规定：“允许各成员要求主管机关在获得初步证据证明知识产权正受到有关货物的侵犯时主动采取行动，中止该货物的放行”，A、B、D选项错误，C选项正确。(2012)", "type": "single", "topic": "专题十 与贸易有关的知识产权协定", "page": 265, "subject": "相关法", "id": "xg_823"},
  {"question": "32. 根据《与贸易有关的知识产权协定》的规定，下列哪些属于各成员在知识产权执法方面应当履行的义务？（多选）", "options": ["A. 知识产权的执法程序不应不必要地复杂或花费高昂，也不应规定不合理的期限或导致不应有的拖延", "B. 就案件的是非作出的决定最好应写成书面，并说明理由", "C. 程序的双方当事人应当有机会要求司法机关对终局的行政决定进行审查"], "answer": "ABC", "explanation": "A选项，根据《与贸易有关的知识产权协定》第41条第2款的规定，知识产权的执法程序应公平合理。它们不得过于复杂或花费过高或包含不合理的时效或无保障的拖延，A选项正确。B选项，根据《与贸易有关的知识产权协定》第41条第3款的规定，就各案的是非作出的判决，最好采取书面形式，并应说明判决的理由，B选项正确。C选项，根据《与贸易有关的知识产权协定》第41条第4款的规定，对于行政的终局决定，诉讼当事人应有机会提交司法当局复审，C选项正确。D选项，根据《与贸易有关的知识产权协定》第41条第5款的规定，本部分之规定被认为并不产生下列义务：为知识产权执法，而代之以不同于一般法律的执行的司法制度，D选项错误。(2015)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 265, "subject": "相关法", "id": "xg_824"},
  {"question": "33. 根据《与贸易有关的知识产权协定》的规定，对于下列哪些文件，成员应当予以公布?(多选)", "options": ["A. 普遍适用的有关知识产权侵权的终局司法判决", "B. 普遍适用的有关知识产权获得和维持的终局行政决定", "C. 已经生效的有关防止知识产权滥用的法律", "D. 成员政府与非成员政府之间有关知识产权执法的双边协定"], "answer": "ABD", "explanation": "A、B、D选项，根据《与贸易有关的知识产权协定》第63条第4款的规定，不要求各成员公开妨碍法律执行或违反公共利益的机密信息，或者损害特定的公有或私有企业的合法商业利益的机密信息，A、B、D选项正确。C选项，根据《与贸易有关的知识产权协定》第63条第1款的规定，任何成员已经生效的与本协定内容有关的法律和规章，均应以本国语言公布，C选项错误。(2009)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 266, "subject": "相关法", "id": "xg_825"},
  {"question": "34. 根据《与贸易有关的知识产权协定》中有关透明度的规定，各成员可以不公开下列哪些信息?(多选)", "options": ["A. 其公开将会妨碍法律执行的机密信息", "B. 其公开将会违反公共利益的机密信息", "C. 成员已经生效的与本协定内容有关的法律和规章", "D. 其公开将会损害特定企业的合法商业利益的机密信息"], "answer": "ABD", "explanation": "A、B、D选项，根据《与贸易有关的知识产权协定》第63条第4款的规定，不要求各成员公开妨碍法律执行或违反公共利益的机密信息，或者损害特定的公有或私有企业的合法商业利益的机密信息，A、B、D选项正确。C选项，根据《与贸易有关的知识产权协定》第63条第1款的规定，任何成员已经生效的与本协定内容有关的法律和规章，均应以本国语言公布，C选项错误。(2009)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 266, "subject": "相关法", "id": "xg_826"},
  {"question": "35. 下列关于《与贸易有关的知识产权协定》的说法哪些是正确的?(多选)", "options": ["A. 该协定由世界知识产权组织管理", "B. 该协定规定了知识产权保护方面的国民待遇原则", "C. 该协定规定了知识产权保护方面的最惠国待遇原则", "D. 在符合该协定规定的前提下，协定授权各成员采取适当措施制止滥用知识产权的做法"], "answer": "BCD", "explanation": "A选项，《与贸易有关的知识产权协定》由与贸易有关的知识产权理事会管理，A选项错误。B、C选项，《与贸易有关的知识产权协定》第3条、第4条分别规定了国民待遇原则和最惠国待遇原则，B、C选项正确。D选项，根据《与贸易有关的知识产权协定》第8条第2款的规定，为了防止权利持有人滥用知识产权，或者采用不合理地限制贸易或不利于国际技术转让的做法，可以采取适当措施，但这些措施是以符合本协定规定为限，D选项正确。(2010，思维扩展)", "type": "multiple", "topic": "专题十 与贸易有关的知识产权协定", "page": 266, "subject": "相关法", "id": "xg_827"},
  {"question": "36. 下列哪项国际公约对用于服务的驰名商标明确提出了保护要求?(单选)", "options": ["A. 与贸易有关的知识产权协定", "B. 保护工业产权巴黎公约", "C. 建立工业品外观设计国际分类洛迦诺协定", "D. 国际承认用于专利程序的微生物保存布达佩斯条约"], "answer": "A", "explanation": "A选项，《与贸易有关的知识产权协定》第16条第2款对用于服务的驰名商标明确提出了保护要求，A选项正确。B选项，《巴黎公约》第6条之二规定了对驰名商标的保护，但是在巴黎公约中的商标指商品商标，不包括服务类商标，B选项错误。C、D选项，《洛迦诺协定》及《布达佩斯条约》均不涉及商标保护，C、D选项错误。(2011，思维扩展)", "type": "single", "topic": "专题十 与贸易有关的知识产权协定", "page": 266, "subject": "相关法", "id": "xg_828"}
];
